insert into platform_topic_master (subject_slug, topic_slug, page_name, sections)
values
('business', '4-4-consumer-law', '4.4 Consumer Law', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>Consumer law protects customers when they buy goods and services. The main piece of legislation you need to understand is the <strong>Consumer Rights Act 2015</strong>.</p>\n    <ul>\n      <li><strong>Consumer Law:</strong> The area of law that protects the customers of a business. This is mainly through the Consumer Rights Act 2015.</li>\n      <li><strong>Consumer Rights Act 2015:</strong> An act of parliament that gives customers protection when they buy goods and services — they must be of satisfactory quality, fit for purpose, and as described.</li>\n      <li><strong>Satisfactory Quality:</strong> How the goods are made must reflect the price. A high-priced product must be of high quality. Goods must not be damaged or faulty when bought.</li>\n      <li><strong>Fit for Purpose:</strong> Goods must do what they are meant to do. If the seller claims that a product performs a particular function, it must be able to do that.</li>\n      <li><strong>As Described:</strong> Goods must be exactly as described or advertised. If you ordered an orange-coloured bike, you should receive an orange bike — not a green one.</li>\n      <li><strong>Reputation:</strong> What customers say and feel about a business. Damage to a reputation can seriously affect a business''s long-term survival and sales.</li>\n      <li><strong>Compensation:</strong> A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987.</li>\n      <li><strong>Consumer Protection Act 1987:</strong> Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.</li>\n    </ul>", "check": {"question": "Under which act can consumers claim compensation if a defective product causes death, damage, or personal injury?", "options": ["Consumer Protection Act 1987", "Trade Descriptions Act 1968", "Consumer Rights Act 2015", "Sale of Goods Act 1979"], "answer": 0, "explain": "The Consumer Protection Act 1987 specifically gives consumers the right to claim compensation for defective products causing death, damage, or personal injury."}}, {"title": "The Consumer Rights Act 2015: The Three Requirements", "html": "<p>The <strong>Consumer Rights Act 2015</strong> is the key law protecting customers in the UK. It states that all goods and services sold to customers must meet three requirements. Businesses that fail to comply face serious legal and financial consequences.</p>\n    <ul>\n      <li><strong>1. Of Satisfactory Quality:</strong> Goods must not be damaged or faulty when bought. The quality expected should reflect the price paid — cheaper ''bargains'' are expected to have lower quality than luxury goods. All goods must be appropriate for their price point.</li>\n      <li><strong>2. Fit for Purpose:</strong> Goods must do what they are meant to do. If the seller claims a product performs a specific function, it must be able to do it. For example, a waterproof jacket must actually be waterproof.</li>\n      <li><strong>3. As Described:</strong> Goods must match their description exactly. If you order orange trainers online, you should receive orange ones — not blue ones.</li>\n    </ul>\n    <div class=\"case-study-box\">\n      <h4>Applying the Three Requirements — Real Scenarios</h4>\n      <p><strong>Lisa</strong> buys a washing machine and the start button doesn''t work &rarr; <em>Not of satisfactory quality</em> (faulty when bought).</p>\n      <p><strong>Mandy</strong> buys face cream claiming to eliminate wrinkles, but it doesn''t work &rarr; <em>Not fit for purpose</em> (does not do what it claims).</p>\n      <p><strong>Tim</strong> orders a blue top online but receives a green one &rarr; <em>Not as described</em> (product does not match its description).</p>\n      <p><strong>Oliver</strong> buys a jumper in the sale and finds the seam is ripped when he gets home &rarr; Could be <em>not of satisfactory quality</em> — even sale goods must meet basic standards unless the fault was pointed out at the time of purchase.</p>\n    </div>", "check": {"question": "Mandy buys face cream claiming to eliminate wrinkles, but it doesn''t work. Which requirement has been breached?", "options": ["Satisfactory quality", "Fit for purpose", "Consumer Protection Act 1987", "As described"], "answer": 1, "explain": "The cream fails to do what the seller claimed it would do, so it is not fit for purpose."}}, {"title": "Time-Based Customer Rights Under the Consumer Rights Act", "html": "<p>The Consumer Rights Act also gives customers specific rights depending on <strong>when</strong> a fault is discovered after purchase. These rights change at key time thresholds.</p>\n    <ul>\n      <li><strong>Within 30 Days — Full Refund:</strong> A customer can return faulty goods for a full refund. Important exception: this does <strong>NOT</strong> apply to digital products such as downloaded music or apps. For digital goods, a customer can request a replacement or, if not provided, a price reduction of up to 100%.</li>\n      <li><strong>Within the First 6 Months — Seller''s Burden of Proof:</strong> If a product develops a fault within the first six months, it is assumed the fault was present at the time of purchase. The <strong>seller</strong> must prove otherwise. The customer may request a repair, replacement, or price reduction.</li>\n      <li><strong>After 6 Months — Customer''s Burden of Proof:</strong> It is up to the <strong>customer</strong> to prove that the fault was present at the time of delivery. This is significantly more difficult. Customers have up to <strong>six years</strong> to complete a claim against the seller.</li>\n      <li><strong>Services:</strong> If a service (e.g. a kitchen fitter or plumber) is not completed in the agreed time or to a reasonable standard, the customer can request the work to be redone. If that is not possible, a price reduction of up to 100% should be agreed.</li>\n    </ul>", "check": {"question": "Within how many months of purchase does the burden of proof fall on the seller, not the customer, to show a fault wasn''t present at purchase?", "options": ["12 months", "30 days", "6 months", "6 years"], "answer": 2, "explain": "Within the first 6 months, a fault is assumed to have been present at purchase and the seller must prove otherwise."}}, {"title": "The Impact of Consumer Law on Business", "html": "<p>Consumer law has several significant impacts on how a business must operate. Businesses need to plan carefully to comply — and face serious consequences if they do not.</p>\n    <ul>\n      <li><strong>Production of Quality Goods:</strong> Businesses must ensure goods are produced to a standard that meets legal requirements. This affects how businesses train employees (links to Unit 3.6) and what quality control procedures they use (links to Unit 4.2). If goods are returned for refunds, costs increase and profits fall.</li>\n      <li><strong>Safety of Goods:</strong> Under the Consumer Protection Act 1987, if defective products cause death, injury, or damage to property, customers can claim compensation. This can result in huge financial costs and forces firms to maintain strict safety procedures throughout production.</li>\n      <li><strong>Loss of Reputation:</strong> If a business produces poor-quality or defective goods, customers will complain — often publicly on social media. Negative reviews spread rapidly, damaging a business''s reputation and driving customers to competitors. In extreme cases, this could lead to the business closing down entirely.</li>\n      <li><strong>Training Costs:</strong> To comply with consumer law, businesses must invest in training employees to produce goods of the required quality standard. This increases operating costs but reduces the risk of producing defective goods that lead to costly refunds or legal claims.</li>\n    </ul>", "check": {"question": "According to this topic, what is the main risk when customers complain about poor-quality goods online?", "options": ["Customers permanently lose their refund rights", "Staff training costs are cut to zero at once", "Negative reviews spread fast and damage its reputation", "An automatic fine gets issued by Trading Standards"], "answer": 2, "explain": "The card explains that negative reviews spread rapidly on social media, damaging reputation and pushing customers towards competitors."}}, {"title": "Advantages & Disadvantages of Complying with Consumer Law", "html": "<p>For a 7-mark ''evaluate'' or ''discuss'' question, you must be able to argue both sides. Complying with consumer law creates both benefits and challenges for a business.</p>\n    <div class=\"two-col\">\n      <div>\n        <div class=\"col-head\">✓ Advantages of Complying</div>\n        <div class=\"pro-item\"><strong>Improved Reputation:</strong> Consistently selling high-quality, correctly described goods builds a strong reputation, increasing customer loyalty and long-term sales revenue.</div>\n        <div class=\"pro-item\"><strong>Fewer Returns & Refunds:</strong> Producing goods of satisfactory quality reduces costly refund and return processing, directly protecting profit margins.</div>\n        <div class=\"pro-item\"><strong>Avoids Legal Action:</strong> Compliance prevents costly compensation claims and court proceedings, protecting the business financially and reputationally.</div>\n        <div class=\"pro-item\"><strong>Competitive Advantage:</strong> A business known for quality and reliability can differentiate itself from competitors and attract more customers over time.</div>\n      </div>\n      <div>\n        <div class=\"col-head\">✗ Disadvantages of Complying</div>\n        <div class=\"con-item\"><strong>Training Costs:</strong> Investing in employee training to ensure goods meet quality standards adds to operating costs, reducing short-term profits.</div>\n        <div class=\"con-item\"><strong>Higher Production Costs:</strong> Meeting quality standards may require better raw materials or upgraded equipment, raising the cost of production.</div>\n        <div class=\"con-item\"><strong>Refund & Compensation Risk:</strong> Even compliant businesses may face unexpected refund demands or compensation claims if products fail, creating unpredictable costs.</div>\n        <div class=\"con-item\"><strong>Reputational Risk Remains:</strong> Even one high-profile product failure — especially amplified on social media — can cause lasting damage despite a strong compliance record.</div>\n      </div>\n    </div>\n    <p style=\"margin-top:12px;\"><strong>Examiner Tip:</strong> When evaluating, always consider the specific business context. A large, well-established business may absorb one complaint without lasting damage — but a smaller business with a local reputation could be severely affected by a single product failure.</p>", "check": {"question": "According to the Examiner Tip, which type of business could be more severely affected by a single product failure?", "options": ["A business operating only online", "A smaller business with a local reputation", "A business with multiple product lines", "A large, well-established business"], "answer": 1, "explain": "The Examiner Tip states a smaller business with a local reputation could be severely affected by just one product failure, unlike a large established business."}}, {"title": "Case Study: Consumer Law in the Real World", "html": "<div class=\"case-study-box\">\n      <h4>Case Study: Primark Ltd</h4>\n      <p>Primark is one of the UK''s largest fashion retailers, selling clothing and homeware at prices significantly lower than most competitors. It launched an online click and collect service in 2022.</p>\n      <p>Being a low-cost retailer does NOT exempt Primark from the Consumer Rights Act — all products must still be of satisfactory quality, fit for purpose, and as described.</p>\n      <p><strong>Takeaway:</strong> If Primark''s low-cost products are found to be ''not as described'' or not of satisfactory quality, the business could face a large volume of returns. Since Primark operates on very thin profit margins with high sales volume, excessive refunds could significantly hurt profitability. Negative social media coverage could further damage its reputation with price-conscious shoppers.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Pukka Pies Ltd</h4>\n      <p>Pukka Pies Ltd is a family-owned business with approximately 360 employees making high-quality savoury pies, sold in over 4,000 food stores nationwide. Three of its key values — delighting customers with quality pies and building trust with suppliers through food safety — directly support its compliance with consumer law.</p>\n      <p><strong>Takeaway:</strong> For a food manufacturer, the safety of goods is especially critical. Defective food products could cause illness or injury, triggering massive compensation claims under the Consumer Protection Act 1987 and catastrophic reputational damage — far outweighing the cost of maintaining quality standards.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Which? — The Consumers'' Champion</h4>\n      <p>Which? (formerly the Consumer''s Association) was founded in 1957 and works on behalf of customers, making them aware of their legal rights and testing products for compliance with the law. It has challenged supermarkets and banks to treat customers more fairly.</p>\n      <p><strong>Takeaway:</strong> Which? exists to make individual customers as powerful as the large organisations they deal with. Its ability to publicly challenge major businesses puts significant pressure on all firms to stay within the law — reinforcing that consumer law is actively enforced, not just theoretical.</p>\n    </div>", "check": {"question": "Approximately how many employees does Pukka Pies Ltd have, according to the case study?", "options": ["1,957", "100", "4,000", "360"], "answer": 3, "explain": "The case study states Pukka Pies Ltd is a family-owned business with approximately 360 employees."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Consumer Law", "definition": "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015."}, {"term": "Consumer Rights Act 2015", "definition": "An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described."}, {"term": "Satisfactory Quality", "definition": "Goods must not be damaged or faulty when bought. Quality must reflect the price — cheaper goods have a lower expectation than luxury goods."}, {"term": "Fit for Purpose", "definition": "Goods must do what they are meant to do. If a seller claims a product performs a function, it must be able to do it."}, {"term": "As Described", "definition": "Goods must be exactly as described or advertised. Ordering an orange bike and receiving a green one is a breach of this requirement."}, {"term": "Reputation", "definition": "What customers say and feel about a business. Damage through defective goods can seriously reduce sales and threaten business survival."}, {"term": "Consumer Protection Act 1987", "definition": "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury."}, {"term": "30-Day Return Rule", "definition": "Customers can return faulty goods for a full refund within 30 days of purchase. Does NOT apply to downloaded digital products."}, {"term": "6-Month Rule (Seller''s Burden)", "definition": "If a fault appears within 6 months of purchase, the seller must prove the fault was not pre-existing at the point of sale."}, {"term": "After 6 Months (Customer''s Burden)", "definition": "If a fault appears after 6 months, the customer must prove the fault existed at the time of delivery. Claims can be made for up to 6 years."}, {"term": "Training & Consumer Law", "definition": "To comply with consumer law, businesses must train employees to produce goods of the required quality — increasing operating costs."}, {"term": "Social Media & Reputation", "definition": "Customers can post complaints about defective goods on social media, rapidly damaging a business''s reputation and reducing sales."}]}, "mcq": {"enabled": true, "questions": [{"question": "When buying any goods or services, customers are entitled to expect:", "options": ["The goods to be of the best standard possible", "The goods to be of satisfactory quality", "The goods to be guaranteed for three years", "The goods to be the same price as competitors"], "answer": 1, "explain": "Correct answer: Of satisfactory quality. The Consumer Rights Act 2015 requires goods to be of ''satisfactory quality'' reflecting their price — not the absolute best quality possible. There is no legal requirement for a guarantee period, price matching, or best-in-class standards."}, {"question": "A business must sell goods that:", "options": ["Do what they are meant to do", "Perform as well as competitor goods", "Are made to last for years", "Are as cheap as possible"], "answer": 0, "explain": "Correct answer: Do what they are meant to do. This is the ''fit for purpose'' requirement of the Consumer Rights Act 2015. Businesses have no legal obligation to match competitors'' performance, guarantee longevity, or price goods cheaply."}, {"question": "A way in which a business can be affected by consumer law is:", "options": ["Having compensation claims because goods are of high quality", "Losing reputation due to defective goods", "Having to sack staff who are always late for work", "Profits being reduced by paying higher wages"], "answer": 1, "explain": "Correct answer: Losing reputation due to defective goods. Producing defective goods leads to customer complaints, negative social media posts, and a damaged reputation. Sacking staff and wage levels are employment law issues — not consumer law."}, {"question": "The loss of a good reputation may mean a business:", "options": ["Can spend less money on advertising its products", "Has to increase production to meet demand", "Can afford to give staff a pay rise", "May have difficulty in recruiting staff"], "answer": 3, "explain": "Correct answer: May have difficulty recruiting staff. A poor reputation makes it harder to attract talented workers who want to be associated with respected companies. A damaged reputation would not reduce advertising needs, increase demand, or free up funds for pay rises."}, {"question": "A company makes wooden jigsaw puzzles. By law, the company must:", "options": ["Buy its wood from local suppliers", "Deliver the jigsaw puzzles in electric vans", "Replace any pieces that customers lose", "Use paint that is non-toxic and safe"], "answer": 3, "explain": "Correct answer: Use paint that is non-toxic and safe. Consumer law requires goods to be safe and of satisfactory quality. Using non-toxic paint ensures the product is safe to handle. There is no legal requirement to use local suppliers, deliver by electric van, or replace pieces lost through customer negligence."}, {"question": "A customer has bought a laptop from a computer shop. By law, the computer shop must:", "options": ["Match the price charged by a local competitor", "Offer to upgrade the laptop for no extra charge", "Provide virus protection to keep the customer''s files safe", "Supply a laptop of satisfactory quality"], "answer": 3, "explain": "Correct answer: Supply a laptop of satisfactory quality. The Consumer Rights Act 2015 requires goods to be of satisfactory quality — free from defects. Price matching, upgrades, and virus protection may be offered as good customer service, but none are required by law."}, {"question": "A customer has ordered an electric shower from a plumbing firm. By law, the plumbing firm must:", "options": ["Charge a lower price than other plumbers", "Fit the shower without turning the water off", "Supply a shower that meets current safety standards", "Use an environmentally friendly supplier"], "answer": 2, "explain": "Correct answer: Supply a shower that meets current safety standards. Consumer law requires goods and services to be safe and of satisfactory quality. There is no legal requirement to undercut competitors'' prices, use a specific installation method, or source from eco-friendly suppliers."}, {"question": "Consumer law requires shops to sell goods that are:", "options": ["Cheap", "High quality", "Safe", "Unique"], "answer": 2, "explain": "Correct answer: Safe. Consumer law requires goods to be safe (of satisfactory quality and fit for purpose). ''High quality'' is a very common distractor — the law only requires ''satisfactory'' quality, not the highest quality. Price and uniqueness are not legal requirements."}, {"question": "Consumer law requires shops to sell goods which are:", "options": ["Environmentally friendly", "Of satisfactory quality", "Reasonably priced", "Unique"], "answer": 1, "explain": "Correct answer: Of satisfactory quality. The Consumer Rights Act 2015 specifically requires goods to be of satisfactory quality — not defective or damaged when sold. Environmental responsibility, pricing, and uniqueness are not legal requirements under consumer law."}, {"question": "Within how many days can a customer return faulty goods for a full refund under the Consumer Rights Act 2015?", "options": ["14 days", "21 days", "30 days", "60 days"], "answer": 2, "explain": "Correct answer: 30 days. The Consumer Rights Act 2015 gives customers a 30-day window to return faulty goods for a full refund. After 30 days, the right to an automatic full refund ends — within 6 months, a repair or replacement is offered first."}, {"question": "If a product develops a fault within the first six months of purchase, who must prove the fault was pre-existing?", "options": ["The customer", "The manufacturer", "The seller", "An independent tribunal"], "answer": 2, "explain": "Correct answer: The seller. Within the first 6 months, it is assumed the fault was present at the time of purchase. The seller must prove otherwise. After 6 months, the burden of proof shifts to the customer."}, {"question": "Which of the following is NOT a requirement of the Consumer Rights Act 2015?", "options": ["Of satisfactory quality", "Fit for purpose", "As described", "Cheapest price on the market"], "answer": 3, "explain": "Correct answer: Cheapest price on the market. The three requirements under the Consumer Rights Act 2015 are: satisfactory quality, fit for purpose, and as described. There is no requirement for businesses to sell at the lowest market price."}]}, "fib": {"enabled": true, "questions": [{"text": "The Consumer Rights Act was introduced in [2015]."}, {"text": "Under consumer law, goods must be of satisfactory [quality], fit for [purpose], and as [described]."}, {"text": "A customer can return faulty goods for a full [refund] within [30] days of purchase."}, {"text": "If a fault appears within the first six [months], the [seller] must prove the fault was not present at point of sale."}, {"text": "After six months, the [customer] must prove that the fault was present at the time of [delivery]."}, {"text": "Consumer law can damage a business''s [reputation] if defective goods are produced, especially through negative [social] media."}, {"text": "The Consumer Protection Act [1987] gives consumers the right to claim [compensation] if a defective product causes death or injury."}, {"text": "Good [training] of employees helps a business produce goods of satisfactory quality, but it increases [costs]."}, {"text": "Cheaper bargains are expected to have a [lower] quality than [luxury] goods."}, {"text": "If a business does not produce goods of satisfactory quality, customers may demand a [refund], which increases costs and reduces [profits]."}, {"text": "Digital products such as downloaded music are NOT covered by the [30-day] return rule; customers can instead request a [replacement]."}, {"text": "Customers have up to [six] years in total to make a legal claim against a seller for faulty goods."}]}, "tf": {"enabled": true, "questions": [{"statement": "The Consumer Rights Act says that goods must always be of the best possible quality.", "answer": false, "explain": "FALSE. The Consumer Rights Act only requires goods to be of ''satisfactory quality'' — a standard that reflects the price paid. Cheaper goods have a lower quality expectation than luxury goods; they do not all need to be the best possible standard."}, {"statement": "Customers can return faulty goods for a full refund within 30 days of purchase.", "answer": true, "explain": "TRUE. The Consumer Rights Act 2015 gives customers a 30-day window to return faulty goods for a full refund. Businesses must comply with this legal right."}, {"statement": "All goods must be described correctly only when they are over £100.", "answer": false, "explain": "FALSE. The ''as described'' requirement applies to ALL goods regardless of their price. Whether a product costs £1 or £1,000, it must match its description exactly."}, {"statement": "Safety in goods bought by customers is covered by the Consumer Protection Act 1987.", "answer": true, "explain": "TRUE. The Consumer Protection Act 1987 gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury — specifically covering product safety."}, {"statement": "Digital goods such as downloaded music are covered in exactly the same way as physical goods by the Consumer Rights Act.", "answer": false, "explain": "FALSE. Digital products such as downloaded music and apps are NOT covered by the 30-day return rule. Instead, customers can request a replacement or, if not provided, a price reduction of up to 100%."}, {"statement": "Good training of employees will help a business produce goods of satisfactory quality.", "answer": true, "explain": "TRUE. Investing in employee training helps businesses produce goods that meet the satisfactory quality standard required by consumer law. This directly links to Unit 3.6 (Training)."}, {"statement": "After 30 days, a customer cannot make any claim whatsoever for faulty goods against a business.", "answer": false, "explain": "FALSE. After 30 days, the right to a full refund ends, but customers retain rights. Within 6 months, they can request a repair or replacement. After 6 months, they can still claim for up to six years if they prove the fault was present at the time of purchase."}, {"statement": "A business can face compensation claims if its products cause personal injury or death.", "answer": true, "explain": "TRUE. Under the Consumer Protection Act 1987, customers can claim compensation for death, damage, or personal injury caused by defective products. This can result in huge financial costs for the business."}, {"statement": "Consumer law only applies to physical products and does not cover services such as plumbing or hairdressing.", "answer": false, "explain": "FALSE. The Consumer Rights Act 2015 also covers services. If a service is not completed in the agreed time or to a reasonable standard, customers can request the work to be redone or receive a price reduction of up to 100%."}, {"statement": "If a fault develops after six months, it is the seller''s responsibility to prove the fault was not there at the time of purchase.", "answer": false, "explain": "FALSE. After six months, the burden of proof shifts to the customer — they must prove the fault existed at the time of delivery. Within the first six months, it is the seller who must prove otherwise."}, {"statement": "A business that complies with consumer law may benefit from an improved reputation.", "answer": true, "explain": "TRUE. Consistently selling goods that are of satisfactory quality, fit for purpose, and as described helps build a strong reputation, increasing customer loyalty and sales over time."}, {"statement": "Social media makes it easier for businesses to conceal poor quality products from consumers.", "answer": false, "explain": "FALSE. Social media makes it significantly harder for businesses to conceal product issues. Customers can post negative reviews publicly and these can spread rapidly, causing serious reputational damage far beyond the original complaint."}]}, "misc": {"enabled": true, "items": [{"myth": "Consumer law requires goods to be of the ''best possible quality''.", "truth": "Consumer law only requires ''satisfactory quality'' — a standard that reflects the price paid. A budget product does not need to be as good as a luxury product; it just needs to be appropriate for its price point.", "check": {"question": "What standard of quality does consumer law actually require?", "options": ["Premium quality for all goods", "No legally defined quality standard", "Satisfactory quality, reflecting the price paid", "The best possible quality regardless of price"], "answer": 2, "explain": "Consumer law only requires ''satisfactory quality'' — a standard appropriate to the price paid, not the best possible quality."}}, {"myth": "Writing about fair wages, worker rights, or ethical suppliers will earn marks in a consumer law question.", "truth": "Consumer law is specifically about protecting customers when they buy goods and services. Employment law covers workers'' rights. Ethical sourcing is a separate topic. The 2025 examiner''s report explicitly warned that candidates who wrote about wages or working conditions scored zero — even with good application and analysis.", "check": {"question": "What did the 2025 examiner''s report say about answers discussing fair wages in a consumer law question?", "options": ["They earned partial marks for application only", "They earned knowledge marks but no application marks", "They scored zero despite good application and analysis", "They earned full marks if linked to reputation"], "answer": 2, "explain": "The examiner''s report explicitly warned that candidates writing about wages or working conditions scored zero, despite good application and analysis."}}, {"myth": "The 30-day refund rule applies to all products, including downloaded music and apps.", "truth": "The 30-day return rule does NOT apply to digital products such as downloaded music, films, or apps. For digital goods, customers can request a replacement or a price reduction of up to 100%.", "check": {"question": "Does the 30-day full refund rule apply to downloaded music or apps?", "options": ["Yes — it applies to all products including digital ones", "Only to downloaded films, not music or apps", "No — digital products are excluded from this rule", "Only if the digital product cost over £50"], "answer": 2, "explain": "The 30-day rule does not apply to digital products; customers can instead request a replacement or a price reduction of up to 100%."}}, {"myth": "After 30 days, customers have no rights at all and cannot make any further claims for faulty goods.", "truth": "Customer rights continue beyond 30 days. Within 6 months, customers can claim a repair or replacement. After 6 months, they can still claim for up to six years if they can prove the fault existed at the time of purchase.", "check": {"question": "What can a customer do after 30 days but within 6 months if goods turn out to be faulty?", "options": ["Only claim a full refund", "Only complain to Which? magazine", "Claim a repair or replacement", "Nothing — rights end completely after 30 days"], "answer": 2, "explain": "Within 6 months of purchase, customers can still claim a repair or replacement, as the fault is assumed to have existed at purchase."}}, {"myth": "Complying with consumer law is purely a cost to a business with no benefits.", "truth": "Compliance brings significant benefits: improved reputation, fewer returns, increased customer loyalty, and avoidance of costly legal action. In 7-mark questions, you must evaluate both sides — benefits and drawbacks.", "check": {"question": "What benefit does complying with consumer law bring to a business, according to this card?", "options": ["Automatic increase in market share", "Guaranteed exemption from all future legal claims", "Immediate elimination of production costs", "Improved reputation and increased customer loyalty"], "answer": 3, "explain": "Compliance brings benefits such as improved reputation, fewer returns, increased customer loyalty, and avoidance of costly legal action."}}, {"myth": "Consumer law only applies to large businesses with many customers.", "truth": "Consumer law applies to ALL businesses selling goods or services to customers, regardless of size. A small family-run bakery must comply with the same Consumer Rights Act 2015 as a large supermarket like Tesco.", "check": {"question": "Does consumer law apply only to large businesses with many customers?", "options": ["Yes — only businesses with over 100 employees", "No — only businesses that sell online", "No — it applies to businesses of any size", "Yes — only publicly listed companies"], "answer": 2, "explain": "Consumer law applies to all businesses selling goods or services, including a small family-run bakery, just as much as a large supermarket like Tesco."}}, {"myth": "The Consumer Rights Act 2015 and the Consumer Protection Act 1987 are the same law.", "truth": "These are two separate laws. The Consumer Rights Act 2015 covers the three requirements (satisfactory quality, fit for purpose, as described). The Consumer Protection Act 1987 specifically covers compensation claims when defective products cause death, injury, or damage.", "check": {"question": "What is the key difference between the Consumer Rights Act 2015 and the Consumer Protection Act 1987?", "options": ["The 1987 Act only protects customers of food businesses", "The 2015 Act covers quality; the 1987 Act covers compensation", "The 2015 Act only protects buyers of digital products", "The two Acts are actually the same law with different names"], "answer": 1, "explain": "The two laws are separate: the 2015 Act covers satisfactory quality, fit for purpose and as described, while the 1987 Act covers compensation for death, injury, or damage caused by defective products."}}, {"myth": "Repeating earlier analysis points in a conclusion will earn evaluation marks in a 7-mark question.", "truth": "Repeating earlier points in a conclusion earns zero evaluation marks. A good conclusion makes a new, justified judgement using specific context from the case study — using ''It depends on...'' or ''However, this is only the case if...'' style reasoning to show higher-level thinking.", "check": {"question": "What happens if a student simply repeats earlier analysis points in a 7-mark conclusion?", "options": ["They earn 1 mark for effort", "They earn zero evaluation marks", "They earn full evaluation marks for consistency", "They earn analysis marks retroactively"], "answer": 1, "explain": "Repeating earlier points in a conclusion earns zero evaluation marks — a good conclusion must make a new, justified judgement."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n          <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. No explanation. No examples. No paragraphs — just one precise, accurate statement.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li>One clear, specific point = 1 mark ✅</li>\n            <li>A vague or general point = 0 marks ❌</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n          <em>\"Consumer law protects customers.\"</em><br/>\n          Too vague — it doesn''t identify any specific protection.</p>\n    \n          <p><strong>✅ Good Answer (1 mark):</strong><br/>\n          <em>\"Goods must be of satisfactory quality.\"</em><br/>\n          Specific, accurate, and directly answers the question.</p>\n    \n          <p><strong>⚠️ Critical Examiner Warning:</strong> Many students confuse consumer law with employment law, writing about fair wages or working conditions. This scores ZERO — no matter how detailed the answer is. The mark scheme explicitly states: \"No further marks can be gained without understanding\" of what consumer law actually requires.</p>\n        ", "check": {"question": "Why does ''Consumer law protects customers'' score 0 marks as an answer to a 1-mark identify question?", "options": ["It is factually incorrect about consumer rights", "It wrongly confuses consumer law with employment law", "It is too long for a 1-mark question", "It is too vague to identify a specific protection"], "answer": 3, "explain": "The card explains this answer is too vague — it doesn''t identify any specific protection required under consumer law."}}, {"title": "Identify It, Then Apply It to the Business", "html": "\n          <p>A 2-mark <strong>''Explain''</strong> question requires you to name an impact of consumer law AND link it specifically to the business named in the question. Two clear steps — one per mark.</p>\n    \n          <p><strong>The 2-Step Formula:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Identify the impact (1 mark):</strong> Name a specific way consumer law affects businesses.</li>\n            <li><strong>Step 2 — Apply to the specific business (1 mark):</strong> Use a detail from the case study to show how this applies to that particular business.</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n          <em>\"Consumer law could affect Tesco''s reputation.\"</em><br/>\n          Identifies an impact but does not apply it to Tesco specifically using case study detail.</p>\n    \n          <p><strong>✅ Good Answer (2 marks):</strong><br/>\n          <em>\"If Tesco plc sells products which are not as described (K — 1 mark), it could receive poor press coverage leading to a loss of sales (APP — 1 mark applied to Tesco as a major UK retailer).\"</em></p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> You only need ONE impact, explained and applied to the business. Writing everything you know about consumer law will NOT earn more marks — only one applied point is needed.</p>\n        ", "check": {"question": "What are the two steps required to earn full marks on a 2-mark ''Explain'' question?", "options": ["State three separate requirements of consumer law", "Identify an impact, then apply it to the business", "Identify an impact and then evaluate its importance", "Give two direct quotes from the case study"], "answer": 1, "explain": "The 2-step formula is: Step 1 identify a specific impact, Step 2 apply it to the named business using case study detail."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n          <p>A 3-mark <strong>''Analyse''</strong> question is the most common extended question on consumer law. You must follow a strict 3-step structure — missing any one step costs you marks. And without demonstrating understanding of consumer law first, you cannot earn ANY further marks.</p>\n    \n          <p><strong>The 3-Step Formula:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Understanding (U — 1 mark):</strong> State a specific requirement of consumer law: \"Consumer law requires goods to be of satisfactory quality / fit for purpose / as described.\"</li>\n            <li><strong>Step 2 — Application (APP — 1 mark):</strong> Link directly to the specific business in the case study using a quoted or paraphrased detail from the text.</li>\n            <li><strong>Step 3 — Analysis (AN — 1 mark):</strong> State the financial or operational impact: costs, profit, reputation, or sales. Keep asking \"So what does this mean for the business?\" until you hit a bottom-line impact.</li>\n          </ul>\n    \n          <p><strong>⚠️ Zero-Mark Trap — Consumer Law vs. Ethical Issues:</strong> Writing about wages, working conditions, or ethical sourcing instead of consumer law will score ZERO — even with perfect application and analysis. The examiner''s report confirms many candidates scored zero for this exact reason.</p>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n          <em>\"One impact of consumer law is that Primark must pay workers a fair wage. Primark sells at cheaper prices than most retailers, so this increases costs.\"</em><br/>\n          This confuses consumer law with employment law. ZERO marks despite having application and analysis.</p>\n    \n          <p><strong>✅ Good Answer (3 marks):</strong><br/>\n          <em>\"Consumer law requires goods to be ''not as described'' (U — 1 mark). If Primark Ltd sells clothing or homeware products that do not match their online description (APP — 1 mark to Primark as a low-price retailer), the business could face large volumes of returned goods. Since Primark operates on very tight profit margins, the additional refund costs could significantly reduce overall profitability (AN — 1 mark).\"</em></p>\n    \n          <p><strong>Sentence Starters to use:</strong></p>\n          <ul>\n            <li><em>\"Consumer law requires goods to be... (U)\"</em></li>\n            <li><em>\"In the case of [Business]... / Because the text states that... (APP)\"</em></li>\n            <li><em>\"This will lead to... / As a result, the business will... / This reduces... meaning... (AN)\"</em></li>\n          </ul>\n        ", "check": {"question": "What are the three steps of the ''Holy Trinity'' structure for a 3-mark analyse question?", "options": ["Application, Evaluation, Reasoning", "Identify, Explain, Conclude", "Understanding, Application, Analysis", "Knowledge, Evaluation, Justification"], "answer": 2, "explain": "The 3-step formula for a 3-mark analyse question is U (Understanding) → APP (Application) → AN (Analysis)."}}, {"title": "Four Paragraphs: Two Impacts + a Justified Conclusion", "html": "\n          <p>A 7-mark question is the most demanding on this topic. You need two separately analysed impacts (with case study application) and a justified evaluative conclusion. Marks: APP (2) + AN (2) + EV (3).</p>\n    \n          <p><strong>The 4-Paragraph Structure:</strong></p>\n          <ul>\n            <li><strong>Para 1 — K & U:</strong> Introduce a key requirement of consumer law and explain what this means for a business in general terms.</li>\n            <li><strong>Para 2 — APP & AN (Impact 1):</strong> Apply your first point to the case study using specific details from the text. Analyse the specific financial or operational impact on the business.</li>\n            <li><strong>Para 3 — APP & AN (Impact 2):</strong> Introduce a second, different impact. Apply and analyse in the same way — it must be a different consequence from Para 2.</li>\n            <li><strong>Para 4 — Evaluation (3 marks):</strong>\n              <ul>\n                <li><strong>Decision (1 mark):</strong> A clear, direct judgement — e.g. \"Consumer law is very important to QUA\" or \"It is more beneficial to comply than not.\"</li>\n                <li><strong>Context (1 mark):</strong> Justify your decision using a specific detail from the case study.</li>\n                <li><strong>Impact/Reasoning (1 mark):</strong> Use a ''depends on'' or ''however'' argument to show nuanced thinking — e.g. \"However, this depends on whether QUA can resolve the quality issues quickly before more negative coverage spreads.\"</li>\n              </ul>\n            </li>\n          </ul>\n    \n          <p><strong>⚠️ Evaluation Warning:</strong> A conclusion that simply repeats your earlier points scores ZERO evaluation marks. Your conclusion must make a NEW, justified judgement that goes beyond what you said in Paragraphs 2 and 3.</p>\n    \n          <p><strong>Evaluation Sentence Starters:</strong></p>\n          <ul>\n            <li><em>\"Overall, I believe consumer law is [very important / more beneficial / more harmful] to [Business] because...\" (Decision)</em></li>\n            <li><em>\"This is particularly significant because the text states that... (Context)\"</em></li>\n            <li><em>\"However, the full impact will depend on whether... / This matters more because the business... (Reasoning)\"</em></li>\n          </ul>\n        ", "check": {"question": "How many marks are allocated to Evaluation (EV) in a 7-mark ''Evaluate/Discuss'' question?", "options": ["2 marks", "4 marks", "7 marks", "3 marks"], "answer": 3, "explain": "The 7 marks split as APP (2) + AN (2) + EV (3), so Evaluation is worth 3 marks."}}, {"title": "Consumer Law ≠ Ethical Behaviour. Know the Difference.", "html": "\n          <p>This is the <strong>single most common reason students score zero</strong> on consumer law questions. The examiner''s report explicitly highlighted this as the major failure point across multiple exam sittings.</p>\n    \n          <p><strong>✅ Consumer Law — Legal Requirements (Scoreable):</strong></p>\n          <ul>\n            <li>Goods must be of satisfactory quality ✅</li>\n            <li>Goods must be fit for purpose ✅</li>\n            <li>Goods must be as described ✅</li>\n            <li>Compensation rights for defective or dangerous products ✅</li>\n            <li>30-day return right for faulty goods ✅</li>\n          </ul>\n    \n          <p><strong>❌ NOT Consumer Law — Ethical / Employment Issues (Scores Zero):</strong></p>\n          <ul>\n            <li>Paying workers a fair or living wage ❌</li>\n            <li>Using sustainable or ethical suppliers ❌</li>\n            <li>Reducing environmental impact ❌</li>\n            <li>Treating employees fairly ❌</li>\n            <li>Supporting local communities ❌</li>\n          </ul>\n    \n          <p><strong>📋 Direct from the 2025 Examiner''s Report:</strong><br/>\n          <em>\"Many candidates did not understand consumer law and mixed it up with employment law (many referred to employee rights, fair pay, or working conditions) or ethical considerations. These candidates could not be credited with any marks, despite having application and analysis, due to not specifying any correct understanding.\"</em></p>\n    \n          <p><strong>The Simple Test:</strong> Can you link your point back to \"satisfactory quality,\" \"fit for purpose,\" or \"as described\"? If not, you are likely writing about the wrong topic. Stop and refocus.</p>\n        ", "check": {"question": "What is the ''Simple Test'' recommended to check whether a point is genuinely about consumer law?", "options": ["Is the point longer than two written sentences?", "Does it directly reference the Consumer Protection Act?", "Can the point be linked to one of the three requirements?", "Does it mention a named business from the case study?"], "answer": 2, "explain": "The Simple Test checks whether a point can be linked back to one of the three requirements: satisfactory quality, fit for purpose, or as described."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one impact of consumer law on Primark Ltd. [3 marks]", "marks": 3, "hint": "Think about the three legal requirements (satisfactory quality, fit for purpose, as described). Do NOT write about wages or ethical suppliers — these are ethical issues, NOT consumer law, and will score zero. You must link your chosen impact specifically to Primark as a fashion retailer.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark — AO1b):</strong> States a correct aspect of consumer law — e.g. goods must be of satisfactory quality / fit for purpose / as described / need to comply with the Consumer Rights Act 2015 / products must meet the standard set.</li><li><strong>Application (1 mark — AO2):</strong> Links directly to Primark using a detail from the case study — e.g. Primark is a fashion retailer / sells clothing and homeware / uses low-cost suppliers / prices lower than most retailers / sells online / offers click and collect.</li><li><strong>Analysis (1 mark — AO3a):</strong> Explains the specific financial or operational impact — e.g. higher costs due to quality assurance / need to use better raw materials / potential for returns which leads to loss of profit / not making products fit for purpose negatively affects reputation / financial impact of fines for not complying with the law.</li></ul><p><strong>Critical Guidance:</strong> NO marks can be awarded without first demonstrating understanding of consumer law. Answers about paying fair wages or using ethical/sustainable suppliers score ZERO — these are ethical issues, not legal consumer law requirements.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments (2025)</h5><p>This question had a high omit rate and was not well answered. Only around one in five candidates correctly identified consumer law. The best answers cited ''fit for purpose'' or ''satisfactory quality'' and went on to link this to the cost of quality assurance or the high volume of returns — especially relevant for a low-price retailer like Primark where margins are already thin.</p><p>Many candidates confused consumer law with employment law (fair pay, working conditions) or ethical issues (sustainable suppliers, living wage). Despite having good application and analysis, these answers scored zero because they lacked any understanding of consumer law. The mark scheme on all similar questions makes clear: \"No further marks can be gained without understanding.\"</p></div><div class=\"marks-section\"><h5>Exemplar Model Answer (3/3)</h5><p>If Primark Ltd sells some of its clothing and homeware products which are ''not as described'' (U — 1 mark), customers could return large volumes of goods for refunds (APP — 1 mark to Primark as a fashion retailer selling online). Since Primark operates on very thin profit margins due to its low-price model, the additional costs of processing these returns and funding refunds could significantly reduce overall profitability (AN — 1 mark).</p></div>"}, {"question": "A company makes wooden jigsaw puzzles. By law, the company must: [1 mark]", "marks": 1, "hint": "Consumer law is about the safety and quality of the product itself — not about where raw materials come from or how the product is delivered.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Use paint that is non-toxic and safe (1 mark)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Buy its wood from local suppliers:</strong> Consumer law does not specify where raw materials must be sourced from. Using local suppliers may be an ethical or logistical choice, but it has no legal requirement under the Consumer Rights Act 2015.</li><li><strong>B — Deliver in electric vans:</strong> The method of delivery is not regulated by consumer law. This may relate to environmental responsibility, but the Consumer Rights Act does not require a specific delivery method.</li><li><strong>C — Replace pieces customers lose:</strong> The Consumer Rights Act does not require businesses to replace items lost through customer negligence. Consumer rights apply to faults present at the time of purchase — not losses caused by the customer.</li><li><strong>D — Use non-toxic and safe paint (CORRECT):</strong> Consumer law requires goods to be of satisfactory quality and safe to use. Using non-toxic paint ensures the product is safe for the consumer — especially critical for a product that children might handle.</li></ul></div>"}, {"question": "A customer has bought a laptop from a computer shop. By law, the computer shop must: [1 mark]", "marks": 1, "hint": "Think about the three key requirements of the Consumer Rights Act 2015. Which one applies directly here?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Supply a laptop of satisfactory quality (1 mark — AO2)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Match the price of a local competitor:</strong> Price matching is not a legal requirement. Consumer law does not regulate pricing — businesses are free to charge what they choose.</li><li><strong>B — Offer a free upgrade:</strong> Upgrades are a customer service gesture, not a legal obligation. The Consumer Rights Act does not require businesses to offer product upgrades at any point.</li><li><strong>C — Provide virus protection:</strong> Installing software or providing cybersecurity is not a requirement under consumer law. It may be offered as an extra service, but the Consumer Rights Act 2015 does not mandate it.</li><li><strong>D — Supply a laptop of satisfactory quality (CORRECT):</strong> The Consumer Rights Act 2015 requires all goods to be of satisfactory quality — free from defects and appropriate for the price paid. This is the core legal obligation of any seller.</li></ul></div>"}, {"question": "Identify one way consumer law protects consumers. [1 mark]", "marks": 1, "hint": "You only need ONE specific point. Think about the three requirements of the Consumer Rights Act 2015 — any one of them is a valid answer. Do not write about the environment or worker pay.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p>1 mark for a correct identification of how consumer law protects consumers.</p><p><strong>Acceptable answers include:</strong></p><ul><li>Products must be of satisfactory quality</li><li>Products must be fit for purpose</li><li>Products must be as described</li><li>Provides customer rights, including the return of faulty products</li><li>Compensation for damage or injury caused by defective products</li></ul><p><strong>Note:</strong> Only accept references to how consumers are protected — not how businesses are affected. Accept correct examples of specific consumer laws (e.g. Consumer Protection Act 1987). Do NOT accept ethical issues such as sustainability or fair wages.</p></div>"}, {"question": "A customer has ordered an electric shower from a plumbing firm. By law, the plumbing firm must: [1 mark]", "marks": 1, "hint": "Consumer law focuses on the safety and quality of goods supplied — not on pricing or the environmental sourcing of materials.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Supply a shower that meets current safety standards (1 mark)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Charge a lower price than other plumbers:</strong> Pricing is not regulated by consumer law. There is no legal obligation to undercut competitors — businesses are free to set their own prices.</li><li><strong>B — Fit the shower without turning the water off:</strong> This is not a requirement of consumer law, and would in fact be dangerous and unsafe — directly contradicting the spirit of consumer protection legislation.</li><li><strong>C — Supply a shower that meets current safety standards (CORRECT):</strong> Consumer law requires goods and services to be of satisfactory quality, which includes meeting current safety standards. A shower must be safe, functional, and fit for the purpose of providing hot water.</li><li><strong>D — Use an environmentally friendly supplier:</strong> Environmental sourcing is an ethical consideration, not a legal consumer law requirement. Consumer law is about the rights of the buyer — not the environmental practices of the supply chain.</li></ul></div>"}, {"question": "Explain one way consumer law may impact Tesco plc. [2 marks]", "marks": 2, "hint": "You need ONE impact on Tesco specifically — use a detail from the case study. Structure: identify the impact of consumer law (1 mark) + apply it specifically to Tesco using the case study (1 mark).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a 1 mark + AO2 1 mark)</h5><ul><li><strong>Knowledge/Identify (1 mark — AO1a):</strong> Names a specific way consumer law may impact a business — e.g. impact on the reputation of the business / impact on the safety of the consumer / impact on the quality of goods / cost of compliance with the law / fines for not complying.</li><li><strong>Application (1 mark — AO2):</strong> Applies the impact specifically to Tesco plc using a detail from the case study — e.g. references Tesco''s wide range of products / its e-commerce operations / its core purpose of being a ''champion for customers'' / the range of UK and foreign suppliers it uses.</li></ul></div><div class=\"marks-section\"><h5>Model Answer</h5><p>One possible impact is that if Tesco plc sells products which are not as described (K — 1 mark), it could receive poor press coverage which then leads to a poor reputation and a significant loss of sales (APP — 1 mark, applied to Tesco as a major UK retailer operating across shops and e-commerce).</p></div>"}, {"question": "Consumer law requires shops to sell goods that are: [1 mark]", "marks": 1, "hint": "Consumer law doesn''t require goods to be the best or the cheapest — think about the word used in the law itself for the quality requirement.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Safe (1 mark — AO1a)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Cheap:</strong> Consumer law does not require goods to be cheap. There is no price regulation in the Consumer Rights Act 2015 — businesses are free to charge market rates.</li><li><strong>B — High quality:</strong> This is the most common wrong answer. The law requires ''satisfactory quality'' — a standard that reflects the price paid — NOT the highest possible quality. Luxury goods must be high quality; budget goods only need to meet a lower, price-appropriate standard.</li><li><strong>C — Safe (CORRECT):</strong> Consumer law requires goods to be safe and of satisfactory quality. Safety is a core requirement — goods must not cause harm to the consumer when used as intended.</li><li><strong>D — Unique:</strong> Consumer law places no requirement on uniqueness or exclusivity. There is no legal reason a business cannot sell standard, mass-produced goods.</li></ul></div>"}, {"question": "Consumer law requires shops to sell goods which are: [1 mark]", "marks": 1, "hint": "Think about the exact wording used in the Consumer Rights Act 2015 for the quality requirement.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Of satisfactory quality (1 mark — AO1a)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Environmentally friendly:</strong> Environmental responsibility is an ethical choice, not a legal consumer law requirement. The Consumer Rights Act 2015 makes no mention of environmental standards.</li><li><strong>B — Of satisfactory quality (CORRECT):</strong> The Consumer Rights Act 2015 specifically requires goods to be of satisfactory quality — not defective or damaged when sold, and appropriate for the price paid. This is one of the three core legal requirements.</li><li><strong>C — Reasonably priced:</strong> Consumer law does not regulate pricing. Businesses are free to charge market rates. ''Reasonably priced'' is not a requirement found anywhere in the Consumer Rights Act 2015.</li><li><strong>D — Unique:</strong> Consumer law places no requirement on uniqueness. Mass-produced, standard goods are perfectly legal to sell and fully covered by consumer law.</li></ul></div>"}, {"question": "State two possible effects on a business of consumer law. [2 marks]", "marks": 2, "hint": "You need TWO separate effects — these are simple 1-mark statements, no explanation is required. Think about what could happen to a business if its products don''t meet consumer law requirements.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a / Knowledge)</h5><p>1 mark for each correct effect. No explanation required — these are knowledge-only marks.</p><p><strong>Acceptable answers include (any two):</strong></p><ul><li>The quality of their products/services must meet legal standards</li><li>Their products must be safe to use</li><li>The business may face compensation claims from customers</li><li>The business may lose its reputation</li><li>The business may have to provide refunds to customers</li><li>Customers may return faulty goods, increasing costs</li><li>The business could face legal action or court cases</li><li>Products must be as described / fit for purpose</li><li>The business may have to recall or stop selling faulty products</li></ul></div>"}, {"question": "Evaluate the importance of consumer law on the running of a business such as QUA. [7 marks]", "marks": 7, "hint": "Write TWO separate impacts of consumer law on QUA (use specific details from the case study to earn application marks). Analyse the business impact of each one. Then write a justified conclusion — make a judgement and back it up using QUA''s specific situation. Do NOT just repeat your earlier analysis in the conclusion.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><ul><li><strong>Application — AO2 (2 marks):</strong> Two separate examples relating specifically to QUA from the case study.</li><li><strong>Analysis — AO3a (2 marks):</strong> Two separate explanations of the effect/impact on QUA as a business.</li><li><strong>Evaluation — AO3b (3 marks):</strong> Judgement (1 mark) + Contextual justification using the case study (up to 2 marks).</li></ul></div><div class=\"marks-section\"><h5>Application Points — Must Refer Specifically to QUA</h5><ul><li>QUA''s new model has quality problems identified by consumers / machine not cleaning dishes thoroughly</li><li>QUA has had a good reputation for years — customers praise the quality of a ''QUA wash''</li><li>Falling sales of the new model since quality problems emerged</li><li>Negative comments appearing on social media, specifically mentioning consumer law being used against QUA</li><li>Abigail wants to halt production; Jason argues stopping would cost a lot of money</li></ul></div><div class=\"marks-section\"><h5>Analysis Points — Impact on QUA as a Business</h5><ul><li>If QUA''s reputation falls, previous loyal customers will not return to purchase the new dishwasher model</li><li>Falling sales of the new model &rarr; income/revenue for QUA will decline</li><li>Possible compensation claims against QUA &rarr; significant additional costs for the business</li><li>Cost of halting production (Abigail''s plan) vs. long-term cost of continued reputational damage</li><li>Further social media coverage could amplify the damage beyond existing customers</li></ul></div><div class=\"marks-section\"><h5>Evaluation — AO3b (3 marks)</h5><ul><li><strong>Judgement (1 mark):</strong> A clear, direct statement — e.g. \"I think that consumer law is very important to the running of a business such as QUA.\"</li><li><strong>Justification (up to 2 marks):</strong> A single, clearly explained idea using QUA''s specific context can earn up to 2 marks. Example: \"Consumer law is very important because QUA has already received negative comments on social media mentioning consumer law. If consumers take QUA to court, the business may face not only compensation costs but the destruction of the strong reputation it has built over many years — which would be extremely difficult to recover from. QUA must resolve the quality issues urgently or the long-term damage to sales may outweigh any short-term saving from continuing production.\"</li></ul></div>"}, {"question": "State the three parts of consumer law that businesses must meet. [3 marks]", "marks": 3, "hint": "This is a pure knowledge question — no explanation or application needed. Simply name all three requirements of the Consumer Rights Act 2015. One mark per correct part.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1 Knowledge)</h5><p>1 mark for each correct part stated. No explanation required.</p><ul><li><strong>1 mark:</strong> Of satisfactory quality</li><li><strong>1 mark:</strong> Fit for purpose</li><li><strong>1 mark:</strong> As described</li></ul><p>All three parts must be stated to achieve full marks. Any other answers score zero — these three are the only requirements students are expected to state for this topic.</p></div>"}, {"question": "Discuss the implications on Delicious Cakes of complying with Consumer Law. [7 marks]", "marks": 7, "hint": "Use TWO specific pieces of information from the Delicious Cakes case study (AP marks). Analyse the implication of each piece for the business (AN marks). Then write a justified conclusion evaluating whether it is more or less beneficial for Delicious Cakes to comply with consumer law. Use the case study to support your conclusion.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><ul><li><strong>Application — AP (2 marks):</strong> Uses 2 specific pieces of information from the Delicious Cakes case study.</li><li><strong>Analysis — AN (2 marks):</strong> Analyses each piece — what is the actual implication for the business?</li><li><strong>Evaluation — EV (3 marks):</strong> Is it more or less beneficial for Delicious Cakes to comply with consumer law? Justified with reasons using the case study.</li></ul></div><div class=\"marks-section\"><h5>Application Points — Must Refer to Delicious Cakes</h5><ul><li>Ingredients clearly on display for allergy checking &rarr; relates to ''as described'' requirement</li><li>Only the freshest ingredients are used, fridge checked daily &rarr; relates to ''satisfactory quality''</li><li>All equipment is up to date &rarr; helps ensure goods are consistently of satisfactory quality</li><li>Excellent reputation — customers describe cakes as ''excellent value for money'' &rarr; benefits of compliance already visible</li><li>The business recently had a full inspection which found good practice throughout</li></ul></div><div class=\"marks-section\"><h5>Analysis Points — Implications for Delicious Cakes</h5><ul><li>Displaying ingredients reduces risk of consumer complaints or legal action regarding allergens &rarr; protects the business from costly claims</li><li>Using fresh ingredients reduces risk of producing substandard cakes &rarr; fewer refund demands and less reputational damage</li><li>Up-to-date equipment maintains consistent quality &rarr; reduces risk of producing faulty goods that breach the Consumer Rights Act</li><li>Maintaining quality has helped build the excellent reputation &rarr; this reputation increases customer loyalty and long-term sales</li><li>Cost of compliance (fresh ingredients, updated equipment) &rarr; increases operating costs and may reduce short-term profits</li></ul></div><div class=\"marks-section\"><h5>Evaluation — EV (3 marks)</h5><ul><li><strong>Decision (1 mark):</strong> Clear statement — e.g. \"I believe it is more beneficial for Delicious Cakes to comply with consumer law.\"</li><li><strong>Contextual Justification (up to 2 marks):</strong> Uses specific case study detail. A single, well-explained reason drawing on Delicious Cakes'' specific context can earn 2 marks. Example: \"Delicious Cakes has built an excellent reputation over 10 years, and this reputation is the business''s main competitive advantage. If the business were to breach consumer law — for example, by mislabelling ingredients — it would face not only compensation costs but the rapid destruction of the customer trust that has taken 10 years to build. The ongoing cost of compliance (fresh ingredients, up-to-date equipment) is far lower than the potential cost of non-compliance, particularly for a small family business where a single legal case or viral complaint could permanently damage the brand.\"</li></ul></div>"}]}}'::jsonb),
('business', '4-5-business-location', '4.5 Business Location', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>Understanding the key vocabulary for business location is essential for exam success.</p>\n<ul>\n  <li><strong>Location:</strong> The place where a business is sited.</li>\n  <li><strong>Proximity:</strong> Means ''nearness to'' — e.g., proximity to the market means being close to customers.</li>\n  <li><strong>Transport infrastructure:</strong> The provision of roads, railways, ports and airports in an area for transporting goods and people, including ICT infrastructure such as broadband.</li>\n  <li><strong>Labour:</strong> A factor of production — the workers employed by businesses to produce goods and services.</li>\n  <li><strong>Raw materials:</strong> Materials that are processed in some way as part of the manufacture of a product.</li>\n  <li><strong>Enterprise zone:</strong> A government-designated area where businesses are offered incentives such as reduced business rates, lower taxes on investment, and superfast broadband to encourage them to locate there.</li>\n  <li><strong>Freeport:</strong> An area where businesses can import goods without paying tariffs or VAT — duties are only payable if goods are sold in the wider UK market.</li>\n  <li><strong>Northern Powerhouse:</strong> A UK Government initiative to encourage businesses to locate, stay and expand in the north of England by improving infrastructure and providing funding from Liverpool to Hull.</li>\n</ul>", "check": {"question": "What is the key difference between an Enterprise Zone and a Freeport?", "options": ["They are identical — both offer the exact same package of incentives to businesses", "Enterprise zones cut business rates and taxes; freeports also let firms import goods tariff-free", "Freeports are only open to food and farming businesses, unlike enterprise zones", "Enterprise zones let firms import goods tariff-free, while freeports only cut business rates"], "answer": 1, "explain": "Enterprise zones offer incentives like reduced business rates, lower taxes on investment, and superfast broadband. Freeports go further — goods can be imported without paying tariffs or VAT until they enter the wider UK market, making them especially attractive for businesses that import, process and re-export."}}, {"title": "Why Location Matters", "html": "<p>For many businesses, choosing <strong>where to locate</strong> is one of the most critical decisions they make. The right location can help a business flourish; the wrong one can make success almost impossible.</p>\n<p>Location affects a business across multiple areas:</p>\n<ul>\n  <li>The <strong>costs</strong> of running the business (rent, wages, transport)</li>\n  <li>Access to <strong>customers</strong> and sales potential</li>\n  <li>Access to <strong>skilled workers</strong></li>\n  <li>Access to <strong>raw materials</strong> and suppliers</li>\n</ul>\n<p>It is rarely just <strong>one</strong> factor that determines where a business locates — usually it is a <strong>combination of factors</strong>. As globalisation increases, some businesses (especially multinationals) consider locations in different countries, not just different regions.</p>\n<div class=\"case-study-box\">\n  <h4>Key Evaluation Point</h4>\n  <p>Proximity to the market remains a very important factor for many businesses. However, the growth of internet selling and the reduction in transport and shipping costs has made it possible for more and more businesses to compete even when not near their customers. A business like <strong>Amazon</strong> competes effectively by selling vast quantities at low prices from strategically positioned warehouses — proximity to the customer is far less important than proximity to a good road network.</p>\n</div>", "check": {"question": "Why is Amazon''s location strategy different from that of a traditional retailer?", "options": ["Amazon ignores location completely, since online sales make the site irrelevant", "Amazon values good road links over closeness to customers, selling from warehouses", "Amazon needs to sit right next to its customers, just like a high street shop", "Amazon''s warehouse sites are chosen purely by where its raw material suppliers sit"], "answer": 1, "explain": "Amazon sells online at high volumes, so being near a motorway network for fast delivery matters far more than being near any individual customer — unlike a high street retailer which relies on footfall."}}, {"title": "Factor 1: Costs", "html": "<p>The <strong>cost of production</strong> varies significantly between locations. Businesses look for sites where costs are kept as low as possible without sacrificing access to key resources.</p>\n<ul>\n  <li><strong>Site and premises costs:</strong> Rents in prosperous cities like London and Cambridge are far higher than in areas with declining industries like Teesside. The cost of the location must be recovered through the prices charged — higher costs can reduce competitiveness.</li>\n  <li><strong>Labour costs:</strong> Wages vary by region. In 2021, the average salary in London was £38,000 vs £33,000 in Leeds — a significant saving for employers considering a move north.</li>\n  <li><strong>Transport costs:</strong> Good road, rail, sea and air links reduce the cost of moving raw materials and finished goods.</li>\n  <li><strong>ICT infrastructure:</strong> Fast broadband and reliable digital communications are increasingly essential for modern businesses.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Cambridge Research Biochemicals (CRB)</h4>\n  <p>CRB produces peptides and antibodies. Originally based in Cambridge, it moved to Billingham in Teesside in 1999 because rents there were only <strong>10% of those in Cambridge</strong>. Labour was also cheaper. In 2014, CRB used a government ''Let''s Grow'' grant of £65,000 to move to the Teesside Valley enterprise zone — receiving both cost savings and government support.</p>\n  <p><strong>Takeaway:</strong> Production cost savings can be so significant that businesses relocate over long distances. Government incentives can make the decision even more attractive.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Burberry</h4>\n  <p>Burberry — a luxury fashion brand with a Royal Warrant — moved production from Wales to China because UK factory and labour costs were higher than almost anywhere else in the world.</p>\n  <p><strong>Takeaway:</strong> Even prestigious brands prioritise cost efficiency, especially when manufacturing is labour-intensive.</p>\n</div>", "check": {"question": "Cambridge Research Biochemicals moved to Teesside in 1999. What was the key financial reason?", "options": ["Teesside offered much faster transport links into central London than Cambridge did", "Rents in Teesside were only 10% of Cambridge rents, saving huge sums", "Government regulations legally required all biochemical firms to relocate to Teesside", "Cambridge had completely lost its supply of skilled biochemical research workers"], "answer": 1, "explain": "CRB relocated because rents in Teesside were only 10% of Cambridge rents — a 90% reduction in premises costs. This was further enhanced in 2014 by a £65,000 government ''Let''s Grow'' grant when they moved into the Teesside Valley enterprise zone."}}, {"title": "Factor 2: Proximity to the Market", "html": "<p><strong>Proximity to the market</strong> means locating close to the business''s customers. This is especially important for service businesses and retailers.</p>\n<ul>\n  <li><strong>Service businesses</strong> (e.g., hairdressers, dentists, cafés) must locate near consumers, who are unlikely to travel far.</li>\n  <li><strong>Retailers</strong> consider the number of potential customers, the level of competition, and whether the local population will buy the product.</li>\n  <li><strong>Manufacturers</strong> may locate near buyers for easy communication and to reduce delivery costs — e.g., Toyota Tsusho UK makes wheels for Jaguar Land Rover cars and is sited just 33 miles from JLR''s Castle Bromwich assembly plant.</li>\n  <li><strong>Online businesses</strong> have changed this dynamic — they need good transport links for their warehouses rather than a high-street location.</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Locating Near the Market</div>\n    <div class=\"pro-item\"><strong>Higher footfall:</strong> More passing customers means greater potential sales revenue for retailers and service businesses.</div>\n    <div class=\"pro-item\"><strong>Lower delivery costs:</strong> Shorter distances to customers reduce transport expenses for manufacturers.</div>\n    <div class=\"pro-item\"><strong>Better communication:</strong> Easier to respond quickly to customer needs, complaints and orders.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Drawbacks of Locating Near the Market</div>\n    <div class=\"con-item\"><strong>Higher rents:</strong> Prime locations (town centres, airports) command much higher rental costs, increasing overheads.</div>\n    <div class=\"con-item\"><strong>More competition:</strong> Popular locations attract rival businesses, increasing competitive pressure and potentially driving down prices.</div>\n    <div class=\"con-item\"><strong>Not always necessary:</strong> Online businesses and manufacturers of small, lightweight goods do not always need to be near their customers.</div>\n  </div>\n</div>", "check": {"question": "Toyota Tsusho UK makes wheels for Jaguar Land Rover and is located just 33 miles from JLR''s Castle Bromwich plant. Which location factor does this best illustrate?", "options": ["Proximity to raw materials — Toyota Tsusho needs steel supplies close by", "Proximity to market — Toyota Tsusho sits near JLR to cut delivery costs", "Government incentives — the West Midlands site sits inside an enterprise zone", "Labour availability — Castle Bromwich has a large pool of skilled engineers"], "answer": 1, "explain": "Toyota Tsusho UK is a manufacturer whose main customer is JLR. Locating 33 miles away reduces delivery costs for bulky car wheels and makes it easier to respond quickly to JLR''s production schedule — a classic example of a manufacturer locating near its market."}}, {"title": "Factor 3: Proximity to Raw Materials", "html": "<p>Some businesses — particularly <strong>manufacturers</strong> — need to locate close to their raw material sources. This is most important when:</p>\n<ul>\n  <li>Raw materials are <strong>bulky</strong> and costly to transport (e.g., wheat, iron ore, stone).</li>\n  <li>Raw materials are <strong>perishable</strong> (e.g., fresh milk for cheese-making).</li>\n  <li>The finished product is <strong>smaller and lighter</strong> than the raw material, making it more efficient to process on-site before transporting.</li>\n</ul>\n<p>There is also an <strong>environmental benefit</strong>: shorter supply chains reduce carbon emissions and help businesses present themselves as environmentally responsible.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Cargill Foods, Liverpool Docks</h4>\n  <p>Cargill Foods processes wheat imported from several countries. Its factory is located directly on the Liverpool docks — wheat arriving by ship is unloaded straight into the factory. If the factory were elsewhere, the wheat would need to be loaded onto lorries, transported, and unloaded again, adding significant cost and time.</p>\n  <p><strong>Takeaway:</strong> When raw materials arrive by sea, locating at a port can dramatically cut transport costs and improve operational efficiency.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Dewlay Cheesemakers, Lancashire</h4>\n  <p>Dewlay buys milk from dairy farms within six miles of its dairy in Garstang, Lancashire. This reduces transport costs <em>and</em> allows Dewlay to market its ''green'' credentials — it was the first cheese producer to generate its own electricity from a wind turbine.</p>\n  <p><strong>Takeaway:</strong> Locating near raw materials can bring both financial savings and reputational benefits in an environmentally conscious market.</p>\n</div>", "check": {"question": "Why does Cargill Foods locate its factory directly on the Liverpool docks rather than inland?", "options": ["Liverpool offers the lowest labour costs of any UK port city", "Wheat is unloaded from ships straight into the factory, cutting cost", "Government regulations require all food processors to sit at ports", "Liverpool docks charge the cheapest factory rent of any UK location"], "answer": 1, "explain": "Cargill imports wheat by sea — locating at the docks means the wheat goes straight from ship to factory with no intermediate transport. Moving the factory inland would add lorry transport, extra loading/unloading, and significant cost."}}, {"title": "Factor 4: Proximity to Labour", "html": "<p>All businesses need workers. The availability and cost of <strong>labour</strong> in an area is a key location factor, especially when a business requires large numbers of workers or specific skills.</p>\n<ul>\n  <li>Businesses needing <strong>skilled workers</strong> may locate near universities or in established industry clusters. <strong>''Silicon Fen''</strong> near Cambridge is a concentration of ICT firms and skilled technology workers.</li>\n  <li>Businesses needing large numbers of <strong>unskilled or semi-skilled</strong> workers may target areas of high population or high unemployment, where labour is plentiful and wages may be lower.</li>\n  <li>In areas where traditional industries (coal mining, steel, shipbuilding) have declined, labour supply is often <strong>plentiful and relatively cheap</strong>.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Channel 4 Moves to Leeds</h4>\n  <p>Channel 4 opened additional headquarters in Leeds. Key reasons: office space costs £250–£300/month in Leeds vs £650–£2,500/month in London; average salaries are lower (£33,000 vs £38,000); and Leeds has three universities — three-quarters of Leeds Beckett graduates stay in the city, providing a strong talent pipeline.</p>\n  <p><strong>Takeaway:</strong> For office-based businesses, northern cities can offer a compelling mix of lower costs AND a well-educated, skilled labour pool.</p>\n</div>", "check": {"question": "What specific labour advantage did Leeds offer Channel 4 compared to London?", "options": ["Leeds has more television and media production studios", "Lower salaries plus strong graduate retention from universities", "Employment law requires Leeds staff to work longer hours", "The government pays Channel 4 staff salaries directly in Leeds"], "answer": 1, "explain": "Leeds offered Channel 4 both lower salaries (£33,000 vs £38,000 in London) and a ready supply of graduates — three-quarters of Leeds Beckett graduates stay in the city — making it both cheaper and talent-rich compared to London."}}, {"title": "Factor 5: Government Influence", "html": "<p>Governments — national and local — often try to <strong>influence where businesses locate</strong> to create jobs and raise incomes in specific regions.</p>\n<ul>\n  <li><strong>Enterprise Zones (48 in the UK):</strong> Businesses benefit from reduced business rates, higher capital allowances (lower taxes on investment), superfast broadband, faster planning approvals, and ready-built premises. Four enterprise zones are in South Wales.</li>\n  <li><strong>Freeports (8 announced in 2021):</strong> Businesses can import goods without paying tariffs or VAT. If goods are exported after processing, no duties are paid at all — encouraging trade, investment and job creation.</li>\n  <li><strong>The Northern Powerhouse:</strong> Invests in infrastructure and provides funds for businesses starting or growing in northern England, from Liverpool to Hull.</li>\n  <li><strong>Regional Growth Funds:</strong> One-off government grants to help businesses relocate or expand in high-unemployment areas (e.g., CRB''s £65,000 ''Let''s Grow'' grant).</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Government Incentives</div>\n    <div class=\"pro-item\"><strong>Reduced costs:</strong> Lower business rates and taxes directly improve profitability for businesses locating in enterprise zones.</div>\n    <div class=\"pro-item\"><strong>Grant funding:</strong> One-off financial support reduces start-up or relocation costs significantly.</div>\n    <div class=\"pro-item\"><strong>Infrastructure improvements:</strong> Government investment in roads, broadband, and buildings makes areas more attractive over time.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Limitations of Government Incentives</div>\n    <div class=\"con-item\"><strong>Temporary benefits:</strong> Incentives may not last forever — once they end, the underlying disadvantages of the location remain.</div>\n    <div class=\"con-item\"><strong>Other factors persist:</strong> Incentives alone cannot compensate for poor transport links, low skilled labour supply, or limited customer base.</div>\n    <div class=\"con-item\"><strong>Bureaucracy:</strong> Applying for grants or enterprise zone status can be time-consuming and the outcome is uncertain.</div>\n  </div>\n</div>", "check": {"question": "How many Enterprise Zones and Freeports were there in the UK at the time covered in this topic?", "options": ["8 Enterprise Zones and 48 Freeports", "48 Enterprise Zones and 8 Freeports", "4 Enterprise Zones and 4 Freeports", "100 Enterprise Zones and 20 Freeports"], "answer": 1, "explain": "There are 48 Enterprise Zones (including four in South Wales) and 8 Freeports announced in 2021. The numbers are easy to mix up — remember there are far more enterprise zones than freeports."}}, {"title": "Online vs Physical Location", "html": "<p>The rise of <strong>e-commerce</strong> has fundamentally changed location decisions. Online businesses have very different priorities to traditional high-street retailers.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of an Online/Warehouse Location</div>\n    <div class=\"pro-item\"><strong>Lower costs:</strong> Warehouses on the outskirts or in industrial areas have far lower rents than high-street shops, improving profit margins.</div>\n    <div class=\"pro-item\"><strong>Wider market reach:</strong> An online business is not restricted to local customers — it can sell nationally or globally from a single location.</div>\n    <div class=\"pro-item\"><strong>Location flexibility:</strong> The business can locate wherever land, labour, and transport links are most cost-effective.</div>\n    <div class=\"pro-item\"><strong>Scalability:</strong> Easier to expand warehouse space than to open multiple physical shops.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of an Online/Warehouse Location</div>\n    <div class=\"con-item\"><strong>No walk-in customers:</strong> Cannot benefit from passing trade or impulse purchases — all marketing must drive customers to the website.</div>\n    <div class=\"con-item\"><strong>Transport dependency:</strong> Must have excellent road/rail links and reliable delivery partners to reach customers on time.</div>\n    <div class=\"con-item\"><strong>Brand visibility:</strong> Without a physical presence, building brand recognition is harder and more expensive.</div>\n    <div class=\"con-item\"><strong>Returns logistics:</strong> Managing customer returns across a wide geographic area can be costly and complex.</div>\n  </div>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: The Wool Warehouse</h4>\n  <p>Set up in 2012, the Wool Warehouse deliberately chose a warehouse rather than a high street shop to enter the online yarn market. At the time, there were only 2–3 yarn suppliers online. Online sales took off, and by 2014 they doubled their warehouse space as their range expanded.</p>\n  <p><strong>Takeaway:</strong> Going online allowed the Wool Warehouse to enter a market with very little competition, reach customers nationally, and keep overheads low — all without needing a prime retail location.</p>\n</div>", "check": {"question": "When The Wool Warehouse launched in 2012, what market condition made the online strategy particularly attractive?", "options": ["There were hundreds of yarn competitors already selling online by that point", "There were only 2–3 yarn suppliers online, meaning almost no competition", "The government awarded them a large grant specifically to launch online sales", "Every high street yarn shop in the country had already shut down by 2012"], "answer": 1, "explain": "In 2012 there were only 2–3 online yarn suppliers — almost no competition. The Wool Warehouse seized that gap, reaching customers nationally without the cost of a high-street location. By 2014 they doubled their warehouse space as sales grew."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Location", "definition": "The place where a business is sited."}, {"term": "Proximity", "definition": "Nearness to something — e.g., proximity to the market means being close to customers."}, {"term": "Transport infrastructure", "definition": "Roads, railways, airports and ports that allow goods and people to move — also includes ICT infrastructure like broadband."}, {"term": "Enterprise zone", "definition": "A government-designated area offering incentives (reduced rates, lower taxes on investment, superfast broadband, faster planning) to attract businesses and create jobs."}, {"term": "Freeport", "definition": "An area where businesses import goods without paying tariffs or VAT — duties are only charged if goods are sold in the wider UK market."}, {"term": "Northern Powerhouse", "definition": "A UK Government scheme to invest in infrastructure and provide funding for businesses in the north of England, from Liverpool to Hull."}, {"term": "Silicon Fen", "definition": "A cluster of ICT firms and skilled technology workers located near Cambridge, UK — named after the flat Fens landscape of the region."}, {"term": "Proximity to market", "definition": "Locating close to customers to increase sales, improve communication, and reduce delivery costs — essential for service businesses and retailers."}, {"term": "Proximity to raw materials", "definition": "Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport."}, {"term": "Proximity to labour", "definition": "Locating where there is a sufficient supply of workers with the right skills — near universities for skilled roles, or in high-unemployment areas for unskilled roles."}, {"term": "Carbon footprint", "definition": "The total greenhouse gas emissions caused by a business — reduced by shorter supply chains and sourcing raw materials locally."}, {"term": "Key location factors (4)", "definition": "1. Costs (rent, wages, transport) → 2. Proximity to market → 3. Proximity to raw materials → 4. Proximity to labour. Government incentives can also influence all of these."}, {"term": "Why online businesses still need a location strategy", "definition": "Their warehouses must have good transport links, available labour, and affordable land — even without needing to be near customers."}, {"term": "Cost per unit formula", "definition": "Cost per unit = Total costs (rent + wages) ÷ Number of units produced. Used to compare the efficiency of different site locations."}, {"term": "Freeport vs Enterprise Zone — key difference", "definition": "Enterprise zones offer reduced domestic taxes and faster approvals. Freeports additionally allow TARIFF-FREE import of goods — particularly beneficial for businesses that import, process, and re-export products."}]}, "mcq": {"enabled": true, "questions": [{"question": "In the context of business operations, what does the phrase ''proximity to market'' refer to?", "options": ["Advertising the business specifically to those who live in the local area", "Locating a business close to its potential customers", "Only employing workers who are part of the local community", "Working on a site that is close to a source of raw materials"], "answer": 1, "explain": "Correct answer: ''Proximity to market'' means locating a business near its potential customers. A relates to marketing, C relates to proximity to labour, and D refers to proximity to raw materials — all separate location factors."}, {"question": "Which one of the following is the most likely reason for a greeting card manufacturer to locate its factory on an out-of-town industrial estate?", "options": ["Council incentives offering reduced business rates", "Greeting cards are destroyed if they get wet during transportation", "Lots of people who work on the industrial estate will buy cards", "The need to be close to the market because customers are unwilling to travel"], "answer": 0, "explain": "Correct answer: A greeting card manufacturer does not need to be near its final customers — cards are small and easy to transport. An industrial estate offers lower costs, and council incentives such as reduced business rates make it even more attractive. B is not valid (cards are packaged), C is incorrect (industrial workers are not a significant market), and D contradicts the out-of-town choice."}, {"question": "Which one of the following is a benefit of locating a tomato farm near to a ready supply of labour?", "options": ["Ease of recruitment of tomato pickers", "Personal contact with supermarket buyers", "Sales of fresh tomatoes are likely to increase", "The tomatoes will not need to be transported"], "answer": 0, "explain": "Correct answer: Locating near a supply of labour means the farm can easily recruit workers — in this case, tomato pickers. B relates to proximity to the market (customers), not labour. C is also about market proximity. D is incorrect — tomatoes still need to be transported to supermarkets regardless of where the farm is relative to its workers."}, {"question": "Which of the following is NOT a reason for a business to locate near to its market?", "options": ["It produces a large finished product", "It uses bulky raw materials to produce a smaller, finished product", "Its customers are not likely to travel far, nor shop over the internet", "It sells fresh products such as cream cakes"], "answer": 1, "explain": "Correct answer: Using bulky raw materials to produce a smaller finished product is a reason to locate near RAW MATERIALS, not near the market. The logic is that it''s cheaper to transport the light finished product than the heavy raw material. A, C, and D are all valid reasons to locate near the market."}, {"question": "Which one of these statements about business location is NOT true?", "options": ["Firms that produce small, finished products are best locating near to their market", "Governments often influence the location of businesses to reduce unemployment in certain areas", "Low-cost locations are important for every single producer", "Where a business locates is often influenced by more than one location factor"], "answer": 2, "explain": "Correct answer: It is NOT true that low-cost locations are important for every single producer. Some businesses prioritise skilled labour, prestige location, or proximity to customers over minimising costs (e.g., a luxury hotel in central London). A, B, and D are all true statements."}, {"question": "A firm is comparing four possible locations. Which site offers the lowest cost per unit produced?", "options": ["Site W: 10,000 units/year, rent £30,000, wages £80,000 → £11.00 per unit", "Site X: 12,000 units/year, rent £42,000, wages £102,000 → £12.00 per unit", "Site Y: 11,000 units/year, rent £34,000, wages £81,500 → £10.50 per unit", "Site Z: 9,000 units/year, rent £32,000, wages £71,500 → £11.50 per unit"], "answer": 2, "explain": "Correct answer: Site Y. Cost per unit = (Total costs) ÷ Output. Site W: £110,000 ÷ 10,000 = £11.00. Site X: £144,000 ÷ 12,000 = £12.00. Site Y: £115,500 ÷ 11,000 = £10.50 ✅. Site Z: £103,500 ÷ 9,000 = £11.50. Site Y has the lowest cost per unit."}, {"question": "An online retailer sells goods across the UK. When deciding where to locate a warehouse, which of the following would NOT be important?", "options": ["Having good access to the road network", "Being near a supply of raw materials", "Being near to most of its customers", "Being in a location where there is a ready supply of labour"], "answer": 1, "explain": "Correct answer: B (and C is also accepted). An online retailer sells finished goods — it does not manufacture, so proximity to raw materials is irrelevant. Being near most customers (C) is also less critical since national delivery handles distribution. Good road access (A) and available labour (D) are both essential for a warehouse operation."}, {"question": "Cambridge Research Biochemicals (CRB) moved production from Cambridge to Billingham in Teesside. What was the primary reason?", "options": ["The government gave CRB a large grant specifically to relocate", "CRB''s main customers were all based in the north of England", "Production costs — especially rent and labour — were much lower in Teesside", "Teesside had better transport links to international markets"], "answer": 2, "explain": "Correct answer: The primary reason was significantly lower costs — rents in Billingham were only 10% of those in Cambridge, and labour was cheaper too. CRB did later receive a ''Let''s Grow'' grant (A), but this was a secondary benefit that helped fund the move to the enterprise zone in 2014, not the original reason for relocating in 1999."}, {"question": "Why might a cheese manufacturer choose to locate near to dairy farms?", "options": ["To benefit from government enterprise zone grants", "To reduce the cost and distance of transporting bulky raw materials (milk)", "To be near to its final customers in supermarkets", "To access a supply of skilled cheese-making labour in rural areas"], "answer": 1, "explain": "Correct answer: Milk is a bulky, perishable raw material. Locating close to dairy farms reduces transport costs and spoilage risk. It also reduces the carbon footprint of the business. This is proximity to raw materials. C relates to the market, A to government, and D to labour — all separate location factors."}, {"question": "What benefits do UK Enterprise Zones offer to businesses that locate there?", "options": ["Free land and premises, unlimited government funding, and exemption from all taxes", "Reduced business rates, lower taxes on investment, superfast broadband, and faster planning approvals", "Guaranteed customers, government contracts, and free advertising", "Exemption from employment law and the right to pay below minimum wage"], "answer": 1, "explain": "Correct answer: Enterprise zones offer a specific package: reduced business rates (taxes on premises), higher capital allowances (lower taxes when businesses invest), superfast broadband, faster planning approvals, and sometimes ready-built premises. They do not offer free land, unlimited funding, or exemptions from employment law."}, {"question": "Lo-Cost Rental, which offers cheap low-specification cars, is considering locating at Heathrow Airport. What is the GREATEST concern?", "options": ["The airport only has 75 million passengers per year — not enough customers", "The high cost of renting a service desk and parking spaces makes profitability very difficult", "There are no competitors at Heathrow, so demand is uncertain", "The airport''s road links are too poor to operate a car rental business"], "answer": 1, "explain": "Correct answer: The greatest concern for a LOW-COST company is that operating costs at Heathrow (service desk rental and parking) are very high. This makes it almost impossible to maintain low rental prices while remaining profitable. Competition (from Hertz, Avis etc.) is also a concern, but costs are the primary issue for Lo-Cost''s business model."}, {"question": "''Silicon Fen'' is an area near Cambridge. Why might an ICT company choose to locate there?", "options": ["It is close to major sea ports for importing computer hardware", "The government offers free land to all technology businesses in the area", "There is a concentration of skilled ICT workers and technology firms already based there", "The area has the lowest business rates of any location in the UK"], "answer": 2, "explain": "Correct answer: Silicon Fen is attractive to ICT firms because of its cluster of existing technology businesses and the proximity to Cambridge University, which produces large numbers of highly skilled technology graduates. This makes recruitment of skilled workers much easier — a key location factor for ICT businesses."}]}, "fib": {"enabled": true, "questions": [{"text": "A business''s [location] refers to the place where it is sited."}, {"text": "[Proximity] means ''nearness to'' — for example, nearness to customers or raw materials."}, {"text": "Businesses may choose to locate near their [market] to reduce the cost of delivering finished goods and improve communication with buyers."}, {"text": "Cambridge Research Biochemicals moved to Billingham because rents there were only [10] per cent of those in Cambridge."}, {"text": "The ''Silicon [Fen]'' is a cluster of ICT firms and skilled workers located near Cambridge."}, {"text": "Cargill Foods located its factory on the [docks] in Liverpool so imported wheat could be unloaded directly into the processing plant."}, {"text": "Enterprise zones offer businesses incentives such as reduced [business] rates, superfast broadband, and faster planning approvals."}, {"text": "The growth of [internet] selling has reduced the importance of being located near customers for many businesses."}, {"text": "Burberry moved its clothing production to [China] in order to reduce factory and labour costs significantly."}, {"text": "An area of high [unemployment] may attract businesses that need a large supply of unskilled or low-cost workers."}, {"text": "The [Northern] Powerhouse is a UK Government initiative to encourage businesses to locate and grow in the north of England."}, {"text": "Locating near raw material sources reduces [transport] costs and can also lower the business''s carbon footprint."}]}, "tf": {"enabled": true, "questions": [{"statement": "For many businesses, the decision of where to locate is one of the most important decisions they make.", "answer": true, "explain": "TRUE. Making the right location decision can help a business flourish and become very successful. Making the wrong decision can make success very difficult. Location affects costs, access to customers, labour supply, and raw material access."}, {"statement": "Low-cost locations are important for every single type of business.", "answer": false, "explain": "FALSE. While cost is important for many businesses, it is not the top priority for every business. Some prioritise skilled labour, proximity to customers, or prestigious location above minimising costs — a luxury hotel in central London is an example."}, {"statement": "Proximity to raw materials is most important for businesses that use bulky materials to produce a smaller, lighter finished product.", "answer": true, "explain": "TRUE. When raw materials are bulky and the finished product is lighter (e.g., wheat → flour, milk → cheese), it is more cost-effective to locate the factory near the raw materials and transport the finished product — not the other way around."}, {"statement": "Online retailers like Amazon need to locate their warehouses close to customers rather than near transport infrastructure.", "answer": false, "explain": "FALSE. Online retailers prioritise access to the road/rail network and a supply of labour for their warehouses. Being near customers is far less important than having a location that allows efficient national delivery."}, {"statement": "Enterprise zones offer incentives such as reduced business rates and faster planning approvals to attract businesses.", "answer": true, "explain": "TRUE. UK enterprise zones offer a package of benefits: reduced business rates, higher capital allowances (lower taxes on investment), superfast broadband, faster planning approvals, and sometimes ready-built premises."}, {"statement": "A business will always be influenced by only one location factor when making its location decision.", "answer": false, "explain": "FALSE. It is rarely only one factor — usually it is a combination. A bakery may consider proximity to customers AND transport costs. A manufacturer may weigh raw material access, labour supply, AND government incentives simultaneously."}, {"statement": "Cambridge Research Biochemicals (CRB) moved to Teesside partly because rents there were only 10% of those in Cambridge.", "answer": true, "explain": "TRUE. The case study explicitly states that rents in Billingham are only 10% of those in Cambridge — a massive cost saving that made the relocation financially compelling for CRB."}, {"statement": "Service businesses such as hairdressers and dentists rarely need to consider proximity to customers when choosing a location.", "answer": false, "explain": "FALSE. Service businesses like hairdressers and dentists MUST locate near their customers because the service is delivered in person. Unlike manufacturers, they cannot transport their service — the customer must come to them, so proximity to potential customers is essential."}, {"statement": "The Northern Powerhouse initiative aims to encourage business growth across the north of England from Liverpool to Hull.", "answer": true, "explain": "TRUE. The Northern Powerhouse is a government scheme investing in infrastructure and providing funding across northern regions from Liverpool in the west to Hull in the east, aiming to create jobs and raise incomes."}, {"statement": "Locating near raw material suppliers always reduces a business''s carbon footprint.", "answer": true, "explain": "TRUE. Shorter supply chains mean less transportation, which means fewer carbon emissions. Dewlay Cheesemakers, for example, sources milk from farms within six miles and uses this as a marketing advantage — highlighting its environmental credentials."}, {"statement": "The Wool Warehouse chose a high street location to benefit from maximum footfall from passing shoppers.", "answer": false, "explain": "FALSE. The Wool Warehouse deliberately chose a WAREHOUSE (not a high street shop) to enter the online market easily, keep costs low, and serve customers nationally. High street locations were irrelevant to their online business model."}, {"statement": "In 2021, the UK government announced eight freeports where businesses can import goods without paying tariffs, unless those goods are sold in the wider UK market.", "answer": true, "explain": "TRUE. Freeports allow businesses to import goods tariff-free and VAT-free. Duties are only paid if the goods enter the wider UK market. If the goods are exported after processing, no duties are paid at all — encouraging trade and investment."}]}, "misc": {"enabled": true, "items": [{"myth": "Students think ''the high street'' is the only location option for a business.", "truth": "Businesses can locate anywhere — high streets, industrial estates, online warehouses, near ports, in enterprise zones. The best location depends entirely on the type of business and which factors are most important to it.", "check": {"question": "Which of the following is NOT a valid location option for a business?", "options": ["A government enterprise zone", "An out-of-town industrial estate", "A warehouse near a motorway junction", "All of these are valid location options"], "answer": 3, "explain": "All of these — industrial estates, motorway-adjacent warehouses, and enterprise zones — are perfectly valid location options. There is no single ''right'' location type; it depends entirely on the business''s needs."}}, {"myth": "Students confuse ''proximity to market'' (near customers) with ''proximity to raw materials'' (near suppliers).", "truth": "These are two completely separate location factors. ''Proximity to market'' = near customers. ''Proximity to raw materials'' = near suppliers of inputs. A business can prioritise one, the other, or both — depending on what it produces.", "check": {"question": "Dewlay Cheesemakers sources milk from farms within six miles of its dairy. Which location factor is this?", "options": ["Proximity to market — Dewlay is close to its cheese buyers", "Labour availability — farm workers make the cheese", "Proximity to raw materials — Dewlay is close to milk suppliers", "Government incentives — the farms are in an enterprise zone"], "answer": 2, "explain": "Milk is the raw material for cheese-making. Dewlay locates near its dairy farms (suppliers of milk) to minimise transport costs and keep milk fresh — this is proximity to raw materials, not proximity to market."}}, {"myth": "Students write that ''an online business doesn''t need to think about location at all.''", "truth": "Online businesses still have critical location decisions — particularly for their warehouses. They need good transport links (road/rail), a reliable labour supply, and affordable land. The Wool Warehouse is a clear example of deliberate location planning for an online business.", "check": {"question": "What location factor is MOST important for an online retailer choosing where to put its warehouse?", "options": ["Proximity to customers — the warehouse should sit near shoppers directly", "Proximity to competitors — the warehouse should sit near rival firms", "Good transport links — road and rail access for fast nationwide delivery", "City centre visibility — the warehouse should boost brand recognition locally"], "answer": 2, "explain": "Online retailers don''t need to be near customers physically — they reach them through delivery. What matters most for a warehouse is excellent road and rail links to get parcels to customers quickly and cheaply across the country."}}, {"myth": "Students write that ''government grants automatically make a location the best choice.''", "truth": "Government incentives reduce costs but do not eliminate other disadvantages. A location with good grants but poor transport links, scarce skilled labour, or no market access may still be unsuitable for certain businesses.", "check": {"question": "A business receives a £100,000 enterprise zone grant to locate in a remote area with no motorway access and few local workers. Should it definitely accept?", "options": ["No — businesses should always reject grants tied to remote areas", "Not necessarily — poor transport and labour could outweigh the grant", "Yes — government grants always cancel out every location downside", "Yes — a grant of that size always makes any site worthwhile"], "answer": 1, "explain": "Government incentives reduce costs but cannot fix fundamental disadvantages like poor transport infrastructure or scarce skilled workers. The overall location package must be evaluated — grants are just one factor among many."}}, {"myth": "Students believe all businesses must locate near their raw materials.", "truth": "Proximity to raw materials only matters when materials are bulky, perishable, or expensive to transport. A business making small, lightweight products (e.g., greeting cards) has no reason to locate near raw materials.", "check": {"question": "Which of the following businesses has the STRONGEST reason to locate near its raw materials?", "options": ["A greeting card manufacturer using lightweight card and paper", "A cheese producer using fresh, perishable local milk", "An online clothing retailer shipping garments nationwide", "A software development company selling downloadable digital products"], "answer": 1, "explain": "Fresh milk is perishable and bulky — it cannot travel long distances before spoiling. A cheese producer must be near its milk supply. The other businesses use materials that are either lightweight, digital, or easily shipped over long distances."}}, {"myth": "For a 7-mark ''discuss'' or ''evaluate'' question, students list location factors without making a final judgement.", "truth": "The examiner''s report highlights that most students gain marks for application and analysis but miss evaluation marks by not making a judgement. You MUST weigh up which factor is most important and state WHY, using context from the case study. Even a simple, contextualised judgement earns evaluation marks.", "check": {"question": "Most students score around 4/7 on a location evaluate question. What do they typically miss?", "options": ["They don''t apply their answer to the specific business", "They don''t make a final judgement on the most important factor", "They don''t name any relevant location factors at all", "They write far too much without ever reaching a conclusion"], "answer": 1, "explain": "The examiner''s report consistently flags this — most candidates demonstrate application and analysis but skip the evaluation mark by failing to make a final contextualised judgement. Even a short, specific conclusion earns evaluation marks."}}, {"myth": "Students think ''Silicon Fen'' is in Silicon Valley, USA.", "truth": "Silicon Fen is an area near Cambridge, UK. It is named after the Fens (the flat marshy land near Cambridge). It is a cluster of ICT firms and highly skilled technology workers, not connected to Silicon Valley in California.", "check": {"question": "Where is ''Silicon Fen'' and why is it relevant to business location?", "options": ["In the north of England — it was created by the Northern Powerhouse initiative", "San Francisco, USA — it is the home of tech giants like Apple and Google", "Near Cambridge, UK — it is a cluster of ICT firms and skilled tech workers", "In South Wales — it is one of four enterprise zones in the region"], "answer": 2, "explain": "Silicon Fen is near Cambridge, UK — named after the flat Fens landscape. It is a cluster of ICT businesses that attracts and benefits from the pool of highly skilled technology graduates from Cambridge University."}}, {"myth": "When asked to ''analyse one factor'', students write about several factors briefly rather than one factor in depth.", "truth": "The examiner wants ONE factor developed with three steps: Understanding (explain the factor) → Application (link to the specific business using case study evidence) → Analysis (explain the impact on the business). Two brief points will not score full marks.", "check": {"question": "On a 3-mark ''Analyse one location factor'' question, a student writes two sentences about two different factors. How many marks do they score?", "options": ["3 marks — covering two different factors shows good breadth of knowledge", "0 marks — only one location factor should ever be discussed", "2 marks — one mark is awarded for each factor mentioned", "1 mark — without U, APP and AN for one factor, marks are capped"], "answer": 3, "explain": "The 3-mark U → APP → AN chain requires depth on ONE factor, not breadth across several. Two brief mentions of different factors can only earn at most 1 mark — without Application and Analysis, the chain is incomplete."}}]}, "tips": {"enabled": true, "items": [{"title": "One Specific Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. No explanation, no examples, no paragraphs required.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific location factor = ✅ 1 mark</li>\n        <li>A vague or repeated answer = ❌ 0 marks</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"The location.\"</em><br/>\n      Too vague — this just repeats the topic of the question.</p>\n      <p><strong>✅ Good Answers (1 mark each):</strong></p>\n      <ul>\n        <li><em>\"Proximity to customers / the market.\"</em></li>\n        <li><em>\"Cost of the site / rent.\"</em></li>\n        <li><em>\"Transport infrastructure / road links.\"</em></li>\n        <li><em>\"Government incentives / enterprise zone.\"</em></li>\n        <li><em>\"Proximity to a supply of labour / workers.\"</em></li>\n      </ul>\n      <p><strong>⏱️ Exam Tip:</strong> Do NOT write more than one sentence for a 1-mark question. Move on quickly — every minute counts in the exam.</p>\n    ", "check": {"question": "Which of these answers would score 1 mark for ''Identify one factor a business considers when choosing its location''?", "options": ["\"Location is very important for all businesses.\"", "\"Proximity to the market / nearness to customers.\"", "\"Businesses need to think carefully about where they are.\"", "\"The area.\""], "answer": 1, "explain": "Only a specific, named factor scores the mark — ''proximity to the market'' is precise and correct. The other options are all vague restatements of the question and would score zero."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark <strong>''Analyse''</strong> question awards one mark for each of three steps. Miss any one and you lose that mark — even if the rest is excellent.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State and briefly explain the location factor you are discussing.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business using evidence from the case study. Quote or paraphrase specific details.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the financial or operational impact on the business. Keep asking \"So what?\" until you reach a bottom-line effect (costs, revenue, profit, productivity).</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark — only U):</strong><br/>\n      <em>\"AM plc should locate where there are skilled workers because they are important for production.\"</em><br/>\n      Vague, no case study link, no analysis of impact on the business.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"AM plc must locate in an area with a supply of skilled engineers (U), as its Warwickshire site already employs over 3,000 highly skilled workers who use up-to-date machinery to produce each luxury car by hand (APP). If AM plc struggled to recruit these workers, productivity would fall and quality could deteriorate, threatening the premium reputation and pricing of its luxury cars (AN).\"</em></p>\n      <p><strong>🚫 Knowledge Dumping Warning:</strong> Do NOT write everything you know about business location. Pick ONE factor and develop it fully through all three steps. Two half-finished points will not earn full marks.</p>\n      <p><strong>Sentence starters:</strong></p>\n      <ul>\n        <li><em>U: \"One factor [business name] would consider is...\"</em></li>\n        <li><em>APP: \"This is evident because the text states that...\" / \"In the case of [business]...\"</em></li>\n        <li><em>AN: \"As a result, the business would...\" / \"This means costs would...\" / \"This could lead to...\"</em></li>\n      </ul>\n    ", "check": {"question": "A student analyses AM plc''s location by writing: ''AM plc should locate where there are skilled workers because they are important.'' How many marks does this score?", "options": ["3 marks — it names skilled workers and links this clearly to AM plc", "2 marks — it shows knowledge and some application to AM plc''s case", "1 mark — it states the factor but gives no application or analysis", "0 marks — skilled workers is not considered a genuine location factor"], "answer": 2, "explain": "This scores only 1 mark (U) — it names the factor but fails to apply it using specific evidence from the AM plc case study (APP) and gives no analysis of the financial or operational consequence (AN). The chain is U → APP → AN and all three steps are needed."}}, {"title": "Make a Decision, Then Back It Up with Both Sides", "html": "\n      <p>A 3-mark <strong>''Recommend''</strong> question has a specific structure. There is 1 mark for a clear judgement and 2 marks for justification. Crucially, your justification must address BOTH sides.</p>\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> State your clear recommendation — e.g., \"Lo-Cost should / should not locate at Heathrow Airport.\"</li>\n        <li><strong>Justification (2 marks):</strong> Explain precisely WHY using specific details from the case study. Your justification must cover both the advantages AND the drawbacks — one-sided answers earn at most 1 justification mark.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Lo-Cost should not locate at Heathrow because it is expensive.\"</em><br/>\n      Only earns the judgement mark — ''expensive'' is too vague, and there is no case study reference.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"Lo-Cost Rental should NOT locate at Heathrow Airport (JUDGEMENT). The very high cost of renting a service desk and parking spaces at the airport would make it almost impossible for Lo-Cost to maintain its low-priced model while staying profitable. Furthermore, well-established competitors such as Hertz and Avis can subsidise lower prices with revenue from premium cars — a strategy Lo-Cost cannot replicate (JUSTIFICATION ×2).\"</em></p>\n      <p><strong>💡 The Rule:</strong> Justification MUST address both sides to earn 2 justification marks. Defending only one side = maximum 1 justification mark.</p>\n    ", "check": {"question": "Why does ''Lo-Cost should not locate at Heathrow because it is expensive'' only score 1 out of 3 marks?", "options": ["It scores 0 — cost is never accepted as a valid location factor", "It scores 1 — just the judgement mark; ''expensive'' is too vague", "It scores 2 — the judgement mark plus one justification point", "It scores 3 — a clear decision alone is enough for full marks"], "answer": 1, "explain": "This earns only the judgement mark (1/3). To score the two justification marks, you need specific case study detail AND consideration of both sides — why Heathrow is unsuitable for Lo-Cost AND why competitors like Hertz can sustain the cost when Lo-Cost cannot."}}, {"title": "4 Paragraphs — Don''t Forget to Judge!", "html": "\n      <p>A 7-mark <strong>''Discuss''</strong> or <strong>''Evaluate''</strong> question uses levels of response marking. To reach the top level (5–7 marks), you must demonstrate <strong>application</strong>, <strong>analysis</strong>, AND <strong>evaluation</strong>.</p>\n      <p><strong>⚠️ The examiner''s report warns:</strong> Most candidates gain around 4/7 by demonstrating application and analysis well — but only the very best pick up evaluation marks. Even a simple judgement is worth marks. Don''t skip it!</p>\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Para 1 — K &amp; U:</strong> Introduce your first location factor with knowledge and understanding. Explain what it means and why it matters.</li>\n        <li><strong>Para 2 — APP &amp; AN:</strong> Apply your first factor to the specific business using evidence from the case study. Analyse the impact on the business.</li>\n        <li><strong>Para 3 — APP &amp; AN:</strong> Introduce a second factor or the opposing perspective. Apply it to the business and analyse the impact.</li>\n        <li><strong>Para 4 — EVAL (3 points = Decision + Context + Impact/Reasoning):</strong> Make a clear judgement about which factor is most important, using specific context from the business to justify your conclusion.</li>\n      </ul>\n      <p><strong>Evaluation sentence starters:</strong></p>\n      <ul>\n        <li><em>\"Overall, I believe the most important factor for [business] was... because...\"</em></li>\n        <li><em>\"However, this depends on whether...\"</em></li>\n        <li><em>\"The decision to [go online / locate here] was [justified / unjustified] because, given that [specific context]...\"</em></li>\n      </ul>\n      <p><strong>🚫 The Most Common Mistake:</strong> Writing a conclusion that simply repeats the two points already made. That earns 0 evaluation marks. A real evaluation makes a <em>judgement about which factor matters most</em> and explains <em>why</em>, using the specific business context.</p>\n      <p><strong>✅ Simple but effective evaluation example (Costa Coffee):</strong><br/>\n      <em>\"Overall, the most important factor for Costa Coffee was the high footfall from the town centre location, because as a retailer selling products in person — not online — passing trade is essential for survival. Without customers walking past, no other factor matters.\"</em><br/>\n      This earns all 3 evaluation marks: a specific judgement (footfall), justified in context (Costa sells in person), with clear reasoning (passing trade is essential).</p>\n    ", "check": {"question": "The Costa Coffee evaluation example earns 3 evaluation marks. What three things does it include?", "options": ["Three separate advantages of choosing a busy town centre spot", "A clear judgement, specific context about Costa, and its reasoning", "A definition of footfall, one advantage, and one clear disadvantage", "Two full analysis paragraphs and a short summary of key points"], "answer": 1, "explain": "A full 3-mark evaluation needs: (1) a clear decision about which factor is most important, (2) specific context from the business (Costa sells face-to-face, not online), and (3) reasoning explaining why that factor matters most — not simply repeating earlier analysis."}}]}, "exam": {"enabled": true, "questions": [{"question": "In the context of business operations, what does the phrase ''proximity to market'' refer to?", "marks": 1, "hint": "Think about what ''proximity'' means — it means ''nearness to''. What does ''market'' refer to in a business context?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Locating a business close to its potential customers</h5><p><strong>Why B is correct:</strong> ''Proximity to market'' is a specific business location term meaning nearness to where the business''s customers are. It encourages businesses to locate where they can access the most potential buyers.</p><ul><li><strong>❌ A is wrong:</strong> Advertising to local people is a marketing decision, not a location factor.</li><li><strong>❌ C is wrong:</strong> Employing local workers relates to proximity to labour, not the market.</li><li><strong>❌ D is wrong:</strong> Being near a source of raw materials is the separate factor of ''proximity to raw materials.''</li></ul></div>"}, {"question": "Which one of the following is the most likely reason for a greeting card manufacturer to locate its factory on an out-of-town industrial estate?", "marks": 1, "hint": "Greeting cards are small, lightweight, and easy to transport. The business does not need to be near its final customers. Think about what advantage an out-of-town industrial estate offers over a high-street location.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Council incentives offering reduced business rates</h5><p><strong>Why A is correct:</strong> A greeting card manufacturer does not need to be near its final customers — cards are small, durable, and easy to transport nationally. An out-of-town industrial estate offers lower costs, and council incentives such as reduced business rates make it even more financially attractive.</p><ul><li><strong>❌ B is wrong:</strong> Greeting cards are packaged and not significantly damaged during normal transportation — this is not a valid reason for choosing an industrial estate.</li><li><strong>❌ C is wrong:</strong> Industrial estate workers are not the primary market for greeting cards. This would not justify the location decision.</li><li><strong>❌ D is wrong:</strong> The question describes an out-of-town location, which directly contradicts the idea of being close to customers. Customers do not travel to a factory to purchase cards.</li></ul></div>"}, {"question": "Which one of the following is a benefit of locating a tomato farm near to a ready supply of labour?", "marks": 1, "hint": "Focus on what ''near to a ready supply of labour'' means. Labour = workers. What specific benefit does having workers nearby provide for a farm?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Ease of recruitment of tomato pickers</h5><p><strong>Why A is correct:</strong> Locating near a ready supply of labour means the business can easily recruit the workers it needs. For a tomato farm, this means pickers are available locally, reducing recruitment costs and labour shortages during harvest time.</p><ul><li><strong>❌ B is wrong:</strong> Personal contact with supermarket buyers relates to proximity to the market (customers), not to labour.</li><li><strong>❌ C is wrong:</strong> Increased tomato sales relate to market proximity, not the labour supply.</li><li><strong>❌ D is wrong:</strong> Tomatoes still need to be transported to supermarkets and shops regardless of where the farm is relative to its workers. Labour location does not affect transportation requirements.</li></ul></div>"}, {"question": "Analyse one possible factor that AM plc may have considered when choosing the location of its main production site. [3 marks]", "marks": 3, "hint": "Choose ONE location factor from the case study. You need three things: (1) explain what the factor is, (2) link it to AM plc using specific evidence from the text, (3) explain the impact on the business. Do NOT try to cover multiple factors.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> States and explains a relevant location factor. Examples include: availability/cost of skilled workers, cost of premises/rent, space available on site, transport infrastructure, government incentives, proximity to market or suppliers, economic conditions.</li><li><strong>Application (1 mark):</strong> Uses specific evidence from the case study. Examples: luxury sports cars (skilled production required), 150+ dealerships in 50+ countries (global reach), globalised supply chain (transport needs), 3,000+ highly skilled workers, cars transported all over UK and beyond, commitment to the environment, bar chart data showing falling unemployment and rising consumer income.</li><li><strong>Analysis (1 mark):</strong> Explains the impact or consequence. Examples: impact on costs, impact on productivity and efficiency, impact on competitive advantage, impact on quality/reputation.</li></ul><p><strong>Note:</strong> No further marks can be gained without the Understanding mark. Application requires using evidence from the text, not just naming AM plc.</p></div><div class=\"marks-section\"><h5>Exemplar Response (3/3)</h5><p><em>\"AM plc must locate in an area where there are highly skilled engineers (U), as the text states that its Warwickshire site employs over 3,000 highly skilled workers who use up-to-date machinery to produce each luxury car (APP). If AM plc struggled to recruit these workers, its productivity could fall and the quality of its luxury cars could deteriorate, threatening the premium pricing and brand reputation on which the business depends (AN).\"</em></p></div>"}, {"question": "Identify one factor that a new business like Martina''s should consider when choosing a location for its business. [1 mark]", "marks": 1, "hint": "Think about the four main location factors from the specification: Costs, Proximity to market, Proximity to labour, Proximity to raw materials. Which would be most relevant for a private sports injury clinic?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a: 1)</h5><p>1 mark for any correct identification of a relevant location factor. Acceptable answers include:</p><ul><li>Cost/rent of the location</li><li>Proximity to customers/patients</li><li>Where the owner lives</li><li>Proximity to staff/labour (e.g., physiotherapists)</li><li>Amount of competition (other clinics nearby)</li></ul></div>"}, {"question": "Identify two factors that influence the location of a business. [2 marks]", "marks": 2, "hint": "There are four main location factors in the specification. Name two of them clearly. You do not need to explain them for this question — just identify each one.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a: 2)</h5><p>1 mark for each correct identification, up to a maximum of 2 marks. Acceptable answers include:</p><ul><li>Cost/rent of the location</li><li>Transport/infrastructure</li><li>Proximity to the market/customers (number of customers, size/population)</li><li>Proximity to labour/workers</li><li>Proximity to raw materials</li><li>Government incentives (enterprise zones)</li><li>Competition/rivals</li><li>Marketing reasons</li></ul><p><strong>Examiner''s Comment:</strong> This question requires knowledge of factors which influence business location. The specification lists four key factors: costs, proximity to market, labour and materials. Examples of each were also permitted.</p></div>"}, {"question": "Discuss the factors that may have influenced Costa Coffee''s decision to locate a new branch in Welshpool. [7 marks]", "marks": 7, "hint": "Use specific details from the Costa Coffee case study above. Cover at least two location factors, apply them directly to Costa Coffee (do not just define them), analyse the impact on the business, and then make a final judgement about which factor was MOST important and why. The command word ''discuss'' requires evaluation — you must weigh up the factors.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks (AO2: 2 APP, AO3a: 2 AN, AO3b: 3 EVAL)</h5><h5>Level 3 (5–7 marks)</h5><p>Good application of knowledge and understanding of location factors specific to Costa Coffee in Welshpool. Good analysis with logical chains of reasoning. Strong evaluation with a fully justified judgement drawing on underpinning knowledge and case study context.</p><h5>Level 2 (3–4 marks)</h5><p>Good application of location factors to Costa Coffee with detailed understanding. Limited analysis (some cause and consequence). Limited evaluation.</p><h5>Level 1 (1–2 marks)</h5><p>Limited application of location factors to Costa Coffee. Some use of the scenario. Limited analysis. No evaluation.</p></div><div class=\"marks-section\"><h5>Application evidence may include:</h5><ul><li>Town centre location / high street position</li><li>Near other businesses including offices and shops</li><li>Only two other coffee shops in the town</li></ul><h5>Analysis may include:</h5><ul><li>Low competition means Costa can attract a larger share of the market</li><li>Being a large firm, location costs may not have been a primary barrier</li><li>High footfall expected from town centre, offices, and shops nearby</li><li>Good infrastructure means stock and staff can access the site easily</li></ul><h5>Evaluation may include:</h5><ul><li>Which factor is most influential and why</li><li>The relative importance of footfall vs competition vs costs in this specific context</li><li>What the success of the decision depends upon</li></ul></div><div class=\"marks-section\"><h5>Exemplar Response (7/7)</h5><p><em>\"By locating in the town centre there will be many people walking past (APP), and so Costa is likely to have more customers and make a profit (AN). However, there were two other coffee shops already located there when Costa set up (APP). This may make it difficult to get enough customers to make the shop profitable (AN). Overall, the number of potential customers is more important than the level of competition (EVAL) when deciding on a suitable location, because a coffee shop cannot compete at all without passing trade (EVAL) — so the High Street is ideal (EVAL).\"</em></p><p><strong>Examiner''s Comment:</strong> Most candidates gained 4/7 for application and analysis. Only the very best picked up evaluation marks. The command word ''discuss'' is evaluative — you MUST weigh up factors and reach a conclusion about their relative influence. Even a simple contextualised judgement earns evaluation marks.</p></div>"}, {"question": "State three factors Holly and Andy would have considered when deciding their business location. [3 marks]", "marks": 3, "hint": "Think about the four main location factors from the specification: Costs, Proximity to market, Proximity to labour, Proximity to raw materials. Which are most relevant for an online warehouse business? You do not need to explain — just state three clearly.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (1 mark each)</h5><p>1 mark for each correct factor stated, up to a maximum of 3 marks. Acceptable answers include:</p><ul><li>Cost of the warehouse / rent</li><li>Access to transport links (for deliveries from suppliers and to customers)</li><li>Proximity to the market / access to customers (via online delivery infrastructure)</li><li>Access to reliable broadband / ICT infrastructure (essential for an online business)</li><li>Proximity to labour / workforce</li><li>Government incentives / enterprise zone benefits</li><li>Space available for stock storage</li></ul></div>"}, {"question": "Evaluate the decision by Holly and Andy to set up a business as an online-only business. [7 marks]", "marks": 7, "hint": "Use TWO pieces of information from the Wool Warehouse case study (APP). Analyse the impact of each one on the business (AN). Then evaluate: was going online-only the right decision? Consider the advantages AND the disadvantages before making your final judgement.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><ul><li><strong>Application (2 marks):</strong> Use 2 pieces of specific, named information from the Wool Warehouse case study.</li><li><strong>Analysis (2 marks):</strong> Analyse each piece of information, discussing the implication for the business (impact on costs, revenue, competition, growth).</li><li><strong>Evaluation (3 marks):</strong> Make a clear judgement — was going online-only the right decision? Use case study context to justify. Ideally consider both sides.</li></ul><h5>Application evidence from the case study:</h5><ul><li>\"There were only 2 or 3 yarn suppliers online\" → very low online competition</li><li>\"Online sales took off\" → strong market demand for online yarn</li><li>\"They doubled their warehouse space in 2014\" → evidence of strong growth</li><li>They chose a warehouse instead of a high street shop → deliberate cost-saving decision</li></ul><h5>Evaluation may include:</h5><ul><li>Low online competition in 2012 made going online a smart first-mover advantage decision</li><li>The business could reach a national market rather than just local customers</li><li>An online-only business faces challenges in building trust without a physical presence</li><li>The success (doubling warehouse space) suggests the decision was justified</li><li>It depends on whether they can maintain advantage as more online competitors emerge</li></ul></div>"}, {"question": "Analyse one benefit to car rental companies of locating at Heathrow Airport. [3 marks]", "marks": 3, "hint": "Choose ONE benefit and develop it fully using the U → APP → AN structure. What is the benefit? Link it to the specific numbers in the case study. What is the financial or commercial impact on a car rental company?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> Identifies a benefit. Examples: large number of potential customers, high level of demand, large and accessible market.</li><li><strong>Application (1 mark):</strong> Links to the case study. Example: \"There are 75 million passengers who pass through the airport each year.\"</li><li><strong>Analysis (1 mark):</strong> Explains the impact on a car rental company. Example: \"The high volume of customers means car rental companies should be able to rent out a large number of cars consistently, significantly increasing revenue and profit.\"</li></ul><p><strong>Note:</strong> The Application mark cannot be gained without the Understanding mark first.</p></div>"}, {"question": "Analyse one disadvantage to car rental companies of locating at Heathrow Airport. [3 marks]", "marks": 3, "hint": "Choose ONE disadvantage and develop it fully using U → APP → AN. Think about what the case study tells you about costs at the airport, the level of competition, or the profile of customers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> Identifies a disadvantage. Examples: high operating costs, high level of competition, customer profile mismatch (many are high-income earners preferring premium cars).</li><li><strong>Application (1 mark):</strong> Links to the case study. Examples: \"The cost of renting a service desk and the parking spaces at the airport is high.\" OR \"Competition from Europ Car, Sixt, Hertz, and Avis will be high.\" OR \"Many passengers are middle- and high-income earners.\"</li><li><strong>Analysis (1 mark):</strong> Explains the impact. Examples: \"Lo-Cost may struggle to attract enough customers as established competitors are already well-known.\" OR \"High costs make it very difficult for Lo-Cost to remain profitable while keeping rental prices low.\"</li></ul></div>"}, {"question": "Recommend whether or not Lo-Cost Rental should start to offer car rentals at Heathrow Airport. Give reasons for your recommendation. [3 marks]", "marks": 3, "hint": "Make a CLEAR decision first (1 mark). Then give a precise justification that addresses BOTH sides of the argument using specific details from the case study (2 marks). One-sided justification earns at most 1 mark for justification.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b: 3)</h5><ul><li><strong>Judgement (1 mark):</strong> A clear recommendation — Lo-Cost should / should not locate at Heathrow Airport. OR \"More information is needed before a decision can be made.\"</li><li><strong>Contextual justification (up to 2 marks):</strong> A precise, case-study-based justification that addresses both sides of the argument.</li></ul><h5>Acceptable justifications include:</h5><ul><li>Lo-Cost cannot make a profit as the very high costs at Heathrow do not suit a low-cost car rental model. Established competitors like Hertz and Avis can subsidise lower prices with revenue from premium vehicle hire — Lo-Cost cannot replicate this.</li><li>It depends on what percentage of the 75 million passengers prefer low-priced rentals. There may be sufficient demand, but there is not enough information in the case study to confirm this.</li><li>It depends on how much Lo-Cost would need to charge to cover Heathrow''s costs. If prices must rise significantly, the business loses its core competitive advantage of offering low-cost cars.</li></ul></div>"}, {"question": "Which of these is NOT a reason for a business locating near to its market?", "marks": 1, "hint": "Think about which option describes locating near RAW MATERIALS rather than near the MARKET. Which one is actually the opposite reason?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — It uses bulky raw materials to produce a smaller, finished product</h5><p><strong>Why B is NOT a reason to locate near the market:</strong> Using bulky raw materials to produce a smaller finished product is a reason to locate near the RAW MATERIALS — not near customers. The logic is that transporting heavy raw materials long distances is more expensive than transporting the lighter finished product.</p><ul><li><strong>❌ A is a valid reason to locate near the market:</strong> Producing a large finished product makes it expensive to transport — so locating near the buyer keeps delivery costs low.</li><li><strong>❌ C is a valid reason:</strong> If customers won''t travel or shop online, the business must go to where the customers are.</li><li><strong>❌ D is a valid reason:</strong> Fresh/perishable products (like cream cakes) must reach customers quickly — locating near the market prevents spoilage and reduces waste.</li></ul></div>"}, {"question": "Which one of these statements about business location is NOT true?", "marks": 1, "hint": "Think about whether ALL businesses need to prioritise keeping costs low, or whether some businesses prioritise other factors — like prestige, skilled labour, or access to customers — above minimising costs.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Low-cost locations are important for every single producer</h5><p><strong>Why C is NOT true:</strong> Low-cost locations are important for many businesses, but NOT every single producer. Some businesses — such as luxury brands, specialist service providers, or those requiring highly skilled labour near universities — prioritise location quality, skilled workers, or proximity to customers above cost minimisation.</p><ul><li><strong>A is true:</strong> Small, light finished products are cheap to transport, so proximity to the market matters less. However, it may still be beneficial for customer accessibility.</li><li><strong>B is true:</strong> Governments use enterprise zones, grants, and freeports to encourage businesses to locate in high-unemployment areas.</li><li><strong>D is true:</strong> Most location decisions involve weighing up multiple factors simultaneously — costs, labour, transport, customers, and government incentives.</li></ul></div>"}, {"question": "A firm has identified four possible locations. Based on the figures available, which offers the lowest cost per unit produced?", "marks": 1, "hint": "Calculate: Cost per unit = (Annual rent + Annual wages) ÷ Units produced. Work this out for all four sites, then compare.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Site Y (£10.50 per unit)</h5><p><strong>Calculations (Cost per unit = Total costs ÷ Output):</strong></p><ul><li>Site W: (£30,000 + £80,000) ÷ 10,000 = £110,000 ÷ 10,000 = <strong>£11.00 per unit</strong></li><li>Site X: (£42,000 + £102,000) ÷ 12,000 = £144,000 ÷ 12,000 = <strong>£12.00 per unit</strong></li><li>Site Y: (£34,000 + £81,500) ÷ 11,000 = £115,500 ÷ 11,000 = <strong>£10.50 per unit ✅ LOWEST</strong></li><li>Site Z: (£32,000 + £71,500) ÷ 9,000 = £103,500 ÷ 9,000 = <strong>£11.50 per unit</strong></li></ul></div>"}, {"question": "An online retailer sells goods across the UK. When deciding where to locate a warehouse, which of the following would NOT be important?", "marks": 1, "hint": "An online retailer SELLS finished goods — it does not manufacture them. Think about which of these factors would only matter for a manufacturing business, not a warehouse.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Being near a supply of raw materials (C is also accepted)</h5><p><strong>Why B is not important:</strong> An online retailer sells finished goods to customers — it does not manufacture anything, so it has no need for raw materials. Proximity to raw materials is completely irrelevant to a warehouse operation.</p><p><strong>Why C may also be accepted:</strong> An online retailer delivers to customers nationally — it does not need to be near most of its customers since deliveries are handled by couriers. Warehouse location is more about transport infrastructure than customer geography.</p><ul><li><strong>❌ A is important:</strong> Good road network access is essential for receiving stock from suppliers and dispatching customer orders efficiently.</li><li><strong>❌ D is important:</strong> Online warehouses require many workers to pick, pack, and dispatch orders — labour availability is critical to operations.</li></ul></div>"}]}}'::jsonb),
('business', '4-6-working-with-suppliers', '4.6 Working with Suppliers', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must be able to define accurately in the exam. Learn these using look, say, cover, write, check.</p>\n<ul>\n  <li><strong>Procurement:</strong> The management of purchasing (buying) goods and services within a business.</li>\n  <li><strong>Logistics:</strong> The management of the transportation and storage of goods from seller to buyer.</li>\n  <li><strong>Supply Chain:</strong> The chain of businesses involved in the production of a product and its delivery to the end user.</li>\n  <li><strong>Supplier:</strong> A party (business or individual) that supplies goods and/or services to another business.</li>\n  <li><strong>Just-In-Time (JIT):</strong> A system where parts or materials are delivered exactly when they are needed for production, minimising storage costs.</li>\n  <li><strong>Ethical Sourcing:</strong> Choosing suppliers who operate responsibly — paying fair wages, protecting workers, and using sustainable materials.</li>\n</ul>", "check": {"question": "Which statement correctly describes a Just-In-Time (JIT) system?", "options": ["Suppliers are chosen only because they charge the lowest price", "Large buffer stocks are kept in the warehouse just in case", "Parts are delivered exactly when needed, keeping storage costs low", "Stock is reordered automatically once levels start running low"], "answer": 2, "explain": "JIT means materials arrive exactly when needed on the production line, which cuts storage costs but relies on very reliable suppliers."}}, {"title": "The Procurement Process — 4 Stages", "html": "<p><strong>Procurement</strong> is the management of all buying activity within a business. Whether it''s a supermarket buying thousands of product lines or a small café ordering coffee beans, every business must manage procurement. There are four key stages:</p>\n<ul>\n  <li><strong>Stage 1 — Identifying goods and services to buy:</strong> What to buy can be influenced by the time of year, changes in fashion, technology developments, or customer demand. For example, a clothing retailer must decide whether to stock winter coats or summer dresses based on the season.</li>\n  <li><strong>Stage 2 — Choosing suppliers:</strong> Who can supply the goods? What do they charge? What is their reputation for quality and reliability? Businesses must evaluate multiple suppliers before committing.</li>\n  <li><strong>Stage 3 — Ordering goods and services:</strong> The actual process of placing orders and procuring goods. Procurement teams consider whether bulk ordering offers a discount, or whether a longer contract reduces unit costs.</li>\n  <li><strong>Stage 4 — Receiving deliveries from suppliers:</strong> When will goods arrive? Where will they be stored? Access for delivery vehicles and sufficient storage space must be planned in advance.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Tesco plc</h4>\n  <p>Tesco is one of the UK''s largest retailers, selling thousands of product lines through its stores and online. Its procurement department manages relationships with hundreds of suppliers across the UK and abroad. If a supplier fails to deliver — say, during a factory flood like the Crawford''s Biscuits incident in 2016 — Tesco suffers immediately: empty shelves, lost sales, and damage to its reputation. This shows why all four stages of procurement must be managed carefully and continuously.</p>\n</div>", "check": {"question": "Deciding what to buy based on the time of year, fashion or technology belongs to which stage of procurement?", "options": ["Stage 4 – receiving deliveries", "Stage 3 – ordering the goods", "Stage 2 – choosing suppliers", "Stage 1 – identifying what to buy"], "answer": 3, "explain": "Identifying what to buy (influenced by season, fashion and technology) is Stage 1; choosing suppliers, ordering and receiving are the later stages."}}, {"title": "Factors Affecting What to Buy", "html": "<p>Before a business can even choose a supplier, it must decide <em>what</em> to buy and <em>when</em> to buy it. Getting this wrong can lead to waste, lost sales, or surplus stock. Three key factors affect this decision:</p>\n<ul>\n  <li><strong>Time of year:</strong> Demand for many products is seasonal. A garden centre must stock barbeques and plants in spring/summer and pivot to Christmas items in winter. Ordering too early or too late leads to either stockouts or unsold goods sold at a loss.</li>\n  <li><strong>Changes in technology:</strong> Technology evolves rapidly. A business must avoid buying too much of a product that is about to be replaced by a newer model — for example, buying large quantities of a laptop that will be superseded in two months.</li>\n  <li><strong>Changes in fashion and lifestyle:</strong> Consumer tastes shift constantly. The rise of veganism and gluten-free diets has forced supermarkets to dramatically increase the range of plant-based and free-from products they procure. Failing to anticipate trends means missing sales opportunities.</li>\n</ul>", "check": {"question": "Why should a business consider changes in technology when deciding what to buy?", "options": ["To avoid overbuying stock soon to be replaced by a newer model", "Because changing technology has no effect on demand at all", "Because newer technology is always cheaper to buy in bulk", "Because customers always prefer the oldest available models"], "answer": 0, "explain": "Fast-changing technology risks a business being left with large stocks of a product about to be superseded, causing waste and lost value."}}, {"title": "Choosing the Right Supplier", "html": "<p>Choosing the wrong supplier can damage a business''s reputation, increase costs, and disrupt production. Businesses evaluate potential suppliers against several criteria:</p>\n<ul>\n  <li><strong>Quality of goods supplied:</strong> The quality of supplies must consistently meet the expected standard. Car manufacturers, for example, cannot afford faulty brake components — quality must be right every time.</li>\n  <li><strong>Reputation of the supplier:</strong> If a supplier is exposed for unethical practices (e.g., poor working conditions or child labour), the reputation of the buying business is also damaged — even if the buying business had no direct involvement. Primark and other fashion retailers have faced exactly this challenge.</li>\n  <li><strong>Cost of supplies:</strong> Lower costs can improve profit margins or allow the business to lower prices. However, the cheapest supplier is not always the best choice if it sacrifices quality or reliability.</li>\n  <li><strong>Reliability:</strong> Can the supplier deliver the right quantity of the right quality on time, every time? For fresh food retailers, daily reliability is non-negotiable.</li>\n  <li><strong>Customer service:</strong> When problems occur — late deliveries, faulty goods — how quickly and effectively will the supplier respond? Poor supplier customer service will force the buying business to find alternatives.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Zara (Fast Fashion)</h4>\n  <p>Zara is a global fashion retailer based in Spain with 2,270 stores worldwide. Its entire business model is built on speed — getting new designs from concept to shelf in just 15 days. To achieve this, Zara buys large quantities of fabric from European suppliers, which guarantees fast delivery to its factories in Spain. If its suppliers were unreliable, Zara could not change its clothing designs every two weeks (while competitors take two to three months). Reliable, quality suppliers are therefore central to Zara''s competitive advantage and its USP.</p>\n</div>", "check": {"question": "Why does a supplier''s reputation matter to the business that buys from it?", "options": ["A good reputation always means the supplier is the cheapest option", "A supplier''s reputation sets the tax rate the buying business pays", "A supplier''s reputation only ever affects the supplier, not the buyer", "A supplier''s unethical practices can damage the buyer''s reputation too"], "answer": 3, "explain": "Even if the buyer had no direct involvement, a supplier exposed for unethical practices damages the buyer''s reputation too."}}, {"title": "Logistical Decisions — Time, Reliability, Supply Chain Length, Costs & Customer Service", "html": "<p><strong>Logistics</strong> is the management of the transportation and storage of goods. Once a business has chosen its suppliers, it must ensure the physical movement of goods is managed effectively. Five key factors affect logistical decisions:</p>\n<ul>\n  <li><strong>Time:</strong> For some businesses, timing is critical. A plumber mid-job needs a part immediately. Car manufacturers use just-in-time delivery so parts arrive exactly when needed on the production line. Any delay stops production and costs money.</li>\n  <li><strong>Reliability of supply:</strong> A shop selling fresh bread needs daily deliveries — if a delivery fails, it has nothing to sell and its reputation suffers. Reliability and time work closely together: a supplier that is sometimes on time is not truly reliable.</li>\n  <li><strong>Length of the supply chain:</strong> The more businesses involved in getting a product from raw material to consumer, the higher the risk of disruption. A car maker relying on brake components from a specialist who relies on steel from a mine in another country has a very long and complex supply chain — one failure anywhere in that chain affects everyone downstream.</li>\n  <li><strong>Costs:</strong> Lower supply costs improve profit margins, but not at the expense of quality or reliability. Paying slightly more for a reliable, high-quality supplier often works out cheaper in the long run than constantly dealing with problems caused by a cheaper but unreliable one.</li>\n  <li><strong>Customer service from suppliers:</strong> Businesses are themselves customers of their suppliers. If a supplier fails to deliver or delivers faulty goods, how quickly do they resolve the problem? A supplier with poor customer service creates knock-on problems that damage the buying business''s own service to its customers.</li>\n</ul>", "check": {"question": "Why can paying slightly more for a reliable supplier work out cheaper overall?", "options": ["Expensive suppliers always have much shorter supply chains overall", "A higher price always guarantees that goods will never be faulty", "It avoids the repeated costs caused by an unreliable, cheaper supplier", "Reliable suppliers always charge less money than unreliable ones do"], "answer": 2, "explain": "A cheaper but unreliable supplier causes disruption and knock-on costs, so a dearer reliable one can be cheaper in the long run."}}, {"title": "Advantages & Disadvantages of Long vs Short Supply Chains", "html": "<p>One of the most important logistical decisions is how many businesses sit between raw material and final product. Here is how the length of the supply chain affects a business:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Short Supply Chain</div>\n    <div class=\"pro-item\"><strong>Greater reliability:</strong> Fewer links in the chain means fewer points of potential failure. Disruption is less likely and easier to manage.</div>\n    <div class=\"pro-item\"><strong>Better communication:</strong> Fewer parties to coordinate with means faster responses to problems and clearer relationships.</div>\n    <div class=\"pro-item\"><strong>Lower transport costs:</strong> Shorter distances between supplier and business reduce delivery costs and carbon footprint.</div>\n    <div class=\"pro-item\"><strong>Faster delivery:</strong> Products arrive more quickly, which is vital for time-sensitive goods like fresh food or fashion.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Long Supply Chain</div>\n    <div class=\"con-item\"><strong>Higher risk of disruption:</strong> More businesses involved means more opportunities for something to go wrong — a strike, a flood, a factory fire — anywhere in the chain.</div>\n    <div class=\"con-item\"><strong>Harder to manage:</strong> Co-ordinating multiple businesses across different countries and time zones is complex and costly.</div>\n    <div class=\"con-item\"><strong>Quality control difficulties:</strong> Monitoring the quality and ethical standards of many suppliers across the world is extremely challenging.</div>\n    <div class=\"con-item\"><strong>Reputational risk:</strong> If one supplier in a long chain behaves unethically, the final seller bears much of the public criticism.</div>\n  </div>\n</div>", "check": {"question": "Which of these is an advantage of a short supply chain?", "options": ["Fewer links in the chain mean fewer points where failure can occur", "It allows the business to monitor many more suppliers worldwide", "It increases the number of countries the goods must travel through", "It spreads the reputational risk across many more businesses involved"], "answer": 0, "explain": "A shorter chain has fewer links to break, making it more reliable, easier to communicate along and cheaper to transport."}}, {"title": "Key Issues in Supply Chain Management", "html": "<p>When things go wrong in a supply chain, the consequences ripple through the entire chain. The table below summarises the key issues and their potential problems:</p>\n<ul>\n  <li><strong>Time:</strong> If a supplier cannot deliver on time, production may halt and the business loses sales and revenue.</li>\n  <li><strong>Reliability:</strong> If the quantity or quality of goods supplied falls short, production is delayed or stopped, again leading to lost sales and revenue.</li>\n  <li><strong>Length of supply chain:</strong> A long supply chain increases the risk of problems at each stage — one broken link can halt the entire chain.</li>\n  <li><strong>Costs:</strong> High delivery costs raise total production costs. If costs become too high, the business may be unable to sell goods at a profit. Keeping delivery costs low is important, but not at the expense of reliability.</li>\n  <li><strong>Customer service:</strong> If a supplier has poor customer service, the buying business may lose its own customers due to unresolved problems and delays.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Crawford''s Biscuits & Tesco (2016)</h4>\n  <p>In 2016, Crawford''s Biscuits factory in Carlisle was badly damaged during winter floods, halting production of custard creams. Tesco could not get enough biscuits to meet customer demand. When production eventually restarted, rising UK fuel prices pushed up transport costs, threatening Tesco''s ability to keep prices competitive. This real-world example shows how natural disasters, supply chain disruptions, and rising costs can combine to damage a retailer''s sales and profitability — even when the problem originates with a supplier, not the retailer itself.</p>\n</div>", "check": {"question": "What is the likely consequence for a business if a supplier repeatedly fails to deliver on time?", "options": ["The business''s supply chain automatically becomes shorter", "The business gains an advantage over rivals", "Production may halt, leading to lost sales and revenue", "The supplier''s customer service costs fall"], "answer": 2, "explain": "Late supply can halt production, so the business loses sales and revenue even though the fault lies with the supplier."}}, {"title": "Ethical Sourcing & Sustainable Supply Chains", "html": "<p>Increasingly, businesses must think beyond price and reliability when choosing suppliers. Consumers, investors, and regulators are all paying close attention to <strong>ethical sourcing</strong> — how and where a business''s supplies are produced.</p>\n<ul>\n  <li><strong>Living wages:</strong> Businesses like Primark have committed to encouraging their supply chains to pay workers a living wage. Ethical treatment of workers reduces the risk of negative press coverage and boycotts.</li>\n  <li><strong>Sustainable materials:</strong> Primark sources material from sustainable sources to give clothes a longer life and reduce environmental impact. This appeals to environmentally-conscious consumers and reduces long-term resource risk.</li>\n  <li><strong>Certified suppliers:</strong> Costa Coffee uses Rainforest Alliance-certified suppliers, guaranteeing ethical and environmental standards. This protects Costa''s reputation and aligns with its brand values.</li>\n  <li><strong>Reputational risk:</strong> Unethical suppliers damage the reputation of the businesses that buy from them. Even if a retailer was unaware of the problem, they often face the most public criticism.</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Ethical Sourcing</div>\n    <div class=\"pro-item\"><strong>Reputation:</strong> Enhances brand image and builds customer loyalty, especially among younger, ethically-conscious consumers.</div>\n    <div class=\"pro-item\"><strong>Legal compliance:</strong> Reduces the risk of breaching supply chain regulations and consumer protection laws.</div>\n    <div class=\"pro-item\"><strong>Long-term sustainability:</strong> Sustainable sourcing protects the supply of raw materials into the future.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Drawbacks of Ethical Sourcing</div>\n    <div class=\"con-item\"><strong>Higher costs:</strong> Ethically sourced materials and certified suppliers often charge more, increasing variable costs.</div>\n    <div class=\"con-item\"><strong>Fewer options:</strong> Limiting suppliers to those with ethical certification reduces choice and negotiating power.</div>\n    <div class=\"con-item\"><strong>Monitoring difficulty:</strong> Verifying ethical standards throughout a global supply chain is complex and expensive.</div>\n  </div>\n</div>", "check": {"question": "Which of the following is a drawback of ethical sourcing for a business?", "options": ["It removes any need to monitor the global supply chain at all", "It always reduces brand loyalty among younger, ethical consumers", "Certified, ethically sourced materials often cost more to buy", "It guarantees that the business breaks consumer protection law"], "answer": 2, "explain": "Ethical and certified suppliers tend to cost more and offer fewer options, and standards are hard to monitor across a global chain."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Procurement", "definition": "The management of purchasing goods and services within a business."}, {"term": "Logistics", "definition": "The management of the transportation and storage of goods from seller to buyer."}, {"term": "Supply Chain", "definition": "The chain of businesses involved in the production of a product and its delivery to the end user."}, {"term": "Stage 1 of Procurement", "definition": "Identifying goods and services to buy — influenced by time of year, fashion, and technology."}, {"term": "Stage 2 of Procurement", "definition": "Choosing suppliers — evaluating quality, cost, reliability, and reputation."}, {"term": "Stage 3 of Procurement", "definition": "Ordering goods and services — placing orders, negotiating discounts for bulk buying."}, {"term": "Stage 4 of Procurement", "definition": "Receiving deliveries — managing storage space and access for delivery vehicles."}, {"term": "Just-In-Time (JIT)", "definition": "Materials arrive exactly when needed for production, minimising storage costs but requiring reliable suppliers."}, {"term": "Reliability of Supply", "definition": "The ability of a supplier to deliver the right quality and quantity of goods consistently on time."}, {"term": "Ethical Sourcing", "definition": "Choosing suppliers who pay fair wages, protect workers, and use sustainable materials."}, {"term": "Zara''s Supply Chain Advantage", "definition": "Zara can get new designs to 2,270 stores in 15 days by sourcing fabric from European suppliers close to its Spanish factories."}, {"term": "Eddie Stobart / Logistics Development Group", "definition": "A UK logistics company that transports goods for businesses like Tesco, ensuring products reach stores reliably."}, {"term": "Why length of supply chain matters", "definition": "Longer chains involve more businesses = more risk of disruption, higher complexity, harder to manage, greater reputational risk."}, {"term": "Rainforest Alliance Certification", "definition": "A certification used by Costa Coffee''s suppliers confirming they meet ethical and environmental sustainability standards."}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the correct definition of procurement?", "options": ["The process of transporting goods from seller to buyer", "The management of purchasing goods and services within a business", "The chain of businesses involved in producing and delivering a product", "The process of checking the quality of goods upon delivery"], "answer": 1, "explain": "Correct answer: Procurement is specifically the management of the purchasing/buying function within a business. Logistics (A) deals with transport and storage. The supply chain (C) is the wider chain of businesses. Quality checking (D) is part of operations, not procurement itself."}, {"question": "Which of the following best describes logistics?", "options": ["Choosing which goods and services a business should sell", "Managing the quality of a finished product", "The management of the transportation and storage of goods", "The process of negotiating prices with suppliers"], "answer": 2, "explain": "Correct answer: Logistics is specifically about managing the movement and storage of goods. Choosing what to sell (A) is a marketing and procurement decision. Quality management (B) is a separate operations function. Negotiating prices (D) is part of procurement."}, {"question": "A longer supply chain means:", "options": ["A business will always receive lower quality goods", "It may be more difficult for a business to manage supplies", "It will take longer to find the right supplier", "The supplier will always demand higher prices"], "answer": 1, "explain": "Correct answer: A longer supply chain involves more businesses, increasing complexity and the risk of disruption — making it harder to manage. It does NOT automatically mean lower quality (A), longer supplier searches (C), or higher prices (D)."}, {"question": "The role of procurement for a car manufacturer might involve:", "options": ["Advertising a new range of electric vehicles", "Negotiating deals with car showrooms", "Receiving deliveries of tyres and windscreens", "Testing the brakes of every new car"], "answer": 2, "explain": "Correct answer: Receiving deliveries of components like tyres and windscreens is a classic procurement function (Stage 4 of procurement). Advertising (A) is marketing. Negotiating with showrooms (B) is sales. Brake testing (D) is quality control/operations."}, {"question": "Which of the following would NOT be part of a procurement officer''s job at a jeans factory?", "options": ["Choosing a supplier of zips and buttons", "Ordering printer paper and ink cartridges", "Receiving delivery of threads and fabrics", "Sewing the size label on to the waistband"], "answer": 3, "explain": "Correct answer: Sewing labels is a production/manufacturing task, not a procurement task. Procurement covers choosing suppliers (A), ordering all goods the business needs including office supplies (B), and receiving deliveries (C)."}, {"question": "Choosing which supplier to use is a:", "options": ["Marketing decision", "Pricing decision", "Procurement decision", "Sales decision"], "answer": 2, "explain": "Correct answer: Selecting and managing suppliers is the core function of procurement. It is not marketing (A), pricing (B), or sales (D). Many students confuse procurement with other business functions — procurement is specifically about the buying/purchasing side."}, {"question": "The length of a firm''s supply chain:", "options": ["Affects how quickly it can respond to changes in demand", "Depends on the production method used by the business", "Has no impact on the procurement function", "Is shown on an organisation chart"], "answer": 0, "explain": "Correct answer: A shorter supply chain allows a business to respond more quickly to demand changes (like Zara''s 15-day turnaround). Production methods (B) do not determine supply chain length. The supply chain absolutely does impact procurement (C is wrong). Organisation charts show internal structure, not supply chains (D is wrong)."}, {"question": "A supermarket decides to extend its opening hours. The supermarket is likely to need:", "options": ["A longer supply chain", "Fewer staff", "Lower quality products", "Reliable suppliers"], "answer": 3, "explain": "Correct answer: Extended opening hours means more products need to be on shelves for longer — this requires reliable suppliers to ensure stock does not run out. A longer supply chain (A) would make this harder, not easier. More staff would be needed (B is wrong). Product quality requirements do not decrease (C is wrong)."}, {"question": "Choosing how products will be delivered to customers is an example of a:", "options": ["Flow production issue", "Liquidity problem", "Logistical decision", "Purchasing concern"], "answer": 2, "explain": "Correct answer: Decisions about how to transport and deliver goods are logistical decisions — logistics is the management of transportation and storage. Flow production (A) is about manufacturing methods. Liquidity (B) is about cash in finance. Purchasing (D) is about buying inputs, not delivering outputs."}, {"question": "Which factor would be MOST important to a discount shop selling all goods at £1?", "options": ["Customer service from suppliers", "Length of the supply chain", "Cost of supplies", "Reliability of supply"], "answer": 2, "explain": "Correct answer: A £1 discount shop has an extremely tight pricing model. It cannot absorb any increase in supply costs without losing its competitive advantage or profitability. Cost is therefore the dominant factor. While reliability (D) also matters to keep shelves stocked, the business model is fundamentally driven by keeping costs as low as possible."}, {"question": "Crawford''s Biscuits factory was damaged in floods, halting production of custard creams. What type of supply chain problem does this illustrate?", "options": ["Poor customer service from Tesco", "A disruption in the reliability of supply", "A failure of Tesco''s logistics team", "A rise in variable costs at Tesco"], "answer": 1, "explain": "Correct answer: The flood disrupted the reliable supply of custard creams — Crawford''s could not produce and therefore could not deliver. This is a supply reliability failure. It was not a customer service failure by Tesco (A), a logistics problem at Tesco (C), or directly a cost problem (D), though costs did rise later due to fuel prices."}, {"question": "If JLR buys 500,000 tyres and 80% come from overseas suppliers, how many tyres come from overseas?", "options": ["80,000", "400,000", "420,000", "450,000"], "answer": 1, "explain": "Correct answer: 500,000 × 80% = 500,000 × 0.8 = 400,000 tyres from overseas. Always show your working: (500,000 ÷ 100) × 80 = 400,000."}, {"question": "The transport costs table for GLU plc (2014–2018) shows costs by road, rail, and air. Which statement about the data is correct?", "options": ["The company prefers to transport its goods by air", "The company''s transport costs have fallen year on year", "GLU plc spent more than £1.25 million on transport costs in 2018", "GLU plc transports more goods by rail than by road"], "answer": 2, "explain": "Correct answer: In 2018: Road (£190,000) + Rail (£430,000) + Air (£650,000) = £1,270,000, which is more than £1.25 million. Option A is wrong — higher air costs reflect higher air prices, not preference. Option B is wrong — all costs increased year on year. Option D is wrong — we cannot determine volume from cost alone (air is most expensive per unit so higher cost ≠ more goods)."}]}, "fib": {"enabled": true, "questions": [{"text": "Procurement is the management of [purchasing] within a business."}, {"text": "Logistics is the management of the [transportation] and storage of goods."}, {"text": "The [supply chain] is the chain of businesses involved in the production of a product and its delivery to the user."}, {"text": "The four stages of procurement are: identifying goods to buy, choosing [suppliers], ordering goods, and receiving [deliveries]."}, {"text": "A [shorter] supply chain is usually more reliable and easier to manage than a long one."}, {"text": "Zara can get new clothing designed, manufactured and delivered to its stores within [15] days."}, {"text": "Businesses that buy from suppliers with poor ethical standards risk damaging their own [reputation]."}, {"text": "Eddie Stobart is an example of a [logistics] business that manages the movement of goods for companies like Tesco."}, {"text": "Just-in-time delivery means parts arrive exactly when needed, which reduces [storage] costs."}, {"text": "When Crawford''s Biscuits factory was flooded in 2016, Tesco was unable to meet customer [demand] for custard creams."}, {"text": "Costa Coffee uses Rainforest Alliance-certified suppliers who meet [ethical] and environmental standards."}, {"text": "The [length] of the supply chain refers to how many businesses are involved between raw material and final product."}]}, "tf": {"enabled": true, "questions": [{"statement": "Procurement is the management of the transportation and storage of goods.", "answer": false, "explain": "FALSE. This is the definition of logistics, not procurement. Procurement is the management of purchasing within a business. This is one of the most common mix-ups students make in the exam."}, {"statement": "A longer supply chain is generally harder to manage than a shorter one.", "answer": true, "explain": "TRUE. More businesses involved in the chain means more coordination, more points of potential failure, and greater complexity. A shorter supply chain is easier to manage and generally more reliable."}, {"statement": "Just-in-time delivery means a business holds large stocks of materials in a warehouse at all times.", "answer": false, "explain": "FALSE. Just-in-time is the opposite — materials and parts arrive exactly when needed for production, so the business holds minimal stock. This reduces storage costs but requires highly reliable suppliers."}, {"statement": "Zara''s supply chain allows it to change clothing designs every two weeks.", "answer": true, "explain": "TRUE. Zara''s highly responsive supply chain — buying fabric in bulk from European suppliers for fast delivery to its Spanish factory — allows it to get new designs to stores in just 15 days, enabling bi-weekly design changes."}, {"statement": "The four stages of procurement are: identify goods, choose suppliers, order goods, receive deliveries.", "answer": true, "explain": "TRUE. These are the four official stages of the procurement process in the correct order. You should be able to recall and explain all four in an exam."}, {"statement": "Choosing the cheapest supplier is always the best procurement decision for a business.", "answer": false, "explain": "FALSE. The cheapest supplier may sacrifice quality, reliability, or ethical standards. A saving on costs could result in lower quality goods, less reliability, and a loss of reputation that is difficult to recover. Factors must be weighed together."}, {"statement": "If a supplier acts unethically, the reputation of the business that buys from them can also be damaged.", "answer": true, "explain": "TRUE. The buying business is often blamed in the media even if it was unaware of the ethical problem. This is why businesses like Primark, Zara, and Costa Coffee invest heavily in auditing their supply chains."}, {"statement": "Tesco''s procurement department deals only with buying food products for its supermarkets.", "answer": false, "explain": "FALSE. Procurement covers all goods and services a business needs to operate — including office supplies, cleaning services, technology, packaging, and more. It is not limited to the products sold in store."}, {"statement": "Reliability and time are closely linked logistical considerations.", "answer": true, "explain": "TRUE. A supplier that is ''sometimes'' on time is not truly reliable. Reliability includes delivering the right goods, in the right quantity, at the right time — consistently. The two factors reinforce each other."}, {"statement": "Eddie Stobart is an example of a procurement business.", "answer": false, "explain": "FALSE. Eddie Stobart (now The Logistics Development Group) is a logistics business — it manages the transportation of goods. Procurement is the buying/purchasing function. Tesco is the one doing the procurement; Eddie Stobart handles the logistics."}, {"statement": "A business can lose customers if its logistics supplier is unreliable, even if the product itself is good.", "answer": true, "explain": "TRUE. If goods are not delivered on time or are delivered incorrectly, the customer (who sees the retailer''s name, not the logistics firm''s) will lose confidence and may switch to a competitor. Poor logistics damages the reputation of the selling business."}]}, "misc": {"enabled": true, "items": [{"myth": "Procurement and logistics mean the same thing.", "truth": "They are two distinct concepts. Procurement is about managing the buying/purchasing of goods. Logistics is about managing the transportation and storage of goods. Many students swap these definitions and lose marks.", "check": {"question": "Which statement correctly distinguishes procurement from logistics?", "options": ["Procurement handles transporting goods; logistics handles the buying", "Procurement handles buying goods; logistics handles transport", "Both terms simply mean choosing which products a shop will sell", "Both terms simply describe managing the storage space for goods"], "answer": 1, "explain": "Procurement is the buying/purchasing function; logistics is the transport and storage of goods — swapping them loses marks."}}, {"myth": "The supply chain only includes the final manufacturer and the customer.", "truth": "The supply chain includes ALL businesses involved from raw material to the end user. A car''s supply chain might include mines, steel producers, component manufacturers, the car assembler, and the dealer — all are part of the chain.", "check": {"question": "Which businesses does a product''s supply chain include?", "options": ["Only businesses based within the same country as the retailer", "Only the shop that sells the product and the customer who buys it", "Only the final manufacturer and the customer who buys the product", "All businesses involved from the raw material stage to the end user"], "answer": 3, "explain": "The supply chain covers every business from raw material to end user — for a car that includes mines, steel producers, component makers, assembler and dealer."}}, {"myth": "A longer supply chain means lower costs because more suppliers are competing.", "truth": "A longer supply chain actually tends to increase costs and risk. More businesses means more transport, more handling, more coordination, and more potential points of failure. Costs are generally higher and reliability is lower in a long supply chain.", "check": {"question": "What is the general effect of a longer supply chain on costs and risk?", "options": ["It has no real effect on either costs or the risk involved", "It tends to increase both overall costs and the risk of disruption", "It lowers risk because responsibility is shared between more firms", "It lowers costs because so many more suppliers are competing"], "answer": 1, "explain": "More businesses in the chain means more transport, handling and coordination, so costs and the risk of disruption both tend to rise."}}, {"myth": "Low-cost suppliers will allow a business to raise its prices and make more profit.", "truth": "Low-cost suppliers allow a business to either keep prices competitive (lower than rivals) OR increase profit margins by keeping selling prices the same while paying less for inputs. They do not justify price increases — Primark, for example, uses low-cost suppliers specifically to undercut rivals on price.", "check": {"question": "What does using low-cost suppliers actually allow a business to do?", "options": ["Keep prices lower than rivals or raise its profit margins", "Ignore how reliable its suppliers are when placing orders", "Justify raising its selling prices well above those of rivals", "Automatically improve the quality of every product it sells"], "answer": 0, "explain": "Lower input costs let a business undercut rivals on price or widen its margins — they do not justify raising prices."}}, {"myth": "Procurement only covers the goods a business sells to customers.", "truth": "Procurement covers ALL goods and services a business needs to operate — including office stationery, cleaning services, IT equipment, and staff uniforms — as well as stock. David the biscuit factory procurement officer orders sugar AND printer paper.", "check": {"question": "What does the procurement function actually cover?", "options": ["Only the finished products the business sells to its customers", "Everything the business needs to run, including stock and supplies", "Only office supplies such as stationery and printer paper", "Only the transportation of the business''s finished goods"], "answer": 1, "explain": "Procurement covers all goods and services a business needs — stock plus stationery, cleaning, IT and uniforms — not just what it sells."}}, {"myth": "If a business has a reliable supplier, cost is irrelevant.", "truth": "Both reliability AND cost must be considered together. A very reliable but extremely expensive supplier may make the business unprofitable. The examiner expects students to evaluate both factors, not treat one as automatically more important.", "check": {"question": "Once a business has found a reliable supplier, how important is cost?", "options": ["Cost only ever matters when a supplier proves to be unreliable", "Cost becomes completely irrelevant once reliability is guaranteed", "Cost then becomes the only factor that really matters at all", "Cost still matters — a very reliable supplier can still be too costly"], "answer": 3, "explain": "The examiner expects both reliability and cost to be weighed together; a reliable but too-expensive supplier can still make the business unprofitable."}}, {"myth": "Just-in-time means the business orders goods just before they run out.", "truth": "Just-in-time (JIT) is a precise system where materials arrive exactly when needed on the production line — not simply ''ordering when stock is low''. It requires highly reliable suppliers and sophisticated coordination between buyer and supplier.", "check": {"question": "What does Just-In-Time (JIT) precisely involve?", "options": ["Buying materials only from whichever supplier is cheapest", "Ordering goods just before the existing stock finally runs out", "Holding large safety stocks just in case deliveries are delayed", "Materials arrive exactly when needed by reliable suppliers"], "answer": 3, "explain": "JIT is a precise system where materials arrive exactly when needed on the line — not simply reordering when stock is low."}}, {"myth": "A business that uses ethical suppliers will always have higher costs.", "truth": "While ethical suppliers can be more expensive, this is not always the case. Ethical sourcing can also bring long-term savings through reduced reputational risk, better supplier relationships, and more sustainable supply of materials. The examiner expects a balanced answer.", "check": {"question": "Is it true that using ethical suppliers always means higher costs?", "options": ["No — it can bring long-term savings via lower reputational risk", "Yes — ethical suppliers are always the most expensive option", "Yes — because ethical suppliers never offer discounts", "No — ethical sourcing has no effect on costs at all"], "answer": 0, "explain": "Ethical suppliers can cost more, but the examiner expects a balanced answer: they can also save money through lower reputational risk and better relationships."}}]}, "tips": {"enabled": true, "items": [{"title": "One Fact. Nothing More. Move On.", "html": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct, specific point. No explanation. No examples. No full sentences required.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague, general answer = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Procurement is about suppliers.\"</em><br/>\n      This is too vague — it says nothing specific about what procurement does.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Choosing suppliers.\"</em> or <em>\"Ordering goods and services.\"</em><br/>\n      Short, specific, and directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> The examiner''s report noted that more than half of candidates did not know what the ''procurement function'' meant — many linked it to finance or marketing. Know your key terms cold.</p>\n    ", "check": {"question": "What does a 1-mark ''State'' or ''Identify'' question require?", "options": ["A judgement supported by case study context", "Two connected points linked to the business", "A point plus a full explanation of why it matters", "One clear, specific point with no explanation needed"], "answer": 3, "explain": "A 1-mark State/Identify answer needs exactly one specific point — a vague answer scores zero and no explanation is required."}}, {"title": "Point + Link = 2 Marks", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question requires two connected steps: a point of knowledge AND a brief explanation of how it works or why it matters.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 (K):</strong> State the relevant fact or concept.</li>\n        <li><strong>Step 2 (APP):</strong> Link it briefly to the business in the question.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"JLP''s procurement team orders goods.\"</em><br/>\n      This states a role but gives no application to JLP specifically.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"One role of procurement is choosing which suppliers to use (K) — for example, JLP takes time evaluating high quality suppliers for its wide range of products including clothing and electronics (APP).\"</em></p>\n    ", "check": {"question": "What two steps earn full marks on a 2-mark ''Explain'' question?", "options": ["State two separate points but never apply either one", "Write a full four-paragraph evaluation of the topic", "Give a judgement, then justify that judgement fully enough", "State a relevant point, then briefly link to the business"], "answer": 3, "explain": "Point + Link: state the knowledge (K) then apply it to the business in the question (APP) — a point with no application caps you at one mark."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>Every 3-mark Analyse question on this topic follows the same structure. Miss any one of the three steps and you miss a mark. Miss application and you <strong>cannot</strong> gain the analysis mark either.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the benefit/impact/concept clearly. e.g., \"Having low-cost suppliers helps a business keep its prices lower than rivals...\"</li>\n        <li><strong>Step 2 — Application (APP):</strong> Quote or reference the specific business from the case study. e.g., \"...As Primark aims to sell clothing and homeware at prices lower than most other retailers...\"</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the business-facing financial or operational impact. e.g., \"...this will help Primark increase its market share and maintain its competitive advantage.\"</li>\n      </ul>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about procurement or supply chains. Examiners only award marks for content that directly answers the specific question asked.</p>\n      <p><strong>💡 The \"So What?\" Rule:</strong> After each sentence, ask yourself \"So what?\" until you reach a bottom-line business impact (profit, sales, reputation, market share, costs).</p>\n      <p><em>\"Low-cost suppliers keep costs down.\" → So what? → \"This improves profit margins.\" → So what? → \"This allows Primark to survive and grow in a competitive retail market.\"</em> ✅</p>\n    ", "check": {"question": "In a 3-mark Analyse answer, what happens if you leave out application?", "options": ["You gain an extra mark for a conclusion", "You cannot gain the analysis mark either", "You lose only the application mark", "You still earn full marks if the analysis is strong"], "answer": 1, "explain": "The chain is U → APP → AN; without application you forfeit the analysis mark too, so the case study must be used."}}, {"title": "Two Separate 3-Mark Answers", "html": "\n      <p>A 6-mark question is simply <strong>two 3-mark questions written back-to-back</strong>. Each impact needs its own U → APP → AN chain.</p>\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Impact 1:</strong> U → APP → AN (3 marks)</li>\n        <li><strong>Impact 2:</strong> U → APP → AN (3 marks)</li>\n      </ul>\n      <p><strong>⚠️ Warning:</strong> Do NOT write a conclusion. There are zero marks available for evaluation in a 6-mark question. Spend the time making sure both impacts are fully analysed with application instead.</p>\n      <p><strong>Example (Pukka Pies, 6 marks):</strong></p>\n      <p><em>Impact 1 — Supply Chain Length: \"A long supply chain involves many businesses (U). Pukka Pies sources ingredients from across the UK and overseas (APP). This makes it harder to coordinate deliveries, increasing the risk that ingredients do not arrive on time and production is disrupted (AN).\"</em></p>\n      <p><em>Impact 2 — Time-Critical Logistics: \"Timing is vital for delivering fresh ingredients to ensure production is not delayed (U). Pukka Pies makes high-quality savoury pies that need fresh ingredients and has food safety as a key value (APP). If deliveries are late, the business may need to recall products or halt production, increasing costs and damaging its reputation (AN).\"</em></p>\n    ", "check": {"question": "Should you write a conclusion in a 6-mark ''Analyse two impacts'' question?", "options": ["No — a 6-mark question actually only needs one full impact", "Yes — the conclusion is where application marks are always awarded", "Yes — a strong conclusion earns the final two marks available", "No — there are no evaluation marks, so focus fully on both impacts"], "answer": 3, "explain": "A 6-mark question is two 3-mark U→APP→AN chains with no evaluation marks, so a conclusion wastes time better spent analysing."}}, {"title": "Argue Both Sides, Then Make a Justified Judgement", "html": "\n      <p>A 7-mark evaluate question tests all skills. You need application, analysis, AND a justified evaluation. This is the question where most students leave marks on the table.</p>\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K &amp; U:</strong> Introduce the key concept and show you understand the issue. e.g., \"Reliable suppliers are those who consistently deliver the right quality and quantity on time...\"</li>\n        <li><strong>Paragraph 2 — AN &amp; APP (Side A):</strong> Analyse the first side using case study context. e.g., \"Given that Zara has 2,270 stores (APP), reliable suppliers ensure products are available in every shop — without them, Zara would miss out on sales (AN).\"</li>\n        <li><strong>Paragraph 3 — AN &amp; APP (Counter-argument):</strong> Analyse the other side. e.g., \"However, if customer incomes fall, Zara''s sales will decline regardless of supplier reliability (APP/AN).\"</li>\n        <li><strong>Paragraph 4 — Evaluation (3 points):</strong> Make a justified decision using context. Decision + Reason using context + Qualifying condition (\"It depends on...\").</li>\n      </ul>\n      <p><strong>✅ Evaluation Sentence Starters:</strong></p>\n      <ul>\n        <li>\"Overall, I believe reliable suppliers are the most important factor for Zara because...\"</li>\n        <li>\"Without reliable suppliers, Zara''s USP of changing designs every 2 weeks would be impossible...\"</li>\n        <li>\"However, this depends on whether Zara''s competitors also improve their supply chains...\"</li>\n      </ul>\n      <p><strong>❌ A weak conclusion that scores 0 eval marks:</strong><br/>\n      <em>\"In conclusion, reliable suppliers are important for Zara.\"</em><br/>\n      This just repeats what was already said. A good evaluation adds NEW reasoning, a condition, or a comparison.</p>\n    ", "check": {"question": "What makes a conclusion score evaluation marks in a 7-mark question?", "options": ["It avoids mentioning the case study business", "It lists every fact known about the topic", "It restates the strongest point already made before", "It adds new reasoning, a condition, or a comparison"], "answer": 3, "explain": "Evaluation marks reward a justified judgement that adds something new — a condition (''it depends on...'') or comparison — not a repeat of earlier points."}}, {"title": "Judgement + Justification + Context", "html": "\n      <p>Some 3-mark questions ask you to <strong>recommend</strong> or <strong>evaluate</strong> between two options. This is a mini-evaluation requiring three clear elements.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> State your clear choice. e.g., \"I think reliability is the most important consideration for Tesco when choosing a logistics business.\"</li>\n        <li><strong>Justification (1 mark):</strong> Give a reason that compares both options. e.g., \"If the logistics operator is not reliable, goods will not be on shelves at the right time and customers will go to competitors — having a greater impact than a small cost increase.\"</li>\n        <li><strong>Context (1 mark):</strong> Use specific detail from the case study to support your judgement.</li>\n      </ul>\n      <p><strong>⚠️ Critical Rule:</strong> Your justification MUST compare both options (cost vs reliability, meeting vs email, etc.). Simply saying why Option A is good, without comparing it to Option B, will not earn the full justification mark.</p>\n    ", "check": {"question": "What must the justification do in a 3-mark ''recommend'' question?", "options": ["Simply repeat the judgement again but using different words", "Describe only the chosen option in a lot of detail", "Compare both options rather than just explain why one is good", "Avoid using any specific detail from the case study"], "answer": 2, "explain": "A recommend answer needs judgement + justification + context, and the justification must compare both options to earn its mark."}}]}, "exam": {"enabled": true, "questions": [{"question": "Explain what is meant by logistics. [1 mark]", "marks": 1, "hint": "Give the official definition — what does logistics manage?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark</h5><ul><li><strong>1 mark:</strong> The management of the transportation (and storage) of goods / organising how goods are moved from seller to buyer.</li></ul><p>Accept any answer that references the movement/transport/storage of goods.</p></div>"}, {"question": "Explain how logistics is involved in the production of custard creams. [2 marks]", "marks": 2, "hint": "Think about how the biscuits get from Crawford''s factory to Tesco''s shelves — what needs to happen? Apply the definition of logistics to the actual process described.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks</h5><ul><li><strong>Knowledge/Understanding (1 mark):</strong> Shows understanding of logistics — e.g., the transportation/movement of goods from producer to retailer/consumer.</li><li><strong>Application (1 mark):</strong> Links logistics specifically to custard creams — e.g., Crawford''s delivers biscuits from its factory in Carlisle to Tesco stores / warehouses across the UK.</li></ul></div>"}, {"question": "Analyse the impact on Tesco of the problems with the supply chain of custard creams. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. First explain what the supply chain problem was, then link it to Tesco, then state the business impact on Tesco (sales, reputation, costs, revenue).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (3 marks: U + APP + AN)</h5><ul><li><strong>Understanding (1 mark):</strong> Shows understanding of the supply chain problem — e.g., Crawford''s could not produce/supply biscuits due to factory damage.</li><li><strong>Application (1 mark):</strong> Links to Tesco specifically — e.g., Tesco was unable to buy enough custard creams to stock its shelves.</li><li><strong>Analysis (1 mark):</strong> States the business-facing impact on Tesco — e.g., lost sales and revenue / damage to reputation / customers going to competitors.</li></ul><p><strong>Note:</strong> Application and Analysis marks cannot be awarded without Understanding.</p></div>"}, {"question": "Analyse how the rise in fuel prices might affect sales of custard creams at Tesco. [3 marks]", "marks": 3, "hint": "Think about the chain of effects: fuel prices rise → transport costs rise → production costs rise → what happens to the price of biscuits in Tesco → what happens to sales?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (3 marks: U + APP + AN)</h5><ul><li><strong>Understanding (1 mark):</strong> Rising fuel prices increase transport/logistics costs.</li><li><strong>Application (1 mark):</strong> Links to custard creams/Crawford''s/Tesco specifically — delivery costs from Carlisle increase.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — higher costs passed on through higher prices → reduced sales / lower profitability for Tesco.</li></ul></div>"}, {"question": "Analyse one benefit to Tesco plc of using cost as a consideration when choosing a logistics business as part of its supply chain. [3 marks]", "marks": 3, "hint": "U → APP → AN. The benefit is about keeping costs down. Why does that matter specifically to Tesco? What is the financial or competitive impact?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (3 marks: U + APP + AN)</h5><ul><li><strong>Understanding (1 mark):</strong> Gives an advantage of considering costs — e.g., helps maintain profitability / keeps prices low / reduces break-even point.</li><li><strong>Application (1 mark):</strong> Links to Tesco from the case study — e.g., Tesco is in a competitive market and needs to keep costs down; DHL won two distribution contracts (competitive bidding).</li><li><strong>Analysis (1 mark):</strong> States the impact on the business — e.g., reducing costs allows Tesco to keep prices lower than competitors, helping maintain market share and profitability.</li></ul><p><strong>Note:</strong> No reward for simply stating ''lower costs'' without explaining the benefit.</p></div>"}, {"question": "Analyse one benefit to Tesco plc of using reliability as a consideration when choosing a logistics business as part of its supply chain. [3 marks]", "marks": 3, "hint": "U → APP → AN. What is the benefit of a reliable logistics provider? Why is this particularly important for a supermarket like Tesco? What happens if logistics is unreliable?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (3 marks: U + APP + AN)</h5><ul><li><strong>Understanding (1 mark):</strong> Shows understanding of a benefit of reliability — e.g., ensures goods are available at the right time in the right quantity.</li><li><strong>Application (1 mark):</strong> Links to Tesco — e.g., as a supermarket, Tesco needs fresh produce delivered daily; Eddie Stobart retained four distribution centre contracts by being reliable.</li><li><strong>Analysis (1 mark):</strong> States the business-facing impact — e.g., if logistics is unreliable, goods are not on shelves and customers go to competitors, permanently damaging Tesco''s reputation.</li></ul></div>"}, {"question": "Evaluate whether Tesco plc should use cost or reliability as a consideration when choosing a logistics business as part of its supply chain. [3 marks]", "marks": 3, "hint": "Make a clear choice (1 mark). Give a reason that compares BOTH options (1 mark). Use specific details from the case study (1 mark). Your justification must explain why your chosen factor is MORE important than the other.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO3b = 3 marks: Judgement + Justification + Context)</h5><ul><li><strong>Judgement (1 mark):</strong> Clear recommendation — reliability OR cost is most important.</li><li><strong>Justification (up to 2 marks):</strong> Comparative reason using case study detail explaining why the chosen factor is more important than the other.</li><li><strong>Non-contextual justification (1 mark only):</strong> Comparative reason without case study detail.</li></ul><p><strong>Note:</strong> Justification must cover BOTH factors to earn justification marks.</p></div>"}, {"question": "Analyse one benefit for Primark Ltd of having low-cost suppliers. [3 marks]", "marks": 3, "hint": "Remember: the benefit of LOW-COST suppliers is NOT to raise prices — it is to keep prices LOW or to increase profit margins. Apply this specifically to what Primark is known for.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (3 marks: U + APP + AN)</h5><ul><li><strong>Understanding (1 mark):</strong> States a benefit of low-cost suppliers — e.g., can pay less for raw materials / keep prices low / buy in bulk / reduce break-even / more money available for other areas.</li><li><strong>Application (1 mark):</strong> Links to Primark — e.g., sells clothing and homeware at prices lower than most retailers / has a click and collect service / aware of need for ethical suppliers.</li><li><strong>Analysis (1 mark):</strong> States the business impact — e.g., can increase sales / maintain market share / compete with other retailers / maintain or improve profit margins.</li></ul><p><strong>NB:</strong> Analysis must be business-facing. No reward for only stating ''low costs'' or ''costs will be lower'' as a benefit.</p><p><strong>⚠️ Examiner''s Comment:</strong> About 60% of candidates gained 2–3 marks. Many candidates did not clearly state a benefit — they only mentioned ''low cost'' and did not gain the understanding mark. Some incorrectly suggested low-cost suppliers would allow Primark to raise prices, which shows a misunderstanding of Primark''s business model.</p></div>"}, {"question": "The role of procurement for a car manufacturer might involve:", "marks": 1, "hint": "Think: which option is about BUYING or receiving goods — not selling, marketing, or testing?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Receiving deliveries of tyres and windscreens</h5><ul><li><strong>Why C is correct:</strong> Procurement covers all stages of buying — including receiving deliveries of components like tyres and windscreens (Stage 4 of procurement).</li><li><strong>Why A is wrong:</strong> Advertising is a marketing activity, not procurement.</li><li><strong>Why B is wrong:</strong> Negotiating with showrooms is a sales/distribution decision, not procurement.</li><li><strong>Why D is wrong:</strong> Testing brakes is a quality control or operations task, not procurement.</li></ul></div>"}, {"question": "Identify two roles of the procurement function in a business. [2 marks]", "marks": 2, "hint": "There are four official stages of procurement. State two of them clearly. Your answers do not need to relate specifically to Zara.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (2 marks: 1 mark per correct role)</h5><ul><li>Identifying goods and services to buy / finding materials</li><li>Ordering or purchasing goods and services</li><li>Identifying or choosing suppliers</li><li>Receiving deliveries from suppliers</li></ul><p><strong>Note:</strong> Answers do not need to relate to Zara. 1 mark for each correct role, up to 2 marks.</p><p><strong>⚠️ Examiner''s Comment:</strong> Only about 1 in 5 candidates gained both marks. More than half did not know what ''procurement function'' meant — many gave answers about finance or marketing.</p></div>"}, {"question": "Evaluate the importance to Zara of having reliable suppliers in the supply chain for its clothing. [7 marks]", "marks": 7, "hint": "This is a 7-mark evaluate question. Use all four skills: APP, AN, and EVAL. Argue both sides (why reliable suppliers matter AND whether other factors could be more important). End with a justified conclusion using context from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (7 marks total)</h5><ul><li><strong>Application — up to 2 marks:</strong> Context from the case study must be used (not just referenced). e.g., 2,270 stores / changing designs every 2 weeks / 15-day turnaround / suppliers from Europe, Asia, Africa / sales fell 29% in 2020 / online sales up 75%.</li><li><strong>Analysis — up to 2 marks:</strong> Business-facing impact. e.g., without reliable suppliers sales/profits would fall as Zara cannot stock shelves; Zara''s reputation would suffer if designs cannot be changed every 2 weeks; loss of USP and competitive advantage.</li><li><strong>Evaluation — up to 3 marks:</strong> Justified judgement about importance of reliable suppliers using case study evidence. For full 3 marks: decision + contextual reasoning + qualification or comparison.</li></ul></div><div class=\"marks-section\"><h5>Level of Response Grid</h5><ul><li><strong>Strong (7 marks):</strong> Two uses of context [APP][APP] + Two business-facing analyses [AN][AN] + Justified contextual evaluation [EVAL][EVAL][EVAL]</li><li><strong>Good (4–5 marks):</strong> One/two uses of context + one/two analyses + limited evaluation</li><li><strong>Limited (1–2 marks):</strong> General points without context or analysis</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> Excellent answers made good use of Zara''s reputation for speed and frequency, changing designs every two weeks, and global suppliers. About a third of answers contained no context. Very few candidates gained all 3 evaluation marks — a conclusion must add NEW reasoning, not just repeat analysis points.</p><p><strong>Assessment for Learning:</strong> There are only 2 marks each for application and analysis. Candidates should make only TWO well-developed points, not three or four. More points gain no extra marks but waste time.</p></div>"}, {"question": "Analyse the impact of each of the following on Pukka Pies Ltd:\n• the length of its supply chain\n• the time-critical nature of its logistics\n[6 marks]", "marks": 6, "hint": "This is TWO separate 3-mark analyses. For each one: U (what is the issue?) → APP (link to Pukka Pies specifically) → AN (what is the business impact on Pukka Pies?). Do NOT write a conclusion — there are no evaluation marks here.", "markScheme": "<div class=\"marks-section\"><h5>Supply Chain Length (3 marks: U + APP + AN)</h5><ul><li><strong>Understanding (1 mark):</strong> The supply chain is the number of organisations involved in bringing the product/materials to the business; longer chain = more coordination required.</li><li><strong>Application (1 mark):</strong> Pukka Pies sources ingredients from across the UK and overseas; supply chain is described as ''long''; must meet demand of 4,000+ food stores.</li><li><strong>Analysis (1 mark):</strong> Need to manage and coordinate many suppliers to ensure timely delivery; risk of disruption anywhere in the chain; increased cost of operating a complex supply chain; impact on quality.</li></ul></div><div class=\"marks-section\"><h5>Time-Critical Nature of Logistics (3 marks: U + APP + AN)</h5><ul><li><strong>Understanding (1 mark):</strong> Timing is vital for delivery of raw materials so production is not delayed and finished products are delivered on time.</li><li><strong>Application (1 mark):</strong> Pukka Pies makes high-quality pies requiring fresh ingredients; food safety is a key value; perishable product; supplies come from UK and overseas.</li><li><strong>Analysis (1 mark):</strong> Increased costs if supply chain fails; risk of unsafe food preparation and expensive product recall; loss of reputation if products not delivered on time to 4,000+ stores.</li></ul></div>"}, {"question": "Recommend whether the length of its supply chain or the time-critical nature of its logistics has the greater impact on Pukka Pies Ltd''s success. [3 marks]", "marks": 3, "hint": "Make a clear choice (1 mark). Give a comparative reason (1 mark). Use context from the case study in your justification (1 mark). Your reason must explain why your choice has MORE impact than the other.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO3b = 3 marks)</h5><ul><li><strong>Judgement (1 mark):</strong> Clear recommendation — supply chain length OR time-critical logistics has the greater impact.</li><li><strong>Justification (1 mark):</strong> Comparative reason explaining why the chosen factor has a greater impact on Pukka Pies''s success than the other.</li><li><strong>Context (1 mark):</strong> Use of specific information from the case study within the justification.</li></ul></div>"}, {"question": "Hugh works in procurement at a factory that makes jeans. Which of the following would NOT be part of Hugh''s job role?", "marks": 1, "hint": "Procurement is about BUYING goods and services. Which option is a manufacturing/production task, not a purchasing task?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Sewing the size label on to the waistband</h5><ul><li><strong>Why D is correct:</strong> Sewing labels is a production/manufacturing task carried out on the factory floor — it has nothing to do with purchasing or procurement.</li><li><strong>Why A is wrong:</strong> Choosing a supplier of zips and buttons is Stage 2 of procurement — this is clearly part of Hugh''s role.</li><li><strong>Why B is wrong:</strong> Procurement covers ALL goods the business needs, including office supplies like printer paper — not just production materials.</li><li><strong>Why C is wrong:</strong> Receiving deliveries of threads and fabrics is Stage 4 of procurement.</li></ul></div>"}, {"question": "Explain one role of procurement within JLP. [2 marks]", "marks": 2, "hint": "State a specific role of procurement (1 mark), then link it to JLP''s actual products or business context (1 mark). Do NOT just say JLP has a wide range of products — that is not knowledge of procurement.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (2 marks: K + APP)</h5><ul><li><strong>Knowledge (1 mark):</strong> Identifying goods and services to buy / choosing suppliers / ordering goods and services / receiving deliveries from suppliers.</li><li><strong>Application (1 mark):</strong> Links to JLP — e.g., evaluating high quality suppliers for its clothing, home furnishings, electronics; reviewing suppliers regularly; sourcing computers, TVs, and washing machines.</li></ul><p><strong>Note:</strong> Do not reward answers that only refer to JLP ''having a wide range of products'' — this is not knowledge of procurement.</p><p><strong>✅ Exemplar response 1:</strong> \"To identify high-quality suppliers (K) for the wide range of products JLP sells, such as computers and washing machines (APP).\"</p><p><strong>✅ Exemplar response 2:</strong> \"One role of procurement is to choose which suppliers to use (K) — JLP takes time evaluating new and existing suppliers to ensure it can supply high-quality products to its customers (APP).\"</p></div>"}, {"question": "Identify two factors that affect the supply decisions made by a business. [2 marks]", "marks": 2, "hint": "Name two separate factors from the list of logistical/supply considerations. No explanation needed — just name them clearly.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (2 marks: 1 mark each)</h5><ul><li>Reliability / reputation of supplier</li><li>Length of supply chain</li><li>Time / speed / location</li><li>Costs / price of supplies</li><li>Customer service</li><li>Availability of substitutes / number of competing suppliers</li><li>Quality of goods supplied</li></ul><p><strong>Note:</strong> Answers do not need to relate to JLP. 1 mark for each correct factor, maximum 2.</p></div>"}, {"question": "Evaluate factors that may have influenced JLP when choosing which suppliers to use. [7 marks]", "marks": 7, "hint": "This is a 7-mark evaluate question. Discuss multiple factors (quality, reliability, cost, speed), apply each to JLP''s specific context, analyse the business impact, then evaluate which factor is most important for JLP and why — using the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (7 marks total)</h5><ul><li><strong>Application — up to 2 marks:</strong> Context from JLP case study used — e.g., chain of department stores / wide range of products / clothing, home furnishings, computers, TVs, washing machines / e-commerce growth / high quality suppliers / regular evaluation of suppliers.</li><li><strong>Analysis — up to 2 marks:</strong> Business-facing impacts — e.g., impact on customer service, sales, reputation, supply chain length, costs, or business risk.</li><li><strong>Evaluation — up to 3 marks:</strong> Justified judgement about which factor(s) are most important for JLP when choosing suppliers, using case study context.</li></ul><p><strong>Note:</strong> Ensure answers focus on CHOOSING SUPPLIERS rather than choosing specific products. For full 3 evaluation marks, the evaluation must be contextual.</p></div>"}, {"question": "Explain two reasons why Tesco plc needs reliable suppliers. [4 marks]", "marks": 4, "hint": "For each reason: state the reason (U/K) and then apply it to Tesco (APP). 2 marks per reason. Think about what would happen to Tesco''s shelves, reputation, and sales if suppliers were unreliable.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (4 marks: 2 marks per reason)</h5><ul><li><strong>Knowledge/Understanding of each reason (1 mark each):</strong> e.g., need products to sell in store; reputation harmed if products unavailable; customers expect same products each visit; building trust with suppliers; quality of products sold.</li><li><strong>Application to Tesco (1 mark each):</strong> e.g., Tesco sells through shops AND e-commerce so needs stock for both channels; facing increasing competition — stock availability is key to retaining customers; core purpose is to provide great products at great value.</li></ul><p><strong>Exemplar response 1:</strong> \"Tesco needs reliable suppliers to ensure it has products to sell on its shelves (K). Without reliable supplies, Tesco''s profit and sales could be affected as customers may go to competitors (APP).\"</p><p><strong>Exemplar response 2:</strong> \"Reliable suppliers must deliver quality products consistently (K). If quality is inconsistent, Tesco''s reputation may be damaged and its sales may decrease (APP).\"</p></div>"}, {"question": "The length of a firm''s supply chain:", "marks": 1, "hint": "Think about Zara — how does its short, fast supply chain allow it to respond to fashion trends every two weeks?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Affects how quickly it can respond to changes in demand</h5><ul><li><strong>Why A is correct:</strong> A shorter supply chain allows a business to respond much more quickly to changes in customer demand — as shown by Zara''s 15-day turnaround. A longer chain means slower response times.</li><li><strong>Why B is wrong:</strong> Production methods (batch, flow, job) do not determine the length of the supply chain — these are separate decisions.</li><li><strong>Why C is wrong:</strong> Supply chain length absolutely affects procurement — longer chains are harder to manage and more prone to disruption.</li><li><strong>Why D is wrong:</strong> Organisation charts show internal staff hierarchy, not supply chain structure.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> This question is best approached by discounting wrong options one at a time. Many candidates rush MCQs — take time to eliminate each incorrect answer carefully.</p></div>"}, {"question": "David works in a biscuit factory and is responsible for procurement. Which task is NOT likely to be part of David''s job role?", "marks": 1, "hint": "Procurement is about BUYING goods and services. Which option is about SELLING — which is a completely different business function?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Selling biscuits</h5><ul><li><strong>Why D is correct:</strong> Selling biscuits is a sales and marketing task — completely separate from procurement. Procurement manages purchasing/buying, not selling.</li><li><strong>Why A is wrong:</strong> Buying sugar is a core procurement task — purchasing raw materials for production.</li><li><strong>Why B is wrong:</strong> Ordering packaging materials is procurement — everything needed to operate the factory falls under procurement.</li><li><strong>Why C is wrong:</strong> Procurement covers all goods a business needs, including office stationery — not just production inputs.</li></ul></div>"}, {"question": "Choosing how products will be delivered to customers is an example of a:", "marks": 1, "hint": "Logistics is the management of transportation and storage. Which answer word directly links to this?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Logistical decision</h5><ul><li><strong>Why C is correct:</strong> Choosing how products are delivered is a transportation/logistics decision — logistics manages the movement of goods from seller to buyer.</li><li><strong>Why A is wrong:</strong> Flow production is a manufacturing method (mass production on a conveyor belt) — it is not about delivery to customers.</li><li><strong>Why B is wrong:</strong> Liquidity is a finance concept about a business''s ability to meet short-term debts — nothing to do with delivery.</li><li><strong>Why D is wrong:</strong> Purchasing concerns involve buying goods and services — not deciding how finished products reach customers.</li></ul></div>"}, {"question": "If JLR buys 500,000 tyres and 80% of these are bought from overseas suppliers, calculate the number of tyres JLR buys from overseas. [1 mark]", "marks": 1, "hint": "Percentage calculation: (500,000 ÷ 100) × 80 = ? Always show your working even for 1-mark calculations.", "markScheme": "<div class=\"marks-section\"><h5>Answer: 400,000 tyres</h5><ul><li><strong>Workings:</strong> 500,000 × 80 ÷ 100 = 400,000</li><li>1 mark for the correct answer of 400,000.</li></ul></div>"}, {"question": "Choosing which supplier to use is a:", "marks": 1, "hint": "Which business function is specifically responsible for managing the buying and purchasing of goods and services?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Procurement decision</h5><ul><li><strong>Why C is correct:</strong> Selecting and managing suppliers is the core activity of procurement. Stage 2 of the procurement process is ''Choosing Suppliers''.</li><li><strong>Why A is wrong:</strong> Marketing involves promoting products and understanding customer needs — not purchasing from suppliers.</li><li><strong>Why B is wrong:</strong> Pricing decisions involve setting the price of the business''s own products or services.</li><li><strong>Why D is wrong:</strong> Sales decisions involve selling the business''s products to customers.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> Many candidates did not know what ''procurement'' meant, making all options seem plausible. Know your key terms — procurement is the management of purchasing within a business.</p></div>"}, {"question": "A supermarket decides to extend its opening hours. The supermarket is likely to need:", "marks": 1, "hint": "Extended hours means more time when customers can buy products. What does the supermarket need to ensure those products are always available?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Reliable suppliers</h5><ul><li><strong>Why D is correct:</strong> Extended opening hours means goods must be available for longer periods. Reliable suppliers ensure shelves stay stocked throughout extended trading hours. Without reliable deliveries, extended hours would mean empty shelves.</li><li><strong>Why A is wrong:</strong> A longer supply chain increases risk and complexity — it makes stocking shelves harder, not easier.</li><li><strong>Why B is wrong:</strong> Extended hours typically require MORE staff to cover longer shifts, not fewer.</li><li><strong>Why C is wrong:</strong> There is no reason extended opening hours would reduce the quality required of products.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> This question is best approached by discounting wrong options. Each option is close to a right-sounding answer — careful elimination of A, B, and C reveals D as the only logical choice.</p></div>"}, {"question": "The data shows that:", "marks": 1, "hint": "Add up all three transport costs for 2018: Road + Rail + Air. Is the total more than £1,250,000? Check each other option by working through the data carefully.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — GLU plc spent more than £1.25 million on transport costs in 2018</h5><ul><li><strong>Why C is correct:</strong> 2018 costs: Road £190,000 + Rail £430,000 + Air £650,000 = £1,270,000. This is greater than £1,250,000 ✅</li><li><strong>Why A is wrong:</strong> Higher air costs reflect the higher unit price of air freight, not a preference. We cannot determine preference from cost data alone.</li><li><strong>Why B is wrong:</strong> ALL costs increased year on year in every category — they did not fall.</li><li><strong>Why D is wrong:</strong> Higher rail costs than road costs do not mean more goods are transported by rail — air freight costs more per unit so fewer goods could generate a higher total cost.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> This numerical question required time to validate or discount each option. Do not rush MCQs — spend time checking the data carefully.</p></div>"}, {"question": "Explain two possible reasons why Costa Coffee uses coffee beans from Rainforest Alliance-certified coffee suppliers. [4 marks]", "marks": 4, "hint": "For each reason: state WHY Costa chooses certified suppliers (U/K) and then apply it to Costa''s specific situation (APP). Think about reputation, competition, reliability, and ethical positioning.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (4 marks: 2 marks per reason)</h5><ul><li><strong>Understanding of each reason (1 mark each):</strong> e.g., to protect/enhance reputation; to use in marketing; reliability of supplies; quality of beans (certified standard); ethical reasons; environmental reasons.</li><li><strong>Application to Costa Coffee (1 mark each):</strong> e.g., Costa meets its own ethical/environmental standards; competitive market with Starbucks; switched to environmentally-friendly coffee; owned by Coca-Cola (importance of reputation); importance of consistency when selling an edible product across 3,300+ stores.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> Most candidates could state one benefit such as increased reputation, but fewer could apply it to Costa''s specific context. Start with the data — what does the case study tell you about Costa that makes each reason particularly relevant?</p></div>"}]}}'::jsonb),
('business', '5-1-role-of-finance-function', '5.1 Role of Finance Function', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must know for this topic. Learn them precisely — examiners reward specific, accurate vocabulary.</p>\n<ul>\n  <li><strong>Finance Function:</strong> The department within a business (also called the finance department) responsible for managing money. Only found in larger businesses — small businesses usually employ an external accountant instead.</li>\n  <li><strong>Financial Information:</strong> Data including profit, loss, cash flow, break-even, profit margin, and average rate of return. Used to support business decision-making.</li>\n  <li><strong>Revenue:</strong> The money a business receives from selling goods or services.</li>\n  <li><strong>Costs:</strong> The expenses involved in making and selling a good or service.</li>\n  <li><strong>Profit/Loss:</strong> Found by subtracting total costs from total revenue. If revenue > costs = profit; if costs > revenue = loss.</li>\n  <li><strong>Break-Even:</strong> The number of products a business must sell to cover all its costs — neither making a profit nor a loss.</li>\n  <li><strong>Cash Flow:</strong> The movement of money into (inflows) and out of (outflows) a business over time.</li>\n  <li><strong>Forecast:</strong> An estimate or prediction of what is expected to happen in the future (e.g. a cash-flow forecast).</li>\n  <li><strong>Sources of Finance:</strong> Where a business gets money from — examples include savings, loans, overdrafts, and share issues.</li>\n  <li><strong>Interdependence:</strong> The way in which different departments within a business rely on each other to operate effectively.</li>\n</ul>", "check": {"question": "According to the key definitions, what is the ''finance function''?", "options": ["The department in a larger business that recruits staff and organises training programmes", "The department in a larger business that designs adverts and researches target customers", "The department in a larger business that manufactures goods and inspects finished products", "The department in a larger business that manages money and produces financial information"], "answer": 3, "explain": "The card defines the finance function as the department that manages money and produces financial information — distinct from HR, marketing, or production departments."}}, {"title": "The Purpose of the Finance Function", "html": "<p>The finance function exists to serve the whole business. Its two core purposes are:</p>\n<ul>\n  <li><strong>Supporting business planning and decision-making:</strong> The finance function contributes to the business plan and ensures all decisions are backed by accurate financial data.</li>\n  <li><strong>Providing financial information:</strong> It produces data on costs, revenues, profit/loss, cash flow, and break-even that other departments rely on to operate.</li>\n</ul>\n<p>Without reliable financial information, a business cannot plan effectively, cannot raise the funding it needs, and may make costly mistakes. As the textbook states: <em>it is vital for any business that this data is accurate and up to date.</em></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Large Businesses</div>\n    <div class=\"pro-item\"><strong>Dedicated team:</strong> Have their own finance department with specialist staff (e.g. accountants, financial analysts).</div>\n    <div class=\"pro-item\"><strong>In-house expertise:</strong> Can respond quickly to financial questions from other departments.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Small Businesses</div>\n    <div class=\"con-item\"><strong>No finance department:</strong> Sole traders and partnerships usually hire an external accountant to check their finances.</div>\n    <div class=\"con-item\"><strong>Limited resources:</strong> Cannot afford a full-time specialist finance team, which may slow decision-making.</div>\n  </div>\n</div>", "check": {"question": "What are the two core purposes of the finance function described in this card?", "options": ["Recruiting new employees and organising staff appraisal and training programmes", "Supporting business planning and providing financial information to other departments", "Negotiating supplier contracts and managing the delivery of essential raw materials", "Designing new products and setting prices for the firm''s target market segments"], "answer": 1, "explain": "The card states the finance function exists to support business planning/decision-making and to provide financial information — not product design, recruitment, or supply-chain tasks."}}, {"title": "Roles of the Finance Function", "html": "<p>The finance function carries out a wide range of tasks to keep a business financially healthy. These include:</p>\n<ul>\n  <li><strong>Calculating sales revenues and production costs:</strong> Ensures the business knows exactly how much it earns and spends.</li>\n  <li><strong>Calculating profit or loss:</strong> Tells managers whether the business is financially viable.</li>\n  <li><strong>Forecasting cash flow:</strong> Uses expected revenues and expenditures to predict whether extra finance will be needed at any point.</li>\n  <li><strong>Calculating the break-even output:</strong> Identifies how many units must be sold to avoid a loss — essential for pricing and production decisions.</li>\n  <li><strong>Calculating the average rate of return:</strong> Measures how well an investment is performing over time.</li>\n  <li><strong>Arranging finance:</strong> Sources funding such as loans, overdrafts, or share issues when the business needs capital.</li>\n  <li><strong>Managing payments and receipts:</strong> Ensures bills are paid on time and money owed to the business is collected.</li>\n</ul>\n<p>⚠️ <strong>Examiner Warning:</strong> The finance function does NOT advertise products, recruit staff, make quality decisions, or choose marketing methods. These belong to other departments. Confusing these is a very common mistake.</p>", "check": {"question": "Which of these is listed as a role of the finance function, rather than another department?", "options": ["Choosing which television advert style will attract more customers", "Deciding which candidates should be shortlisted for interview", "Checking that finished goods meet the required quality standard", "Calculating the break-even output needed to avoid making a loss"], "answer": 3, "explain": "The card lists calculating break-even output as a finance function task; advertising style, recruitment shortlisting and quality checks belong to marketing, HR and operations instead."}}, {"title": "How the Finance Function Influences Business Activity", "html": "<p>The finance function does not just record numbers — it actively shapes what the business can and cannot do. Here are key examples:</p>\n<ul>\n  <li><strong>Going environmentally friendly:</strong> The finance function calculates the extra costs involved, monitors cash flow, and may need to arrange additional finance to fund the changes.</li>\n  <li><strong>Responding to a recession:</strong> Provides revenue and cost data to help the business decide how to cut costs or protect cash flow.</li>\n  <li><strong>Changing production methods (e.g. job to flow):</strong> Forecasts changes in revenue, costs, and cash flow, and calculates the new break-even output.</li>\n  <li><strong>Running a marketing campaign:</strong> Sets a budget and monitors sales and profit data during and after the campaign to judge whether it was successful.</li>\n  <li><strong>Business expansion:</strong> Advises on sources of finance, forecasts costs, and models the impact on break-even and cash flow.</li>\n  <li><strong>Changing the way products are sold (e.g. moving online):</strong> Provides data on the impact of different sales channels on revenues and costs.</li>\n</ul>\n<p>This shows that business departments are <strong>interdependent</strong> — they rely on each other. The finance function sits at the heart of this, providing data that every other department needs to make good decisions.</p>", "check": {"question": "How does the finance function support a business that is changing its production method?", "options": ["It writes the new job descriptions needed for the fully redesigned production process", "It designs the new packaging that will be used once production has changed", "It negotiates the planning permission needed for the new production site", "It forecasts changes in revenue and costs and recalculates the new break-even output"], "answer": 3, "explain": "The card explains that when production methods change, finance forecasts revenue/cost changes and recalculates break-even — not job design, packaging, or planning permission."}}, {"title": "Finance and Business Growth", "html": "<p>The ability (or inability) to raise finance has a direct effect on how a business grows and what legal form it takes.</p>\n<ul>\n  <li><strong>Sole trader &rarr; Partnership:</strong> A sole trader who wants to expand may invite someone who can provide capital to become a partner.</li>\n  <li><strong>Partnership &rarr; Private Limited Company (Ltd):</strong> Partnerships may incorporate as a private limited company so they can sell shares and expand ownership.</li>\n  <li><strong>Private Limited Company &rarr; Public Limited Company (plc):</strong> A plc can sell shares publicly (on the stock market), gaining access to a much wider pool of investors.</li>\n</ul>\n<p>Many small businesses <strong>remain small</strong> simply because they could not raise the finance needed to expand. This shows how critically the finance function — or the lack of one — can shape the future of a business.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Stellantis / Vauxhall — Ellesmere Port</h4>\n  <p>In July 2021, Stellantis (owners of Vauxhall) announced their Ellesmere Port factory would produce all-electric vans. The decision followed lengthy negotiations with the UK government, which reportedly offered a £30 million grant. The finance function at Stellantis played a central role — supporting business planning and ensuring all decision-making was informed by accurate financial data. Without this financial analysis, such a major investment decision could not have been made confidently.</p>\n  <p><strong>Takeaway:</strong> Large-scale business decisions always involve the finance function. It provides the financial evidence needed to justify investment, expansion, or change.</p>\n</div>", "check": {"question": "According to this card, why do many small businesses remain small?", "options": ["They lacked enough staff willing to work extra hours during busy periods", "They could not raise the finance needed to expand into a larger business", "They chose not to advertise their products outside their local area", "They refused to change their opening hours to suit more customers"], "answer": 1, "explain": "The card states many small businesses remain small simply because they could not raise the finance needed to expand — a direct link between finance and business growth."}}, {"title": "Financial Information: What It Includes", "html": "<p>The finance function produces specific types of financial information. You need to know what each one is and why it matters:</p>\n<ul>\n  <li><strong>Sources of Finance (Unit 5.2):</strong> Where does the money come from? Savings, loans, overdrafts, share issues. Needed when the business wants to invest or expand.</li>\n  <li><strong>Revenue, Costs & Profit/Loss (Unit 5.3):</strong> Revenue − Total Costs = Profit or Loss. Tells managers whether the business is making money.</li>\n  <li><strong>Break-Even (Unit 5.4):</strong> How many units must be sold to cover all costs? Based on selling price and costs. Vital for setting prices and production targets.</li>\n  <li><strong>Cash Flow (Unit 5.5):</strong> Tracks money in and money out. Allows the business to spot periods where it may struggle to pay bills and plan ahead.</li>\n</ul>\n<div class=\"formula-box\">\n  <strong>Profit / Loss =</strong> Total Revenue &minus; Total Costs\n</div>\n<div class=\"formula-box\">\n  <strong>Break-Even Output =</strong> Fixed Costs &divide; (Selling Price &minus; Variable Cost per Unit)\n</div>\n<p>Each of these pieces of information feeds into business decision-making — no manager should make a significant decision without consulting the finance function first.</p>", "check": {"question": "Which of these is one of the four types of financial information listed in this card?", "options": ["Market map, which shows how competitors are positioned by price", "Job description, which shows the duties expected of a new employee", "Organisation chart, which shows the levels of hierarchy in a firm", "Break-even, which shows how many units must be sold to cover all costs"], "answer": 3, "explain": "The card lists break-even alongside sources of finance, revenue/costs/profit and cash flow as the four types of financial information — the other options belong to HR and marketing."}}, {"title": "Finance & Interdependence Between Departments", "html": "<p>The finance function does not work in isolation. It is deeply connected to every other part of the business. This is called <strong>interdependence</strong>.</p>\n<ul>\n  <li><strong>Marketing:</strong> Finance sets marketing budgets and assesses whether a campaign generated enough extra revenue to justify its cost.</li>\n  <li><strong>Operations/Production:</strong> Finance provides data on production costs and calculates break-even when production methods change.</li>\n  <li><strong>Human Resources:</strong> Finance must approve wage increases, training budgets, and redundancy packages — all of which affect costs.</li>\n  <li><strong>Senior Management:</strong> Finance supplies the data that directors use to make strategic decisions about the future direction of the business.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: IKEA — Lancing Store Decision</h4>\n  <p>In July 2021, IKEA backed out of opening a new store at Lancing, West Sussex — a site it had identified back in 2016. The coronavirus pandemic had dramatically shifted consumer behaviour towards online shopping, making the financial case for the store much weaker. The finance function would have analysed projected revenues, costs, and profitability of the Lancing store before recommending the business not proceed. IKEA announced it would instead invest further in its online operations.</p>\n  <p><strong>Takeaway:</strong> The finance function doesn''t just track money — it protects the business from bad investments by providing the evidence needed to make the right call, even when that means walking away from a major project.</p>\n</div>", "check": {"question": "What does ''interdependence'' mean in the context of the finance function?", "options": ["Different departments within a business rely on each other to operate effectively", "Departments work in complete isolation without needing any shared data", "A business relies entirely on a single supplier for all of its raw material needs", "A company depends on a single bank for every one of its sources of finance"], "answer": 0, "explain": "The card defines interdependence as departments relying on each other — e.g. marketing depends on finance for a budget — which is the opposite of departments working in isolation."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Finance Function", "definition": "The department in a larger business responsible for managing money, producing financial information, and supporting decision-making across the organisation."}, {"term": "Revenue", "definition": "The total money received by a business from selling goods or services."}, {"term": "Profit", "definition": "Total Revenue minus Total Costs when the result is positive."}, {"term": "Loss", "definition": "Total Revenue minus Total Costs when the result is negative (costs exceed revenue)."}, {"term": "Break-Even", "definition": "The level of output where total revenue exactly equals total costs — no profit or loss is made."}, {"term": "Cash Flow", "definition": "The movement of money into (inflows) and out of (outflows) a business over time."}, {"term": "Cash-Flow Forecast", "definition": "A prediction of future inflows and outflows of money, used to identify periods when a business may face a cash shortage."}, {"term": "Sources of Finance", "definition": "The ways a business can raise money — examples include savings, loans, overdrafts, and share issues."}, {"term": "Interdependence", "definition": "The way different departments within a business rely on each other to function — e.g. marketing relies on finance for budgets."}, {"term": "Financial Information", "definition": "Data on profit, loss, cash flow, break-even, profit margin, and average rate of return, used in business decision-making."}, {"term": "Average Rate of Return", "definition": "A calculation that measures how profitable an investment is, expressed as an average annual profit as a percentage of investment."}, {"term": "Sole Trader → Partnership", "definition": "A sole trader may invite a partner who can provide capital, changing the business''s legal form and increasing available finance."}, {"term": "Tautological Answer", "definition": "An answer that merely repeats the question using different words — e.g. ''the finance function is about finance.'' Scores zero in exams."}, {"term": "Budget", "definition": "A financial plan that sets targets for income and expenditure over a given period, helping a business control its spending."}]}, "mcq": {"enabled": true, "questions": [{"question": "Sam is a finance assistant for a national taxi firm. Which task is most likely to be part of Sam''s job role?", "options": ["Phoning garages to negotiate vehicle servicing at reduced prices", "Posting discount codes on social media for pre-booked journeys", "Producing spreadsheets analysing quantitative market research data", "Providing cost data to help decide when to purchase new vehicles"], "answer": 3, "explain": "Correct answer: Providing cost data to help decide when to purchase new vehicles is a finance function — it involves analysing financial information to support a business decision. A is procurement/operations, B is marketing, and C is market research, not finance."}, {"question": "Which business function is responsible for supporting business planning by anticipating periods of cash shortages?", "options": ["Finance", "Logistics", "Procurement", "Sales"], "answer": 0, "explain": "Correct answer: The finance function produces cash-flow forecasts, which identify future periods when the business may have more outflows than inflows — allowing it to plan ahead and arrange additional funding if needed."}, {"question": "Which of the following tasks is NOT a finance function?", "options": ["Advertising price reductions", "Applying for a bank loan", "Calculating break-even", "Measuring profit and loss"], "answer": 0, "explain": "Correct answer: Advertising price reductions is a marketing activity, not a finance function. Applying for a bank loan (sourcing finance), calculating break-even, and measuring profit and loss are all core finance department responsibilities."}, {"question": "Which functional area is responsible for providing information about a firm''s revenue?", "options": ["Finance", "Logistics", "Marketing", "Production"], "answer": 0, "explain": "Correct answer: The finance function tracks and reports on revenue — the money received from selling goods and services. Marketing generates sales but it is finance that records and analyses the resulting revenue figures."}, {"question": "Which one of the following is an example of how the finance function can support business activity?", "options": ["Analysing primary market research results", "Predicting revenues and costs", "Reviewing the quality of the products made by the firm", "Selecting staff for a business expansion"], "answer": 1, "explain": "Correct answer: Predicting revenues and costs is a core finance function — it provides the financial forecasts other departments need to plan. A is market research, C is operations/quality control, and D is human resources."}, {"question": "Taj is a finance assistant working in a secondary school. Which one of the following tasks would be done by Taj?", "options": ["Creating educational resources", "Keeping the school website up to date", "Producing reports on the school''s GCSE results", "Providing financial data on school energy usage"], "answer": 3, "explain": "Correct answer: Providing financial data on energy usage is a finance task — it involves tracking costs for the school. A is teaching/curriculum, B is IT/marketing, and C is academic reporting, none of which are finance roles."}, {"question": "Which of the following is a role of the finance function?", "options": ["Advertise for temporary Christmas staff", "Decide on the style of a new television advert", "Monitor the costs and revenues of a business", "Make sure that the quality of goods made is of the highest standard"], "answer": 2, "explain": "Correct answer: Monitoring costs and revenues is a core finance function. Advertising for staff is HR, deciding on adverts is marketing, and quality control is an operations function."}, {"question": "Which of the following statements is FALSE?", "options": ["Business growth may be limited by problems of raising finance", "Finance is needed to pay for the start-up costs of a business", "Marketing costs are always paid out of revenue the business raises so finance is not needed", "A business may need to change its legal form to raise finances"], "answer": 2, "explain": "Correct answer: This is false — a new business or one launching a major campaign may need to source finance BEFORE it generates revenue. Marketing costs are not always self-funding, especially at start-up or during expansion."}, {"question": "A business that makes clothes decides to increase production. Which of the following is NOT likely to happen?", "options": ["Expenditures measured on the cash flow forecast will increase", "The firm may need to raise finance to expand the production facilities", "The total cost of production will increase", "The firm will spend less money on raw materials"], "answer": 3, "explain": "Correct answer: Increasing production means the firm will need MORE raw materials, not less. All other options are logical consequences of increasing production — higher expenditure, possible need for new finance, and higher total costs."}, {"question": "The finance function of a business will NOT usually be involved in decisions about:", "options": ["Whether a business should introduce environmentally friendly practices", "Whether to switch production to goods aimed at a different market", "The appointment of a new apprentice in production", "How to proceed for a successful expansion of the business"], "answer": 2, "explain": "Correct answer: Appointing an apprentice is a human resources (HR) decision, not a finance function. The finance team would be involved in environmental decisions (extra costs), switching markets (revenue impact), and expansion planning (sourcing finance)."}, {"question": "A sole trader who wants to expand their business but cannot raise enough finance on their own might change the legal structure to:", "options": ["A franchise", "A partnership", "A charity", "A cooperative"], "answer": 1, "explain": "Correct answer: By taking on a partner who can contribute capital, the sole trader gains access to more finance. The business becomes a partnership. They might later become a private limited company (Ltd) to sell shares for even more funding."}, {"question": "Which of the following best describes ''break-even''?", "options": ["The point at which a business starts to make a large profit", "The number of units a business must sell to cover all its costs", "The total amount of money coming into a business from sales", "The difference between a business''s revenue and its fixed costs"], "answer": 1, "explain": "Correct answer: Break-even is the output level at which total revenue equals total costs — meaning the business makes neither a profit nor a loss. It tells managers the minimum sales needed to avoid a financial loss."}]}, "fib": {"enabled": true, "questions": [{"text": "The finance function is usually only found in [larger] businesses, while smaller businesses typically employ an external [accountant]."}, {"text": "Break-even is calculated as fixed costs divided by the difference between [selling] price and [variable] cost per unit."}, {"text": "Profit or loss is calculated by subtracting total [costs] from total [revenue]."}, {"text": "A cash-flow forecast allows a business to anticipate periods of cash [shortage] and plan ahead to raise additional [finance]."}, {"text": "When departments within a business rely on each other to operate, this is called [interdependence]."}, {"text": "A sole trader who needs more finance to expand might invite someone to become a [partner], changing the business into a [partnership]."}, {"text": "The finance function provides [financial] information to other departments so they can make informed [decisions]."}, {"text": "A private limited company may become a [public] limited company in order to sell shares publicly and raise finance from a wider range of [investors]."}, {"text": "The finance function is critical because it provides data on revenues, costs, [cash] flow, and [break]-even to help businesses plan."}, {"text": "When a business goes environmentally friendly, the finance function must calculate the extra [costs] and may need to arrange additional [finance]."}, {"text": "Sources of finance include savings, loans, [overdrafts], and share [issues]."}, {"text": "The average [rate] of return measures how well a business investment is performing over time."}]}, "tf": {"enabled": true, "questions": [{"statement": "The finance function is only found in small businesses such as sole traders.", "answer": false, "explain": "FALSE. The finance function (finance department) is only found in LARGER businesses. Sole traders and partnerships usually employ an external accountant to manage their finances instead."}, {"statement": "Break-even is the point at which a business''s total revenue equals its total costs.", "answer": true, "explain": "TRUE. At the break-even point, the business is making neither a profit nor a loss. Every unit sold beyond break-even contributes to profit."}, {"statement": "The finance function is responsible for deciding on the style of a television advertisement.", "answer": false, "explain": "FALSE. Designing and deciding on advertising is a marketing function. The finance function may set the advertising budget and monitor whether the campaign was profitable, but it does not create the advert."}, {"statement": "A business that cannot raise finance may be unable to expand.", "answer": true, "explain": "TRUE. Many small businesses remain small precisely because they could not raise the capital needed to grow. Finance is a key enabler of business growth."}, {"statement": "Cash flow records the inflow and outflow of money in a business.", "answer": true, "explain": "TRUE. Cash flow tracks money coming in (inflows) and money going out (outflows). A cash-flow forecast helps a business spot future periods where it may not have enough cash to pay its bills."}, {"statement": "A sole trader who wants to raise more capital might convert their business into a partnership.", "answer": true, "explain": "TRUE. By bringing in a partner who provides capital, the sole trader gains access to more finance. The business legally becomes a partnership, sharing ownership and responsibility."}, {"statement": "The finance function stands alone and does not interact with other departments.", "answer": false, "explain": "FALSE. The finance function is deeply interdependent with all other departments. Marketing, operations, and HR all rely on financial data from the finance function to make decisions."}, {"statement": "Revenue is calculated by subtracting total costs from total profit.", "answer": false, "explain": "FALSE. This is the wrong formula. Profit = Revenue − Costs. Revenue is the money received from sales; you cannot calculate it by subtracting costs from profit."}, {"statement": "Providing financial data on a business''s energy usage would be a task for the finance function.", "answer": true, "explain": "TRUE. Tracking and reporting on costs — including energy costs — is part of the finance function''s role. This data helps management understand expenditure and make cost-saving decisions."}, {"statement": "Advertising price reductions to customers is a task performed by the finance function.", "answer": false, "explain": "FALSE. Advertising is a marketing function. The finance team might set the budget for an advertising campaign, but the actual advertising activity belongs to marketing."}, {"statement": "A public limited company (plc) can raise more finance than a sole trader because it can sell shares publicly on the stock market.", "answer": true, "explain": "TRUE. A plc has access to the widest range of investors because its shares are traded publicly. This is one of the main reasons businesses change their legal form as they grow."}, {"statement": "The finance function is not involved when a business decides to become more environmentally friendly.", "answer": false, "explain": "FALSE. Any change to business practice affects costs and cash flow. The finance function must calculate the extra costs of going green, assess the impact on break-even, and may need to arrange additional finance to fund the changes."}]}, "misc": {"enabled": true, "items": [{"myth": "The finance function manages the whole business — it is the most important department.", "truth": "The finance function is one of several departments. It provides financial information and supports other departments, but decisions are made across the business collaboratively. Its importance varies depending on the decision being made.", "check": {"question": "Why is it wrong to say the finance function is ''the most important department''?", "options": ["It only really matters once a business is preparing to close down completely", "It is actually the least important department of all because it only ever counts and records money", "It is only relevant once a business has already become a public limited company", "It is one of several departments that provides data to support decisions made across the business"], "answer": 3, "explain": "The correct explanation is that finance is one of several interdependent departments supporting decisions collaboratively — its importance is not fixed as ''most important'' in every case."}}, {"myth": "Revenue and profit are the same thing.", "truth": "Revenue is the total money received from sales. Profit is what is LEFT after subtracting total costs from revenue. A business can have high revenue but still make a loss if its costs are even higher.", "check": {"question": "What is the key difference between revenue and profit?", "options": ["Revenue is what remains after total costs are subtracted from total profit", "Profit is always a fixed percentage of whatever revenue a business earns", "Profit is what remains after total costs are subtracted from total revenue", "Revenue and profit both refer to the same figure shown on a cash-flow forecast"], "answer": 2, "explain": "Profit = Revenue − Costs, so profit is what is left after costs are deducted from revenue; a business can have high revenue but still make a loss if costs are higher still."}}, {"myth": "The finance function decides what to spend money on.", "truth": "The finance function provides the financial data that informs spending decisions — but it does not make those decisions alone. For example, marketing decides to run a campaign; finance tells them how much they can afford and monitors the results.", "check": {"question": "What role does the finance function actually play in spending decisions?", "options": ["It only gets involved after money has already been spent by a department", "It makes every spending decision alone without input from other departments", "It has no involvement at all in decisions about how money is spent", "It provides financial data that informs decisions but does not make them alone"], "answer": 3, "explain": "The correct view is that finance supplies the data — e.g. telling marketing what it can afford — while other departments still make the actual spending decision."}}, {"myth": "Break-even means the business is making a profit.", "truth": "Break-even means the business is making exactly zero profit — it has covered all its costs but has nothing left over. Profit only begins after the break-even point is exceeded.", "check": {"question": "What does reaching the break-even point actually mean for a business?", "options": ["The business has covered all its costs but made exactly zero profit", "The business has made a loss equal to its total fixed costs", "The business has started to generate a small but growing profit", "The business has generated enough revenue to repay all its loans"], "answer": 0, "explain": "Break-even means total revenue equals total costs, so the business makes exactly zero profit — profit only begins once output rises beyond the break-even point."}}, {"myth": "Only large businesses need to worry about finance.", "truth": "All businesses — no matter their size — must manage their finances well to survive. Small businesses may not have a finance department, but the owner must still track costs, revenue, and cash flow carefully.", "check": {"question": "Which statement correctly describes who needs to manage finances carefully?", "options": ["Only businesses that have already taken out a large bank loan need to worry", "All businesses, regardless of size, must manage their finances well to survive", "Only large businesses with a dedicated finance department need to worry at all", "Only businesses that sell shares publicly on the stock market need to worry"], "answer": 1, "explain": "The card corrects the misconception that only large firms need to worry about finance — every business, including sole traders without a finance department, must track money carefully."}}, {"myth": "''Finance'' and ''finance function'' mean the same thing in exam questions.", "truth": "In exam questions, ''finance'' often refers to money or sources of funding, while ''finance function'' refers to the specific department in a business. Read the question carefully to understand which one is being asked about.", "check": {"question": "In exam questions, how do ''finance'' and ''finance function'' typically differ?", "options": ["''Finance'' refers to profit only, while ''finance function'' refers to revenue only", "''Finance'' always means a bank loan, while ''finance function'' means a share issue", "''Finance'' and ''finance function'' are simply two names for the exact same department", "''Finance'' usually means money or funding, while ''finance function'' means the department"], "answer": 3, "explain": "The card explains that ''finance'' often refers to money/funding, while ''finance function'' refers specifically to the department — so exam questions must be read carefully to see which is meant."}}, {"myth": "Saying ''the finance function manages the business efficiently'' is enough to score the understanding mark in an analyse question.", "truth": "This is a tautological answer — it just repeats the idea without explaining what the finance function actually does. You must explain a specific task (e.g. producing cash-flow forecasts, calculating break-even) to earn the understanding mark.", "check": {"question": "Why does saying the finance function ''manages the business efficiently'' fail to earn the understanding mark?", "options": ["It is factually incorrect because the finance function does not manage efficiency", "It is too technical for an examiner to accept as a valid business term", "It only applies to public limited companies, not to smaller private firms", "It is tautological and does not name a specific finance task the department performs"], "answer": 3, "explain": "The card explains this answer just repeats the idea without naming a specific task, such as producing cash-flow forecasts — a tautological answer scores no understanding mark."}}, {"myth": "Cash flow and profit are the same — if a business is profitable, it won''t have cash flow problems.", "truth": "A profitable business can still run out of cash if it doesn''t receive payment from customers quickly enough. Cash flow is about timing of money in and out; profit is a longer-term calculation. A business can be profitable but cash-poor.", "check": {"question": "Why can a profitable business still run into cash-flow problems?", "options": ["A profitable business automatically receives all customer payments instantly", "Cash flow depends on payment timing, while profit is a longer-term calculation", "Cash-flow problems can only happen to a business that is making a loss", "Profit and cash flow are identical figures calculated the same way"], "answer": 1, "explain": "The card explains that cash flow is about the timing of money in and out, whereas profit is a longer-term measure — so a business can be profitable yet still cash-poor."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct, specific point. No explanation. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific finance function task = 1 mark ✅</li>\n        <li>A vague or general statement = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"The finance function manages money.\"</em><br/>\n      This is too vague and tautological — it just says finance is about finance.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"The finance function produces cash-flow forecasts.\"</em><br/>\n      This is specific and names a real task the finance function performs.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> Do NOT say \"the finance function is important for the business\" — this tells the examiner nothing. State a specific role: budgeting, calculating break-even, measuring profit and loss, sourcing finance, forecasting cash flow.</p>\n    ", "check": {"question": "What is the key rule for answering a 1-mark ''Identify'' or ''State'' question?", "options": ["Give one vague general statement summarising the whole topic", "Give a short paragraph explaining the point in full detail", "Give two or three related points to maximise your chances", "Give one clear, specific point with no explanation needed"], "answer": 3, "explain": "The card explains a 1-mark question needs exactly one clear, specific point — a vague or general statement, or unnecessary explanation, will not gain the mark."}}, {"title": "The Holy Trinity: Understand → Apply → Analyse", "html": "\n      <p>A 3-mark analyse question requires three distinct steps. Miss any one of them and you cap your marks at 2. Miss understanding and you score <strong>zero</strong> — even if your other points are excellent.</p>\n\n      <p><strong>Step 1 — Understanding (U): What does the finance function actually do?</strong><br/>\n      Name and briefly explain a specific finance task. Do NOT just repeat words from the question.</p>\n      <p><em>Starter: \"The finance function [produces/calculates/forecasts]...\"</em></p>\n\n      <p><strong>Step 2 — Application (APP): Link it to the specific business in the case study.</strong><br/>\n      Quote or directly reference information from the text — name the business, use a figure, reference a specific detail.</p>\n      <p><em>Starter: \"In the case of [Business Name], which [detail from text]...\"</em></p>\n\n      <p><strong>Step 3 — Analysis (AN): What is the impact on the business?</strong><br/>\n      Explain the effect on costs, revenue, profit, cash flow, or the ability to meet objectives.</p>\n      <p><em>Starter: \"This means that [Business Name] will be able to... / As a result, the business can...\"</em></p>\n\n      <p><strong>✅ Model Answer (BP question):</strong><br/>\n      \"The finance function produces budgets (U) in order to provide accurate financial information for BP''s managers to make informed decisions about possible partnerships (U), when developing wind farms (APP). This means BP can allocate the correct level of funding to renewable energy investments without putting the wider business at financial risk (AN).\"</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Many students write everything they know about the finance function without linking it to BP. The examiner''s report noted that the majority of candidates scored zero on Q2 because they did not explain what the finance function involves — they just said it \"manages the business efficiently.\"</p>\n    ", "check": {"question": "What are the three steps required in a 3-mark ''Analyse'' answer?", "options": ["Identification, Description, then a relevant real-world worked example", "Definition, Evaluation, then a final and fully justified overall judgement", "Introduction, Summary, then a concluding recommendation paragraph", "Understanding, Application, then Analysis of the impact on the business"], "answer": 3, "explain": "The card sets out the ''Holy Trinity'' for analyse questions: Understanding (what the finance function does), Application (link to the case study), and Analysis (the impact)."}}, {"title": "Argue Both Sides, Then Commit to a Justified Judgement", "html": "\n      <p>A 7-mark evaluate question rewards four things: Knowledge, Application, Analysis (two separate points), and Evaluation (a justified judgement). Structure your answer in four paragraphs:</p>\n\n      <p><strong>Paragraph 1 — Knowledge & Understanding (K + U):</strong><br/>\n      Define or explain the finance function and its role in general terms.<br/>\n      <em>Starter: \"The finance function is the department responsible for... It plays a key role in...\"</em></p>\n\n      <p><strong>Paragraph 2 — Analysis & Application Point 1 (AN + APP):</strong><br/>\n      Give a specific example of how the finance function supports the business in the case study. Explain the impact.<br/>\n      <em>Starter: \"For example, in the case of [Business Name], the finance function... This will result in...\"</em></p>\n\n      <p><strong>Paragraph 3 — Analysis & Application Point 2 (AN + APP):</strong><br/>\n      Give a second, different example. Use case study detail again.<br/>\n      <em>Starter: \"Furthermore, the finance function could also... Because the text states that [quote/detail]...\"</em></p>\n\n      <p><strong>Paragraph 4 — Evaluation (EVAL — 3 marks):</strong><br/>\n      Make a clear judgement (1 mark). Then justify it using case study context (up to 2 marks). Your conclusion must add something NEW — do not just repeat your analysis points.</p>\n      <ul>\n        <li><strong>Decision:</strong> \"Overall, I believe the finance function is vital to the future success of [Business]...\"</li>\n        <li><strong>Context:</strong> \"...because the business is facing [specific challenge from text]...\"</li>\n        <li><strong>Impact/Reasoning:</strong> \"...meaning that without accurate financial data, the business could [specific consequence], putting its long-term survival at risk.\"</li>\n      </ul>\n      <p><strong>⚠️ The \"It Depends\" Trap:</strong> Only use \"it depends\" if you then specify what it depends on and why. A conclusion that simply repeats your analysis scores zero evaluation marks.</p>\n    ", "check": {"question": "What must a strong evaluation paragraph do, beyond repeating the analysis points?", "options": ["List every possible advantage and disadvantage without choosing between them", "Make a clear judgement and justify it with new reasoning from the case study", "Introduce a brand new topic that has not been discussed anywhere before", "Restate the two earlier analysis points using slightly different wording"], "answer": 1, "explain": "The card warns that a conclusion which just repeats the analysis scores zero evaluation marks — the judgement must be justified with new reasoning tied to the case study."}}, {"title": "You MUST Define the Finance Function Before Anything Else", "html": "\n      <p>In analyse questions about the finance function, <strong>the understanding mark is the gateway mark</strong>. Without it, no further marks can be awarded — regardless of how well you apply or analyse.</p>\n      <p>The examiner''s report for Q2 (BP question) stated: <em>\"The majority of candidates gained no marks, as they did not identify what the finance function of a business involved.\"</em></p>\n      <p><strong>What counts as understanding?</strong> You must name a specific task the finance function carries out:</p>\n      <ul>\n        <li>✅ \"produces cash-flow forecasts\"</li>\n        <li>✅ \"calculates break-even output\"</li>\n        <li>✅ \"measures revenue and costs\"</li>\n        <li>✅ \"creates budgets to plan spending\"</li>\n        <li>✅ \"arranges sources of finance such as loans\"</li>\n        <li>❌ \"manages the business efficiently\" — too vague, tautological</li>\n        <li>❌ \"looks after the finances\" — just repeats the question</li>\n        <li>❌ \"decides what to spend money on\" — this is not a finance function</li>\n      </ul>\n      <p><strong>Rule of thumb:</strong> Could a student who had never studied business write your answer? If yes, it''s not showing understanding — it''s just common sense and will score zero.</p>\n    ", "check": {"question": "Why is the understanding mark described as the ''gateway mark'' in analyse questions?", "options": ["It is the only one of the marks that can be earned without reading the case study", "It is worth far more marks than the application and analysis points combined", "Without naming a specific finance task, no further marks can be awarded at all", "It is automatically awarded to every single student who attempts the question"], "answer": 2, "explain": "The examiner''s report cited in the card shows most candidates scored zero because they never identified a specific finance task — without that gateway mark, no further marks can follow."}}]}, "exam": {"enabled": true, "questions": [{"question": "Which task is most likely to be part of Sam''s job role? [1 mark]", "marks": 1, "hint": "Think about what a finance assistant specifically does — they deal with financial data, not advertising, procurement negotiation, or market research.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Providing cost data to help decide when to purchase new vehicles</h5><p><strong>Why D is correct:</strong> Providing cost data to inform a purchasing decision is a core finance function — it involves producing and analysing financial information to support business decision-making.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Phoning garages to negotiate vehicle servicing:</strong> This is a procurement or operations task, not a finance function. Finance does not negotiate external service contracts.</li><li><strong>B — Posting discount codes on social media:</strong> This is a marketing or sales activity. The finance team does not manage social media or promotional campaigns.</li><li><strong>C — Producing spreadsheets analysing market research data:</strong> Analysing market research is a marketing function. Finance may use spreadsheets, but for financial data (costs, revenues, forecasts) — not market research.</li></ul></div>"}, {"question": "Analyse how BP''s finance function may influence its ability to meet BP''s objectives. [3 marks]", "marks": 3, "hint": "Start by naming a specific task the finance function carries out (NOT just ''managing the business''). Then link it to a specific detail from the BP case study. Finally, explain the impact on BP''s objectives.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1 + AO2: 1 + AO3a: 1)</h5>\n<p><strong>Understanding (1 mark) — must be awarded first; without it, no further marks:</strong></p>\n<ul>\n  <li>Informs the business how much money is available for investment/expansion</li>\n  <li>Budgeting</li>\n  <li>Financial forecasts / Cash-flow forecasts</li>\n  <li>Calculates revenue, costs, profit</li>\n  <li>Informing spending or investment decisions</li>\n</ul>\n<p>⚠️ An answer must say more than \"the finance function is about finance\" — this is tautological and scores zero.</p>\n<p><strong>Application (1 mark) — must link understanding to BP using text evidence:</strong></p>\n<ul>\n  <li>Sells and distributes products globally</li>\n  <li>Revenue increased from $245bn to $283bn</li>\n  <li>18,700 petrol stations (8,500 in UK)</li>\n  <li>Aims to reduce carbon emissions by 2050</li>\n  <li>Installing electric charging points / investing in wind farms</li>\n</ul>\n<p><strong>Analysis (1 mark) — explain the impact on BP''s objectives:</strong></p>\n<ul>\n  <li>Monitors revenue/profits to inform managers how much to invest in environmentally friendly partnerships</li>\n  <li>Investigates financial stability of potential takeovers/partnerships</li>\n  <li>Provides financial information on costs of diversification/investments</li>\n</ul>\n<p><strong>Exemplar Response:</strong> \"The finance function produces budgets (U) in order to provide accurate financial information for BP''s managers to make informed decisions about possible partnerships (U), when developing wind farms (APP). This allows BP to allocate the correct level of funding to renewable energy without putting the wider business at financial risk (AN).\"</p>\n<p><strong>Examiner''s Comment:</strong> This was the first 3-mark analyse question requiring understanding before further marks can be accessed. The majority of candidates gained no marks as they did not identify what the finance function involves. Many responses referred generally to ''managing the business efficiently'' or credited finance with activities it does not undertake, such as ways of increasing revenue or deciding what to spend money on.</p></div>"}, {"question": "Which business function is responsible for supporting business planning by anticipating periods of cash shortages? [1 mark]", "marks": 1, "hint": "Which department produces cash-flow forecasts — the financial plans that predict when money might run low?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Finance</h5><p><strong>Why A is correct:</strong> The finance function produces cash-flow forecasts that predict future inflows and outflows of money. This allows the business to identify in advance any periods where it may face a cash shortage, and arrange additional finance if needed.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — Logistics:</strong> Logistics manages the movement and delivery of goods. It does not produce financial forecasts or manage cash.</li><li><strong>C — Procurement:</strong> Procurement is responsible for sourcing and buying supplies. It interacts with finance in terms of budgets but does not itself anticipate cash shortages.</li><li><strong>D — Sales:</strong> Sales generates revenue by selling goods/services but does not manage or forecast the cash position of the business as a whole.</li></ul></div>"}, {"question": "Which of the following tasks is NOT a finance function? [1 mark]", "marks": 1, "hint": "Think about which task involves communicating with customers rather than managing money and financial data.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Advertising price reductions</h5><p><strong>Why A is correct:</strong> Advertising is a marketing function. The finance department may set the advertising budget, but the actual creation and placement of adverts belongs to the marketing team.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — Applying for a bank loan:</strong> This is a finance function — sourcing external finance is one of the key roles of the finance department.</li><li><strong>C — Calculating break-even:</strong> Break-even analysis is a core finance function, telling the business how many units must be sold to cover all costs.</li><li><strong>D — Measuring profit and loss:</strong> Calculating and reporting profit and loss is a fundamental finance function, providing critical information for decision-making.</li></ul></div>"}, {"question": "Which functional area is responsible for providing information about a firm''s revenue? [1 mark]", "marks": 1, "hint": "Revenue is financial data — which department tracks, calculates and reports on financial data?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Finance</h5><p><strong>Why A is correct:</strong> The finance function records and provides information about revenue — the money received from selling goods and services. Even though marketing activities generate sales, it is the finance function that measures and reports on the resulting revenue figures.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — Logistics:</strong> Logistics manages the movement and delivery of goods, not financial data.</li><li><strong>C — Marketing:</strong> Marketing creates campaigns that drive sales, but it does not formally track and report revenue — that is a finance responsibility.</li><li><strong>D — Production:</strong> Production focuses on making goods efficiently. It deals with output and costs, not revenue data.</li></ul></div>"}, {"question": "Which one of the following is an example of how the finance function can support business activity? [1 mark]", "marks": 1, "hint": "The finance function deals with financial data — revenues, costs, profits, forecasts. Which option involves financial data?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Predicting revenues and costs</h5><p><strong>Why B is correct:</strong> Predicting (forecasting) revenues and costs is a core finance function. These forecasts support business planning by helping managers understand the financial implications of their decisions.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Analysing primary market research results:</strong> Market research analysis is a marketing function. Finance does not collect or analyse customer feedback or survey data.</li><li><strong>C — Reviewing product quality:</strong> Quality control is an operations function. Finance does not inspect physical products.</li><li><strong>D — Selecting staff for a business expansion:</strong> Recruitment and selection is a human resources (HR) function, not a finance function.</li></ul></div>"}, {"question": "Which one of the following tasks would be done by Taj? [1 mark]", "marks": 1, "hint": "Taj works in finance — his role involves financial data. Which option involves financial/cost data rather than education, IT, or academic reporting?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Providing financial data on school energy usage</h5><p><strong>Why D is correct:</strong> Tracking and reporting on costs — including energy costs — is a finance function. Providing this data helps management understand expenditure and make cost-saving decisions. This applies in any organisation, including a school.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Creating educational resources:</strong> This is a teaching/curriculum responsibility, not a finance role.</li><li><strong>B — Keeping the school website up to date:</strong> This is an IT or marketing/communications role, not a finance role.</li><li><strong>C — Producing reports on GCSE results:</strong> Academic performance reporting is the responsibility of senior leadership or data managers, not the finance department.</li></ul></div>"}, {"question": "State two ways in which the finance function is involved in the running of a business. [2 marks]", "marks": 2, "hint": "This is a knowledge question — no explanation needed. Simply name two specific tasks the finance function carries out.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a: Knowledge)</h5><p>Award 1 mark for each correct, specific statement. No explanation required.</p><p><strong>Acceptable answers include:</strong></p><ul><li>Planning for the future (e.g. producing forecasts)</li><li>Supporting business decision-making</li><li>Calculating profit or loss</li><li>Producing cash-flow forecasts</li><li>Calculating break-even output</li><li>Sourcing/arranging finance</li><li>Monitoring costs and revenues</li><li>Setting budgets</li></ul><p>⚠️ Do NOT accept answers that describe the work of another department (e.g. \"advertise the business\", \"recruit new staff\", \"improve product quality\").</p></div>"}, {"question": "Evaluate the importance of the finance function to the future success of IKEA. [7 marks]", "marks": 7, "hint": "Plan four paragraphs: (1) define/explain the finance function, (2) first specific example applying to IKEA, (3) second specific example applying to IKEA, (4) a justified judgement using IKEA context. Use figures and details from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5>\n<p><strong>Application — AO2 (2 marks):</strong> Two examples relating to the IKEA case study</p>\n<ul>\n  <li>The decision not to open the Lancing store will have been largely made by the finance function, in consultation with other departments.</li>\n  <li>Investing in the online section of the business will be a decision supported by the finance function, along with others.</li>\n</ul>\n<p><strong>Analysis — AO3a (2 marks):</strong> Two separate points explaining the effect/impact on IKEA</p>\n<ul>\n  <li>The finance function at IKEA will enable well-informed decisions that save money in the future, such as not proceeding with the Lancing store. This will help profitability, which could be used to increase investment or dividend payments.</li>\n  <li>Investing in technology to develop the online side of IKEA can help the business become more efficient. Such decisions call on the finance function, which may have to arrange the necessary finance to buy equipment.</li>\n</ul>\n<p><strong>Evaluation — AO3b (3 marks):</strong></p>\n<ul>\n  <li><strong>Judgement (1 mark):</strong> e.g. \"The finance function is very important to the future success of IKEA.\"</li>\n  <li><strong>Justification (up to 2 marks):</strong> IKEA is facing difficult decisions about how many stores it needs and how much it should rely on online selling. Buying the Lancing site and then deciding not to build was a major decision that required detailed financial analysis. The future success of the business is built on these important decisions being well-informed — and this is the role of the finance function.</li>\n</ul></div>"}, {"question": "Evaluate the importance of the finance department in helping Cheeseman Publishers to be successful. [9 marks]", "marks": 9, "hint": "Plan four paragraphs: define the finance function, then give TWO specific ways it supports Cheeseman Publishers (with analysis each time), and finish with a strong justified judgement. Use specific details from the case study — falling profits, printing in Italy, cost reduction, pricing decisions.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks</h5>\n<p><strong>Knowledge (1 mark):</strong> Define the role of the finance department (e.g. it produces financial information to help the business plan and make decisions).</p>\n<p><strong>Understanding (1 mark):</strong> Explain how finance is needed for success (e.g. without financial data, managers cannot make informed decisions about costs, pricing, or investment).</p>\n<p><strong>Application (2 marks):</strong> Two ways the finance function supports Cheeseman Publishers specifically:</p>\n<ul>\n  <li>Analysing the cost of printing in Italy vs. alternative options to find savings</li>\n  <li>Calculating the impact on revenue and profit of raising book prices</li>\n  <li>Assessing the financial viability of producing new guide books for different areas</li>\n  <li>Producing updated profit forecasts to show the extent of the likely fall</li>\n</ul>\n<p><strong>Analysis (2 marks):</strong> Benefits of the two ways they can support — explain the impact on Cheeseman Publishers:</p>\n<ul>\n  <li>Identifying cost savings (e.g. alternative printers) would reduce total costs, helping to prevent the predicted fall in profit and improving financial sustainability.</li>\n  <li>Modelling the effect of a price increase allows managers to see whether higher prices would offset falling demand, protecting profit margins.</li>\n</ul>\n<p><strong>Evaluation (3 marks):</strong></p>\n<ul>\n  <li><strong>Decision (1 mark):</strong> e.g. \"The finance department is extremely important to the success of Cheeseman Publishers.\"</li>\n  <li><strong>Context (1 mark):</strong> Reference the falling profits and the multiple decisions the business faces simultaneously — cutting costs, changing prices, expanding the product range.</li>\n  <li><strong>Impact/Reasoning (1 mark):</strong> Without detailed financial analysis from the finance department, the business could make the wrong call — for example, raising prices in a competitive market could reduce sales further, worsening the profit decline rather than reversing it. The finance department''s data is the only reliable basis for making these decisions.</li>\n</ul></div>"}]}}'::jsonb),
('business', '5-2-sources-of-finance', '5.2 Sources of Finance', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>Finance is the money a business uses to fund its activities. Understanding the different sources and uses of finance is essential for any business, whether new or established.</p>\n<ul>\n  <li><strong>Finance:</strong> Money used by a business to fund its operations, start-up costs, expansion or day-to-day expenses.</li>\n  <li><strong>Internal finance:</strong> Money raised from within the business itself, such as retained profit, owner''s capital, or sale of assets.</li>\n  <li><strong>External finance:</strong> Money raised from outside the business, such as loans, share issues, overdrafts, trade credit or crowdfunding.</li>\n  <li><strong>Owner''s capital:</strong> Money from savings put into the business by the owner(s).</li>\n  <li><strong>Retained profit:</strong> Profit that is not distributed to shareholders or owners but is reinvested back into the business.</li>\n  <li><strong>Sale of assets:</strong> Raising finance by selling fixed assets such as machinery or property that the business owns.</li>\n  <li><strong>Overdraft:</strong> An arrangement with a bank that allows a business to spend more money than it has in its account, up to an agreed limit.</li>\n  <li><strong>Trade credit:</strong> An arrangement where a business obtains goods from a supplier without immediate payment — typically 30–90 days interest-free.</li>\n  <li><strong>Loan:</strong> A sum of money borrowed from a bank or lender for a stated purpose and fixed period, repaid with interest.</li>\n  <li><strong>Share issue:</strong> Raising finance by selling new shares in the business; buyers become part-owners (shareholders).</li>\n  <li><strong>Crowdfunding:</strong> Raising money from a large number of contributors — usually via a website such as Kickstarter or Seedrs — through donations, loans or equity.</li>\n  <li><strong>Taking on a new partner:</strong> Inviting someone to join a partnership who contributes capital to the business in exchange for a share of ownership and profits.</li>\n  <li><strong>Interest:</strong> The cost of borrowing money — a percentage charged on the amount owed.</li>\n  <li><strong>Security:</strong> An asset offered to a lender as a guarantee of repayment (e.g. a house or business premises).</li>\n  <li><strong>Dividend:</strong> A share of the company''s profit paid out to shareholders.</li>\n</ul>", "check": {"question": "According to the key definitions, what is ''external finance''?", "options": ["Money the business receives from selling goods or services to customers", "Money the business pays out to shareholders as a reward for their investment", "Money raised from outside the business, such as loans, share issues or overdrafts", "Money raised from within the business, such as retained profit or owner''s capital"], "answer": 2, "explain": "The card defines external finance as money raised from outside the business — such as loans, share issues, overdrafts, trade credit or crowdfunding — unlike internal finance."}}, {"title": "Why Businesses Need Finance", "html": "<p>All businesses will need finance at some stage. The reasons vary depending on whether the business is new or already established, and how much money is needed and for how long.</p>\n<ul>\n  <li><strong>Starting up a new business:</strong> Spending money on capital equipment, recruiting workers, and marketing activities before any revenue is earned.</li>\n  <li><strong>Funding expansion (internal growth):</strong> Buying new machinery, opening new premises, or hiring more staff as the business grows.</li>\n  <li><strong>External growth (takeover/acquisition):</strong> Purchasing another business or merging with a competitor requires a large, often one-off injection of capital.</li>\n  <li><strong>Replacing old machinery, equipment or premises:</strong> Assets wear out or become obsolete and must be updated to maintain productivity.</li>\n  <li><strong>Day-to-day expenses:</strong> Paying wages, buying stock or raw materials, and covering bills — especially when there is a temporary cash-flow problem.</li>\n  <li><strong>Research and development:</strong> Investing in new products or processes to stay competitive.</li>\n  <li><strong>Marketing activities:</strong> Funding campaigns to maintain or increase sales and market share.</li>\n  <li><strong>Recruitment costs:</strong> Advertising, interviewing and training new employees.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Makerfield Services Ltd — Short-Term Financing</h4>\n  <p>Makerfield Services Ltd is a small electrical contractor. It needs money day-to-day for wiring, sockets and wages. Cash flow in is not always enough to cover these costs, so it arranges an overdraft facility with its bank — it can overspend by an agreed amount, paying interest only on what it borrows. When revenue arrives, the overdraft is reduced. This illustrates how short-term finance solves a temporary cash-flow problem without committing to a long-term loan.</p>\n</div>", "check": {"question": "Which of these is given as a reason a business needs finance in this card?", "options": ["Replacing old machinery, equipment or premises that have become obsolete", "Recording customer complaints made about a recent product launch event", "Choosing which supplier offers the best quality raw materials", "Deciding which television channel to advertise a new product on"], "answer": 0, "explain": "The card lists replacing worn-out or obsolete assets as a reason a business needs finance; the other options are marketing, procurement and customer service tasks, not reasons for raising finance."}}, {"title": "Internal Sources of Finance", "html": "<p><strong>Internal finance</strong> is raised from within the business. It is generally cheaper because there is no interest to pay, but it is not always available — especially to new businesses.</p>\n<ul>\n  <li><strong>Owner''s capital:</strong> The owner uses their own savings. Available to new and established businesses. No repayment or interest required, but limited by how much the owner has saved.</li>\n  <li><strong>Retained profit:</strong> Profit kept in the business rather than paid out to owners. Only available to established businesses that have already made a profit. No interest or repayment needed.</li>\n  <li><strong>Sale of assets:</strong> Selling machinery, vehicles or property the business no longer needs. Available to established businesses. Generates a one-off lump sum but may take time to find a buyer.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Peter Hobson, Gardener — Owner''s Capital</h4>\n  <p>Peter Hobson saved £12,000 from his wages to buy a van and gardening tools to start his own business. He chose to use savings rather than a bank loan because the amount was small and he did not want to risk his family home as security. Later, he used further savings (retained profits) to buy new tools and expand his range of services. This shows how internal finance can fund both start-up and growth without interest costs.</p>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of Internal Finance</div>\n    <div class=\"pro-item\"><strong>No interest:</strong> The business does not have to pay a lender, keeping costs lower and protecting profit margins.</div>\n    <div class=\"pro-item\"><strong>No repayment obligation:</strong> Owner''s capital and retained profit do not need to be paid back, reducing financial pressure.</div>\n    <div class=\"pro-item\"><strong>No loss of control:</strong> No outside parties are brought in, so the original owners keep full decision-making power.</div>\n    <div class=\"pro-item\"><strong>No cost to raise:</strong> Unlike a share issue or crowdfunding campaign, internal sources require no fees or promotion.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of Internal Finance</div>\n    <div class=\"con-item\"><strong>Limited availability:</strong> If the owner has little savings or the business has low profits, internal sources may not raise enough money.</div>\n    <div class=\"con-item\"><strong>Only established businesses have retained profit:</strong> New businesses cannot use this source as they have not yet made any profit.</div>\n    <div class=\"con-item\"><strong>Opportunity cost:</strong> Using savings or retained profit means that money cannot be used elsewhere (e.g. invested in a savings account).</div>\n    <div class=\"con-item\"><strong>Sale of assets takes time:</strong> It may be difficult or slow to find a buyer for machinery or property.</div>\n  </div>\n</div>", "check": {"question": "Which of these is correctly identified as an internal source of finance?", "options": ["A share issue, which is only available to limited companies", "Trade credit, which is only available once a supplier agrees the terms", "A bank loan, which is only available to businesses that can offer sufficient security", "Retained profit, which is only available to businesses that have already made a profit"], "answer": 3, "explain": "The card lists retained profit alongside owner''s capital and sale of assets as internal sources; bank loans, trade credit and share issues are all external sources."}}, {"title": "External Sources of Finance", "html": "<p><strong>External finance</strong> is raised from outside the business. It gives access to larger sums of money but usually involves a cost (interest or loss of ownership).</p>\n<ul>\n  <li><strong>Overdraft:</strong> Short-term arrangement with a bank to spend more than the account balance. Interest is charged on the daily amount overdrawn. Suitable for new and established businesses needing to cover day-to-day cash flow gaps.</li>\n  <li><strong>Trade credit:</strong> The supplier allows the business to pay for goods 30–90 days after receiving them. Typically interest-free within the credit period. Useful for buying stock without immediate cash outlay.</li>\n  <li><strong>Loan:</strong> A fixed sum borrowed from a bank or other lender for a stated period. Repaid in instalments with interest. May require security. Suitable for medium- to long-term investment such as machinery or premises.</li>\n  <li><strong>Share issue:</strong> Selling new shares to investors who become part-owners. Available to limited companies only. Raises large sums without repayment or interest, but shareholders gain a say in the business.</li>\n  <li><strong>Crowdfunding:</strong> Raising money from many contributors via a website (e.g. Kickstarter). Contributors may donate, lend, or buy equity. Suitable for start-ups and expansion. No security needed for loans, but success is not guaranteed.</li>\n  <li><strong>Taking on a new partner:</strong> A new partner contributes capital and joins the partnership. Long-term source available to partnerships only. May bring new skills but reduces control for existing partners.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Chineasy — Crowdfunding a Start-Up</h4>\n  <p>ShaoLan Hsueh needed finance to develop a course to help Western people learn Chinese characters, including books, flash cards and a website. She used Kickstarter to raise nearly £200,000 within a month — well above her £75,000 target — by promoting her idea on social media. Contributors became shareholders in Chineasy Limited. This case shows how crowdfunding can reach a large number of investors quickly, removing the need for a bank loan or traditional investor.</p>\n</div>", "check": {"question": "Which of these external sources is limited-company-only, according to this card?", "options": ["Crowdfunding, which allows the business to raise money from a website", "Overdraft, which allows the business to spend more than its account balance", "Trade credit, which allows the business to delay paying its suppliers", "Share issue, which allows the business to sell new shares to investors"], "answer": 3, "explain": "The card states a share issue is available to limited companies only, since it involves selling shares — overdrafts, trade credit and crowdfunding are open to a wider range of business types."}}, {"title": "Advantages & Disadvantages of Each External Source", "html": "<p>The table below summarises the pros and cons of each external source of finance. This is the most commonly tested area in the exam — you must be able to apply these to a specific business context.</p>\n\n<p><strong>Overdraft</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Flexible — interest is only charged on the amount overdrawn each day.</div>\n    <div class=\"pro-item\">Quick to arrange if the business already has a bank account.</div>\n    <div class=\"pro-item\">Helps the business continue trading through short-term cash shortages.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Interest rates on overdrafts are high — can be expensive if used for a long time.</div>\n    <div class=\"con-item\">The bank can demand repayment at short notice.</div>\n    <div class=\"con-item\">Not suitable for long-term investment needs.</div>\n  </div>\n</div>\n\n<p><strong>Trade Credit</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Typically interest-free within the agreed credit period.</div>\n    <div class=\"pro-item\">Allows the business to sell goods before paying the supplier, improving cash flow.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Goods must be paid for even if they do not sell.</div>\n    <div class=\"con-item\">Interest is charged if payment is not made within the time limit.</div>\n  </div>\n</div>\n\n<p><strong>Bank Loan</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Repayment is spread over time in fixed instalments, aiding budgeting.</div>\n    <div class=\"pro-item\">Can be arranged for a specific amount and purpose.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Interest must be paid throughout the term, increasing the total cost.</div>\n    <div class=\"con-item\">The bank may require security — the business risks losing an asset if it defaults.</div>\n  </div>\n</div>\n\n<p><strong>Share Issue</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Large sums can be raised from many investors.</div>\n    <div class=\"pro-item\">No interest and no repayment required.</div>\n    <div class=\"pro-item\">Shareholders may bring expertise and contacts to the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Shareholders gain a say in how the business is run, reducing owners'' control.</div>\n    <div class=\"con-item\">Dividends may need to be paid to shareholders from profits.</div>\n    <div class=\"con-item\">Risk of takeover if too many shares are sold (more of a risk for public limited companies).</div>\n  </div>\n</div>\n\n<p><strong>Crowdfunding</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Can raise large amounts from many contributors with no security needed.</div>\n    <div class=\"pro-item\">Generates publicity and a community of supporters around the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Not guaranteed — the business may not reach its funding target.</div>\n    <div class=\"con-item\">Requires time and effort to promote the campaign; publicity stunts can be costly.</div>\n    <div class=\"con-item\">If equity is sold, profits must be shared with contributors.</div>\n  </div>\n</div>\n\n<p><strong>Taking on a New Partner</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Provides a long-term injection of capital at no direct financial cost (no interest).</div>\n    <div class=\"pro-item\">The new partner may bring valuable skills and experience to the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">The new partner shares ownership, profits and decision-making power.</div>\n    <div class=\"con-item\">The partner may not have the required skills or enough capital to meet the business''s needs.</div>\n    <div class=\"con-item\">Decision-making can become slower and lead to disagreements.</div>\n  </div>\n</div>", "check": {"question": "According to this card, what is a key disadvantage of using a share issue?", "options": ["Interest rates on a share issue are extremely high compared with a bank loan", "The bank can demand repayment of a share issue at very short notice", "Shareholders gain a say in how the business is run, reducing owners'' control", "Goods bought through a share issue must be paid for even if unsold"], "answer": 2, "explain": "The card lists reduced owner control as a disadvantage of a share issue, since shareholders gain a say in the business — share issues do not carry interest or bank repayment demands."}}, {"title": "Short-, Medium- and Long-Term Finance", "html": "<p>Businesses need finance for different lengths of time. Matching the time period of the finance to the purpose is important — using a short-term source for a long-term investment would be costly and risky.</p>\n<ul>\n  <li><strong>Short-term finance (up to 12 months):</strong> Used for day-to-day running costs such as wages, stock and bills. Examples: overdraft, trade credit.</li>\n  <li><strong>Medium-term finance (1–5 years):</strong> Used for machinery, vehicles, or extending premises. Examples: bank loan, owners'' capital, retained profit, sale of assets.</li>\n  <li><strong>Long-term finance (5 years or more):</strong> Used for major investments such as new buildings, takeovers, or large-scale expansion. Examples: share issue, crowdfunding, taking on a new partner, bank loan.</li>\n</ul>\n<p>Some sources of finance span more than one time period — for example, a bank loan can be medium or long term depending on the repayment schedule.</p>\n<p>Not all sources of finance are available to every business. Key constraints include:</p>\n<ul>\n  <li>Sole traders and partnerships <strong>cannot issue shares</strong> — this is only available to limited companies.</li>\n  <li>Limited companies <strong>cannot take on extra partners</strong>.</li>\n  <li>Businesses with a poor financial record may struggle to get a bank loan.</li>\n  <li>Retained profit is <strong>only available to established businesses</strong> that have already generated profit.</li>\n</ul>", "check": {"question": "Which of these is classed as a short-term source of finance in this card?", "options": ["Taking on a new partner, used for a long-term injection of capital funds", "Share issue, used to fund major long-term expansion projects", "Overdraft, used to cover day-to-day running costs such as wages and stock", "Bank loan, used to purchase machinery over several years"], "answer": 2, "explain": "The card classifies overdraft (alongside trade credit) as short-term finance, used for day-to-day costs — share issues, most bank loans and new partners are medium- or long-term."}}, {"title": "Choosing the Right Source of Finance", "html": "<p>When choosing a source of finance, a business must consider several key factors:</p>\n<ul>\n  <li><strong>The purpose:</strong> What is the money for? Day-to-day costs need short-term finance; a new building needs long-term finance.</li>\n  <li><strong>The amount needed:</strong> Small amounts can come from an overdraft or owner''s savings; large sums may require a share issue or crowdfunding.</li>\n  <li><strong>The cost:</strong> Interest on loans and overdrafts increases the total cost. Internal finance (retained profit, owner''s capital) has no interest but has an opportunity cost.</li>\n  <li><strong>The type of business:</strong> A sole trader cannot issue shares. A new business has no retained profit. A partnership cannot issue shares but can take on a new partner.</li>\n  <li><strong>Control:</strong> Share issues and new partners reduce the owner''s control. Loans and overdrafts do not affect ownership.</li>\n  <li><strong>Risk:</strong> Loans require security; if the business fails, the lender may repossess assets. Internal finance carries no such risk.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Brew Dog — Crowdfunding for Expansion</h4>\n  <p>Brew Dog, the Scottish craft beer company, raised over £100 million through crowdfunding between 2011 and 2021 by selling shares via social media campaigns. In 2020 it launched a new crowdfund targeting £50 million to open new bars worldwide, build breweries and buy farmland. Beer enthusiasts who invested received discounts and free birthday beers. Brew Dog deliberately avoided bank loans because it feared lenders would gain too much influence over business decisions. This shows how a business''s values and desire for independence can shape its choice of finance, not just the cost.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Everton FC — Share Issue and Loans</h4>\n  <p>In 2020–21, Everton Football Club needed finance for three reasons: lost matchday revenue due to COVID-19, new player signings costing over £180 million, and a new £500 million stadium project. The club issued £250 million of new shares to its existing owner Farhad Moshiri and planned to borrow the rest from private lenders. This illustrates how large, established organisations may use a combination of share issues and loans to fund major long-term investments.</p>\n</div>", "check": {"question": "Which factor does this card identify as affecting the choice of finance source?", "options": ["Location, since some sources are only available in certain towns or cities", "Weather, since seasonal businesses cannot use any external sources at all", "Control, since share issues and new partners reduce the owner''s decision-making power", "Colour, since some sources are only available to businesses with a certain brand image"], "answer": 2, "explain": "The card lists control as a factor in choosing finance, since share issues and new partners reduce the owner''s control, unlike loans or overdrafts which do not affect ownership."}}, {"title": "Share Issue Calculations", "html": "<p>In the exam you may be asked to calculate the total amount of money raised by a share issue. The formula is simple:</p>\n<div class=\"formula-box\">\n  <strong>Total Finance Raised = </strong> Number of shares sold &times; Price per share\n</div>\n<p>For example, if a company sells 10,000 shares at £1.50 each:</p>\n<div class=\"formula-box\">\n  10,000 &times; £1.50 = <strong>£15,000 raised</strong>\n</div>\n<p>If it sold all 50,000 available shares at £1.50:</p>\n<div class=\"formula-box\">\n  50,000 &times; £1.50 = <strong>£75,000 raised</strong>\n</div>\n<p>If it sold 50% of 50,000 shares (= 25,000) at £1.50:</p>\n<div class=\"formula-box\">\n  25,000 &times; £1.50 = <strong>£37,500 raised</strong>\n</div>\n<p>Also note: interest on a bank loan is calculated as:</p>\n<div class=\"formula-box\">\n  <strong>Annual Interest = </strong> Loan Amount &times; Interest Rate (%)\n</div>\n<p>Example: A £12,000 loan at 8% interest per year = £12,000 &times; 0.08 = <strong>£960 interest in year 1</strong></p>", "check": {"question": "How is the total finance raised by a share issue calculated?", "options": ["Total profit of the business divided by the number of shareholders", "Number of shares sold divided by the price per share", "Loan amount multiplied by the annual interest rate percentage", "Number of shares sold multiplied by the price per share"], "answer": 3, "explain": "The card gives the formula Total Finance Raised = Number of shares sold x Price per share — the interest formula (loan x rate) is a different calculation used for bank loans."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Owner''s capital", "definition": "Money from the owner''s own savings invested into the business. No interest, no repayment — but limited by personal savings."}, {"term": "Retained profit", "definition": "Profit kept in the business rather than paid to owners. Only available to established, profitable businesses. No interest or repayment."}, {"term": "Sale of assets", "definition": "Raising finance by selling fixed assets the business owns. Established businesses only. Can take time to find a buyer."}, {"term": "Overdraft", "definition": "Short-term bank arrangement allowing a business to spend more than its balance. Interest charged daily — expensive long term."}, {"term": "Trade credit", "definition": "Receive goods now, pay later (typically 30–90 days). Usually interest-free within the credit period. Used for stock/raw materials."}, {"term": "Bank loan", "definition": "Fixed sum borrowed for a fixed period, repaid in instalments with interest. May require security. Medium- to long-term."}, {"term": "Share issue", "definition": "Selling new shares in the business. Only for limited companies. Raises large sums — no interest, no repayment — but shareholders gain ownership rights."}, {"term": "Crowdfunding", "definition": "Raising money from many contributors via a website. Can be donations, loans or equity. No security needed. Success is not guaranteed."}, {"term": "Taking on a new partner", "definition": "A new partner contributes capital to a partnership. Brings finance and possibly new skills, but reduces existing owners'' control and profit share."}, {"term": "Short-term finance", "definition": "Finance needed for up to 12 months. Used for day-to-day costs: wages, stock, bills. Sources: overdraft, trade credit."}, {"term": "Medium-term finance", "definition": "Finance needed for 1–5 years. Used for machinery, vehicles, extending premises. Sources: bank loan, retained profit, owner''s capital."}, {"term": "Long-term finance", "definition": "Finance needed for 5+ years. Used for buildings, major expansion, takeovers. Sources: share issue, crowdfunding, long-term bank loan."}, {"term": "Internal finance", "definition": "Finance raised from within the business: owner''s capital, retained profit, sale of assets. No interest, but limited availability."}, {"term": "External finance", "definition": "Finance raised from outside: overdraft, loan, share issue, trade credit, crowdfunding, new partner. Usually has a cost (interest or loss of ownership)."}, {"term": "Security", "definition": "An asset pledged to a lender as a guarantee. If the loan is not repaid, the lender can sell the asset to recover the money."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is a short-term, external source of finance?", "options": ["Retained profit", "Owner''s capital", "Overdraft", "Sale of assets"], "answer": 2, "explain": "Correct answer: Overdraft. An overdraft is arranged with a bank and allows a business to spend more than its account balance. It is external (from a bank) and short-term (used for day-to-day cash needs). Retained profit and owner''s capital are internal sources. Sale of assets can be internal but is not specifically short-term."}, {"question": "Which of the following is NOT a feature of trade credit?", "options": ["The supplier does not need to be paid for 90 days", "Interest has to be paid if the money is not paid within the time limit", "It is useful for dealing with a short-term cash flow problem", "It can be used to finance the purchase of new machinery"], "answer": 3, "explain": "Correct answer: Trade credit is a short-term source used to buy stock or raw materials — it is not suitable for financing the purchase of capital assets such as new machinery, which requires medium- or long-term finance."}, {"question": "Which of the following involves money being reinvested by the business?", "options": ["Overdraft", "Bank loan", "Retained profit", "Crowdfunding"], "answer": 2, "explain": "Correct answer: Retained profit. This is profit earned by the business that is not paid out to owners but reinvested back into the business. Overdraft and bank loans are external borrowing. Crowdfunding raises money from external contributors."}, {"question": "A sole trader borrows £12,000 at 8% interest per year. How much interest will she pay in the first year?", "options": ["£430", "£960", "£1200", "£1500"], "answer": 1, "explain": "Correct answer: £960. The calculation is £12,000 × 0.08 = £960. A is incorrect (£430 has no basis). C would be 10% interest. D would be 12.5% interest."}, {"question": "Which of the following is least likely to be a reason for a business to need finance?", "options": ["To decrease the size of the workforce", "To extend a marketing campaign", "To increase the size of its factory", "To reduce the amount of stock it purchases"], "answer": 3, "explain": "Correct answer: Reducing stock purchases actually decreases the need for finance. Extending a marketing campaign (B), increasing factory size (C), and even decreasing the workforce (A — redundancy payments are required) all require spending money."}, {"question": "Which of the following is an advantage of receiving trade credit?", "options": ["It can be used to pay wages and salaries", "It encourages production operatives to work harder", "It is often interest free", "It may bring new skills into the business"], "answer": 2, "explain": "Correct answer: Trade credit is typically interest-free within the agreed credit period (e.g. 30–90 days). A is wrong — trade credit is for goods, not wages. B is unrelated to finance. D describes a benefit of taking on a new partner, not trade credit."}, {"question": "Which of the following is a benefit to a public limited company of using a share issue to raise finance?", "options": ["Dividends will need to be paid", "New skills will be brought into the company", "No interest will be paid", "Repayments will be spread over a long period of time"], "answer": 2, "explain": "Correct answer: A key benefit of issuing shares is that no interest is payable, unlike a loan. A is a disadvantage (dividends are a cost). B can happen but is not guaranteed. D describes a bank loan, not a share issue — shares do not have repayments."}, {"question": "Which of the following is NOT a good source of new capital (raising additional funds)?", "options": ["Taking a new partner", "Overdraft", "Share issue", "Crowdfunding"], "answer": 1, "explain": "Correct answer: Overdraft. An overdraft is a short-term borrowing tool for managing cash flow; it is not a source of new, permanent capital. Taking a new partner, issuing shares and crowdfunding all bring in new capital to the business."}, {"question": "A business has decided to update all of its computers and printers. This decision will:", "options": ["Increase selling prices", "Reduce fixed costs", "Require financial resources", "Temporarily increase cash inflows"], "answer": 2, "explain": "Correct answer: Buying computers and printers is a capital expenditure — it requires financial resources (money). It will not automatically increase selling prices or reduce fixed costs (it may actually increase them). It will temporarily decrease cash inflows (or increase outflows), not increase them."}, {"question": "Which of the following is an appropriate source of finance for a newly established company?", "options": ["Overdraft", "Retained profit", "Sale of assets", "Taking a partner"], "answer": 0, "explain": "Correct answer: Overdraft. An overdraft is available to new businesses and helps cover short-term cash flow gaps. Retained profit (B) and sale of assets (C) are only available to established businesses that have already traded. Taking a partner (D) is possible but less common for newly established companies."}, {"question": "A sole trader is short of cash to pay a supplier this month. She should:", "options": ["Buy higher quality products", "Improve customer service", "Get an overdraft", "Repay her loan"], "answer": 2, "explain": "Correct answer: Get an overdraft. An overdraft is the ideal short-term solution for a temporary cash flow problem, allowing the business to continue trading. Buying higher quality products or improving customer service will not solve the immediate cash shortage. Repaying a loan would make the cash problem worse."}, {"question": "Which of the following is a short-term source of finance suitable for a new business?", "options": ["Retained profit", "Sale of business assets", "Share issue", "Trade credit"], "answer": 3, "explain": "Correct answer: Trade credit. Trade credit allows a new business to obtain goods from a supplier without paying immediately, which is ideal for a short-term cash need. Retained profit (A) and sale of assets (B) require the business to have been trading. A share issue (C) is long-term and requires incorporation as a limited company."}]}, "fib": {"enabled": true, "questions": [{"text": "An overdraft is a [short-term] source of finance that allows a business to spend more than it has in its [bank account]."}, {"text": "Retained profit is only available to [established] businesses, because a new business will not yet have made any [profit]."}, {"text": "Trade credit allows a business to receive [goods] from a supplier before making payment, and is usually [interest-free] within the agreed credit period."}, {"text": "A share issue can only be used by [limited] companies. The buyers of shares become part-[owners] of the business."}, {"text": "Crowdfunding raises money from a large number of [contributors] via a website, and no [security] is needed for loan-based crowdfunding."}, {"text": "When a business takes on a new partner, the new partner will have a say in the [running] of the business and will be entitled to a share of the [profits]."}, {"text": "A bank loan is usually a [medium-term] or long-term source of finance. The borrower pays back the money in [instalments] over an agreed period."}, {"text": "Owner''s capital is an [internal] source of finance because it comes from within the business owner''s [savings]."}, {"text": "Short-term finance is typically needed for up to [one] year(s) and is used for day-to-day expenses such as [wages] and stock."}, {"text": "One disadvantage of a share issue is that shareholders are entitled to a [say] in how the company is run, and may receive [dividends] from company profits."}, {"text": "Selling a fixed asset such as a machine is a source of [internal] finance. A disadvantage is that it may take [time] to find a buyer."}, {"text": "A business that borrows £10,000 at 5% interest will pay £[500] in interest in the first year. This means the total cost of borrowing is £[10,500]."}]}, "tf": {"enabled": true, "questions": [{"statement": "A bank loan must be repaid with interest.", "answer": true, "explain": "TRUE. A bank loan is a form of external borrowing. The lender charges interest on the amount borrowed, which must be repaid in addition to the original loan amount."}, {"statement": "Shareholders are part-owners of a business.", "answer": true, "explain": "TRUE. When investors buy shares in a company, they become part-owners (shareholders). They are entitled to vote on key decisions and may receive dividends from profits."}, {"statement": "Banks will always lend money to a business that applies for a loan.", "answer": false, "explain": "FALSE. Banks assess the risk of lending. Businesses with a poor financial record, insufficient security, or operating in a very risky sector may be refused a loan."}, {"statement": "Retained profit is available to both new and established businesses.", "answer": false, "explain": "FALSE. Retained profit is only available to established businesses that have already traded and made a profit. A new business has not yet generated any profit to retain."}, {"statement": "An overdraft is a cheap and appropriate way for a business to fund the purchase of a new building.", "answer": false, "explain": "FALSE. An overdraft is a short-term source of finance suitable for day-to-day cash flow issues. Buying a building requires long-term finance (e.g. a bank loan). Using an overdraft long-term is very expensive due to high daily interest charges."}, {"statement": "Trade credit is typically interest-free if paid within the agreed time limit.", "answer": true, "explain": "TRUE. Trade credit allows a business to receive goods and pay for them later, usually within 30–90 days, without paying interest — as long as payment is made within the agreed period."}, {"statement": "Sole traders are able to raise finance by issuing shares.", "answer": false, "explain": "FALSE. Only limited companies (private or public) can issue shares. Sole traders and partnerships are unincorporated businesses and cannot raise money in this way."}, {"statement": "All businesses will have retained profit available to use.", "answer": false, "explain": "FALSE. Only established businesses that have made a profit and chosen not to distribute all of it to owners will have retained profit. New businesses and loss-making businesses cannot use this source."}, {"statement": "One disadvantage of taking on a new partner is that the existing owner(s) must share control and future profits.", "answer": true, "explain": "TRUE. A new partner becomes a co-owner of the business. They are entitled to a share of the profits and have the right to participate in decision-making, which reduces the existing owners'' control."}, {"statement": "Crowdfunding is only available to established businesses.", "answer": false, "explain": "FALSE. Crowdfunding is available to both new and established businesses. It is often used specifically for start-up and early-stage businesses to raise capital from a large number of online contributors."}, {"statement": "A business that takes out a bank loan may be required to offer security.", "answer": true, "explain": "TRUE. Banks often require security — an asset such as property or equipment — as a guarantee that if the business cannot repay the loan, the bank can sell the asset to recover its money."}, {"statement": "Selling assets is always a quick and reliable way to raise finance.", "answer": false, "explain": "FALSE. Selling assets can take time as the business needs to find a willing buyer. There is no guarantee that a buyer can be found, or that the sale price will meet the business''s finance needs."}]}, "misc": {"enabled": true, "items": [{"myth": "Retained profit is a pot of cash sitting in the business that can be spent at any time.", "truth": "Retained profit is an accounting figure showing profits not paid out to owners. The cash from those profits has likely already been used in day-to-day operations. Only if cash has been physically set aside will the business have a lump sum to invest.", "check": {"question": "What is the correct view of what ''retained profit'' represents?", "options": ["An accounting figure for profit not paid out, which may already be spent on operations", "A pot of cash sitting untouched in the business that can be spent at any time at all", "A loan from the bank that must be repaid together with interest charges", "A fee charged to shareholders for holding shares in the business"], "answer": 0, "explain": "The card explains retained profit is an accounting figure, not necessarily a cash pile — the cash from those profits may already have been used in day-to-day operations."}}, {"myth": "All sources of finance are available to every type of business.", "truth": "Different sources are available to different types of businesses. For example, share issues are only for limited companies; taking on a partner is only for sole traders/partnerships; retained profit is only for established businesses.", "check": {"question": "Which statement correctly describes the availability of finance sources?", "options": ["Every single source of finance is available equally to any type of business at all", "Only limited companies are able to raise any finance at all", "Different sources are available to different types of business, such as share issues", "Only sole traders are restricted from using any external finance sources"], "answer": 2, "explain": "The card corrects the misconception that all sources are available to everyone — share issues suit limited companies, taking a partner suits sole traders/partnerships, and retained profit needs an established business."}}, {"myth": "An overdraft is a good way to fund a major long-term investment like buying a building.", "truth": "An overdraft is a short-term source designed for day-to-day cash flow problems. It is expensive (high daily interest) and not suitable for long-term investments. A bank loan or share issue would be more appropriate.", "check": {"question": "Why is an overdraft not suitable for funding a major long-term investment?", "options": ["It requires the business to sell part of its ownership to a bank", "It is only available to businesses that have already made a large profit", "It is a short-term, expensive source designed for day-to-day cash flow gaps", "It cannot legally be arranged unless the business has zero debt"], "answer": 2, "explain": "The card explains an overdraft is short-term and expensive (high daily interest), designed for day-to-day cash flow problems rather than major long-term investments like buying a building."}}, {"myth": "Interest is only a disadvantage of bank loans.", "truth": "Interest applies to overdrafts and trade credit (if not paid on time) as well as loans. Crowdfunding loans also carry interest. The only sources with no interest are internal sources (owner''s capital, retained profit) and share issues.", "check": {"question": "Which sources of finance can also involve paying interest, besides bank loans?", "options": ["Sale of assets and retained profit are the only other examples", "Share issues and taking on a new partner are the only other examples", "Owner''s capital and retained profit are the only other examples", "Overdrafts and late trade credit, as well as crowdfunding loans"], "answer": 3, "explain": "The card corrects the idea that interest only applies to bank loans — overdrafts, late trade credit payments, and crowdfunding loans can all involve interest too."}}, {"myth": "Taking on a new partner means hiring a new employee who earns a salary.", "truth": "A new partner is a co-owner of the business, not an employee. They contribute capital, share in the profits AND losses, and have the right to take part in decision-making. They do not earn a fixed salary.", "check": {"question": "What is the correct status of a new partner joining a business?", "options": ["A lender who is repaid with interest over a fixed period of time", "A co-owner who contributes capital and shares in profits and losses", "An employee who is paid a fixed salary for the work they do", "A shareholder who receives a dividend but has no voting rights"], "answer": 1, "explain": "The card explains a new partner is a co-owner, not an employee — they contribute capital, share in profits AND losses, and take part in decision-making rather than earning a salary."}}, {"myth": "Using your own savings to finance a business is completely free with no cost at all.", "truth": "Owner''s capital has no interest cost, but it does have an opportunity cost — the money could have been earning interest in a bank account or invested elsewhere. There is also the risk of losing personal savings if the business fails.", "check": {"question": "What cost does using owner''s savings to finance a business actually involve?", "options": ["A fee paid to shareholders for the use of their personal savings", "No cost of any kind at all, since savings are always entirely free to use", "Interest charged by the bank on the amount of savings used", "An opportunity cost, since the money could have earned interest elsewhere"], "answer": 3, "explain": "The card explains owner''s capital has no interest cost but does have an opportunity cost, since the money could have earned interest elsewhere or been invested another way."}}, {"myth": "For a ''recommend'' question, you only need to give reasons FOR your chosen option to get full marks.", "truth": "OCR examiners require a comparative answer — you must explain why your chosen option is BETTER THAN the alternative. Answers that only discuss the chosen option without referencing the rejected option cannot score more than 1 mark for justification.", "check": {"question": "What must a full-mark answer to a ''recommend'' question include?", "options": ["A general definition of finance with no reference to either option", "A complete list of every possible source of finance available", "Only reasons for the chosen option, without ever mentioning the alternative", "A comparison explaining why the chosen option is better than the alternative"], "answer": 3, "explain": "The card explains OCR requires a comparative answer justifying why the chosen option is better than the rejected one — answers covering only the chosen option score at most 1 mark."}}, {"myth": "A share issue means the business has to repay shareholders like a loan.", "truth": "Money raised through a share issue does not need to be repaid. Shareholders own part of the business and may receive dividends if profits are made and distributed, but the original sum invested is not returned to them.", "check": {"question": "Does money raised through a share issue need to be repaid like a loan?", "options": ["Yes — but only if the business fails to make a profit that year", "Yes — shareholders must be repaid the full amount plus additional interest", "No — but only if the shareholders agree in writing to waive repayment", "No — shareholders own part of the business and are not repaid the original sum"], "answer": 3, "explain": "The card corrects the misconception that a share issue must be repaid — shareholders own part of the business and may receive dividends, but the original investment is not repaid to them."}}, {"myth": "Crowdfunding always means people are donating money with nothing in return.", "truth": "Crowdfunding can work in three ways: donors give money (common for community projects), lenders provide a loan (repaid with interest), or investors buy equity (a share of the business). Most business crowdfunding involves equity or lending.", "check": {"question": "What does the card say about how crowdfunding contributions actually work?", "options": ["Contributors always receive a fixed rate of interest on their money", "Contributors may donate, lend, or buy equity — not just donate with nothing back", "Contributors always donate money with absolutely nothing given back in return", "Contributors always become full legal business partners as a result"], "answer": 1, "explain": "The card explains crowdfunding can work three ways — donation, loan, or equity — correcting the idea that it always means donations with nothing given in return."}}, {"myth": "A bank loan and an overdraft are essentially the same thing.", "truth": "They are very different. A bank loan is a fixed sum borrowed for a fixed period with set instalments. An overdraft is a flexible, daily arrangement where interest is charged only on the amount overdrawn — it varies day by day and is meant for short-term needs.", "check": {"question": "What is the key difference between a bank loan and an overdraft?", "options": ["A loan is a fixed sum for a fixed period, while an overdraft is a flexible daily arrangement", "A loan requires no interest to be paid at all, while an overdraft always charges some interest", "A loan and an overdraft are essentially identical arrangements with a bank", "A loan is repaid daily, while an overdraft is repaid in one single lump sum"], "answer": 0, "explain": "The card explains a bank loan is a fixed sum for a fixed period with set instalments, while an overdraft is a flexible daily arrangement charged only on the amount overdrawn."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. No explanation. No examples. No paragraphs.</p>\n      <p><strong>Common question types:</strong></p>\n      <ul>\n        <li>\"Identify one reason, other than expansion, why a business needs finance.\" [1 mark]</li>\n        <li>\"State one disadvantage of using an overdraft.\" [1 mark]</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Finance.\"</em><br/>\n      Too vague — this doesn''t state anything about the business.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"To pay for day-to-day expenses such as wages and stock.\"</em><br/>\n      Specific and directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> If the question says \"other than expansion\", any answer linked to growth or opening new premises scores zero — even if it''s perfectly correct business knowledge. Always re-read the exact wording.</p>\n    ", "check": {"question": "What must you avoid when answering a question that says ''other than expansion''?", "options": ["Giving an answer that mentions research and development costs", "Giving any answer linked to growth or opening new premises", "Giving an answer that mentions replacing old machinery or equipment", "Giving an answer that mentions day-to-day running costs like wages"], "answer": 1, "explain": "The card warns that when a question excludes expansion, any growth-related answer scores zero — even if it is otherwise correct business knowledge — so re-read the exact wording."}}, {"title": "Two Disadvantages, One Each — Don''t Confuse Them", "html": "\n      <p>Some questions ask you to state one disadvantage of <strong>two different sources of finance</strong> — one mark each. These are knowledge-only questions, so no application or analysis is needed.</p>\n      <p><strong>Example question:</strong> \"State one disadvantage to a business owner of using: (a) their own capital, (b) a bank loan.\" [2 marks]</p>\n      <p><strong>Formula:</strong> State the disadvantage clearly for each source. Keep it simple.</p>\n      <p><strong>✅ Owner''s capital (1 mark):</strong><br/>\n      <em>\"Using savings will leave the owner with less money for personal use / emergencies.\"</em></p>\n      <p><strong>✅ Bank loan (1 mark):</strong><br/>\n      <em>\"Interest must be paid on the loan, increasing the total cost for the business.\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Students often write a disadvantage of the wrong source — e.g. writing about interest for owner''s capital. Always make sure your disadvantage logically matches the source it''s asking about.</p>\n    ", "check": {"question": "What is the most common mistake in a ''state one disadvantage of each'' question?", "options": ["Writing the disadvantage using bullet points instead of full sentences", "Writing a disadvantage that doesn''t logically match the source being asked about", "Failing to mention any specific source of finance at all in the answer", "Writing far more disadvantages than the actual number the question really asks for"], "answer": 1, "explain": "The card warns students often write a disadvantage of the wrong source — e.g. mentioning interest for owner''s capital — so the disadvantage must logically match the source asked about."}}, {"title": "The U → APP → AN Chain: Three Steps, Zero Shortcuts", "html": "\n      <p>For a 3-mark analyse question, you need to follow the <strong>Understanding → Application → Analysis</strong> chain. You will score ZERO for the analysis mark if you do not apply to the specific business in the case study.</p>\n      <p><strong>The 3-step formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback of this source of finance. What is it?</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it to the specific business in the case study. Use their name, figures, or context.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the financial or operational impact on the business. What does this mean for their costs, cash flow, profit, or growth?</li>\n      </ul>\n      <p><strong>Sentence starters:</strong><br/>\n      U: \"A share issue means the business can raise money without paying interest...\"<br/>\n      APP: \"For CFM, which has a negative closing balance of -£5,500...\"<br/>\n      AN: \"...this will reduce their financial costs, helping them improve their net profit margin.\"</p>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"A share issue is good because it raises money. This is good for the business.\"</em><br/>\n      No application to the case study, no real analysis.</p>\n      <p><strong>✅ Full-Mark Answer (3 marks):</strong><br/>\n      <em>\"A share issue raises finance without requiring repayment (U). This is useful for CFM as they are considering becoming a private limited company and need to fund a new café costing several thousand pounds (APP). By avoiding a bank loan, Martin and Anne will not have to pay interest, keeping their costs low and protecting their 25% net profit margin (AN).\"</em></p>\n      <p><strong>🚫 Examiner Warning — \"Knowledge Dumping\":</strong> Writing everything you know about share issues without referring to the specific business scores very few marks. The examiner is testing whether you can apply theory to context, not just recall theory.</p>\n    ", "check": {"question": "What score do you get for the analysis mark if you don''t apply to the case study business?", "options": ["Zero — the analysis mark requires application to the specific business", "One mark, regardless of whether or not you apply the answer", "Half marks, since basic understanding alone still counts for quite a lot", "Full marks, since analysis can always be entirely theoretical"], "answer": 0, "explain": "The card states you score zero for the analysis mark without applying to the case study business — the U to APP to AN chain requires application before analysis can be credited."}}, {"title": "You MUST Compare Both Options to Get Full Marks", "html": "\n      <p>A 3-mark ''Recommend'' question asks you to choose between <strong>two specific sources of finance</strong> and justify your choice. This is the most commonly failed question type on this topic.</p>\n      <p><strong>The 3-mark formula:</strong></p>\n      <ul>\n        <li><strong>Mark 1 — Judgement:</strong> State your clear recommendation. \"CFM should use retained profit / a share issue.\"</li>\n        <li><strong>Mark 2 — Justification:</strong> Explain why your chosen option is BETTER THAN the other. You must cover BOTH methods.</li>\n        <li><strong>Mark 3 — Context:</strong> Embed a specific detail from the case study to support your comparison.</li>\n      </ul>\n      <p><strong>Sentence starter:</strong><br/>\n      \"I recommend [Option A] because... Unlike [Option B], this will... Given that the case study states [specific detail], this means...\"</p>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n      <em>\"CFM should use retained profit. It is free and they won''t have to pay it back.\"</em><br/>\n      This only discusses the chosen option — no comparison with a share issue, no context.</p>\n      <p><strong>✅ Full-Mark Answer:</strong><br/>\n      <em>\"CFM should use retained profit (JUDGEMENT). Unlike a share issue, retained profit does not require Martin and Anne to sell part of their business, so they keep full control (JUSTIFICATION). Since CFM has only been trading for two years and has a negative cash flow forecast (-£5,500 closing balance), bringing in outside shareholders could lead to pressure to prioritise profit over the partners'' goals (CONTEXT).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Over 50% of students fail to score more than 1 mark on this type of question. The most common mistake is repeating points from the previous two questions without making a clear comparison. The examiner wants new reasoning — not a summary of what you already said.</p>\n    ", "check": {"question": "According to this card, why do most students fail to score well on ''recommend'' questions?", "options": ["They forget to state any final judgement anywhere in their answer", "They recommend an option that isn''t actually mentioned anywhere in the case study", "They write far more detail than the three available marks actually require", "They repeat earlier points without making a clear comparison between the two options"], "answer": 3, "explain": "The card explains over 50% of students fail to score more than 1 mark by repeating earlier points instead of making a genuine new comparison between the two options."}}, {"title": "Argue Both Sides, Then Make a Justified Conclusion", "html": "\n      <p>A 7-mark evaluate question uses Levels of Response marking. You need to demonstrate application, analysis AND evaluation — in that order.</p>\n      <p><strong>Structure your answer in 4 paragraphs:</strong></p>\n      <p><strong>Paragraph 1 — Understanding & Option A (K + U):</strong><br/>\n      Explain what source of finance A is and one reason it could be appropriate.<br/>\n      <em>\"Owner''s capital is money the owner uses from their own savings. For Martina, who has just over £5,000 in savings, this would mean no interest payments...\"</em></p>\n      <p><strong>Paragraph 2 — Analysis & Application of Option A (AN + APP):</strong><br/>\n      Develop the impact on the business using case study details.<br/>\n      <em>\"However, as the equipment costs £5,000 and Martina has just over £5,000 saved, using all her savings would leave her with almost nothing to fall back on in the first months of trading, when the clinic is unlikely to be fully booked...\"</em></p>\n      <p><strong>Paragraph 3 — Analysis & Application of Option B (AN + APP):</strong><br/>\n      Now consider the second option (e.g. bank loan) with its impact.<br/>\n      <em>\"A bank loan would allow Martina to keep her savings as a financial safety net. However, interest charges would increase her monthly fixed costs, putting pressure on MD Sports Clinic''s cash flow, especially in its early months...\"</em></p>\n      <p><strong>Paragraph 4 — Evaluation (3 points: Decision + Context + Impact/Reasoning):</strong><br/>\n      Make a justified conclusion that goes beyond simply repeating your analysis.<br/>\n      <em>\"Overall, I recommend the bank loan. This is because Martina''s savings are barely enough to cover the equipment cost — leaving her with no contingency fund is very risky for a new business. The interest cost is manageable if she secures a low rate, and her stable cash flow forecast suggests she can afford the repayments. Ultimately, it depends on the interest rate offered — if it is high, using savings becomes more attractive.\"</em></p>\n      <p><strong>\"It Depends On...\" Rule:</strong> A conclusion that simply says \"Option A is best\" without nuance scores few evaluation marks. Examiners reward answers that identify the key condition or factor the decision hinges on.</p>\n    ", "check": {"question": "What do examiners reward in the final evaluation paragraph, according to this card?", "options": ["Avoiding a final decision so that both options remain equally valid", "Identifying the key condition or factor that the final decision actually depends on", "Simply stating that one option is the best one without giving any further reasoning", "Repeating the two earlier analysis paragraphs in a slightly shorter form"], "answer": 1, "explain": "The card''s ''It Depends On...'' rule explains examiners reward identifying the key factor the decision hinges on, rather than a bare judgement or a repeat of earlier analysis."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one advantage to the partnership of taking on Finley as a new partner to fund the proposed hotel. [3 marks]", "marks": 3, "hint": "Think about what taking on a new partner means financially — does the partnership have to pay the money back? Does it cost them interest? Then link this to something specific in the case study (the £2m cost, the existing loan, Finley''s background). Finally, explain the impact on the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Identifies an advantage of taking on a partner — e.g. no cost to raise finance / no interest / long-term injection of capital / Finley may bring new skills.</li><li><strong>Application (1 mark):</strong> Links the advantage to the Sea View Hotel context — e.g. the £2m cost of expansion / the existing bank loan / concerns about rising borrowing costs / Finley''s background as a traveller/photographer.</li><li><strong>Analysis (1 mark):</strong> Explains the business-facing impact — e.g. no interest payments frees up money for the hotel / reduces risk compared to taking out a second loan / hotel development can begin sooner.</li></ul><p><strong>Exemplar response:</strong> Taking on a new partner would be a cost-free option (U) to raise the £2m needed for the new hotel development (APP). Not needing to pay interest on this finance saves them money, which can now be spent on the hotel itself (AN).</p><p><strong>Note:</strong> No further marks can be awarded without the understanding mark. Analysis must be business-facing.</p></div>"}, {"question": "Analyse one disadvantage to the partnership of taking on Finley as a new partner to fund the proposed hotel. [3 marks]", "marks": 3, "hint": "Think about what Finley is like — what does the case study tell us about him? Is he unemployed? Does he have relevant hotel experience? What does sharing ownership mean for Anika and Charlie? Then explain the impact on the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Identifies a disadvantage — e.g. loss of control / decision-making slower / profit must be split three ways / Finley may not have the right skills / may not have enough money.</li><li><strong>Application (1 mark):</strong> Links to the case study — e.g. Finley is unemployed / has been travelling / is a photographer not a hotelier / the expansion costs £2m which Finley may not have.</li><li><strong>Analysis (1 mark):</strong> Explains the business-facing impact — e.g. delays to development / conflict in decision-making / less relevant expertise could harm the hotel''s performance.</li></ul><p><strong>Exemplar response:</strong> It may mean that it takes longer to make decisions (U), especially as Finley may not have the skills needed as he is a photographer (APP). This could delay the development of the hotel and mean it opens later, losing potential revenue (AN).</p><p><strong>Examiner''s Comment:</strong> Many candidates wrote about Finley being a \"member of staff\" who needs paying — this is wrong and showed a misunderstanding of how a partnership operates. A partner is a co-owner, not an employee.</p></div>"}, {"question": "Recommend whether the partnership should take on Finley as a new partner or use a bank loan to fund the proposed hotel. [3 marks]", "marks": 3, "hint": "Make a clear choice. Then explain WHY that option is BETTER THAN the other — you must compare them. Use a specific detail from the case study for the third mark. Simply repeating your answers from parts (i) and (ii) will score zero here.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>Judgement (1 mark):</strong> Clear recommendation — bank loan OR new partner.</li><li><strong>Justification (1 mark):</strong> Explains why that option is BETTER THAN the other. Must cover both methods.</li><li><strong>Context (1 mark):</strong> Embeds a specific case study detail to support the comparison.</li></ul><p><strong>Important:</strong> An answer that only discusses the chosen option without comparing it to the rejected option cannot score more than 1 mark. Repeating points from (i) and (ii) scores zero here.</p><p><strong>Exemplar 1 (bank loan):</strong> I think Anika and Charlie should take out a bank loan (JUDGEMENT). This will get them the £2m they need for the hotel straight away, which may be preferable to taking on Finley who is currently unemployed and may not have enough money to invest (CONTEXT + JUSTIFICATION).</p><p><strong>Exemplar 2 (new partner):</strong> The partnership should take on Finley as a new partner (JUDGEMENT). This is better than a bank loan as there would be no interest to pay, which is important given that they are already concerned about their existing loan''s borrowing costs rising (CONTEXT). Unlike a bank loan, this also avoids increasing their debt (JUSTIFICATION).</p></div>"}, {"question": "Identify one reason, other than expansion, why a business needs finance. [1 mark]", "marks": 1, "hint": "Think about what a business spends money on day-to-day, or what it needs when it first starts up. The question excludes expansion, so do not write about opening new branches or growing.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><ul><li>1 mark for any correct reason not linked to expansion or growth.</li></ul><p><strong>Acceptable answers include:</strong></p><ul><li>To cover day-to-day expenses / cash flow (e.g. wages, stock, bills)</li><li>To start up a new business</li><li>To fund recruitment/training activities</li><li>To develop marketing activities</li><li>To develop new products (R&D)</li><li>To replace old machinery or equipment</li><li>To pay back previous debt</li></ul><p><strong>Examiner''s Comment:</strong> Most candidates got this mark. Common correct answers included wages and raw materials. Some candidates answered about the need for a finance department rather than finance itself — this scores zero.</p></div>"}, {"question": "Which of the following is least likely to be a reason for a business to need finance?", "marks": 1, "hint": "Think about which option actually reduces spending rather than requiring money to be spent.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — To reduce the amount of stock it purchases</h5><p><strong>Why D is correct:</strong> Reducing stock purchases means the business is spending less money, so it needs less finance — not more.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Decrease the workforce:</strong> Making staff redundant requires redundancy payments, which need financing.</li><li><strong>B — Extend a marketing campaign:</strong> Marketing costs money — advertising, promotions and campaigns all require finance.</li><li><strong>C — Increase factory size:</strong> Expanding premises is a major capital expenditure that requires significant long-term finance.</li></ul><p><strong>Examiner''s Comment:</strong> Under half of students answered correctly. Many chose A, suggesting they didn''t realise that redundancy payments require finance.</p></div>"}, {"question": "Which of the following is an advantage of receiving trade credit?", "marks": 1, "hint": "What is the key feature of trade credit that makes it attractive to businesses managing their cash flow?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — It is often interest free</h5><p><strong>Why C is correct:</strong> Trade credit is typically interest-free within the agreed repayment period (e.g. 30–90 days), which makes it an attractive, cost-free way to manage cash flow when buying stock.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Pay wages and salaries:</strong> Trade credit is specifically for purchasing goods from suppliers — it cannot be used to pay wages.</li><li><strong>B — Encourages workers to work harder:</strong> This is entirely unrelated to trade credit, which is a financial arrangement between businesses, not employees.</li><li><strong>D — Brings new skills into the business:</strong> This is a benefit of taking on a new partner, not trade credit.</li></ul></div>"}, {"question": "Which of the following is a benefit to a public limited company of using a share issue to raise finance?", "marks": 1, "hint": "Think about the key financial advantage of a share issue compared to a bank loan. What cost does a share issue avoid?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — No interest will be paid</h5><p><strong>Why C is correct:</strong> Unlike a bank loan or overdraft, a share issue does not require the business to pay interest. The money raised does not need to be repaid, and there is no interest charge.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Dividends will need to be paid:</strong> This is a disadvantage of a share issue, not a benefit. Dividends are a cost to the business.</li><li><strong>B — New skills will be brought into the company:</strong> This can happen but is not guaranteed — it is a possible benefit of new shareholders, not a definitive advantage of the share issue itself.</li><li><strong>D — Repayments spread over a long period:</strong> This describes a bank loan, not a share issue. Share capital does not require repayment at all.</li></ul></div>"}, {"question": "Analyse one advantage to RCP of selling its old machines to finance the purchase of the new machinery. [3 marks]", "marks": 3, "hint": "What is the financial benefit of using the sale of assets — what cost does it avoid? Then link specifically to RCP''s financial situation (the growing overdraft, the £100,000+ cost). Finally, explain the impact this has on the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Advantage of selling assets as finance — e.g. no interest / no repayment needed / no need to raise external finance / internal source.</li><li><strong>Application (1 mark):</strong> Links to RCP — e.g. growing overdraft / over £100,000 required / cash flow concerns / overdraft already a problem.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. no negative impact on cash flow from interest / avoids worsening the overdraft / retains ownership and control.</li></ul><p><strong>Exemplar:</strong> RCP will not need to obtain external finance such as a bank loan (U), which will mean no negative impact on their growing overdraft (APP + AN).</p><p><strong>Important:</strong> The advantage must be about using the old machines as a source of finance — not about the benefits of having new machines (e.g. improved production quality scores zero here).</p></div>"}, {"question": "Analyse one disadvantage to RCP of selling its old machines to finance the purchase of the new machinery. [3 marks]", "marks": 3, "hint": "What could go wrong with selling old machines? Consider whether they''d raise enough money, how long it might take, or what RCP loses by not taking a new partner. Link to the specific context.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Disadvantage of selling assets — e.g. may not generate enough money / can take time / may not find a buyer.</li><li><strong>Application (1 mark):</strong> Links to RCP — e.g. over £100,000 required / Alessia prefers a new partner / growing overdraft.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. if insufficient money raised, must find other finance / delays productivity / business left without machinery.</li></ul><p><strong>Exemplar:</strong> This option may not generate enough finance (U) to cover the £100,000 needed (APP). RCP will then need to spend time raising finance from other sources (AN).</p></div>"}, {"question": "Recommend whether RCP should finance the purchase of the new machinery by selling its old machines or by taking on a new partner. [3 marks]", "marks": 3, "hint": "Choose one option clearly. Explain why it is BETTER THAN the other — you must mention both. Use a specific detail from the case study (e.g. the growing overdraft, the £100,000 cost, Alessia''s preference) for the third mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>Judgement (1 mark):</strong> Clear recommendation — sell old machines OR take on a new partner.</li><li><strong>Justification (1 mark):</strong> Explains why chosen option is better than the other. Both methods must be referenced.</li><li><strong>Context (1 mark):</strong> Embeds a specific detail from the case study.</li></ul><p><strong>Exemplar 1 (new partner):</strong> I think they should take on a partner (1). This will probably bring in more money than selling the old assets (1) and is the option preferred by Alessia (APP).</p><p><strong>Exemplar 2 (sell machines):</strong> RCP should sell the old machine (1). As their overdraft is already a cause for concern (APP), a new partner may not be interested in joining a business they may fear will soon fail (1).</p></div>"}, {"question": "Identify one reason, other than expansion, why a business may need to raise finance. [1 mark]", "marks": 1, "hint": "What else does a business spend money on other than growing? Think about day-to-day costs or other purposes.", "markScheme": "<div class=\"marks-section\"><h5>Answer — 1 mark (AO1a)</h5><p>1 mark for any correct reason not linked to expansion or growth.</p><p><strong>Acceptable answers:</strong></p><ul><li>To start a new business</li><li>To pay for day-to-day expenses / wages / stock</li><li>To fund marketing or advertising activities</li><li>To replace old machinery or equipment</li><li>To manage cash flow / working capital</li><li>To fund recruitment or staff training</li><li>To cover costs / prevent going bankrupt</li></ul></div>"}, {"question": "Which of the following is a short-term source of finance suitable for a new business?", "marks": 1, "hint": "Which option is available to a brand new business with no previous trading history? Which one is also short-term?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Trade credit</h5><p><strong>Why D is correct:</strong> Trade credit allows a new business to obtain goods from suppliers and pay later (usually 30–90 days). It is short-term and available to new businesses from the start.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Retained profit:</strong> Only available to established businesses that have already made and kept profit. A new business has no retained profit.</li><li><strong>B — Sale of business assets:</strong> A new business has no assets to sell. This is only available to established businesses.</li><li><strong>C — Share issue:</strong> This is a long-term source of finance for limited companies only — not typically short-term, and requires the business to be incorporated.</li></ul></div>"}, {"question": "Analyse one benefit to CFM of using retained profit to finance the new café. [3 marks]", "marks": 3, "hint": "What is retained profit and why is it financially beneficial? Then link to CFM''s specific situation — think about their cash flow and the fact that they''ve been trading for two years. Finally, explain what this means for the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Correct understanding of retained profit as a source of finance — profit not paid to owners that is kept and reinvested.</li><li><strong>Application (1 mark):</strong> Links to CFM — e.g. two years of trading / improving profit margins / negative cash flow / no need for interest payments.</li><li><strong>Analysis (1 mark):</strong> Impact on CFM — e.g. no interest to pay means lower costs / helps improve net profit margin / Martin and Anne retain full control.</li></ul><p><strong>Exemplar:</strong> Retained profits are those kept in the business not given out to Martin and Anne (U). The retained profit belongs to Martin and Anne as the owners of CFM, and if they use it, they will not have to pay any interest (APP). This keeps CFM''s costs low and helps them maintain a good net profit margin (AN).</p></div>"}, {"question": "Analyse one benefit to CFM of using a share issue to finance the new café. [3 marks]", "marks": 3, "hint": "What is a share issue and what financial benefit does it provide? Link to CFM''s specific situation — they would need to become a private limited company. What is the impact on the business?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Correct understanding of share issue — selling shares to investors who become part-owners; no repayment needed; no interest.</li><li><strong>Application (1 mark):</strong> Links to CFM — e.g. becoming a private limited company / need for significant capital / Anne and Martin as sole decision makers currently.</li><li><strong>Analysis (1 mark):</strong> Impact on CFM — e.g. can raise a large sum / no interest means lower costs / can use retained profit for other purposes / reduces personal financial risk.</li></ul><p><strong>Exemplar:</strong> Becoming a private limited company would allow Martin and Anne to sell shares. Part of the business is sold but they gain money from selling that part (U). Since they are the only partners, they decide whether to lose some ownership (APP). If they sell shares, they use that money to finance the café without risking their own money (AN).</p></div>"}, {"question": "Recommend whether Martin and Anne should use retained profit or a share issue to finance the opening of the new café. [3 marks]", "marks": 3, "hint": "Choose one option clearly. Then explain why it is BETTER THAN the other. You must reference both options. Use details from the case study — the cash flow forecast, the profit margins, the fact it''s a partnership — for full marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>1 mark:</strong> Judgement with limited justification showing some appraisal.</li><li><strong>2 marks:</strong> Judgement with good justification showing appraisal of relevant information.</li><li><strong>3 marks:</strong> Judgement with strong justification that clearly uses case study context in a comparative way.</li></ul><p><strong>Exemplar (retained profit):</strong> The most important consideration for Anne and Martin would be to keep control of their business, so they should use retained profit (1). However, the business has only been trading for two years so there may not be enough retained profit available (1). The decision depends on whether CFM has sufficient retained profit to fully fund the new café (1).</p><p><strong>Exemplar (share issue):</strong> Anne and Martin should use a share issue because it not only provides finance but also reduces risk by giving them limited liability (1). However, it depends on whether they are willing to lose some control of CFM by becoming a private limited company (1). They must decide if expansion is more important than retaining full ownership (1).</p></div>"}, {"question": "A business has decided to update all of its computers and printers. This decision will:", "marks": 1, "hint": "What does buying new equipment mean for the business in financial terms?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Require financial resources</h5><p><strong>Why C is correct:</strong> Updating equipment is a capital expenditure — it requires money (financial resources) to purchase the computers and printers.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Increase selling prices:</strong> Buying new computers does not automatically allow a business to charge more for its products or services.</li><li><strong>B — Reduce fixed costs:</strong> New equipment may eventually reduce costs (e.g. through efficiency), but initially it increases costs, not reduces them.</li><li><strong>D — Temporarily increase cash inflows:</strong> Buying equipment is a cash outflow, not an inflow. It takes money out of the business.</li></ul></div>"}, {"question": "Which of the following is an appropriate source of finance for a newly established company?", "marks": 1, "hint": "Which of these is available to a business that has only just started trading and has no financial history?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Overdraft</h5><p><strong>Why A is correct:</strong> An overdraft can be arranged with a bank by a new business to help cover short-term cash flow needs. It is one of the few external sources accessible from the start.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — Retained profit:</strong> A newly established company has not yet made any profit, so there is nothing to retain and reinvest.</li><li><strong>C — Sale of assets:</strong> A new business typically has very few or no assets to sell.</li><li><strong>D — Taking a partner:</strong> While possible, this is less typical for a newly established company and is more of a structural decision than a routine source of start-up finance.</li></ul></div>"}, {"question": "State one disadvantage to a business owner of using:\n(a) their own capital to buy equipment\n(b) a bank loan to buy equipment\n[2 marks]", "marks": 2, "hint": "For owner''s capital, think about what happens to Martina''s personal finances. For a bank loan, think about what the bank charges and what the business has to do each month.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><ul><li><strong>1 mark:</strong> Correct disadvantage of owner''s capital — e.g. uses up most of savings / leaves owner short of funds / limited contingency / loss of interest earned in bank account.</li><li><strong>1 mark:</strong> Correct disadvantage of a bank loan — e.g. expensive / interest must be paid / monthly repayments impact cash flow / may need security / risk of losing assets if defaulted / difficult for new businesses to obtain.</li></ul></div>"}, {"question": "Evaluate whether Martina should use her own savings or a bank loan to buy the equipment for MD Sports Clinic. [7 marks]", "marks": 7, "hint": "You need to argue BOTH sides and make a justified conclusion. Consider what happens to her savings if she uses them all, what happens to her cash flow if she takes a loan, and what she is most at risk from as a brand new business.", "markScheme": "<div class=\"marks-section\"><h5>Levels of Response — 7 marks (AO2 + AO3a + AO3b)</h5>\n\n<p><strong>Level 3 (5–7 marks): AO2 = 2, AO3a = 2, AO3b = 3</strong></p>\n<ul>\n  <li>Good application of knowledge to MD Sports Clinic context — detailed understanding of the scenario used throughout.</li>\n  <li>Detailed analysis — logical chains of reasoning about the effects of both savings and bank loan on the business.</li>\n  <li>Strong evaluation — a fully justified conclusion is made that draws on case study context; recognises conditions that affect the decision.</li>\n</ul>\n\n<p><strong>Level 2 (3–4 marks): AO2 = 2, AO3a = 1, AO3b = 1</strong></p>\n<ul>\n  <li>Good application to MD Sports Clinic context.</li>\n  <li>Limited analysis — some cause-and-effect reasoning.</li>\n  <li>Limited evaluation — attempts a conclusion with some recognition of relevant factors.</li>\n</ul>\n\n<p><strong>Level 1 (1–2 marks): AO2 = 1, AO3a = 1</strong></p>\n<ul>\n  <li>Some use of the scenario but limited.</li>\n  <li>Basic chains of reasoning.</li>\n  <li>No evaluation.</li>\n</ul>\n\n<p><strong>0 marks:</strong> No response or nothing worthy of credit.</p></div>"}, {"question": "A sole trader is short of cash to pay a supplier this month. She should:", "marks": 1, "hint": "What short-term financial tool allows a business to spend more than it has in its account to cover immediate payments?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Get an overdraft</h5><p><strong>Why C is correct:</strong> An overdraft is specifically designed for short-term cash flow problems. It allows a business to spend more than its current bank balance, covering immediate payments such as a supplier invoice.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Buy higher quality products:</strong> This would cost more money, making the cash shortage worse — not better.</li><li><strong>B — Improve customer service:</strong> While beneficial long-term, improving customer service does not solve an immediate cash shortage this month.</li><li><strong>D — Repay her loan:</strong> Repaying a loan would further reduce the cash available, making it even harder to pay the supplier.</li></ul></div>"}, {"question": "Analyse one advantage and one disadvantage to Brew Dog of using crowdfunding to finance its expansion. [6 marks]", "marks": 6, "hint": "This is two separate 3-mark analyse questions in one. For each point, follow the U → APP → AN structure. For advantage application, use Brew Dog''s track record, social media following and figures. For disadvantage, think about the costs of publicising crowdfunding and the risks of failing to hit targets.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b x2 + AO2 x2 + AO3a x2)</h5>\n\n<p><strong>Advantage of crowdfunding (3 marks):</strong></p>\n<ul>\n  <li><strong>Understanding (1 mark):</strong> A benefit of crowdfunding — e.g. cheap way to raise investment / money does not need to be repaid / raise money from many investors.</li>\n  <li><strong>Application (1 mark):</strong> Links to Brew Dog — e.g. previous success raising £100m / large social media following / 200,000 existing shareholders / strong brand awareness.</li>\n  <li><strong>Analysis (1 mark):</strong> Impact on Brew Dog — e.g. investors are likely to be sympathetic to the business''s values so won''t seek to change its direction / more people become customers as well as investors.</li>\n</ul>\n\n<p><strong>Disadvantage of crowdfunding (3 marks):</strong></p>\n<ul>\n  <li><strong>Understanding (1 mark):</strong> A problem with crowdfunding — e.g. needs to be publicised / must give away benefits / no guarantee the target will be reached.</li>\n  <li><strong>Application (1 mark):</strong> Links to Brew Dog — e.g. discounts and birthday beers cost money / publicity stunts are expensive / £50 million is a very large target.</li>\n  <li><strong>Analysis (1 mark):</strong> Impact on Brew Dog — e.g. if crowdfunding fails, it means bad publicity and the planned expansion cannot go ahead / high promotion costs reduce profit.</li>\n</ul></div>"}, {"question": "Recommend whether Brew Dog should continue to use crowdfunding to finance its expansion. [3 marks]", "marks": 3, "hint": "You can recommend continuing OR switching to loans. Whichever you choose, you must explain why it is BETTER THAN the alternative. Use specific details from the Brew Dog case study — figures, their stated aims, social media presence — for the third mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>Judgement (1 mark):</strong> Clear recommendation — continue crowdfunding / switch to loans / use a combination.</li><li><strong>Justification (up to 2 marks):</strong> Justified comparison using case study context.</li></ul><p><strong>For continuing crowdfunding:</strong></p><ul><li>Brew Dog has been very successful — raised £100m+ previously.</li><li>Large social media following and strong brand means it can continue to attract investors.</li><li>Like-minded investors who share Brew Dog''s values are less likely to interfere with decision-making than bank lenders.</li></ul><p><strong>For switching to a bank loan:</strong></p><ul><li>£50 million is a very large target — may be more than crowdfunding supporters can provide.</li><li>A bank loan can be arranged quickly with certainty of the full amount.</li><li>Brew Dog''s strong track record makes it a low-risk borrower for banks.</li></ul></div>"}]}}'::jsonb),
('business', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>This unit covers how businesses calculate and use financial data to measure performance and guide decisions. Master these terms before attempting any exam question.</p>\n    <ul>\n    <li><strong>Revenue (Total Revenue):</strong> The money received from sales. Calculated as: Revenue = Quantity Sold × Selling Price.</li>\n    <li><strong>Fixed Costs:</strong> Costs that stay the same regardless of a change in output — e.g. rent, salaries, business rates, insurance.</li>\n    <li><strong>Variable Costs:</strong> Costs that change as output changes — e.g. wages, raw materials, packaging, energy used in production.</li>\n    <li><strong>Total Costs:</strong> The addition of total fixed costs and total variable costs. TC = TFC + TVC.</li>\n    <li><strong>Cost of Sales:</strong> The direct cost of producing the goods sold — e.g. buying materials, buying stock, paying workers to make a product.</li>\n    <li><strong>Expenses:</strong> The ongoing costs of running the business — e.g. rent, wages, insurance, heating and lighting, advertising.</li>\n    <li><strong>Gross Profit:</strong> Revenue minus the cost of sales. Profit before running costs are deducted.</li>\n    <li><strong>Net Profit:</strong> Gross profit minus expenses. The most accurate measure of overall business performance.</li>\n    <li><strong>Loss:</strong> When the costs of the business are greater than its revenue.</li>\n    <li><strong>Gross Profit Margin (GPM):</strong> (Gross Profit ÷ Revenue) × 100. Expressed as a percentage.</li>\n    <li><strong>Net Profit Margin (NPM):</strong> (Net Profit ÷ Revenue) × 100. Expressed as a percentage.</li>\n    <li><strong>Profitability Ratios:</strong> Calculations (GPM and NPM) used to measure how efficiently a business generates profit from its revenue.</li>\n    <li><strong>Average Rate of Return (ARR):</strong> A method of calculating the average annual return on an investment as a percentage of its cost.</li>\n    </ul>", "check": {"question": "According to the key definitions, how is net profit calculated?", "options": ["Revenue minus cost of sales", "Gross profit margin multiplied by revenue", "Gross profit minus expenses", "Total fixed costs plus total variable costs"], "answer": 2, "explain": "The card defines Net Profit = Gross Profit − Expenses, distinguishing it from gross profit (Revenue − Cost of Sales) and total costs (TFC + TVC)."}}, {"title": "Revenue — Formula & Decision Making", "html": "<p><strong>Revenue</strong> is the income coming into a business from the sale of products and services. It is NOT the same as profit.</p>\n    <div class=\"formula-box\">\n      <strong>Revenue = Quantity Sold × Selling Price</strong>\n    </div>\n    <p>Example: A business sells 25 cars at £7,500 each → TR = 25 × £7,500 = <strong>£187,500</strong></p>\n    <p>Revenue must be analysed carefully before making pricing decisions. Simply cutting the price does not guarantee higher revenue — you must calculate total revenue at each price point.</p>\n    <ul>\n    <li><strong>Raise price:</strong> Earns more per unit but may lose customers. Works when competitors are few.</li>\n    <li><strong>Lower price:</strong> Sells more units but earns less each. Works when demand is price-sensitive.</li>\n    <li><strong>Increase advertising:</strong> Can drive more sales, but the extra revenue must exceed the cost of advertising.</li>\n    <li><strong>Expand product range:</strong> More products attract more customers (e.g. Dyson, Tesco, Amazon).</li>\n    <li><strong>Open new markets / e-commerce:</strong> Reaches customers globally without high fixed costs.</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">Factors That Increase Revenue</div>\n    <div class=\"pro-item\"><strong>Fewer competitors:</strong> A business can raise prices without losing customers to rivals.</div>\n    <div class=\"pro-item\"><strong>Competitor price rises:</strong> Allows you to raise prices too without losing market share.</div>\n    <div class=\"pro-item\"><strong>Product is already cheap:</strong> A percentage price rise has little impact on demand and boosts revenue.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">Factors That May Reduce Revenue</div>\n    <div class=\"con-item\"><strong>Many competitors:</strong> Customers switch, reducing sales volume and revenue.</div>\n    <div class=\"con-item\"><strong>Competitor price cuts:</strong> You may need to match them or lose customers.</div>\n    <div class=\"con-item\"><strong>Premium-priced products:</strong> Any further price rise may significantly reduce demand.</div>\n    </div>\n    </div>", "check": {"question": "According to this card, what must a business do before assuming a price cut will raise revenue?", "options": ["Calculate total revenue at each price point rather than assuming", "Wait until its net profit margin has doubled compared with last year", "Automatically raise prices to match its main competitors", "Reduce its total fixed costs before changing any prices"], "answer": 0, "explain": "The card warns that cutting price does not guarantee higher revenue — a business must calculate total revenue at each price point before deciding."}}, {"title": "Fixed Costs vs Variable Costs", "html": "<p>Every cost a business pays falls into one of two categories. Getting this distinction right is essential for exam questions on costs, break-even and profit.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">Fixed Costs</div>\n    <div class=\"pro-item\"><strong>Do NOT change</strong> when output changes. Must be paid whether the business produces 0 or 10,000 units.</div>\n    <div class=\"pro-item\"><strong>Examples:</strong> Rent, business rates, insurance, <em>salaries</em>, interest on loans, mortgage payments, advertising (if contracted).</div>\n    <div class=\"pro-item\"><strong>Key fact:</strong> Even if a business temporarily closes, fixed costs continue.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">Variable Costs</div>\n    <div class=\"con-item\"><strong>DO change</strong> when output changes. The more the business produces, the higher the total variable cost.</div>\n    <div class=\"con-item\"><strong>Examples:</strong> Raw materials, <em>wages</em> (hourly paid), packaging, energy used in production, stock purchased to resell.</div>\n    <div class=\"con-item\"><strong>Formula:</strong> Total Variable Costs = Quantity × Variable Cost per Unit</div>\n    </div>\n    </div>\n    <p>⚠️ <strong>Salaries vs Wages:</strong> Salaries (fixed annual pay) = fixed cost. Hourly wages (paid per hour worked) = variable cost.</p>\n    <div class=\"formula-box\">\n      <strong>Total Costs (TC) = Total Fixed Costs (TFC) + Total Variable Costs (TVC)</strong>\n    </div>\n    <p><strong>Worked Example:</strong> Fixed costs = £18,000/month. Variable cost per unit = £2.75. Units sold = 5,450.<br>\n    TVC = 5,450 × £2.75 = £14,987.50 &nbsp; TC = £18,000 + £14,987.50 = <strong>£32,987.50</strong></p>", "check": {"question": "According to this card, how are salaries and hourly wages classified?", "options": ["Salaries are a fixed cost, while hourly wages are a variable cost", "Both salaries and hourly wages are always classed as fixed costs", "Both salaries and hourly wages are always classed as variable costs", "Salaries are a variable cost, while hourly wages are a fixed cost"], "answer": 0, "explain": "The card explains salaries (fixed annual pay) are a fixed cost, while hourly wages (paid per hour worked) are a variable cost — a key exam distinction."}}, {"title": "Gross Profit and Net Profit", "html": "<p>There are two types of profit. Both are calculated differently and tell you different things about a business.</p>\n    <div class=\"formula-box\">\n      <strong>Gross Profit = Revenue − Cost of Sales</strong>\n    </div>\n    <p>Gross profit measures the profit from buying and selling goods <em>before</em> the running costs of the business are deducted. Example: buy goods for £30, sell for £50 → Gross profit = £20.</p>\n    <div class=\"formula-box\">\n      <strong>Net Profit = Gross Profit − Expenses</strong>\n    </div>\n    <p>Net profit is a more accurate measure because it accounts for ALL costs. Example:</p>\n    <ul>\n    <li>Gross profit: £500,000</li>\n    <li>Wages &amp; salaries: £300,000 &nbsp;|&nbsp; Rent: £50,000 &nbsp;|&nbsp; Heating: £10,000 &nbsp;|&nbsp; Insurance: £5,000 = Total expenses: £365,000</li>\n    <li><strong>Net profit = £500,000 − £365,000 = £135,000</strong></li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ When Profit Rises...</div>\n    <div class=\"pro-item\">Buy new equipment and buildings</div>\n    <div class=\"pro-item\">Expand or take over other businesses</div>\n    <div class=\"pro-item\">Pay increasing dividends to shareholders</div>\n    <div class=\"pro-item\">Develop new products and services</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ When Losses Occur...</div>\n    <div class=\"con-item\">Investment decisions postponed</div>\n    <div class=\"con-item\">May be forced to accept a takeover</div>\n    <div class=\"con-item\">Dividends reduced or cancelled</div>\n    <div class=\"con-item\">Cannot invest in new products — loses customers to rivals</div>\n    </div>\n    </div>", "check": {"question": "What happens to a business''s spending options when it makes a loss, according to this card?", "options": ["The business can automatically raise its dividends paid to shareholders", "Investment decisions may be postponed and dividends reduced or cancelled", "The business must immediately increase its net profit margin", "The business is guaranteed to be taken over by a competitor firm"], "answer": 1, "explain": "The card lists postponed investment and reduced or cancelled dividends as consequences of a loss — the opposite of what happens when profit rises."}}, {"title": "Profitability Ratios — GPM & NPM", "html": "<p>Profitability ratios allow a business to <strong>measure and compare performance</strong> more accurately than just looking at profit figures. A rising profit can still mean falling profitability if revenue rises faster.</p>\n    <div class=\"formula-box\">\n      <strong>Gross Profit Margin (%) = (Gross Profit ÷ Revenue) × 100</strong>\n    </div>\n    <div class=\"formula-box\">\n      <strong>Net Profit Margin (%) = (Net Profit ÷ Revenue) × 100</strong>\n    </div>\n    <p><strong>Example — Jacquelyn Williams Booksellers:</strong></p>\n    <ul>\n    <li>Year 1: Revenue £150,000 | Gross Profit £70,000 | Net Profit £30,000</li>\n    <li>Year 2: Revenue £225,000 | Gross Profit £85,000 | Net Profit £30,000</li>\n    </ul>\n    <p>Year 1 GPM = (70,000 ÷ 150,000) × 100 = <strong>46.7%</strong> &nbsp; Year 2 GPM = (85,000 ÷ 225,000) × 100 = <strong>37.8%</strong></p>\n    <p>Year 1 NPM = (30,000 ÷ 150,000) × 100 = <strong>20%</strong> &nbsp; Year 2 NPM = (30,000 ÷ 225,000) × 100 = <strong>13.3%</strong></p>\n    <p>Although net profit stayed the same in pounds, <strong>both margins fell</strong> — the business is becoming less efficient at converting revenue into profit. Action should be taken.</p>\n    <p>⚠️ <strong>Net profit margin is considered the more accurate profitability measure</strong> because it accounts for ALL costs, not just cost of sales.</p>", "check": {"question": "In the Jacquelyn Williams example, what happened to profitability even though net profit in pounds stayed the same?", "options": ["Both the gross and net profit margins rose as revenue fell faster than profit", "Both margins stayed exactly the same because profit in pounds was unchanged", "The gross profit margin rose while the net profit margin stayed the same", "Both the gross and net profit margins fell as revenue rose faster than profit"], "answer": 3, "explain": "The card shows that although net profit stayed at £30,000, both GPM and NPM fell because revenue rose faster than profit — profitability, not just profit, must be tracked."}}, {"title": "Interpreting Profitability Ratios", "html": "<p>Being able to calculate a ratio is only the first step. Examiners award the higher marks for interpreting what the figures mean and recommending appropriate action.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">↑ GPM Improves When...</div>\n    <div class=\"pro-item\">Revenue rises faster than cost of sales</div>\n    <div class=\"pro-item\">Revenue falls but cost of sales falls more</div>\n    <div class=\"pro-item\">Revenue rises AND cost of sales falls</div>\n    <div class=\"col-head\" style=\"margin-top:8px\">↑ NPM Improves When...</div>\n    <div class=\"pro-item\">Gross profit rises faster than expenses</div>\n    <div class=\"pro-item\">Gross profit falls but expenses fall more</div>\n    <div class=\"pro-item\">Gross profit rises AND expenses fall</div>\n    </div>\n    <div>\n    <div class=\"col-head\">↓ GPM Worsens When...</div>\n    <div class=\"con-item\">Revenue falls AND cost of sales rises</div>\n    <div class=\"con-item\">Revenue rises but cost of sales rises more</div>\n    <div class=\"con-item\">Revenue falls but cost of sales falls less</div>\n    <div class=\"col-head\" style=\"margin-top:8px\">↓ NPM Worsens When...</div>\n    <div class=\"con-item\">Gross profit falls AND expenses rise</div>\n    <div class=\"con-item\">Gross profit rises but expenses rise more</div>\n    <div class=\"con-item\">Gross profit falls but expenses fall less</div>\n    </div>\n    </div>\n    <p><strong>How to improve GPM:</strong> Increase revenue (adjust pricing, increase advertising, enter new markets) OR reduce cost of sales (negotiate lower supplier prices, find cheaper suppliers).</p>\n    <p><strong>How to improve NPM:</strong> All GPM strategies PLUS reduce expenses — cut the wage bill, save on energy, reduce rent.</p>", "check": {"question": "According to this card, when does gross profit margin improve?", "options": ["When fixed costs increase while variable costs stay exactly the same", "When net profit falls but expenses rise even further than that", "When cost of sales rises faster than revenue increases each year", "When revenue rises faster than cost of sales, or cost of sales falls"], "answer": 3, "explain": "The card lists revenue rising faster than cost of sales (or cost of sales falling) as ways GPM improves — expenses and fixed/variable cost changes affect NPM, not GPM directly."}}, {"title": "Average Rate of Return (ARR)", "html": "<p>ARR is used to judge whether a business investment (in equipment or another business) is worthwhile, by expressing the average annual profit as a percentage of the original cost.</p>\n    <div class=\"formula-box\">\n      <strong>Step 1: Total Profit = Total Income (from investment) − Cost of Investment</strong><br><br>\n      <strong>Step 2: Average Annual Profit = Total Profit ÷ Life of Investment (years)</strong><br><br>\n      <strong>Step 3: ARR (%) = (Average Annual Profit ÷ Cost of Investment) × 100</strong>\n    </div>\n    <p><strong>Worked Example:</strong> A business buys a mower for £5,000 and earns £13,000 over 5 years.</p>\n    <ul>\n    <li>Step 1: £13,000 − £5,000 = £8,000 total profit</li>\n    <li>Step 2: £8,000 ÷ 5 = £1,600 average annual profit</li>\n    <li>Step 3: (£1,600 ÷ £5,000) × 100 = <strong>32%</strong></li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages of ARR</div>\n    <div class=\"pro-item\">Gives a percentage return easily compared with other investments or savings rates</div>\n    <div class=\"pro-item\">Focuses on profitability — key for shareholders and investors</div>\n    <div class=\"pro-item\">Straightforward to calculate and explain</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages of ARR</div>\n    <div class=\"con-item\">Based on a forecast — actual results may differ significantly</div>\n    <div class=\"con-item\">Does not account for the timing of cash flows</div>\n    <div class=\"con-item\">Ignores the time value of money</div>\n    </div>\n    </div>\n    <p><strong>How ARR is used:</strong> Compare two investments and choose the one with the higher ARR. Compare ARR against a bank interest rate — if ARR is only slightly higher than a risk-free savings rate, the investment may not be worth the risk.</p>", "check": {"question": "What is Step 1 of the ARR calculation, according to this card?", "options": ["Divide total income directly by the cost of investment straight away", "Subtract the cost of investment from total income to find total profit", "Multiply the cost of investment by the number of years invested", "Divide the cost of investment by the total annual profit figure"], "answer": 1, "explain": "The card sets out Step 1 as Total Profit = Total Income − Cost of Investment, before dividing by years (Step 2) and then by cost of investment (Step 3)."}}, {"title": "Revenue, Costs & Profit in Decision Making", "html": "<p>Financial data is only valuable if it is used to make better business decisions. Each measure of performance has specific implications for what a business should do next.</p>\n    <p><strong>Revenue and Decision Making:</strong> Revenue data helps set pricing strategy. A business must test different price points to find which maximises total revenue. Increasing sales volume through advertising or expansion is another route — but the cost must be outweighed by the revenue gain.</p>\n    <p><strong>Costs and Decision Making:</strong> High fixed costs mean the business must sell many products just to break even. If variable costs rise (e.g. raw materials become more expensive), the business can accept the increase, find a cheaper supplier, or negotiate with the existing one.</p>\n    <p><strong>Profit and Loss in Decision Making:</strong> Sustained profit funds expansion and investment. Losses force cuts. A business that continues to make losses will eventually fail.</p>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Zara (Global Fashion)</h4>\n      <p>Zara keeps its variable costs low by buying fabric in large quantities from European suppliers. This lowers cost of sales and improves gross profit margin. With better margins, Zara''s owners receive more profit. When COVID-19 struck in 2020, Zara''s revenue fell 29% from €19,954m to €14,129m. Its ability to control costs helped it survive the fall. This shows that profitability ratios — not just revenue — are the true test of financial health.</p>\n    </div>", "check": {"question": "According to the Zara case study, what helped the business survive its 2020 revenue fall?", "options": ["Closing its stores permanently in every country it traded in", "Controlling costs, which protected its profitability despite falling revenue", "Borrowing heavily from banks to cover its day-to-day running costs", "Raising its selling prices sharply across every single global market it serves"], "answer": 1, "explain": "The card explains Zara''s low variable costs and controlled cost of sales protected its profit margins when revenue fell 29% in 2020 — showing profitability ratios matter more than revenue alone."}}, {"title": "How to Increase Revenue & Reduce Costs", "html": "<p>Businesses can improve their profitability from two sides: increasing revenue or reducing costs. Both affect profit margins.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">↑ Strategies to Increase Revenue</div>\n    <div class=\"pro-item\"><strong>Raise selling price:</strong> Works if customers are not very price-sensitive (few alternatives)</div>\n    <div class=\"pro-item\"><strong>Lower price to increase volume:</strong> Works if demand is highly price-sensitive</div>\n    <div class=\"pro-item\"><strong>Increase advertising:</strong> Builds brand awareness and drives sales</div>\n    <div class=\"pro-item\"><strong>Expand product range:</strong> Appeal to more customer segments</div>\n    <div class=\"pro-item\"><strong>Open new markets / sell online:</strong> Reach more customers globally</div>\n    </div>\n    <div>\n    <div class=\"col-head\">↓ Strategies to Reduce Costs</div>\n    <div class=\"con-item\"><strong>Find cheaper suppliers:</strong> Must also check quality and reliability</div>\n    <div class=\"con-item\"><strong>Negotiate lower prices:</strong> Ask existing suppliers for discounts, especially on bulk orders</div>\n    <div class=\"con-item\"><strong>Use technology:</strong> Automate production to reduce labour costs</div>\n    <div class=\"con-item\"><strong>Reduce the wage bill:</strong> Cut hours, reduce pay, or replace labour with machines</div>\n    <div class=\"con-item\"><strong>Save on energy:</strong> More efficient equipment, better insulation</div>\n    </div>\n    </div>", "check": {"question": "Which of these is listed as a strategy to reduce costs in this card?", "options": ["Expanding the product range to appeal to new customer segments", "Using technology to automate production and reduce labour costs", "Opening new markets by selling products online internationally", "Raising the selling price charged to existing loyal customers"], "answer": 1, "explain": "The card lists automating production with technology as a cost-reduction strategy; raising prices, expanding range and opening new markets are all revenue-increasing strategies instead."}}, {"title": "Real-World Examples", "html": "<div class=\"case-study-box\">\n      <h4>Case Study: Alan Cropley Guitars (ACG)</h4>\n      <p>ACG''s guitars were featured at a major music festival in 2016, driving huge demand. Revenue doubled as Alan was able to increase prices. However, he also hired six more skilled workers and the factory was reaching capacity. His financial data (Revenue: £860,000 | Gross Profit: £550,000 | Net Profit: £210,000 | Guitars sold: 520) gives a net profit margin of 24.4%. Alan must consider whether a new factory investment (a higher fixed cost) would be justified by the additional revenue it could generate — this is exactly the kind of decision ARR is designed to support.</p>\n      <p><strong>Takeaway:</strong> Revenue growth does not automatically guarantee rising profitability. Tracking profit margins over time is essential to spot whether costs are rising faster than revenue.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Unilever plc</h4>\n      <p>Unilever sells products including Lynx, Dove, Hellmann''s and Persil across 190 countries. Its worldwide revenue grew from €50,900m (2018) to €60,000m (2022) — but dipped to €50,700m in 2020. Despite revenue growth, Unilever must manage both variable costs (raw materials per product) and fixed costs (factory rent, salaries) to protect its profit margins. This illustrates that revenue trends alone do not tell the full financial story.</p>\n    </div>", "check": {"question": "What is the key takeaway from the Alan Cropley Guitars (ACG) case study?", "options": ["Net profit margin is irrelevant whenever a business''s revenue is increasing", "Guitar factories never need to consider fixed costs when they invest", "Revenue growth always guarantees that profitability will also rise too", "Revenue growth does not automatically guarantee that profitability also rises"], "answer": 3, "explain": "The card''s takeaway is that revenue growth does not automatically mean rising profitability — tracking profit margins over time reveals whether costs are outpacing revenue."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Revenue Formula", "definition": "Revenue = Quantity Sold × Selling Price"}, {"term": "Gross Profit Formula", "definition": "Gross Profit = Revenue − Cost of Sales"}, {"term": "Net Profit Formula", "definition": "Net Profit = Gross Profit − Expenses"}, {"term": "Total Costs Formula", "definition": "TC = Total Fixed Costs + Total Variable Costs"}, {"term": "Gross Profit Margin Formula", "definition": "(Gross Profit ÷ Revenue) × 100 = GPM %"}, {"term": "Net Profit Margin Formula", "definition": "(Net Profit ÷ Revenue) × 100 = NPM %"}, {"term": "ARR — Step 1", "definition": "Total Profit = Total Income (from investment) − Cost of Investment"}, {"term": "ARR — Step 2", "definition": "Average Annual Profit = Total Profit ÷ Number of Years"}, {"term": "ARR — Step 3", "definition": "ARR = (Average Annual Profit ÷ Cost of Investment) × 100"}, {"term": "Percentage Change Formula", "definition": "(Change ÷ Original Value) × 100"}, {"term": "Fixed Cost", "definition": "A cost that does NOT change when output changes — e.g. rent, insurance, salaries"}, {"term": "Variable Cost", "definition": "A cost that DOES change when output changes — e.g. raw materials, wages, packaging"}, {"term": "Cost of Sales", "definition": "The direct cost of producing the goods sold — e.g. buying materials, stock, or paying workers to make the product"}, {"term": "Expenses", "definition": "Ongoing running costs of the business — rent, wages, utilities, insurance, advertising"}, {"term": "Why NPM is more accurate than GPM", "definition": "NPM accounts for ALL business costs including expenses, not just cost of sales — giving a fuller picture of profitability"}, {"term": "Why use ARR?", "definition": "To compare the profitability of different investments over their lifetime and decide which offers the best return relative to cost"}, {"term": "Revenue vs Profit", "definition": "Revenue = total income from sales. Profit = revenue MINUS all costs. A business can have high revenue but still make a loss."}, {"term": "Loss", "definition": "When total costs exceed total revenue — costs > revenue = loss"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which formula correctly calculates a business''s total revenue?", "options": ["Revenue = Net Profit + Expenses", "Revenue = Gross Profit + Total Costs", "Revenue = Fixed Costs + Variable Costs", "Revenue = Quantity Sold × Selling Price"], "answer": 3, "explain": "Correct: Revenue = Quantity Sold × Selling Price. This gives total income from sales. For example, 200 units at £10 each = £2,000 revenue. Revenue is NOT profit — costs have not yet been subtracted."}, {"question": "A hairdresser pays £800 per month rent for her salon regardless of how many customers she serves. Rent is an example of:", "options": ["A net profit", "The cost of sales", "A variable cost", "A fixed cost"], "answer": 3, "explain": "Correct: Fixed cost. Rent does not change with output — the hairdresser pays £800 whether she serves 5 customers or 500. Fixed costs must be paid even if the business produces nothing."}, {"question": "A bakery uses more flour as it bakes more loaves. The cost of flour is a:", "options": ["Salary cost", "Total cost", "Fixed cost", "Variable cost"], "answer": 3, "explain": "Correct: Variable cost. The cost of flour increases directly with the number of loaves produced. Variable costs change as output changes."}, {"question": "A business has revenue of £90,000 and cost of sales of £30,000. What is the gross profit?", "options": ["£90,000", "£60,000", "£30,000", "£120,000"], "answer": 1, "explain": "Correct: Gross Profit = Revenue − Cost of Sales = £90,000 − £30,000 = £60,000. Remember: gross profit does NOT deduct expenses such as wages or rent."}, {"question": "A business has gross profit of £60,000 and expenses of £35,000. What is the net profit?", "options": ["£60,000", "£95,000", "£35,000", "£25,000"], "answer": 3, "explain": "Correct: Net Profit = Gross Profit − Expenses = £60,000 − £35,000 = £25,000. Net profit is the more accurate measure of performance because it accounts for ALL running costs."}, {"question": "A business has gross profit of £45,000 and revenue of £150,000. What is the gross profit margin?", "options": ["3%", "33%", "45%", "30%"], "answer": 3, "explain": "Correct: GPM = (Gross Profit ÷ Revenue) × 100 = (£45,000 ÷ £150,000) × 100 = 30%. This means the business keeps 30p of every £1 of revenue after paying for the goods it sells."}, {"question": "Which of the following statements about net profit margin is correct?", "options": ["It equals gross profit divided by cost of sales × 100", "It is considered a more accurate measure of profitability than gross profit margin", "It always rises when revenue rises", "It is calculated before expenses are deducted"], "answer": 1, "explain": "Correct: NPM is considered more accurate because it accounts for ALL business costs — not just cost of sales. It shows how much net profit is generated per pound of revenue."}, {"question": "A business invests £20,000 in a machine. Over 4 years it earns total income of £36,000 from the investment. What is the ARR?", "options": ["20%", "25%", "80%", "45%"], "answer": 1, "explain": "Correct: Step 1: Total profit = £36,000 − £20,000 = £16,000. Step 2: Average annual profit = £16,000 ÷ 4 = £4,000. Step 3: ARR = (£4,000 ÷ £20,000) × 100 = 25%."}, {"question": "A business''s net profit margin falls from 18% to 12%. Which statement is correct?", "options": ["The business''s revenue has fallen by 6%", "Net profit has fallen by 33%", "The business is now making a loss", "For every £100 of sales, the business earns £6 less net profit"], "answer": 3, "explain": "Correct: A margin of 18% means £18 per £100 of sales. At 12% it is £12 per £100. The difference is £6 per £100 — the business earns £6 less net profit for every £100 of sales. The business is still profitable (not making a loss)."}, {"question": "Which of the following would MOST LIKELY improve a business''s gross profit margin?", "options": ["Taking out a larger bank loan", "Raising wages for all staff", "Negotiating lower prices from raw material suppliers", "Increasing rent on the factory"], "answer": 2, "explain": "Correct: Lower raw material costs reduce cost of sales. Since GPM = (Gross Profit ÷ Revenue) × 100 and Gross Profit = Revenue − Cost of Sales, lower cost of sales increases gross profit and therefore GPM."}, {"question": "Total costs for a business with fixed costs of £12,000 and variable costs of £5 per unit, producing 800 units, would be:", "options": ["£12,000", "£28,000", "£16,000", "£4,000"], "answer": 2, "explain": "Correct: TVC = 800 × £5 = £4,000. TC = TFC + TVC = £12,000 + £4,000 = £16,000."}, {"question": "ARR is most useful for a business because it:", "options": ["Shows the total income from an investment", "Allows comparison of the profitability of different investments over their lifetime", "Calculates how long until an investment pays for itself", "Shows the business''s annual revenue"], "answer": 1, "explain": "Correct: ARR allows a business to compare investments — e.g. Machine A vs Machine B — by expressing the average annual return as a percentage of the investment cost."}, {"question": "A business has total revenue of £200,000, cost of sales of £80,000, and expenses of £60,000. What is the net profit margin?", "options": ["30%", "20%", "40%", "60%"], "answer": 0, "explain": "Correct: Gross Profit = £200,000 − £80,000 = £120,000. Net Profit = £120,000 − £60,000 = £60,000. NPM = (£60,000 ÷ £200,000) × 100 = 30%."}, {"question": "Which of these would be a fixed cost for a pizza delivery business?", "options": ["Fuel for delivery vehicles", "Monthly lease on the delivery van", "Pizza dough and toppings", "Packaging boxes per pizza"], "answer": 1, "explain": "Correct: A monthly lease (like rent) does not change with the number of pizzas sold — it is fixed. Pizza ingredients, fuel, and packaging all change with output, making them variable costs."}, {"question": "When net profit stays the same but revenue doubles, what happens to the net profit margin?", "options": ["It stays the same", "It doubles", "It falls to zero", "It halves"], "answer": 3, "explain": "Correct: NPM = (Net Profit ÷ Revenue) × 100. If net profit is constant but revenue doubles, the margin halves. This is why businesses must watch profitability ratios, not just absolute profit figures."}]}, "fib": {"enabled": true, "questions": [{"text": "Revenue is calculated by multiplying [quantity sold] by [selling price]."}, {"text": "Costs that do NOT change when output changes are called [fixed] costs."}, {"text": "Costs that rise as production increases are called [variable] costs."}, {"text": "Gross Profit = Revenue minus [cost of sales]."}, {"text": "Net Profit = [gross profit] minus [expenses]."}, {"text": "The Gross Profit Margin formula is: (Gross Profit ÷ Revenue) × [100]."}, {"text": "The [net] profit margin is considered the more accurate measure of profitability."}, {"text": "When costs are greater than revenue, the business makes a [loss]."}, {"text": "Total Costs = Total [Fixed] Costs + Total [Variable] Costs."}, {"text": "In the ARR calculation, Step 3 is: (Average Annual [Profit] ÷ Cost of Investment) × 100."}, {"text": "In ARR, you first subtract the [cost of investment] from total income to find total profit."}, {"text": "Rent, business rates and insurance are all examples of [fixed] costs."}, {"text": "Raw materials and packaging are examples of [variable] costs because they change with output."}]}, "tf": {"enabled": true, "questions": [{"statement": "Fixed costs remain the same whether a business produces 0 or 1,000 units.", "answer": true, "explain": "TRUE. Fixed costs (e.g. rent, insurance) do not vary with output. They must be paid regardless of how much or how little the business produces."}, {"statement": "Gross profit is calculated by subtracting all business expenses from revenue.", "answer": false, "explain": "FALSE. Gross Profit = Revenue − Cost of Sales ONLY. Expenses are only deducted when calculating NET profit."}, {"statement": "A business with increasing revenue is always becoming more profitable.", "answer": false, "explain": "FALSE. Revenue can increase while costs rise faster, causing profit margins to fall. You must analyse profitability ratios, not just revenue figures."}, {"statement": "Net profit margin is considered a more accurate measure of performance than gross profit margin.", "answer": true, "explain": "TRUE. Net profit margin accounts for ALL running costs (wages, rent, utilities, insurance), giving a fuller picture of how efficiently the business generates profit."}, {"statement": "Raw materials used in manufacturing are a variable cost.", "answer": true, "explain": "TRUE. As more products are made, more raw materials are consumed. The cost rises directly with output — a classic variable cost."}, {"statement": "ARR is calculated by dividing total income by the cost of investment × 100.", "answer": false, "explain": "FALSE. ARR requires three steps. First: Total Profit = Total Income − Cost of Investment. Then: Average Annual Profit = Total Profit ÷ Years. Finally: ARR = (Average Annual Profit ÷ Cost of Investment) × 100. Using total income alone gives the wrong answer."}, {"statement": "A business that consistently makes losses will eventually be unable to continue operating.", "answer": true, "explain": "TRUE. If costs continually exceed revenue, the business depletes its cash and resources and will eventually be unable to pay its bills."}, {"statement": "Salaries paid to permanent staff are generally considered a variable cost.", "answer": false, "explain": "FALSE. Salaries are a fixed annual payment — they do not change with output levels. Hourly wages can be variable, but annual salaries are typically classified as fixed costs."}, {"statement": "If a business''s net profit margin falls from 10% to 8%, it means the business has made a loss.", "answer": false, "explain": "FALSE. A net profit margin of 8% still indicates a profit. The business has become less efficient (less profitable) but it is still making a positive net profit."}, {"statement": "ARR allows a business to compare two different investments and choose the one with the better return.", "answer": true, "explain": "TRUE. By expressing the average annual return as a percentage of cost, ARR provides a common basis for comparing different investment options."}, {"statement": "Increasing the selling price will always increase a business''s total revenue.", "answer": false, "explain": "FALSE. Revenue = Price × Quantity. If raising the price causes a significant fall in the quantity sold, total revenue could actually decrease. The impact depends on how price-sensitive demand is."}, {"statement": "Total Costs = Total Fixed Costs + Total Variable Costs.", "answer": true, "explain": "TRUE. Every cost a business incurs is either fixed or variable. Adding all fixed and variable costs together gives total costs."}]}, "misc": {"enabled": true, "items": [{"myth": "Revenue is the same as profit.", "truth": "Revenue is the total income from sales (quantity × price). Profit is what remains AFTER costs are deducted. A business can have high revenue but still make a loss if costs are even higher.", "check": {"question": "What is the correct relationship between revenue and profit?", "options": ["Revenue is always exactly equal to a business''s net profit figure", "Profit is calculated by adding all of a business''s costs to revenue", "Revenue and profit are simply two different names for the same figure", "Profit is what remains after all costs are deducted from revenue"], "answer": 3, "explain": "The card explains revenue is total income from sales, while profit is what remains after costs are deducted — a business can have high revenue but still make a loss."}}, {"myth": "If net profit in pounds increases, the net profit margin must also increase.", "truth": "Not necessarily. If revenue grows faster than net profit, the margin actually falls. For example: net profit stays at £30,000 but revenue doubles from £150,000 to £300,000 — the NPM halves from 20% to 10%.", "check": {"question": "Why can net profit margin fall even though net profit in pounds stays the same?", "options": ["If revenue grows faster than net profit, the margin actually falls", "Net profit margin cannot change unless net profit in pounds also changes", "Net profit margin always rises whenever net profit in pounds is unchanged", "Net profit margin depends only on cost of sales, not on revenue at all"], "answer": 0, "explain": "The card''s example shows net profit staying at £30,000 while revenue doubles, causing NPM to halve from 20% to 10% — margin depends on the relationship between profit and revenue."}}, {"myth": "All wages are variable costs.", "truth": "It depends on how workers are paid. Hourly wages that vary with output are variable. Annual salaries (a fixed payment) are a fixed cost. Examiners specifically do NOT accept ''salaries'' as a variable cost.", "check": {"question": "Which statement about wages and salaries does this card confirm is correct?", "options": ["Wages and salaries are both always classed as cost of sales figures", "Hourly wages that vary with output are variable costs, but salaries are fixed", "All forms of staff pay, including salaries, count as variable costs", "All forms of staff pay, including hourly wages, always count as fixed costs"], "answer": 1, "explain": "The card confirms hourly wages that vary with output are variable costs, while salaries (a fixed payment) are fixed costs — examiners do not accept salaries as variable."}}, {"myth": "In ARR, you divide total income by the cost of investment.", "truth": "You must first subtract the investment cost from total income to get total PROFIT, then divide by years for average annual profit, THEN divide by cost of investment × 100. Skipping step 1 is one of the most common exam errors.", "check": {"question": "What must be done before dividing by the cost of investment in an ARR calculation?", "options": ["Add the cost of investment straight onto the total income figure", "Multiply total income by the cost of investment directly and immediately", "Divide total income by the number of years invested immediately", "Subtract the investment cost from total income to find total profit first"], "answer": 3, "explain": "The card explains you must first subtract investment cost from income to get total profit, then divide by years, THEN divide by cost of investment — skipping step one is a common error."}}, {"myth": "Gross profit margin and net profit margin measure the same thing.", "truth": "GPM = (Gross Profit ÷ Revenue) × 100 — only deducts cost of sales. NPM = (Net Profit ÷ Revenue) × 100 — deducts ALL expenses too. NPM is always lower and is the more accurate measure.", "check": {"question": "What is the key difference between gross profit margin and net profit margin?", "options": ["NPM deducts all expenses too, while GPM only deducts cost of sales", "NPM is always higher than GPM because it excludes cost of sales entirely", "GPM and net profit margin are calculated using exactly the same formula", "GPM deducts all expenses, while NPM only deducts cost of sales figures"], "answer": 0, "explain": "The card explains GPM only deducts cost of sales, while NPM deducts all expenses too, making NPM always lower and the more accurate overall measure."}}, {"myth": "If costs increase, the business must be performing worse.", "truth": "Not necessarily. If revenue increases by MORE than the cost increase, profitability can actually improve. The key is the relationship between revenue and costs — measured by profit margins.", "check": {"question": "Why might a business still improve its profitability even if its costs increase?", "options": ["If revenue increases by more than the cost increase, profitability can improve", "Profitability can only ever improve when a business''s total costs actually fall", "Costs increasing always means a business is definitely performing worse", "Rising costs always cause both gross and net profit margins to rise too"], "answer": 0, "explain": "The card explains that if revenue rises by more than costs increase, profitability can still improve — the key is the relationship between revenue and costs, shown by profit margins."}}, {"myth": "Revenue and profit are interchangeable terms for ''money the business makes''.", "truth": "They are completely different. Revenue is total income from sales. Profit is what is left after ALL costs are paid. In an exam, mixing these up will cost you marks on every finance question.", "check": {"question": "Why are ''revenue'' and ''profit'' not interchangeable terms in a business context?", "options": ["Revenue is calculated after costs, while profit is calculated before costs", "Revenue is total income from sales, while profit is what remains after costs", "They both mean exactly the same thing — the total money a business makes", "Profit always refers to a much bigger number than revenue in any business"], "answer": 1, "explain": "The card stresses revenue is total income from sales, while profit is what remains after ALL costs are paid — mixing these up costs marks on finance questions."}}, {"myth": "A business that is ''profitable'' always has a positive cash flow.", "truth": "Profit and cash flow are different. A business can be profitable on paper but still run out of cash (e.g. if customers owe money that hasn''t been paid yet). This is a common real-world business failure.", "check": {"question": "Why can a profitable business still fail due to cash flow problems?", "options": ["A profitable business is legally guaranteed to always have enough cash", "Cash flow problems can only ever affect businesses that are making a loss", "A business can be profitable on paper but still run out of cash owed by customers", "Profit and cash flow always rise and fall together at precisely the same rate"], "answer": 2, "explain": "The card explains profit and cash flow are different — a business can be profitable on paper yet run out of cash if customers haven''t paid what they owe."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Stop. Move On.", "html": "<p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation, no examples, no paragraphs.</p>\n    <p><strong>The common trap:</strong> Writing too much and contradicting yourself, or naming a variable cost when asked for a fixed cost (or vice versa).</p>\n    <ul>\n    <li><strong>✅ Good (1 mark):</strong> <em>\"Rent\"</em> (in response to ''identify a fixed cost'')</li>\n    <li><strong>❌ Bad (0 marks):</strong> <em>\"Production costs\"</em> — too vague. Always name a specific cost.</li>\n    <li><strong>❌ Bad (0 marks):</strong> <em>\"Salaries\"</em> — in response to ''identify a variable cost''. Examiners specifically do NOT accept salaries as a variable cost.</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning:</strong> The word ''vary'' or ''variable'' cannot be used to define ''variable costs''. A derivative of the keyword appearing in the question gains no marks. Say what they ARE (costs that change with output), not what they''re called.</p>", "check": {"question": "Which answer would NOT be accepted if asked to ''identify a variable cost''?", "options": ["Raw materials, since usage increases as more units are made", "Wages, since hourly pay changes directly with the level of output produced", "Packaging, since more units produced requires more packaging used", "Salaries, since examiners specifically do not accept this as a variable cost"], "answer": 3, "explain": "The card states examiners specifically do NOT accept salaries as a variable cost, since a salary is a fixed annual payment rather than one that changes with output."}}, {"title": "State + Develop: The Two-Step Formula", "html": "<p>Every 2-mark ''Explain'' question needs two linked steps. State a point, then develop it with a ''because'' or ''this means'' or ''so that''.</p>\n    <p><strong>Formula: Point (K) → Development / So what? (U)</strong></p>\n    <ul>\n    <li><strong>❌ Bad (1 mark only):</strong> <em>\"Variable costs change when output changes.\"</em></li>\n    <li><strong>✅ Good (2 marks):</strong> <em>\"Variable costs change when output changes (K), which means if a business produces more units, it will spend more on raw materials and packaging (U).\"</em></li>\n    </ul>\n    <p>For ''Explain why profit is important'': identify a benefit (K) + explain how that benefit actually works for a business (U).</p>\n    <p><strong>✅ Example:</strong> <em>\"Profit can be reinvested in the business (K) to buy new equipment that increases production capacity and reduces costs in the long run (U).\"</em></p>\n    <p><strong>⚠️ Warning:</strong> Do NOT just write a definition when asked to ''explain why''. Definitions score only 1 mark. Always ask yourself: <em>so what? why does it matter?</em></p>", "check": {"question": "What must a 2-mark ''Explain'' answer include, beyond a simple definition?", "options": ["A full list of every possible cost a business could ever incur at all", "A development step showing ''so what'' or ''why it matters'' for the business", "A restatement of the original question using slightly different wording", "A second, completely unrelated definition of a totally different key term"], "answer": 1, "explain": "The card''s formula is Point (K) then Development (U) — a bare definition scores only 1 mark, so the answer must go on to explain ''so what'' or ''why it matters''."}}, {"title": "The U → APP → AN Chain: All Three or Zero", "html": "<p>A 3-mark Analyse question follows a strict chain. <strong>You cannot score Application or Analysis marks without first scoring Understanding.</strong></p>\n    <p><strong>Step 1 — Understanding (U):</strong> Show you understand the concept. What is it? What does it do?</p>\n    <p><strong>Step 2 — Application (APP):</strong> Link your point DIRECTLY to the business in the case study. Quote or reference specific data from the text. Phrases: <em>\"For ACG...\"</em> / <em>\"As the text states...\"</em> / <em>\"With net profit of £210,000 from £860,000 revenue...\"</em></p>\n    <p><strong>Step 3 — Analysis (AN):</strong> State the impact/effect on the business. Phrases: <em>\"This means...\"</em> / <em>\"As a result...\"</em> / <em>\"This will lead to...\"</em> / <em>\"This could cause...\"</em></p>\n    <p><strong>❌ Bad answer (1 mark):</strong> <em>\"Calculating the net profit margin is useful because it shows how profitable a business is.\"</em></p>\n    <p><strong>✅ Good answer (3 marks):</strong> <em>\"Net profit margin shows the percentage of revenue kept as net profit (U). For ACG, with net profit of £210,000 from £860,000 revenue (APP), this is 24.4%, allowing ACG to compare this year''s efficiency against previous years (AN), alerting them if the margin is falling even as profit in pounds appears to rise.\"</em></p>\n    <p><strong>🚫 No case study reference = maximum 2 marks.</strong> Always name the business and use its specific data.</p>", "check": {"question": "What is the maximum mark available if an analyse answer does not reference the case study?", "options": ["1 mark, since understanding alone is always enough for full credit", "3 marks, since analysis can still be scored without any application", "0 marks, since absolutely no marks can be given without application", "2 marks, since application requires naming the business and its data"], "answer": 3, "explain": "The card states no case study reference caps the answer at 2 marks maximum — you must name the business and use its specific data to access the application mark."}}, {"title": "Always Show Your Workings — Every Step Earns Marks", "html": "<p>Calculation questions award marks for the process, not just the answer. Even if your final number is wrong, correct working earns marks.</p>\n    <p><strong>Golden Rules:</strong></p>\n    <ul>\n    <li>Write the formula first: <em>NPM = (Net Profit ÷ Revenue) × 100</em></li>\n    <li>Substitute the numbers: <em>(£210,000 ÷ £860,000) × 100</em></li>\n    <li>Write the answer with units: <em>= 24.4%</em></li>\n    <li>Always include the % sign for margin and ARR answers</li>\n    </ul>\n    <p><strong>Most Common Calculation Mistakes:</strong></p>\n    <ul>\n    <li>❌ <strong>ARR:</strong> Dividing total income (not profit) by cost of investment. You MUST subtract the investment cost first.</li>\n    <li>❌ <strong>GPM / NPM:</strong> Using the wrong denominator — always divide by REVENUE, not by cost of sales or gross profit.</li>\n    <li>❌ <strong>Average Revenue:</strong> Using the wrong time period — re-read the question carefully for start and end dates.</li>\n    <li>❌ <strong>Percentage change:</strong> Dividing by the NEW value instead of the ORIGINAL value.</li>\n    </ul>\n    <p><strong>Percentage Change Formula: (Change ÷ Original Value) × 100</strong></p>\n    <p>⚠️ If an answer seems unrealistically large (e.g. £1600m), always re-check whether you accidentally multiplied instead of divided.</p>", "check": {"question": "According to this card, what is a common mistake when calculating GPM or NPM?", "options": ["Writing out the formula before substituting in the actual numbers", "Including a percentage sign at the very end of the final answer", "Using the wrong denominator instead of always dividing by revenue", "Showing each step of the calculation instead of just the final answer"], "answer": 2, "explain": "The card lists using the wrong denominator as a common mistake — GPM and NPM must always be divided by revenue, not by cost of sales or gross profit."}}, {"title": "Make a Clear Decision — Never Sit on the Fence", "html": "<p>A recommendation question requires a <strong>clear, committed judgement</strong>. Sitting on the fence scores zero evaluation marks.</p>\n    <p><strong>Three-Part Structure:</strong></p>\n    <ul>\n    <li><strong>Judgement (1 mark):</strong> State your recommendation clearly. <em>\"SP should buy HD Sewing.\"</em></li>\n    <li><strong>Justification (1 mark):</strong> Explain WHY using sound business reasoning.</li>\n    <li><strong>Context (1 mark):</strong> Support with specific data from the table or case study.</li>\n    </ul>\n    <p><strong>✅ Model Response:</strong><br>\n    <em>\"SP should buy Fast Stitch (JUDGEMENT) because Pippa stated she wants to see her investment returned within five years (CONTEXT), and Fast Stitch has a higher ARR of 13.8% compared to HD Sewing''s 11.25% (DATA), meaning it offers a better return on investment and is more likely to achieve Pippa''s goal (JUSTIFICATION).\"</em></p>\n    <p><strong>⚠️ Examiner Warning:</strong> \"It could go either way\" or \"both have advantages\" without a final decision = 0 marks for evaluation. You MUST commit. You can briefly acknowledge the other side, but always return to your chosen recommendation.</p>", "check": {"question": "What score does an answer get for evaluation if it doesn''t commit to a decision?", "options": ["Half marks, as long as the overall answer is a reasonable length", "One mark, provided that some numerical data is mentioned somewhere", "Zero evaluation marks, even if both sides are discussed in real detail", "Full marks, since discussing both sides shows a genuinely balanced judgement"], "answer": 2, "explain": "The card warns that saying ''it could go either way'' without a final decision scores zero evaluation marks — a clear, committed judgement is required."}}, {"title": "Impact on Profitability ≠ Impact on Profit", "html": "<p>When analysing profitability data, examiners look for the <strong>difference between profit (£ amount) and profitability (the ratio)</strong>. Many students confuse these.</p>\n    <p><strong>To show an impact on PROFITABILITY, the relationship between costs and revenue must change.</strong></p>\n    <p><strong>Three-Step Structure:</strong></p>\n    <ul>\n    <li><strong>Understanding (U):</strong> <em>\"CFM''s gross profit margin rose from 60% in Year 1 to 70% in Year 2.\"</em></li>\n    <li><strong>Application (APP):</strong> <em>\"This means CFM retained 70p of every £1 of revenue after paying for its food supplies in Year 2, compared to 60p in Year 1.\"</em></li>\n    <li><strong>Analysis (AN):</strong> <em>\"This improvement shows CFM is becoming more efficient at generating profit from its sales — the business could use this improved margin to fund the new café from retained profit rather than borrowing.\"</em></li>\n    </ul>\n    <p><strong>❌ Common mistake:</strong> Saying <em>\"the business''s profit will increase\"</em> when asked about profitability. Always discuss the RATIO and what it means for efficiency, not just the pound figure.</p>\n    <p><strong>Sentence starters for AN marks:</strong> <em>\"This means the business is becoming more/less efficient at...\"</em> / <em>\"As a result, the business generates more/less profit per pound of revenue...\"</em></p>", "check": {"question": "What mistake do many students make when asked about a change in profitability?", "options": ["They avoid mentioning either profit or profitability in their answer", "They discuss the ratio rather than the pound figure for profit itself", "They discuss the change in profit rather than the change in the ratio", "They correctly discuss both the ratio and the pound figure together"], "answer": 2, "explain": "The card warns students often say ''profit will increase'' when asked about profitability — the answer must discuss the ratio and what it means for efficiency, not the pound figure."}}]}, "exam": {"enabled": true, "questions": [{"question": "The business made a net profit of: [1 mark]", "marks": 1, "hint": "First calculate revenue (quantity × price), then subtract total costs to find profit.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — £3 million</h5><ul><li><strong>Working:</strong> Revenue = 22m × £0.75 = £16.5m. Net profit = £16.5m − £13.5m = £3m.</li><li><strong>Why B is wrong:</strong> £16.5m is the revenue figure, not the profit — costs have not been subtracted.</li><li><strong>Why C is wrong:</strong> No valid calculation produces this figure — a common error from multiplying rather than subtracting.</li><li><strong>Why D is wrong:</strong> £1,650m incorrectly treats both figures as millions and adds them rather than subtracting.</li></ul></div>"}, {"question": "Which would be variable costs for a building firm? [1 mark]", "marks": 1, "hint": "Variable costs change with output — think about what the building firm uses MORE of when it builds more houses.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Bricks and roof tiles</h5><ul><li><strong>Why B is correct:</strong> Bricks and roof tiles are raw materials — the more buildings the firm constructs, the more materials it uses. They change directly with output.</li><li><strong>Why A is wrong:</strong> Administrative and legal expenses are largely fixed — they don''t change significantly with the number of buildings constructed.</li><li><strong>Why C is wrong:</strong> Business rates and buildings insurance are fixed costs — paid regardless of output.</li><li><strong>Why D is wrong:</strong> Cement mixers and tools are capital equipment — a one-off fixed cost, not a variable cost.</li></ul></div>"}, {"question": "This means that: [1 mark]", "marks": 1, "hint": "A net profit margin of 4.2% means £4.20 per £100 of sales. A margin of 2.9% means £2.90 per £100. What is the difference?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — every £100 of sales earns £1.30 less net profit than it used to</h5><ul><li><strong>Why A is correct:</strong> 4.2% means £4.20 per £100. 2.9% means £2.90 per £100. The difference is £1.30 per £100 of sales.</li><li><strong>Why B is wrong:</strong> The company earns £2.90 per £100 (the current margin), not £1.30. B confuses the margin difference with the current margin.</li><li><strong>Why C is wrong:</strong> Net profit LEVELS (the £ amount) have not necessarily fallen by 1.3% — the MARGIN has fallen by 1.3 percentage points. These are different things.</li><li><strong>Why D is wrong:</strong> A margin of 2.9% still means a positive profit. The company is less profitable but is NOT making a loss.</li></ul><p><strong>Examiner''s Comment:</strong> This was the least well-answered question in the paper. Many students chose C, confusing a fall in the margin with a fall in the actual profit level.</p></div>"}, {"question": "The percentage change in the company''s total costs from 2020 to 2023 was: [1 mark]", "marks": 1, "hint": "First calculate total costs in 2020 and 2023 by adding operating + other costs. Then use the percentage change formula: (change ÷ original) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 50%</h5><ul><li><strong>Working:</strong> 2020 total = £200,000 + £40,000 = £240,000. 2023 total = £320,000 + £40,000 = £360,000. Change = £120,000. % change = (£120,000 ÷ £240,000) × 100 = 50%.</li><li><strong>Why A is wrong:</strong> 33% comes from dividing the change by the wrong denominator.</li><li><strong>Why B is wrong:</strong> 37.5% may come from comparing operating costs alone or using incorrect figures.</li><li><strong>Why D is wrong:</strong> 60% is produced by dividing by the new (2023) total rather than the original (2020) total — always use the original as the denominator.</li></ul></div>"}, {"question": "The market trader''s gross profit margin was approximately: [1 mark]", "marks": 1, "hint": "First calculate gross profit (selling price minus cost price), then express it as a percentage of the selling price (revenue).", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 63%</h5><ul><li><strong>Working:</strong> Gross profit = £12,500 − £4,600 = £7,900. GPM = (£7,900 ÷ £12,500) × 100 = 63.2% ≈ 63%.</li><li><strong>Why A is wrong:</strong> 37% is the cost of sales as a percentage of revenue (£4,600 ÷ £12,500), not the gross profit margin.</li><li><strong>Why C is wrong:</strong> 79% incorrectly divides gross profit by cost of sales instead of revenue.</li><li><strong>Why D is wrong:</strong> 172% is produced by dividing selling price by cost, which is not a margin calculation.</li></ul><p><strong>Examiner''s Comment:</strong> Under 40% of candidates got this right. The most common mistake was not calculating gross profit first, and just dividing figures directly.</p></div>"}, {"question": "Over the first three years of trading, the entrepreneur should expect to make: [1 mark]", "marks": 1, "hint": "ARR = (Average Annual Profit ÷ Cost of Investment) × 100. Rearrange to find average annual profit, then multiply by 3 years for the total.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — profits totalling £45,000</h5><ul><li><strong>Working:</strong> ARR 10% of £150,000 = £15,000 average profit per year. Over 3 years: £15,000 × 3 = £45,000 total profit.</li><li><strong>Why A is wrong:</strong> £45,000 per year would be the total profit spread wrongly — that would imply an ARR of 30% per year, not 10%.</li><li><strong>Why B is wrong:</strong> £135,000 per year represents 90% ARR — far too high and comes from multiplying the investment by the years and the rate incorrectly.</li><li><strong>Why C is wrong:</strong> £15,000 is the average ANNUAL profit, not the total profit over 3 years.</li></ul><p><strong>Examiner''s Comment:</strong> Only half of candidates identified D. Many chose A, suggesting they did not read carefully — £45,000 is the total over 3 years, not per year.</p></div>"}, {"question": "Which of the following would be fixed costs of a fruit farm? [1 mark]", "marks": 1, "hint": "Fixed costs don''t change with how much fruit is grown. Which of these stays the same regardless of harvest size?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Rent and rates</h5><ul><li><strong>Why C is correct:</strong> Rent and rates are paid regardless of how much fruit is grown. They are fixed costs.</li><li><strong>Why A is wrong:</strong> Farm workers'' wages are variable — more workers (or more hours) are needed during harvest seasons when output is higher.</li><li><strong>Why B is wrong:</strong> Plant food and fertiliser change with the amount of crop being grown — a variable cost.</li><li><strong>Why D is wrong:</strong> Seeds and seedlings are variable — more seeds are used when planting more crops.</li></ul></div>"}, {"question": "The entrepreneur''s average rate of return is: [1 mark]", "marks": 1, "hint": "ARR = (Average Annual Profit ÷ Cost of Investment) × 100. You already have the average annual profit — just plug it in.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 26.5%</h5><ul><li><strong>Working:</strong> ARR = (£53,000 ÷ £200,000) × 100 = 26.5%.</li><li><strong>Why A is wrong:</strong> 6.6% would come from incorrectly dividing £200,000 by £53,000 × something.</li><li><strong>Why C is wrong:</strong> 73.5% incorrectly calculates the proportion of investment NOT returned (100% − 26.5%).</li><li><strong>Why D is wrong:</strong> 106% would mean the total profit over all years exceeded the original investment, not the annual average rate.</li></ul></div>"}, {"question": "Which of the following would help Emma and Henry deal with this problem? [1 mark]", "marks": 1, "hint": "The problem is paying expenses (a cash flow problem), not a profit problem. Which option injects cash into the business without increasing costs?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Taking on a new partner</h5><ul><li><strong>Why D is correct:</strong> A new partner brings capital (money) into the business, which directly addresses the problem of not being able to pay expenses.</li><li><strong>Why A is wrong:</strong> Holding larger stocks ties up cash, making the cash flow problem worse, not better.</li><li><strong>Why B is wrong:</strong> Increasing wages increases costs and makes the problem worse.</li><li><strong>Why C is wrong:</strong> A partnership cannot issue shares — only limited companies can do this.</li></ul></div>"}, {"question": "Pilti plc''s gross profit in 2022 was: [1 mark]", "marks": 1, "hint": "Net profit = Gross profit − Expenses. Rearrange: Gross profit = Net profit + Expenses.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £26 million</h5><ul><li><strong>Working:</strong> Net profit = Gross profit − Expenses → Gross profit = Net profit + Expenses = £14m + £12m = £26m.</li><li><strong>Why A is wrong:</strong> £18m comes from subtracting expenses from net profit rather than adding them.</li><li><strong>Why C is wrong:</strong> £32m comes from subtracting net profit from revenue (Revenue − Net profit), which is not a standard formula.</li><li><strong>Why D is wrong:</strong> £58m adds revenue and net profit, which has no financial meaning.</li></ul><p><strong>Examiner''s Comment:</strong> Less than 1 in 5 candidates got this right. The key rearrangement is: Gross Profit = Net Profit + Expenses.</p></div>"}, {"question": "The lowest cost that Riley can obtain 1200 litres of cleaning fluid from one supplier is: [1 mark]", "marks": 1, "hint": "You must get AT LEAST 1200 litres from ONE supplier only. Work out the cost of getting 1200L from each supplier.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £600</h5><ul><li><strong>Working:</strong> Supplier 2 sells 200L barrels at £100 each. 1200L ÷ 200L = 6 barrels. Cost = 6 × £100 = £600.</li><li><strong>Why A is wrong:</strong> £480 is not achievable from any single supplier for 1200L. Supplier 1 sells 100L at £80 = £0.80/L, but 12 × £80 = £960.</li><li><strong>Why C is wrong:</strong> £700 is not achievable from any one supplier for exactly 1200L.</li><li><strong>Why D is wrong:</strong> £800 is what Supplier 4 charges for 2000L — more expensive than Supplier 2 for 1200L.</li></ul><p><strong>Examiner''s Comment:</strong> Around half got this right. Key insight: Supplier 3 sells 1000L for £600 but that is only 1000L, not enough. Supplier 2 provides exactly 1200L for £600.</p></div>"}, {"question": "Which of the following must be true for this business? [1 mark]", "marks": 1, "hint": "The margin went from 6% to 9% — that is an increase of 3 percentage points. Think about what 3 extra percentage points means as a percentage change FROM 6%.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Profitability has increased by 50%</h5><ul><li><strong>Working:</strong> Percentage change in profitability = (3 ÷ 6) × 100 = 50%. The margin increased from 6% to 9% — an increase of 50% relative to the starting margin of 6%.</li><li><strong>Why A is wrong:</strong> There is no information to say expenses have fallen. Even if they have, we cannot confirm by exactly 50%.</li><li><strong>Why B is wrong:</strong> Net profit (the £ figure) has not necessarily increased by 3%. The MARGIN has risen by 3 percentage points — the actual profit change depends on revenue levels too.</li><li><strong>Why D is wrong:</strong> Revenue could have risen, fallen, or stayed the same — we cannot determine this from margin data alone.</li></ul><p><strong>Examiner''s Comment:</strong> The least well-answered MCQ. B was the most common wrong answer — students confused ''net profit'' with ''net profit margin''.</p></div>"}, {"question": "This data is useful to Amir when making this pricing decision because it shows that: [1 mark]", "marks": 1, "hint": "Calculate total revenue at each price point (price × quantity) and see which price gives the highest revenue.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — reducing the price charged for each loaf is likely to increase total revenue</h5><ul><li><strong>Working:</strong> £1.50 × 350 = £525 | £1.75 × 250 = £437.50 | £2.00 × 150 = £300 | £2.25 × 50 = £112.50. The lowest price (£1.50) produces the highest revenue.</li><li><strong>Why A is wrong:</strong> The data shows clearly that price changes have a significant effect on revenue — from £525 down to £112.50.</li><li><strong>Why B is wrong:</strong> The highest price (£2.25) produces the lowest revenue of only £112.50.</li><li><strong>Why D is wrong:</strong> The current price of £2.00 gives revenue of only £300 — lower than £1.50 would deliver.</li></ul></div>"}, {"question": "Pallin Ltd''s average level of profit over the last five years is: [1 mark]", "marks": 1, "hint": "Add all five profit figures (including the negative ones/losses) and divide by 5.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — £4,000 per year</h5><ul><li><strong>Working:</strong> Total = £15,000 + 0 + (−£9,000) + £17,000 + (−£3,000) = £20,000. Average = £20,000 ÷ 5 = £4,000 per year.</li><li><strong>Why B is wrong:</strong> £5,000 may come from summing only the profitable years or using incorrect figures.</li><li><strong>Why C is wrong:</strong> £6,400 may result from ignoring the loss years entirely.</li><li><strong>Why D is wrong:</strong> £8,000 comes from summing all positive figures and dividing by 2 profitable years only, rather than all 5 years.</li></ul></div>"}, {"question": "This means: [1 mark]", "marks": 1, "hint": "A GPM of 50% means gross profit is 50% of revenue. If selling price is double the cost price, what is the gross profit as a percentage of sales?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — the shop charges customers double what it pays when buying the perfume</h5><ul><li><strong>Why C is correct:</strong> GPM = 50% means cost of sales = 50% of revenue. If selling price is £10 and cost of sales is £5 (50%), the shop charges double what it pays. Gross profit = £5, which is 50% of £10 revenue.</li><li><strong>Why A is wrong:</strong> GPM is gross profit — it does NOT account for all costs. After all costs, the NET profit margin applies. £5 after ALL costs would require a net profit margin of 50%.</li><li><strong>Why B is wrong:</strong> There is no relationship between GPM and the ratio of variable to fixed costs.</li><li><strong>Why D is wrong:</strong> If GPM = 50% and profit = £10, revenue needed = £10 ÷ 0.50 = £20, not £50.</li></ul><p><strong>Examiner''s Comment:</strong> This was the least well-answered question in Section A. A was the most popular wrong answer — students confused gross profit (before expenses) with net profit (after all costs).</p></div>"}, {"question": "The manufacturer''s estimated total cost for the year is: [1 mark]", "marks": 1, "hint": "Convert all costs to annual figures: raw materials × 500 kits; rent × 12 months; heating × 4 quarters; other expenses are already annual.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £86,800</h5><ul><li><strong>Working:</strong> Variable: 500 × £40 = £20,000. Fixed: rent = £600 × 12 = £7,200; heating = £900 × 4 = £3,600; other = £56,000. Fixed total = £66,800. TC = £20,000 + £66,800 = £86,800.</li><li><strong>Why A is wrong:</strong> £66,840 might come from using only part of the fixed costs or miscalculating heating/rent periods.</li><li><strong>Why B is wrong:</strong> £77,500 comes from miscalculating one or more of the cost components.</li><li><strong>Why C is wrong:</strong> £85,900 may come from a small arithmetic error in one category.</li></ul></div>"}, {"question": "Which of the following would be a variable cost for a restaurant? [1 mark]", "marks": 1, "hint": "Variable costs change with how much the restaurant produces (serves). Which item changes with the number of meals prepared?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Fruit and vegetables</h5><ul><li><strong>Why D is correct:</strong> Fruit and vegetables are raw materials (ingredients). The more meals served, the more ingredients are needed — a classic variable cost.</li><li><strong>Why A is wrong:</strong> Advertising fees are typically fixed (contracted or decided in advance) — they don''t change with the number of meals served.</li><li><strong>Why B is wrong:</strong> Buildings insurance is a fixed cost — it doesn''t change with output.</li><li><strong>Why C is wrong:</strong> The chef''s salary is a fixed annual payment — not variable. (If the chef were paid per meal cooked, it would be variable.)</li></ul></div>"}, {"question": "Tictal Ltd''s gross profit margin in 2020 was: [1 mark]", "marks": 1, "hint": "First calculate gross profit (Revenue − Cost of Sales), then divide by Revenue and multiply by 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 75%</h5><ul><li><strong>Working:</strong> Gross profit = £180,000 − £45,000 = £135,000. GPM = (£135,000 ÷ £180,000) × 100 = 75%.</li><li><strong>Why A is wrong:</strong> 25% is the cost of sales as a percentage of revenue (£45,000 ÷ £180,000 × 100), not the gross profit margin.</li><li><strong>Why B is wrong:</strong> 45% may come from incorrectly using net profit (revenue − cost of sales − expenses) and dividing by a wrong figure.</li><li><strong>Why C is wrong:</strong> 55% may come from subtracting both cost of sales and expenses from revenue before calculating the margin.</li></ul></div>"}, {"question": "Assuming the forecasted figures are correct, the average rate of return for this upgrade will be: [1 mark]", "marks": 1, "hint": "Step 1: Total income = 2 × £60,000. Step 2: Total profit = Total income − Cost of investment. Step 3: Average annual profit ÷ cost of investment × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 50%</h5><ul><li><strong>Working:</strong> Total income = 2 × £60,000 = £120,000. Total profit = £120,000 − £60,000 = £60,000. Average annual profit = £60,000 ÷ 2 = £30,000. ARR = (£30,000 ÷ £60,000) × 100 = 50%.</li><li><strong>Why A is wrong:</strong> 33% may come from dividing by 3 years incorrectly.</li><li><strong>Why C is wrong:</strong> 67% may come from miscalculating the profit or average.</li><li><strong>Why D is wrong:</strong> 100% would come from ignoring Step 1 (not subtracting cost) and just dividing total income by cost.</li></ul></div>"}, {"question": "What percentage reduction in transport costs has Shanco plc achieved? [1 mark]", "marks": 1, "hint": "Percentage change = (Change ÷ Original) × 100. The original is the 2019 figure.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 14.3%</h5><ul><li><strong>Working:</strong> Change = £0.7m − £0.6m = £0.1m. % change = (£0.1m ÷ £0.7m) × 100 = 14.3%.</li><li><strong>Why A is wrong:</strong> 6% has no clear derivation from the given figures.</li><li><strong>Why B is wrong:</strong> 7% is not achieved by any correct method.</li><li><strong>Why D is wrong:</strong> 16.7% comes from dividing by the NEW value (£0.6m) instead of the ORIGINAL value (£0.7m) — always use the original as the denominator.</li></ul></div>"}, {"question": "The company''s labour costs in 2019 were: [1 mark]", "marks": 1, "hint": "Labour costs = 40% of total costs. Calculate 40% of £9 million.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — £3.6 million</h5><ul><li><strong>Working:</strong> 40% × £9m = 0.40 × £9m = £3.6 million.</li><li><strong>Why B is wrong:</strong> £5.4m is 60% of £9m — the proportion that is NOT labour costs.</li><li><strong>Why C is wrong:</strong> £12.6m incorrectly adds 40% to £9m instead of finding 40% of £9m.</li><li><strong>Why D is wrong:</strong> £14.4m comes from multiplying £9m by 1.6 rather than 0.4.</li></ul></div>"}, {"question": "Variable costs: [1 mark]", "marks": 1, "hint": "Think about what happens to a manufacturer''s raw material costs when they produce twice as many products.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — increase as output rises</h5><ul><li><strong>Why C is correct:</strong> Variable costs (e.g. raw materials, packaging) increase directly as more is produced — more output requires more inputs.</li><li><strong>Why A is wrong:</strong> That describes fixed costs, not variable costs.</li><li><strong>Why B is wrong:</strong> Variable costs do not fall as output rises — they increase.</li><li><strong>Why D is wrong:</strong> Remaining constant describes fixed costs.</li></ul></div>"}, {"question": "The expected average rate of return for this purchase is: [1 mark]", "marks": 1, "hint": "Step 1: Total income = £9,000. Total profit = £9,000 − £6,000 = £3,000. Step 2: Average annual profit = £3,000 ÷ 3. Step 3: ARR = (average annual profit ÷ £6,000) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 16.67%</h5><ul><li><strong>Working:</strong> Total income = £9,000. Total profit = £9,000 − £6,000 = £3,000. Average annual profit = £3,000 ÷ 3 = £1,000. ARR = (£1,000 ÷ £6,000) × 100 = 16.67%.</li><li><strong>Why A is wrong:</strong> £1,000 is the average annual profit — the number used IN the ARR calculation, not the ARR itself.</li><li><strong>Why B is wrong:</strong> £3,000 is total profit, not ARR.</li><li><strong>Why D is wrong:</strong> 33.33% comes from dividing total profit by cost (£3,000 ÷ £6,000 × 100) — skipping Step 2 (averaging over the years).</li></ul></div>"}, {"question": "If Andrea paints and sells 50 portraits a year, total costs are estimated to be: [1 mark]", "marks": 1, "hint": "Variable cost per portrait = £52 + £23 = £75. Total variable costs = 50 × £75. Fixed costs = £1,000 × 12 months. Add both.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £15,750 per year</h5><ul><li><strong>Working:</strong> VC per portrait = £52 + £23 = £75. TVC = 50 × £75 = £3,750. Fixed costs = £1,000 × 12 months = £12,000. TC = £3,750 + £12,000 = £15,750.</li><li><strong>Why A is wrong:</strong> £1,075 ignores most costs — possibly just adding £52 + £23 = £75 then adding £1,000 once.</li><li><strong>Why B is wrong:</strong> £4,750 is the variable costs only (£3,750) plus one month''s fixed costs (£1,000).</li><li><strong>Why C is wrong:</strong> £12,075 is the annual fixed costs (£12,000) plus only one portrait''s variable costs (£75).</li></ul></div>"}, {"question": "This data is useful to Seiji when making business decisions because it shows that: [1 mark]", "marks": 1, "hint": "Add up all three cost rows for each year and compare. Which statement can definitely be proven from this data?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — total costs are increasing</h5><ul><li><strong>Working:</strong> 2015: £98,000. 2016: £126,000. 2017: £131,000. 2018: £134,000. Total costs are clearly rising year on year.</li><li><strong>Why A is wrong:</strong> Labour costs are NOT increasing every year — they rose from 2015 to 2016 but then fell in 2017 and 2018.</li><li><strong>Why B is wrong:</strong> We have no revenue data, so we cannot determine whether profit levels are falling.</li><li><strong>Why C is wrong:</strong> We cannot determine output levels from cost data alone.</li></ul></div>"}, {"question": "Assuming the forecasted figures are correct, the average rate of return for upgrading the robotics will be: [1 mark]", "marks": 1, "hint": "Step 1: Total income = 5 × £1m. Total profit = total income − cost. Step 2: Average annual profit ÷ 5. Step 3: ARR = (average annual profit ÷ £4m) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — 5%</h5><ul><li><strong>Working:</strong> Total income = 5 × £1m = £5m. Total profit = £5m − £4m = £1m. Average annual profit = £1m ÷ 5 = £0.2m. ARR = (£0.2m ÷ £4m) × 100 = 5%.</li><li><strong>Why B is wrong:</strong> 20% skips Step 2 — dividing £1m (total profit) by £4m gives 25%, not 20%.</li><li><strong>Why C is wrong:</strong> 25% comes from dividing total profit (£1m) by cost (£4m) without dividing by years first.</li><li><strong>Why D is wrong:</strong> 125% comes from total income (£5m) ÷ cost (£4m) × 100 — ignoring the need to subtract cost first.</li></ul></div>"}, {"question": "The agency''s percentage increase in spending on digital communications from 2017 to 2018 was approximately equal to: [1 mark]", "marks": 1, "hint": "Percentage change = (Change ÷ Original) × 100. The 2017 figure is the original. The figures have more than doubled, so the answer must be over 100%.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 110%</h5><ul><li><strong>Working:</strong> Change = £525,000 − £250,000 = £275,000. % change = (£275,000 ÷ £250,000) × 100 = 110%.</li><li><strong>Why A is wrong:</strong> 48% comes from dividing by the NEW value (£525,000): 275/525 × 100 ≈ 52%. Not 48%.</li><li><strong>Why B is wrong:</strong> 52% comes from (£275,000 ÷ £525,000) × 100 — using the new figure as denominator instead of the original.</li><li><strong>Why D is wrong:</strong> 210% comes from (£525,000 ÷ £250,000) × 100 — this is the new value as a % of old, not the % CHANGE.</li></ul><p><strong>Examiner''s Comment:</strong> This had the most incorrect answers of all MCQs. Key rule: always divide by the ORIGINAL value for percentage change. Since spending more than doubled, the answer must exceed 100%.</p></div>"}, {"question": "What was the market stall''s revenue? [1 mark]", "marks": 1, "hint": "Calculate revenue for bread and cookies separately, then add them together.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £2,200</h5><ul><li><strong>Working:</strong> Bread: 1,000 × £1 = £1,000. Cookies: 2,000 × £0.60 = £1,200. Total = £1,000 + £1,200 = £2,200.</li><li><strong>Why A is wrong:</strong> £200 is not achievable from any correct calculation with these figures.</li><li><strong>Why B is wrong:</strong> £1,000 is bread revenue only — cookies have been ignored.</li><li><strong>Why C is wrong:</strong> £1,200 is cookie revenue only — bread has been ignored.</li></ul></div>"}, {"question": "Gross profit margin is: [1 mark]", "marks": 1, "hint": "GPM measures the percentage of revenue kept as gross profit. Which category does this type of calculation belong to?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — a financial ratio</h5><ul><li><strong>Why B is correct:</strong> GPM is a profitability ratio — a calculation that expresses one financial figure as a percentage of another (gross profit as a % of revenue).</li><li><strong>Why A is wrong:</strong> A computerised method of production is something like an automated assembly line — completely unrelated to financial performance.</li><li><strong>Why C is wrong:</strong> A pricing method (e.g. cost-plus pricing, penetration pricing) is how a business sets its selling price — not a measure of profitability.</li><li><strong>Why D is wrong:</strong> Variable costs are costs that change with output — not a financial ratio.</li></ul></div>"}, {"question": "Which one of the following must be true for this business? [1 mark]", "marks": 1, "hint": "A positive net profit margin (8%) means the business is making a profit. What does profit mean for the relationship between revenue and costs?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — The business has revenues that are greater than its costs</h5><ul><li><strong>Why C is correct:</strong> Net profit margin of 8% means net profit is positive. Net Profit = Revenue − Total Costs > 0, therefore Revenue > Total Costs.</li><li><strong>Why A is wrong:</strong> Profit and cash flow are different. A profitable business can still have cash flow problems — but we cannot determine this from profit margin alone.</li><li><strong>Why B is wrong:</strong> A positive net profit margin means a profit, not a loss.</li><li><strong>Why D is wrong:</strong> If the business is above break-even, it is making a profit. An 8% NPM confirms it is above break-even.</li></ul></div>"}, {"question": "What is the approximate increase between 2015 and 2016 in Jimco plc''s production costs? [1 mark]", "marks": 1, "hint": "% change = (change ÷ original) × 100. Change = £22.9m − £21.3m = £1.6m. Original = £21.3m.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 7.5%</h5><ul><li><strong>Working:</strong> Change = £22.9m − £21.3m = £1.6m. % change = (£1.6m ÷ £21.3m) × 100 ≈ 7.5%.</li><li><strong>Why A is wrong:</strong> 0.9% has no logical derivation from these figures.</li><li><strong>Why B is wrong:</strong> 1.6% confuses the absolute change (£1.6m) with the percentage change — these are different things.</li><li><strong>Why C is wrong:</strong> 7.0% may come from rounding errors or using a slightly different denominator.</li></ul></div>"}, {"question": "In 2018 Pluck and Grow Ltd made: [1 mark]", "marks": 1, "hint": "Add up all three cost categories to find total costs, then subtract from revenue. If positive = profit, if negative = loss.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — a profit of £16,000</h5><ul><li><strong>Working:</strong> Total costs = £26,000 + £16,000 + £10,000 = £52,000. Profit = £68,000 − £52,000 = £16,000.</li><li><strong>Why A is wrong:</strong> A loss of £52,000 uses total costs as the answer — forgetting to subtract from revenue.</li><li><strong>Why B is wrong:</strong> A loss of £42,000 has no logical derivation from these figures.</li><li><strong>Why D is wrong:</strong> A profit of £26,000 uses only labour costs rather than all three cost types.</li></ul></div>"}, {"question": "The data shows that: [1 mark]", "marks": 1, "hint": "Add all three transport modes for 2018 to test option C. Check the other options against the data.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — GLU plc spent more than £1.25 million on transport costs in 2018</h5><ul><li><strong>Working:</strong> 2018 total = £190,000 + £430,000 + £650,000 = £1,270,000 &gt; £1,250,000. ✓</li><li><strong>Why A is wrong:</strong> The data shows costs, not preference. Highest cost could mean they are forced to use air, not that they prefer it. No preference data is given.</li><li><strong>Why B is wrong:</strong> All three transport modes show rising costs year on year, not falling.</li><li><strong>Why D is wrong:</strong> The data shows the COST of transport, not the quantity of goods. Higher cost per rail doesn''t mean more goods are transported by rail.</li></ul></div>"}, {"question": "What was Exobike''s gross profit margin? [1 mark]", "marks": 1, "hint": "First calculate total revenue (42 × £350). Then GPM = (Gross Profit ÷ Revenue) × 100. The answer must be a percentage.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — 68%</h5><ul><li><strong>Working:</strong> Revenue = 42 × £350 = £14,700. GPM = (£9,996 ÷ £14,700) × 100 ≈ 68%.</li><li><strong>Why B is wrong:</strong> 147% would only be possible if gross profit exceeded revenue — impossible.</li><li><strong>Why C is wrong:</strong> £4,704 is the cost of sales (£14,700 − £9,996) — not a gross profit margin.</li><li><strong>Why D is wrong:</strong> £14,700 is the total revenue — not a gross profit margin.</li></ul><p><strong>Examiner''s Comment:</strong> Students who knew a GPM must be a percentage could immediately eliminate C and D. Only A and B are percentages, and 147% exceeding 100% for a GPM is unrealistic.</p></div>"}, {"question": "Calculate Unilever plc''s average revenue from 2019 to 2022. [2 marks]", "marks": 2, "hint": "Add the four revenue figures from 2019, 2020, 2021 and 2022 — NOT 2018 — then divide by 4.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5><ul><li><strong>2 marks:</strong> Correct answer of €53,750m (with or without workings).</li><li><strong>1 mark:</strong> Correct method shown (adding 2019–2022 figures and dividing by 4) but arithmetic error in final answer.</li><li><strong>0 marks:</strong> Using all five years (2018–2022) or calculating difference rather than average.</li></ul><p><strong>Working:</strong> 51,900 + 50,700 + 52,400 + 60,000 = 215,000m. Average = 215,000 ÷ 4 = €53,750m.</p><p><strong>Examiner''s Comment:</strong> Less than half of candidates scored full marks. Most common mistake: using all five figures from 2018–2022 instead of the four from 2019–2022.</p></div>"}, {"question": "Explain one way revenue affects a business'' decision making. [2 marks]", "marks": 2, "hint": "Think of a specific business decision (pricing, expansion, product development) and explain HOW revenue data informs that decision.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b)</h5><ul><li><strong>1 mark:</strong> Identifying a specific way revenue affects decision making (e.g. pricing decisions, expansion, new products, reducing costs).</li><li><strong>1 further mark:</strong> Explaining HOW revenue data leads to that decision.</li><li><strong>Note:</strong> Answers do not need to relate to Unilever. No reward for a definition of revenue only.</li></ul><p><strong>Acceptable answers include:</strong></p><ul><li>Pricing decisions — if revenue is low, consider raising/lowering prices.</li><li>Expansion decisions — high revenue may justify opening new stores.</li><li>Product development — revenue data guides which products to invest in.</li><li>Cost management — low revenue signals the need to reduce costs.</li></ul><p><strong>Examiner''s Comment:</strong> Most candidates scored at least 1 mark. A common weakness was not specifying a decision — just saying ''revenue helps make decisions'' without explaining how.</p></div>"}, {"question": "Explain why profit is important to a business'' future. [2 marks]", "marks": 2, "hint": "Think of a specific benefit that profit enables a business to do — reinvest, expand, reward owners. Then explain WHY that benefit matters.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a + AO1b)</h5><ul><li><strong>1 mark:</strong> Identifying a specific reason why profit is important.</li><li><strong>1 further mark:</strong> Explaining HOW or WHY that benefit matters to the business.</li><li><strong>No reward for:</strong> a definition of profit, or answers purely about survival.</li></ul><p><strong>Acceptable answers include:</strong></p><ul><li>To reinvest in new equipment (K) — allowing the business to improve productivity/reduce costs over time (U).</li><li>To fund expansion (K) — allowing the business to grow and increase future revenue (U).</li><li>To pay dividends (K) — keeping shareholders satisfied so they do not sell their shares (U).</li><li>To repay loans (K) — reducing interest costs and improving the business''s financial position (U).</li><li>To develop new products (K) — allowing the business to compete with rivals and maintain market share (U).</li></ul><p><strong>Examiner''s Comment:</strong> Most students identified one reason but many failed to develop it with a clear explanation of why it matters.</p></div>"}, {"question": "Calculate the daily break-even quantity for the proposed hotel. [3 marks]", "marks": 3, "hint": "Break-even = Fixed Costs ÷ Contribution per unit. Contribution = Selling Price − Variable Cost. Fixed costs are given weekly — convert to daily by dividing by 7.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2)</h5><ul><li><strong>1 mark:</strong> Correct contribution calculation: £100 − £40 = £60.</li><li><strong>1 mark:</strong> Correct daily fixed cost calculation: £6,300 ÷ 7 = £900.</li><li><strong>1 mark:</strong> Correct final answer: £900 ÷ £60 = 15 rooms. [OFR applies]</li><li><strong>2 marks max:</strong> If student does not divide by 7 days: FC ÷ Contribution = 6,300 ÷ 60 = 105 (weekly break-even).</li><li><strong>No reward:</strong> for stating the formula alone without calculation.</li></ul><p><strong>Examiner''s Comment:</strong> Despite ''daily'' being emboldened, many candidates scored only 2 marks by producing 105 (the weekly break-even) rather than dividing by 7.</p></div>"}, {"question": "Analyse one disadvantage to the partnership if the proposed hotel''s fixed costs were 10% higher than expected. [3 marks]", "marks": 3, "hint": "Structure: Understanding (what does higher fixed costs mean for a business?) → Application (use the actual figures from the case study) → Analysis (what is the specific impact on Anika and Charlie?).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>1 mark (U):</strong> Understanding — higher fixed costs could lead to lower profits, higher break-even point, price increases needed, or less money available for other needs.</li><li><strong>No further marks without understanding.</strong></li><li><strong>1 further mark (APP):</strong> Application to Sea View Hotel — FC rises from £6,300 to £6,930 per week (increase of £630/week or £90/day), or break-even rises from 15 to 17 rooms per day, or reference to existing bank loan.</li><li><strong>1 further mark (AN):</strong> Analysis of impact on the partnership — need to sell more rooms to cover costs; may reduce dividends/profit for owners; may make second bank loan unaffordable; less attractive to new investors.</li><li><strong>No reward:</strong> ''Costs will increase'' as understanding. Analysis must be business-facing.</li></ul><p><strong>Examiner''s Comment:</strong> Many students named a disadvantage without showing understanding. The best answers quantified the change (£6,300 → £6,930) and linked it to a specific business impact such as needing to fill more rooms.</p></div>"}, {"question": "Analyse one reason why keeping variable costs low may reward Zara''s owners. [3 marks]", "marks": 3, "hint": "Structure: Understanding (how does lower VC lead to reward for owners?) → Application (reference specific Zara details from the case study) → Analysis (what is the specific impact on Zara''s owners?).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>1 mark (U):</strong> Lower variable costs → lower total costs → better profit margins.</li><li><strong>No further marks without understanding.</strong></li><li><strong>1 further mark (APP):</strong> Application to Zara — buying fabric in large quantities from European suppliers; 2,270 stores; online sales up 75%; 15-day delivery cycle.</li><li><strong>1 further mark (AN):</strong> Analysis of benefit to owners — higher dividends; ability to reinvest and expand; business can grow and increase owner value.</li><li><strong>No reward:</strong> Answers suggesting lower costs increase revenue. Analysis must relate to owner reward specifically.</li></ul><p><strong>Examiner''s Comment:</strong> Many responses were too generic. Answers must be contextual (refer to Zara). The key link is: lower VC → better profit margin → owners receive more dividends or business can expand, increasing the value of their investment.</p></div>"}, {"question": "Calculate the percentage decrease in Zara''s sales revenue between 2019 and 2020. Show your workings. [2 marks]", "marks": 2, "hint": "% change = (Change ÷ Original) × 100. The original is the 2019 figure. Change = 2019 revenue − 2020 revenue.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5><ul><li><strong>2 marks:</strong> Correct answer of 29.2% (or 29% accepted) with or without workings.</li><li><strong>1 mark:</strong> Correct calculation of change (€5,825m) shown in workings, but error in final percentage.</li><li><strong>Note:</strong> Negative sign is not required. Accept any reasonable level of accuracy (29% to 29.2%).</li></ul><p><strong>Working:</strong> €19,954m − €14,129m = €5,825m. (€5,825m ÷ €19,954m) × 100 = 29.2%.</p></div>"}, {"question": "Explain one possible advantage to a business of selling its products via e-commerce. [2 marks]", "marks": 2, "hint": "Think about what e-commerce specifically enables (24/7 selling, global reach, lower operating costs) and explain WHY that is an advantage.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b)</h5><ul><li><strong>1 mark:</strong> Identifying an advantage specific to e-commerce (not just ''selling more'').</li><li><strong>1 further mark:</strong> Explaining the advantage — how does it help the business?</li><li><strong>Acceptable answers include:</strong></li></ul><ul><li>Can sell worldwide / to a wider audience (K) — increasing potential customer base beyond local area (U).</li><li>Open 24/7 (K) — generating sales outside normal trading hours without additional staff costs (U).</li><li>Lower operating costs (K) — no need for expensive high-street premises, reducing fixed costs (U).</li></ul><p><strong>Examiner''s Comment:</strong> ''Selling more products'' without linking to e-commerce features gains no marks. Answers from the customer''s perspective also gain no marks — the question asks about the business.</p></div>"}, {"question": "Calculate AZ''s gross profit margin for 2021. Show your workings. [2 marks]", "marks": 2, "hint": "GPM = (Gross Profit ÷ Revenue) × 100. Both figures are given in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5><ul><li><strong>2 marks:</strong> Correct answer of 66.8% (accept 67%, 66.76%, 66.7%, or the full decimal).</li><li><strong>1 mark:</strong> Setting out the correct calculation (£24,980m ÷ £37,417m × 100) even if answer is incorrect or missing units.</li><li><strong>0 marks:</strong> Incorrect formula or answer without any supporting workings.</li></ul><p><strong>Examiner''s Comment:</strong> Mistakes included rounding errors and omitting the % sign.</p></div>"}, {"question": "Calculate the percentage change in BP''s revenue between 2017 and 2019. Show your workings. [2 marks]", "marks": 2, "hint": "% change = (Change ÷ Original) × 100. The original is the 2017 figure. Change = 2019 − 2017.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5><ul><li><strong>2 marks:</strong> Correct answer of 15.5% (accept 15% or 16% with workings shown).</li><li><strong>1 mark:</strong> Correct change calculation of $38bn shown in workings with arithmetic error in percentage.</li><li><strong>Note:</strong> An answer of 13.4% (using 2019 as denominator) earns 1 mark OFR if working is shown.</li></ul><p><strong>Working:</strong> Change = $283bn − $245bn = $38bn. % change = ($38bn ÷ $245bn) × 100 = 15.5%.</p></div>"}, {"question": "Identify two factors that can affect a company''s revenue. [2 marks]", "marks": 2, "hint": "Revenue = Price × Quantity sold. Think of factors that change either the price a business charges OR the number of units sold.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><ul><li><strong>1 mark per factor</strong> (up to 2 marks): Any two correct factors affecting revenue.</li><li><strong>Acceptable answers include:</strong> number of competitors, actions of competitors, selling price of the product, level of advertising, quality of the product, customer service, product range, entry into new markets.</li><li><strong>No reward for:</strong> factors affecting only costs (e.g. supplier prices, wage levels). Revenue is affected by price and quantity sold — any factor affecting either of these is acceptable.</li></ul><p><strong>Examiner''s Comment:</strong> Some students confused ''price'' (what a business charges customers) with ''cost'' (what a business pays). These are completely different concepts.</p></div>"}, {"question": "Calculate the average rate of return (ARR) for the Standard Van by using the information in Table 2. Show your workings. [3 marks]", "marks": 3, "hint": "The ''total net profit for the life of the van'' is already given (this IS the profit, not the income). Step 2: divide by years. Step 3: ARR = (average annual profit ÷ cost) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2)</h5><ul><li><strong>1 mark:</strong> Average annual profit = £60,000 ÷ 3 = £20,000.</li><li><strong>1 mark:</strong> Setting up: (£20,000 ÷ £40,000) × 100. [OFR]</li><li><strong>1 mark:</strong> Correct final answer of 50%. [OFR]</li><li><strong>Note:</strong> ''Total net profit'' is already given — no need to subtract cost. % sign not required as printed on paper.</li></ul><p><strong>Examiner''s Comment:</strong> Generally well answered. Errors came from inability to select the correct data from Table 2 or poor knowledge of the formula.</p></div>"}]}}'::jsonb),
('business', '5-4-break-even', '5.4 Break-even', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>Break-even analysis is a financial tool that helps businesses calculate the minimum number of units they must sell to cover all costs — making neither a profit nor a loss.</p>\n    <ul>\n      <li><strong>Break-even quantity:</strong> The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss.</li>\n      <li><strong>Contribution per unit:</strong> Selling price minus variable cost per unit. Each unit sold \"contributes\" towards covering fixed costs before profit can be made.</li>\n      <li><strong>Total Revenue (TR):</strong> Selling price × quantity sold.</li>\n      <li><strong>Fixed Costs:</strong> Costs that do not change depending on output (e.g., rent, insurance, loan repayments).</li>\n      <li><strong>Variable Costs:</strong> Costs that change depending on the level of output (e.g., raw materials, packaging, direct labour).</li>\n      <li><strong>Total Costs:</strong> Total fixed costs + total variable costs.</li>\n      <li><strong>Margin of Safety:</strong> Actual sales − break-even sales. The amount by which a business''s actual output is greater than its break-even level of output.</li>\n      <li><strong>Break-even forecast:</strong> A prediction about the break-even quantity based on estimates of future sales revenues and costs.</li>\n      <li><strong>Profit:</strong> Total revenue − total costs (when TR > TC).</li>\n      <li><strong>Loss:</strong> When total costs exceed total revenue (TC > TR) — this occurs when output is below the break-even point.</li>\n    </ul>", "check": {"question": "According to the key definitions, what is ''contribution per unit''?", "options": ["Total revenue minus total costs of the business", "Selling price minus variable cost per unit", "Selling price minus total fixed costs of the business", "Fixed costs divided by the total quantity sold"], "answer": 1, "explain": "The card defines contribution per unit as selling price minus variable cost per unit — the amount each unit contributes towards covering fixed costs."}}, {"title": "Calculating the Break-Even Quantity", "html": "<p>There is one formula you must know for the OCR GCSE exam. Break-even is <strong>always recorded in units</strong>, never in pounds (£).</p>\n    <div class=\"formula-box\">\n      <strong>Break-Even Output =</strong> Total Fixed Costs ÷ Contribution per Unit<br><br>\n      <strong>Contribution per Unit =</strong> Selling Price − Variable Cost per Unit\n    </div>\n    <p><strong>Worked Example:</strong> A toy manufacturer has fixed costs of £50,000, sells toys at £6 each, and variable costs of £2 per toy.</p>\n    <ul>\n      <li>Contribution = £6 − £2 = <strong>£4 per unit</strong></li>\n      <li>Break-even = £50,000 ÷ £4 = <strong>12,500 units</strong></li>\n    </ul>\n    <p><strong>⚠️ Key Rules:</strong></p>\n    <ul>\n      <li><strong>Always round UP</strong> if your answer is a decimal — you cannot break even on a fraction of a unit. For example, 583.3 rounds up to 584.</li>\n      <li><strong>Always show your working</strong> — even if the final answer is wrong, you can earn method marks for each correct step.</li>\n      <li><strong>Watch for time period traps</strong> — if costs are given weekly but the question asks for a daily break-even, divide fixed costs by 7 first.</li>\n    </ul>", "check": {"question": "According to this card, how should the break-even output always be recorded?", "options": ["In units, always rounded down if the answer is a decimal", "In pounds, always rounded down if the answer is a decimal", "In units, always rounded up if the answer is a decimal", "In pounds, always rounded up if the answer is a decimal"], "answer": 2, "explain": "The card states break-even is always recorded in units and rounded UP if the answer is a decimal, since a business cannot break even on a fraction of a unit."}}, {"title": "The Break-Even Graph", "html": "<p>Break-even can be shown visually using a line graph. You may be asked to <strong>read and interpret</strong> a break-even graph in the exam.</p>\n    <ul>\n      <li><strong>Horizontal axis (x-axis):</strong> Output / Units sold</li>\n      <li><strong>Vertical axis (y-axis):</strong> Costs and Revenue (£)</li>\n      <li><strong>Fixed Costs line:</strong> A <em>horizontal</em> straight line — costs stay the same at all levels of output</li>\n      <li><strong>Total Costs line:</strong> Starts at the fixed cost level, then rises diagonally as output increases (adding variable costs)</li>\n      <li><strong>Total Revenue line:</strong> Starts at zero (no sales = no revenue), rises diagonally as output increases</li>\n      <li><strong>Break-even point:</strong> Where the Total Revenue line crosses the Total Costs line (TR = TC)</li>\n      <li><strong>Loss area:</strong> To the <em>left</em> of the break-even point — TC > TR, so the business makes a loss</li>\n      <li><strong>Profit area:</strong> To the <em>right</em> of the break-even point — TR > TC, so the business makes a profit</li>\n    </ul>\n    <p>The <strong>Margin of Safety</strong> is shown as the horizontal distance between actual output and the break-even point. A larger margin of safety means the business has more protection against a fall in sales.</p>", "check": {"question": "According to this card, what does the area to the left of the break-even point represent?", "options": ["The loss area, where total costs exceed total revenue", "The fixed cost area, where output has no effect on revenue", "The profit area, where total revenue exceeds total costs", "The margin of safety, showing spare capacity above the target"], "answer": 0, "explain": "The card explains the loss area lies to the left of the break-even point, where TC > TR; the profit area lies to the right, where TR > TC."}}, {"title": "Benefits of Break-Even Analysis", "html": "<p>Break-even analysis is a powerful planning tool with several key benefits for businesses:</p>\n    <ul>\n      <li><strong>Planning sales targets:</strong> It shows exactly how many units must be sold to make a profit, giving the business a specific, measurable target to aim for.</li>\n      <li><strong>Securing a bank loan:</strong> Banks often ask to see a break-even forecast as part of a business plan. It demonstrates that the owner has planned carefully, reducing the risk for the bank and making them more willing to lend.</li>\n      <li><strong>Pricing and cost decisions:</strong> If the break-even output is too high to be realistic, the business can consider raising its price or cutting variable/fixed costs to lower the break-even point.</li>\n      <li><strong>Estimating expected profit:</strong> Once break-even is known, the business can forecast how much profit it would make at different levels of output.</li>\n      <li><strong>Assessing the margin of safety:</strong> The business can evaluate how far sales can fall before it starts making a loss, helping it plan for economic uncertainty.</li>\n    </ul>", "check": {"question": "According to this card, why might a bank be more willing to lend to a business?", "options": ["A break-even forecast proves the business will never face any real competitors at all", "Break-even analysis removes the business''s need to ever repay any interest", "A break-even forecast shows the owner has planned carefully, reducing the bank''s risk", "Break-even analysis guarantees that the business will always be profitable"], "answer": 2, "explain": "The card lists securing a bank loan as a benefit, since a break-even forecast demonstrates careful planning and reduces the perceived risk for the bank."}}, {"title": "Limitations of Break-Even Analysis", "html": "<p>Despite its usefulness, break-even analysis has several important limitations that businesses must be aware of:</p>\n    <ul>\n      <li><strong>It is only a prediction:</strong> All figures used are estimates of future costs and revenues. Actual results may differ significantly from the forecast.</li>\n      <li><strong>Competitors may change:</strong> If a new competitor enters the market, the business may have to lower its price to maintain sales. This reduces contribution per unit and raises the break-even output — making the original forecast inaccurate.</li>\n      <li><strong>Variable costs may change:</strong> If the cost of raw materials rises or falls unexpectedly, the variable cost per unit changes, altering the contribution and therefore the break-even point.</li>\n      <li><strong>Difficult for multi-product businesses:</strong> Calculating break-even is straightforward for a single-product business but becomes complex and less reliable when a firm sells many different products at different prices and costs.</li>\n      <li><strong>Promotional pricing is ignored:</strong> A business may offer discounts at launch, meaning actual revenue is less than the planned price — raising the real break-even output.</li>\n      <li><strong>Price increases may not raise revenue:</strong> If a price rise leads to a large fall in demand, total revenue could actually decrease — meaning the assumed revenue line on the graph would be inaccurate.</li>\n    </ul>", "check": {"question": "According to this card, why can a new competitor make a break-even forecast inaccurate?", "options": ["A new competitor always forces the business to stop selling its products internationally", "A new competitor guarantees that the business''s break-even output will fall", "A new competitor automatically increases the business''s total fixed costs", "The business may have to lower its price, reducing contribution and raising break-even"], "answer": 3, "explain": "The card explains a new competitor may force a price cut, reducing contribution per unit and raising the real break-even output above the original forecast."}}, {"title": "Advantages vs Disadvantages of Break-Even Analysis", "html": "<div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Clear sales target:</strong> Shows exactly how many units must be sold to cover all costs and move into profit — giving management a specific goal to plan around.</div>\n    <div class=\"pro-item\"><strong>Supports bank loan applications:</strong> A bank manager is more likely to lend money if the business can present a break-even forecast as part of a well-prepared business plan.</div>\n    <div class=\"pro-item\"><strong>Informs pricing and cost decisions:</strong> If the break-even output is too high, the business knows it must either raise its price or reduce its costs to make profitability realistic.</div>\n    <div class=\"pro-item\"><strong>Forecasts profit at different outputs:</strong> Allows the business to estimate how much profit it could make at various sales levels, aiding strategic planning.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Based on estimates only:</strong> All revenue and cost figures are predictions. If prices or costs change unexpectedly, the entire forecast becomes inaccurate.</div>\n    <div class=\"con-item\"><strong>Ignores competition:</strong> New competitors entering the market may force price cuts, reducing contribution per unit and pushing the real break-even output above what was forecast.</div>\n    <div class=\"con-item\"><strong>Variable costs can change:</strong> Raw material price increases raise the variable cost per unit, shrinking the contribution and raising the break-even output beyond the original calculation.</div>\n    <div class=\"con-item\"><strong>Not suitable for multi-product businesses:</strong> Firms selling several products with different costs and prices find break-even analysis complex and unreliable as a guide to overall performance.</div>\n    </div>\n    </div>", "check": {"question": "According to this card, why is break-even analysis less reliable for multi-product businesses?", "options": ["Break-even analysis can only ever be calculated using a single fixed cost", "Multi-product businesses are legally banned from using break-even analysis at all", "Calculating break-even becomes complex when products have different prices and costs", "Multi-product businesses never have any variable costs to include at all"], "answer": 2, "explain": "The card lists multi-product businesses as a limitation, since calculating break-even is complex and less reliable when products have different prices and costs."}}, {"title": "How Changes Affect the Break-Even Point", "html": "<p>A key exam skill is predicting what happens to the break-even output when variables change. Use the formula to reason through each scenario logically:</p>\n    <ul>\n      <li><strong>Selling price increases &rarr;</strong> Contribution per unit rises &rarr; Break-even output <strong>decreases</strong> (fewer units needed).</li>\n      <li><strong>Selling price decreases &rarr;</strong> Contribution per unit falls &rarr; Break-even output <strong>increases</strong> (more units needed).</li>\n      <li><strong>Fixed costs increase &rarr;</strong> More costs to cover &rarr; Break-even output <strong>increases</strong>.</li>\n      <li><strong>Fixed costs decrease &rarr;</strong> Fewer costs to cover &rarr; Break-even output <strong>decreases</strong>.</li>\n      <li><strong>Variable cost per unit increases &rarr;</strong> Contribution per unit falls &rarr; Break-even output <strong>increases</strong>.</li>\n      <li><strong>Variable cost per unit decreases &rarr;</strong> Contribution per unit rises &rarr; Break-even output <strong>decreases</strong>.</li>\n    </ul>\n    <p>On a break-even graph: a <strong>price increase</strong> is shown as a steeper Total Revenue line (pivoting upward). A <strong>rise in variable costs</strong> is shown as a steeper Total Costs line (pivoting upward from the fixed cost level).</p>", "check": {"question": "According to this card, what happens to the break-even output if fixed costs increase?", "options": ["It stays exactly the same, since fixed costs do not affect break-even", "It decreases, since higher fixed costs raise contribution per unit", "It increases, since more costs must be covered by contribution", "It decreases, since fewer units are then needed to cover costs"], "answer": 2, "explain": "The card explains that when fixed costs increase, there are more costs to cover, so the break-even output increases — the opposite happens when fixed costs fall."}}, {"title": "Case Study: Lord Digby Jones & Hereford Furniture", "html": "<div class=\"case-study-box\">\n    <h4>Case Study: Hereford Furniture</h4>\n    <p>Lord Digby Jones, a respected businessman, appeared on a BBC TV programme called <em>The New Trouble Shooter</em>. He visited Hereford Furniture, a family-owned business run by Mike Muxworthy and his daughter Kate. At the time of his visit, the business was making a loss of £80,000 and the jobs of 40 workers were at risk.</p>\n    <p>Lord Jones <strong>heavily criticised the owners for not completing break-even forecasts</strong>, calling them \"essential for good business planning.\" Without knowing their break-even output, the owners had no clear sales target and no way of knowing whether their pricing was sufficient to cover costs.</p>\n    <p><strong>The Takeaway:</strong> Even established businesses must regularly calculate break-even. Without it, managers are effectively \"flying blind\" — unable to make informed decisions about price, costs, or how much to produce. Lord Jones'' intervention helped the business develop a clear financial plan to return to profitability.</p>\n    </div>", "check": {"question": "According to the Hereford Furniture case study, what did Lord Digby Jones criticise the owners for?", "options": ["Employing far too many staff relative to their level of output", "Charging their customers far too little for their furniture products", "Not completing break-even forecasts as part of their business planning", "Refusing to apply for any external sources of finance at all"], "answer": 2, "explain": "The card explains Lord Jones criticised Hereford Furniture for not completing break-even forecasts, calling them essential for good business planning."}}, {"title": "Case Study: Samantha Dixon — Cake Decorating", "html": "<div class=\"case-study-box\">\n    <h4>Case Study: Samantha Dixon — Wedding Cake Business</h4>\n    <p>Samantha Dixon is starting up a cake decorating business. In her area there are already two other cake decorating businesses. She estimates she can sell wedding cakes at £300 each — slightly less than her competitors. Variable costs per cake are £180. Her fixed costs are £3,600 per year.</p>\n    <p><strong>Break-Even Calculation:</strong></p>\n    <ul>\n      <li>Contribution = £300 − £180 = £120 per cake</li>\n      <li>Break-even = £3,600 ÷ £120 = <strong>30 cakes per year</strong></li>\n    </ul>\n    <p><strong>What this means for Samantha:</strong></p>\n    <ul>\n      <li>She must sell at least 30 cakes before making any profit.</li>\n      <li>If she expects to sell 35 cakes, her margin of safety is 35 − 30 = 5 cakes.</li>\n      <li>She can show this forecast to a bank manager to support a loan application, demonstrating she has a clear financial plan.</li>\n    </ul>\n    <p><strong>Key Limitation:</strong> There are already 2 competitors. If they lower their prices below £300, Samantha may have to follow — reducing contribution per cake and pushing her break-even output above 30, making the forecast inaccurate.</p>\n    </div>", "check": {"question": "In the Samantha Dixon case study, what is her margin of safety if she sells 35 cakes?", "options": ["300 cakes, based on her selling price per cake in pounds", "35 cakes, since none of her cakes have covered any costs yet", "180 cakes, based on her variable cost per cake in pounds", "5 cakes, since her break-even output is 30 cakes per year"], "answer": 3, "explain": "The card calculates Samantha''s margin of safety as actual sales (35) minus break-even sales (30), giving a margin of safety of 5 cakes."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Break-even quantity", "definition": "The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss."}, {"term": "Break-even formula", "definition": "Total Fixed Costs ÷ Contribution per Unit\n(where Contribution = Selling Price − Variable Cost per Unit)"}, {"term": "Contribution per unit", "definition": "Selling price minus variable cost per unit. Each unit sold ''contributes'' towards covering fixed costs before profit is made."}, {"term": "Margin of safety", "definition": "Actual sales − break-even sales (in units). Shows how far output can fall before a loss is made."}, {"term": "Total Revenue", "definition": "Selling price × quantity sold"}, {"term": "Fixed Costs", "definition": "Costs that do NOT change with the level of output, e.g. rent, loan repayments, insurance."}, {"term": "Variable Costs", "definition": "Costs that DO change with the level of output, e.g. raw materials, packaging, direct labour per unit."}, {"term": "Total Costs", "definition": "Total fixed costs + total variable costs"}, {"term": "Break-even forecast", "definition": "A prediction of the break-even output based on estimated future revenues and costs. It is not a guarantee — actual results may differ."}, {"term": "Effect of a price INCREASE on break-even", "definition": "Contribution increases → break-even output DECREASES (fewer units needed to cover fixed costs)."}, {"term": "Effect of HIGHER fixed costs on break-even", "definition": "More costs to cover → break-even output INCREASES (more units must be sold)."}, {"term": "Effect of HIGHER variable costs on break-even", "definition": "Contribution falls → break-even output INCREASES."}, {"term": "Why is break-even useful for bank loans?", "definition": "Banks ask to see a break-even forecast as part of a business plan. It shows the owner has thought carefully about costs, revenue, and viability — reducing the bank''s risk."}, {"term": "Key limitation of break-even analysis", "definition": "All figures are estimates. Actual costs, prices, or competitor behaviour may differ — especially if a new competitor enters the market or raw material costs change unexpectedly."}, {"term": "What does the break-even POINT look like on a graph?", "definition": "It is where the Total Revenue line crosses the Total Costs line. To the left = loss zone. To the right = profit zone."}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the break-even quantity?", "options": ["The output level at which a business maximises its profit", "The output level at which total revenue equals total costs", "The output level at which fixed costs equal variable costs", "The output level at which a business earns its highest revenue"], "answer": 1, "explain": "Correct answer: Break-even is the point where total revenue exactly equals total costs, so the business makes neither a profit nor a loss."}, {"question": "A manufacturer that makes and sells MORE than its break-even quantity will:", "options": ["Have insufficient revenue to cover costs", "Make a profit", "Need to improve its quality control", "Require an overdraft"], "answer": 1, "explain": "Correct answer: Once a business sells beyond its break-even output, total revenue exceeds total costs, resulting in a profit. Options A and D are what happens BELOW break-even. Option C is unrelated to break-even."}, {"question": "At break-even, a firm''s total revenue equals its:", "options": ["Fixed costs only", "Gross profit", "Net profit", "Total costs"], "answer": 3, "explain": "Correct answer: At break-even, TR = TC. The business covers ALL costs (fixed AND variable), meaning there is zero profit and zero loss."}, {"question": "Amaya is a gardener. She charges £15 per hour. Her fixed costs are £18,000 per annum. Her variable costs are £2 per hour. How many hours does Amaya need to work to START making a profit?", "options": ["1,059 hours", "1,385 hours", "2,340 hours", "3,060 hours"], "answer": 1, "explain": "Correct answer: 1,385 hours. Contribution = £15 − £2 = £13. Break-even = £18,000 ÷ £13 = 1,384.6 → round UP to 1,385 hours. Always round up because you cannot break even on a fraction of a unit."}, {"question": "Kim is a driving instructor charging £30 per lesson. Fixed costs are £14,000 per year. Variable costs are £6 per lesson. How many lessons must Kim give before making a profit?", "options": ["389 lessons", "467 lessons", "584 lessons", "2,334 lessons"], "answer": 2, "explain": "Correct answer: 584 lessons. Contribution = £30 − £6 = £24. Break-even = £14,000 ÷ £24 = 583.3 → round UP to 584. Option D results from dividing by variable cost only (÷ £6), ignoring the selling price."}, {"question": "Which of the following is a limitation of break-even analysis?", "options": ["It cannot be used to estimate the profit a business is likely to make", "It cannot factor in seasonal pricing and price discounts", "It cannot show how much a business needs to sell to cover its costs", "It cannot show the level of profit or loss at a range of outputs"], "answer": 1, "explain": "Correct answer: Break-even assumes a single fixed price. It cannot account for seasonal pricing, promotional discounts, or variable pricing — all of which affect actual revenue. Options A, C, and D are all things break-even CAN do."}, {"question": "A business has fixed costs of £20,000, a selling price of £50, and variable costs of £30 per unit. What is its break-even output?", "options": ["400 units", "667 units", "1,000 units", "1,500 units"], "answer": 2, "explain": "Correct answer: 1,000 units. Contribution = £50 − £30 = £20. Break-even = £20,000 ÷ £20 = 1,000 units."}, {"question": "A business''s actual output is 5,000 units and its break-even output is 3,500 units. What is the margin of safety?", "options": ["1,500 units", "3,500 units", "5,000 units", "8,500 units"], "answer": 0, "explain": "Correct answer: 1,500 units. Margin of safety = actual sales − break-even sales = 5,000 − 3,500 = 1,500 units."}, {"question": "Carlton Press Ltd has fixed costs of £30,000, variable costs of £2 per booklet, and sells each booklet at £5. What is the break-even output?", "options": ["5,000 booklets", "10,000 booklets", "15,000 booklets", "20,000 booklets"], "answer": 1, "explain": "Correct answer: 10,000 booklets. Contribution = £5 − £2 = £3. Break-even = £30,000 ÷ £3 = 10,000 booklets."}, {"question": "Which of these may cause a break-even forecast to turn out to be incorrect?", "options": ["The number of competitors in the market remains the same", "The business sells all its goods at its planned price", "The cost of importing raw materials increases", "Workers accept the planned rise in wages"], "answer": 2, "explain": "Correct answer: If raw material costs increase, variable costs rise unexpectedly — making the original break-even forecast inaccurate. Options A, B, and D all describe scenarios where things go exactly as planned, so the forecast would remain valid."}, {"question": "A business will make a LOSS if:", "options": ["Its revenues are greater than its costs", "It uses its revenues to pay off all its debts", "It sells less than its break-even output", "It has to take out an overdraft"], "answer": 2, "explain": "Correct answer: A business makes a loss when it sells fewer units than its break-even output — meaning total costs exceed total revenue. An overdraft is a cash flow issue; it does not automatically mean the business is making a loss."}, {"question": "If Carlton Press Ltd (break-even = 10,000) sells 20,000 books, what is its margin of safety?", "options": ["5,000 booklets", "10,000 booklets", "15,000 booklets", "20,000 booklets"], "answer": 1, "explain": "Correct answer: 10,000 booklets. Margin of safety = actual sales − break-even output = 20,000 − 10,000 = 10,000 booklets."}, {"question": "If a business''s fixed costs INCREASE, what happens to its break-even output?", "options": ["It decreases because there are more costs to spread", "It increases because more units must be sold to cover the higher costs", "It stays the same because variable costs are unchanged", "It decreases because contribution per unit rises"], "answer": 1, "explain": "Correct answer: Break-even = FC ÷ contribution. If fixed costs rise (numerator increases) while contribution stays the same, the result is a higher break-even output — the business must sell more units to cover all its costs."}, {"question": "Andrea paints portraits. Labour VC = £52, materials VC = £23 per portrait, fixed costs = £1,000 per month. If she paints 50 portraits per year, total annual costs are:", "options": ["£1,075 per year", "£4,750 per year", "£12,075 per year", "£15,750 per year"], "answer": 3, "explain": "Correct answer: £15,750. Annual FC = £1,000 × 12 = £12,000. VC per portrait = £52 + £23 = £75. TVC = £75 × 50 = £3,750. Total costs = £12,000 + £3,750 = £15,750. Many students forget to convert monthly FC to annual."}]}, "fib": {"enabled": true, "questions": [{"text": "The break-even formula is: total [fixed] costs divided by [contribution] per unit."}, {"text": "Contribution per unit is calculated as selling [price] minus [variable] cost per unit."}, {"text": "A business breaks even when total [revenue] equals total [costs]."}, {"text": "The margin of safety is calculated as actual sales minus [break-even] sales."}, {"text": "Break-even output is always measured in [units], never in pounds."}, {"text": "If a business sells [less] than its break-even output, it will make a loss."}, {"text": "If fixed costs increase, the break-even output will [increase]."}, {"text": "If the selling price increases, the contribution per unit will [increase], and the break-even output will [decrease]."}, {"text": "A bank manager may ask to see a break-even [forecast] as part of a business [plan]."}, {"text": "Break-even analysis is described as a [prediction] because the figures are based on estimates of future costs and revenues."}, {"text": "If variable costs per unit rise, the contribution per unit [falls], causing the break-even output to [increase]."}, {"text": "On a break-even graph, the profit area is to the [right] of the break-even point, and the loss area is to the [left]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Break-even is the point at which total revenue equals total costs.", "answer": true, "explain": "TRUE. At break-even, TR = TC exactly. The business covers all its costs but makes neither a profit nor a loss. This is the core definition."}, {"statement": "Break-even output is measured in pounds (£), not units.", "answer": false, "explain": "FALSE. Break-even output is always measured in UNITS (e.g., 12,500 toys or 30 cakes). Writing a £ sign instead of units will cost you a mark in the exam."}, {"statement": "If a business sells more than its break-even output, it will make a profit.", "answer": true, "explain": "TRUE. Once output exceeds break-even, every additional unit sold generates profit — because total revenue now exceeds total costs."}, {"statement": "Fixed costs change depending on the level of output produced.", "answer": false, "explain": "FALSE. Fixed costs remain the same regardless of output. Rent is the same whether a business produces 100 or 10,000 units. It is variable costs that change with output."}, {"statement": "An increase in selling price will cause the break-even output to decrease.", "answer": true, "explain": "TRUE. A higher price increases the contribution per unit. Since break-even = FC ÷ contribution, a larger contribution means fewer units need to be sold to cover fixed costs."}, {"statement": "An increase in variable costs per unit will cause the break-even output to decrease.", "answer": false, "explain": "FALSE. If variable costs increase, contribution per unit falls (price − VC is smaller). A lower contribution means MORE units must be sold to cover fixed costs — so break-even output INCREASES."}, {"statement": "The margin of safety is calculated by subtracting break-even sales from actual sales.", "answer": true, "explain": "TRUE. Margin of safety = actual sales − break-even sales. It shows how far sales can fall before the business starts making a loss."}, {"statement": "Break-even analysis gives perfectly accurate predictions because it is based on mathematical calculations.", "answer": false, "explain": "FALSE. Break-even uses estimated figures for future costs and revenues — it is a forecast, not a certainty. Actual results may differ due to competitors, price changes, or rising raw material costs."}, {"statement": "Break-even analysis is most accurate for businesses that sell a wide variety of different products.", "answer": false, "explain": "FALSE. Break-even is most straightforward for single-product businesses. Multi-product businesses have different costs and prices for each product, making break-even analysis complex and much less reliable."}, {"statement": "A break-even forecast can help a business secure a bank loan.", "answer": true, "explain": "TRUE. Banks often ask to see a break-even forecast as part of a business plan. It demonstrates the owner has planned carefully and understood their finances, reassuring the bank that the loan is less risky."}, {"statement": "On a break-even graph, the Total Revenue line starts at zero when output is zero.", "answer": true, "explain": "TRUE. If a business sells zero units, it earns zero revenue. The Total Revenue line always begins at the origin (0, 0) and rises diagonally as units are sold."}, {"statement": "On a break-even graph, the Fixed Costs line rises diagonally from left to right.", "answer": false, "explain": "FALSE. The Fixed Costs line is horizontal — it stays flat at the same level regardless of output. It is the Total Costs and Total Revenue lines that are diagonal."}]}, "misc": {"enabled": true, "items": [{"myth": "Students write the break-even output in pounds, e.g. ''£12,500'' or ''£30''.", "truth": "Break-even output must always be written in UNITS (e.g., ''12,500 units'' or ''30 cakes''). Writing a £ sign loses you a mark — the examiner is strict on this.", "check": {"question": "In what unit must the break-even output always be recorded?", "options": ["In pounds, such as ''£12,500'' or ''£30''", "In percentages, such as ''12,500%'' or ''30%''", "In hours, such as ''12,500 hours'' or ''30 hours''", "In units, such as ''12,500 units'' or ''30 cakes''"], "answer": 3, "explain": "The card explains break-even output must always be written in units — writing a £ sign loses a mark, as examiners are strict on this."}}, {"myth": "Students think ''break-even'' means the business is doing well or making a profit.", "truth": "At break-even, the business makes NEITHER a profit NOR a loss. Total revenue exactly equals total costs — there is no money left over. It is the minimum acceptable level of sales.", "check": {"question": "What does reaching the break-even point actually tell us about a business?", "options": ["It makes neither a profit nor a loss — revenue exactly equals total costs", "It has definitely covered its costs and is now growing quickly", "It is making a healthy profit and performing very well overall", "It has failed completely and will need to close down within the next year"], "answer": 0, "explain": "The card corrects the misconception that break-even means doing well — at break-even, revenue exactly equals total costs and there is no money left over."}}, {"myth": "Students use total costs (not fixed costs) in the break-even formula: ''TC ÷ contribution''.", "truth": "The formula uses FIXED COSTS only: FC ÷ contribution. Variable costs are already built into the contribution figure (price − VC), so using total costs would count variable costs twice.", "check": {"question": "Which figure is used in the break-even formula: fixed costs or total costs?", "options": ["Total revenue only, since costs do not appear in the formula at all", "Variable costs only, since fixed costs are irrelevant to break-even", "Total costs only, since fixed costs alone would understate the final answer", "Fixed costs only, since variable costs are already built into contribution"], "answer": 3, "explain": "The card explains the formula uses fixed costs only, since variable costs are already accounted for within the contribution figure — using total costs would double-count them."}}, {"myth": "Students round DOWN when the break-even gives a decimal (e.g., 583.3 becomes 583).", "truth": "Always round UP. At 583 units the business has NOT yet covered all fixed costs — it needs to sell at least 584 to actually break even.", "check": {"question": "How should a decimal break-even answer, such as 583.3, be rounded?", "options": ["Rounded to the nearest 10, to 580, for a simpler final answer", "Left as a decimal, since break-even units may include a fraction", "Always rounded up, to 584, since 583 would not cover all fixed costs", "Always rounded down, to 583, to keep the final answer as low as possible"], "answer": 2, "explain": "The card explains you must always round UP, since at 583 units the business has not yet covered all its fixed costs and would still be making a loss."}}, {"myth": "Students say break-even analysis is perfectly accurate and reliable because it uses maths.", "truth": "Break-even is a PREDICTION based on estimated figures. Actual costs and revenues may differ significantly — competitors, price changes, or rising material costs can all make the forecast inaccurate.", "check": {"question": "Why is break-even analysis not considered perfectly accurate and reliable?", "options": ["It removes the need for a business to consider its competitors at all", "It uses maths, so the result is always guaranteed to be completely correct", "It is a prediction based on estimated figures that may turn out to be wrong", "It only ever uses figures that have already actually happened in the past"], "answer": 2, "explain": "The card explains break-even is a prediction based on estimated figures — actual costs and revenues may differ significantly due to competitors or rising costs."}}, {"myth": "When asked to ''analyse a benefit of break-even'', students simply describe what break-even is.", "truth": "The examiner wants U + APP + AN. State the benefit (U), apply it to the specific business in the case study (APP), and explain the impact on THAT business (AN). Describing the concept of break-even without any analysis or application scores zero.", "check": {"question": "What must a full-mark ''analyse a benefit of break-even'' answer include, beyond a description?", "options": ["A complete list of every possible benefit of break-even analysis", "Only a general description of what break-even means as a concept", "A definition of profit rather than a definition of break-even itself", "Application to the specific business plus analysis of the impact on it"], "answer": 3, "explain": "The card explains the examiner wants U + APP + AN — describing the concept of break-even alone, without application or analysis, scores zero."}}, {"myth": "Students say ''it shows how many a business needs to sell to break-even'' as their Understanding mark.", "truth": "This is tautological — you cannot explain break-even by using the term ''break-even''. You must show understanding by explaining WHAT break-even means: ''the point at which total revenue covers all costs, with no profit or loss.''", "check": {"question": "Why does ''it shows how many a business needs to sell to break-even'' fail as an Understanding mark?", "options": ["It only applies to businesses that sell more than one single product", "It is factually incorrect and does not relate to break-even in any real way", "It is tautological, using the term ''break-even'' to explain break-even itself", "It is too detailed and includes far more information than is needed"], "answer": 2, "explain": "The card explains this answer is tautological — you cannot explain break-even using the word ''break-even''; you must state what it actually means."}}, {"myth": "When asked about a limitation, students say ''the figures might be wrong'' or ''it is inaccurate''.", "truth": "This is too vague and scores zero marks. You must explain WHY the figures could be wrong — e.g., ''A new competitor could force the business to lower its price, reducing contribution per unit and raising the real break-even output above the forecast.''", "check": {"question": "Why does ''the figures might be wrong'' fail as an answer about a limitation?", "options": ["It correctly identifies the limitation without needing any more detail", "It is too vague — you must explain WHY the figures could be wrong", "It is completely incorrect, since break-even figures are never wrong", "It only applies to businesses that use a graph, not a formula"], "answer": 1, "explain": "The card explains this answer is too vague and scores zero — you must explain why the figures could be wrong, e.g. a new competitor forcing a price cut."}}, {"myth": "Students confuse ''margin of safety'' with ''profit''.", "truth": "The margin of safety is measured in UNITS (actual sales minus break-even sales). It shows how far output can fall before a loss is made. Profit is a financial value in £ (TR minus TC) — a completely different calculation.", "check": {"question": "What is the key difference between margin of safety and profit?", "options": ["Margin of safety can only be calculated once a business has already made a profit", "Margin of safety is measured in units, while profit is a financial value in pounds", "Profit is measured in units, while margin of safety is a financial value in pounds", "Margin of safety and profit are simply two different names for the same figure"], "answer": 1, "explain": "The card explains margin of safety (actual sales minus break-even sales) is measured in units, while profit (TR minus TC) is a financial value in pounds — a completely different calculation."}}, {"myth": "Students think any business can use break-even analysis equally well.", "truth": "Break-even works best for businesses selling a SINGLE product at a fixed price. For businesses with multiple products at varying prices and costs, break-even is difficult to calculate accurately and much less useful as a planning tool.", "check": {"question": "For which type of business does break-even analysis work best, according to this card?", "options": ["A business that has no variable costs of any kind to consider", "A business selling many different products at many different prices", "A business that has no fixed costs of any kind to consider", "A business selling a single product at one fixed price"], "answer": 3, "explain": "The card explains break-even works best for a single-product business at a fixed price; multi-product businesses with varying prices and costs find it far less useful."}}]}, "tips": {"enabled": true, "items": [{"title": "One Specific Point. One Sentence. Full Stop.", "html": "\n          <p>A 1-mark question needs exactly <strong>one correct, specific point</strong>. Do not write a paragraph — one focused sentence is more than enough.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li>One clear, specific, relevant point = <strong>1 mark ✅</strong></li>\n            <li>A vague or general statement = <strong>0 marks ❌</strong></li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br>\n          <em>\"Break-even helps a business.\"</em><br>\n          Too vague — doesn''t say what the business can actually do with break-even information.</p>\n    \n          <p><strong>✅ Good Answer (1 mark):</strong><br>\n          <em>\"Break-even analysis allows Virgin Atlantic to identify the minimum number of passengers needed on each flight to cover all operating costs.\"</em><br>\n          Specific, relevant, and applied to the business context.</p>\n    \n          <p><strong>⚠️ Examiner Warning:</strong> Do NOT define break-even when the question asks for a USE of it. Re-read the exact wording of the question before writing your answer. A definition of \"what break-even is\" when asked \"how can break-even be used\" will score zero.</p>\n        ", "check": {"question": "What mistake does this card warn against when a question asks for a USE of break-even?", "options": ["Writing more than one clear, specific point in the answer that is given", "Rounding the final numerical answer up instead of rounding it down", "Applying the given answer to a specific business named in the case study text", "Writing a definition of break-even instead of describing how it is actually used"], "answer": 3, "explain": "The card warns that defining ''what break-even is'' when the question asks ''how can break-even be used'' scores zero — always re-read the exact question wording."}}, {"title": "Make Your Point, Then Explain the ''Why''", "html": "\n          <p>A 2-mark question requires a <strong>point + explanation</strong>. State a fact, then immediately explain WHY or HOW it matters.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li><strong>Point (K — 1 mark):</strong> State the benefit, reason, or fact.</li>\n            <li><strong>Explanation (U — 1 mark):</strong> Explain why this matters or how it works.</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark max):</strong><br>\n          <em>\"Profit is important because it means the business has money.\"</em></p>\n    \n          <p><strong>✅ Good Answer (2 marks):</strong><br>\n          <em>\"Profit allows the business to invest in new equipment (K). This helps the business expand, replace worn-out assets, and remain competitive in its market in the long term (U).\"</em></p>\n    \n          <p><strong>⚠️ Examiner Warning — \"Survival\" Trap:</strong> Answers linking profit solely to survival were not awarded full marks in the exam. Survival is about cash flow, not profit. Focus on what profit <em>allows</em> the business to do: invest, expand, attract shareholders, repay debts, or develop new products.</p>\n        ", "check": {"question": "According to this card, why do answers linking profit solely to ''survival'' lose marks?", "options": ["Profit and survival always mean exactly the same thing in any answer", "Survival relates to cash flow, not profit, so the link is not fully accurate", "Survival is not a real business concept and should never be mentioned at all", "Survival can only be discussed in a 1-mark ''state'' question, not here"], "answer": 1, "explain": "The card explains survival is about cash flow, not profit — full marks require discussing what profit allows the business to do, such as invest or expand."}}, {"title": "Always Show Every Step of Your Working", "html": "\n          <p>Calculation questions are among the most predictable in the exam — but students still lose marks by not showing workings or forgetting to convert time periods.</p>\n    \n          <p><strong>The 3-Step Method:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Contribution:</strong> Selling price − variable cost per unit (1 mark)</li>\n            <li><strong>Step 2 — Divide:</strong> Fixed costs ÷ contribution, written clearly (1 mark)</li>\n            <li><strong>Step 3 — Final answer in UNITS:</strong> Write the number and the word \"units\" or the appropriate measure — never a £ sign (1 mark)</li>\n          </ul>\n    \n          <p><strong>⚠️ Watch for Multi-Step / Time Period Questions:</strong><br>\n          In the Sea View Hotel exam question, many students calculated the <em>weekly</em> break-even (105 rooms) instead of the <em>daily</em> break-even (15 rooms) — missing the final mark because they forgot to divide the weekly fixed costs by 7.<br>\n          <strong>Always re-read the question</strong> to check what time period is required.</p>\n    \n          <p><strong>⚠️ Add up ALL variable costs:</strong><br>\n          In the Luxury Cushions question, variable costs had three components (filling + cover + wage = £19 per unit). Students who missed one component got the wrong contribution and the wrong answer.</p>\n    \n          <p><strong>⚠️ Always round UP:</strong> If your answer is 583.3 → write 584. At 583 the business has not yet covered all its fixed costs.</p>\n        ", "check": {"question": "What error did many students make in the Sea View Hotel calculation question?", "options": ["They calculated the daily break-even instead of the required weekly figure", "They forgot to round their final answer to the nearest whole number", "They forgot to include the selling price anywhere in their calculation", "They calculated the weekly break-even instead of the required daily figure"], "answer": 3, "explain": "The card explains many students calculated the weekly break-even (105 rooms) instead of the required daily figure (15 rooms), missing a mark by not dividing by 7."}}, {"title": "The Holy Trinity: Understanding → Application → Analysis", "html": "\n          <p>The 3-mark analyse question is the most common written question on break-even. You <strong>must</strong> follow this exact structure to earn all 3 marks:</p>\n    \n          <ol>\n            <li><strong>Understanding (U) — 1 mark:</strong> State what the benefit/limitation IS. Explain the concept without using the term \"break-even\" tautologically.</li>\n            <li><strong>Application (APP) — 1 mark:</strong> Use a specific figure, name, or fact from the case study. Quote data from the text directly.</li>\n            <li><strong>Analysis (AN) — 1 mark:</strong> Explain the business-facing IMPACT. What does this mean FOR the business? Use language like \"this means that...\", \"as a result...\", \"this will lead to...\"</li>\n          </ol>\n    \n          <p><strong>Critical Rules:</strong></p>\n          <ul>\n            <li>You CANNOT score the Application mark without first scoring the Understanding mark.</li>\n            <li>Analysis must be <em>business-facing</em> — \"costs will increase\" alone is not enough. Say what the business must then DO as a result.</li>\n            <li>You cannot explain break-even by using the word \"break-even\": \"it helps GK know when it reaches break-even\" scores ZERO.</li>\n          </ul>\n    \n          <p><strong>Sentence Starters:</strong></p>\n          <ul>\n            <li><em>U: \"Break-even shows the point at which all costs are covered but no profit has yet been made...\"</em></li>\n            <li><em>APP: \"For [business name], this means that...\" / \"As the text states that [figure/fact]...\"</em></li>\n            <li><em>AN: \"As a result, the business will...\" / \"This means the business could...\" / \"This will lead to...\"</em></li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br>\n          <em>\"Break-even analysis helps GK know when it breaks even.\"</em></p>\n    \n          <p><strong>✅ Full-Mark Answer (3 marks):</strong><br>\n          <em>\"Break-even shows the point at which GK covers all of its costs but has not yet made a profit (U). GK''s break-even is 29 Deluxe kitchens per year (APP). This means the sales team can be set a target of selling more than 29 to move into profit, and GK can calculate its margin of safety to assess how resilient it is to falling consumer demand (AN).\"</em></p>\n        ", "check": {"question": "According to this card, what must happen before the Application mark can be awarded?", "options": ["A conclusion must already have been written out", "The Understanding mark must be scored first", "The Analysis mark must already have been scored", "A break-even graph must already have been drawn"], "answer": 1, "explain": "The card states you cannot score the Application mark without first scoring the Understanding mark — the U to APP to AN chain must be followed in order."}}, {"title": "Two Complete Chains of Analysis — No Conclusion Needed", "html": "\n          <p>A 6-mark question is simply <strong>two 3-mark analyse questions written in sequence</strong>. You need two completely separate points, each with a full U → APP → AN chain.</p>\n    \n          <p><strong>Structure:</strong></p>\n          <ul>\n            <li><strong>Point 1:</strong> Understanding (1 mark) → Application (1 mark) → Analysis (1 mark)</li>\n            <li><strong>Point 2:</strong> Understanding (1 mark) → Application (1 mark) → Analysis (1 mark)</li>\n          </ul>\n    \n          <p><strong>⚠️ Do NOT write a conclusion</strong> — there are zero marks available for evaluation in a 6-mark question. Every sentence must earn marks for U, APP, or AN. A conclusion wastes time and earns nothing.</p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> Do not list every limitation you know. Write two limitations in full — with application and analysis each time. A long bullet-point list of vague statements scores very poorly.</p>\n    \n          <p><strong>✅ Example — \"Analyse two limitations of Samantha''s break-even forecast\":</strong></p>\n          <p><em><strong>Limitation 1:</strong> A new competitor could enter the market, increasing competition (U). There are already two other cake decorating businesses in Samantha''s area (APP). If they reduce their prices, Samantha may have to follow — cutting her contribution per cake and pushing her break-even output above 30 cakes, making the forecast inaccurate (AN).</em></p>\n          <p><em><strong>Limitation 2:</strong> The cost of ingredients could rise unexpectedly (U). Samantha''s variable cost is currently £180 per cake (APP). If ingredient costs increase, her contribution per cake falls, meaning she would need to sell more than 30 cakes to break even — making her existing forecast an underestimate (AN).</em></p>\n        ", "check": {"question": "According to this card, should a 6-mark ''analyse two impacts'' answer include a conclusion?", "options": ["No — but only because the question does not require two points", "Yes — a strong conclusion is worth one of the six marks available", "Yes — without a conclusion the answer cannot be marked at all", "No — there are zero marks for evaluation, so a conclusion wastes time"], "answer": 3, "explain": "The card warns against writing a conclusion in a 6-mark question, since there are zero evaluation marks available — every sentence should earn U, APP or AN marks instead."}}]}, "exam": {"enabled": true, "questions": [{"question": "A manufacturer that makes and sells more than its break-even quantity will:", "marks": 1, "hint": "Think about what happens to profit when total revenue exceeds total costs.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Make a profit</h5><p><strong>Why B is correct:</strong> Once a business sells more units than its break-even output, total revenue exceeds total costs — a profit is made on every additional unit sold.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Incorrect:</strong> Insufficient revenue to cover costs describes what happens BELOW break-even. Above break-even, revenue more than covers all costs.</li><li><strong>C — Incorrect:</strong> Quality control is unrelated to the break-even quantity. Selling above break-even says nothing about product quality.</li><li><strong>D — Incorrect:</strong> An overdraft relates to a cash flow problem, not to selling above the break-even point. A business can be profitable but still have cash flow issues.</li></ul></div>"}, {"question": "Explain why profit is important to a business'' future. [2 marks]", "marks": 2, "hint": "Give ONE reason profit is important, then explain HOW or WHY this benefits the business. Do NOT simply define profit. Avoid linking profit to ''survival'' — that''s a cash flow point.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a + AO1b)</h5><p>One mark for identifying why profit is important, plus one further mark for explaining the benefit (how or why profit enables this).</p><p><strong>Acceptable identification points (1 mark):</strong></p><ul><li>To invest in new equipment / buildings (to replace worn-out items)</li><li>To help fund expansion (e.g. opening new hotels/stores)</li><li>To repay a loan or debt (so that future costs fall)</li><li>To pay dividends (which keeps shareholders satisfied)</li><li>To attract new investors (enabling further growth)</li><li>To develop new products (allowing more future profit)</li><li>To compare performance against competitors (using profitability ratios)</li></ul><p><strong>Note:</strong> Answers do NOT need to relate to The Sea View Hotel. No reward for a definition of profit. No reward for answers about \"allowing the business to survive.\"</p><p><strong>Examiner''s Comment:</strong> Most candidates achieved at least 1 mark. The most popular answer was expansion or growth. Many candidates failed to explain HOW or WHY the profit enables the benefit, missing the second mark. Answers mentioning \"survival\" confused profit with cash flow and did not score the second mark.</p></div>"}, {"question": "Calculate the daily break-even quantity for the proposed hotel. [3 marks]", "marks": 3, "hint": "The fixed costs are given WEEKLY — you must convert to a daily figure by dividing by 7 before using the formula. Your final answer should be in rooms per day, not pounds.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2)</h5><ul><li><strong>Mark 1:</strong> Correct contribution = £100 − £40 = £60 per room per day</li><li><strong>Mark 2:</strong> Correct daily fixed costs = £6,300 ÷ 7 = £900</li><li><strong>Mark 3 (OFR):</strong> Correct final answer = £900 ÷ £60 = <strong>15 rooms per day</strong></li></ul><p><strong>Alternative method (also earns full marks):</strong></p><ul><li>Contribution = £60 (1 mark)</li><li>Weekly break-even = £6,300 ÷ £60 = 105 (1 mark)</li><li>Daily break-even = 105 ÷ 7 = 15 rooms (1 mark OFR)</li></ul><p><strong>Partial credit:</strong> A total of 2 marks for arriving at 105 rooms (weekly break-even, without dividing by 7). Maximum 2 marks for an answer with the wrong units (e.g. £15).</p><p><strong>Examiner''s Comment:</strong> Even though the word ''daily'' was emboldened in the question, a significant number of candidates stopped at 105 rooms (the weekly break-even) and only gained 2 marks. Always re-read the question to check what time period the answer requires.</p></div>"}, {"question": "Analyse one disadvantage to the partnership if the proposed hotel''s fixed costs were 10% higher than expected. [3 marks]", "marks": 3, "hint": "Start with WHAT the disadvantage is (U). Then use a specific number from the case study — calculate the 10% increase (APP). Finally, explain the impact on Anika and Charlie''s business (AN). The analysis must be business-facing — ''costs will increase'' alone scores zero.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><p><strong>Understanding (1 mark) — a disadvantage of higher-than-expected fixed costs:</strong></p><ul><li>Could lead to lower profits or a loss</li><li>Increases the break-even level of output (harder to reach)</li><li>Could force a price increase</li><li>Less money available for day-to-day running of the hotel</li></ul><p><strong>Application (1 mark) — use of case study figures:</strong></p><ul><li>Fixed costs rise from £6,300 to £6,930 per week (10% increase = +£630)</li><li>That''s an extra £90 per day in fixed costs</li><li>Break-even rises from 15 rooms to approximately 17 rooms per day</li><li>Reference to the 25-room hotel, existing bank loan, or the £2m expansion cost</li></ul><p><strong>Analysis (1 mark) — business-facing impact:</strong></p><ul><li>The hotel must fill more rooms each day to cover the higher costs</li><li>Could make it harder to attract a new partner or investor like Finley</li><li>May lead to a need for additional finance or higher debt levels</li><li>Could prevent the partnership from repaying its existing bank loan</li></ul><p><strong>No reward for:</strong> \"Costs will increase\" (this is the given fact, not an analysis). Context about the existing hotel (e.g. \"it is already profitable\"). Answers about owner stress levels.</p><p><strong>Examiner''s Comment:</strong> Better answers showed understanding about profit or break-even, applied the specific numbers (£6,930 / 17 rooms), and explained the need to fill more rooms. This full-mark answer can be written in just two sentences.</p></div>"}, {"question": "Analyse how GK can use the break-even level of output for its Deluxe range. [3 marks]", "marks": 3, "hint": "Think about what knowing the break-even output (29 kitchens) ALLOWS GK to do. Do NOT say ''it shows them when they break even'' — this is tautological and scores zero. Think: sales targets, margin of safety, pricing decisions, securing finance.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><p><strong>Understanding (1 mark):</strong></p><ul><li>To identify when total revenue covers all total costs</li><li>To know the point at which a loss turns into a profit</li><li>To set clear sales targets for the team</li><li>To use alongside break-even diagrams for visual planning</li></ul><p><strong>Application (1 mark) — use of GK''s specific data:</strong></p><ul><li>Fixed costs = £250,000; Price = £15,000; Variable cost = £6,380 per kitchen</li><li>GK needs to sell 29 Deluxe kitchens to break even</li><li>Concerns about a future economic downturn</li><li>Forecast fall in consumer incomes / unemployment declining</li></ul><p><strong>Analysis (1 mark):</strong></p><ul><li>GK can calculate the margin of safety</li><li>GK can estimate profit at different sales volumes</li><li>GK can use the data when attracting investors or applying for finance</li><li>GK can make decisions about adjusting its price or reducing costs</li><li>GK may use the data to plan increased marketing spend to push sales above 29</li></ul><p><strong>⚠️ Zero marks for:</strong> \"It shows how many GK needs to sell to break even.\" This is tautological — you cannot define break-even by using the word \"break-even.\" The majority of candidates scored zero on this question for exactly this reason.</p><p><strong>Examiner''s Comment:</strong> Only a small number of candidates correctly recognised that break-even is used to identify when loss turns to profit and that knowing the output of 29 allows GK to calculate the margin of safety or make marketing/pricing decisions.</p></div>"}, {"question": "Analyse one limitation to GK of using break-even when making decisions about its Deluxe range. [3 marks]", "marks": 3, "hint": "Pick ONE specific reason the break-even forecast might be inaccurate for GK. Reference a figure or fact from the case study. Then explain what this means for GK''s decisions — do NOT just say ''the data is wrong.''", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><p><strong>Understanding (1 mark) — limitations include:</strong></p><ul><li>All data in break-even is estimated / a prediction</li><li>The number of competitors may change</li><li>The business may make promotional offers at a lower price</li><li>Costs may change unexpectedly</li><li>External economic factors may change</li><li>Qualitative / non-financial issues are not considered</li></ul><p><strong>Application (1 mark) — specific reference to GK:</strong></p><ul><li>GK''s variable cost of £6,380 per kitchen / price of £15,000</li><li>GK sells high-quality luxury kitchens — demand is sensitive to income changes</li><li>Forecast fall in consumer incomes across the south-east</li><li>Unemployment forecast to fall from 4.0% to 3.1% (suggesting more potential customers)</li></ul><p><strong>Analysis (1 mark):</strong></p><ul><li>GK may need to adjust its prices or costs to overcome uncertainty in the data</li><li>Sales targets may need to be constantly revised as circumstances change</li><li>A price cut to stimulate demand may not lead to an increase in revenue if demand is inelastic</li></ul><p><strong>⚠️ Zero marks for:</strong> Answers suggesting the data is \"wrong\" or \"inaccurate\" — this does not show understanding of WHY or HOW it could be inaccurate.</p><p><strong>Examiner''s Comment:</strong> Fewer than half of candidates gained at least 1 mark. Most correct answers noted data was estimated, but then failed to apply this to GK''s specific context or analyse the resulting impact on the business.</p></div>"}, {"question": "How many hours of gardening will Amaya need to do to start to make a profit?", "marks": 1, "hint": "Contribution = selling price − variable cost per hour. Break-even = fixed costs ÷ contribution. Remember to round UP your answer.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 1,385 hours</h5><p><strong>Working:</strong></p><ul><li>Contribution = £15 − £2 = £13 per hour</li><li>Break-even = £18,000 ÷ £13 = 1,384.6 → round UP = <strong>1,385 hours</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (1,059):</strong> Incorrect — results from using the wrong contribution figure, e.g. dividing by £17 (adding price + VC rather than subtracting).</li><li><strong>C (2,340):</strong> Incorrect — results from an error in dividing by the wrong number, possibly using the selling price alone as the denominator in a partial calculation.</li><li><strong>D (3,060):</strong> Incorrect — results from dividing fixed costs only by the variable cost (£18,000 ÷ £2 × something), ignoring the correct contribution formula entirely.</li></ul></div>"}, {"question": "How many one-hour lessons will Kim need to give before making a profit?", "marks": 1, "hint": "Contribution = price per lesson − variable cost. Break-even = fixed costs ÷ contribution. Remember to round UP.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 584 lessons</h5><p><strong>Working:</strong></p><ul><li>Contribution = £30 − £6 = £24 per lesson</li><li>Break-even = £14,000 ÷ £24 = 583.3 → round UP = <strong>584 lessons</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (389):</strong> Incorrect — results from using an incorrect contribution figure.</li><li><strong>B (467):</strong> Incorrect — results from dividing by the wrong number in the formula.</li><li><strong>D (2,334):</strong> Incorrect — results from dividing fixed costs by the variable cost only (£14,000 ÷ £6 = 2,333.3), completely ignoring the selling price in the contribution calculation.</li></ul></div>"}, {"question": "Calculate the break-even point for LC. Show your workings. [3 marks]", "marks": 3, "hint": "You need to add up ALL three variable costs per cushion first (filling + cover + wage). Then use the break-even formula. Show every step clearly.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1a + AO2)</h5><ul><li><strong>Mark 1:</strong> Correct formula stated: BE = FC ÷ (SP − VC)</li><li><strong>Mark 2:</strong> Correct use of figures: £7,440 ÷ (£50 − £19) = £7,440 ÷ £31</li><li><strong>Mark 3 (OFR):</strong> Correct answer = <strong>240 cushions per month</strong></li></ul><p><strong>Key workings:</strong></p><ul><li>Variable cost per unit = £3 + £6 + £10 = £19</li><li>Contribution = £50 − £19 = £31</li><li>Break-even = £7,440 ÷ £31 = 240 cushions</li></ul><p>Maximum 2 marks if wrong units (e.g. £240). OFR applies if the method is correct but figures are used incorrectly.</p></div>"}, {"question": "Analyse one way Elizabeth could use her break-even data. [3 marks]", "marks": 3, "hint": "Think about what knowing the break-even output (240 cushions) ALLOWS Elizabeth to do in practice. Consider: supporting her bank loan application, identifying margin of safety, changing her pricing strategy.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2 + AO3a)</h5><p><strong>Application (up to 2 marks) — using evidence from the text or the calculation:</strong></p><ul><li>Break-even of 240 cushions per month (OFR from part i)</li><li>She currently makes and sells 250 cushions per month</li><li>Margin of safety = 250 − 240 = 10 cushions per month</li><li>She is considering a bank loan of £30,000 for expansion</li><li>She wants to take over a competitor and move to larger premises</li><li>Reference to 2019 revenue of £150,000 or net profit of £56,800</li></ul><p><strong>Analysis (1 mark) — a specific use of break-even data:</strong></p><ul><li>Influence on pricing strategy</li><li>Helps plan to identify profit at different output levels</li><li>To support a bank loan application</li><li>To identify the margin of safety</li><li>To make informed decisions about whether to expand</li></ul><p><strong>Exemplar responses:</strong><br>\n    <em>\"Elizabeth could use the break-even data to support her application for a £30,000 bank loan (AN). The bank would be more willing to lend (APP) to help fund her expansion if she could show she already sells above her break-even output of 240 cushions, with a margin of safety of 10 cushions per month (APP).\"</em></p><p><em>\"Elizabeth could change her pricing strategy (AN). By increasing the price from £50 to £60, this would increase her contribution to £41 and reduce the break-even point to approximately 181 cushions (APP).\"</em></p></div>"}, {"question": "State one use of break-even to Virgin Atlantic. [1 mark]", "marks": 1, "hint": "Be specific — think about what knowing the minimum number of passengers per flight ALLOWS Virgin Atlantic to do operationally or strategically.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO2)</h5><p>One mark for a correct, specific statement of a use of break-even applied to Virgin Atlantic''s context.</p><p><strong>Acceptable answers include:</strong></p><ul><li>To identify the minimum number of passengers needed on each flight to cover all operating costs</li><li>To inform marketing decisions, such as how many tickets must be sold per flight</li><li>To inform planning decisions, such as how many planes / flights are needed to break even overall</li><li>To set a minimum sales target for ticket sales on each route</li><li>To calculate the margin of safety on ticket sales</li></ul></div>"}, {"question": "If Andrea paints and sells 50 portraits a year, total costs are estimated to be:", "marks": 1, "hint": "Convert monthly fixed costs to annual first (× 12). Then calculate total variable costs (VC per portrait × 50). Finally, add fixed and variable costs together.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £15,750 per year</h5><p><strong>Working:</strong></p><ul><li>Annual fixed costs = £1,000 × 12 = £12,000</li><li>Variable cost per portrait = £52 + £23 = £75</li><li>Total variable costs = £75 × 50 = £3,750</li><li>Total costs = £12,000 + £3,750 = <strong>£15,750</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (£1,075):</strong> Incorrect — results from simply adding £52 + £23 + £1,000 without multiplying by 50 portraits or converting monthly to annual FC. Completely ignores the quantities involved.</li><li><strong>B (£4,750):</strong> Incorrect — results from using the monthly fixed cost (£1,000) instead of the annual figure (£12,000), giving £3,750 + £1,000 = £4,750.</li><li><strong>C (£12,075):</strong> Incorrect — likely used only one variable cost component (e.g. just £52 or £23) rather than adding both together, then added the annual FC of £12,000.</li></ul></div>"}, {"question": "At break-even a firm''s total revenue equals its:", "marks": 1, "hint": "At break-even, the business makes no profit and no loss. What does this tell you about the relationship between revenue and costs?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Total costs</h5><p>At break-even, total revenue equals total costs (TR = TC). The business makes neither a profit nor a loss.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Fixed costs only:</strong> Total revenue must cover BOTH fixed AND variable costs to break even. Fixed costs alone understates the total costs the business must cover.</li><li><strong>B — Gross profit:</strong> Gross profit = revenue − cost of sales. At break-even, net profit is zero, but gross profit may still exist. Gross profit is not the same as total costs.</li><li><strong>C — Net profit:</strong> If TR equalled net profit, there would be no costs at all — this is clearly impossible for any real business.</li></ul></div>"}, {"question": "Calculate the number of sessions MD Sports Clinic would need to break-even in its first month of trading. Show your workings. [4 marks]", "marks": 4, "hint": "Use the full break-even formula and show every step. Four steps = four marks: (1) state the formula, (2) calculate the contribution, (3) divide FC by contribution, (4) state the final answer in sessions.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 4 marks (AO1a + AO2)</h5><ul><li><strong>Mark 1:</strong> Correct formula: FC ÷ (SP − VC)</li><li><strong>Mark 2:</strong> Correct contribution: £30 − £5 = £25</li><li><strong>Mark 3:</strong> Correct use of figures: £6,000 ÷ £25</li><li><strong>Mark 4 (OFR):</strong> Correct final answer = <strong>240 sessions</strong></li></ul><p>Award full marks for a correct final answer regardless of how workings are set out. Check workings and award marks as shown above if the final answer is incorrect. Award maximum 1 mark for a correct formula in the absence of any numerical workings. OFR applies throughout.</p></div>"}, {"question": "Which of the following is a limitation of break-even analysis?", "marks": 1, "hint": "Think about what break-even CANNOT do. Eliminate options A, C, and D by checking whether break-even CAN actually do those things.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — It cannot factor in seasonal pricing and price discounts</h5><p>Break-even assumes a single, fixed selling price throughout. It cannot account for price changes such as seasonal discounts, promotional pricing, or variable pricing strategies — all of which affect actual revenue differently at different points in time.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Incorrect:</strong> Break-even CAN be used to estimate profit at different output levels — by comparing TR with TC at any point on the graph or table.</li><li><strong>C — Incorrect:</strong> Showing how much a business must sell to cover its costs IS the core purpose and main strength of break-even analysis.</li><li><strong>D — Incorrect:</strong> By comparing TR and TC at various outputs (on a graph or in a table), break-even CAN show the level of profit or loss across a full range of outputs.</li></ul><p><strong>Examiner''s Comment:</strong> Many candidates chose A because they saw the word \"estimate\" and assumed it must be a limitation. This is a common trap — always read all four options carefully before selecting. Each MCQ is worth 1 mark and deserves at least a minute of careful thought.</p></div>"}, {"question": "Calculate how many cakes Samantha must sell to break even. [3 marks]", "marks": 3, "hint": "Use the standard break-even formula. Show all three steps — even if your final answer is wrong, you may still earn method marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2/Application)</h5><p>Calculates the break-even output using the data provided. One or two marks may be awarded where the final answer is incorrect but the method uses correct figures.</p><ul><li><strong>Mark 1:</strong> Correct contribution = £300 − £180 = £120</li><li><strong>Mark 2:</strong> Correct formula applied: £3,600 ÷ £120</li><li><strong>Mark 3:</strong> Correct answer = <strong>30 cakes per year</strong></li></ul><p>Method marks: one mark for using £3,600 in the numerator; one mark for using (£300 − £180) as the denominator.</p></div>"}, {"question": "Analyse one advantage to Samantha of calculating the break-even level of output. [3 marks]", "marks": 3, "hint": "Choose ONE advantage. Follow the U → APP → AN chain. The understanding mark needs you to explain what the advantage IS (without using ''break-even'' tautologically). Then apply it specifically to Samantha. Then explain the impact on Samantha''s business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><p><strong>Understanding (1 mark) — one advantage, e.g.:</strong></p><ul><li>Aid to planning (knowing how many to sell to cover costs)</li><li>Supporting a loan application to a bank</li><li>Helping make decisions about pricing and costs</li><li>Estimating the expected level of profit at different outputs</li><li>Identifying the margin of safety</li></ul><p><strong>Application (1 mark) — specific to Samantha''s situation:</strong></p><ul><li>Samantha must plan to sell at least 30 cakes to break even</li><li>Samantha can show the forecast to a bank manager when asking for a loan</li><li>If Samantha expects to sell more than 30, she knows she has a margin of safety</li></ul><p><em>Note: Application cannot be awarded without Understanding.</em></p><p><strong>Analysis (1 mark) — the effect on Samantha''s business:</strong></p><ul><li>If she expects to sell fewer than 30, she must change her plans — raise price, reduce costs, or find ways to increase sales</li><li>Knowing the margin of safety means she can assess how far demand could fall before she makes a loss</li><li>Presenting a break-even forecast to a bank manager helps convince them to provide a loan, as it shows careful planning</li></ul></div>"}, {"question": "Analyse two limitations to the break-even forecast that Samantha has calculated. [6 marks]", "marks": 6, "hint": "Write TWO separate paragraphs, each following the full U → APP → AN chain. Pick two DIFFERENT limitations and apply each one specifically to Samantha. Do NOT write a conclusion — there are zero evaluation marks available here.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (2× AO1b + 2× AO2 + 2× AO3a)</h5><p>Two lines of answer required, each demonstrating U + APP + AN.</p><p><strong>Understanding (2 marks — one per limitation):</strong></p><ul><li>The number of competitors / behaviour of competitors may change</li><li>Effect of promotional offers reducing actual price received</li><li>Changes in variable or fixed costs</li><li>External factors (e.g. economy) may affect demand</li></ul><p><strong>Application (2 marks — one per limitation, relating to Samantha''s case):</strong></p><ul><li>New competitors could enter the market, increasing competition in her area</li><li>Existing competitors could reduce their prices below £300</li><li>Samantha might sell for less than £300 initially as a promotional offer</li><li>The cost of cake ingredients (currently £180 per cake) may rise or fall</li></ul><p><strong>Analysis (2 marks — one per limitation):</strong></p><ul><li>Increased competition may force Samantha to lower her price, reducing contribution per cake and pushing her real break-even above 30 cakes</li><li>If competitors cut prices, Samantha may not achieve planned sales of 30, meaning she operates at a loss</li><li>A promotional offer brings in less revenue than forecasted, raising the actual break-even output</li><li>If ingredient costs rise, contribution falls and Samantha must sell more than 30 cakes to break even — making the forecast an underestimate</li><li>Changes to break-even output will affect the margin of safety and could change the viability of the business</li></ul></div>"}, {"question": "Calculate the total variable cost of producing 20,000 pallets. [2 marks]", "marks": 2, "hint": "Total variable cost = variable cost per unit × quantity produced. Show your working.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2/Application)</h5><ul><li><strong>Mark 1:</strong> Correct method shown: 20,000 × £9</li><li><strong>Mark 2:</strong> Correct answer: <strong>£180,000</strong></li></ul><p>2 marks for the correct answer. 1 mark if a correct method is shown but the answer is incorrect.</p></div>"}, {"question": "Calculate the total costs of producing 20,000 pallets. [2 marks]", "marks": 2, "hint": "Total costs = total fixed costs + total variable costs. Use your answer from part (i) for the variable costs.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2/Application)</h5><ul><li><strong>Mark 1:</strong> Correct method: £40,000 + £180,000</li><li><strong>Mark 2:</strong> Correct answer: <strong>£220,000</strong></li></ul><p>OFR applies from part (i).</p></div>"}, {"question": "Calculate the total revenue from selling 20,000 pallets. [2 marks]", "marks": 2, "hint": "Total revenue = selling price × quantity sold. Use the price stated in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2/Application)</h5><ul><li><strong>Mark 1:</strong> Correct method: 20,000 × £10</li><li><strong>Mark 2:</strong> Correct answer: <strong>£200,000</strong></li></ul><p>Note: Helle would make a LOSS of £20,000 at this output and price (TC = £220,000 > TR = £200,000). The current price of £10 does not cover all costs.</p></div>"}, {"question": "Calculate the price that Helle must charge on average for each pallet for Bentham Pallets to break even. [2 marks]", "marks": 2, "hint": "To break even, total revenue must equal total costs. If she produces and sells 20,000 pallets, divide the total costs (from part a ii) by 20,000 to find the minimum price per pallet.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2/Application)</h5><ul><li><strong>Mark 1:</strong> Correct method: £220,000 ÷ 20,000</li><li><strong>Mark 2:</strong> Correct answer: <strong>£11 per pallet</strong></li></ul><p>OFR from part a(ii) applies. 2 marks for the correct answer; 1 mark if a correct method is used but the final figure is incorrect.</p></div>"}, {"question": "Analyse one way in which the start-up of a new firm selling pallets in the same area might affect Bentham Pallets'' business. [3 marks]", "marks": 3, "hint": "Think about what a new competitor could do — reduce Helle''s price, lower her sales volume, or increase costs. Then link this back to what it means for Bentham Pallets'' break-even output.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><p><strong>Understanding (1 mark):</strong></p><ul><li>The price Helle can charge may have to be lower</li><li>Variable costs may rise (increased demand for raw materials)</li><li>Helle''s sales volume may decrease if customers switch to the new competitor</li></ul><p><strong>Application (1 mark) — using case study data:</strong></p><ul><li>The average price Helle achieves may fall below £10</li><li>The increased demand for raw materials (wood and nails) may push variable costs above £9 per pallet</li><li>Helle may sell fewer than the 20,000 pallets she currently forecasts</li></ul><p><strong>Analysis (1 mark):</strong></p><ul><li>A fall in price would mean Helle''s break-even output increases (beyond the current 20,000 pallets)</li><li>A rise in variable costs reduces contribution per pallet and raises the break-even price above £11</li><li>A fall in sales means Helle may not sell enough to cover all her costs, causing a loss</li></ul></div>"}]}}'::jsonb),
('business', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential definitions you <strong>must</strong> know for 5.5 Cash and Cash Flow.</p>\n<ul>\n<li><strong>Cash Flow Forecast:</strong> A statement showing the expected flow of money into and out of a business over a period of time.</li>\n<li><strong>Net Cash Flow:</strong> Total inflow minus total outflow for a given period.</li>\n<li><strong>Opening Balance:</strong> The amount of cash available at the beginning of the month — it is always the closing balance from the previous month.</li>\n<li><strong>Closing Balance:</strong> The amount of cash left at the end of the month. This becomes the opening balance for the next month.</li>\n<li><strong>Total Inflow:</strong> The total amount of cash flowing into a business in a given period.</li>\n<li><strong>Total Outflow:</strong> The total amount of cash flowing out of a business in a given period.</li>\n<li><strong>Positive Cash Flow:</strong> When more cash flows into the business than flows out during a month (also called a cash flow surplus).</li>\n<li><strong>Negative Cash Flow:</strong> When more cash flows out of the business than flows in during a month (also called a cash flow deficit).</li>\n<li><strong>Liquidity:</strong> The ability of a business to pay its short-term debts which must be paid in the near future.</li>\n<li><strong>Cash:</strong> Not simply notes and coins — also includes money held in a bank account.</li>\n<li><strong>Profit:</strong> The revenue received by a business minus the total costs of running that business.</li>\n<li><strong>Income / Revenue:</strong> Money that the business receives.</li>\n<li><strong>Expenditure:</strong> Money that the business pays out.</li>\n<li><strong>Short-term debts / expenses:</strong> Bills that a business has to pay in the near future, such as electricity, wages, or rent.</li>\n</ul>", "check": {"question": "According to the key definitions, what is the ''opening balance'' for a month?", "options": ["The total inflow received during the current month alone", "The closing balance carried over from the previous month", "The total outflow paid out during the current month", "The net cash flow calculated for the current month"], "answer": 1, "explain": "The card defines the opening balance as always being the closing balance from the previous month — it carries straight over rather than being freshly calculated."}}, {"title": "The Importance of Cash to a Business", "html": "<p>A business needs cash to survive day-to-day, even if it is making a good profit. Cash is used to pay for <strong>short-term expenses and debts</strong> — the bills that arrive regularly and must be paid promptly.</p>\n<p>Examples of what cash is needed for include:</p>\n<ul>\n<li>Wages and salaries for staff</li>\n<li>Rent on premises</li>\n<li>Paying suppliers for stock and raw materials</li>\n<li>Heating, lighting and utility bills</li>\n</ul>\n<p>If these are not paid on time, the consequences can be severe: suppliers may stop delivering, staff may leave, landlords may evict the business, or creditors may force the business to close.</p>\n<h4>Liquidity</h4>\n<p><strong>Liquidity</strong> is the ability of a business to turn its assets into cash quickly enough to pay its short-term debts. A business with poor liquidity cannot pay its bills even if it owns valuable assets (such as machinery or property). A lack of liquidity is one of the main reasons businesses are forced to close — even profitable ones. Creditors (people owed money) can legally force the business to be sold so that debts are repaid from the proceeds.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: Broder Metals Group</h4>\n<p>Broder Metals Group supplies high-quality alloys to power stations, aircraft manufacturers, Formula 1 teams and oil exploration companies. They must order stock up to 12 months in advance. When events like the 2015 oil-price collapse reduced demand, Broder still had to pay wages, rent and suppliers — even though revenue had dropped significantly.</p>\n<p>To stay on top of this, Broder prepares annual budgets and monitors actual cash against the forecast every month. If a shortfall looks likely, they take action early: reducing prices to boost sales, or contacting the bank about available facilities. As their Finance Director states: \"Cash flow is fundamental — get it wrong and the company will fail.\"</p>\n<p><strong>Takeaway:</strong> Even a business selling to major industries can face a cash crisis if it fails to plan. Monitoring cash flow is not optional — it is fundamental to survival.</p>\n</div>", "check": {"question": "According to this card, what is ''liquidity''?", "options": ["The ability of a business to turn assets into cash to pay short-term debts", "The amount of stock a business currently holds in its warehouse", "The total revenue a business receives from selling its products", "The total profit a business has made over its last full financial year"], "answer": 0, "explain": "The card defines liquidity as a business''s ability to turn assets into cash quickly enough to pay short-term debts — poor liquidity can force even profitable businesses to close."}}, {"title": "Cash vs Profit: A Critical Distinction", "html": "<p>This is the most important distinction in this topic — and the one students most commonly confuse in the exam. Examiners consistently report that candidates lose marks by mixing these two concepts up.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">💰 Cash</div>\n<div class=\"pro-item\"><strong>What it is:</strong> Money held in bank accounts and on the premises, used to pay day-to-day expenses and short-term debts right now.</div>\n<div class=\"pro-item\"><strong>When it matters:</strong> Today — can you physically pay your bills this week?</div>\n<div class=\"pro-item\"><strong>Shown in:</strong> A cash flow forecast.</div>\n<div class=\"pro-item\"><strong>Formula:</strong> Cash = Opening Balance + Cash Received − Cash Paid</div>\n</div>\n<div>\n<div class=\"col-head\">📈 Profit</div>\n<div class=\"con-item\"><strong>What it is:</strong> Total revenue minus total costs. A calculated figure summarising whether the business has earned more than it spent over a period.</div>\n<div class=\"con-item\"><strong>When it matters:</strong> At the end of a trading period — did the business make money overall?</div>\n<div class=\"con-item\"><strong>Shown in:</strong> An income statement (profit and loss account).</div>\n<div class=\"con-item\"><strong>Formula:</strong> Profit = Revenue − Total Costs</div>\n</div>\n</div>\n<p><strong>Key insight:</strong> A business can be profitable but still run out of cash. For example, if a large customer owes the business £50,000 but hasn''t paid yet, the business has high revenue on paper but no cash to pay wages this week. This is sometimes called being \"cash poor but profit rich.\"</p>\n<p>Equally, a business can have lots of cash (e.g. from a bank loan) but still be making a loss.</p>\n<p><strong>Examiner warning:</strong> \"A business needs cash to survive\" is NOT the same as \"cash = profit.\" Never write that a cash flow forecast shows profit — it does not. The forecast only shows cash movements.</p>", "check": {"question": "According to this card, what is the key insight about cash and profit?", "options": ["A cash flow forecast shows the same information as a profit calculation", "A business can never be profitable if it also has plenty of cash", "A business can be profitable on paper but still run out of cash", "Cash and profit are always exactly equal at the end of a trading period"], "answer": 2, "explain": "The card''s key insight is that a business can be ''cash poor but profit rich'' — profitable on paper but unable to pay bills if customers haven''t paid yet."}}, {"title": "How to Read and Complete a Cash Flow Forecast", "html": "<p>A cash flow forecast is a table showing predicted cash inflows and outflows over a number of months. Mastering the three formulas below will allow you to calculate any missing figure.</p>\n<div class=\"formula-box\">\n<strong>Net Cash Flow</strong> = Total Inflow − Total Outflow<br><br>\n<strong>Closing Balance</strong> = Opening Balance + Net Cash Flow<br><br>\n<strong>Opening Balance</strong> = Closing Balance of the previous month\n</div>\n<p>A worked example for HMJA Fashion (a business selling teenage clothes):</p>\n<table class=\"case-table\"><caption>Table 1 — HMJA Fashion Cash Flow Forecast</caption><tr><th></th><th>October £</th><th>November £</th><th>December £</th></tr><tr><td>Revenue (Total Inflow)</td><td>30,000</td><td>40,000</td><td>55,000</td></tr><tr><td>Wages</td><td>6,000</td><td>7,500</td><td>10,000</td></tr><tr><td>Overheads</td><td>3,500</td><td>3,500</td><td>4,000</td></tr><tr><td>Stock</td><td>35,000</td><td>15,000</td><td>10,000</td></tr><tr><td><strong>Total Outflow</strong></td><td><strong>44,500</strong></td><td><strong>26,000</strong></td><td><strong>24,000</strong></td></tr><tr><td><strong>Net Cash Flow</strong></td><td><strong>−14,500</strong></td><td><strong>14,000</strong></td><td><strong>31,000</strong></td></tr><tr><td>Opening Balance</td><td>1,000</td><td>−13,500</td><td>500</td></tr><tr><td><strong>Closing Balance</strong></td><td><strong>−13,500</strong></td><td><strong>500</strong></td><td><strong>31,500</strong></td></tr></table>\n<p><strong>October step-by-step:</strong> Net Cash Flow = £30,000 − £44,500 = <strong>−£14,500</strong>. Closing Balance = £1,000 + (−£14,500) = <strong>−£13,500</strong>. This negative closing balance carries forward as November''s opening balance.</p>\n<p>Notice: the negative October was planned — the business bought Christmas stock early. By December, cash has recovered strongly. A single negative month is not automatically a crisis.</p>", "check": {"question": "According to this card, why was HMJA Fashion''s negative October balance not automatically a crisis?", "options": ["The negative balance was a permanent feature of every month of the year", "The business had already closed down permanently by the end of October", "It was a planned outflow for buying Christmas stock early, and cash recovered later", "HMJA Fashion had no outflows at all recorded during that particular month of trading"], "answer": 2, "explain": "The card explains the negative October balance was planned (buying Christmas stock early), and cash recovered strongly by December — a single negative month is not automatically a crisis."}}, {"title": "The Usefulness of Cash Flow Forecasting", "html": "<p>A cash flow forecast is one of the most important planning tools a business can use. Evaluating its usefulness is a very common exam question — especially at 7 marks.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits (Why it is useful)</div>\n<div class=\"pro-item\"><strong>1. Planning tool:</strong> The forecast can be shown to banks to help secure a loan or overdraft. It demonstrates the business has thought carefully about its financial future.</div>\n<div class=\"pro-item\"><strong>2. Anticipates cash shortages:</strong> By looking ahead, the business can see months where cash may run low — giving time to act before the problem becomes serious.</div>\n<div class=\"pro-item\"><strong>3. Enables remedies:</strong> Once a shortage is spotted in advance, solutions can be arranged — such as an overdraft, delaying purchases, or chasing unpaid invoices.</div>\n<div class=\"pro-item\"><strong>4. Provides targets:</strong> The forecast helps the business set spending targets to ensure there is always enough cash, and may identify a need to build up a cash surplus.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Limitations (Why it may not always be useful)</div>\n<div class=\"con-item\"><strong>Only an estimate:</strong> A forecast is a prediction — it cannot be 100% accurate. Circumstances can change unexpectedly.</div>\n<div class=\"con-item\"><strong>Supplier price changes:</strong> Unexpected cost increases (e.g. raw materials rising) make the outflow figures immediately inaccurate.</div>\n<div class=\"con-item\"><strong>External shocks:</strong> A pandemic, new competitor, or economic recession can make even well-researched forecasts unreliable very quickly.</div>\n<div class=\"con-item\"><strong>Short-term reliability only:</strong> Short-term forecasts (weeks/months ahead) are far more reliable than long-term ones (1+ years ahead).</div>\n</div>\n</div>", "check": {"question": "According to this card, why are short-term cash flow forecasts more reliable than long-term ones?", "options": ["Short-term forecasts always show a bigger cash surplus than long-term ones", "Circumstances are less likely to change unexpectedly over a shorter period", "Short-term forecasts do not need to include any outflow figures at all", "Long-term forecasts are not allowed to be shown to a bank manager"], "answer": 1, "explain": "The card lists short-term reliability as a limitation of forecasting in general — short-term forecasts (weeks/months) are far more reliable than long-term ones (1+ years) since less can change unexpectedly."}}, {"title": "Solving a Cash Flow Problem", "html": "<p>When a business identifies a negative cash flow in its forecast, it has several options. The best solution depends on <strong>how long the shortage will last</strong>, <strong>how significant it is</strong>, and the specific situation of the business.</p>\n<ul>\n<li><strong>Arrange an overdraft:</strong> A short-term bank facility allowing spending beyond the balance. Quick to arrange but carries interest charges.</li>\n<li><strong>Reduce expenses:</strong> Cut non-essential costs to reduce outflows (e.g. delay new equipment purchases or reduce stock orders).</li>\n<li><strong>Raise prices:</strong> Higher prices increase inflows, though this risks losing customers to competitors.</li>\n<li><strong>Chase customers for payment:</strong> Send invoices promptly and reduce the credit period given to customers so money arrives faster.</li>\n<li><strong>Delay payment of bills:</strong> Negotiate with suppliers to pay later — this keeps cash in the business for longer without borrowing.</li>\n<li><strong>Cut stock levels:</strong> Ordering less stock reduces outflows and frees up cash tied up in unsold inventory.</li>\n<li><strong>Sell assets:</strong> Selling unused equipment or property raises a one-off cash inflow.</li>\n<li><strong>Seek additional finance:</strong> A bank loan or new investor/partner provides an immediate cash injection.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: The Deltic Group (2021)</h4>\n<p>The Deltic Group owned 53 nightclubs in the UK, valued at £80 million. During the Covid-19 pandemic, nightclubs were forced to close. With almost no revenue (only £80,000/month from a few bars), Deltic still faced £1 million per month in rent alone — plus utility bills, wages, and over £17 million in accumulated debt. Despite some government support, the cash flow problem became unsolvable. Unable to keep up with debts and with no certainty of when clubs could reopen, the owners were forced to sell the entire business to a Scandinavian company for just £10 million.</p>\n<p><strong>Takeaway:</strong> Even a large, established, and previously profitable business can be destroyed by a sustained cash flow problem. The business was not unprofitable by nature — it ran out of cash. This is why monitoring and planning cash flow is fundamental to business survival.</p>\n</div>", "check": {"question": "According to the Deltic Group case study, what ultimately happened to the business?", "options": ["It successfully expanded into new nightclub locations across the entire country", "It was forced to sell the entire business due to an unsolvable cash flow problem", "It made significant profits throughout the entire Covid-19 pandemic period", "It received enough government support to fully cover all of its debts"], "answer": 1, "explain": "The card explains Deltic''s cash flow problem became unsolvable during the pandemic, forcing owners to sell the business for far less than its previous value."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Cash Flow Forecast", "definition": "A statement predicting the flow of cash into and out of a business over a future period of time."}, {"term": "Net Cash Flow", "definition": "Total Inflow − Total Outflow. Positive = more came in; negative = more went out."}, {"term": "Closing Balance", "definition": "Opening Balance + Net Cash Flow. Becomes the next month''s opening balance."}, {"term": "Liquidity", "definition": "The ability of a business to pay its short-term debts as they fall due."}, {"term": "Negative Cash Flow", "definition": "When more cash flows out of a business than flows in during a period — a cash flow deficit."}, {"term": "Overdraft", "definition": "A short-term bank facility allowing a business to spend more than its current balance up to an agreed limit."}, {"term": "Cash vs Profit", "definition": "Cash = money available now to pay bills. Profit = Revenue − Total Costs (a calculated summary figure). They are NOT the same."}, {"term": "Opening Balance", "definition": "The cash available at the start of a month — always the same as the previous month''s closing balance."}, {"term": "4 Uses of Cash Flow Forecast", "definition": "1. Planning tool (for bank loans) 2. Anticipates cash shortages 3. Enables remedies 4. Provides targets."}, {"term": "Expenditure", "definition": "Money that the business pays out — e.g. wages, rent, materials, utilities."}, {"term": "4 Ways to Improve Cash Flow", "definition": "1. Arrange overdraft 2. Reduce expenses 3. Chase customer payments 4. Delay paying suppliers."}, {"term": "Why Cash is Important", "definition": "To pay SHORT-TERM expenses and debts: wages, rent, suppliers, utilities. Not for long-term investment."}, {"term": "Limitation of Cash Flow Forecast", "definition": "It is only an estimate — supplier prices may change, competitors may arrive, or unexpected events (e.g. pandemic) may occur."}, {"term": "Total Outflow", "definition": "The total amount of all cash payments leaving the business in a given period (wages + rent + materials + overheads etc.)."}, {"term": "Cash Flow Deficit / Surplus", "definition": "Deficit = negative cash flow (more out than in). Surplus = positive cash flow (more in than out)."}]}, "mcq": {"enabled": true, "questions": [{"question": "A business has a net profit of £44,000 for the year but is £5,000 overdrawn at the bank. What does this tell us?", "options": ["An accounting error has been made because the business is not profitable", "At least £49,000 must have been stolen from the business", "Despite being profitable, the business may be unable to pay its short-term debts", "The business is highly profitable and unlikely to experience cash shortages"], "answer": 2, "explain": "Correct: This illustrates the key difference between cash and profit. The business has made a profit (revenue exceeded costs) but has run out of cash — possibly because customers haven''t paid yet, or large investments were made. A = wrong because profit and cash are different; a business can have both. B = there is no evidence of theft. D = wrong because the overdraft shows it IS experiencing cash shortages right now."}, {"question": "Which of the following is the correct formula for net cash flow?", "options": ["Opening balance minus closing balance", "Total outflow minus total inflow", "Total inflow minus total outflow", "Closing balance minus opening balance"], "answer": 2, "explain": "Correct: Net cash flow = Total Inflow − Total Outflow. A = that formula gives the change in balance, not net cash flow. B = this is the wrong way round and would give a negative when the business is doing well. D = closing minus opening gives the same result as net cash flow numerically, but the formula refers to inflows and outflows."}, {"question": "A cash flow forecast is most useful for helping a business to:", "options": ["Calculate net profit for the year", "Identify changes in the market", "Predict liquidity problems before they occur", "Understand the concept of break-even"], "answer": 2, "explain": "Correct: A cash flow forecast predicts when cash may run short — i.e. a potential liquidity problem — so the business can act in advance. A = a cash flow forecast does NOT show profit; that is done using the income statement. B = market analysis is a separate activity. D = break-even analysis uses costs and selling price, not a cash flow forecast."}, {"question": "A manufacturer is experiencing a range of problems. Which of the following would be classed as a ''liquidity problem''?", "options": ["A breakdown on the production line", "Being short of funds to pay suppliers", "Experiencing high levels of wastage during production", "Having insufficient financial information to make decisions"], "answer": 1, "explain": "Correct: Liquidity is the ability to pay short-term debts. Being unable to pay suppliers is a classic liquidity problem — not enough cash to meet immediate obligations. A = a production breakdown is an operational problem, not a financial one. C = wastage is an efficiency/quality problem. D = lack of information is a management/planning issue."}, {"question": "A business will make a profit if it:", "options": ["Ends the year with a positive bank balance", "Exceeds its break-even quantity", "Has costs that are greater than its revenues", "Pays off all of its debts"], "answer": 1, "explain": "Correct: At break-even, revenue exactly equals total costs. Selling more than the break-even quantity means revenue exceeds total costs — which is the definition of profit. A = a positive bank balance shows liquidity, not profitability (it could come from a loan). C = if costs exceed revenue, the business makes a LOSS, not a profit. D = paying off debts is about solvency, not profitability."}, {"question": "A company has made a net profit of £16,000. Which statement must be true?", "options": ["The company has at least £16,000 in its bank account", "The company will have no difficulty paying its bills", "The company''s cash outflows were £16,000 more than its cash inflows", "The company''s revenue exceeded its total costs"], "answer": 3, "explain": "Correct: Net profit = Revenue − Total Costs. If net profit is positive, revenue must have exceeded costs — that is what profit means. A = the business might have already spent or invested that profit money; cash and profit are separate. B = a profitable business can still have cash flow problems and struggle to pay bills. C = that would describe a net CASH OUTFLOW of £16,000, not profit — completely different concept."}, {"question": "A cash flow shortage in a business is most often solved in the short term by arranging:", "options": ["An overdraft", "A long-term bank loan", "Crowdfunding", "Selling new shares"], "answer": 0, "explain": "Correct: An overdraft is specifically designed for short-term cash shortages — it gives the business immediate access to extra funds up to an agreed limit. B = a bank loan is a long-term source of finance, not suited to short-term cash gaps, and takes time to arrange. C = crowdfunding takes considerable time and effort to set up. D = selling shares is a long-term method of raising capital used by limited companies, not a quick fix for a cash shortage."}, {"question": "An extract from a cash flow forecast shows: Total Inflow £28,000 | Total Outflow £18,500 | Net Cash Flow £9,500 | Opening Balance −£4,700. What is the closing balance?", "options": ["£4,700", "£4,800", "£14,200", "£14,300"], "answer": 1, "explain": "Correct: Closing Balance = Opening Balance + Net Cash Flow = −£4,700 + £9,500 = £4,800. A = £4,700 is the opening balance with its sign removed — a common error. C = £14,200 would result from adding £9,500 to £4,700 (ignoring the negative sign). D = a rounding error — always be precise with negative opening balances."}, {"question": "An extract shows: Net Cash Flow −£2,600 | Closing Balance −£7,300. What is the opening balance for this month?", "options": ["−£9,900", "−£4,700", "£4,700", "£9,900"], "answer": 1, "explain": "Correct: Rearranging: Opening Balance = Closing Balance − Net Cash Flow = −£7,300 − (−£2,600) = −£7,300 + £2,600 = −£4,700. A = −£9,900 results from adding both negative figures together. C = £4,700 ignores the negative sign. D = £9,900 adds the absolute values incorrectly."}, {"question": "What is the difference between cash and profit?", "options": ["Cash and profit are the same thing — both measure how much money a business has made", "Cash is money available to pay immediate bills; profit is revenue minus total costs over a period", "Profit is the money in the bank; cash is calculated by subtracting costs from revenue", "Cash refers to money earned from sales; profit refers to money received from investors"], "answer": 1, "explain": "Correct: Cash is the money physically available (in bank accounts/on premises) to pay short-term debts right now. Profit is a calculated financial figure showing whether revenue exceeded costs over a period. A = confusing these two is the most common examiner-noted misconception at GCSE. C = has the definitions backwards. D = both definitions are incorrect."}, {"question": "Which of the following is an example of a cash inflow for a retail business?", "options": ["Paying wages to shop staff", "Purchasing new stock from a supplier", "Revenue received from customers buying goods", "Paying the monthly rent on the shop premises"], "answer": 2, "explain": "Correct: A cash inflow is money coming INTO the business. Revenue from customers is the main inflow for a retail business. A = paying wages is a cash OUTFLOW. B = purchasing stock is a cash OUTFLOW (money leaves the business to pay the supplier). D = paying rent is a cash OUTFLOW."}, {"question": "A business has a closing balance of −£3,500 at the end of March. What does this tell us?", "options": ["The business has made a loss of £3,500 in March", "The business has spent £3,500 more than it earned in March", "The business has an overdraft situation — it owes its bank £3,500", "The business is definitely going to close down"], "answer": 2, "explain": "Correct: A negative closing balance means the business has spent more than it has received in total, resulting in a deficit — effectively an overdrawn position at the bank. A = a negative closing balance is not the same as a loss; profit is calculated separately. B = the negative closing balance reflects the cumulative position, not just that one month''s activity. D = a single negative closing balance does not mean the business will close; it may be temporary and manageable."}]}, "fib": {"enabled": true, "questions": [{"text": "Net cash flow is calculated by subtracting [total outflow] from [total inflow]."}, {"text": "The [closing] balance of one month becomes the [opening] balance of the following month."}, {"text": "A business can be [profitable] but still have a negative cash flow if customers have not yet paid their invoices."}, {"text": "[Liquidity] is the ability of a business to pay its short-term debts in the near future."}, {"text": "A cash flow forecast is only an [estimate] of future income and expenditure — it is not guaranteed to be accurate."}, {"text": "An [overdraft] is a common short-term solution to a cash flow problem, allowing the business to spend beyond its bank balance."}, {"text": "Total [outflow] includes items such as wages, rent, materials and utilities paid out by the business."}, {"text": "A cash flow forecast can be shown to a [bank] to help the business secure a loan or other form of finance."}, {"text": "Short-term cash flow forecasts are generally more [accurate] than long-term forecasts because there is less uncertainty."}, {"text": "If a business has a negative closing balance for several consecutive months, it may have to close — not because it is unprofitable, but because it has run out of [cash]."}, {"text": "Closing Balance = [Opening] Balance + Net Cash Flow."}, {"text": "[Profit] is the revenue received by a business minus the total costs of running that business."}]}, "tf": {"enabled": true, "questions": [{"statement": "A negative net cash flow in one month always means the business is making a loss.", "answer": false, "explain": "FALSE. Net cash flow and profit are completely different. A business can have a negative cash flow in one month (e.g. because it paid for a lot of stock in advance) while still being highly profitable overall. For example, HMJA Fashion had a negative cash flow in October when buying Christmas stock, but made a strong profit across the year."}, {"statement": "The closing balance of one month becomes the opening balance of the next month.", "answer": true, "explain": "TRUE. This is one of the key mechanics of a cash flow forecast. The cash remaining at the end of one period carries forward as the starting point for the next. This is why a large negative closing balance in one month immediately makes the following month more difficult."}, {"statement": "A business that is profitable will always have enough cash to pay its bills on time.", "answer": false, "explain": "FALSE. A business can be profitable on paper but still run out of cash — for example, if customers are slow to pay invoices, or if large expenses fall due before revenue arrives. This is called being ''cash poor but profit rich.'' This distinction is frequently tested in exams."}, {"statement": "A cash flow forecast shows predicted future cash movements, not actual historical figures.", "answer": true, "explain": "TRUE. A cash flow forecast is exactly that — a forecast, i.e. an estimate of what is expected to happen in the future. It is not the same as a bank statement (which shows actual past transactions). Because it is a prediction, it will not always be perfectly accurate."}, {"statement": "Net cash flow is calculated by subtracting total inflow from total outflow.", "answer": false, "explain": "FALSE. The correct formula is Net Cash Flow = Total Inflow − Total Outflow (inflow minus outflow, not the other way around). Reversing the formula would give a negative number when the business is doing well, and a positive number when it is struggling — the complete opposite of what is correct."}, {"statement": "Cash includes only physical notes and coins held on the business premises.", "answer": false, "explain": "FALSE. Cash is defined as money held in bank accounts as well as any notes and coins on the premises. In the modern business world, most cash is held electronically in bank accounts. A business could have thousands of pounds in ''cash'' without holding a single banknote."}, {"statement": "A business with a negative cash flow for several months in a row faces a serious risk of being forced to close.", "answer": true, "explain": "TRUE. If negative cash flow continues over multiple months, the business may not be able to pay its suppliers, staff, or landlord. Creditors can apply to a court to force the business to sell its assets and close down. This can happen even to profitable businesses — as shown by the Deltic Group case study."}, {"statement": "An overdraft is the most common short-term solution to a cash flow problem.", "answer": true, "explain": "TRUE. An overdraft allows a business to spend beyond its bank balance up to an agreed limit. It is specifically designed for short-term shortfalls and can usually be arranged quickly with a bank. Interest is only charged on the amount overdrawn, making it efficient for temporary problems."}, {"statement": "A cash flow forecast can be useful when a business applies for a bank loan.", "answer": true, "explain": "TRUE. Presenting a well-prepared cash flow forecast to a bank demonstrates that the business has carefully planned its financial future. It shows the bank that the business understands when money will come in and go out, and that it will be able to afford loan repayments."}, {"statement": "Profit is simply the amount of money a business has in its bank account at any given time.", "answer": false, "explain": "FALSE. The money in a bank account is cash — not profit. Profit is a calculated figure: Revenue − Total Costs, determined at the end of a trading period. A business might have £500 in the bank (cash) but have made £20,000 in profit over the year. These are completely different measurements."}, {"statement": "Long-term cash flow forecasts are more reliable than short-term ones.", "answer": false, "explain": "FALSE. It is the other way around. Short-term forecasts (e.g. for the next month or few months) are far more reliable because there is less time for unexpected changes to occur. The further ahead you forecast, the more uncertain the figures become — supplier prices may change, new competitors may arrive, or the economy may shift."}, {"statement": "A positive net cash flow guarantees that a business is profitable.", "answer": false, "explain": "FALSE. A positive net cash flow simply means more cash came in than went out that month. The business might have positive cash flow because it received a bank loan (an inflow) — but a loan is not profit. Profit requires revenue to exceed costs, which is a separate calculation. The two do not always move together."}]}, "misc": {"enabled": true, "items": [{"myth": "A cash flow forecast shows whether the business is making a profit or a loss.", "truth": "A cash flow forecast only shows cash movements — money in and money out. It says nothing about profit. Profit is calculated on the income statement (revenue minus total costs). Examiners consistently note this is the most common error in this topic.", "check": {"question": "What does a cash flow forecast actually show, according to this card?", "options": ["The break-even output the business needs to achieve each month", "The total revenue and total costs for the entire trading year", "Only cash movements — money in and money out — not profit", "Whether the business is making a profit or a loss overall"], "answer": 2, "explain": "The card explains a cash flow forecast only shows cash movements — profit is calculated separately on the income statement, not shown in a cash flow forecast."}}, {"myth": "If a business has a negative net cash flow in one month, it is definitely losing money and in serious trouble.", "truth": "A negative net cash flow simply means more cash went out than came in that month — it could be planned and temporary, such as buying stock ahead of a busy season. Only sustained negative cash flow over many months becomes a serious problem.", "check": {"question": "What does a single month of negative net cash flow necessarily mean?", "options": ["The business is definitely losing money and in serious financial trouble", "The business has made an accounting error somewhere in its financial records", "More cash went out than came in that month — it may be planned and temporary", "The business has permanently run out of cash and must close immediately"], "answer": 2, "explain": "The card explains negative net cash flow in one month can be planned and temporary, such as buying stock ahead of a busy season — only sustained negative flow is a serious problem."}}, {"myth": "Cash is important to a business because it allows the business to expand and invest.", "truth": "Cash is specifically important for paying SHORT-TERM debts and expenses — wages, rent, suppliers, utilities. Examiners do not award marks for answers linking cash to expansion or long-term investment, as that is the role of long-term finance.", "check": {"question": "According to this card, what is cash specifically important for paying?", "options": ["Long-term investments such as buying new factories or premises", "Dividends paid out to shareholders at the end of the financial year", "The cost of a long-term expansion into new international markets", "Short-term debts and expenses such as wages, rent and suppliers"], "answer": 3, "explain": "The card explains cash is specifically needed for short-term debts and expenses — examiners do not credit answers linking cash to expansion, which is the role of long-term finance."}}, {"myth": "The opening balance for a month is calculated by adding up all the inflows.", "truth": "The opening balance is simply the CLOSING BALANCE from the previous month — it carries straight over. It has nothing to do with inflows. Many students lose marks in calculation questions by trying to recalculate it.", "check": {"question": "How is the opening balance for a month actually calculated?", "options": ["It is calculated by adding up all of that month''s cash outflows", "It is calculated by adding up all of that month''s cash inflows", "It is calculated by subtracting outflows from that month''s inflows", "It carries over directly from the previous month''s closing balance"], "answer": 3, "explain": "The card explains the opening balance simply carries over from the previous month''s closing balance — it has nothing to do with that month''s own inflows."}}, {"myth": "A business with high revenue must have plenty of cash.", "truth": "Revenue and cash are not the same. A business could have high revenue on paper but very little cash if customers are buying on credit and haven''t paid yet. This is why businesses with large order books can still face a cash crisis.", "check": {"question": "Why might a business with high revenue still have very little cash?", "options": ["Revenue and cash are simply two different names for exactly the same figure", "Customers may be buying on credit and have not yet paid for their purchases", "High revenue always converts into cash immediately upon every single sale", "A business with high revenue is legally required to hold zero cash reserves"], "answer": 1, "explain": "The card explains revenue and cash are not the same — a business can have high revenue on paper but little cash if customers are buying on credit and haven''t paid yet."}}, {"myth": "Net cash flow = closing balance − opening balance.", "truth": "Net Cash Flow = Total Inflow − Total Outflow. While the numerical result may sometimes appear similar, the correct formula is always inflow minus outflow. Using the wrong formula will lead to errors on calculation questions.", "check": {"question": "What is the correct formula for net cash flow?", "options": ["Total Outflow minus Total Inflow", "Total Inflow minus Total Outflow", "Closing Balance minus Opening Balance", "Opening Balance minus Closing Balance"], "answer": 1, "explain": "The card confirms Net Cash Flow = Total Inflow − Total Outflow; although the result can numerically resemble closing minus opening, the correct formula is always inflow minus outflow."}}]}, "tips": {"enabled": true, "items": [{"title": "Cash Questions: Avoid the Profit Trap", "html": "<p>When asked to \"state one reason why cash is important\" or \"identify a use of a cash flow forecast,\" students frequently lose marks by writing answers about <strong>profit</strong> or <strong>break-even</strong>.</p>\n<p><strong>⚠️ Examiner Warning:</strong> In real exam papers, nearly half of all candidates scored zero on these questions by giving answers about profit and loss. The examiner''s report stated: \"The most common wrong answers were to do with being able to calculate profit and loss, or break-even.\"</p>\n<p><strong>❌ Wrong (0 marks):</strong><br><em>\"Cash is important so the business can make a profit.\"</em><br><em>\"The cash flow forecast helps calculate profit.\"</em></p>\n<p><strong>✅ Correct (1 mark):</strong><br><em>\"Cash is important to pay short-term debts such as wages and rent.\"</em><br><em>\"A cash flow forecast anticipates periods when cash may run short so the business can arrange an overdraft in advance.\"</em></p>\n<p>For \"identify\" questions, one clear, specific point is all you need. Do not write a paragraph.</p>", "check": {"question": "According to this card, what is the most common wrong answer to ''why is cash important''?", "options": ["Answers that correctly reference a specific business named in the case study", "Answers that are far too short to contain any specific detail at all", "Answers about calculating profit and loss, or break-even, instead of cash", "Answers that mention paying short-term debts such as wages or rent"], "answer": 2, "explain": "The card cites an examiner''s report stating nearly half of candidates scored zero by writing about profit and loss or break-even instead of answering about cash."}}, {"title": "Master the Three Cash Flow Formulas", "html": "<p>All cash flow calculation marks come from just three formulas. Memorise all three and practise applying them in the right order.</p>\n<div style=\"background:#f0f4ff;border-left:4px solid #4a6cf7;padding:12px 16px;margin:12px 0;border-radius:4px;\"><strong>Formula 1:</strong> Net Cash Flow = Total Inflow − Total Outflow<br><strong>Formula 2:</strong> Closing Balance = Opening Balance + Net Cash Flow<br><strong>Formula 3:</strong> Opening Balance = Closing Balance of the previous month</div>\n<p><strong>Strategy for missing figure questions:</strong></p>\n<ul>\n<li>Identify which formula the missing figure belongs to.</li>\n<li>Fill in the two values you know, and rearrange to find the unknown.</li>\n<li>Always check your answer: does the closing balance equal opening + net? If not, you''ve made an error.</li>\n</ul>\n<p><strong>⚠️ Watch out for negative numbers!</strong> If the opening balance is −£4,700 and net cash flow is £9,500: Closing = −£4,700 + £9,500 = +£4,800. Many students accidentally add the negative sign in or drop it and get the wrong answer.</p>\n<p><strong>❌ Common Error:</strong> Working out an \"opening balance\" by adding up inflows — the opening balance just CARRIES OVER from the previous month''s closing balance.</p>", "check": {"question": "According to this card, what is a common error when calculating the opening balance?", "options": ["Working it out by adding up inflows instead of carrying it over from last month", "Forgetting to include the word ''balance'' anywhere in the final written answer", "Rounding the final opening balance figure to the nearest whole pound amount", "Writing the opening balance in units instead of writing it in pounds sterling"], "answer": 0, "explain": "The card warns students often try to recalculate the opening balance by adding inflows, when it should simply carry over from the previous month''s closing balance."}}, {"title": "The U → APP → AN Chain (Cash & Profit Questions)", "html": "<p>For a 3-mark analyse question, you need exactly three distinct steps. Without all three, you cannot get full marks — even if your business knowledge is perfect.</p>\n<p><strong>Step 1 — Understanding (U):</strong> Define or explain the concept being asked about (cash, profit, liquidity, cash flow). This <em>must</em> come first — if you skip it, the examiner cannot award the application or analysis marks.</p>\n<p><strong>Step 2 — Application (APP):</strong> Use specific data or details from the case study or table. Reference actual numbers, names, or details given to you. Saying \"the business\" without referencing the specific context earns 0 for APP.</p>\n<p><strong>Step 3 — Analysis (AN):</strong> State the consequence or impact on the business. It must be business-facing (e.g. affects profit, affects ability to expand, risks closure). \"Costs will increase\" alone scores 0 for analysis — you must explain WHAT THAT MEANS for the business.</p>\n<p><strong>✅ Full-mark example (3 marks):</strong><br><em>\"Cash is the money QT has in its bank account available to spend (U). QT''s closing balance has fallen from £500 to £0 over five months (APP). This means the bank may refuse to lend QT money to fund its van purchase, preventing its planned expansion (AN).\"</em></p>\n<p><strong>❌ 1-mark example:</strong><br><em>\"Cash is important. QT needs cash. If it doesn''t have cash it will struggle.\"</em> — vague, no real U, no real APP, no real AN.</p>", "check": {"question": "According to this card, why does saying ''the business'' without detail score 0 for Application?", "options": ["Application can only ever be scored after the Analysis mark has already been awarded", "Application requires referencing specific data, names or details from the case study", "The word ''business'' is banned from ever appearing anywhere in the answer", "Application marks are never available at all in a 3-mark analyse question"], "answer": 1, "explain": "The card explains Application requires specific data or details from the case study — saying ''the business'' without referencing the actual context earns zero for APP."}}, {"title": "Identify + Explain = 2 Marks (Not Just One Point)", "html": "<p>A 2-mark \"explain\" question requires <strong>two separate things</strong>: an identification (1 mark) plus an explanation of how or why that point works (1 mark).</p>\n<p><strong>Formula:</strong> State the point → Then explain the mechanism or effect.</p>\n<p><strong>✅ Good answer (2 marks):</strong><br><em>\"A cash flow forecast can be used as a planning tool (1). It can be shown to a bank, helping the business to secure a loan or overdraft if a cash shortage is anticipated (1).\"</em></p>\n<p><strong>❌ Bad answer (1 mark maximum):</strong><br><em>\"A cash flow forecast is useful for planning.\"</em> — states the point but does not explain what the planning involves or why it helps the business.</p>\n<p><strong>⚠️ Examiner note:</strong> Many students correctly identified a use of a cash flow forecast but then failed to explain it — earning only 1 out of 2. Always ask yourself: \"Have I explained WHY or HOW, or have I just repeated the same point in different words?\"</p>", "check": {"question": "Why does ''a cash flow forecast is useful for planning'' score only 1 mark out of 2?", "options": ["It states the point but does not explain what the planning involves or why it helps", "It is factually incorrect, since forecasts are never used for planning purposes", "It fails to mention a specific business named anywhere in the case study text given", "It is too long and includes far more detail than the question actually requires"], "answer": 0, "explain": "The card explains this answer identifies a use but doesn''t explain the mechanism — full marks require explaining HOW or WHY, not just repeating the same point."}}, {"title": "The 4-Paragraph Structure for Evaluate Questions", "html": "<p>A 7-mark evaluate question is broken into four specific paragraphs. Each has a different job. Write them in this order every time.</p>\n<p><strong>Paragraph 1 — K &amp; U (Knowledge and Understanding):</strong><br>Define the key concept and explain how it works in general. This earns the knowledge mark and sets up everything that follows.<br><em>Starter: \"A cash flow forecast is a statement that shows... For a business like [Name], this means...\"</em></p>\n<p><strong>Paragraph 2 — AN &amp; APP (First Point with Analysis):</strong><br>Make your first specific point, link it directly to the case study using facts/numbers, and explain the impact on the business.<br><em>Starter: \"One benefit of completing a cash flow forecast for [Name] is... because [case study detail]... This would mean that...\"</em></p>\n<p><strong>Paragraph 3 — AN &amp; APP (Second Point with Analysis):</strong><br>Make a second, different point. Do not repeat paragraph 2 — explore a different aspect or argue a counterpoint.<br><em>Starter: \"Furthermore / However, another [benefit/limitation] is... In [Name]''s case, [case study detail]... As a result...\"</em></p>\n<p><strong>Paragraph 4 — Evaluation (Justified Judgement):</strong><br>Make a clear decision, justify it with case study context, and explain why — ideally using an \"it depends on...\" condition to show sophisticated thinking.<br><em>Starter: \"Overall, I believe [the cash flow forecast is very/fairly/limited in its] usefulness to [Name] because... This is particularly important given that [specific case study detail]... However, this depends on...\"</em></p>\n<p><strong>⚠️ Warning:</strong> A conclusion that simply repeats what you said in paragraphs 2 and 3 earns ZERO evaluation marks. The judgement must go beyond the analysis — it must make a decision and justify it using context.</p>", "check": {"question": "According to this card, what happens if the final evaluation paragraph just repeats paragraphs 2 and 3?", "options": ["It earns zero evaluation marks, since the judgement must go beyond the analysis", "It earns half of the available evaluation marks as a form of partial credit", "It earns full marks provided that the paragraph is a reasonable length overall", "It still earns full evaluation marks, since the content itself remains accurate"], "answer": 0, "explain": "The card warns a conclusion that simply repeats paragraphs 2 and 3 earns ZERO evaluation marks — the judgement must go beyond the analysis and be justified with context."}}, {"title": "Recommend Questions: Judgement + Context + Impact", "html": "<p>A 3-mark recommend question (e.g. \"Recommend whether cash or profit will have the biggest impact\") is structured as follows:</p>\n<p><strong>Mark 1 — Basic Judgement:</strong> State your clear decision. \"Cash / profit will have the biggest impact.\"</p>\n<p><strong>Mark 2 — Application (use context):</strong> Back up your choice using specific data from the case study. Reference actual figures, names or situation details.</p>\n<p><strong>Mark 3 — Analysis (the consequence):</strong> Explain what this means for the business going forward — link it back to the question''s focus (e.g. expansion plans).</p>\n<p><strong>✅ Full-mark example:</strong><br><em>\"QT''s cash position will have the biggest impact on its expansion (1). Its closing balance has already fallen to £0 over five months (APP), meaning the bank may refuse to lend it the £40,000 needed for the van (1). Without the loan, the expansion cannot proceed at all (1).\"</em></p>\n<p><strong>❌ Common error:</strong> Writing a general discussion of both cash and profit without making a clear decision. Examiners report that some candidates \"could not reach a decision, even in the light of being led to this question.\" A judgement without a clear recommendation earns 0.</p>", "check": {"question": "According to this card, what happens if an answer discusses both options without a clear decision?", "options": ["It scores full marks, since discussing both options shows genuinely balanced thinking", "It scores 2 out of 3 marks, since application and analysis are both still present", "It scores full marks provided that both options are given exactly equal space", "It scores zero, since a judgement without a clear recommendation earns no marks"], "answer": 3, "explain": "The card explains examiners report candidates who fail to reach a decision score zero — a general discussion of both options without a clear recommendation is not enough."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify two uses of a cash flow forecast to a business. [2 marks]", "marks": 2, "hint": "Think about what a business can DO with a cash flow forecast — not what it shows about profit. Each use needs to be a distinct, separate point.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><p>One mark for each correct use, up to a maximum of two marks.</p><p><strong>Answers may include:</strong></p><ul><li>A planning tool (e.g. estimating future inflows or outflows)</li><li>Anticipate periods of negative cash flow / cash shortages</li><li>Enable remedies to be put in place (e.g. arrange an overdraft)</li><li>Help with budgeting</li><li>Identify or arrange an overdraft / funding</li><li>Provide targets for managing spending</li></ul><p><strong>No reward for:</strong> answers about profit, loss, break-even, calculating costs or spending money generally.</p><p><strong>Examiner''s Comment:</strong> This question was poorly answered — nearly half of candidates scored zero. The most common wrong answers were about calculating profit and loss or break-even. Centres must ensure candidates understand the vital distinction between cash, revenue, and profit.</p></div>"}, {"question": "These figures show that:", "marks": 1, "hint": "Think about the difference between cash and profit. Can you have one without the other?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 1 mark (AO2)</h5><p><strong>Why C is correct:</strong> Profit (revenue − total costs = £44,000) and cash (the bank balance = −£5,000 overdrawn) are completely different. A business can be profitable overall but still have a negative bank balance — for example if it has made large investments or is waiting for customers to pay.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A</strong> — Wrong. Profit of £44,000 is genuine; there is no error. Cash and profit are different calculations.</li><li><strong>B</strong> — Wrong. There is absolutely no evidence of theft. The difference between profit and cash has many legitimate explanations.</li><li><strong>D</strong> — Wrong. The firm IS experiencing cash shortages right now (it is overdrawn); the high profit does not prevent this.</li></ul></div>"}, {"question": "Explain why profit is important to a business'' future. [2 marks]", "marks": 2, "hint": "Give one specific reason why profit matters, then explain how or why it leads to a benefit. Do NOT just define profit.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a / AO1b)</h5><p>One mark for identifying why profit is important, plus one further mark for understanding (an explanation of how or why).</p><p><strong>Answers may include:</strong></p><ul><li>To help expansion (1) by opening new stores/hotels (1)</li><li>To attract new investors (1) so that the business can grow (1)</li><li>No need to seek other finance (1) which could be expensive (1)</li><li>To pay dividends (1) which keeps shareholders happy (1)</li><li>To help repay a loan/debt (1) so that costs fall (1)</li><li>Buy new equipment and buildings (1) to replace worn-out items (1)</li><li>Develop new products (1) to allow more profit in the future (1)</li><li>To compare performance against competitors (1) using profitability ratios (1)</li></ul><p><strong>No reward for:</strong> a definition of profit alone; answers about allowing the business to survive (that is about cash, not profit).</p><p><strong>Examiner''s Comment:</strong> Most candidates achieved one mark. Popular correct answers included expansion and paying off debts. Many could identify a reason but failed to support it with any explanation. Some confused profit with survival (a cash concept).</p></div>"}, {"question": "Calculate the daily break-even quantity for the proposed hotel. [3 marks]", "marks": 3, "hint": "You need to: (1) find the contribution per room per day, (2) convert weekly fixed costs into daily fixed costs, (3) divide daily fixed costs by contribution. Show all working.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2)</h5><p><strong>Method:</strong></p><ul><li>SP − VC = Contribution: 100 − 40 = <strong>£60</strong> (1 mark)</li><li>FC ÷ 7 days: 6,300 ÷ 7 = <strong>£900 per day</strong> (1 mark)</li><li>Daily break-even = 900 ÷ 60 = <strong>15 rooms</strong> (1 mark) [OFR applies]</li></ul><p><strong>Alternative method:</strong><br>Weekly break-even = 6,300 ÷ 60 = 105 rooms per week (2 marks)<br>Daily break-even = 105 ÷ 7 = 15 rooms (1 mark) [OFR]</p><p><strong>Notes:</strong></p><ul><li>Maximum 2 marks if the weekly fixed costs are not divided by 7 (answer of 105)</li><li>Maximum 2 marks if the answer is given in the wrong units (e.g. £)</li><li>No reward for writing the formula alone</li></ul><p><strong>Examiner''s Comment:</strong> Even though ''daily'' was emboldened in the question, a significant number of candidates gave 105 rooms (the weekly figure) and scored only 2 marks. Always read the question carefully.</p></div>"}, {"question": "Analyse one disadvantage to the partnership if the proposed hotel''s fixed costs were 10% higher than expected. [3 marks]", "marks": 3, "hint": "Follow U → APP → AN. First state a disadvantage of higher costs (U). Then use a number from the case study to show the increase (APP). Then explain the business consequence (AN). Do NOT just say ''costs will increase'' — that earns zero for analysis.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b / AO2 / AO3a)</h5><p><strong>Understanding (1 mark) — a disadvantage of higher costs:</strong></p><ul><li>Could lead to lower profits (or a loss)</li><li>Could lead to higher prices being charged</li><li>Less money available for other needs (e.g. day-to-day running)</li><li>Increases the break-even level — harder to cover costs</li></ul><p><strong>Application (1 mark) — use case study numbers:</strong></p><ul><li>Fixed costs increase from £6,300 to £6,930 per week (+£630)</li><li>£90 more per day in fixed costs</li><li>Break-even increases from 15 to 17 rooms per day</li><li>Existing bank loan already in place</li></ul><p><strong>Analysis (1 mark) — business consequence:</strong></p><ul><li>Need to fill more rooms to cover the extra costs</li><li>May reduce customer demand if prices are raised</li><li>May put off investors or a new partner joining</li><li>May lead to more debt or need for extra finance</li><li>Expansion decisions may need to be postponed</li></ul><p><strong>No reward for:</strong> ''costs will increase'' as analysis; application referring to context about the current hotel being profitable; any mention of owner stress.</p><p><strong>Examiner''s Comment:</strong> Better answers showed understanding linked to profit or break-even, applied the numbers, and identified an impact (e.g. needing to sell more rooms). A full-mark answer can be written in two sentences.</p></div>"}, {"question": "Yoshi''s Sweet Shop''s opening balance for December is expected to be:", "marks": 1, "hint": "The opening balance for December = the closing balance for November. Use: Closing Balance = Opening Balance + Net Cash Flow.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £4,800 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Closing Balance (November) = Opening Balance + Net Cash Flow = −£4,700 + £9,500 = <strong>£4,800</strong>. This closing balance becomes December''s opening balance.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — £4,700:</strong> This removes the negative sign from the opening balance but ignores the net cash flow entirely.</li><li><strong>C — £14,200:</strong> This adds £9,500 to £4,700, ignoring the negative opening balance sign.</li><li><strong>D — £14,300:</strong> A rounding or arithmetic error — always be precise with negative values.</li></ul></div>"}, {"question": "A cash flow forecast can help a business:", "marks": 1, "hint": "Think about what a cash flow forecast actually shows — money in vs money out. Which of these four things does that help a business do?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Predict liquidity problems (1 mark)</h5><p><strong>Why C is correct:</strong> A cash flow forecast shows when more cash goes out than comes in. This allows the business to predict when it may struggle to pay its debts (a liquidity problem) and act in advance.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> A cash flow forecast does NOT calculate profit. Profit = Revenue − Total Costs, which is on the income statement, not the cash flow forecast.</li><li><strong>B:</strong> Identifying market changes requires market research and competitor analysis — not a cash flow forecast.</li><li><strong>D:</strong> Break-even analysis uses selling price and costs, not a cash flow forecast.</li></ul></div>"}, {"question": "State one reason why cash is important to a business. [1 mark]", "marks": 1, "hint": "Think about SHORT-TERM needs — what does a business need cash for right now? Do NOT write about expansion or long-term investment.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p><strong>Answers may include:</strong></p><ul><li>To pay short-term debts / loans / finances</li><li>To pay short-term expenses: heating / lighting / rent / raw materials / supplies / wages</li><li>To maintain liquidity</li><li>To ease cash-flow problems</li></ul><p><strong>No reward for:</strong> answers linking to long-term issues (e.g. expansion, investment in equipment). Cash is specifically for SHORT-TERM needs.</p><p><strong>Examiner''s Comment:</strong> Half of candidates either left this blank or wrote that cash was needed \"to run the business\" — too vague for a mark. Correct answers recognised cash as being for short-term funding (liquidity, paying suppliers, wages, rent). About half of candidates scored zero on this question.</p></div>"}, {"question": "Analyse QT''s cash position considering its current expansion plans. [3 marks]", "marks": 3, "hint": "U → APP → AN. First define/explain what ''cash position'' means (not profit). Then refer to QT''s specific cash data (the declining balance). Then explain what consequence this has for the expansion.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b / AO2 / AO3a)</h5><p><strong>Understanding (1 mark):</strong></p><ul><li>Money held in the bank / bank balance / closing balance</li><li>Money on the premises (cash in hand)</li><li>The money available to spend / reference to cash flow</li></ul><p><strong>Application (1 mark) — must reference changes in cash:</strong></p><ul><li>Deteriorating cash position</li><li>Cash has fallen from approximately £500 to £0 over five months</li><li>Current cash position is approximately zero / very low</li><li>Will need to take out a bank loan for the £40,000 van</li></ul><p><strong>Analysis (1 mark):</strong></p><ul><li>It will struggle to pay day-to-day debts</li><li>Banks may not lend it money given deteriorating cash position</li><li>May cause liquidity problems</li><li>May be unable to proceed with expansion plans</li></ul><p><strong>Note:</strong> If using the graph/closing balance data for APP, responses must reference the CHANGES in cash flow, not just state the business sells to retail shops.</p></div>"}, {"question": "Analyse QT''s profit position considering its current expansion plans. [3 marks]", "marks": 3, "hint": "U → APP → AN. Define profit/profit margin. Then refer to QT''s specific margin data from the table (not just ''profit is good''). Then explain the business consequence for its expansion.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b / AO2 / AO3a)</h5><p><strong>Understanding (1 mark):</strong></p><ul><li>Profit = total revenue minus total costs</li><li>Shown by/measured through profit margins</li></ul><p><strong>Application (1 mark) — must reference changes in profit margins:</strong></p><ul><li>Gross profit margin has increased from 57% to 65% over three years</li><li>Net profit margin has increased from 23% to 27% over three years</li></ul><p><strong>Analysis (1 mark):</strong></p><ul><li>Increased profits help pay for the expansion</li><li>Managers are keeping costs under control</li><li>Banks/investors may see improving profitability as a good reason to lend/invest</li><li>Profits may be adversely affected by the cost of the expansion</li></ul><p><strong>Examiner''s Comment:</strong> This was the least well-answered of the three parts. Many responses did not manage to gain the analysis mark because they did not link back to the expansion plans (the focus of the question). Simply using \"profit\" without referencing margins or understanding does not earn the understanding mark.</p></div>"}, {"question": "Recommend whether QT''s cash position or profit position will have the biggest impact on its expansion plans. [3 marks]", "marks": 3, "hint": "Make a clear decision first (1 mark). Then justify your choice using specific detail from the case study (APP). Then explain the consequence for the expansion (AN). Do NOT just repeat what you said in Q7(i) or Q7(ii).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><p><strong>Judgement (1 mark):</strong> A clear statement of whether cash or profit has the biggest impact.</p><p><strong>Justification with context (2 marks):</strong> A clear, contextualised justification using case study details.</p><p><strong>OR Justification without context (1 mark):</strong> A general justification with no reference to QT''s specific situation.</p><p><strong>Examiner''s Comment:</strong> Some candidates could not reach a clear decision. Others wrote a few focused sentences using the context effectively and earned full marks. Strong responses noted QT''s closing balance of £0 (cash problem) while acknowledging improving profit margins. The distinction between cash (right now) and profit (overall performance) was key. Candidates who just said \"cash\" or \"profit\" without using language showing understanding of these terms could not gain the understanding mark underpinning the justification.</p></div>"}, {"question": "Marble & Sons'' opening balance for September is expected to be:", "marks": 1, "hint": "Rearrange: Closing Balance = Opening Balance + Net Cash Flow → Opening Balance = Closing Balance − Net Cash Flow. Be careful with negatives.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — −£4,700 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Opening Balance = Closing Balance − Net Cash Flow = −£7,300 − (−£2,600) = −£7,300 + £2,600 = <strong>−£4,700</strong>.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — −£9,900:</strong> This adds both negative figures together (−7,300 + −2,600). When net cash flow is negative, it reduces the balance — so the opening balance must be less negative than the closing balance.</li><li><strong>C — £4,700:</strong> Correct absolute value but wrong sign — the balance is negative.</li><li><strong>D — £9,900:</strong> Adds the absolute values with the wrong sign.</li></ul></div>"}, {"question": "State one reason why cash is important to a business. [1 mark]", "marks": 1, "hint": "Think SHORT-TERM. What must a business pay for right now? Do NOT write about investing or expanding.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p><strong>Answers may include:</strong></p><ul><li>To pay expenses / costs</li><li>Meeting short-term debts</li><li>Providing liquidity</li><li>A source of working capital / keeps the business running day-to-day</li><li>Allows spending without needing to arrange finance</li><li>Accept specific examples of expenses (wages, rent, materials, utilities)</li></ul><p><strong>No reward for:</strong> \"to invest\" or \"to help expand\" — these relate to long-term uses of finance, not cash.</p></div>"}, {"question": "Explain one use of a cash flow forecast in a business. [2 marks]", "marks": 2, "hint": "Name a specific use (1 mark) and then explain HOW or WHY that use benefits the business (1 mark). Do not mention profit.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a / AO1b)</h5><p><strong>1 mark for identifying a use:</strong></p><ul><li>As a planning or targeting tool</li><li>To help anticipate a shortage of money / negative cash flow</li><li>To put remedies in place to address cash shortages</li></ul><p><strong>1 further mark for explanation:</strong> Explain what the use involves or why it helps the business.</p><p><strong>No reward for:</strong> any reference to forecasting profit.</p></div>"}, {"question": "Pia''s Diner''s total inflow for July is expected to be:", "marks": 1, "hint": "Net Cash Flow = Total Inflow − Total Outflow. Rearrange to find Total Inflow = Net Cash Flow + Total Outflow.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £11,600 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Total Inflow = Net Cash Flow + Total Outflow = −£1,900 + £13,500 = <strong>£11,600</strong>.</p><p><strong>Verification:</strong> Closing Balance = Opening Balance + Net Cash Flow = −£2,300 + (−£1,900) = −£4,200 ✓</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — £7,000:</strong> No clear logic — possibly a random guess.</li><li><strong>B — £9,300:</strong> Possibly calculated by subtracting net cash flow from opening balance.</li><li><strong>C — £11,200:</strong> Possibly calculated using the closing balance minus net cash flow incorrectly.</li></ul></div>"}, {"question": "Calculate the gross profit margin for 2019. Show your workings. [2 marks]", "marks": 2, "hint": "Gross Profit Margin = (Gross Profit ÷ Revenue) × 100. Both figures are given in the case study for 2019.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5><p><strong>Calculation:</strong> £118,000 ÷ £150,000 × 100 = <strong>78.7%</strong> (Accept 79% or 78.6%)</p><ul><li>2 marks for the correct answer (with or without workings shown)</li><li>1 mark for evidence of using the correct two numbers (£118,000 and £150,000)</li><li>Maximum 1 mark if the answer has the incorrect units or magnitude</li></ul></div>"}, {"question": "Calculate the net profit margin for 2019. Show your workings. [2 marks]", "marks": 2, "hint": "Net Profit Margin = (Net Profit ÷ Revenue) × 100. Both net profit and revenue for 2019 are given in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5><p><strong>Calculation:</strong> £56,800 ÷ £150,000 × 100 = <strong>37.9%</strong> (Accept 38% or 37.8%)</p><ul><li>2 marks for the correct answer (with or without workings shown)</li><li>1 mark for evidence of using the correct two numbers (£56,800 and £150,000)</li><li>Maximum 1 mark if the answer has the incorrect units or magnitude</li></ul></div>"}, {"question": "What is Pete''s Pet Shop''s estimated total cash outflow for July?", "marks": 1, "hint": "Net Cash Flow = Total Inflow − Total Outflow. Rearrange to find: Total Outflow = Total Inflow − Net Cash Flow.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — £7,505 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Total Outflow = Total Inflow − Net Cash Flow = £6,900 − (−£605) = £6,900 + £605 = <strong>£7,505</strong>.</p><p><strong>Verification:</strong> Closing = Opening + Net = £3,000 + (−£605) = £2,395 ✓</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — £3,900:</strong> No logical basis.</li><li><strong>B — £6,295:</strong> Subtracts £605 from £6,900 without considering the sign, giving £6,295 instead of adding.</li><li><strong>D — £9,295:</strong> Adds £6,900 + £3,000 - £605, mixing up different rows incorrectly.</li></ul></div>"}, {"question": "Which of the following problems would be classed as a ''liquidity problem''?", "marks": 1, "hint": "Liquidity = ability to pay SHORT-TERM debts. Which option is about an immediate inability to pay a bill?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Being short of funds to pay suppliers (1 mark)</h5><p><strong>Why B is correct:</strong> Liquidity is defined as the ability to pay short-term debts. Being unable to pay suppliers is a direct example of a liquidity problem — the business does not have enough cash available to meet an immediate payment obligation.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> A production line breakdown is an operational problem, not a financial one.</li><li><strong>C:</strong> High wastage is an efficiency and quality management issue — not directly a cash/liquidity problem.</li><li><strong>D:</strong> Lack of financial information is a management and planning issue, not a liquidity problem.</li></ul></div>"}, {"question": "A business will make a profit if it:", "marks": 1, "hint": "Profit = Revenue − Total Costs. Which answer describes a situation where revenue is greater than costs?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Exceeds its break-even quantity (1 mark)</h5><p><strong>Why B is correct:</strong> At break-even, revenue exactly equals total costs. If a business sells more than the break-even quantity, revenue exceeds total costs, which is the definition of profit.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> A positive bank balance shows liquidity (cash), not profitability. The money in the bank could have come from a loan.</li><li><strong>C:</strong> If costs are greater than revenues, the business is making a LOSS, not a profit.</li><li><strong>D:</strong> Paying off debts relates to solvency, not to whether revenue exceeds costs.</li></ul></div>"}, {"question": "Calculate the net cash flow in Table 2. [1 mark]", "marks": 1, "hint": "Net Cash Flow = Total Inflow − Total Outflow. Both figures are given in the table.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO2)</h5><p><strong>Answer: −£2,000</strong></p><p>Net Cash Flow = £23,000 − £25,000 = −£2,000.</p><p><strong>Verification:</strong> Closing Balance = −£3,500 + (−£2,000) = −£5,500 ✓</p><p>The £ sign does not have to be included. Accept −2000 or −£2,000.</p></div>"}, {"question": "Identify two cash outflows from CFM if Anne and Martin open a new café. [2 marks]", "marks": 2, "hint": "Think about what CFM would need to PAY FOR when opening a new café. Look at the clues in the case study for specific examples.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5><p>1 mark for each correct identification of a cash outflow, up to a maximum of 2 marks.</p><p><strong>Answers may include:</strong></p><ul><li>Fixtures and fittings for the new café</li><li>Property costs / purchase price of new premises</li><li>Staff training costs</li><li>Raw materials / ingredients</li><li>Fuel for delivery service</li><li>Wages / salaries for new staff</li><li>Rent on new premises</li></ul></div>"}, {"question": "State one way Anne and Martin could use the cash flow forecast in Table 2. [1 mark]", "marks": 1, "hint": "The forecast shows a negative cash balance. What could Anne and Martin DO about this, or USE the forecast to help them do?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO2)</h5><p><strong>Answers may include:</strong></p><ul><li>Obtain a short-term overdraft or finance to cover the negative balance</li><li>Negotiate with suppliers about when to make purchases</li><li>Make decisions over when to employ staff</li><li>Decide on resource allocation (opening times, stock levels etc.)</li><li>Show to the bank to support a loan application for the new café</li></ul></div>"}, {"question": "Which of the following statements must be true?", "marks": 1, "hint": "Think about the definition of profit. Profit = Revenue − Costs. If profit is positive, what does that tell us about revenue vs costs?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — The company''s revenue exceeded its costs (1 mark, AO2)</h5><p><strong>Why D is correct:</strong> Net profit = Revenue − Total Costs. If net profit is £16,000 (positive), then by definition revenue must have been greater than total costs.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> The company might have spent or invested the profit money; profit and cash are different. The bank balance could be very low even with a good profit.</li><li><strong>B:</strong> A profitable business can still struggle to pay its bills if it has a cash flow problem (e.g. customers not paying on time).</li><li><strong>C:</strong> That would describe a net CASH OUTFLOW of £16,000 — meaning a cash deficit, not a profit. It is the complete opposite of what happened.</li></ul></div>"}, {"question": "What is Millican Garage''s closing balance for September?", "marks": 1, "hint": "Closing Balance = Opening Balance + Net Cash Flow. Use September''s opening balance and net cash flow.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £320 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Closing Balance = Opening Balance + Net Cash Flow = £1,225 + (−£905) = <strong>£320</strong>.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — −£2,130:</strong> Adds −£905 and −£1,225 incorrectly (opening balance is +£1,225, not negative).</li><li><strong>C — £2,130:</strong> Adds 1,225 + 905 (ignores the negative sign on net cash flow).</li><li><strong>D — £12,040:</strong> Adds total inflow and opening balance, ignoring outflows — not a valid formula.</li></ul></div>"}, {"question": "Pasha''s Carpets'' net cash flow for August 2019 is expected to be:", "marks": 1, "hint": "Net Cash Flow = Total Inflow − Total Outflow. Both figures are given.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — −£1,500 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Net Cash Flow = £44,000 − £45,500 = <strong>−£1,500</strong>.</p><p><strong>Verification:</strong> Closing = Opening + Net = −£1,100 + (−£1,500) = −£2,600 ✓</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — −£3,700:</strong> Possibly adds the opening balance to the outflow difference. Examiner noted many candidates chose C or A by recognising the inflow/outflow difference but failing to apply the correct sign.</li><li><strong>C — £1,500:</strong> Correct absolute value but the sign is wrong — outflow exceeded inflow so net cash flow must be negative.</li><li><strong>D — £3,700:</strong> No clear basis — possibly adds the two figures.</li></ul><p><strong>Examiner''s Comment:</strong> Candidates who got this wrong often recognised the difference between inflow and outflow, but did not see that it was a negative amount, therefore choosing C instead of B.</p></div>"}, {"question": "Identify two items of expenditure that Clara and Annabelle are likely to have in their cash flow forecast. [2 marks]", "marks": 2, "hint": "Expenditure = money going OUT. Think about what a small food shop would need to pay for regularly.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a / Knowledge)</h5><p>1 mark for each correct item of expenditure, up to a maximum of 2 marks.</p><p><strong>Answers may include:</strong></p><ul><li>Stock for the shop (food items / vegetarian or vegan products)</li><li>Overheads — heating / lighting / electricity</li><li>Wages / salaries (if they employ staff)</li><li>Rent for the shop premises</li><li>Packaging materials</li><li>Loan repayments (repaying parents)</li></ul></div>"}, {"question": "Evaluate the usefulness to Clara and Annabelle of completing a cash flow forecast. [7 marks]", "marks": 7, "hint": "This is a 7-mark evaluate question — use the 4-paragraph structure: (1) K&U — explain what a cash flow forecast is and does; (2) AN&APP — first benefit linked to ClarAnn''s specific situation; (3) AN&APP — second benefit or counterpoint; (4) EVAL — justified judgement using ClarAnn''s context.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><p><strong>AO2 / Application (2 marks):</strong> Two examples that relate specifically to the ClarAnn case study.</p><ul><li>This is a new business with no experience; they must keep a careful eye on cash, especially with competition present.</li><li>They need to anticipate possible cash shortages — they have used all their savings and borrowed from parents, so they have nothing to fall back on.</li></ul><p><strong>AO3a / Analysis (2 marks):</strong> Two separate points explaining the effect or impact on the business.</p><ul><li>Without cash, a business will not be able to meet its short-term debts. As a new business, ClarAnn must not fail to pay suppliers — it has no reputation to fall back on. Without suppliers, there is no stock to sell.</li><li>Planning ahead with a cash flow forecast means a business can arrange finance ahead of any potential shortfall. This is especially important for a new business with no financial history.</li></ul><p><strong>AO3b / Evaluation (3 marks):</strong></p><ul><li><strong>Judgement (1 mark):</strong> A clear statement — e.g. \"I think completing a cash flow forecast will be very useful to Clara and Annabelle.\"</li><li><strong>Justification (up to 2 marks):</strong> A clear justification using case study context — e.g. Clara and Annabelle are new to running a business with no experience, so the forecast will force them to think about inflows and outflows and help them arrange finance if needed.</li></ul></div>"}, {"question": "Explain what is meant by a cash flow problem. [2 marks]", "marks": 2, "hint": "Define ''cash flow'' (income and expenditure over time) and then explain what a ''problem'' means in this context — link to negative cash flow and the inability to pay debts.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a / Knowledge)</h5><p>A clear explanation of the term ''cash flow problem'' for 2 marks.</p><p><strong>Key points to include:</strong></p><ul><li>Cash flow = income received and payments made by the business over a period</li><li>A problem = when income is less than that needed to make payments (negative cash flow)</li><li>Reference to ''negative cash flow'' is useful and well-regarded</li><li>A business with a cash flow problem cannot pay its short-term debts on time</li></ul></div>"}, {"question": "Discuss the factors that may have influenced the owners'' decision to sell the Deltic Group. [7 marks]", "marks": 7, "hint": "This is a 7-mark discuss/evaluate question. Use the 4-paragraph structure: (1) K&U — explain a factor; (2) AN&APP — analyse one factor using Deltic''s specific data; (3) AN&APP — analyse another factor; (4) EVAL — justified judgement about which factor was MOST important, using context.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><p><strong>AO2 / Application (1 mark):</strong></p><ul><li>Reference to Deltic''s income falling to £80,000/month while rent alone was £1 million/month</li><li>Rising debts: £9.4m to landlords, £7.7m further debt</li><li>Lack of cash reserves</li><li>The sale price was only £10 million vs £80 million valuation</li></ul><p><strong>AO3a / Analysis (3 marks):</strong></p><ul><li>To continue trading, Deltic needed to make payments. When there is a negative cash flow, an overdraft can help but this incurs extra costs and raises debts further.</li><li>The selling price of £10m was far below the £80m valuation — the owners would incur a significant loss from the sale.</li><li>With £17m+ in total debt and no certainty of when clubs would reopen, the position was getting worse each month.</li></ul><p><strong>AO3b / Evaluation (3 marks):</strong></p><ul><li><strong>Judgement (1 mark):</strong> e.g. \"The decision was most influenced by the rising debts and continuing cash flow problem.\"</li><li><strong>Justification (up to 2 marks):</strong> Rising debts and rising interest costs meant the financial position was deteriorating rapidly. Creditors could force the business to close, giving the owners nothing. By selling, at least they received £10 million. The uncertainty over reopening dates made it impossible to plan a recovery.</li></ul></div>"}, {"question": "Calculate the missing figures A, B, C, and D in the cash flow forecast for Bowton Garage Ltd. [4 marks]", "marks": 4, "hint": "Work through each missing figure in order. A = Net cash flow (inflow − outflow). B = a missing outflow (total outflow − other outflows). C = opening balance February (= closing balance January). D = closing balance March.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 4 marks (1 mark each)</h5><ul><li><strong>A = £10,000</strong> — Net Cash Flow (January) = £35,000 − £25,000 = £10,000 (1 mark)</li><li><strong>B = £11,000</strong> — Wages (February) = £22,000 − £8,000 − £1,000 − £2,000 = £11,000 (1 mark)</li><li><strong>C = £15,000</strong> — Opening Balance (February) = Closing Balance (January) = £5,000 + £10,000 = £15,000 (1 mark)</li><li><strong>D = £25,000</strong> — Closing Balance (March) = £18,000 + £7,000 = £25,000 (1 mark)</li></ul></div>"}, {"question": "State one reason why drawing up a cash flow forecast is useful for Bowton Garage Ltd. [1 mark]", "marks": 1, "hint": "Think about what Bowton Garage can DO with or because of the cash flow forecast. One clear, specific point.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p><strong>Answers may include:</strong></p><ul><li>It helps them to plan ahead / acts as a planning tool</li><li>It allows them to anticipate months of negative cash flow or cash shortage</li><li>It can be used to arrange finance (e.g. overdraft) in advance</li><li>It can be shown to a bank to support a loan application</li><li>It provides targets for managing their spending</li></ul><p><strong>No reward for:</strong> answers about profit or break-even.</p></div>"}, {"question": "Explain the difference between cash and profit. [2 marks]", "marks": 2, "hint": "Define BOTH terms clearly — one sentence for each. Make sure your definitions show they are different measurements of a business''s financial situation.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a / AO1b)</h5><ul><li><strong>Cash (1 mark):</strong> Money held in bank accounts or on the premises, used to pay short-term debts and expenses as they arise.</li><li><strong>Profit (1 mark):</strong> Calculated by subtracting total costs from total revenue; shows whether the business has earned more than it spent over a period. A business could be short of cash one month but still make a good profit overall (e.g. if waiting for a large order to be paid).</li></ul></div>"}, {"question": "If Bowton Garage had a negative cash flow, explain two ways in which the business could deal with it. [4 marks]", "marks": 4, "hint": "Give two SEPARATE ways. For each one: (1) name the method clearly, and (2) use evidence from the actual Bowton Garage cash flow to explain HOW it would help. Do not give vague answers like ''get more money.''", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 4 marks (AO1b / AO2)</h5><p>2 marks for each way (1 for identifying the method + 1 for explaining/applying it to Bowton Garage''s situation).</p><p><strong>Possible ways include:</strong></p><ul><li>Arrange an overdraft (1) — this would give Bowton Garage access to short-term funds to cover the shortfall, e.g. to pay wages and rent in a difficult month (1)</li><li>Reduce expenditure (1) — for example, Bowton Garage could negotiate lower material costs or delay purchasing non-essential items (1)</li><li>Increase revenue / raise prices (1) — higher sales revenue would increase inflows, reducing the gap between inflows and outflows (1)</li><li>Delay payment of bills (1) — Bowton Garage could negotiate with suppliers to extend payment terms, keeping cash in the business longer (1)</li><li>Chase customers for quicker payment (1) — if some of Bowton Garage''s customers pay on credit, speeding up payments would improve cash inflows (1)</li></ul><p><strong>Note:</strong> Each way must be genuinely different. Two marks cannot be awarded for the same type of action described twice.</p></div>"}]}}'::jsonb),
('business', '6-1-ethical-environmental', '6.1 Ethical & Environmental', '{"learn": {"enabled": true, "items": [{"title": "Core Definitions — Ethics & Environment", "html": "<ul>\n<li><strong>Ethics</strong> — what is right and wrong</li>\n<li><strong>Ethical behaviour</strong> — doing what is morally right; concerns how workers, suppliers and customers are treated</li>\n<li><strong>Child labour</strong> — the use of young children below the legal age for employment to achieve low-cost production</li>\n<li><strong>Fairtrade</strong> — a movement encouraging businesses to pay a fair price to suppliers in developing countries; the Fairtrade Mark guarantees this</li>\n<li><strong>Environmentally friendly</strong> — consumers and businesses that act to make production sustainable</li>\n<li><strong>Sustainable production</strong> — production that does not lead to the depletion (using up) of natural resources</li>\n<li><strong>Renewable resources</strong> — resources that can be used more than once (wind, water, crops)</li>\n<li><strong>Non-renewable resources</strong> — resources that can only be used once (e.g. oil)</li>\n<li><strong>Recycling</strong> — when resources are reused to produce something new</li>\n</ul>", "check": {"question": "According to the key definitions, what does ''sustainable production'' mean?", "options": ["Production that maximises profit regardless of environmental impact", "Production that relies entirely on non-renewable resources like oil", "Production that uses only recycled materials for every single product", "Production that does not lead to the depletion of natural resources"], "answer": 3, "explain": "The card defines sustainable production as production that does not deplete natural resources — distinct from recycling, profit-maximising, or relying on non-renewables."}}, {"title": "Four Areas of Ethical Consideration", "html": "<p><strong>1. Treatment of Workers</strong></p>\n<ul>\n<li>No child labour</li>\n<li>Pay at least the National Minimum/Living Wage</li>\n<li>Fair hours — no excessive working hours</li>\n<li>Safe working conditions</li>\n<li>No discrimination on gender, ethnicity or disability grounds</li>\n</ul>\n<p><strong>2. Treatment of Suppliers</strong></p>\n<ul>\n<li>No late payment of bills (harms supplier cash flow)</li>\n<li>Pay fair prices</li>\n<li>Do not use power to force smaller suppliers into lower-priced deals</li>\n</ul>\n<p><strong>3. Treatment of Customers</strong></p>\n<ul>\n<li>No overcharging / exorbitant prices</li>\n<li>No false claims — marketing must be legal, decent, honest and truthful</li>\n<li>Do not put customers in danger with fake or faulty products</li>\n</ul>\n<p><strong>4. Sourcing of Materials</strong></p>\n<ul>\n<li>Do not buy from businesses that use child labour</li>\n<li>Do not buy from anyone who does not produce sustainably</li>\n<li>Consider using the Fairtrade Mark — guarantees a fair price was paid to farmers</li>\n</ul>", "check": {"question": "Which of these is listed under ''Treatment of Suppliers'' in this card?", "options": ["No false claims made in marketing that must be honest and truthful", "No late payment of bills, since this harms a supplier''s cash flow", "No discrimination on the grounds of gender, ethnicity or disability", "No overcharging or exorbitant prices charged to customers"], "answer": 1, "explain": "The card lists no late payment of bills under Treatment of Suppliers; discrimination relates to workers, overcharging and false claims relate to customers."}}, {"title": "Benefits & Drawbacks of Being Ethical", "html": "<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits</div>\n<div class=\"pro-item\">Improved reputation — more customers buy from trustworthy businesses</div>\n<div class=\"pro-item\">Increased sales — ethical brands attract customers willing to pay more</div>\n<div class=\"pro-item\">Worker motivation — trust increases productivity; reduces labour turnover and recruitment costs</div>\n<div class=\"pro-item\">Investor confidence — long-term success attracts investors</div>\n<div class=\"pro-item\">Long-term survival — ethical producers more likely to be profitable over time</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Drawbacks</div>\n<div class=\"con-item\">Higher costs — better materials, fair wages and ethical sourcing all cost more</div>\n<div class=\"con-item\">Reduced profits — higher costs cut into profit margins</div>\n<div class=\"con-item\">Lost sales — unethical competitors can charge less, making the ethical business less competitive</div>\n<div class=\"con-item\">Threat to survival — in highly competitive markets, extra costs may threaten existence</div>\n</div>\n</div>", "check": {"question": "According to this card, what is a drawback of being an ethical business?", "options": ["Higher costs, since better materials and fair wages cost more money", "Lower sales, since ethical brands never attract any customers at all", "Reduced investor confidence, since investors avoid ethical businesses", "Higher staff turnover, since ethical treatment reduces worker motivation"], "answer": 0, "explain": "The card lists higher costs as a drawback of ethical behaviour — the other options contradict the benefits listed, such as increased sales and worker motivation."}}, {"title": "Key Environmental Issues", "html": "<ul>\n<li><strong>Pollution</strong> — causing harm to the environment: air, land, water and noise</li>\n<li><strong>Waste disposal</strong> — getting rid of unwanted materials; traditionally via incineration or landfill</li>\n<li><strong>Recycling</strong> — reusing resources to produce something new</li>\n<li><strong>Climate change</strong> — the process where average temperatures rise or fall and weather patterns change</li>\n<li><strong>Global warming</strong> — rise in average temperatures caused by human activity (burning fossil fuels, deforestation)</li>\n</ul>\n<p><strong>Sustainable production methods:</strong></p>\n<ul>\n<li><strong>Renewable energy</strong> — solar and wind power instead of fossil fuels</li>\n<li><strong>Sustainable construction</strong> — recycled materials, insulation, solar panels built in</li>\n<li><strong>Resource management</strong> — rotating crops, fixing water leaks, sensor-controlled lighting</li>\n<li><strong>Transport</strong> — fuel-efficient vehicles, car-sharing, video-conferencing to reduce travel</li>\n</ul>", "check": {"question": "According to this card, what is the difference between climate change and global warming?", "options": ["Climate change only affects water, while global warming only affects land", "Global warming is simply a form of recycling, while climate change is a form of waste disposal", "Climate change is broader weather-pattern change; global warming is the specific temperature rise", "Climate change and global warming are simply two different names for pollution"], "answer": 2, "explain": "The card defines climate change as changing weather patterns and global warming specifically as the rise in average temperatures caused by human activity."}}, {"title": "Benefits & Drawbacks of Being Environmentally Friendly", "html": "<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits</div>\n<div class=\"pro-item\">Increased sales — consumers increasingly choose ''green'' brands</div>\n<div class=\"pro-item\">Reduced costs — energy-saving bulbs, solar panels, reduced packaging save money long-term</div>\n<div class=\"pro-item\">Reduced tax bills — less pollution = potential tax reductions</div>\n<div class=\"pro-item\">Government subsidies — grants available for eco-friendly products and processes</div>\n<div class=\"pro-item\">Better reputation and marketing opportunities</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Drawbacks</div>\n<div class=\"con-item\">Raw material costs — environmentally friendly materials often cost more</div>\n<div class=\"con-item\">Capital costs — solar panels, anaerobic digesters are very expensive to install</div>\n<div class=\"con-item\">Expensive production methods — organic farming costs more than using fertilisers and pesticides</div>\n</div>\n</div>", "check": {"question": "According to this card, how can being environmentally friendly reduce a business''s costs?", "options": ["Government subsidies fully cover every environmental cost a business faces", "Energy-saving measures like solar panels and reduced packaging save money long-term", "Organic farming always costs less than using fertilisers and pesticides", "Environmentally friendly materials are always cheaper than the standard materials"], "answer": 1, "explain": "The card lists reduced costs from energy-saving measures as a benefit; it also notes environmental materials, organic farming and capital costs are often MORE expensive, not less."}}, {"title": "Key Case Studies", "html": "<p><strong>Pukka Teas (Fairtrade ethics):</strong> Certified ''Fair for Life'' producer. Turnover grew from £9m (2012) to £45m (2019) — proof ethical businesses can thrive. Cost: paid £148,000 into a Fairtrade community fund in 2017.</p>\n<p><strong>Olleco (Sustainability):</strong> Collects waste cooking oil/food to produce biodiesel. Revenue exceeds £220m across 19 UK sites. Cost: spent millions on R&D and specialist processing plants (anaerobic digesters).</p>\n<p><strong>Tesco (Unethical supplier treatment):</strong> Found guilty of delaying payments to small suppliers — one waited 24 months for £2 million, damaging their cash flow.</p>\n<p><strong>Unilever (Environment):</strong> Aims to halve greenhouse gas emissions by 2030 through ''cool blending'' and compressed packaging.</p>\n<p><strong>Shanks plc (Waste):</strong> Turns rubbish into fuel, compost and wood products instead of landfill — ''waste to product'' process.</p>\n<p><strong>Boohoo (Unethical sourcing):</strong> Faced heavy criticism in 2020/21 for supplier allegations of underpaying workers and ignoring COVID-19 safety rules in Leicester factories.</p>\n<p><strong>Woody''s Caravan Park:</strong> Reduced carbon emissions by 50% using electric vehicles and solar panels; pays above minimum wage; recycles all waste.</p>", "check": {"question": "According to the case studies in this card, what happened to Tesco regarding its suppliers?", "options": ["Tesco was found guilty of delaying payments, damaging a supplier''s cash flow", "Tesco stopped using any suppliers from developing countries entirely at all", "Tesco was praised for always paying its suppliers early and in full", "Tesco was the first retailer to gain full Fairtrade certification"], "answer": 0, "explain": "The card describes Tesco being found guilty of delaying payments to a small supplier for 24 months, damaging that supplier''s cash flow — an example of unethical supplier treatment."}}, {"title": "CSR and Long-Term Business Strategy", "html": "<p><strong>Corporate Social Responsibility (CSR)</strong> is the idea that businesses should be judged on their overall contribution to society — not just on profits. Key examples:</p>\n<ul>\n<li><strong>Next plc</strong> — recognises success is judged on ethical and environmental duties, not just financial performance</li>\n<li><strong>M&S ''Plan A''</strong> — three pillars: nourishing wellbeing, transforming local communities, caring for the planet</li>\n<li><strong>AstraZeneca</strong> — has a code of ethics at the centre of all its operations</li>\n<li><strong>Costa Coffee</strong> — uses Rainforest Alliance-certified suppliers for all coffee beans worldwide</li>\n</ul>\n<p><strong>Interdependence of ethics with other business areas:</strong></p>\n<ul>\n<li><strong>Marketing</strong> — ethical sourcing improves brand image; environmental friendliness can be promoted</li>\n<li><strong>Human Resources</strong> — ethical treatment of workers improves motivation, reduces turnover, lowers recruitment costs</li>\n<li><strong>Finance</strong> — ethical/environmental practices can raise costs but also reduce tax and attract investment</li>\n<li><strong>Operations</strong> — sustainable production methods change production processes and supply chains</li>\n</ul>", "check": {"question": "According to this card, what does ''Corporate Social Responsibility'' (CSR) mean?", "options": ["Businesses should only report their performance to their shareholders", "Businesses should ignore environmental and ethical duties completely", "Businesses should be judged on their overall contribution to society, not just profits", "Businesses should be judged only on their own annual financial profit figures each year"], "answer": 2, "explain": "The card defines CSR as the idea that businesses should be judged on their overall contribution to society, not just on profits, citing Next plc and M&S ''Plan A'' as examples."}}, {"title": "Case Studies: Olleco & Costa Coffee", "html": "<p><strong>Olleco (Environmental Focus):</strong><br>\n  Olleco collects used cooking oil and food waste from the catering industry and converts it into renewable energy (biofuels). Since 2006, they have grown from 1 site to 19 sites with sales exceeding £220m. <br><em>Impact:</em> While researching and developing new biofuel technology incurs massive R&D costs, their environmental focus has allowed them to survive and grow significantly in a highly competitive market.</p>\n  <p><strong>Costa Coffee (Ethical Focus):</strong><br>\n  Costa switched to using Rainforest Alliance-certified coffee beans. <br><em>Impact:</em> This ensures suppliers are treated fairly and farming is sustainable. It boosts Costa''s reputation against rivals like Starbucks, allowing them to attract ethically-minded consumers, even if the certified beans cost more to purchase.</p>", "check": {"question": "According to this card, how has Costa Coffee shown its ethical focus?", "options": ["By reducing the number of branches it operates in across the whole country", "By refusing to compete with rival coffee chains such as Starbucks", "By converting waste cooking oil into biofuels at its own sites", "By switching to Rainforest Alliance-certified coffee beans from its suppliers"], "answer": 3, "explain": "The card describes Costa Coffee''s ethical focus as switching to Rainforest Alliance-certified beans, ensuring fair supplier treatment and sustainable farming."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Ethics", "definition": "Focusing on what is morally ''right'' or ''wrong'' in business behavior, going beyond just legal requirements."}, {"term": "Fairtrade", "definition": "A movement encouraging businesses to pay a fair, livable price to suppliers and farmers in developing countries."}, {"term": "Child Labour", "definition": "The unethical use of young children below the legal age for employment to achieve low-cost production."}, {"term": "Sustainable Production", "definition": "Manufacturing that does not lead to the depletion of natural resources, protecting them for future generations."}, {"term": "Renewable Resources", "definition": "Resources that can be used more than once and do not run out (e.g., wind, solar, water)."}, {"term": "Non-renewable Resources", "definition": "Resources that can only be used once and will eventually run out (e.g., coal, oil, natural gas)."}, {"term": "Ethical Impact: Cost", "definition": "Acting ethically usually INCREASES costs because fair wages and ethically sourced materials are more expensive."}, {"term": "Ethical Impact: Reputation", "definition": "Acting ethically improves brand image, attracting loyal customers who are often willing to pay a premium price."}, {"term": "Environmental Considerations", "definition": "Sustainability, safe waste disposal, reducing pollution, and combating climate change."}, {"term": "Ethical Considerations", "definition": "Treatment of workers, fair treatment of suppliers, honest marketing to customers, and ethical sourcing."}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the definition of ''Ethics'' in business?", "options": ["Following the basic laws of the country", "Focusing on what is the ''right'' or ''wrong'' thing to do", "Maximizing profit at all costs", "Reducing the carbon footprint of a factory"], "answer": 1, "explain": "Correct answer: Ethics goes beyond the law and focuses on moral principles of right and wrong."}, {"question": "Which of the following is an example of a renewable resource?", "options": ["Coal", "Oil", "Natural Gas", "Wind power"], "answer": 3, "explain": "Correct answer: Wind power can be used more than once and does not run out, making it renewable."}, {"question": "What does ''Fairtrade'' encourage businesses to do?", "options": ["Pay the legal minimum wage in the UK", "Pay a fair price to suppliers in developing countries", "Trade goods without paying taxes", "Use child labour to keep costs fair for consumers"], "answer": 1, "explain": "Correct answer: Fairtrade ensures suppliers and farmers in developing nations receive a fair, livable price for their goods."}, {"question": "Sustainable production means:", "options": ["Producing goods as cheaply as possible", "Production that does not lead to the depletion of natural resources", "Producing goods that last a long time before breaking", "Using non-renewable resources exclusively"], "answer": 1, "explain": "Correct answer: Sustainability ensures we do not use up natural resources, leaving them available for future generations."}, {"question": "Which of the following is a major DISADVANTAGE of a business choosing to act ethically?", "options": ["It improves the brand''s reputation", "Employees are more motivated to work there", "It usually results in higher production costs", "Customers refuse to buy ethical products"], "answer": 2, "explain": "Correct answer: Paying fair wages, sourcing Fairtrade materials, and using safe conditions all increase the costs of production."}, {"question": "Which of the following is an ENVIRONMENTAL consideration (rather than an ethical one)?", "options": ["Paying suppliers on time", "Safe waste disposal and recycling", "Refusing to use child labour", "Not making false claims in advertising"], "answer": 1, "explain": "Correct answer: Waste disposal directly affects the physical planet, making it an environmental issue. The others are ethical issues regarding how people are treated."}, {"question": "Child labour is defined as:", "options": ["Employing anyone under the age of 21", "Using young children below the legal age for employment to achieve low-cost production", "Allowing children to visit their parents at work", "Selling products specifically designed for children"], "answer": 1, "explain": "Correct answer: Child labour is an unethical practice used to exploit young, under-age workers for cheap labour."}, {"question": "If an ethical business faces competitors who use unethical, cheap labour, what is a likely consequence?", "options": ["The ethical business will automatically have a monopoly", "The ethical business might struggle to compete on price", "The unethical competitors will immediately be shut down by the UN", "The ethical business''s costs will magically drop"], "answer": 1, "explain": "Correct answer: Unethical businesses have lower costs and can charge lower prices, potentially stealing price-sensitive customers from the ethical business."}, {"question": "How can being environmentally friendly benefit a business''s marketing?", "options": ["It allows them to ignore consumer laws", "It provides a Unique Selling Point (USP) that attracts green consumers", "It increases their carbon emissions", "It guarantees they will never make a loss"], "answer": 1, "explain": "Correct answer: Being ''green'' improves reputation and acts as a strong USP, allowing the business to market themselves positively."}, {"question": "A business delays paying its bills to small suppliers for 6 months to improve its own cash flow. This is considered:", "options": ["Environmentally friendly", "Fairtrade", "Unethical", "Sustainable"], "answer": 2, "explain": "Correct answer: Poor treatment of suppliers (like late payments) is an unethical business practice."}, {"question": "Woody''s Caravan Park switched to electric vehicles and solar panels. This primarily addresses which environmental issue?", "options": ["Child labour", "Climate change and carbon emissions", "False advertising", "Fairtrade sourcing"], "answer": 1, "explain": "Correct answer: Electric vehicles and solar panels directly reduce carbon emissions, combating climate change."}, {"question": "Why might a business choose to ignore environmental considerations?", "options": ["Because consumers hate green products", "To avoid the high costs of installing new green technology and renewable energy", "Because the government forces them to pollute", "Because renewable energy is illegal"], "answer": 1, "explain": "Correct answer: Implementing green technology (like Olleco''s R&D or installing solar panels) is very expensive in the short term."}]}, "fib": {"enabled": true, "questions": [{"text": "Ethics focuses on what is the [right] or [wrong] thing to do in business."}, {"text": "Using young children for cheap production is known as [child] [labour], which is highly unethical."}, {"text": "The [Fairtrade] movement encourages businesses to pay a fair [price] to suppliers in developing countries."}, {"text": "Production is considered [sustainable] if it does not lead to the depletion of natural [resources]."}, {"text": "Wind and solar power are examples of [renewable] energy, whereas oil and coal are [non-renewable]."}, {"text": "An ethical business might face higher [costs] because ethically sourced materials are more [expensive]."}, {"text": "Being environmentally friendly can improve a business''s [reputation], attracting more loyal [customers]."}, {"text": "A business must consider safe [waste] disposal and aim to recycle rather than send rubbish to [landfill]."}, {"text": "To combat climate [change], businesses are trying to reduce their carbon [emissions] by using electric vehicles."}, {"text": "Unethical competitors might charge [lower] prices, making it hard for an ethical business to [compete]."}, {"text": "Making false claims in marketing or advertising is considered [unethical] treatment of [customers]."}, {"text": "Employees are often more [motivated] to work for a business that treats people fairly and respects human [rights]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Ethics in business is solely about obeying the legal laws of the country.", "answer": false, "explain": "FALSE. Ethics goes beyond the law; it involves doing what is morally ''right'', even if the law does not strictly require it."}, {"statement": "Child labour is used by some unethical businesses to achieve low-cost production.", "answer": true, "explain": "TRUE. Unethical businesses exploit under-age workers because they can be paid extremely low wages."}, {"statement": "Fairtrade guarantees that consumers will get the cheapest possible price in the supermarket.", "answer": false, "explain": "FALSE. Fairtrade usually results in slightly higher prices for consumers, because it guarantees a fair, higher price is paid to the farmers/suppliers."}, {"statement": "Oil and natural gas are examples of renewable resources.", "answer": false, "explain": "FALSE. Oil and gas are non-renewable because they can only be used once and will eventually run out."}, {"statement": "A major disadvantage of installing environmentally friendly technology is the high initial cost.", "answer": true, "explain": "TRUE. Things like solar panels, electric vehicles, and researching biofuels require significant financial investment."}, {"statement": "Making false claims in an advertisement is considered an ethical marketing practice.", "answer": false, "explain": "FALSE. Lying or misleading customers is highly unethical (and often illegal)."}, {"statement": "Sustainable production ensures that natural resources are not depleted for future generations.", "answer": true, "explain": "TRUE. Sustainability is about balancing current needs without ruining the planet for the future."}, {"statement": "An ethical business will never have a competitive advantage.", "answer": false, "explain": "FALSE. Acting ethically can be a Unique Selling Point (USP), improving reputation and attracting loyal customers willing to pay premium prices."}, {"statement": "Treating suppliers ethically includes paying their invoices on time.", "answer": true, "explain": "TRUE. Deliberately delaying payments to suppliers can ruin small businesses and is considered unethical."}, {"statement": "Environmentally friendly policies have no impact on employee motivation.", "answer": false, "explain": "FALSE. Employees are generally much more motivated and proud to work for a company that respects the environment and treats people well."}, {"statement": "Reducing carbon emissions helps a business combat climate change.", "answer": true, "explain": "TRUE. Switching to electric vehicles or renewable energy reduces emissions and lessens environmental impact."}, {"statement": "All competitors in a market will always act ethically.", "answer": false, "explain": "FALSE. Many businesses choose to act unethically to keep costs low and maximize their own profits."}]}, "misc": {"enabled": true, "items": [{"myth": "Students confuse ''Ethical'' and ''Environmental'' considerations.", "truth": "ETHICAL is about how you treat PEOPLE (workers, suppliers, customers, no child labour). ENVIRONMENTAL is about how you treat the PLANET (sustainability, pollution, waste, renewable energy).", "check": {"question": "What is the correct distinction between ''ethical'' and ''environmental'' considerations?", "options": ["Ethical concerns how people are treated; environmental concerns how the planet is treated", "Ethical concerns the planet, while environmental concerns how people are treated", "Ethical and environmental considerations mean exactly the same thing in every business", "Ethical only applies to customers, while environmental only applies to suppliers"], "answer": 0, "explain": "The card explains ethical is about treatment of people (workers, suppliers, customers), while environmental is about treatment of the planet (sustainability, pollution, waste)."}}, {"myth": "Students think being ethical guarantees higher profits automatically.", "truth": "Being ethical usually increases COSTS (fair wages, fairtrade materials). It only increases profit IF the business can convince customers to pay a higher premium price to cover those costs.", "check": {"question": "Does being ethical automatically guarantee a business higher profits?", "options": ["Yes — ethical businesses are always guaranteed higher profits than their rivals", "No — it usually raises costs, and only increases profit if customers pay a premium", "Yes — being ethical automatically removes all extra costs for a business", "No — ethical businesses can never make a profit under any circumstances"], "answer": 1, "explain": "The card explains ethical behaviour usually raises costs, and only increases profit if the business can convince customers to pay a higher premium price."}}, {"myth": "Students think non-renewable resources can be recycled forever.", "truth": "Non-renewable resources (like coal and oil) are burned/used once and are gone forever. Renewable resources (like wind and solar) never run out.", "check": {"question": "Can non-renewable resources be recycled and reused forever?", "options": ["No — renewable resources like wind and solar also run out eventually", "No — non-renewable resources like coal and oil are used once and are gone", "Yes — non-renewable resources can be recycled indefinitely without any limit", "Yes — but only renewable resources like oil can be recycled forever"], "answer": 1, "explain": "The card explains non-renewable resources like coal and oil are burned or used once and are gone forever, unlike renewable resources such as wind and solar which never run out."}}, {"myth": "For ''analyse'' questions, students just state ''it gives a good reputation''.", "truth": "You must explain the BUSINESS IMPACT. ''It improves reputation (U), which attracts more ethically-minded customers (APP), leading to an increase in sales revenue and market share (AN).''", "check": {"question": "What must a full ''analyse'' answer include, beyond stating ''it gives a good reputation''?", "options": ["Only the same statement repeated using slightly different wording again", "The business impact — e.g. how reputation leads to increased sales revenue", "A complete list of every possible ethical consideration a business could make", "A definition of environmental considerations rather than ethical ones"], "answer": 1, "explain": "The card explains you must explain the business impact — reputation (U) attracting ethical customers (APP) leading to increased sales revenue and market share (AN)."}}, {"myth": "Obeying the law (e.g. paying minimum wage, not discriminating) counts as ethical behaviour.", "truth": "Ethics is about what a firm does OVER AND ABOVE what the law requires. Paying the minimum wage is a legal obligation — not an ethical choice. Ethical behaviour means going further: paying a living wage, treating suppliers fairly, and choosing Fairtrade even when not legally required.", "check": {"question": "Does obeying the law, such as paying minimum wage, count as ethical behaviour?", "options": ["Yes — any legal requirement automatically counts as ethical behaviour too", "Yes — minimum wage is specifically an ethical rather than legal requirement", "No — ethical behaviour can only ever apply to environmental issues instead", "No — ethics is about going over and above what the law legally requires"], "answer": 3, "explain": "The card explains ethics is about what a firm does over and above the law — paying minimum wage is a legal obligation, not an ethical choice."}}, {"myth": "Environmental considerations and ethical considerations are the same thing and can be used interchangeably.", "truth": "They are different. ETHICAL considerations concern the treatment of people — workers, suppliers and customers (fair pay, child labour, false claims). ENVIRONMENTAL considerations concern the natural world — pollution, global warming, waste disposal, sustainable production. Mixing them up loses marks in the exam.", "check": {"question": "Are ethical and environmental considerations the same thing that can be used interchangeably?", "options": ["No — ethical concerns people, while environmental concerns the natural world", "No — ethical considerations only ever apply to a business''s suppliers alone", "Yes — environmental considerations are simply one type of ethical consideration", "Yes — both terms describe exactly the same set of business considerations"], "answer": 0, "explain": "The card explains ethical considerations concern the treatment of people, while environmental considerations concern the natural world — mixing them up loses exam marks."}}, {"myth": "Being ethical is always bad for business because it increases costs.", "truth": "Being ethical has BOTH costs and benefits. Yes, it raises costs (higher wages, Fairtrade prices) but it also brings benefits: improved reputation, increased sales from ethical consumers, more motivated staff (lower turnover and recruitment costs), and long-term survival. The net effect depends on the market and the business.", "check": {"question": "Is being ethical always bad for business because it increases costs?", "options": ["Yes — being ethical only ever increases costs with no benefits at all whatsoever", "No — it has both costs and benefits, such as improved reputation and sales", "Yes — ethical businesses always make a loss in the long run overall", "No — being ethical never increases a business''s costs in any way at all"], "answer": 1, "explain": "The card explains being ethical has both costs (higher wages, Fairtrade prices) and benefits (reputation, sales, motivation, long-term survival) — the net effect depends on the market."}}, {"myth": "Using robotics instead of workers is an example of ethical treatment of the workforce.", "truth": "Using robotics is a business OPERATIONS/TECHNOLOGY decision, not an ethical one. Ethical treatment of workers is about HOW existing and future human workers are treated — pay, hours, safety, fairness. Replacing workers with machines is a productivity/cost decision, not an ethical employer practice.", "check": {"question": "Is using robotics instead of workers an example of ethical treatment of the workforce?", "options": ["Yes — replacing workers with robots is always considered ethical practice", "No — it is an operations/technology decision, not an ethical one at all", "No — but only because robots are classed as an environmental consideration", "Yes — robotics automatically improves the pay and safety of remaining staff"], "answer": 1, "explain": "The card explains using robotics is an operations/technology decision about productivity and cost, not an ethical decision about how human workers are treated."}}, {"myth": "For ''analyse one benefit of being ethical'' (3 marks), stating ''the business gets a better reputation'' is enough.", "truth": "3 marks require: Understanding (1) — explain what the ethical action is. Application (1) — link to the specific business using case study detail. Analysis (1) — show the business IMPACT (e.g. ''this leads to increased sales and higher revenue''). A bare statement earns only 1 mark. You must chain: ethical action → intermediate effect → business consequence.", "check": {"question": "Why does ''the business gets a better reputation'' alone not earn all 3 marks?", "options": ["It is missing application to the specific business and analysis of the impact", "It already contains full understanding, application and analysis in one sentence", "It is factually incorrect, since ethical businesses never gain a better reputation", "It only ever applies to environmental considerations, not ethical ones"], "answer": 0, "explain": "The card explains a bare statement earns only 1 mark — full marks require Application (link to the specific business) and Analysis (the business impact) as well."}}, {"myth": "The Fairtrade Mark guarantees that a product is organic and environmentally produced.", "truth": "The Fairtrade Mark specifically guarantees that a FAIR PRICE was paid to the farmers/suppliers in developing countries. It is an ETHICAL guarantee about fair treatment of suppliers — not a guarantee about organic farming or environmental production methods, though these may overlap.", "check": {"question": "What does the Fairtrade Mark actually guarantee?", "options": ["That a fair price was paid to farmers and suppliers in developing countries", "That a product was produced using only renewable sources of energy", "That a product contains no ingredients sourced from developing countries", "That a product was grown organically without any pesticides or chemicals"], "answer": 0, "explain": "The card explains the Fairtrade Mark is an ethical guarantee about fair supplier treatment — not a guarantee about organic farming or environmental production methods."}}, {"myth": "For a 9-mark evaluate question, listing as many ethical and environmental points as possible will score high marks.", "truth": "9-mark questions require a structured chain: K (define) → U (explain) → APP x2 (use the case study twice) → AN x2 (show the business impact) → EVAL (make a judgement and justify it using the context). Listing generic points without application to the case study earns very few marks. Depth and context always outperform breadth.", "check": {"question": "For a 9-mark evaluate question, is listing as many points as possible the best strategy?", "options": ["No — a structured chain with application and analysis scores far more highly", "Yes — the more points listed, the higher the mark awarded every single time", "Yes — application to the case study is not required in a 9-mark question", "No — but only because 9-mark questions do not require any evaluation at all"], "answer": 0, "explain": "The card explains 9-mark questions require a structured K-U-APP-AN-EVAL chain — listing generic points without case study application scores very few marks."}}]}, "tips": {"enabled": true, "items": [{"title": "Naming Considerations", "html": "<p>If asked to state an <strong>Ethical</strong> consideration, use: Fair wages, child labour, Fairtrade, treating suppliers fairly.</p>\n  <p>If asked to state an <strong>Environmental</strong> consideration, use: Waste disposal, pollution, sustainability, carbon emissions.</p>", "check": {"question": "According to this card, which of these would correctly answer a question asking for an environmental consideration?", "options": ["Fair wages, child labour, Fairtrade or treating suppliers fairly", "Waste disposal, pollution, sustainability or carbon emissions", "Break-even, cash flow, profit margin or average rate of return", "Market segmentation, market research, product life cycle or price"], "answer": 1, "explain": "The card lists waste disposal, pollution, sustainability and carbon emissions as environmental considerations; the other options are ethical, finance, or marketing terms."}}, {"title": "Analysing the Disadvantages", "html": "<p>Always remember that Ethics and Environment cost money.</p>\n  <p><strong>Structure:</strong> \"One reason not to be environmentally friendly is the high initial cost (U). For example, installing solar panels to power the caravan park is expensive (APP). This drains cash flow and could reduce short-term profit margins (AN).\"</p>", "check": {"question": "According to this card''s example, what is the Understanding (U) point in the solar panel argument?", "options": ["This drains cash flow and could reduce short-term profit margins here", "The caravan park has fully repaid its solar panel investment already", "Installing solar panels to power the caravan park is expensive to do", "One reason not to be environmentally friendly is the high initial cost"], "answer": 3, "explain": "The card''s model structure identifies ''the high initial cost'' as the Understanding (U) point, before the Application (solar panels) and Analysis (drains cash flow) steps."}}, {"title": "Using the Context Data", "html": "<p>In large questions (like the Costa Coffee 9-marker), you MUST use the data provided.</p>\n  <p>If the text says Costa has 2,100 branches or competes with Starbucks, use those exact facts in your Application (APP) sentences to secure top marks. Do not write a generic essay about ethics.</p>", "check": {"question": "According to this card, what must a strong Costa Coffee 9-mark answer avoid writing?", "options": ["A final judgement given at the end of the answer about Costa Coffee''s ethics", "Any reference at all to the number of branches Costa Coffee operates", "Any comparison at all between Costa Coffee and its rival Starbucks", "A generic essay about ethics that does not use the specific case study facts"], "answer": 3, "explain": "The card warns you must use exact facts from the text, such as branch numbers or the Starbucks comparison, rather than writing a generic essay about ethics."}}, {"title": "Identify two ethical/environmental considerations (2 marks)", "html": "<p><strong>Ethical:</strong> Treatment of workers, Treatment of suppliers, Treatment of customers, Sourcing of materials.</p>\n  <p><strong>Environmental:</strong> Sustainability, Waste disposal, Pollution, Climate change.</p>\n  <p><em>Tip:</em> Give the CATEGORY name — not just an example. e.g., ''Treatment of workers'' earns the mark; ''paying fair wages'' alone may not unless the question asks you to explain.</p>", "check": {"question": "According to this card, what should you give when asked to identify a consideration?", "options": ["A full paragraph explaining the consideration in complete detail", "A specific example only, and never the broader category name", "A calculation showing the cost of the consideration in pounds", "The category name itself, not just a specific example of it"], "answer": 3, "explain": "The card advises giving the category name — e.g. ''Treatment of workers'' — since a specific example alone may not earn the mark unless the question asks you to explain."}}, {"title": "Analyse one benefit/disadvantage of being ethical (3 marks)", "html": "<p><strong>Structure:</strong></p>\n  <ul>\n    <li><strong>(U)</strong> State and explain the benefit e.g., ''ethical businesses often gain an improved reputation''.</li>\n    <li><strong>(APP)</strong> Link to the specific business — e.g., ''Pukka Teas'' turnover rose from £9m to £45m''.</li>\n    <li><strong>(AN)</strong> Show the business impact — ''this increased revenue can be reinvested to fund further growth''.</li>\n  </ul>\n  <p>A chain of three linked points earns all 3 marks.</p>", "check": {"question": "In the Pukka Teas example on this card, which part is the Application (APP) point?", "options": ["A chain of three linked points together earns all three marks available", "Pukka Teas'' turnover rose from nine million pounds to forty-five million", "Ethical businesses often gain an improved reputation as a result", "This increased revenue can be reinvested to fund further growth plans"], "answer": 1, "explain": "The card identifies Pukka Teas'' turnover growth (£9m to £45m) as the Application point, linking the general Understanding point to a specific business."}}, {"title": "Analyse one method of sustainable production (3 marks)", "html": "<p>Name the method (e.g., solar panels / renewable energy). Apply it to the specific business in the case study. Analyse the business impact — usually reduced costs OR improved reputation &rarr; increased sales.</p>\n  <p><strong>Example:</strong> ''Aston Martin could install solar panels (K) to power its Warwickshire production site (APP) which would cut energy costs and reduce its carbon footprint, improving its environmental image (AN).''</p>", "check": {"question": "In the Aston Martin example on this card, what is being analysed as the business impact?", "options": ["The specific geographic location of Aston Martin''s production site", "Installing solar panels at its Warwickshire production site directly", "The general concept of renewable energy as a sustainable method overall", "Cutting energy costs and improving its environmental image as a result"], "answer": 3, "explain": "The card''s Analysis (AN) step identifies cutting energy costs and improving environmental image as the business impact of installing solar panels."}}, {"title": "Evaluate whether ethical/environmental considerations conflict with shareholder objectives", "html": "<p><strong>Structure:</strong></p>\n  <ul>\n    <li><strong>K:</strong> Define ethics.</li>\n    <li><strong>U:</strong> Explain how ethical practices work (e.g., fair wages, Fairtrade sourcing).</li>\n    <li><strong>APP x2:</strong> Use the case study to show two specific ethical actions.</li>\n    <li><strong>AN x2:</strong> Show how each raises costs or reduces profits — conflicting with shareholder profit goals.</li>\n    <li><strong>EVAL:</strong> Judge the EXTENT of conflict — e.g., in the LONG TERM, ethical businesses like Pukka Teas may generate more profit through increased sales, but SHORT TERM costs rise and dividends may fall.</li>\n  </ul>", "check": {"question": "According to this card''s example, how might ethical practices conflict with shareholder objectives?", "options": ["They raise costs or reduce profits in the short term, before benefits appear", "They remove the need for a business to consider its costs at all in future", "They have no effect on shareholder objectives in either the short or long term", "They guarantee higher dividends to shareholders immediately every single year"], "answer": 0, "explain": "The card explains ethical practices can raise costs or reduce profits short-term, conflicting with shareholder goals, even though long-term profit may rise through increased sales."}}, {"title": "Evaluate how environmental considerations affect the marketing mix", "html": "<p>Link environment to each P:</p>\n  <ul>\n    <li><strong>Product:</strong> May need to redesign packaging (e.g., Pukka Pies replacing non-recyclable plastics).</li>\n    <li><strong>Price:</strong> May need to rise to cover eco costs.</li>\n    <li><strong>Place:</strong> Distribution using lower-emission vehicles.</li>\n    <li><strong>Promotion:</strong> Green credentials become a marketing message.</li>\n  </ul>\n  <p><strong>Evaluate</strong> which P is most affected, using case study figures. e.g., ''Price is most affected as no waste to landfill reduces costs, offsetting the cost of new packaging.''</p>", "check": {"question": "In this card''s example, why might ''Price'' be judged the most affected element of the marketing mix?", "options": ["Promotion is always more affected than price by any environmental change", "Place is always more affected than price by any environmental change", "Price is never affected by any environmental consideration at all here", "No waste to landfill reduces costs, offsetting the cost of new packaging"], "answer": 3, "explain": "The card''s example judges Price as most affected because reduced landfill waste cuts costs, offsetting the cost of new eco-friendly packaging."}}, {"title": "Do NOT confuse ethical with legal, or ethical with environmental", "html": "<p>Three common errors that lose marks:</p>\n  <ol>\n    <li><strong>Describing legal compliance</strong> (e.g., paying minimum wage) as an ethical choice — it is a legal duty. Ethics goes BEYOND the law.</li>\n    <li><strong>Writing about pollution and sustainability</strong> when asked about ethics — these are environmental issues.</li>\n    <li><strong>Writing about fair pay and child labour</strong> when asked about environmental considerations — these are ethical issues.</li>\n  </ol>", "check": {"question": "According to this card, why is describing minimum wage payment as an ''ethical choice'' a common error?", "options": ["Ethics and legal compliance are officially treated as the same concept", "Minimum wage payments are actually classed as an environmental consideration", "Paying minimum wage is a legal duty, and ethics goes beyond the law", "Minimum wage does not exist as a legal requirement in any country at all"], "answer": 2, "explain": "The card lists this as a common error — describing legal compliance like minimum wage as an ethical choice, when ethics specifically goes beyond what the law requires."}}, {"title": "Short-term costs vs. long-term benefits — the key evaluation point", "html": "<p>The strongest evaluations in this unit recognise that:</p>\n  <ul>\n    <li><strong>In the SHORT TERM:</strong> ethical/environmental practices raise costs, may reduce profits, and could conflict with shareholder objectives.</li>\n    <li><strong>In the LONG TERM:</strong> they improve reputation, increase sales, motivate workers, reduce turnover, attract investors, and can lower costs (e.g., solar panels).</li>\n  </ul>\n  <p>Always judge whether short-term costs are outweighed by long-term benefits, using the specific business context.</p>", "check": {"question": "According to this card, what should the strongest evaluations recognise?", "options": ["Long-term benefits never apply to ethical or environmental practices at all", "Short-term costs may be outweighed by long-term benefits, given the context", "Short-term costs always outweigh every possible long-term benefit available", "Ethical and environmental practices have no effect on costs whatsoever"], "answer": 1, "explain": "The card advises the strongest evaluations judge whether short-term costs are outweighed by long-term benefits, using the specific business context."}}, {"title": "Always use specific case study numbers", "html": "<p>Application marks are ONLY awarded when you use the specific details from the case study — not generic statements.</p>\n  <ul>\n    <li><strong>Wrong:</strong> ''The business is growing.''<br><strong>Right:</strong> ''Pukka Teas'' turnover rose from £9m in 2012 to £45m in 2019.''</li>\n    <li><strong>Wrong:</strong> ''The business paid money to a fund.''<br><strong>Right:</strong> ''Pukka Teas paid £148,000 into the Fairtrade community fund in 2017.''</li>\n  </ul>\n  <p>Always quote figures, names and specific facts from the text.</p>", "check": {"question": "According to this card, when are Application marks actually awarded?", "options": ["Only when no numbers or figures are mentioned anywhere in the answer", "Whenever a generic statement like ''the business is growing'' is used instead", "Automatically, regardless of whether any case study detail is used at all", "Only when specific case study details, figures or names are actually used"], "answer": 3, "explain": "The card explains Application marks are only awarded when specific case study details are used — e.g. ''Pukka Teas'' turnover rose from £9m to £45m'' rather than a generic claim."}}]}, "exam": {"enabled": true, "questions": [{"question": "Evaluate whether Primark Ltd''s use of ethical suppliers comes into conflict with its shareholders'' objectives. [9 marks]", "marks": 9, "hint": "Think about what shareholders want from a business — profits, dividends, growth, share price. Then consider what using ethical suppliers costs. Does this help or hinder those objectives? You must come to a clear, justified judgement at the end specific to Primark.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1a (1 mark):</strong> Knowledge of ethics</li>\n    <li><strong>AO1b (1 mark):</strong> Understanding of ethics</li>\n    <li><strong>AO2 (2 marks):</strong> Synoptic application — examples of shareholder objectives only (not application to Primark itself)</li>\n    <li><strong>AO3a (2 marks):</strong> Analysis — how ethical suppliers affect a shareholder objective</li>\n    <li><strong>AO3b (3 marks):</strong> Evaluation — justified, contextual judgement about whether conflict exists</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Knowledge (1 mark)</h5>\n  <ul>\n    <li>Ethics focuses on doing what is right or wrong</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Understanding (1 mark)</h5>\n  <ul>\n    <li>Pay suppliers a fair and appropriate amount</li>\n    <li>Using fair trade suppliers</li>\n    <li>Treat their workers well (no reward for legal requirements)</li>\n    <li>Using sustainable resources</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Application — synoptic only (up to 2 marks)</h5>\n  <p>Reference to the context of a shareholder objective:</p>\n  <ul>\n    <li>Profits / profitability</li>\n    <li>Growth of the business</li>\n    <li>Reputation of the business</li>\n    <li>Share price / value (market capitalisation)</li>\n    <li>Dividends</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Analysis (up to 2 marks)</h5>\n  <ul>\n    <li>Higher costs will lead to lower profits</li>\n    <li>Decreased profits mean less dividends for shareholders</li>\n    <li>May increase the price of clothes for customers, and Primark could lose share value</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Evaluation (up to 3 marks)</h5>\n  <ul>\n    <li>Primark''s ethical supply chain will / will not come into conflict with the owners'' objectives</li>\n    <li>Other factors may be more important</li>\n    <li>Other things may conflict with the shareholder''s objectives, like providing a good service</li>\n    <li>Consideration of short-term costs versus long-term benefits</li>\n    <li>A judgement about why a particular shareholder objective is most affected</li>\n  </ul>\n  <p><em>Decision must be explicit for 1 mark. For 2 marks there must be a valid justification. For full 3 marks the evaluation must be contextual to Primark.</em></p>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>General stakeholder objectives (must be shareholder objectives specifically)</li>\n    <li>Environmental considerations</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>About one in six candidates did not attempt this question. Only 10% of answers contained specific knowledge of what ethics means. About half gave a suitable example of ethical behaviour to gain the understanding mark. Many candidates confused shareholders with stakeholders — answers solely about other stakeholders gained very little reward. Many did not know any shareholder objectives and listed items from the text instead. Most weaker answers did not make any attempt to evaluate.</p>\n</div>"}, {"question": "A health centre wishes to improve its environmental sustainability. Which of the following would help achieve this? [1 mark]", "marks": 1, "hint": "Environmental sustainability means reducing the impact on the natural world. Which option directly saves energy or resources?", "markScheme": "<div class=\"marks-section\">\n  <h5>Correct answer: D</h5>\n  <p>Installing sensors to switch off lights when not needed directly reduces energy consumption, improving the environmental sustainability of the health centre.</p>\n  <p>Options A, B, and C all relate to health or wellbeing of staff and patients — they are not environmental sustainability measures.</p>\n</div>"}, {"question": "Identify two ethical considerations a business may have. [2 marks]", "marks": 2, "hint": "Ethics is about doing what is fair and right — going beyond legal requirements. Think about how a business treats its workers, suppliers, and customers in a way that is morally fair, not just legally required.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO1a: 2 marks)</h5>\n  <p>One mark for each correct ethical consideration, up to a maximum of two. Answers do not need to relate to AZ.</p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Treatment of workers (e.g., fair wage, child labour, modern slavery)</li>\n    <li>Treatment of suppliers (e.g., fair prices, payment terms)</li>\n    <li>Treatment of customers</li>\n    <li>Ethical marketing factors</li>\n    <li>How to source materials (e.g., ethical credentials, fair trade, sustainability)</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Environmental considerations (e.g., less use of fertilisers)</li>\n    <li>Issues which are legal requirements (e.g., pay the minimum wage, discrimination, working conditions, illegal advertising)</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>Around three quarters of candidates gave at least one answer which is a legal requirement or an environmental issue. Ethics considers what is the ''right'' or ''fair'' thing to do, rather than what is legally required.</p>\n</div>"}, {"question": "Identify two possible advantages to a business of being environmentally friendly. [2 marks]", "marks": 2, "hint": "Focus on advantages for the business itself — not for the planet or customers. Think about how being green can help a business with its costs, reputation, sales, or investment.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO1b: 2 marks)</h5>\n  <p>One mark for each advantage to a business of being environmentally friendly. Answers do not need to relate to BP.</p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Increases sales / more customers</li>\n    <li>Increases publicity / promotion / advertising / reputation</li>\n    <li>Can increase prices (competitive advantage)</li>\n    <li>Reduces costs</li>\n    <li>Reduces tax bills</li>\n    <li>Receive subsidies</li>\n    <li>Reduces resource scarcity / more sustainable business</li>\n    <li>Attracts investment</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Advantages which are not for a business (e.g., reduced emissions, climate change, reduced carbon footprint)</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>Most candidates scored 1 or 2 marks, with most selecting increased reputation and increased sales. Less successful responses ignored the phrase ''to a business'' and gave responses about consumer behaviour or advantages for climate change.</p>\n</div>"}, {"question": "Explain one way climate change might affect business activity. [2 marks]", "marks": 2, "hint": "Climate change means long-term shifts in global temperatures and weather patterns. Think about how this changes what a business does — does it force them to change behaviour, switch to renewables, alter their marketing, or face new costs? Focus on the business response, not the effect on the planet.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO1a: 1 mark, AO1b: 1 mark)</h5>\n  <ul>\n    <li>One mark for knowledge of a way climate change affects business activity</li>\n    <li>One mark for a further exemplification of that way</li>\n  </ul>\n  <p>Answers do not need to relate to BP.</p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Leads to a change in business behaviour (e.g., switch to renewable energy, go greener, aim to be more sustainable)</li>\n    <li>Lead to marketing campaigns which publicise the firm''s ''green'' credentials</li>\n    <li>Risk to supplies / raw materials</li>\n    <li>Opportunities to supply goods (e.g., more sustainable products)</li>\n    <li>Increased costs of insurance</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>The effect of climate change on other stakeholders</li>\n    <li>The impact of policies in response to climate change</li>\n    <li>Answers which only consider the impact of ''bad weather''</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>One of the least well answered questions on the paper, with many candidates scoring zero. Many candidates did not know what was meant by climate change, with references to ''poor weather'' or ''oceans freezing over''. Few candidates identified how the business would respond to climate change — they described what happened rather than the change the business would make. Other responses considered the implication for the planet rather than the business.</p>\n</div>"}, {"question": "Identify two ethical considerations for a business. [2 marks]", "marks": 2, "hint": "Ethics is about doing what is fair and right — not what is legally required. Think about how a business treats workers, suppliers, or customers in a way that is morally fair but not a legal obligation.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO1a: 2 marks)</h5>\n  <p>One mark for each of two correct considerations. Answers do not need to relate to any specific company.</p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Treatment of workers (e.g., fair wage, child labour, modern slavery)</li>\n    <li>Treatment of suppliers (e.g., fair prices, payment terms)</li>\n    <li>Treatment of customers</li>\n    <li>Ethical marketing factors</li>\n    <li>How to source materials (e.g., ethical credentials, fair trade)</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Environmental considerations (e.g., less use of fertilisers)</li>\n    <li>Issues which are legal requirements (e.g., pay the minimum wage, discrimination, safe working conditions, illegal advertising)</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>Most candidates scored 1 or 2 marks. However, a significant minority listed legal requirements such as minimum wage or discrimination, or environmental issues. Ethics is about what is fair or is over and above what is legally required.</p>\n</div>"}, {"question": "Explain one reason why a business should act ethically. [2 marks]", "marks": 2, "hint": "Think about the benefits to a business of being ethical — what does it do for the business''s reputation, customers, employees, or suppliers? Make sure you explain the reason, not just state it.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO1a: 1 mark, AO1b: 1 mark)</h5>\n  <ul>\n    <li>One mark for knowledge of a reason why a business may act ethically</li>\n    <li>One mark for a further exemplification of that reason</li>\n  </ul>\n  <p>Answers do not need to relate to any specific company.</p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Customers may shop at ethical firms — as they want to be associated with businesses which act fairly</li>\n    <li>Suppliers may want to work with the company — as they want to be associated with businesses which do more than the law requires</li>\n    <li>Investors might want to be associated with an ethical firm — as they want to be associated with businesses which act fairly</li>\n    <li>Improved motivation of employees — who want to work for firms which have ethical standards</li>\n    <li>Improved reputation — which may give them a competitive advantage</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Suggesting it helps them to avoid breaking the law or being fined</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>Even candidates who were unable to correctly identify an ethical consideration were at least able to explain why it was important to be ethical. The most common responses focused on it being about a firm''s marketing, so that it appeared to act in a ''good'' way so it was able to attract customers or employees more easily.</p>\n</div>"}, {"question": "A business wishes to be known as an ethical employer. Which of the following is NOT an example of ethical treatment of the workforce? [1 mark]", "marks": 1, "hint": "The question asks for what is NOT ethical treatment of workers. Three options clearly benefit employees directly. Which one is about business efficiency rather than how workers are treated?", "markScheme": "<div class=\"marks-section\">\n  <h5>Correct answer: D — Using robotics</h5>\n  <p>Using robotics is about production technology and business efficiency — it does not directly represent ethical treatment of the workforce.</p>\n  <ul>\n    <li>Flexible working (A) — directly benefits workers</li>\n    <li>Paying high wages (B) — directly benefits workers</li>\n    <li>Good working conditions (C) — directly benefits workers</li>\n    <li>Using robotics (D) — relates to production, not the ethical treatment of employees</li>\n  </ul>\n</div>"}, {"question": "Analyse one way Barclays plc could treat its customers ethically. [3 marks]", "marks": 3, "hint": "Think about what Barclays does — it provides financial products like loans, savings, and insurance. How could it treat its customers fairly and honestly in how it sells or provides these? Then explain what would happen as a result for the business.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of one way a business could treat customers ethically — no further marks without this</li>\n    <li><strong>AO2 (1 mark):</strong> Application to Barclays specifically</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of the impact for a business of treating customers ethically</li>\n  </ul>\n  <p><em>Note: There is no AO1a (knowledge) mark for this question.</em></p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Understanding may include:</h5>\n  <ul>\n    <li>Firms should act in ways that customers consider to be fair including pricing, information, advertising and product availability</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Application may include:</h5>\n  <ul>\n    <li>Financial products</li>\n    <li>Global bank with many customers worldwide</li>\n    <li>Barclays has a core value of integrity</li>\n    <li>Provides online services</li>\n    <li>Rapid growth in online banking</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Analysis may include:</h5>\n  <ul>\n    <li>Lying to customers will lead to poor brand image</li>\n    <li>Advertising is not misleading so customers make better decisions</li>\n    <li>Products are priced fairly so customers remain loyal</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Answers about customer service in general</li>\n    <li>Answers which are linked to legal requirements (e.g., consumer law or discrimination)</li>\n  </ul>\n</div>"}, {"question": "Evaluate how Pukka Pies Ltd''s environmental considerations might influence its marketing mix. [9 marks]", "marks": 9, "hint": "The marketing mix has four elements: Product, Price, Place, Promotion. Think about how being more environmentally conscious could affect each of these for Pukka Pies. Use details from the case study (recycled packaging, no landfill waste). You need to come to a clear judgement at the end about the overall impact.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1a (1 mark):</strong> Knowledge of the environment</li>\n    <li><strong>AO1b (1 mark):</strong> Understanding of environmental considerations</li>\n    <li><strong>AO2 (2 marks):</strong> Synoptic application — must reference marketing mix elements</li>\n    <li><strong>AO3a (2 marks):</strong> Analysis — must be a business-facing impact</li>\n    <li><strong>AO3b (3 marks):</strong> Evaluation — for full 3 marks, must be contextual to Pukka Pies</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Knowledge (1 mark)</h5>\n  <ul>\n    <li>The environment is about our natural world</li>\n    <li>Environmentalism is about trying to keep the impact of business operations on the environment to a minimum</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Understanding (1 mark)</h5>\n  <ul>\n    <li>Sustainability issues — including examples</li>\n    <li>Waste disposal</li>\n    <li>Pollution</li>\n    <li>Climate change</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Application — synoptic (up to 2 marks)</h5>\n  <ul>\n    <li><strong>Product</strong> — impact on range of products, types of products or packaging (not quantity)</li>\n    <li><strong>Price</strong> — impact on prices</li>\n    <li><strong>Place</strong> — how distribution/transportation is carried out or where products are sold</li>\n    <li><strong>Promotion</strong> — efforts to make customers aware of being more environmentally friendly</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Analysis (up to 2 marks)</h5>\n  <ul>\n    <li>It may result in Pukka Pies changing its pie range (e.g., vegan pies) using more environmentally friendly suppliers</li>\n    <li>The business may need to change its promotion — e.g., create an advertising campaign that stresses a more environmentally approach to choosing suppliers of its raw materials</li>\n    <li>Pricing may have to change in response to higher supplier costs / distribution costs higher (electric vans)</li>\n    <li>Packaging can be replaced with recyclable materials or used to show the environmentally friendly nature of the product</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Evaluation (up to 3 marks)</h5>\n  <ul>\n    <li>Whether environmental considerations will have major implications for Pukka Pies'' marketing mix compared to other factors</li>\n    <li>Whether the impact is larger for one element of the mix than another</li>\n    <li>The relative importance of environmental considerations</li>\n    <li>Use of contextual evidence to support any judgement</li>\n  </ul>\n</div>"}, {"question": "State one ethical consideration a business may need to consider. [1 mark]", "marks": 1, "hint": "Ethics is about what is fair and morally right — not legal requirements. Think about fair treatment of workers, suppliers, or customers.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO1a: 1 mark)</h5>\n  <p>1 mark for a correct ethical consideration. Answers do not need to relate to Aston Martin.</p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Treatment of workers (e.g., child labour, fair wages)</li>\n    <li>Treatment of customers</li>\n    <li>Treatment of suppliers</li>\n    <li>Sourcing of raw materials (e.g., Fairtrade)</li>\n    <li>Marketing / ethical marketing (e.g., fair prices)</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Answers which are clearly legal considerations (e.g., discrimination, minimum wage)</li>\n    <li>Answers which are clearly environmental considerations (e.g., pollution, sustainability)</li>\n  </ul>\n</div>"}, {"question": "Analyse one method of sustainable production that AM plc could use. [3 marks]", "marks": 3, "hint": "Sustainable production means producing goods in a way that reduces the impact on the environment and preserves resources for the future. Think about what AM plc specifically does — luxury car manufacture, large production site, over 3,000 workers, global transportation — and choose a method that fits.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1a (1 mark):</strong> Knowledge of a method of sustainable production — no further marks without this</li>\n    <li><strong>AO2 (1 mark):</strong> Application to AM plc, using evidence from the text</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of how using that method may affect a business</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Knowledge may include:</h5>\n  <ul>\n    <li>Using renewable resources or less non-renewable resources</li>\n    <li>Using solar energy in production</li>\n    <li>Sustainable construction</li>\n    <li>Saving water / switching off lights</li>\n    <li>Disposing of waste properly</li>\n    <li>Transportation (of workers and supplies)</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Answers which just focus on producing ''greener'' cars / products</li>\n  </ul>\n</div>"}, {"question": "Which of the following issues is climate change an example of? [1 mark]", "marks": 1, "hint": "Climate change concerns the long-term impact of human activity on the natural world. Which category does that belong to?", "markScheme": "<div class=\"marks-section\">\n  <h5>Correct answer: D — An environmental issue</h5>\n  <p>Climate change is an environmental issue — it concerns the impact of human activity on the natural world, including rising global temperatures and changing weather patterns. It is not primarily a financial, quality control, or economic issue.</p>\n</div>"}, {"question": "Analyse one impact that ethical considerations may have on Virgin Atlantic. [3 marks]", "marks": 3, "hint": "Think about an area of ethics (e.g., treatment of workers, customers, or suppliers) and how it specifically applies to what Virgin Atlantic does as an airline. Then explain the consequence for the business.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of ethical considerations</li>\n    <li><strong>AO2 (1 mark):</strong> Application of ethical considerations to Virgin Atlantic</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of an impact of ethical considerations on Virgin Atlantic</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Answers may include:</h5>\n  <ul>\n    <li>The treatment of its employees — wages, hours, safe working conditions</li>\n    <li>The treatment of its suppliers</li>\n    <li>Choice of ethical suppliers — e.g., do suppliers pay appropriately? Not use child labour?</li>\n    <li>Level of employee pay</li>\n    <li>Treatment of customers</li>\n  </ul>\n</div>"}, {"question": "Analyse one impact that environmental considerations may have on Virgin Atlantic. [3 marks]", "marks": 3, "hint": "Think about the type of business Virgin Atlantic is — an airline that flies millions of passengers worldwide. What environmental concerns apply specifically to aviation? Then analyse the financial or operational impact on the business.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of environmental considerations</li>\n    <li><strong>AO2 (1 mark):</strong> Application of environmental considerations to Virgin Atlantic</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of an impact of environmental considerations on Virgin Atlantic</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Answers may include:</h5>\n  <ul>\n    <li>Sustainability</li>\n    <li>Waste disposal</li>\n    <li>Pollution</li>\n    <li>Climate change</li>\n  </ul>\n</div>"}, {"question": "Recommend whether ethical considerations or environmental considerations will have the greatest impact on Virgin Atlantic. [3 marks]", "marks": 3, "hint": "You must make a clear choice and justify it. Think about the scale of each impact on Virgin Atlantic specifically — it is an airline (high pollution, many employees, global operation). Consider which type of consideration has the greater impact and why.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO3b: 3 marks)</h5>\n  <ul>\n    <li><strong>1 mark:</strong> A judgement with limited justification showing some appraisal of relevant information</li>\n    <li><strong>2 marks:</strong> A judgement with good justification showing appraisal of relevant information</li>\n    <li><strong>3 marks:</strong> A judgement with strong justification showing detailed appraisal of relevant information</li>\n  </ul>\n  <p><em>Either judgement can gain full marks — there is no single correct answer.</em></p>\n</div>"}, {"question": "Analyse one way in which being environmentally friendly could impact on NEXT plc''s marketing function. [3 marks]", "marks": 3, "hint": "The marketing function covers advertising, promotion, pricing, and product development. How might becoming more environmentally friendly change what NEXT does in any of these areas? Think about the consequences for the business too.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of one way being environmentally friendly could impact on marketing</li>\n    <li><strong>AO2 (1 mark):</strong> Application to NEXT''s marketing function</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of impact on NEXT''s marketing function</li>\n  </ul>\n  <p><em>Content from components 01 and 02 is synoptically assessed in this question.</em></p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Change of advertising strategy</li>\n    <li>Promotion of environmentally friendly behaviour</li>\n    <li>Additional market research</li>\n    <li>Change of target market</li>\n    <li>Charge higher prices</li>\n    <li>Extension of product lifecycle</li>\n    <li>Change in the way NEXT segments the market</li>\n  </ul>\n</div>"}, {"question": "Analyse one way in which being environmentally friendly could impact on NEXT plc''s human resources function. [3 marks]", "marks": 3, "hint": "The HR function covers recruitment, training, and managing employees. Think about how going green might change how NEXT recruits people, how it trains them, or how employees work day-to-day.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of one way being environmentally friendly could impact on HR</li>\n    <li><strong>AO2 (1 mark):</strong> Application to NEXT''s HR function</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of impact on NEXT''s HR function</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Increased use of technology</li>\n    <li>Reduced waste — e.g., paper</li>\n    <li>Use of recycled paper</li>\n    <li>Communication by email</li>\n    <li>Use of online application forms</li>\n    <li>Job interviews conducted online</li>\n    <li>Online training packages</li>\n    <li>Use of hot desking</li>\n    <li>Offered home working opportunities</li>\n    <li>Issued mobile communication technologies to staff</li>\n    <li>Encouraged remote working</li>\n  </ul>\n</div>"}, {"question": "Analyse one way in which being environmentally friendly could impact on NEXT plc''s finance function. [3 marks]", "marks": 3, "hint": "The finance function manages costs, cash flow, budgets, and sources of funding. How might becoming more environmentally friendly increase costs or change the financial position of NEXT?", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of one way being environmentally friendly could impact on finance</li>\n    <li><strong>AO2 (1 mark):</strong> Application to NEXT''s finance function</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of impact on NEXT''s finance function</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Increased costs</li>\n    <li>Need to monitor cash flow</li>\n    <li>Need to obtain additional sources of finance</li>\n    <li>Effect on break even</li>\n  </ul>\n</div>"}, {"question": "Recommend which function would be most affected by NEXT plc being environmentally friendly. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "You need to make a clear choice between marketing, human resources, and finance. Think about which function would face the biggest change across NEXT as a whole business, and justify your choice with reasons.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO3b: 3 marks)</h5>\n  <ul>\n    <li><strong>1 mark:</strong> A judgement with limited justification showing some appraisal of relevant information and/or issues</li>\n    <li><strong>2 marks:</strong> A judgement with good justification showing appraisal of relevant information and/or issues</li>\n    <li><strong>3 marks:</strong> A judgement with strong justification showing detailed appraisal of relevant information and/or issues</li>\n  </ul>\n</div>"}, {"question": "Analyse how NEXT plc could ethically source the clothes that it sells. [3 marks]", "marks": 3, "hint": "NEXT sources clothes from suppliers around the world. Ethical sourcing means ensuring suppliers act fairly in their treatment of workers. Think about what NEXT could demand of its suppliers, and then explain why this matters.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of how to ethically source products</li>\n    <li><strong>AO2 (1 mark):</strong> Application to how NEXT could ethically source the clothes it sells</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of how NEXT could ethically source the clothes it sells</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Do not use suppliers who use child labour</li>\n    <li>Avoid fabrics which have involved animal testing</li>\n    <li>Ensure suppliers pay a fair wage</li>\n    <li>Ensure suppliers do not use zero hours contracts</li>\n    <li>Ensure suppliers offer good working conditions</li>\n    <li>Pay suppliers a reasonable price</li>\n    <li>Insist on suppliers using recycled packaging materials</li>\n    <li>Encourage suppliers to produce clothing made of recyclable materials</li>\n    <li>Minimise air miles / buy from local suppliers</li>\n    <li>Investigate suppliers'' ethical credentials</li>\n    <li>Do spot checks on suppliers'' premises / processes</li>\n    <li>Have a clear ethical supply chain policy</li>\n  </ul>\n</div>"}, {"question": "Analyse how M&S''s ''Plan A'' ethical programme may impact on the profitability of the business. [3 marks]", "marks": 3, "hint": "Profitability means the difference between revenue and costs. Think about how ''Plan A'' could increase costs and/or boost revenue, and link your point specifically to the impact on that difference — not just profit in general.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of the impact of ethical considerations — no further marks without this (note: understanding of the impact, not necessarily understanding of ethics itself)</li>\n    <li><strong>AO2 (1 mark):</strong> Application to M&S specifically, using evidence from the text</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of an impact of ethical considerations on M&S''s profitability</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Understanding may include:</h5>\n  <ul>\n    <li>It may cost more to be ethical to workers / suppliers / customers</li>\n    <li>It may benefit a business''s reputation</li>\n    <li>It may benefit sales revenue</li>\n    <li>It may benefit recruitment / retention</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Application may include:</h5>\n  <ul>\n    <li>''Nourishing our wellbeing'' — looking after staff and their needs — wages, hours, safe working conditions</li>\n    <li>''Transforming local communities'' — supporting staff who want to volunteer in charities</li>\n    <li>''Caring for the planet we share''</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Analysis may include:</h5>\n  <ul>\n    <li>If the price/revenue stays the same, it will decrease profitability</li>\n    <li>If revenue goes up (by even more than costs) then it may increase profitability</li>\n    <li>If costs stay the same, it will increase profitability</li>\n    <li>If costs go up (by even more than the price/revenue) then it may decrease profitability</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>Many candidates struggled to analyse how this would impact on profitability. There was a great deal of confusion between an impact on profit (such as revenue increasing or costs decreasing) and an impact on profitability. To show an impact on profitability, there needed to be an understanding that the difference between costs and revenue was either increasing or decreasing.</p>\n</div>"}, {"question": "Evaluate how the ethical treatment of workers may have an impact on the motivation and retention of M&S''s staff. [9 marks]", "marks": 9, "hint": "You need to cover three areas: (1) what is the ethical treatment of workers, (2) how does it affect motivation, (3) how does it affect retention. Then analyse the business impact of each and make a final judgement about whether motivation or retention is more affected, with justification.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1a (1 mark):</strong> Knowledge of ethics</li>\n    <li><strong>AO1b (1 mark):</strong> Understanding of ethical treatment of workers</li>\n    <li><strong>AO2 (2 marks):</strong> Application — one use of ethics to motivation AND one use to retention</li>\n    <li><strong>AO3a (2 marks):</strong> Analysis — business-facing impact of each</li>\n    <li><strong>AO3b (3 marks):</strong> Evaluation — justified judgement about whether motivation or retention is more affected</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Knowledge (1 mark)</h5>\n  <ul>\n    <li>Ethics are to do with moral principles</li>\n    <li>What is right and wrong</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Understanding (1 mark)</h5>\n  <ul>\n    <li>Being fair and consistent in how a business deals with employees (not about legal rights)</li>\n    <li>Paying a ''fair'' wage (not about paying the minimum wage)</li>\n    <li>Having good working conditions (not about health and safety)</li>\n    <li>Allowing workers time off beyond minimum legal requirements</li>\n    <li>Treating employees with dignity</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Application (up to 2 marks)</h5>\n  <p><strong>Motivation:</strong></p>\n  <ul>\n    <li>Making workers happier in the workplace</li>\n    <li>Employees wanting to come to work</li>\n    <li>Employees working harder</li>\n  </ul>\n  <p><strong>Retention:</strong></p>\n  <ul>\n    <li>Encouraging workers to stay at M&S</li>\n    <li>Workers not looking for different jobs</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Analysis (up to 2 marks)</h5>\n  <ul>\n    <li>Higher productivity of workers for M&S</li>\n    <li>Increased costs of promoting ethical behaviour</li>\n    <li>Lower recruitment costs for M&S</li>\n    <li>Lower training costs for M&S</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Evaluation (up to 3 marks)</h5>\n  <ul>\n    <li>Whether ethical treatment of workers has more benefits than costs for M&S</li>\n    <li>Whether the impact is bigger on motivation or retention of M&S staff</li>\n    <li>The relative importance of the ethical treatment of workers compared with other factors</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Level descriptors</h5>\n  <ul>\n    <li><strong>Level 3 (7–9 marks):</strong> Good knowledge and understanding + good application to both motivation AND retention + good analysis + strong, fully justified contextual evaluation</li>\n    <li><strong>Level 2 (4–6 marks):</strong> Good knowledge and understanding + good application + limited analysis + limited evaluation</li>\n    <li><strong>Level 1 (1–3 marks):</strong> Limited knowledge/understanding + limited application + limited analysis + no evaluation</li>\n    <li><strong>0 marks:</strong> No response or no response worthy of credit</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>This question synoptically tests knowledge from across the specification — ethical treatment of workers (component 2) alongside motivation and retention (component 1). Most candidates could apply knowledge to motivation; many could also show how it would affect retention. However, candidates found the skills of knowledge and evaluation more difficult.</p>\n  <p>Candidates who achieved full marks started with a simple definition and example, applied to both motivation and retention, analysed the business impact of each, then concluded with a supported judgement about whether motivation or retention is more affected. The 9-mark question always requires all five skill areas to be demonstrated explicitly.</p>\n</div>"}, {"question": "State two environmental considerations for a business. [2 marks]", "marks": 2, "hint": "The specification lists four key environmental considerations. Think about what impacts a business has on the natural world — covering areas like the sustainability of resources, the disposal of waste, the release of pollutants, and long-term climate effects.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation (AO1a: 2 marks)</h5>\n  <p>One mark for each correct identification, up to a maximum of two.</p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Acceptable answers include:</h5>\n  <ul>\n    <li>Sustainability</li>\n    <li>Waste disposal</li>\n    <li>Pollution</li>\n    <li>Climate change</li>\n  </ul>\n</div>\n\n<div class=\"marks-section warn\">\n  <h5>No reward for:</h5>\n  <ul>\n    <li>Using the same type of consideration twice (e.g., waste disposal AND recycling count as the same category — only one mark awarded)</li>\n    <li>Ethical considerations confused with environmental ones</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>The specification lists four environmental considerations: sustainability, waste disposal, pollution, climate change. Relatively few candidates could name two of these. Where misunderstanding existed, it was often a confusion between environmental and ethical considerations.</p>\n</div>"}, {"question": "Analyse one advantage to Costa Coffee of being a sustainable business. [3 marks]", "marks": 3, "hint": "Sustainability means using resources in a way that does not deplete them for future generations and minimises environmental harm. Think about a specific advantage for Costa Coffee as a business — not for the environment — and use details from the case study to apply it.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (1 mark):</strong> Understanding of what it means to be a sustainable business — no further marks without this</li>\n    <li><strong>AO2 (1 mark):</strong> Application to Costa Coffee specifically, using evidence from the text</li>\n    <li><strong>AO3a (1 mark):</strong> Analysis of one advantage to Costa Coffee of being a sustainable business</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Understanding may include:</h5>\n  <ul>\n    <li>Recycling, ''green business'', renewable energy, not using single use plastic</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Application may include:</h5>\n  <ul>\n    <li>Owned by Coca-Cola</li>\n    <li>Second largest coffeehouse chain in the world (2,100 branches in UK, 1,200 in rest of world)</li>\n    <li>Switched to environmentally friendly coffee beans</li>\n    <li>Use beans from Rainforest Alliance-certified suppliers</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Analysis may include:</h5>\n  <ul>\n    <li>Improved brand image and competitive advantage</li>\n    <li>Increased ability to comply with regulation</li>\n    <li>Attract employees and investors</li>\n    <li>Reduce waste</li>\n    <li>Make shareholders happy</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>The most common error was to give an answer which showed no understanding of what being a sustainable business means. Sustainability is an environmental consideration in GCSE Business — a generic understanding of the word alone is not sufficient. A strong response has all three elements: understanding of sustainability (positively affecting the environment), application to Costa Coffee using the text, and a chain of analysis of the advantage to the business.</p>\n</div>"}, {"question": "Explain two possible reasons why Costa Coffee uses coffee beans from Rainforest Alliance-certified coffee suppliers. [4 marks]", "marks": 4, "hint": "Think about the benefits for Costa Coffee of choosing certified, ethical suppliers. Look back at the case study for clues — what does being certified mean, and why would that appeal to Costa Coffee in a competitive market?", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark allocation</h5>\n  <ul>\n    <li><strong>AO1b (2 marks):</strong> One mark for understanding of a reason why certain suppliers are chosen, up to a maximum of 2 marks</li>\n    <li><strong>AO2 (2 marks):</strong> One further mark for application of each reason to Costa Coffee, up to a maximum of 2 marks</li>\n  </ul>\n  <p><em>No application marks can be gained without understanding.</em></p>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Understanding may include:</h5>\n  <ul>\n    <li>To help the local communities</li>\n    <li>To use as part of its marketing</li>\n    <li>Reliability of supplies</li>\n    <li>Quality of the beans — certified</li>\n    <li>Ethical reasons</li>\n    <li>Environmental reasons</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Application may include:</h5>\n  <ul>\n    <li>Meet Costa''s ethical / environmental standards</li>\n    <li>Competitive market — e.g., Starbucks</li>\n    <li>Switched to environmentally friendly coffee</li>\n    <li>Switched to ethically sourced beans</li>\n    <li>Owned by Coca-Cola (importance of reputation)</li>\n    <li>Importance when selling an edible product</li>\n  </ul>\n</div>\n\n<div class=\"marks-section\">\n  <h5>Examiner''s comments</h5>\n  <p>To answer this question, candidates needed to understand what benefits a business might gain from choosing an ethical supplier, then apply this to Costa Coffee and the Rainforest Alliance-certified suppliers. Most candidates could understand at least one benefit such as increased reputation, but it was rarer to apply this to the given context. The data is full of signposts to the most appropriate answers — always start with the text itself, not the specification.</p>\n</div>"}]}}'::jsonb),
('business', '6-2-the-economic-climate', '6.2 The Economic Climate', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>Learn and memorise these official definitions — they are the foundation of every answer you write in this topic.</p>\n<ul>\n  <li><strong>Economic climate:</strong> Refers to how well the country is doing in terms of the levels of income and employment.</li>\n  <li><strong>Income:</strong> The amount of money that people receive from work and from assets they own, such as shares and property.</li>\n  <li><strong>Customers:</strong> Buyers who buy goods and services for the satisfaction or benefit they will get from them.</li>\n  <li><strong>Consumer income:</strong> The total amount of income that all customers in the country receive and which they have available to spend.</li>\n  <li><strong>Level of employment:</strong> The number of people in work in a country.</li>\n  <li><strong>Level of unemployment:</strong> The number of people out of work in a country.</li>\n  <li><strong>Level of income:</strong> The average income of people in a country.</li>\n  <li><strong>GDP (Gross Domestic Product):</strong> A measure of how much a country produces in a year. It influences the level of income and employment.</li>\n  <li><strong>Economic growth:</strong> A period when GDP is rising, causing income and employment to rise.</li>\n  <li><strong>Recession:</strong> A period when GDP is falling, causing income and employment to fall.</li>\n  <li><strong>Distribution of income:</strong> Refers to how the income is shared out among different people in the community. It can become more unequal if the incomes of the rich rise faster than those of lower earners.</li>\n  <li><strong>International economic climate:</strong> Refers to what is happening to income and employment in different parts of the world.</li>\n</ul>", "check": {"question": "According to the key definitions, what does ''recession'' mean?", "options": ["The average income earned by people living in a country", "A period when GDP is falling, causing income and employment to fall", "The number of people out of work at any given moment in time", "A period when GDP is rising, causing income and employment to rise"], "answer": 1, "explain": "The card defines recession as a period when GDP is falling, causing income and employment to fall — the opposite of economic growth."}}, {"title": "What Is the Economic Climate?", "html": "<p>The <strong>economic climate</strong> refers to the state of the economy a business operates in. It can be:</p>\n<ul>\n  <li><strong>Favourable</strong> — good for business (rising incomes, low unemployment, growing GDP)</li>\n  <li><strong>Unfavourable</strong> — bad for business (falling incomes, high unemployment, recession)</li>\n</ul>\n<p>⚠️ A favourable climate for one business is <strong>not always</strong> favourable for another. For example, a recession is bad for luxury car dealers but can be good for discount supermarkets like Aldi.</p>\n<br>\n<p>The two main factors you need to know for OCR GCSE are:</p>\n<ul>\n  <li><strong>Changes in consumer income</strong></li>\n  <li><strong>Changes in employment / unemployment levels</strong></li>\n</ul>", "check": {"question": "According to this card, is a recession always bad for every business?", "options": ["No — a recession only ever affects businesses selling luxury goods", "Yes — a recession is always equally bad for every type of business", "Yes — a recession only ever affects large multinational businesses", "No — a recession can be good for discount supermarkets like Aldi"], "answer": 3, "explain": "The card explains a recession is bad for luxury car dealers but can be good for discount supermarkets like Aldi — a favourable/unfavourable climate is not universal."}}, {"title": "The Impact of Changes in Income", "html": "<p>Income levels directly affect how much customers can spend, which in turn affects business sales and profits.</p>\n<br>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">📈 When Income RISES</div>\n    <div class=\"pro-item\"><strong>More spending:</strong> Customers have more money so demand for goods and services increases.</div>\n    <div class=\"pro-item\"><strong>Higher revenue & profit:</strong> Businesses can sell more — or even raise prices.</div>\n    <div class=\"pro-item\"><strong>Business expansion:</strong> Firms may need to hire more staff, buy more stock, or open new outlets.</div>\n    <div class=\"pro-item\"><strong>Exception — cheap goods:</strong> Some lower-quality businesses may see sales fall as customers switch to better products they can now afford.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">📉 When Income FALLS</div>\n    <div class=\"con-item\"><strong>Less spending:</strong> Customers have less disposable income, reducing demand.</div>\n    <div class=\"con-item\"><strong>Lower revenue & profit:</strong> Luxury or non-essential businesses are hit hardest.</div>\n    <div class=\"con-item\"><strong>Risk of closure:</strong> Businesses that cannot adapt may close (e.g. Comet in 2012).</div>\n    <div class=\"con-item\"><strong>Exception — budget goods:</strong> Discount businesses like Aldi can actually benefit when incomes fall as customers trade down.</div>\n  </div>\n</div>\n<br>\n<p><strong>How much a business is affected depends on:</strong></p>\n<ul>\n  <li>How much income changes — bigger change = bigger impact</li>\n  <li>The type of product sold — luxury goods are more vulnerable than essentials</li>\n  <li>How other businesses respond — competitors may gain market share</li>\n  <li>How the business itself responds — good businesses adapt and survive</li>\n</ul>", "check": {"question": "According to this card, which businesses can benefit when consumer income falls?", "options": ["Only businesses that raise their prices in response to falling income", "Luxury car dealers, since falling income increases demand for luxury goods", "Every type of business equally, regardless of what they sell", "Discount businesses like Aldi, as customers trade down to cheaper options"], "answer": 3, "explain": "The card lists discount businesses like Aldi as an exception — they benefit when incomes fall as customers trade down, unlike luxury or non-essential businesses."}}, {"title": "The Impact of Changes in Employment", "html": "<p>Employment and income are closely linked — when more people are in work, incomes tend to rise, and vice versa. But changes in employment also affect <strong>production costs</strong> and <strong>recruitment</strong>.</p>\n<br>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">📉 When Unemployment RISES (Employment Falls)</div>\n    <div class=\"pro-item\"><strong>Easier to recruit:</strong> More workers are available, giving businesses a larger pool to choose from.</div>\n    <div class=\"pro-item\"><strong>Lower wages:</strong> Greater competition for jobs means businesses may pay less, reducing labour costs.</div>\n    <div class=\"con-item\"><strong>Lower consumer spending:</strong> More unemployed people means less income in the economy, reducing demand for goods.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">📈 When Unemployment FALLS (Employment Rises)</div>\n    <div class=\"pro-item\"><strong>More consumer spending:</strong> More people in work = higher incomes = more demand for goods and services.</div>\n    <div class=\"con-item\"><strong>Harder to recruit:</strong> Fewer workers available; businesses may struggle to find staff with the right skills.</div>\n    <div class=\"con-item\"><strong>Higher wages:</strong> Competition for workers forces businesses to offer higher pay, raising costs and reducing profits.</div>\n  </div>\n</div>\n<br>\n<p><strong>How much a business is affected depends on:</strong></p>\n<ul>\n  <li>How much employment changes</li>\n  <li>The type of employment — a rise in demand for <em>skilled</em> workers is harder to deal with than a rise in demand for unskilled workers</li>\n</ul>", "check": {"question": "According to this card, what happens to wages when unemployment rises?", "options": ["Wages can only be affected by consumer income, not by employment", "Wages tend to fall, since greater competition for jobs reduces labour costs", "Wages tend to rise, since businesses have to compete harder for scarce workers", "Wages stay exactly the same regardless of the unemployment rate"], "answer": 1, "explain": "The card explains that when unemployment rises, greater competition for jobs means businesses may pay less, reducing labour costs."}}, {"title": "Business Strategies When Income & Employment Fall", "html": "<p>When the economic climate becomes unfavourable, businesses across all departments must respond strategically to survive. Here are the key strategies by department:</p>\n<br>\n<ul>\n  <li>🏭 <strong>Production:</strong>\n    <ul>\n      <li>Reduce waste to cut costs per unit</li>\n      <li>Improve worker productivity (e.g. new technology)</li>\n      <li>Outsource production to cheaper locations</li>\n    </ul>\n  </li>\n  <br>\n  <li>👥 <strong>Human Resources (HR):</strong>\n    <ul>\n      <li>Motivate workers with bonuses or awards to improve productivity</li>\n      <li>Lay off workers to reduce the wage bill</li>\n      <li>Improve skills through training</li>\n    </ul>\n  </li>\n  <br>\n  <li>📣 <strong>Marketing:</strong>\n    <ul>\n      <li>Increase or improve advertising to attract customers</li>\n      <li>Produce a cheaper product to appeal to lower-income consumers</li>\n      <li>Lower prices to increase demand</li>\n      <li>Target new markets (e.g. sell abroad)</li>\n      <li>Change the product upmarket to appeal to wealthier buyers</li>\n    </ul>\n  </li>\n  <br>\n  <li>💰 <strong>Finance:</strong>\n    <ul>\n      <li>Take out cheaper loans to reduce interest payments</li>\n      <li>Reduce overdraft to save on interest costs</li>\n      <li>Improve cash flow management</li>\n    </ul>\n  </li>\n</ul>", "check": {"question": "According to this card, which strategy is listed under the Finance department?", "options": ["Taking out cheaper loans to reduce interest payments", "Outsourcing production to cheaper locations abroad", "Increasing or improving advertising to attract more customers", "Laying off workers to reduce the overall wage bill"], "answer": 0, "explain": "The card lists taking out cheaper loans under Finance strategies; advertising is Marketing, laying off workers is HR, and outsourcing is Production."}}, {"title": "Distribution of Income & the International Economic Climate", "html": "<p>Two additional aspects of the economic climate that can affect businesses are:</p>\n<br>\n<p><strong>📊 Distribution of Income</strong></p>\n<p>Even if the overall level of income stays the same, how income is <em>shared</em> among people matters.</p>\n<ul>\n  <li>Since the 1980s, the gap between rich and poor in the UK has <strong>widened</strong>.</li>\n  <li>If richer people''s incomes rise faster, businesses selling luxury goods may still perform well even during a wider recession.</li>\n  <li>After the 2008 recession, many new jobs were part-time or zero-hours contracts — so income for many rose only slowly, even as employment recovered.</li>\n</ul>\n<br>\n<p><strong>🌍 International Economic Climate</strong></p>\n<p>The UK does not operate in isolation — global economic conditions affect UK businesses too.</p>\n<ul>\n  <li>A world recession or recession in key trading partners (e.g. EU, USA) reduces demand for UK exports.</li>\n  <li>The 2008–09 recession affected both the UK and its trading partners simultaneously.</li>\n  <li>The COVID-19 pandemic in 2020–21 dramatically reduced international trade and travel.</li>\n  <li>Events like Brexit can also affect UK businesses trading internationally.</li>\n</ul>", "check": {"question": "According to this card, what has happened to the distribution of income in the UK since the 1980s?", "options": ["The gap between rich and poor has completely disappeared", "The gap between rich and poor in the UK has steadily widened over time", "The government abolished income distribution as an economic measure", "Income has become perfectly equally distributed among all people"], "answer": 1, "explain": "The card states that since the 1980s the gap between rich and poor in the UK has widened, affecting which businesses perform well during a recession."}}, {"title": "Case Study: Comet vs Carpet Right", "html": "<div class=\"case-study-box\">\n  <h4>Case Study: Comet vs Carpet Right — Two Very Different Responses to Recession</h4>\n  <p>Both Comet (electrical goods) and Carpet Right (carpets) were successful high-street chains before the 2008 recession. Both sold ''big ticket'' items — expensive purchases that consumers cut back on when incomes fell.</p>\n  <br>\n  <p><strong>Comet</strong> failed to adapt to the downturn. By December 2012, it had closed entirely.</p>\n  <br>\n  <p><strong>Carpet Right</strong> responded by:</p>\n  <ul>\n    <li>Selling better-quality, more expensive carpets (moving upmarket)</li>\n    <li>Improving customer service</li>\n    <li>Closing some stores to reduce costs</li>\n    <li>Offering interest-free credit to attract cautious buyers</li>\n  </ul>\n  <br>\n  <p>By 2016, Carpet Right''s profits had risen by 33.1% and like-for-like sales had grown by 4.8%. It was taken over by Meditor in 2019 and continues to trade.</p>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> The same difficult economic climate affected both businesses equally — but only one survived. The key difference was <strong>how each business responded</strong>. Businesses that adapt their strategy (product, price, promotion, place) can survive and even grow through a recession.</p>", "check": {"question": "According to this case study, what was the key difference between Comet and Carpet Right?", "options": ["Carpet Right adapted its strategy, while Comet failed to adapt and closed", "Neither business was affected at all by the 2008 recession", "Comet adapted its strategy, while Carpet Right failed to adapt and closed", "Both businesses closed permanently during the 2008 recession"], "answer": 0, "explain": "The card explains Carpet Right adapted (moving upmarket, improving service, offering credit) and survived, while Comet failed to adapt and closed by 2012."}}, {"title": "Case Study: Aldi — Turning Recession Into Opportunity", "html": "<div class=\"case-study-box\">\n  <h4>Case Study: Aldi — Growing Through the Downturn</h4>\n  <p>In 2007, Aldi held just a <strong>2.5% share</strong> of the UK supermarket market. By 2020, it had become the <strong>sixth-largest supermarket chain</strong> in the UK with a 7.8% market share. Its rapid growth was driven largely by the poor economic climate after 2008.</p>\n  <br>\n  <p>Aldi''s strategy included:</p>\n  <ul>\n    <li>Selling cheaper groceries — some products 50% cheaper than rivals</li>\n    <li>Focusing on own-label products to keep buying costs low</li>\n    <li>A ''no frills'' store experience — basic layout, no saunas or cafés</li>\n    <li>Highly efficient warehousing and distribution to keep costs minimal</li>\n  </ul>\n  <br>\n  <p>During the COVID-19 lockdowns (2020–21), Aldi''s market share temporarily fell as it lacked online services. However, once restrictions lifted, its share rose again.</p>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> A poor economic climate is not bad for every business. Aldi proves that a business model built around <strong>low cost and low price</strong> can turn an economic downturn into a competitive advantage. When consumer incomes fall, customers trade down — and discount retailers benefit directly.</p>", "check": {"question": "According to the Aldi case study, what has driven its rapid growth since 2008?", "options": ["Aldi''s decision to add saunas and cafés to every one of its stores", "A strong economic climate, as customers had more money to spend", "Aldi''s decision to become the most expensive supermarket in the whole UK", "The poor economic climate, as customers traded down to cheaper groceries"], "answer": 3, "explain": "The card explains Aldi''s growth was driven largely by the poor economic climate after 2008, as customers traded down to its cheaper ''no frills'' groceries."}}, {"title": "Case Study: The Coronavirus Pandemic (2020–21)", "html": "<div class=\"case-study-box\">\n  <h4>Case Study: COVID-19 — The Biggest Fall in UK GDP Ever Recorded</h4>\n  <p>The coronavirus pandemic caused the largest drop in UK GDP ever recorded — by March 2021, GDP was <strong>8.1% lower</strong> than pre-pandemic levels.</p>\n  <br>\n  <p><strong>Businesses severely affected:</strong></p>\n  <ul>\n    <li>Travel and tourism</li>\n    <li>Hospitality — pubs, restaurants, cafés</li>\n    <li>Retail (non-essential shops)</li>\n    <li>Entertainment — theatres, cinemas, festivals</li>\n  </ul>\n  <br>\n  <p><strong>Government support measures:</strong></p>\n  <ul>\n    <li>Grants and loans to struggling businesses</li>\n    <li>Furlough scheme — government paid up to 80% of wages for workers who could not work</li>\n  </ul>\n  <br>\n  <p><strong>Businesses that thrived:</strong></p>\n  <ul>\n    <li>Online retailers and delivery companies</li>\n    <li>Home improvement businesses (builders, decorators, home furnishings)</li>\n  </ul>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> Even in the worst economic climate, <strong>some businesses benefit</strong>. The pandemic accelerated the shift to online retail and home working. Businesses that could adapt quickly — or whose products were in demand — survived and grew. The pandemic is a perfect exam example of both the negative <em>and</em> positive effects of an unfavourable economic climate.</p>", "check": {"question": "According to this case study, what does the pandemic show about an unfavourable economic climate?", "options": ["No business anywhere was able to benefit from the pandemic in any way", "GDP rose to its highest ever recorded level during the pandemic period", "Every single business in the country closed permanently during the pandemic", "Even in a very bad economic climate, some businesses can still benefit"], "answer": 3, "explain": "The card explains the pandemic shows even in the worst economic climate some businesses benefit — online retailers and home improvement businesses thrived."}}, {"title": "Case Study: Fitspace — Low-Cost Gym in a Changing Economy", "html": "<div class=\"case-study-box\">\n  <h4>Case Study: Fitspace — Targeting Lower-Income Consumers</h4>\n  <p>Fitspace is a gym chain that specifically targets lower-paid workers and those without a guaranteed stable income. It operates as follows:</p>\n  <ul>\n    <li>Monthly membership fees lower than most other gyms</li>\n    <li>No annual contract — customers can pay month by month</li>\n    <li>No frills — no luxury changing rooms, saunas or cafés</li>\n  </ul>\n  <br>\n  <p>In 2016, Fitspace was acquired by GLL (which also runs the Better gym chain). By 2018, GLL''s turnover had grown 7% to £298 million with a profit of £1.3 million.</p>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> Fitspace is a prime example of a business that aligned its model to the economic reality of its target market. By keeping costs and prices low, it attracted customers who would otherwise not join a gym. However, its lack of frills may deter customers seeking higher-quality experiences — showing that <strong>every strategy involves trade-offs</strong>.</p>", "check": {"question": "According to the Fitspace case study, how did the business align with the economic reality of its market?", "options": ["By adding luxury features such as saunas and cafés to its gyms", "By requiring customers to sign a long and expensive annual contract term", "By targeting only the highest-income consumers in each local area", "By keeping membership costs and prices low to attract lower-income customers"], "answer": 3, "explain": "The card explains Fitspace kept membership fees low with no annual contract or frills, aligning its model with lower-paid workers and unstable incomes."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Economic climate", "definition": "How well the country is doing in terms of the levels of income and employment."}, {"term": "Recession", "definition": "A period when GDP is falling, causing income and employment to fall."}, {"term": "Economic growth", "definition": "A period when GDP is rising, causing income and employment to rise."}, {"term": "GDP", "definition": "Gross Domestic Product — a measure of how much a country produces in a year."}, {"term": "Consumer income", "definition": "The total amount of income all customers in the country receive and have available to spend."}, {"term": "Level of unemployment", "definition": "The number of people out of work in a country."}, {"term": "Distribution of income", "definition": "How income is shared out among different people in the community."}, {"term": "International economic climate", "definition": "What is happening to income and employment in different parts of the world."}, {"term": "Impact of rising income on luxury goods", "definition": "Demand typically increases as customers can afford higher-quality or non-essential products."}, {"term": "Impact of falling income on budget goods", "definition": "Demand may increase as customers trade down from more expensive options."}, {"term": "Impact of falling unemployment on wages", "definition": "Wages tend to rise because businesses must compete to attract the smaller pool of available workers."}, {"term": "Aldi''s growth strategy", "definition": "Low prices, own-label products, no-frills stores, and efficient logistics — which benefited from the post-2008 economic downturn."}, {"term": "How Carpet Right survived the 2008 recession", "definition": "Moved upmarket, improved customer service, closed costly stores, and introduced interest-free credit."}, {"term": "Why Comet closed in 2012", "definition": "Failed to adapt its strategy in response to falling consumer income — did not change its products, pricing, or service model."}, {"term": "Finance department recession strategy", "definition": "Take out cheaper loans, reduce overdraft, improve cash flow to cut interest payments."}]}, "mcq": {"enabled": true, "questions": [{"question": "What does the term ''economic climate'' refer to?", "options": ["The weather conditions affecting a country''s agriculture", "How well the country is doing in terms of income and employment levels", "The level of inflation in the economy", "The number of businesses trading in a country"], "answer": 1, "explain": "Correct: The economic climate refers to how well the country is doing in terms of the levels of income and employment. It does NOT refer to weather or climate change — a common examiner-noted mistake."}, {"question": "Consumer spending is most likely to fall when:", "options": ["Average incomes rise", "Unemployment falls", "The country produces less as measured by GDP", "Immigration rises"], "answer": 2, "explain": "Correct: When GDP falls (a recession), incomes and employment also fall, reducing consumer spending. Rising incomes (A) and falling unemployment (B) both increase spending. Immigration (D) is not directly linked."}, {"question": "In a period of rising income and employment, most businesses can expect:", "options": ["Prices to fall", "Sales to rise", "Profits to fall", "Immigration to fall"], "answer": 1, "explain": "Correct: When incomes rise, customers have more to spend, so demand increases and sales rise. Prices typically rise (not fall) in a growing economy, and profits usually increase too."}, {"question": "When a business loses sales due to a fall in consumer income, it should:", "options": ["Increase the amount it produces", "Stop selling the product abroad", "Reduce production costs", "Recruit more workers"], "answer": 2, "explain": "Correct: Reducing production costs allows the business to lower prices or maintain profit margins despite falling sales. Increasing production (A) or recruiting more workers (D) would be counterproductive when demand is falling."}, {"question": "A tour company has average annual sales of £8 million. When income falls by 2%, its sales fall by 4%. What is the expected fall in sales if income fell by 2%?", "options": ["£80,000", "£160,000", "£320,000", "£640,000"], "answer": 2, "explain": "Correct: A 4% fall on £8 million = £8,000,000 × 0.04 = £320,000. Option A (£80,000) is 1% of £8m. Option B (£160,000) is 2% of £8m. Option D (£640,000) is 8% of £8m."}, {"question": "Which of the following is most likely to benefit from a fall in consumer incomes?", "options": ["A luxury car dealership", "A five-star hotel chain", "A budget supermarket selling own-label products", "A high-end bespoke kitchen manufacturer"], "answer": 2, "explain": "Correct: When incomes fall, consumers trade down to cheaper alternatives, benefiting discount retailers. Luxury and high-end businesses (A, B, D) suffer as consumers can no longer afford their products."}, {"question": "What is the most likely impact of falling unemployment on a business''s production costs?", "options": ["Costs will fall because there are fewer workers to pay", "Costs will rise because wages increase due to competition for workers", "Costs will remain unchanged", "Costs will fall because workers become more productive"], "answer": 1, "explain": "Correct: When unemployment falls, fewer workers are available, creating competition for labour. Businesses must offer higher wages to attract and retain staff, raising their production costs."}, {"question": "What is a recession?", "options": ["A period when GDP is rising", "A period when unemployment is at its lowest", "A period when GDP is falling, causing income and employment to fall", "A period when consumer prices are rising"], "answer": 2, "explain": "Correct: A recession is defined as a period when GDP is falling, which causes income to fall and unemployment to rise. Option A describes economic growth. Option D describes inflation."}, {"question": "Falling levels of consumer income have caused a car dealership to experience a significant reduction in retail sales. Which action should the dealership take?", "options": ["Advertise less", "Offer price reductions", "Reduce customer engagement", "Reduce its costs only"], "answer": 1, "explain": "Correct: Offering price reductions makes the cars more affordable during a period of lower consumer income, helping to maintain sales. Advertising less (A) or reducing customer engagement (C) would further harm sales."}, {"question": "Which of the following statements about the impact of rising income is TRUE?", "options": ["The sales of all businesses will always increase when incomes rise", "Rising incomes often lead to an increase in sales of luxury goods", "A rise in unemployment will make all consumers worse off", "A fall in consumer income will always cause a business to sell less"], "answer": 1, "explain": "Correct: Rising incomes often boost luxury goods sales because consumers can now afford higher-quality or non-essential items. ''Always'' in options A, C and D is incorrect — there are always exceptions (e.g. budget goods may see falls when incomes rise)."}, {"question": "What does GDP stand for and what does it measure?", "options": ["General Domestic Price — the average cost of goods in a country", "Gross Domestic Product — a measure of how much a country produces in a year", "Government Debt Percentage — the level of public borrowing", "Gross Disposable Pay — the average take-home wage"], "answer": 1, "explain": "Correct: GDP (Gross Domestic Product) measures the total value of goods and services a country produces in a year. It is the key indicator of economic growth or recession."}, {"question": "Which of the following is NOT an example of a business strategy used during a recession?", "options": ["Reducing waste in production", "Increasing advertising to boost sales", "Hiring more full-time workers to increase output", "Taking out cheaper loans to reduce interest costs"], "answer": 2, "explain": "Correct: During a recession, businesses typically try to reduce costs — hiring more full-time workers increases the wage bill, which is the opposite of what most businesses do in a downturn. All other options are common recession strategies."}]}, "fib": {"enabled": true, "questions": [{"text": "The economic climate refers to how well the country is doing in terms of the levels of [income] and [employment]."}, {"text": "A period when GDP is falling, causing income and employment to fall, is called a [recession]."}, {"text": "A period when GDP is rising is called [economic growth] _____."}, {"text": "When consumer income rises, businesses often experience an increase in [sales] and [profits]."}, {"text": "When unemployment falls, businesses may find it harder to [recruit] workers and may need to pay higher [wages]."}, {"text": "GDP stands for Gross [Domestic] Product."}, {"text": "The distribution of income refers to how income is [shared] among different people in the community."}, {"text": "During a recession, businesses in the marketing department might try to [lower] prices or increase [advertising] to maintain sales."}, {"text": "When income falls, luxury goods businesses are likely to see a [fall] in demand, while budget retailers may see demand [rise]."}, {"text": "Aldi grew its UK market share from 2.5% in 2007 to [7.8%] by 2020, partly because of the poor economic climate after 2008."}, {"text": "The [furlough] scheme during COVID-19 meant the government paid up to 80% of wages for workers who could not work."}, {"text": "A business''s finance department might respond to a recession by taking out cheaper [loans] or reducing its [overdraft]."}]}, "tf": {"enabled": true, "questions": [{"statement": "The economic climate only refers to weather and environmental conditions affecting businesses.", "answer": false, "explain": "FALSE. The economic climate refers to how well the country is doing in terms of income and employment levels — NOT the weather. This is one of the most common misconceptions noted by examiners."}, {"statement": "When consumer incomes rise, the sales of ALL businesses will increase.", "answer": false, "explain": "FALSE. While most businesses benefit from rising incomes, businesses selling cheap or lower-quality products may actually see sales FALL as customers switch to more expensive alternatives they can now afford."}, {"statement": "A recession is a period when GDP is falling, causing income and employment to fall.", "answer": true, "explain": "TRUE. This is the official definition. During a recession, GDP falls, businesses cut production, workers are laid off, unemployment rises, and incomes fall — reducing consumer spending further."}, {"statement": "When unemployment falls, businesses will find it easier and cheaper to hire new workers.", "answer": false, "explain": "FALSE. When unemployment falls, fewer workers are available. This makes it HARDER to recruit, and businesses often need to offer HIGHER wages to attract staff — increasing their costs."}, {"statement": "A fall in consumer income always causes a business to sell less.", "answer": false, "explain": "FALSE. Some businesses actually benefit from falling incomes. Discount retailers like Aldi saw sales and market share GROW during the 2008 recession as consumers switched to cheaper options."}, {"statement": "Aldi''s rapid growth after 2008 was partly due to the poor economic climate.", "answer": true, "explain": "TRUE. As consumer incomes fell after the 2008 recession, shoppers switched to cheaper options. Aldi''s low-price model was perfectly positioned to benefit, growing its market share from 2.5% to 7.8% by 2020."}, {"statement": "GDP (Gross Domestic Product) is a measure of how much a country produces in a year.", "answer": true, "explain": "TRUE. GDP measures the total value of goods and services produced by a country in a year. It is the main indicator of economic growth or recession."}, {"statement": "During a recession, all businesses will lose money and many will close.", "answer": false, "explain": "FALSE. While many businesses struggle in a recession, some thrive. Budget retailers, discount stores, and businesses that adapt effectively can grow during a downturn. Carpet Right survived the 2008 recession; Comet did not."}, {"statement": "The international economic climate can affect UK businesses even if the UK economy itself is performing well.", "answer": true, "explain": "TRUE. If major trading partners (such as the EU or USA) go into recession, demand for UK exports falls. The 2008 recession affected the UK AND its trading partners simultaneously."}, {"statement": "When unemployment rises, businesses will typically face higher wage costs.", "answer": false, "explain": "FALSE. When unemployment RISES, there are MORE workers looking for jobs. This gives businesses more choice and reduces competition for labour, often allowing businesses to pay LOWER wages, reducing their costs."}, {"statement": "The distribution of income refers to how evenly income is shared among people in the community.", "answer": true, "explain": "TRUE. Distribution of income describes the gap between rich and poor. In the UK since the 1980s, this gap has widened — the rich have seen incomes rise faster than lower earners."}, {"statement": "Comet and Carpet Right were both affected equally by the 2008 recession, and both eventually closed.", "answer": false, "explain": "FALSE. Both were affected by the recession, but only Comet closed (by December 2012). Carpet Right adapted — it moved upmarket, improved customer service, closed some stores, and offered interest-free credit. It survived and grew."}]}, "misc": {"enabled": true, "items": [{"myth": "The ''economic climate'' is about the weather or environmental climate change.", "truth": "The economic climate refers to the state of income and employment levels in a country — it has nothing to do with weather. The examiner reports note that less than 40% of students answered Q1 correctly because of this confusion.", "check": {"question": "What does the term ''economic climate'' actually refer to?", "options": ["The weather conditions affecting a country''s agriculture sector", "The state of income and employment levels in a country", "The number of businesses that operate within a country", "The rate of environmental climate change in a country"], "answer": 1, "explain": "The card corrects a common misconception — the economic climate refers to income and employment levels, not weather or environmental climate change."}}, {"myth": "If unemployment falls, a business now has fewer employees.", "truth": "A fall in unemployment means there are FEWER unemployed people in the country — not fewer people working for a specific business. It means it becomes HARDER and MORE EXPENSIVE to recruit new workers, as fewer people are available.", "check": {"question": "What does a fall in unemployment actually mean for businesses trying to recruit?", "options": ["A specific business now automatically has fewer employees working for it", "It becomes easier and cheaper to recruit, since more people are now available", "It becomes harder and more expensive to recruit, as fewer people are available", "Recruitment costs are not affected at all by the unemployment rate"], "answer": 2, "explain": "The card explains a fall in unemployment means fewer people are available nationally, making it harder and more expensive for businesses to recruit new workers."}}, {"myth": "A fall in consumer income always causes every business to sell less.", "truth": "It depends on the type of product. Luxury goods businesses typically see sales fall. But budget and discount businesses (like Aldi) often see sales RISE as consumers trade down to cheaper options.", "check": {"question": "Does a fall in consumer income always cause every business to sell less?", "options": ["No — discount businesses like Aldi can see sales rise as customers trade down", "No — but only because consumer income never actually falls in reality", "Yes — but only luxury goods businesses are exempt from this effect", "Yes — every single business always sells less whenever consumer income falls"], "answer": 0, "explain": "The card explains it depends on the product type — luxury goods businesses see sales fall, but discount businesses like Aldi often see sales rise as consumers trade down."}}, {"myth": "Economic factors include things like the cost of raw materials, rents, and prices.", "truth": "Costs, rents, and prices are NOT economic factors in the OCR specification. Economic factors specifically refer to consumer income levels, (un)employment, economic growth/GDP, and inflation. Do not confuse these with business costs.", "check": {"question": "According to the OCR specification, which of these counts as an economic factor?", "options": ["Consumer income levels, unemployment, and economic growth or GDP", "The cost of raw materials used in a business''s production process", "The rent a business pays for its premises each and every month", "The prices a business charges its own customers for its products"], "answer": 0, "explain": "The card explains economic factors specifically mean income, employment, growth/GDP and inflation — not business costs like raw materials, rent or prices."}}, {"myth": "Writing about how the economic climate affects business generally — without linking to the specific case study — is enough for full marks on a 3-mark analyse question.", "truth": "You CANNOT score application or analysis marks without first showing understanding. You must also use evidence from the specific business in the question (e.g. the price of a product, number of employees). No context = maximum 1 mark.", "check": {"question": "Can writing about the economic climate generally, without the case study, score full marks on a 3-mark analyse question?", "options": ["Yes — application and analysis marks do not require any case study evidence", "Yes — understanding marks are not required for a 3-mark analyse question", "No — without any case study evidence, the maximum score you can get is 1 mark", "No — but only because 3-mark analyse questions do not exist in this topic"], "answer": 2, "explain": "The card explains you cannot score application or analysis without case study evidence — without context, the maximum score is 1 mark for understanding alone."}}, {"myth": "For a 3-mark recommend/evaluate question, I just need to explain my chosen option in detail.", "truth": "A 3-mark evaluation question REQUIRES a comparison between both options. If you only justify your chosen option without saying why it is better THAN the other option, you can score a maximum of 1 mark.", "check": {"question": "Is explaining your chosen option in detail enough for full marks on a 3-mark recommend question?", "options": ["Yes — a 3-mark recommend question never requires any kind of comparison", "Yes — comparing both options actually loses marks in this question type", "No — you must also compare it against the other option to score full marks", "No — but only because recommend questions are always worth more than 3 marks"], "answer": 2, "explain": "The card explains a 3-mark evaluation question requires comparing both options — justifying only the chosen option without contrast scores a maximum of 1 mark."}}, {"myth": "Inflation, interest rates, and economic growth are outside the scope of this topic.", "truth": "While the OCR specification focuses mainly on income and unemployment for 6.2, examiners WILL accept other valid economic factors (such as inflation and economic growth/GDP) when a question asks for an ''economic factor''. These are credit-worthy answers.", "check": {"question": "Are inflation and economic growth completely outside the scope of this topic?", "options": ["No — examiners will accept them as valid economic factors when relevant", "No — but only inflation is accepted, never economic growth or GDP", "Yes — only income and unemployment can ever be mentioned in any answer", "Yes — inflation and economic growth can never be credited in this topic"], "answer": 0, "explain": "The card explains that while 6.2 focuses mainly on income and unemployment, examiners will accept other valid economic factors like inflation and GDP when relevant."}}, {"myth": "The economic climate only affects large businesses — small businesses are too small to be impacted.", "truth": "The economic climate affects businesses of ALL sizes. A small independent café may be more vulnerable than a large chain because it has fewer reserves. Small businesses are frequently used as case studies in this topic.", "check": {"question": "Does the economic climate only affect large businesses, not small ones?", "options": ["Yes — only large multinational businesses are ever used as exam case studies", "No — but only because small businesses always have larger cash reserves", "No — it affects businesses of all sizes, and small ones may be more vulnerable", "Yes — small businesses are too small to ever be affected by the economy"], "answer": 2, "explain": "The card explains the economic climate affects businesses of all sizes — a small independent café may be more vulnerable than a large chain due to fewer reserves."}}]}, "tips": {"enabled": true, "items": [{"title": "Always Define the Economic Problem FIRST", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs two things: a feature of the difficult economic climate (1 mark) AND how it affects the business (1 mark).</p>\n      <br>\n      <p><strong>⚠️ Examiner Warning:</strong> In the real exam, fewer than 40% of students scored any marks on this question type because they jumped straight to the business impact without defining what a difficult economic climate actually involves.</p>\n      <br>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 (K):</strong> Identify a feature of a difficult economic climate (e.g. rising unemployment OR falling consumer incomes)</li>\n        <li><strong>Step 2 (U):</strong> Explain how this affects the business (e.g. demand may fall, sales may decrease)</li>\n      </ul>\n      <br>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br>\n      <em>\"The economic climate is changing and this affects businesses.\"</em><br>\n      This shows no understanding of what a difficult economic climate IS.</p>\n      <br>\n      <p><strong>✅ Good Answer (2 marks):</strong><br>\n      <em>\"In a difficult economic climate, unemployment may rise (K). This means consumers have less income to spend, so demand for the business''s products may fall (U).\"</em></p>\n      <br>\n      <p><strong>🚫 Misconception Alert:</strong> The economic climate does NOT refer to weather or environmental change. Always connect it to income and/or unemployment.</p>\n    ", "check": {"question": "According to this card, why did fewer than 40% of students score marks on this question type?", "options": ["They confused this two-mark question with a much longer nine-mark essay question", "They jumped straight to the business impact without defining the economic climate", "They wrote far too much detail for a question that was only worth two marks", "They defined the economic climate but never mentioned any business impact at all"], "answer": 1, "explain": "The card explains most students jumped straight to the business impact without first defining what a difficult economic climate actually involves, losing the knowledge mark."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>Every 3-mark <strong>analyse</strong> question follows the same structure. Miss the understanding step and you score ZERO — even if your application and analysis are perfect.</p>\n      <br>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State what the economic concept means (e.g. \"A fall in consumer income means customers have less money to spend.\")</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link directly to the specific business in the case study using a fact or figure (e.g. \"GK''s kitchens are priced at £15,000...\")</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the bottom-line impact on the business (e.g. \"...so demand for GK''s kitchens is likely to fall, meaning they may not reach their break-even point of 29 units.\")</li>\n      </ul>\n      <br>\n      <p><strong>❌ Bad Answer (1 mark maximum):</strong><br>\n      <em>\"GK will sell fewer kitchens because incomes are falling.\"</em><br>\n      No understanding shown — skipped straight to the impact.</p>\n      <br>\n      <p><strong>✅ Good Answer (3 marks):</strong><br>\n      <em>\"A fall in consumer income means customers have less money to spend (U). As GK''s Deluxe kitchen costs £15,000 (APP), it is likely that fewer customers will be able to afford this luxury purchase, causing sales to fall. This may mean GK fails to reach its break-even point of 29 kitchens (AN).\"</em></p>\n      <br>\n      <p><strong>📝 Sentence Starters:</strong></p>\n      <ul>\n        <li><em>(U):</em> \"A fall in consumer income means that customers have less disposable income to spend...\"</li>\n        <li><em>(APP):</em> \"In the case of [business], which sells [product/price from text]...\"</li>\n        <li><em>(AN):</em> \"This will lead to... / As a result, the business will... / This means profits may fall because...\"</li>\n      </ul>\n    ", "check": {"question": "According to this card, what happens if you skip the Understanding step in a 3-mark analyse question?", "options": ["You still score full marks, since application matters more than understanding", "You score zero, even if your application and analysis are perfect", "You score full marks provided your final numerical answer is correct", "You automatically score 2 out of 3 marks for the remaining two steps"], "answer": 1, "explain": "The card warns that missing the understanding step scores zero overall, even with perfect application and analysis — understanding is the required first step."}}, {"title": "You MUST Compare Both Options", "html": "\n      <p>A 3-mark <strong>recommend</strong> question is the most commonly under-scored question. Students lose marks because they argue for their chosen option but <strong>never say why it is better than the other option</strong>.</p>\n      <br>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Judgement (1 mark):</strong> State your clear decision (e.g. \"The fall in consumer income will have the greater impact...\")</li>\n        <li><strong>Step 2 — Justification with contrast (1 mark):</strong> Explain WHY your choice is bigger/more important THAN the other factor</li>\n        <li><strong>Step 3 — Context (1 mark):</strong> Use a specific figure or detail from the case study to support your comparison</li>\n      </ul>\n      <br>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br>\n      <em>\"Consumer income will have the greatest impact because people will have less money to spend on kitchens.\"</em><br>\n      A judgement with justification — but no comparison to the unemployment factor.</p>\n      <br>\n      <p><strong>✅ Good Answer (3 marks):</strong><br>\n      <em>\"The fall in consumer income will have the greater impact on GK (JUDGEMENT). Although unemployment is forecast to fall by 0.9%, newly employed people are unlikely to immediately purchase a £15,000 luxury kitchen (CONTEXT + CONTRAST). In contrast, falling consumer income directly reduces the spending power of GK''s existing customer base, making it much harder for GK to achieve its break-even of 29 kitchens (JUSTIFICATION).\"</em></p>\n      <br>\n      <p><strong>⚠️ Examiner Warning:</strong> If you do not compare both factors, you can score a maximum of 1 mark on a 3-mark evaluation question — regardless of how detailed your answer is.</p>\n    ", "check": {"question": "According to this card, what is the maximum score if you don''t compare both options?", "options": ["1 mark, regardless of how detailed your chosen-option answer actually is", "0 marks, since any answer without a comparison scores absolutely nothing", "3 marks, since a detailed justification alone is enough for full credit", "2 marks, since justification and context are still both clearly present"], "answer": 0, "explain": "The card explains you can score a maximum of 1 mark without comparing both options — regardless of how detailed your justification of the chosen option is."}}, {"title": "Two Stakeholders: Analyse, Then Judge", "html": "\n      <p>The 7-mark evaluate question requires you to discuss the impact on <strong>two different stakeholders</strong> and then make a final judgement about which is more affected.</p>\n      <br>\n      <p><strong>Structure — 3 Paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — Stakeholder 1 (APP + AN):</strong> Identify stakeholder 1, apply the economic change to them using the case study, and analyse the impact on them specifically.</li>\n        <li><strong>Paragraph 2 — Stakeholder 2 (APP + AN):</strong> Repeat for a different stakeholder — use different impacts to avoid repetition.</li>\n        <li><strong>Paragraph 3 — Evaluation (EVAL × 3):</strong> Make a decision + state context + explain why this stakeholder is MORE affected than the other.</li>\n      </ul>\n      <br>\n      <p><strong>Good stakeholder choices for a rise in unemployment:</strong></p>\n      <ul>\n        <li>Customers — less income to spend, forced to buy cheaper goods</li>\n        <li>Shareholders — lower profits may reduce dividends and share price</li>\n        <li>Employees — risk of redundancy, pressure to accept lower wages</li>\n        <li>Suppliers — orders may fall if the business reduces production</li>\n      </ul>\n      <br>\n      <p><strong>📝 Sentence Starters:</strong></p>\n      <ul>\n        <li><em>(APP P1):</em> \"Customers of Tesco plc would be affected because a rise in unemployment means...\"</li>\n        <li><em>(AN P1):</em> \"As a result, customers may need to switch to cheaper product ranges, reducing their quality of life...\"</li>\n        <li><em>(APP P2):</em> \"Shareholders may also be impacted because falling sales lead to lower profits...\"</li>\n        <li><em>(EVAL):</em> \"Overall, I believe customers are more affected than shareholders because... However, this depends on whether Tesco''s product range (from ''basics'' to ''finest'') allows it to retain customers even during a downturn...\"</li>\n      </ul>\n    ", "check": {"question": "According to this card, what must a 7-mark evaluate answer discuss?", "options": ["A definition of the economic climate with no further analysis at all", "The impact on two different stakeholders, followed by a final judgement", "A calculation showing the exact numerical impact on the business''s profit", "The impact on only one single stakeholder, in as much detail as possible"], "answer": 1, "explain": "The card requires discussing the impact on two different stakeholders in separate paragraphs, then a final judgement on which is more affected."}}, {"title": "The Full Essay: Knowledge → Analysis → Evaluation", "html": "\n      <p>The 9-mark question is the highest-tariff question in this topic. It requires <strong>knowledge, application, analysis from two angles, and a fully justified conclusion</strong>.</p>\n      <br>\n      <p><strong>Structure — 4 Paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K &amp; U:</strong> Define the key economic concept and explain how it generally affects businesses.</li>\n        <li><strong>Paragraph 2 — AN &amp; APP (Impact 1):</strong> Analyse one specific impact on the named business, using evidence from the case study.</li>\n        <li><strong>Paragraph 3 — AN &amp; APP (Impact 2):</strong> Analyse a second, different impact (e.g. the marketing response, or the effect on a different area like HR or Finance).</li>\n        <li><strong>Paragraph 4 — Evaluation (3 points):</strong>\n          <ul>\n            <li><strong>Decision:</strong> State your overall judgement (e.g. \"Overall, a fall in consumer income is the greater threat to NEXT...\")</li>\n            <li><strong>Context:</strong> Refer to a specific detail from the case study to support your conclusion</li>\n            <li><strong>Impact/Reasoning:</strong> Explain why — include a counterargument or limiting factor (e.g. \"However, this depends on whether NEXT can successfully reposition itself as a value-for-money brand...\")</li>\n          </ul>\n        </li>\n      </ul>\n      <br>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about the economic climate. Every sentence must link back to the specific business in the question. Generic statements about recessions score very few marks at Level 3.</p>\n      <br>\n      <p><strong>📝 Sentence Starters:</strong></p>\n      <ul>\n        <li><em>(K/U):</em> \"A fall in consumer income means customers have less disposable income available to spend...\"</li>\n        <li><em>(AN/APP P2):</em> \"For NEXT plc, which sells clothing and accessories, this is particularly significant because...\"</li>\n        <li><em>(AN/APP P3):</em> \"NEXT''s marketing department may need to respond by... This could involve changing the 4Ps, specifically...\"</li>\n        <li><em>(EVAL — Decision):</em> \"Overall, I believe that a fall in consumer income poses the greater threat to NEXT''s marketing activities...\"</li>\n        <li><em>(EVAL — Context):</em> \"This is because NEXT operates in a competitive market where customers can easily switch to cheaper rivals such as Primark...\"</li>\n        <li><em>(EVAL — Reasoning):</em> \"However, the impact depends on how quickly NEXT adapts its pricing strategy and whether it can maintain brand loyalty during a period of falling incomes...\"</li>\n      </ul>\n    ", "check": {"question": "According to this card, what does the 9-mark question require beyond analysis from two angles?", "options": ["Nothing further — analysis from two angles alone is enough for full marks", "Knowledge, application, and a fully justified conclusion", "A hand-drawn diagram illustrating the economic concept being discussed", "A comparison with a completely different exam topic entirely"], "answer": 1, "explain": "The card explains the 9-mark question requires knowledge, application, analysis from two angles AND a fully justified conclusion in the final paragraph."}}]}, "exam": {"enabled": true, "questions": [{"question": "Explain how operating in a difficult economic climate might affect a business. [2 marks]", "marks": 2, "hint": "First, state what a difficult economic climate involves (e.g. rising unemployment or falling consumer income). Then explain the impact this has on a business. Do NOT start with the business impact before defining the economic problem.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 2 marks (AO1a + AO1b)</h5>\n  <ul>\n    <li><strong>Mark 1 (K):</strong> Identifies a feature of a difficult economic climate:<br>\n      • Increased unemployment / fewer jobs<br>\n      • Reduced consumer incomes / less spending</li>\n    <li><strong>Mark 2 (U):</strong> Explains how this affects a business:<br>\n      • If consumer incomes fall, demand for products might fall<br>\n      • People may have less income so demand may fall</li>\n  </ul>\n  <p><strong>Important:</strong> There must be evidence of a poor economic climate issue before any impact on a business can be rewarded. Answers do NOT need to relate to Unilever specifically.</p>\n  <p>Also accept other valid examples of a difficult economic climate: high inflation, low/negative economic growth, high interest rates.</p>\n</div>\n<div class=\"marks-section\">\n  <h5>Examiner''s Comments</h5>\n  <p>This was not well answered — fewer than 40% of candidates gained any marks. ''Economic climate'' was not understood by many students, including some who thought it referred to climate change or environmental issues. There was little reference to unemployment or consumer income. Some answers correctly described the impact but did not first show understanding of what a poor economic climate is — so no marks could be credited.</p>\n</div>"}, {"question": "Analyse one impact on GK of the predicted fall in consumer incomes. [3 marks]", "marks": 3, "hint": "Start with what a fall in consumer income means (U), then link to GK''s specific product and price from the case study (APP), then explain the consequence for the business (AN). You CANNOT score application or analysis marks without the understanding mark.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n  <ul>\n    <li><strong>Understanding (1 mark):</strong> Lower consumer spending / cannot afford products / customers have less money to spend / less disposable income</li>\n    <li><strong>Application (1 mark — must use case study):</strong>\n      <ul>\n        <li>The range is £15,000</li>\n        <li>Kitchens are luxury / expensive items</li>\n        <li>Cannot sell 29 kitchens (break-even)</li>\n        <li>GK sells in the south-east (where consumer incomes are falling)</li>\n      </ul>\n    </li>\n    <li><strong>Analysis (1 mark):</strong>\n      <ul>\n        <li>Decreased demand / revenue / profits</li>\n        <li>May not achieve break-even</li>\n        <li>Less money available for wages, investment, etc.</li>\n        <li>Need to reduce prices / cannot buy stock</li>\n      </ul>\n    </li>\n  </ul>\n  <p><strong>No further marks can be gained without the understanding mark.</strong></p>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Response</h5>\n  <p>\"Customers have less income to spend (U) and given GK''s kitchens are priced at £15,000 (APP) it is likely sales will decrease (AN).\"</p>\n</div>\n<div class=\"marks-section\">\n  <h5>Examiner''s Comments</h5>\n  <p>This question was answered well — more than half of candidates gained 2 or 3 marks. Better answers quickly identified that lower disposable income means consumers cannot afford £15,000 luxury kitchens. A common error was jumping straight to \"GK will sell fewer kitchens\" without first explaining WHY (the understanding mark) — this scored zero for both application and analysis even when correct.</p>\n</div>"}, {"question": "Analyse one impact on GK of the forecast change in the unemployment rate shown in Table 1. [3 marks]", "marks": 3, "hint": "The unemployment rate is FALLING (from 4.0% to 3.1%). Fewer unemployed people means it is harder to find workers AND that more people have jobs and income to spend. Pick ONE angle and follow U → APP → AN. Most students get this wrong by confusing falling unemployment with having fewer employees.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n  <ul>\n    <li><strong>Understanding (1 mark):</strong> Less easy to recruit employees / more consumers have an income</li>\n    <li><strong>Application (1 mark — must use Table 1):</strong>\n      <ul>\n        <li>Unemployment rate expected to fall by 0.9% over 3 years</li>\n        <li>Any use of individual data comparing the rate to 2022 (e.g. 4.0% falling to 3.1%)</li>\n      </ul>\n    </li>\n    <li><strong>Analysis (1 mark):</strong>\n      <ul>\n        <li>Wages may increase / higher recruitment costs</li>\n        <li>Unable to complete jobs on time</li>\n        <li>Increased demand / revenue / profits</li>\n        <li>Get closer to or exceed break-even</li>\n      </ul>\n    </li>\n  </ul>\n  <p><strong>Answers MUST consider the FALL in the unemployment rate (not just its existence).</strong></p>\n</div>\n<div class=\"marks-section\">\n  <h5>Examiner''s Comments</h5>\n  <p>Many candidates mixed up employment and unemployment — some suggested a fall in unemployment meant GK would now have fewer employees. This led to nearly half of all candidates scoring zero. Better answers correctly identified that falling unemployment makes it more expensive to hire staff (rising wages) or that more employed consumers could increase demand for GK''s products.</p>\n</div>"}, {"question": "Recommend whether the predicted fall in consumer incomes or the forecast change in the unemployment rate will have the greatest impact on GK. [3 marks]", "marks": 3, "hint": "Make a clear decision first (1 mark). Then COMPARE both factors — say why your chosen factor has a bigger impact than the other (1 mark). Use a specific detail from the case study to support your comparison (1 mark). If you only argue for one side without comparing, maximum 1 mark.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO3b)</h5>\n  <ul>\n    <li><strong>Judgement (1 mark):</strong> A clear decision — fall in consumer incomes OR fall in unemployment rate will have the greatest impact</li>\n    <li><strong>Justification without context (1 mark):</strong> A comparative reason explaining why the chosen factor is more significant than the other — but without specific reference to the case study data</li>\n    <li><strong>Justification with context (2 marks total for justification):</strong> A comparative reason that explicitly uses data or detail from the case study (e.g. £15,000 price, 0.9% fall, 3-year timeframe)</li>\n  </ul>\n  <p><strong>Note:</strong> A full answer MUST compare both factors. Justifying only one side without reference to the other scores a maximum of 1 mark.</p>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Responses</h5>\n  <p><strong>Example 1 (Full marks):</strong> \"Consumer incomes falling will have a bigger impact (JUDGEMENT). As GK sells expensive non-essential products (APP), a fall in consumer incomes will reduce demand, whereas the decrease in unemployment may mean people only have low-paid jobs so still cannot afford GK''s £15,000 kitchens (CONTRAST + CONTEXT).\"</p>\n  <p><strong>Example 2 (Full marks):</strong> \"The fall in unemployment rate will have little impact immediately (JUDGEMENT) as it will take 3 years and only fall by 0.9% (CONTEXT). Therefore, a fall in consumer incomes, which is happening now, will have the greater impact (CONTRAST).\"</p>\n</div>\n<div class=\"marks-section\">\n  <h5>Examiner''s Comments</h5>\n  <p>Many candidates scored only 1 mark because they justified their chosen option in detail but made no attempt to explain why it was more significant than the other factor. The comparison is essential. Better answers used specific data (e.g. £15,000, 0.9%, 3 years) to sharpen their comparison.</p>\n</div>"}, {"question": "Identify one economic factor which may affect a company''s profit. [1 mark]", "marks": 1, "hint": "Think about the two key areas covered in 6.2 — income and unemployment. You can also include GDP/economic growth or inflation. Do NOT write about costs, rents, or prices — these are NOT economic factors.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 1 mark (AO1a)</h5>\n  <p><strong>Accept any ONE valid economic factor, including:</strong></p>\n  <ul>\n    <li>Income / wages of consumers</li>\n    <li>(Un)employment levels</li>\n    <li>Economic growth / GDP / state of the economy</li>\n    <li>Inflation</li>\n  </ul>\n  <p><strong>Do NOT accept:</strong></p>\n  <ul>\n    <li>Costs / rents / prices — these are business costs, not economic factors</li>\n    <li>''The economic climate'' — this is too vague and treated as insufficient alone</li>\n    <li>Environmental factors (climate change, deforestation) — these are NOT economic factors</li>\n  </ul>\n</div>\n<div class=\"marks-section\">\n  <h5>Examiner''s Comments &amp; Misconception</h5>\n  <p>Some students correctly identified an economic factor. Wrong answers included climate change, deforestation, and costs of raw materials. Students must understand the clear difference between economic, ethical, and environmental factors — this distinction is directly tested in Section 6 of the specification.</p>\n</div>"}, {"question": "Analyse one way falling unemployment might influence recruitment at Pukka Pies Ltd. [3 marks]", "marks": 3, "hint": "Falling unemployment = fewer people out of work = harder to find available staff = businesses must offer higher wages to compete. Use a specific detail from the Pukka Pies case study (e.g. 360 employees, factory in Leicester) for the application mark.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n  <ul>\n    <li><strong>Understanding (1 mark):</strong>\n      <ul>\n        <li>The increased difficulty of replacing workers</li>\n        <li>Unable to recruit enough workers</li>\n        <li>Reference to higher consumer spending / linkage to demand for products</li>\n      </ul>\n    </li>\n    <li><strong>Application (1 mark):</strong>\n      <ul>\n        <li>360 employees</li>\n        <li>Factory in Leicester</li>\n        <li>Family-owned business</li>\n      </ul>\n    </li>\n    <li><strong>Analysis (1 mark):</strong>\n      <ul>\n        <li>Increased costs of recruitment</li>\n        <li>Higher wages needed</li>\n        <li>Production may decrease or become less efficient</li>\n        <li>May encourage the business to relocate</li>\n      </ul>\n    </li>\n  </ul>\n  <p><strong>No further marks without the understanding mark.</strong></p>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Response</h5>\n  <p>\"It may be harder to recruit workers (U) which will lead to a significant increase in costs (AN) as Pukka Pies employs 360 workers (APP).\"</p>\n</div>"}, {"question": "Analyse, with reference to Bar chart 1, one impact on AM plc of the changes in the UK unemployment rate. [3 marks]", "marks": 3, "hint": "Bar chart 1 shows UK unemployment FALLING from 7.5% (2013) to 4% (2018). You must reference this change specifically. Then explain what falling unemployment means for AM plc — either more consumer spending (demand side) or harder/more expensive recruitment (cost side).", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n  <ul>\n    <li><strong>Understanding (1 mark):</strong> Less easy to recruit employees / easier retention of employees / consumers have more income / increase in GDP</li>\n    <li><strong>Application (1 mark — must reference Bar chart 1):</strong>\n      <ul>\n        <li>Unemployment rate fell from 7.5% in 2013 to 4% in 2018</li>\n        <li>The fall in the unemployment rate is declining (rate of change)</li>\n      </ul>\n    </li>\n    <li><strong>Analysis (1 mark):</strong>\n      <ul>\n        <li>Wages may increase / higher recruitment costs</li>\n        <li>Increased demand / revenue / profits</li>\n      </ul>\n    </li>\n  </ul>\n  <p><strong>Answers MUST consider the CHANGE in the unemployment rate — not just the presence of unemployment.</strong></p>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Response</h5>\n  <p>\"A decrease in the unemployment rate (APP) from 7.5% in 2013 to 4% in 2018 may lead to increased demand in the economy (U), which may lead to increased sales for AM plc (AN).\"</p>\n</div>"}, {"question": "Analyse, with reference to Bar chart 2, one impact on AM plc of the changes in the average UK consumer income. [3 marks]", "marks": 3, "hint": "Bar chart 2 shows average UK consumer income RISING from £30,000 (2013/14) to £32,250 (2018). Reference this data specifically. Then link rising income to AM plc''s luxury products — higher income means more people can afford luxury sports cars.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n  <ul>\n    <li><strong>Understanding (1 mark):</strong> Increased disposable income / consumer spending / customers more able to purchase luxury goods</li>\n    <li><strong>Application (1 mark — must reference Bar chart 2):</strong>\n      <ul>\n        <li>Average consumer income increased from £30,000 (2013/14) to £32,250 in 2018</li>\n        <li>Growth was greatest in 2015</li>\n        <li>Consumer income has grown slowly since 2015</li>\n      </ul>\n    </li>\n    <li><strong>Analysis (1 mark):</strong>\n      <ul>\n        <li>Increased demand / revenue / profits</li>\n        <li>Consumers more likely to buy luxury products</li>\n      </ul>\n    </li>\n  </ul>\n  <p><strong>Answers MUST consider the change in consumer income.</strong></p>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Response</h5>\n  <p>\"Potential customers have more income to spend on products (U) with an average income increase to £32,250 in 2018 from £30,000 in 2013 (APP). This may also lead to increased sales for AM plc (AN).\"</p>\n</div>"}, {"question": "Recommend whether the change in the unemployment rate or the change in consumer income levels will have the greatest impact on AM plc. [3 marks]", "marks": 3, "hint": "Make a clear decision. Then COMPARE both factors — explain why your chosen one has a bigger effect on AM plc than the other. Use a specific detail from the charts or the case study. Remember: Aston Martin sells expensive LUXURY cars — who is most likely to buy one, and what makes the difference?", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO3b)</h5>\n  <ul>\n    <li><strong>Judgement (1 mark):</strong> Clear decision — unemployment rate OR consumer income levels will have the greater impact</li>\n    <li><strong>Justification (1 mark):</strong> Comparative reason (with or without context) explaining why the chosen factor outweighs the other</li>\n    <li><strong>Context (1 mark):</strong> Use of specific data or details from the case study to support the comparison</li>\n  </ul>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Response</h5>\n  <p>\"Whilst unemployment has fallen, those who have found a job are not all likely to purchase an expensive luxury car (APP). I therefore think that an increase in average consumer income will have the greatest effect (JUDGEMENT) as more high earners will see an increase in their income (JUSTIFICATION).\"</p>\n</div>"}, {"question": "Analyse one advantage and one disadvantage to Elizabeth of using crowd funding to finance the takeover. [6 marks]", "marks": 6, "hint": "This is two separate 3-mark analyses (advantage + disadvantage). For each one: state the advantage/disadvantage (U), link it to something specific about Elizabeth and LC (APP), then explain the consequence for the business (AN). You MUST show understanding before you can get application or analysis marks.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 6 marks (AO1b ×2, AO2 ×2, AO3a ×2)</h5>\n  <p>Each of the advantage and disadvantage is worth up to 3 marks using the same U → APP → AN structure. No further marks can be gained for either without the understanding mark.</p>\n  <p><strong>Advantages of crowdfunding may include:</strong></p>\n  <ul>\n    <li>Provides cheap investment — no need to pay back the money</li>\n    <li>Social media can be used to reach investors easily</li>\n    <li>Investors may offer skills or experience to the business</li>\n  </ul>\n  <p><strong>Disadvantages of crowdfunding may include:</strong></p>\n  <ul>\n    <li>Not every crowdfunding project reaches its target</li>\n    <li>A great deal of time and effort needed to promote the campaign</li>\n    <li>The business may have to give away too much (products / shares) to get enough funding</li>\n    <li>If target not met, all funds are returned to investors</li>\n  </ul>\n  <p><strong>Application evidence from the text:</strong></p>\n  <ul>\n    <li>10,000 Instagram followers / celebrity influencers</li>\n    <li>Small business / niche market</li>\n    <li>Intends to raise £30,000</li>\n    <li>Stable cash flow forecast</li>\n    <li>Net profit £56,800 in 2019</li>\n  </ul>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Responses</h5>\n  <p><strong>Advantage:</strong> \"Crowdfunding can provide cheap investment (U) because Elizabeth already has 10,000 followers on Instagram (APP), so she does not need to spend lots of money to find interested investors (AN).\"</p>\n  <p><strong>Disadvantage:</strong> \"Crowdfunding may cost Elizabeth a great deal of money (U) because she will need to give incentives to potential investors, such as free cushions (APP), reducing the profitability of the expansion (AN).\"</p>\n</div>"}, {"question": "Recommend whether Elizabeth should use crowdfunding or a bank loan to finance the takeover. [3 marks]", "marks": 3, "hint": "Make a clear decision. Then COMPARE both options — explain why your chosen method is better than the alternative. Use specific details from the case study (e.g. Instagram followers, interest on loan, £30,000 needed, stable cash flow) to support your recommendation.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 3 marks (AO3b)</h5>\n  <ul>\n    <li><strong>Judgement (1 mark):</strong> Clear recommendation — crowdfunding OR bank loan</li>\n    <li><strong>Justification (1 mark):</strong> Comparative reason explaining why the chosen option is better than the other</li>\n    <li><strong>Context (1 mark):</strong> Use of specific detail from the case study to support the comparison</li>\n  </ul>\n  <p>Students may also justify a combination of both — this is acceptable if well justified.</p>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Response</h5>\n  <p>\"I would tell Elizabeth to use a bank loan (JUDGEMENT) as it is quick and relatively easy to arrange, whereas she might struggle to raise money through crowdfunding as she is selling upmarket, expensive cushions (APP) and people may not like the price/product and therefore not want to invest (CONTRAST).\"</p>\n</div>"}, {"question": "Identify two possible impacts on a business of a rise in unemployment. [2 marks]", "marks": 2, "hint": "Give two separate impacts. Each is worth 1 mark. Keep each point brief and specific — no explanation needed for an ''identify'' question.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 2 marks (AO1a × 2)</h5>\n  <p>1 mark for each correct impact identified, up to a maximum of 2 marks.</p>\n  <p><strong>Acceptable answers include:</strong></p>\n  <ul>\n    <li>Less money in the economy / people have less income</li>\n    <li>Less spending on luxury / expensive goods</li>\n    <li>More inferior / cheaper goods purchased</li>\n    <li>Cheaper to employ new workers</li>\n    <li>Less pressure for pay increases</li>\n    <li>More potential workers available to employ</li>\n  </ul>\n</div>"}, {"question": "Evaluate the impact of a rise in unemployment on any two stakeholders of Tesco plc. [7 marks]", "marks": 7, "hint": "Choose two different stakeholders (e.g. customers and shareholders). Analyse the impact on each using the case study. Then make a final evaluation comparing which stakeholder is MORE affected — and why. You must discuss BOTH stakeholders to access evaluation marks.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 7 marks (AO2 ×2, AO3a ×2, AO3b ×3) — Levels of Response</h5>\n  <p><strong>Level 3 (5–7 marks):</strong> Good application of the impact on both stakeholders using the case study. Good analysis with logical chains of reasoning. Strong evaluation with a fully justified judgement comparing both stakeholders.</p>\n  <p><strong>Level 2 (3–4 marks):</strong> Good application to one or both stakeholders. Limited analysis — some chains of reasoning. Limited evaluation — attempts a conclusion but limited justification.</p>\n  <p><strong>Level 1 (1–2 marks):</strong> Limited application (some use of the scenario). Limited analysis — simple cause and consequence. No evaluation.</p>\n  <p><strong>0 marks:</strong> No response worthy of credit.</p>\n</div>\n<div class=\"marks-section\">\n  <h5>Stakeholder Suggestions</h5>\n  <ul>\n    <li>Shareholders — lower profits → lower dividends → possible fall in share price</li>\n    <li>Customers — less income → switch to cheaper goods → reduced quality of life</li>\n    <li>Employees — risk of redundancy / wage cuts</li>\n    <li>Suppliers — Tesco may order less → supplier revenue falls</li>\n  </ul>\n</div>\n<div class=\"marks-section\">\n  <h5>Exemplar Response Extract</h5>\n  <p>\"Tesco is a public limited company which means it has shareholders (AO2). They are likely to be adversely affected because sales and profits will go down as there will be less spending in the economy, which may mean lower dividends and possibly a lower share price (AO3a). Customers may also be adversely affected because they will have less money to spend on their shopping (AO2). This could mean that they have to buy cheaper goods from Tesco, such as the basics range of food (AO2), which may not be as nice to eat and reduce their happiness (AO3a). The customers are likely to face a bigger impact than the shareholders because having to buy lower quality food has a direct impact on daily life. However, because Tesco sells products aimed at every income level (from basic to ''finest''), it is unlikely that sales will reduce by very much, so the share price may not be badly affected (AO3b).\"</p>\n</div>"}, {"question": "* Evaluate how a fall in consumer income levels might impact on the marketing activities of NEXT plc. [9 marks]", "marks": 9, "hint": "This is a 9-mark essay. You need Knowledge, Understanding, Application to NEXT, two chains of Analysis, and a fully justified Evaluation with a clear decision. Discuss at least two aspects of the marketing mix (4Ps: Product, Price, Promotion, Place). Make sure your conclusion compares the options and doesn''t just repeat what you said earlier.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 9 marks (AO1a ×1, AO1b ×1, AO2 ×2, AO3a ×2, AO3b ×3) — Levels of Response</h5>\n  <p><strong>Level 3 (7–9 marks):</strong> Good knowledge and understanding of marketing activities and the effects of falling incomes. Good application using NEXT''s specific context. Good analysis — logical chains of reasoning. Strong evaluation — a fully justified judgement drawing on underpinning knowledge.</p>\n  <p><strong>Level 2 (4–6 marks):</strong> Good knowledge/understanding and application to NEXT. Limited analysis — some chains of reasoning. Limited evaluation — attempts a conclusion with some recognition of influencing factors.</p>\n  <p><strong>Level 1 (1–3 marks):</strong> Limited knowledge/understanding. Some use of the scenario. Limited analysis — simple cause and consequence. No evaluation.</p>\n  <p><strong>0 marks:</strong> No response worthy of credit.</p>\n</div>\n<div class=\"marks-section\">\n  <h5>Content That May Be Included</h5>\n  <ul>\n    <li>Greater need for market research to understand changing customer needs</li>\n    <li>Change of marketing mix — product, price, promotion, place</li>\n    <li>More promotion / increased advertising</li>\n    <li>Cheaper prices / penetration pricing</li>\n    <li>Change in distribution channel (increase online sales)</li>\n    <li>Change marketing objectives</li>\n    <li>Consider ethical/sustainable credentials as a marketing angle</li>\n    <li>Buy in greater bulk to reduce costs and offer lower prices</li>\n  </ul>\n</div>\n<div class=\"marks-section\">\n  <h5>Examiner''s Note</h5>\n  <p>Content from components 01 and 02 is synoptically assessed in this question — students should draw on their wider knowledge of marketing (Section 2) alongside the economic climate (Section 6).</p>\n</div>"}, {"question": "Which one of the following actions should the car dealership take to help increase its sales during a period of falling consumer income?", "marks": 1, "hint": "Think about what happens when customers have less money. What marketing action directly makes products more affordable and attractive to price-sensitive buyers?", "markScheme": "<div class=\"marks-section\">\n  <h5>Answer: B — Offer price reductions</h5>\n  <p><strong>Why B is correct:</strong> When consumer incomes fall, customers have less money to spend. Offering price reductions makes the cars more accessible to buyers with reduced budgets, directly addressing the affordability problem and helping to maintain demand.</p>\n  <br>\n  <p><strong>Why the other options are wrong:</strong></p>\n  <ul>\n    <li><strong>A — Advertise less:</strong> Reducing advertising would make the business less visible to potential customers, likely causing sales to fall further — the opposite of what is needed.</li>\n    <li><strong>C — Reduce customer engagement:</strong> Poor customer engagement means fewer interactions with potential buyers, reducing the chance of making a sale. This would worsen the problem.</li>\n    <li><strong>D — Reduce its costs:</strong> While reducing costs is a sensible internal strategy during a downturn, it does not directly increase sales. The question asks what should be done to increase sales, not to manage internal finances.</li>\n  </ul>\n</div>"}, {"question": "Which of the following statements is true?", "marks": 1, "hint": "Watch out for the words ''always'' and ''all'' — these are clues that a statement is likely to be FALSE. Think about which statement is sometimes true and not an absolute rule.", "markScheme": "<div class=\"marks-section\">\n  <h5>Answer: B — Rising incomes often lead to an increase in the sales of luxury goods</h5>\n  <p><strong>Why B is correct:</strong> When incomes rise, customers can afford higher-quality and non-essential items. Luxury goods businesses like JC Motors typically benefit from rising incomes, as more customers can consider purchasing high-end products. The word ''often'' makes this statement accurate — it is a tendency, not an absolute rule.</p>\n  <br>\n  <p><strong>Why the other options are wrong:</strong></p>\n  <ul>\n    <li><strong>A — \"Will always increase\":</strong> FALSE. Businesses selling cheap or budget goods may actually see sales FALL when incomes rise, as customers trade up to more expensive alternatives.</li>\n    <li><strong>C — \"Will make ALL consumers worse off\":</strong> FALSE. Not all consumers are unemployed. Those who keep their jobs may even benefit if lower unemployment causes wages to eventually rise. Budget shoppers may also find it easier to get work.</li>\n    <li><strong>D — \"Will always cause a business to sell less\":</strong> FALSE. Discount retailers like Aldi can see sales RISE when consumer incomes fall, as customers switch to cheaper options.</li>\n  </ul>\n</div>"}, {"question": "Evaluate how a fall in consumer incomes and an increase in unemployment might impact on JC Motors Ltd. [9 marks]", "marks": 9, "hint": "This is a 9-mark evaluate question. You need to discuss BOTH factors (falling incomes AND rising unemployment) and their specific impact on JC Motors. Apply both to the context of a high-end car business. Include JC Motors'' response (diversifying into second-hand cars) and end with a fully justified evaluation.", "markScheme": "<div class=\"marks-section\">\n  <h5>Mark Allocation — 9 marks (K ×1, U ×1, APP ×2, AN ×2, EV ×3)</h5>\n  <p><strong>Knowledge (1 mark):</strong> Understanding what a fall in consumer income or a rise in unemployment means.</p>\n  <p><strong>Understanding (1 mark):</strong> Explaining how this affects businesses generally.</p>\n  <p><strong>Application (2 marks):</strong> Linking to JC Motors specifically — using the prices (£50,000–£300,000), the unemployment figures (2m to 2.2m), and the diversification into second-hand cars (£15,000–£80,000).</p>\n  <p><strong>Analysis (2 marks):</strong> Developing the chain of consequences — e.g. falling incomes → fewer luxury car sales → revenue falls → may threaten survival of the business OR diversification → broader customer base → may offset some lost revenue.</p>\n  <p><strong>Evaluation (3 marks):</strong> A justified judgement — which factor has the greater impact? Does the diversification strategy solve the problem? What does success depend on?</p>\n</div>"}]}}'::jsonb),
('business', '6-3-globalisation', '6.3 Globalisation', '{"learn": {"enabled": true, "items": [{"title": "What is Globalisation?", "html": "<p><strong>Globalisation</strong> is the process by which business activity around the world has become increasingly interconnected. It involves three key movements:</p>\n<ul>\n<li><strong>Trade:</strong> Buying and selling goods and services made in different countries.</li>\n<li><strong>People:</strong> The movement of workers from country to country.</li>\n<li><strong>Capital:</strong> The movement of money or assets (machines, buildings, vehicles) from country to country.</li>\n</ul>\n<p>Globalisation has increased at a rapid rate, driven by three major improvements:</p>\n<ul>\n<li><strong>Transport:</strong> Costs have fallen as ships and planes have grown bigger. The development of <strong>containers</strong> — standardised boxes lifted by crane from ship to lorry — has significantly reduced costs.</li>\n<li><strong>Telecommunications & the Internet:</strong> Communication is faster and cheaper. Businesses can research suppliers worldwide, order via email or video-conferencing, and promote products through websites and social media.</li>\n<li><strong>Free Trade Arrangements:</strong> <strong>Free trade</strong> exists when there are no barriers such as <strong>tariffs</strong> (taxes on imports), <strong>quotas</strong> (limits on the amount imported) or <strong>regulations</strong> (rules on goods that can be sold). The WTO encourages countries to remove these barriers. Examples of free trade areas include NAFTA (USA, Canada, Mexico) and SAFTA (South Asia).</li>\n</ul>", "check": {"question": "According to this card, what are the three key movements involved in globalisation?", "options": ["Branding, marketing, and advertising", "Tariffs, quotas, and regulations", "Trade, people, and capital movement", "Imports, exports, and exchange rates"], "answer": 2, "explain": "The card explains globalisation involves three key movements: trade (goods/services), people (workers), and capital (money and assets) between countries."}}, {"title": "Key Terminology", "html": "<ul>\n<li><strong>Globalisation:</strong> The process by which business activity around the world has become increasingly interconnected.</li>\n<li><strong>International Branding:</strong> Creating an image or values for a product that are communicated in countries around the world.</li>\n<li><strong>Free Trade:</strong> The absence of restrictions on trade between countries.</li>\n<li><strong>Tariff:</strong> A tax on a good or service that is imported.</li>\n<li><strong>Quota:</strong> A limit in terms of weight or value on the amount of a good or service that can be imported.</li>\n<li><strong>Regulations:</strong> Rules about the goods and services that can be sold in a country.</li>\n<li><strong>Multinational Company (MNC):</strong> A business that operates in different countries around the world.</li>\n<li><strong>Productivity:</strong> A measure of the output of each worker on average.</li>\n<li><strong>Unit Cost:</strong> The cost per unit produced. The greater the productivity of workers, the lower the unit cost.</li>\n<li><strong>Exchange Rate:</strong> The price of one currency in terms of another (e.g. £1 = €1.2).</li>\n</ul>", "check": {"question": "According to the key terminology, what is a ''quota''?", "options": ["A tax charged on a good or service that is imported", "The price of one currency expressed in terms of another", "A rule about the goods and services that can be sold in a country", "A limit on the weight or value of a good that can be imported"], "answer": 3, "explain": "The card defines a quota as a limit on the weight or value of a good that can be imported — distinct from a tariff (a tax) or a regulation (a rule)."}}, {"title": "Multinational Companies (MNCs)", "html": "<p><strong>Multinational companies (MNCs)</strong> are businesses that operate in more than one country. They are a key feature of globalisation. Well-known examples include Google, Amazon, Coca-Cola, Starbucks and McDonald''s.</p>\n<p>There are several advantages to a <strong>business</strong> of becoming a multinational:</p>\n<ul>\n<li><strong>Increasing sales:</strong> Selling in more countries increases the size of the market and potential revenue.</li>\n<li><strong>Spreading risk:</strong> If one market suffers a recession, the company can compensate with sales growth in another country.</li>\n<li><strong>Lower costs:</strong> Production may be cheaper in another country due to lower wages, cheaper land, or better technology.</li>\n<li><strong>Tax avoidance:</strong> MNCs may set up headquarters in low-tax countries (e.g. Luxembourg or Ireland) to reduce their overall tax bill, even while selling in higher-tax countries.</li>\n</ul>", "check": {"question": "According to this card, why might a business become a multinational to reduce risk?", "options": ["If one market suffers a recession, sales growth elsewhere can compensate", "Multinationals never have to pay any tax in any country they operate in", "Multinationals only ever sell their products in a single country at once", "Multinationals are legally protected from ever making a loss at all"], "answer": 0, "explain": "The card lists spreading risk as an advantage of becoming multinational — if one market suffers a recession, growth in another market can compensate."}}, {"title": "Impact of MNCs on the Host Country", "html": "<p>The country where a multinational locates is called the <strong>host country</strong>. MNCs bring both benefits and drawbacks to that country.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages to Host Country</div>\n<div class=\"pro-item\"><strong>Creates demand for local businesses:</strong> MNCs employ local people, increasing incomes and local spending. They may also buy supplies from local firms.</div>\n<div class=\"pro-item\"><strong>Taxes & public services:</strong> Tax payments by MNCs help governments fund education, health and infrastructure.</div>\n<div class=\"pro-item\"><strong>Lower prices:</strong> By keeping costs low, MNCs may offer goods and services at cheaper prices for consumers and businesses.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages to Host Country</div>\n<div class=\"con-item\"><strong>Business closures:</strong> Local firms may be unable to compete on price or quality and get forced out of business. MNCs may also pay higher wages, pulling workers away from local employers.</div>\n<div class=\"con-item\"><strong>Outflows of money:</strong> Profits are often sent back to the MNC''s home country headquarters, limiting the financial benefit to the host country.</div>\n<div class=\"con-item\"><strong>Diseconomies of scale:</strong> As MNCs grow very large, they can become harder to manage and less efficient.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: Vodafone in the UK</h4>\n<p>Vodafone sells mobile and ICT services across many countries. Although headquartered in the UK, profits are routed to Luxembourg where taxation is much lower — a practice accused of being tax avoidance. Vodafone disputes this, arguing it pays all taxes legally owed and contributes through investment, job creation and over £1.2 billion spent on UK network upgrades. This case illustrates the debate around whether MNCs truly benefit host countries or exploit lower-tax loopholes.</p>\n</div>", "check": {"question": "According to the Vodafone case study, what practice is Vodafone accused of?", "options": ["Selling all of its UK operations to a foreign competitor firm", "Refusing to invest any money at all in UK network upgrades", "Routing profits to Luxembourg, where taxation is much lower", "Employing no staff whatsoever within the United Kingdom itself"], "answer": 2, "explain": "The card explains Vodafone routes profits to Luxembourg where taxation is lower — a practice accused of being tax avoidance, which Vodafone disputes."}}, {"title": "Influences on Business Location", "html": "<p>Globalisation means businesses have greater freedom to choose <strong>where</strong> they locate production. A UK business may move production abroad — or bring it back home — for several reasons.</p>\n<p><strong>Reasons to locate ABROAD:</strong></p>\n<ul>\n<li><strong>Lower labour costs:</strong> Wages are much lower in many countries, especially in the Far East. This is why Raleigh Cycles moved production to Taiwan.</li>\n<li><strong>Lower technology costs:</strong> Some foreign firms have invested more in up-to-date manufacturing technology, reducing production costs.</li>\n<li><strong>Lower property/land costs:</strong> Factories and premises may be cheaper abroad.</li>\n<li><strong>Access to expertise:</strong> Businesses may locate near specialist skills or R&D talent in other countries.</li>\n<li><strong>Proximity to demand:</strong> Locating near the target market can increase sales. The Electric Car Corporation moved production to Denmark because demand for electric cars was stronger there.</li>\n</ul>\n<p><strong>Reasons to move production BACK to the UK:</strong></p>\n<ul>\n<li><strong>Quality control:</strong> It is easier to monitor standards when production is close to headquarters.</li>\n<li><strong>Communications:</strong> No language barriers or time zone differences with a UK workforce.</li>\n<li><strong>Skilled labour:</strong> The UK has a strong supply of skilled workers in many industries.</li>\n<li><strong>Consumer preference:</strong> Many UK customers prefer goods labelled ''Made in Britain''.</li>\n<li><strong>Environment:</strong> UK production reduces transport distances, lowering the business''s carbon footprint — a strong marketing point.</li>\n<li><strong>Rising foreign wages:</strong> As wages in developing countries increase, the cost advantage of producing abroad shrinks.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: Raleigh Cycles</h4>\n<p>Raleigh, the famous Nottingham bicycle manufacturer, went bankrupt in the 2000s. New owners moved production to Taiwan and South East Asia to cut costs, while keeping sales, marketing and design in the UK. The business recovered strongly and has since moved some assembly back to Nottingham — showing that location decisions are not permanent and must be regularly reviewed.</p>\n</div>", "check": {"question": "According to the Raleigh Cycles case study, what does the company''s history show?", "options": ["Moving production abroad always causes a company to go bankrupt", "Once a business moves abroad, it can never return production home", "Raleigh has never produced any bicycles outside of Nottingham at all", "Location decisions are not permanent and must be regularly reviewed"], "answer": 3, "explain": "The card explains Raleigh moved production to Taiwan then moved some assembly back to Nottingham — showing location decisions must be regularly reviewed."}}, {"title": "International Branding", "html": "<p><strong>Branding</strong> refers to a product''s image, reputation and values — communicated through logos, words, images, music and media (TV, social media, websites). When selling globally, a business must adapt its branding to suit each country. The key principle is: <strong>\"Think global, act local\"</strong> — promote the same core values worldwide, but deliver the message differently in each market.</p>\n<p>Businesses must consider the following factors when creating an international brand:</p>\n<ul>\n<li><strong>Culture & Religion:</strong> Images or themes acceptable in one country may deeply offend in another. A Coca-Cola ad featuring Father Christmas would not work in a predominantly Muslim country like Pakistan.</li>\n<li><strong>Language:</strong> Product names, slogans and advertisements must be translated carefully. An American fast food company mistakenly advertised ''yassuppoi'' chips in Japan — meaning ''low quality'' in Japanese.</li>\n<li><strong>Names:</strong> Products sometimes need different names. Burger King operates as ''Hungry Jack''s'' in Australia because the Burger King name was already trademarked there.</li>\n<li><strong>Level & Distribution of Income:</strong> There is no point promoting a luxury product in a country where most people cannot afford it. Businesses must research average incomes and how evenly wealth is spread.</li>\n<li><strong>Legal Factors:</strong> Businesses must follow local advertising laws. Alcohol advertising is illegal in Sri Lanka; cigarettes are banned entirely in Bhutan.</li>\n<li><strong>Bribery:</strong> In some countries, bribery is commonplace in business dealings. In the UK it is illegal and carries serious reputational and legal consequences.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: McDonald''s in India</h4>\n<p>McDonald''s adapts its products to suit local cultures. In India, where beef is not eaten for religious reasons, the Big Mac is made from chicken and marketed as the ''Maharajah Mac'' (meaning king-size burger). Prices are also lower — around £1.97 compared to £3.25 in the UK — to reflect lower average incomes. This shows how the 4 Ps (Product, Price, Promotion, Place) must all be adapted for international markets.</p>\n</div>", "check": {"question": "According to the McDonald''s in India case study, how did McDonald''s adapt its product?", "options": ["It made the Big Mac from chicken instead of beef, for religious reasons", "It kept the exact same product and price as in every other country", "It charged higher prices in India than in the UK for the same burger", "It refused to sell any burgers at all within the Indian market"], "answer": 0, "explain": "The card explains McDonald''s made the ''Maharajah Mac'' from chicken (since beef is not eaten for religious reasons in India) and priced it lower than the UK Big Mac."}}, {"title": "How Businesses Compete Internationally", "html": "<p>Competing internationally means both selling abroad and competing against foreign firms at home. Businesses must adapt across all areas of the organisation:</p>\n<ul>\n<li><strong>Growth:</strong> Businesses may expand organically (e.g. Marks & Spencer opening shops across the world) or through joint ventures (e.g. Jaguar Land Rover partnering with Chery in China to produce and sell cars without import tariffs).</li>\n<li><strong>Marketing (4 Ps):</strong> Products may need to be changed (e.g. JLR makes longer wheelbase cars for Chinese buyers); prices adjusted for local incomes; promotions must reflect local culture; and place decisions must consider whether to be near customers or raw materials.</li>\n<li><strong>Human Resources:</strong> Businesses must recruit and train overseas workers, comply with local employment laws, and find suitable ways to motivate staff in different cultural contexts.</li>\n<li><strong>Business Operations:</strong> Methods of production may need to change — switching from job to batch production to cut costs. Quality assurance processes must be put in place if producing abroad.</li>\n<li><strong>Finance:</strong> International expansion requires sources of finance for investment. Break-even analysis helps businesses assess whether selling in a new country will be profitable.</li>\n<li><strong>Ethical & Environmental:</strong> Businesses must consider the ethical implications of producing in countries with weaker labour laws or environmental standards. Negative publicity (e.g. Primark and child labour accusations) can damage a brand significantly.</li>\n</ul>", "check": {"question": "According to this card, why did Jaguar Land Rover form a joint venture with Chery in China?", "options": ["To avoid ever having to adapt its products for Chinese buyers", "To prevent Chinese customers from being able to buy its cars", "To stop selling any of its cars within the United Kingdom market", "To produce and sell cars in China without paying import tariffs"], "answer": 3, "explain": "The card explains JLR partnered with Chery in China to produce and sell cars there without import tariffs, while also adapting products like longer wheelbase cars."}}, {"title": "Exchange Rates & International Competitiveness", "html": "<p>The <strong>exchange rate</strong> is the price of one currency in terms of another (e.g. £1 = €1.20). Changes in the exchange rate directly affect the price of exports and imports, and therefore a business''s competitiveness abroad.</p>\n<p>A useful mnemonic to remember the effects is <strong>SPICED</strong>:</p>\n<div class=\"formula-box\">\n<strong>SPICED</strong> = Strong Pound → Imports Cheaper, Exports Dearer\n</div>\n<ul>\n<li><strong>If the pound rises (strengthens):</strong> Exports become more expensive for foreign buyers (likely to reduce export sales). Imports become cheaper for UK businesses (good for importers, but harder for domestic producers to compete).</li>\n<li><strong>If the pound falls (weakens):</strong> Exports become cheaper for foreign buyers (likely to increase export sales). Imports become more expensive (raises costs for UK firms that rely on imported materials).</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Weak Pound — Good For</div>\n<div class=\"pro-item\"><strong>Exporters:</strong> Their goods become cheaper abroad, increasing overseas sales. Brandauer, a Birmingham engineering firm, saw export sales rise after the pound fell following Brexit.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Weak Pound — Bad For</div>\n<div class=\"con-item\"><strong>Importers:</strong> Imported raw materials and components become more expensive, pushing up production costs. Princess Yachts noted costs rose as imported components became pricier after the pound fell.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: Princess Yachts</h4>\n<p>Princess Yachts, based in Plymouth, sells 80% of its yachts abroad. After the pound fell in value, exports became cheaper for overseas buyers and sales increased. However, costs also rose slightly as some imported components became more expensive. This illustrates that exchange rate changes rarely have a simple, one-sided effect — businesses that both import and export must weigh up the overall impact carefully.</p>\n</div>", "check": {"question": "According to the SPICED mnemonic in this card, what happens when the pound is strong?", "options": ["Both imports and exports become dearer at the same time", "Both imports and exports become cheaper at the same time", "Imports become dearer and exports become cheaper", "Imports become cheaper and exports become dearer"], "answer": 3, "explain": "The SPICED mnemonic states: Strong Pound leads to Imports Cheaper, Exports Dearer — the reverse happens when the pound weakens."}}, {"title": "Brexit & Its Impact on UK Businesses", "html": "<p>The UK officially left the European Union in January 2020. Since 1 January 2021, new trading rules have applied. Brexit has had both negative and positive effects on UK businesses.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✗ Negative Effects</div>\n<div class=\"con-item\"><strong>New paperwork & inspections:</strong> UK exports to the EU must now meet EU standards and be accompanied by documentation. This costs time and money, and border delays have slowed deliveries. Some UK firms have stopped trading with the EU entirely.</div>\n<div class=\"con-item\"><strong>Labour shortages:</strong> Freedom of movement has ended. EU workers must now apply for the right to work in the UK. Restaurant chains like D&D London (43 restaurants) have struggled to recruit skilled chefs as a result.</div>\n<div class=\"con-item\"><strong>Rules of origin:</strong> UK-made goods must use a minimum proportion of British components to qualify as ''Made in the UK'' when exporting to the EU.</div>\n<div class=\"con-item\"><strong>Northern Ireland complications:</strong> Goods moving from the rest of the UK to Northern Ireland are treated as exports to the EU, requiring extra checks.</div>\n</div>\n<div>\n<div class=\"col-head\">✓ Positive Effects</div>\n<div class=\"pro-item\"><strong>New trade deals:</strong> The UK is now free to negotiate independently with non-EU countries. A deal with Japan already makes 99% of UK exports to Japan tariff-free.</div>\n<div class=\"pro-item\"><strong>Weaker pound boosts exports:</strong> The fall in the pound''s value after Brexit made UK exports cheaper. Brandauer (Birmingham) increased EU exports of precision-engineered components as a result.</div>\n<div class=\"pro-item\"><strong>Some inward investment:</strong> Nissan announced over £1 billion of investment to expand electric car production in Sunderland after the Brexit free-trade deal was secured.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: The Cheshire Cheese Company</h4>\n<p>Before Brexit, the Cheshire Cheese Company exported cheese to the EU with no tariffs and no additional paperwork. After Brexit, each export now requires a health certificate costing £180 — even for a gift package worth just £30. The owner estimated a loss of revenue of up to £250,000. This illustrates how non-tariff barriers (like certificates and inspections) can be just as damaging as tariffs for small exporters.</p>\n</div>", "check": {"question": "According to the Cheshire Cheese Company case study, what changed after Brexit?", "options": ["The company was banned from exporting any cheese at all", "Exports to the EU became completely free of any paperwork", "Each export now requires a health certificate costing £180", "Tariffs on cheese exports to the EU were removed entirely"], "answer": 2, "explain": "The card explains that after Brexit each export now requires a £180 health certificate, even for a small gift package — a non-tariff barrier that damaged the business."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Globalisation", "definition": "The process by which business activity around the world has become increasingly interconnected through trade, movement of people, and movement of capital."}, {"term": "Tariff", "definition": "A tax on a good or service that is imported into a country, making it more expensive and less competitive."}, {"term": "Quota", "definition": "A limit in terms of weight or value on the amount of a good or service that can be imported."}, {"term": "Free Trade", "definition": "Trade between countries with no barriers such as tariffs, quotas, or trade regulations."}, {"term": "Multinational Company (MNC)", "definition": "A business that operates in more than one country — not just sells there, but has physical facilities or staff there."}, {"term": "International Branding", "definition": "Creating an image or values for a product that are recognised and communicated in countries around the world."}, {"term": "Exchange Rate", "definition": "The price of one currency expressed in terms of another (e.g. £1 = €1.20)."}, {"term": "SPICED", "definition": "Strong Pound → Imports Cheaper, Exports Dearer. A mnemonic to remember the effect of exchange rate changes on trade."}, {"term": "Host Country", "definition": "The country in which a multinational company chooses to locate its operations."}, {"term": "Profit Repatriation", "definition": "When a multinational company transfers profits earned in a host country back to its home country headquarters."}, {"term": "Think Global, Act Local", "definition": "A branding principle: maintain consistent global brand values but adapt the message, product, or promotion to suit local cultures and markets."}, {"term": "Containerisation", "definition": "The use of standardised shipping containers that can be transferred between ships, lorries, and trains — dramatically reducing the cost of global trade."}, {"term": "WTO", "definition": "The World Trade Organisation — an international body that encourages countries to reduce trade barriers and promote free trade."}, {"term": "Unit Cost", "definition": "The cost of producing one unit of output. Higher productivity = lower unit costs."}, {"term": "Productivity", "definition": "A measure of the output produced per worker on average. Higher productivity means more output for the same cost."}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the correct definition of globalisation?", "options": ["The process by which a business expands its product range", "The process by which business activity across the world has become increasingly interconnected", "The process of a business setting up a new branch in a foreign country", "The process of removing taxes on goods produced in a single country"], "answer": 1, "explain": "Correct answer: Globalisation refers to the increasing interconnection of business activity worldwide — including trade, movement of people, and movement of capital across borders."}, {"question": "Which of the following is a tariff?", "options": ["A limit on the amount of a good that can be imported", "A rule about the quality standard a product must meet", "A tax on a good or service that is imported", "A government subsidy given to domestic producers"], "answer": 2, "explain": "Correct answer: A tariff is a tax placed on imported goods or services, making them more expensive and less competitive compared to domestically produced alternatives."}, {"question": "A quota is best described as:", "options": ["A tax applied to exports leaving a country", "A limit in terms of weight or value on the amount of a good that can be imported", "A government grant given to multinational companies", "A minimum wage level set for overseas workers"], "answer": 1, "explain": "Correct answer: A quota restricts the volume or value of imports allowed into a country, protecting domestic industries from too much foreign competition."}, {"question": "Which mnemonic helps students remember the effect of a strong pound on trade?", "options": ["SMART — Strong Money Affects Retail Trading", "FOREX — Foreign Exchange Reduces Exports", "SPICED — Strong Pound: Imports Cheaper, Exports Dearer", "TRADE — Tariffs Reduce All Domestic Earnings"], "answer": 2, "explain": "Correct answer: SPICED stands for Strong Pound: Imports Cheaper, Exports Dearer. When the pound strengthens, UK exports become more expensive for foreign buyers, reducing competitiveness abroad."}, {"question": "What makes a company a multinational company (MNC)?", "options": ["It sells products to customers in more than one country", "It has an internationally recognised brand name", "It operates (has physical presence) in more than one country", "It is listed on a foreign stock exchange"], "answer": 2, "explain": "Correct answer: An MNC is defined by where it operates — having factories, offices, or facilities in multiple countries. Simply selling abroad does not make a business a multinational."}, {"question": "Which of the following developments most helped reduce the cost of international shipping?", "options": ["The introduction of tariff-free zones", "The development of standardised containers", "The creation of the World Trade Organisation", "The expansion of free trade areas in Asia"], "answer": 1, "explain": "Correct answer: Standardised shipping containers revolutionised global trade by making it faster and cheaper to transfer goods between ships, lorries and trains, dramatically cutting logistics costs."}, {"question": "If the pound weakens against the euro, what is the most likely effect for a UK exporter?", "options": ["UK exports become more expensive for EU buyers, reducing sales", "UK exports become cheaper for EU buyers, potentially increasing sales", "UK imports become cheaper, improving profit margins", "The exchange rate has no effect on export competitiveness"], "answer": 1, "explain": "Correct answer: A weaker pound means UK goods cost less in foreign currencies. This makes UK exports more competitively priced abroad, which can boost export sales."}, {"question": "International branding requires businesses to ''think global, act local''. What does this mean?", "options": ["Translate all advertising into every language", "Sell the same product at the same price globally", "Maintain core brand values worldwide but adapt the message for local cultures", "Only promote products in countries where average incomes are high"], "answer": 2, "explain": "Correct answer: ''Think global, act local'' means a business maintains a consistent global brand identity (e.g. logo, core values) while adapting elements like language, imagery and promotions to suit local cultural and religious norms."}, {"question": "Which of the following is a benefit of becoming a multinational for the host country?", "options": ["Profits are kept in the host country", "Local firms always grow stronger due to increased competition", "Jobs and tax revenues are created in the host country", "The host country''s currency always strengthens"], "answer": 2, "explain": "Correct answer: MNCs bring jobs to host countries, increasing incomes and local spending. They also pay taxes which fund public services. However, profits are often repatriated to the home country."}, {"question": "Raleigh Cycles moved production to Taiwan. Which factor best explains this decision?", "options": ["Proximity to major UK customers", "Lower labour and production costs abroad", "Better quality control near UK headquarters", "To avoid paying UK corporation tax"], "answer": 1, "explain": "Correct answer: Raleigh moved production to Taiwan primarily to reduce costs — wages and manufacturing costs were significantly lower there than in the UK, improving competitiveness."}, {"question": "What is free trade?", "options": ["Trade between businesses that do not charge customers", "The absence of barriers such as tariffs or quotas between countries", "A government scheme that subsidises domestic exporters", "Trade only conducted between countries with the same currency"], "answer": 1, "explain": "Correct answer: Free trade means trading between countries without barriers like tariffs, quotas or regulations. It is encouraged by organisations like the WTO and exists in areas like NAFTA and SAFTA."}, {"question": "Which of the following is a disadvantage of globalisation for a host country?", "options": ["Access to foreign investment and technology", "New job opportunities for local workers", "Profits sent back to the MNC''s home country, reducing local economic benefit", "Lower prices for consumers"], "answer": 2, "explain": "Correct answer: A key drawback of MNCs in host countries is profit repatriation — where profits are transferred to the company''s home country headquarters rather than being reinvested locally, limiting economic benefit."}]}, "fib": {"enabled": true, "questions": [{"text": "Globalisation involves three key movements: [trade], people, and [capital]."}, {"text": "A [tariff] is a tax on an imported good, while a [quota] is a limit on the amount that can be imported."}, {"text": "The mnemonic [SPICED] reminds us that a strong pound makes imports [cheaper] and exports [dearer]."}, {"text": "A multinational company is one that [operates] in more than one country, not just [sells] there."}, {"text": "International branding means creating a product [image] that is communicated in countries around the [world]."}, {"text": "Raleigh Cycles moved production to [Taiwan] in order to benefit from lower [labour] costs."}, {"text": "When the pound [weakens], UK exports become cheaper for overseas buyers, which may increase [sales]."}, {"text": "The principle ''think [global], act [local]'' means maintaining global brand values while adapting to local cultures."}, {"text": "One disadvantage of an MNC for the host country is [profit] repatriation, where profits are sent back to the [home] country."}, {"text": "The World Trade Organisation (WTO) encourages countries to reduce [tariffs] and other trade [barriers]."}, {"text": "After Brexit, UK businesses exporting to the EU must complete additional [paperwork] and pay for [health] certificates."}, {"text": "The development of standardised shipping [containers] significantly reduced the cost of global [sea] transport."}]}, "tf": {"enabled": true, "questions": [{"statement": "A tariff is a limit on the quantity of a good that can be imported.", "answer": false, "explain": "FALSE. A tariff is a TAX on imported goods. A QUOTA is the limit on the quantity or value of imports. These are two different trade barriers."}, {"statement": "A multinational company is defined as any business that sells products to customers in another country.", "answer": false, "explain": "FALSE. A multinational company must OPERATE in more than one country — meaning it has physical facilities such as factories, offices or staff there. Simply selling abroad does not make a business multinational."}, {"statement": "When the pound strengthens against other currencies, UK exports become more expensive for foreign buyers.", "answer": true, "explain": "TRUE. A stronger pound means foreign buyers need more of their currency to buy the same amount of pounds. This makes UK goods more expensive abroad, potentially reducing export sales — as summarised by SPICED."}, {"statement": "Free trade means there are no tariffs, quotas, or restrictions on trade between countries.", "answer": true, "explain": "TRUE. Free trade is defined as the absence of barriers (tariffs, quotas, regulations) on international trade. Examples of free trade areas include NAFTA and SAFTA."}, {"statement": "International branding means a business sells its products in every country in the world.", "answer": false, "explain": "FALSE. International branding means creating a brand image that is recognised and promoted across multiple countries — but a business does not need to sell everywhere to have an international brand."}, {"statement": "One benefit for a host country when an MNC locates there is that jobs and tax revenues are created.", "answer": true, "explain": "TRUE. MNCs create employment for local workers and pay taxes to the host government, helping to fund public services such as schools and hospitals."}, {"statement": "When the pound weakens, UK imports become cheaper for domestic businesses.", "answer": false, "explain": "FALSE. When the pound weakens, imports become MORE expensive because it costs more pounds to buy the same amount of foreign currency. A weaker pound makes exports cheaper, not imports."}, {"statement": "Containerisation has helped reduce the cost of international trade by standardising how goods are transported by sea.", "answer": true, "explain": "TRUE. Standardised shipping containers can be loaded quickly between ships, lorries, and trains, dramatically cutting transport costs and boosting global trade volumes."}, {"statement": "Raleigh Cycles moved production back to the UK to take advantage of lower labour costs.", "answer": false, "explain": "FALSE. Raleigh moved production TO Taiwan (abroad) to benefit from lower labour costs. Some production was later returned to the UK, but the initial move abroad was specifically to cut costs."}, {"statement": "One risk of a multinational becoming too large is that it may face diseconomies of scale, becoming harder to manage efficiently.", "answer": true, "explain": "TRUE. As MNCs grow very large and spread across many countries, coordination becomes complex, communication slows down, and management costs rise — all signs of diseconomies of scale."}, {"statement": "After Brexit, UK businesses can now export to the EU with no additional paperwork or checks.", "answer": false, "explain": "FALSE. Since January 2021, UK exports to the EU require additional documentation, health certificates, and border checks. Some businesses have had to stop exporting to the EU entirely due to these increased costs."}, {"statement": "The principle ''think global, act local'' means a business should sell identical products in every country without any adaptations.", "answer": false, "explain": "FALSE. ''Think global, act local'' means maintaining a consistent global brand identity while ADAPTING the message, products, or promotions to suit local cultures, religions, and income levels in each market."}]}, "misc": {"enabled": true, "items": [{"myth": "A business that sells products to customers abroad is automatically a multinational company.", "truth": "A multinational company must OPERATE in more than one country — having physical facilities, staff, or offices there. Simply exporting goods abroad does not make a business a multinational. The examiner''s report specifically warned against this confusion.", "check": {"question": "Does selling products to customers abroad automatically make a business a multinational?", "options": ["Yes — any business that exports goods abroad is automatically a multinational", "Yes — but only if the business sells to more than ten different countries", "No — a multinational must physically operate in more than one country", "No — but only because multinationals are not allowed to export goods"], "answer": 2, "explain": "The card explains a multinational must OPERATE in more than one country with facilities or staff — simply exporting goods abroad does not make a business a multinational."}}, {"myth": "International branding, international trade, and multinational company all mean the same thing.", "truth": "These are three completely different concepts. International branding = creating a consistent brand image across countries. International trade = buying/selling across borders. Multinational company = physically operating in multiple countries. Confusing them will cost marks in every question.", "check": {"question": "Are international branding, international trade, and multinational company the same concept?", "options": ["Yes — but only international trade and branding are the same thing", "No — they are three completely different business concepts entirely", "No — but only multinational and international trade mean the same thing", "Yes — all three terms describe exactly the same business activity"], "answer": 1, "explain": "The card explains these are three completely different concepts — branding is image, trade is buying/selling, and multinational means physically operating abroad."}}, {"myth": "A tariff and a quota are the same type of trade barrier.", "truth": "A tariff is a TAX on imported goods, making them more expensive. A quota is a LIMIT on the quantity or value of goods that can be imported. They are different tools with different mechanisms.", "check": {"question": "What is the key difference between a tariff and a quota?", "options": ["A tariff and a quota are simply two different names for the same tool", "A quota is a tax on imports, while a tariff is a limit on import quantity", "A tariff only applies to exports, while a quota only applies to imports", "A tariff is a tax on imports, while a quota is a limit on import quantity"], "answer": 3, "explain": "The card explains a tariff is a TAX on imported goods, while a quota is a LIMIT on the quantity or value that can be imported — different tools entirely."}}, {"myth": "When the pound strengthens, UK exports become cheaper and more competitive abroad.", "truth": "When the pound STRENGTHENS, exports become MORE EXPENSIVE (dearer) for foreign buyers — reducing competitiveness. Use SPICED: Strong Pound → Imports Cheaper, Exports Dearer. A WEAK pound makes exports cheaper.", "check": {"question": "What actually happens to UK exports when the pound strengthens?", "options": ["Exports are completely unaffected by any change in the exchange rate", "Exports automatically double in price whenever the pound strengthens", "Exports become cheaper and more competitive abroad instantly", "Exports become more expensive and less competitive abroad"], "answer": 3, "explain": "The card corrects the misconception that a strong pound helps exports — SPICED shows a strong pound makes exports DEARER, reducing competitiveness abroad."}}, {"myth": "Globalisation only benefits businesses — host countries always lose out.", "truth": "Globalisation brings mixed effects to host countries. Benefits include jobs, tax revenue, and access to cheaper goods. Drawbacks include profit repatriation, local business closures, and potential exploitation of lower standards.", "check": {"question": "Does globalisation only benefit businesses, with host countries always losing out?", "options": ["No — but only because globalisation never actually affects host countries", "No — host countries gain jobs and tax revenue, but also face some drawbacks", "Yes — host countries never gain any benefit at all from globalisation", "Yes — but only multinational businesses ever lose out from globalisation"], "answer": 1, "explain": "The card explains globalisation brings mixed effects to host countries — benefits like jobs and tax revenue, alongside drawbacks like profit repatriation."}}, {"myth": "International branding simply means advertising your product abroad.", "truth": "International branding involves creating a consistent brand identity (image, values, logo) that is recognised across multiple countries, taking into account cultural, religious, language, and legal differences in each market.", "check": {"question": "Does international branding simply mean advertising your product abroad?", "options": ["Yes — but only if the advertising uses the exact same language everywhere", "Yes — international branding and advertising abroad are exactly the same thing", "No — but only because branding never involves any advertising at all", "No — it means creating a consistent brand identity recognised across countries"], "answer": 3, "explain": "The card explains international branding involves creating a consistent identity across countries, considering cultural, religious, language and legal differences."}}, {"myth": "A weaker pound always benefits UK businesses by making everything cheaper.", "truth": "A weaker pound makes UK EXPORTS cheaper for overseas buyers (good for exporters) but makes IMPORTS more expensive for UK businesses (bad for importers). The effect depends on whether the business mainly exports or imports.", "check": {"question": "Does a weaker pound always benefit UK businesses by making everything cheaper?", "options": ["No — but only because a weaker pound never actually affects exporters", "No — it helps exporters but makes imports more expensive for importers", "Yes — a weaker pound always benefits every single UK business equally", "Yes — but only because a weaker pound has no effect on imports at all"], "answer": 1, "explain": "The card explains a weaker pound makes exports cheaper (good for exporters) but makes imports more expensive (bad for importers) — the effect depends on the business."}}, {"myth": "Businesses should always move production abroad because it is always cheaper.", "truth": "Moving abroad reduces labour costs but brings drawbacks: quality control difficulties, communication problems due to language and time zones, rising foreign wages, and consumer preference for ''Made in Britain''. The decision must weigh up all factors.", "check": {"question": "Should businesses always move production abroad because it is always cheaper?", "options": ["Yes — moving production abroad is always cheaper with absolutely no drawbacks", "No — but only because foreign wages are always higher than UK wages", "Yes — but only because quality control is always easier when producing abroad", "No — moving abroad brings drawbacks like quality control and communication issues"], "answer": 3, "explain": "The card explains moving abroad reduces labour costs but brings drawbacks like quality control, communication problems, rising foreign wages, and consumer preference."}}, {"myth": "Globalisation is only about trade in physical goods between countries.", "truth": "Globalisation involves three key flows: TRADE (goods and services), PEOPLE (migration of workers), and CAPITAL (movement of money and physical assets like machines and buildings). It is far broader than just importing and exporting goods.", "check": {"question": "Is globalisation only about trade in physical goods between countries?", "options": ["Yes — but only capital movement counts as part of globalisation too", "Yes — globalisation only ever involves the trade of physical goods", "No — it also involves the movement of people and capital, not just goods", "No — but only because physical goods are never traded internationally"], "answer": 2, "explain": "The card explains globalisation involves three flows — trade, people, and capital — and is far broader than just importing and exporting physical goods."}}, {"myth": "''Think global, act local'' means selling the same product at the same price everywhere.", "truth": "''Think global, act local'' means maintaining the same core brand VALUES worldwide, but adapting the product, price, promotion, and sometimes even the name to suit local cultures, incomes, religions, and legal requirements in each country.", "check": {"question": "Does ''think global, act local'' mean selling the same product at the same price everywhere?", "options": ["No — but only because branding never needs to adapt to different countries", "Yes — the product and price must be kept identical in every single country", "No — it means keeping core brand values, while adapting locally to each market", "Yes — but only the price needs to stay the same in every single country"], "answer": 2, "explain": "The card explains ''think global, act local'' means maintaining core brand values worldwide while adapting product, price and promotion to local cultures and incomes."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation, no examples, no paragraphs. For a 2-mark <strong>''Explain''</strong> question, add one sentence explaining <em>why</em> — nothing more.</p>\n\n      <p><strong>The Formula (1 mark):</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague, general point = 0 marks ❌</li>\n      </ul>\n\n      <p><strong>The Formula (2 marks):</strong></p>\n      <ul>\n        <li>Make a point (1) + Explain how it works (1)</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Identify a reason why a UK business might locate in another country\" (0 marks):</strong><br/>\n      <em>\"More customers.\"</em><br/>\n      This is a marketing answer, not a location answer. You can gain more customers without moving abroad.</p>\n\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Lower labour costs in the host country.\"</em><br/>\n      This is specific to location — it explains WHY a business would physically move operations.</p>\n\n      <p><strong>❌ Bad Answer — \"Explain one advantage of operating as a multinational\" (0 marks):</strong><br/>\n      <em>\"A multinational can sell to more people and make more money.\"</em><br/>\n      Any business can sell abroad without being a multinational. This doesn''t explain what''s special about operating in multiple countries.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"A multinational can spread its risk across different markets (1). This means that if consumer spending falls in one country, the business can rely on income from other countries to protect overall profits (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> On this paper, many students lost marks on the ''identify two factors that led to increased globalisation'' question by listing the same factor twice in different words (e.g., \"the internet\" and \"e-commerce\" and \"online banking\" — these are all the same thing and count as one answer). Make sure your two factors are genuinely different.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a paragraph about everything you know about globalisation when asked to simply identify a factor. You will waste time and score the same mark as someone who wrote two words.</p>\n    ", "check": {"question": "According to this card, what mistake did many students make on the ''identify two factors'' question?", "options": ["They gave a factor that was completely unrelated to globalisation entirely", "They wrote far too little detail for a question that was actually worth two whole marks", "They forgot to identify any factor relating to globalisation at all", "They listed the same factor twice using different words, such as internet and e-commerce"], "answer": 3, "explain": "The card warns students lost marks by listing the same factor twice in different words, like ''the internet'' and ''e-commerce'' — the two factors must be genuinely different."}}, {"title": "Show Your Working. Every Single Time.", "html": "\n      <p>Calculation questions in globalisation topics are usually straightforward — but students regularly drop marks by not showing their working. Even if your final answer is wrong, you can still earn the mark if your method is correct.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>Write the calculation clearly: e.g., <strong>500,000 × 80/100</strong></li>\n        <li>Write the final answer with the correct unit: e.g., <strong>400,000 tyres</strong></li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"400,000\"</em><br/>\n      No working shown. If the examiner can''t see your method, they can''t award a method mark.</p>\n\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>500,000 × 80/100 = <strong>400,000 tyres</strong></em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> For percentage questions, always convert the percentage properly. 80% means 80 divided by 100 — not 80 divided by 10. A common mistake is dividing by the wrong number.</p>\n\n      <p><strong>💡 Tip:</strong> Always include the unit in your answer (e.g., \"tyres\", \"£\", \"%\"). Examiners appreciate precision and it shows you understood the question.</p>\n    ", "check": {"question": "According to this card, why is it important to show your working in a calculation question?", "options": ["You can still earn the mark for a correct method even if the final answer is wrong", "Working is only required for calculations involving percentages, not other sums", "The examiner only ever looks at the final numerical answer given, not the method", "Showing your working automatically doubles the marks available for the question"], "answer": 0, "explain": "The card explains that showing your working lets you earn a method mark even if the final answer is wrong — no working shown means no method mark is available."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>Every single 3-mark analyse question in Business Studies follows the same pattern. Master this structure and you will pick up marks consistently across the whole exam.</p>\n\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — U (Understanding):</strong> State the advantage, disadvantage, or impact using business terminology.</li>\n        <li><strong>Step 2 — APP (Application):</strong> Quote or refer directly to the specific business in the case study. Use their name, a figure, or a detail from the text.</li>\n        <li><strong>Step 3 — AN (Analysis):</strong> State the financial or operational consequence for the business. Think: costs, revenue, profit, efficiency, market share, share price, dividends.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Analyse an advantage of AZ operating as a multinational\" (1 mark max):</strong><br/>\n      <em>\"AZ can make more money because it sells to more people.\"</em><br/>\n      This is vague, has no case study detail, and any business can sell to more people without being a multinational.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"One advantage is that AZ is able to access a larger pool of skilled workers in different countries (U). AZ has approximately 75,000 employees worldwide across its three research and development centres (APP). This means AZ can attract the best scientific talent globally, leading to more innovative treatments and higher profits in the long run (AN).\"</em></p>\n\n      <p><strong>🚫 Critical Warning — Being a Multinational ≠ Just Selling Abroad:</strong><br/>\n      The examiner''s report on this paper specifically stated: <em>\"Being a multinational is more than just being able to sell abroad. Any business can sell to more countries without being a multinational.\"</em> What makes an MNC special is that it physically OPERATES in multiple countries — so your advantages must reflect this: lower costs in host countries, access to local labour, spreading risk, dealing with different tax regimes.</p>\n\n      <p><strong>💡 The \"So What?\" Rule for Analysis:</strong><br/>\n      Keep asking yourself \"So what?\" until you hit a bottom-line business impact.</p>\n      <ul>\n        <li>\"AZ operates in over 100 countries.\" → So what?</li>\n        <li>\"They can sell more medicines.\" → So what?</li>\n        <li>\"This increases total revenue and allows AZ to reinvest profits into developing new treatments.\" ✅ <strong>This is AN.</strong></li>\n      </ul>\n\n      <p><strong>Sentence Starters to Use:</strong></p>\n      <ul>\n        <li><strong>APP:</strong> \"Because the text states that AZ operates in over 100 countries...\" / \"In the case of AZ, with 75,000 employees worldwide...\"</li>\n        <li><strong>AN:</strong> \"This will lead to...\" / \"As a result, the business will...\" / \"This reduces costs, meaning profit margins improve...\"</li>\n      </ul>\n    ", "check": {"question": "According to this card, what makes a multinational company special, beyond just selling abroad?", "options": ["It only ever sells its products in one single foreign country outside its own home market entirely", "It physically operates in multiple countries, such as through lower costs and access to labour", "It refuses to sell any of its products in its own home country at all", "It is legally prevented from paying any tax in any country it operates in"], "answer": 1, "explain": "The card''s examiner warning states being a multinational means physically OPERATING in multiple countries — not just being able to sell abroad like any business."}}, {"title": "Just Do the 3-Mark Formula Twice", "html": "\n      <p>A 6-mark ''Analyse two impacts'' question is simply a <strong>3-mark question done twice</strong>. There are no evaluation marks here — do not write a conclusion or recommendation. You will score zero for it and waste precious time.</p>\n\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Impact 1:</strong> U → APP → AN (3 marks)</li>\n        <li><strong>Impact 2:</strong> U → APP → AN (3 marks)</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Analyse two benefits to Virgin Atlantic of developing an international brand\" (2 marks max):</strong><br/>\n      <em>\"International branding helps Virgin Atlantic get more customers and make more money. It also means people trust the brand more.\"</em><br/>\n      There is no case study detail and no clear business-facing consequence. This scores at most 1 mark per impact.</p>\n\n      <p><strong>✅ Good Answer — Impact 1 (3 marks):</strong><br/>\n      <em>\"International branding creates a consistent message that is recognised across many markets (U). Virgin Atlantic flies to destinations around the world and has pursued growth and international branding since its launch in 1984 (APP). This means that customers globally associate Virgin with quality service, leading to more flight bookings and higher revenue for the business (AN).\"</em></p>\n\n      <p><strong>✅ Good Answer — Impact 2 (3 marks):</strong><br/>\n      <em>\"An international brand can reduce the marketing costs of operating globally (U). Because Virgin Atlantic already has a globally recognised brand identity, it can use the same advertising campaigns across all the countries it flies to (APP). This avoids the need to develop separate campaigns for each market, reducing overall costs and improving profit margins (AN).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> The most common mistake in 6-mark questions is repeating the same impact twice with slightly different words (e.g., ''more sales'' and ''more customers'' — this is the same point). Make sure your two impacts are genuinely different.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT spend half your answer defining what international branding is. The examiner already knows. Use that time to apply it to the specific business and analyse the impact.</p>\n\n      <p><strong>💡 Tip — Impacts can be negative too:</strong> For questions like \"Analyse two impacts of globalisation on JLR\", you can use one positive and one negative impact. This shows balanced thinking and is perfectly acceptable.</p>\n    ", "check": {"question": "According to this card, should a 6-mark ''analyse two impacts'' answer include a conclusion?", "options": ["No — but only because the question does not require two separate impacts", "Yes — a strong conclusion is worth one of the six marks that are available", "Yes — without a conclusion the answer cannot be marked by the examiner at all", "No — there are no evaluation marks, so a conclusion wastes time and scores zero"], "answer": 3, "explain": "The card warns there are no evaluation marks in a 6-mark question — writing a conclusion wastes time and scores zero, since it is simply the 3-mark formula done twice."}}, {"title": "Define the Term Precisely — Not Vaguely", "html": "\n      <p>A 2-mark ''State what is meant by'' question wants a <strong>clear, complete definition</strong>. It must include both key parts of the concept — not just one half of it.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Part 1 (1 mark):</strong> The core idea or feature of the term.</li>\n        <li><strong>Part 2 (1 mark):</strong> The full scope — e.g., where it happens, who it involves, what it leads to.</li>\n      </ul>\n\n      <p><strong>The Classic Trap — International Branding:</strong><br/>\n      The examiner''s report on this paper stated this was <em>\"not well understood by most candidates\"</em> and was frequently confused with being a multinational or international trade. These are <strong>completely different concepts</strong>:</p>\n      <ul>\n        <li><strong>International branding</strong> = creating a recognisable image/identity for a product that is promoted consistently across multiple countries.</li>\n        <li><strong>International trade</strong> = buying and selling goods between countries.</li>\n        <li><strong>Multinational</strong> = a business that operates (has facilities) in more than one country.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"State what is meant by international branding\" (0 marks):</strong><br/>\n      <em>\"When a company sells its products all over the world.\"</em><br/>\n      This is a definition of international trade, not international branding. No marks.</p>\n\n      <p><strong>❌ Partial Answer (1 mark only):</strong><br/>\n      <em>\"When a business creates a brand for its product.\"</em><br/>\n      This only defines ''branding'' — there is nothing ''international'' about it.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"International branding is when a business creates a recognisable image or identity for its product (1) that is then promoted and recognised consistently in countries all around the world (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> This term has a very specific meaning. The examiner will not reward an answer that talks about selling abroad, being a multinational, or expanding internationally — unless it specifically mentions creating a consistent brand image across countries.</p>\n    ", "check": {"question": "According to this card, why did ''international branding'' catch out most candidates?", "options": ["It only ever appears in nine-mark evaluate questions, never anywhere else", "It requires a detailed calculation rather than a written definition", "It was frequently confused with being a multinational or international trade", "It was never actually tested in any real past exam paper at all"], "answer": 2, "explain": "The card cites the examiner''s report stating international branding was ''not well understood'' and frequently confused with being a multinational or international trade."}}, {"title": "APP + AN First, Then Make a Judgement That Uses the Case Study", "html": "\n      <p>A 7-mark evaluate question has three layers of marks: Application (2), Analysis (2), and Evaluation (3). Most students pick up the first four marks without too much difficulty — it''s the <strong>3 evaluation marks</strong> where marks are lost.</p>\n\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — APP + AN:</strong> Benefit/impact 1, linked to the business with a financial consequence.</li>\n        <li><strong>Paragraph 2 — APP + AN:</strong> Benefit/impact 2, linked to the business with a different financial consequence.</li>\n        <li><strong>Paragraph 3 — EVAL (Start):</strong> A clear judgement — state your overall view.</li>\n        <li><strong>Paragraph 4 — EVAL (Develop):</strong> Justify and contextualise — reference the case study evidence to support your judgement. Use \"it depends on...\" or weigh one factor against another.</li>\n      </ul>\n\n      <p><strong>❌ Bad Evaluation (1 mark max):</strong><br/>\n      <em>\"Overall, international branding is very important for Unilever.\"</em><br/>\n      This is a basic decision with no justification. It scores 1 mark at best.</p>\n\n      <p><strong>✅ Good Evaluation (3 marks):</strong><br/>\n      <em>\"Overall, international branding is the most important factor in Unilever''s growth (EVAL) because it allows a consistent campaign to run across all 190 countries they operate in, saving on marketing costs through economies of scale (EVAL). However, the value of this depends on the economic climate — if consumer incomes fall globally, even well-known brands like Persil and Dove may see declining sales as customers switch to cheaper alternatives (EVAL).\"</em></p>\n\n      <p><strong>💡 The \"It Depends On...\" Rule:</strong><br/>\n      The very best evaluation answers don''t just say \"X is important.\" They say: <em>\"X is the most important factor, BUT it depends on [a specific contextual condition].\"</em></p>\n      <ul>\n        <li>\"Globalisation is essential for BP''s location decisions, but it depends on whether the global oil price remains high enough to justify the cost of operating rigs in Norway and Angola.\"</li>\n        <li>\"International branding is vital for Unilever, but its impact depends on whether the difficult economic climate suppresses consumer spending worldwide.\"</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> On this paper, the examiner noted that many evaluation answers simply repeated analysis from earlier paragraphs. <em>Repeating analysis is NOT evaluation.</em> Evaluation must add something new — a judgement, a condition, a weighing of factors.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT open a 7-mark evaluate question with a long definition of globalisation or international branding. There are <strong>zero knowledge marks</strong> in a pure evaluate question. Go straight to APP and AN.</p>\n\n      <p><strong>Sentence Starters for Evaluation:</strong></p>\n      <ul>\n        <li>\"Overall, I believe that... because...\"</li>\n        <li>\"The most significant factor is... because it directly affects...\"</li>\n        <li>\"However, this depends entirely on whether...\"</li>\n        <li>\"In the context of [business name], this is particularly important because...\"</li>\n      </ul>\n    ", "check": {"question": "According to this card, why does simply repeating earlier analysis not count as evaluation?", "options": ["Evaluation must add something new — a judgement, condition, or weighing of factors", "Repeating analysis is actually the correct way to score all three evaluation marks", "There are no evaluation marks available at all in a seven-mark question", "Evaluation marks are awarded automatically regardless of what is actually written"], "answer": 0, "explain": "The card warns repeating analysis is NOT evaluation — evaluation must add something new, such as a judgement, a condition, or weighing factors against each other."}}, {"title": "Knowledge + Balanced Analysis + A Contextual Verdict", "html": "\n      <p>A 9-mark evaluate question is the most demanding question type. It tests all five assessment objectives: K, U, APP, AN, and EVAL. You must cover <strong>both sides</strong> (risk AND reward, or advantage AND disadvantage) and reach a clear, justified verdict that uses the case study.</p>\n\n      <p><strong>The Mark Split to Remember:</strong></p>\n      <ul>\n        <li>Knowledge (1) + Understanding (1) + Application (2) + Analysis (2) + Evaluation (3) = 9</li>\n      </ul>\n\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K + U:</strong> Define the key concept (e.g., globalisation) and explain what it involves. Keep this brief — 2 sentences maximum.</li>\n        <li><strong>Paragraph 2 — APP + AN (Reward/Advantage):</strong> One clear benefit, linked to the business, with a financial/operational consequence for shareholders.</li>\n        <li><strong>Paragraph 3 — APP + AN (Risk/Disadvantage):</strong> One clear risk, linked to the business, with a financial/operational consequence for shareholders.</li>\n        <li><strong>Paragraph 4 — EVAL × 3:</strong> A clear overall judgement, justified with case study context, and a condition that could change your verdict.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (3 marks max):</strong><br/>\n      <em>\"Globalisation is when businesses operate around the world. Aston Martin can sell to more countries, which means more profit. But it also faces more competition. Overall globalisation is good for Aston Martin.\"</em><br/>\n      No case study detail, no financial consequences, and the evaluation is just a basic statement.</p>\n\n      <p><strong>✅ Good Answer — Paragraph structure (approaching full marks):</strong></p>\n      <ul>\n        <li><strong>K+U:</strong> \"Globalisation is the process of interaction and integration between businesses, governments and people worldwide. It involves the increasing movement of goods, capital and labour across national borders.\"</li>\n        <li><strong>APP+AN (Reward):</strong> \"One reward for AM plc''s shareholders is that globalisation has allowed AM plc to open 150 dealerships in over 50 countries across six continents (APP). With a larger global customer base, revenue from car sales can increase significantly, leading to higher profits and potentially higher dividends paid to shareholders (AN).\"</li>\n        <li><strong>APP+AN (Risk):</strong> \"However, globalisation also creates risk. AM plc relies on a globalised supply chain with suppliers from the UK, EU and across the world (APP). If a supplier in another country experiences disruption — for example due to political instability or exchange rate fluctuations — production could be delayed, increasing costs and reducing profit margins, which would lower the dividends shareholders receive (AN).\"</li>\n        <li><strong>EVAL:</strong> \"Overall, the rewards of globalisation are likely to outweigh the risks for AM plc''s shareholders (EVAL), because the global demand for luxury sports cars is growing and AM plc''s strong brand identity across 50+ countries gives it a competitive advantage in premium markets (EVAL). However, this depends on whether exchange rate movements make AM plc''s cars more expensive abroad — if sterling strengthens, exports become pricier and international sales could fall, directly reducing shareholder dividends (EVAL).\"</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Always link analysis to the <strong>shareholders specifically</strong> — not just ''the business''. Shareholders care about: dividends, share price, return on investment, and financial risk. Make sure your consequences reference at least one of these.</p>\n\n      <p><strong>💡 The Contextual Evaluation Rule:</strong> To earn all 3 evaluation marks, your judgement must reference specific detail from the case study. A general statement like \"globalisation is mostly beneficial\" only scores 1 mark. A contextual verdict using the bar charts, specific figures, or named products earns all 3.</p>\n    ", "check": {"question": "According to this card, who must the analysis in a 9-mark question specifically link to?", "options": ["Suppliers specifically, referencing only the length of their payment terms", "Competitors specifically, referencing their exact market share percentage figures", "Shareholders specifically, referencing dividends, share price or investment return", "The general public, with no reference at all to any particular stakeholder"], "answer": 2, "explain": "The card''s examiner warning states analysis must link to shareholders specifically — dividends, share price, return on investment, and financial risk."}}, {"title": "Judgement First, Then Justify Using the Case Study", "html": "\n      <p>A 3-mark ''Recommend'' question follows a clear pattern: <strong>make a decision, justify it, and use the case study</strong>. These marks are very accessible if you stick to the structure — but many students lose 2 out of 3 by giving a vague, unsupported recommendation.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>1 mark:</strong> A clear recommendation (yes/no, continue/stop, option A/B).</li>\n        <li><strong>+ 1 mark:</strong> A reason WHY — with no case study detail needed.</li>\n        <li><strong>+ 1 mark (or replaces above):</strong> A contextual justification — use a specific fact, figure, or detail from the case study.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Recommend whether AZ should continue to operate as a multinational\" (1 mark):</strong><br/>\n      <em>\"Yes, AZ should continue as a multinational because it is a good idea.\"</em><br/>\n      There is no justification and no case study detail.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"AZ should continue to operate as a multinational (1). Without global operations, AZ would be unable to generate the profits needed to fund its research (1). This is particularly important as AZ has three research and development centres and 10,000 staff working to develop new treatments — all of which require significant ongoing investment (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> On this paper, the examiner noted that most candidates correctly said AZ should continue as a multinational, but many failed to justify it with case study context. Always find at least one specific detail from the text to support your recommendation.</p>\n\n      <p><strong>💡 Tip — You don''t always have to recommend \"yes\":</strong> If there is a strong case for the opposite view, argue it — as long as you can justify it with context. Examiners award marks for the quality of justification, not for picking the \"right\" side.</p>\n\n      <p><strong>Sentence Starters:</strong></p>\n      <ul>\n        <li>\"[Business] should [recommendation] because...\"</li>\n        <li>\"Without this, [business] would be unable to...\"</li>\n        <li>\"This is supported by the fact that the case study states...\"</li>\n      </ul>\n    ", "check": {"question": "According to this card, why do many students lose 2 out of 3 marks on recommend questions?", "options": ["They give a vague recommendation without any case study justification", "They give two separate recommendations instead of committing to just one", "They spend too much time defining every key term before making a decision", "They recommend an option that is not mentioned anywhere in the question"], "answer": 0, "explain": "The card explains most candidates give a vague recommendation without case study context, losing marks despite correctly identifying the right answer."}}, {"title": "Eliminate First. Don''t Rush. Watch the ''NOT'' Questions.", "html": "\n      <p>Multiple choice questions on globalisation are worth just 1 mark each — but students regularly drop them through careless reading. The most dangerous word in an MCQ is <strong>NOT</strong>.</p>\n\n      <p><strong>The Strategy:</strong></p>\n      <ul>\n        <li><strong>Step 1:</strong> Read the question stem carefully. Underline key words like \"NOT\", \"most likely\", \"best describes\".</li>\n        <li><strong>Step 2:</strong> Eliminate the options you''re certain are wrong.</li>\n        <li><strong>Step 3:</strong> Choose from what remains — don''t second-guess yourself.</li>\n      </ul>\n\n      <p><strong>⚠️ The \"NOT\" Trap:</strong><br/>\n      Q1 on this paper asked: <em>\"What has NOT contributed to increased globalisation?\"</em><br/>\n      Many students chose options A, B or D because they are true statements about globalisation — but the question asked for what has NOT contributed. The answer is C (trade restrictions) because restrictions <em>block</em> globalisation.</p>\n\n      <p><strong>⚠️ The Terminology Trap:</strong><br/>\n      Questions on this paper tested whether students could distinguish between very similar terms:</p>\n      <ul>\n        <li><strong>Globalisation</strong> = the interconnected nature of business activities across the world.</li>\n        <li><strong>International branding</strong> = creating a consistent brand image across countries — requires taking account of <em>cultural differences</em>.</li>\n        <li><strong>Multinational organisation</strong> = a business that <em>operates</em> in several countries.</li>\n      </ul>\n\n      <p><strong>❌ Common MCQ Mistake:</strong><br/>\n      Confusing ''international branding'' (requires cultural awareness — Answer D) with ''selling goods in every country'' (Answer C). A brand can be international without selling everywhere — but it always requires sensitivity to local culture.</p>\n\n      <p><strong>💡 Final Tip:</strong> If you are unsure between two answers, re-read the question one more time and pick the answer that most precisely matches the exact wording. Never leave an MCQ blank — there is no negative marking.</p>\n    ", "check": {"question": "According to this card, why is the word ''NOT'' so dangerous in an MCQ question stem?", "options": ["The word ''NOT'' means the question has no correct answer among the options given", "Students may pick a true statement about the topic instead of answering what was NOT asked", "The word ''NOT'' automatically makes every single answer option in the question incorrect", "Questions containing the word ''NOT'' are always worth double the normal marks"], "answer": 1, "explain": "The card''s example shows students chose true statements about globalisation instead of correctly identifying the option that had NOT contributed to it."}}, {"title": "The Four Concepts Students Constantly Confuse", "html": "\n      <p>The examiner''s report on this paper explicitly stated that students regularly confused four key globalisation concepts. <strong>These are not the same thing.</strong> Using one term when you mean another will cost you marks across every question type.</p>\n\n      <p><strong>The Four Concepts — Know the Difference:</strong></p>\n      <ul>\n        <li><strong>Globalisation:</strong> The process by which businesses, governments, and people become increasingly interconnected and interdependent across the world. It is driven by improvements in technology, transport, and trade agreements.</li>\n\n        <li><strong>International Trade:</strong> The buying and selling of goods and services between countries. A small local business can participate in international trade without being a multinational or having an international brand.</li>\n\n        <li><strong>International Branding:</strong> Creating a consistent image, logo, or identity for a product that is recognised and promoted across multiple countries. It requires taking account of cultural and religious differences in each market.</li>\n\n        <li><strong>Multinational Company (MNC):</strong> A business that physically OPERATES in more than one country — not just sells there. This means having factories, offices, staff, or facilities in other countries.</li>\n      </ul>\n\n      <p><strong>❌ Classic Confusion (costs marks in EVERY question):</strong><br/>\n      <em>\"Unilever is an international brand because it sells products in 190 countries.\"</em><br/>\n      Selling in 190 countries makes Unilever a multinational. The international BRAND part is about the consistent logo/image (Dove, Lynx, Persil) that is recognised in those countries.</p>\n\n      <p><strong>✅ Correct Distinction:</strong><br/>\n      <em>\"Unilever is a multinational company that uses international branding — products like Persil and Dove have a consistent image that is recognised worldwide, helping build customer loyalty across all 190 markets.\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> The examiner''s report on this paper specifically said: <em>\"International branding, international trade, international marketing, and multinational companies are not inter-changeable terms. This confusion has been seen from many candidates. Centres need to ensure that these are understood as clearly separate concepts.\"</em></p>\n\n      <p><strong>💡 Quick Test — Can You Answer These?</strong></p>\n      <ul>\n        <li>Can a business trade internationally without being a multinational? <strong>YES</strong> — it just sells abroad.</li>\n        <li>Can a multinational exist without an international brand? <strong>YES</strong> — it could operate different brands in different countries.</li>\n        <li>Does international branding require selling in every country? <strong>NO</strong> — just a consistent brand across the countries where it does operate.</li>\n      </ul>\n    ", "check": {"question": "According to this card, what is the classic confusion the examiner''s report warned about?", "options": ["Calling Unilever an ''exporter'' simply because it operates factories abroad", "Calling Unilever an ''international brand'' simply because it sells in 190 countries", "Calling Unilever a ''host country'' simply because it sells in many countries", "Calling Unilever a ''multinational'' simply because it has a recognised brand image"], "answer": 1, "explain": "The card explains selling in 190 countries makes Unilever a multinational — the international BRAND is specifically about the consistent logo/image recognised there."}}]}, "exam": {"enabled": true, "questions": [{"question": "What has <strong>not</strong> contributed to increased globalisation?", "marks": 1, "hint": "Think about what factors INCREASE globalisation — the answer is the option that REDUCES or BLOCKS it, not enables it.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Restrictions on international trade</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A is wrong</strong> — A reduction in shipping costs through bulk containerisation made it cheaper to transport goods across the world, directly contributing to increased globalisation.</li><li><strong>B is wrong</strong> — An increase in labour migration means more workers moving between countries, which is a defining feature of globalisation, not a barrier to it.</li><li><strong>D is wrong</strong> — The internet and mobile communication technologies have massively increased the speed and ease of global communication, enabling businesses to operate internationally and driving globalisation.</li></ul></div>"}, {"question": "State what is meant by international branding. [2 marks]", "marks": 2, "hint": "Think about what a ''brand'' is (a logo, image, or name) and then add what ''international'' means in this context. You need BOTH parts for 2 marks. Do not confuse this with being a multinational company or international trade.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a = 2 marks)</h5><ul><li><strong>2 marks:</strong> A clear, full definition — e.g., \"Creating an image for a product (1) that is then communicated in countries all around the world (1)\"</li><li><strong>1 mark:</strong> A partial definition — e.g., a definition of branding only, or international marketing only</li><li><strong>0 marks:</strong> A definition solely about international trade or being a multinational</li></ul><p>Answers do not need to relate to Unilever.</p></div><div class=\"marks-section\"><h5>Acceptable Answers include:</h5><ul><li>Creating an image for a product (1) that is then communicated in countries all around the world (1)</li><li>A recognisable brand (1) that is known worldwide (1)</li><li>Having a logo (1) which is recognised around the globe (1)</li><li>Promoting your product all over the world (1)</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>This term was not well understood by most candidates. It was often confused with ''international marketing'' and many answers suggested it was the same as being a multinational or partaking in international trade. International branding has a very specific meaning — it is about creating a consistent brand image recognised across the world — which was largely misunderstood.</p><p><strong>Misconception:</strong> International branding, international trade, international marketing, and multinational companies are NOT interchangeable terms.</p></div>"}, {"question": "Evaluate the benefits of international branding to Unilever plc. [7 marks]", "marks": 7, "hint": "Start by explaining a benefit of international branding (not just being a multinational), then apply it using Unilever''s specific products or countries from the case study, then evaluate by judging how important it really is. Remember: international branding ≠ international trade ≠ multinational.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 + AO3a + AO3b = 7 marks)</h5><ul><li><strong>Application (up to 2 marks):</strong> Uses context from the Unilever case study in relation to the benefits of international branding [APP][APP]</li><li><strong>Analysis (up to 2 marks):</strong> Two different business-facing benefits of international branding [AN][AN]</li><li><strong>Evaluation (up to 3 marks):</strong> A justified contextual judgement about the benefits to Unilever of international branding [EVAL][EVAL][EVAL]</li></ul><p><strong>NB:</strong> Context must be used to be awarded as application. Analysis must be business-facing. For full evaluation (3 marks), evaluation must be contextual. No reward for answers about being a multinational. No reward for disadvantages unless part of evaluation.</p></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>Multinational company; 190 countries</li><li>Products include Lynx, Dove, Hellmann''s, Ben &amp; Jerry''s, Persil</li><li>Sells a wide range of quality products</li><li>Factories around the globe</li><li>Economic climate is difficult</li><li>Worldwide revenue high and increasing since 2020</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Operating in many more countries may increase sales / profits</li><li>Develop a global brand that is recognisable in every country to build customer loyalty or increase sales / profits</li><li>Allows development of a larger range of products</li><li>The brand / reputation can provide a competitive advantage</li><li>More businesses may want to set up partnerships or joint ventures</li><li>Able to focus on countries where the economy is strong at that time</li></ul></div><div class=\"marks-section\"><h5>Evaluation may include:</h5><ul><li>The particular importance of international branding for a global business like Unilever</li><li>Despite strong international brands, if consumer incomes reduce around the world, Unilever profit levels will go down and lead to cost cutting such as redundancies</li><li>Having strong international brands is very important to Unilever''s growth in terms of sales/profit but so is the range and quality of products they provide</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Many candidates gained only 2 or 3 marks, often wrongly referring to the benefits of being an MNC or confusing international branding with international trade. Some repeated analytical comments such as ''leads to higher sales'' rather than developing further. Application was noticeably weak. Better answers included two benefits with case study context, plus a clear evaluative judgement that was applied to Unilever specifically.</p></div>"}, {"question": "Globalisation refers to:", "marks": 1, "hint": "Think about what ''global'' means — it is about the whole world and how businesses, people, and economies connect across international borders.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — the interconnected nature of business activities across the world</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A is wrong</strong> — Financial data refers to performance measurement within a business; it has no connection to the definition of globalisation.</li><li><strong>C is wrong</strong> — Interdependencies in decision-making refers to internal organisational management within a single large company, not cross-border global activity.</li><li><strong>D is wrong</strong> — The relationships between functional areas (e.g. marketing and finance) is an internal business concept and has nothing to do with globalisation or international trade.</li></ul></div>"}, {"question": "Analyse one advantage and one disadvantage to AZ of operating as a multinational company. [6 marks]", "marks": 6, "hint": "For each point: (1) State the advantage/disadvantage clearly, (2) Apply it using AZ''s details from the case study, (3) Analyse the business impact. Being a multinational is about OPERATING in other countries — not just selling there.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 6 marks)</h5><p>For each of Advantage and Disadvantage:</p><ul><li><strong>1 mark:</strong> Understanding of a possible advantage/disadvantage of operating as a multinational</li><li><strong>+1 mark:</strong> Application of understanding to AZ, using evidence from the text [APP]</li><li><strong>+1 mark:</strong> Analysis of the given advantage/disadvantage for a business [AN]</li></ul><p>No further marks without understanding first. Do not reward answers which consider being an MNC to be only about selling internationally.</p></div><div class=\"marks-section\"><h5>Advantages — Understanding may include:</h5><ul><li>Higher sales (revenue)</li><li>Spread risk</li><li>Access to skilled workers in other countries</li><li>Lower costs — labour / land / technology</li><li>Benefits of competition</li><li>Lower legal or ethical standards in other countries</li></ul></div><div class=\"marks-section\"><h5>Advantages — Analysis may include:</h5><ul><li>Setting up where there is demand for the products making distribution easier</li><li>Higher profits / larger dividends for shareholders</li><li>Higher market share</li><li>More money to invest, making the business more competitive</li><li>Growth of ideas and innovation</li><li>Increased efficiency</li></ul></div><div class=\"marks-section\"><h5>Disadvantages — Understanding may include:</h5><ul><li>Various legal differences / regulatory requirements in each country</li><li>May become too large — difficult to manage</li><li>Transport costs increase when moving products around the globe</li><li>Costs of operating across a large number of countries</li><li>Worldwide opposition to multinational businesses</li><li>Communication difficulties due to language / cultural / time differences</li><li>Will face more competition</li><li>Currency / exchange rate fluctuations</li></ul></div><div class=\"marks-section\"><h5>Disadvantages — Analysis may include:</h5><ul><li>May have an impact on quality control due to co-ordination around the globe</li><li>May lead to decreased profits / margins</li><li>Effect on brand identity while customising the brand message to appeal to local cultures</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Many answers were narrow in scope. Being a multinational is more than just being able to sell abroad — it means operating (not just selling) in more than one country. Advantages should focus on spreading risk, taking advantage of low-cost locations, or benefiting from lower tax levels in a host country. Stronger candidates focused on these operational aspects rather than just ''more customers''.</p></div>"}, {"question": "Recommend whether AZ should continue to operate as a multinational company. [3 marks]", "marks": 3, "hint": "Make a clear judgement first (yes or no). Then justify using specific details from the AstraZeneca case study — e.g., mention the 3 R&D centres, 75,000 employees, or 100+ countries. Just saying ''it increases profit'' without context will not earn the third mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO3b = 3 marks)</h5><ul><li><strong>1 mark:</strong> A basic judgement — whether AZ should or should not continue to operate as a multinational</li><li><strong>+1 mark:</strong> Justification of the judgement with no use of context</li><li><strong>OR +2 marks:</strong> Justification of the judgement with use of context from the case study [APP]</li></ul><p>Further analysis of advantages/disadvantages should not be rewarded but can form part of the candidate''s justification.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>The majority of candidates scored at least 2 marks. Most decided that AZ should continue as a multinational, although this was not always fully justified and often did not include context from the case study.</p></div>"}, {"question": "Identify two reasons why a UK business might choose to locate in another country. [2 marks]", "marks": 2, "hint": "Think about what a business physically GAINS by setting up operations in another country — think costs, labour, materials, and proximity to customers. Do NOT simply say ''more customers'' — the question is about physical location decisions, not sales strategy.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a = 2 marks)</h5><ul><li><strong>1 mark each</strong> for two correct reasons (up to 2 marks total)</li><li>Answers do not need to relate to BP</li><li><strong>No reward</strong> for general answers such as ''more customers'' or ''more business opportunities'' — this is about the firm''s physical location decisions, not marketing</li></ul></div><div class=\"marks-section\"><h5>Acceptable Answers include:</h5><ul><li>Lower costs such as labour, technology, property / land</li><li>Availability of skilled labour</li><li>Proximity to customers / market</li><li>Proximity / availability of raw materials</li><li>Availability of subsidies / grants</li><li>Lower levels of taxation</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Many responses treated location as a marketing concern rather than an operations issue. This led to answers linked to increases in customers and market share, which could be achieved regardless of where a business is physically located.</p></div>"}, {"question": "Evaluate how globalisation has influenced where BP locates its businesses. [7 marks]", "marks": 7, "hint": "Focus on LOCATION — why does globalisation cause BP to physically set up in different countries? Use BP''s specific details (18,700 petrol stations, oil rigs in Norway/Australia/Angola) as your application. There are no marks for simply defining globalisation.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 + AO3a + AO3b = 7 marks)</h5><ul><li><strong>Application (up to 2 marks):</strong> Uses context from the BP case study [APP][APP]</li><li><strong>Analysis (up to 2 marks):</strong> Two business-facing pieces of analysis of how globalisation affects location [AN][AN]</li><li><strong>Evaluation (up to 3 marks):</strong> A justified contextual judgement about how globalisation affects BP''s location using evidence [EVAL][EVAL][EVAL]</li></ul><p><strong>NB:</strong> Context must be used for application marks. Analysis must be business-facing. For full evaluation (3 marks), evaluation must be contextual. Answers must focus on influence on location, not globalisation in general.</p></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>UK-based company</li><li>Sells and distributes products all over the world</li><li>18,700 petrol stations around the world</li><li>Extracts oil using rigs in the sea around UK, Norway, Australia, Angola, the Gulf of Mexico</li><li>Striving to be more sustainable / aims to cut carbon emissions</li><li>Wind farms in America</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Being near customers so they can sell more</li><li>Being near raw materials to keep transport costs down</li><li>Having skilled workers in refineries to save labour costs</li><li>A large multinational can afford to operate in many markets across the globe</li><li>Reduces costs by being where new technology is developed</li></ul></div><div class=\"marks-section\"><h5>Evaluation may include:</h5><ul><li>Globalisation is essential for BP as its raw materials are found all over the globe</li><li>But it costs BP a lot to set up and maintain locations around the globe</li><li>Potential downsides of locating globally (e.g., working conditions, political instability, environmental impact)</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Many candidates knew what globalisation was but wasted time defining it — there are no knowledge/understanding marks in this question. Often, candidates mentioned petrol stations and oil drilling but did not link these to globalisation, meaning application but not analysis marks could be awarded. Few attempted evaluation, and those who did often just considered ''is globalisation important to BP?'' rather than addressing how it has specifically influenced location decisions.</p></div>"}, {"question": "Identify two factors that have led to increased globalisation. [2 marks]", "marks": 2, "hint": "Think about what has made it easier for businesses to operate globally — technology, transport infrastructure, and trade agreements are good areas to consider. Make sure your two factors are genuinely different from each other.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a = 2 marks)</h5><ul><li><strong>1 mark each</strong> for two correct factors (up to 2 marks)</li><li>Answers do not need to apply to Barclays plc</li><li>Specific examples of technology or uses of the Internet (e.g. online spending) are acceptable</li><li><strong>Important:</strong> The two factors must be genuinely different — ''use of the Internet'', ''e-commerce'', and ''online banking'' are the same factor and would only earn 1 mark (REP)</li></ul></div><div class=\"marks-section\"><h5>Acceptable Answers include:</h5><ul><li>Improved technology / telecommunications / Internet / e-commerce</li><li>Improved global infrastructure</li><li>Improvements in transportation / containerisation</li><li>Free trade agreements</li></ul></div>"}, {"question": "Explain one possible advantage to a business of operating as a multinational. [2 marks]", "marks": 2, "hint": "First IDENTIFY the advantage (1 mark), then EXPLAIN why it is an advantage for the business — what does it lead to? (1 mark). Your answer must apply to the business, not to the country it is operating in.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a + AO1b = 2 marks)</h5><ul><li><strong>1 mark:</strong> Identifying an advantage of operating as a multinational</li><li><strong>+1 mark:</strong> Explaining why it is an advantage for the business</li><li>Answers must apply to the business, not to the host country</li><li>No reward for answers that are simply an advantage of a business growing in general</li><li>Answer does not need to apply to Barclays plc</li></ul></div><div class=\"marks-section\"><h5>Acceptable Answers include:</h5><ul><li>The ability to source labour cheaply → helping to maximise profit</li><li>Access to a larger number of customers → leading to increased sales / market share</li><li>Spreading risk by increasing sales in one country if another is in decline</li><li>Taking advantage of different tax regimes → helping to reduce costs / increase retained profit</li></ul></div>"}, {"question": "International branding requires a business to:", "marks": 1, "hint": "Think about what a business must consider to make its brand work successfully across different countries and audiences.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — take account of cultural differences</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A is wrong</strong> — Advertising online is just one communication channel. A business can have a strong international brand without advertising online, and online advertising is not a defining requirement of international branding.</li><li><strong>B is wrong</strong> — Ignoring religious differences would actively damage a brand internationally. Successful international branding requires sensitivity to both cultural AND religious differences, not ignoring them.</li><li><strong>C is wrong</strong> — A business does not need to sell in every single country to develop an international brand. International branding is about creating a consistent global image; a business could operate in just a handful of countries and still have an international brand.</li></ul></div>"}, {"question": "* Evaluate how globalisation may bring risk and reward to the shareholders of AM plc. [9 marks]", "marks": 9, "hint": "Cover BOTH risk AND reward and link them specifically to AM plc''s shareholders (think: dividends, share price, profits). Use the bar chart data and case study details in your evaluation. Finish with a clear overall judgement — does reward outweigh risk or vice versa?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a + AO1b + AO2 + AO3a + AO3b = 9 marks)</h5><ul><li><strong>Knowledge (1 mark):</strong> Definition/explanation of globalisation [K]</li><li><strong>Understanding (1 mark):</strong> An aspect of how globalisation operates [U]</li><li><strong>Application (up to 2 marks):</strong> Synoptic application using context from the AM plc case study [APP][APP]</li><li><strong>Analysis (up to 2 marks):</strong> Business-facing impacts specifically for shareholders of AM plc [AN][AN]</li><li><strong>Evaluation (up to 3 marks):</strong> A justified contextual judgement about whether risk or reward is greater for shareholders [EVAL][EVAL][EVAL]</li></ul><p>For full evaluation (3 marks), evaluation must be contextual.</p></div><div class=\"marks-section\"><h5>Knowledge may include:</h5><ul><li>Globalisation is the process of interaction and integration between people, companies, and governments worldwide</li></ul></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>Involves the movement of workers and/or capital from country to country</li><li>Greater dependence on external factors, e.g. exchange rates</li><li>Advances in transportation and communication technology</li><li>Any other examples of how globalisation is found in an economy (e.g. a globalised supply chain)</li></ul></div><div class=\"marks-section\"><h5>Application — Reward may include:</h5><ul><li>More revenue / sales from a larger global market</li><li>Growth of ideas and innovation</li><li>Larger market size — more than 150 dealerships in over 50 countries</li></ul></div><div class=\"marks-section\"><h5>Application — Risk may include:</h5><ul><li>Increased competition from global luxury car manufacturers</li><li>Global brands will have to carefully manage legal, political, cultural and regulatory requirements in each country</li><li>Failure to survive in a highly competitive global marketplace</li></ul></div><div class=\"marks-section\"><h5>Analysis (for shareholders of AM plc) may include:</h5><ul><li>Higher profits / dividends / share price if globalisation brings in more sales</li><li>Higher market share may lead to a higher share price</li><li>Higher sales may mean reducing average cost per car, increasing profitability and hence share price / dividends</li><li>Risks may mean profits decrease, which could decrease share price and dividends</li><li>Maintaining brand identity while customising products / marketing to appeal to local cultures costs money, impacting profitability and share price</li></ul></div><div class=\"marks-section\"><h5>Evaluation may include:</h5><ul><li>The extent to which risk exceeds reward or vice versa for AM plc specifically</li><li>The factors which may determine the balance between risk and reward</li><li>Use of contextual data — e.g., rising consumer income (£30,000 to £32,250) and falling unemployment (7.5% to 4%) suggest growing demand for luxury goods, tipping balance towards reward</li></ul></div>"}, {"question": "Analyse two benefits to Virgin Atlantic of developing an international brand. [6 marks]", "marks": 6, "hint": "For each benefit: (1) Show you understand what the benefit of international branding is, (2) Apply it to Virgin Atlantic using the case study, (3) Analyse the business impact. You need TWO separate, distinct benefits.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 6 marks)</h5><ul><li><strong>1 mark</strong> for understanding of a benefit of international branding (up to 2 marks across both benefits)</li><li><strong>+1 mark</strong> for applying a benefit to Virgin Atlantic using the case study (up to 2 marks)</li><li><strong>+1 mark</strong> for analysis of the benefit''s impact on Virgin Atlantic (up to 2 marks)</li></ul></div><div class=\"marks-section\"><h5>Benefits may include:</h5><ul><li>Consistent message across many markets</li><li>Reduced risk</li><li>Centralised decision making / reduced costs</li><li>Can use global media / global social media platforms</li><li>Builds customer trust and confidence across borders</li></ul></div>"}, {"question": "A company operates in several countries.<br><br>This is an example of:", "marks": 1, "hint": "Think about what we call a business that has operations (not just sales) running in more than one country.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — a multinational organisation</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>B is wrong</strong> — Customer engagement refers to the ways a business interacts with its customers to build loyalty and relationships. It is not related to the geographic scope of a business''s operations.</li><li><strong>C is wrong</strong> — International branding is about creating a recognisable brand image that is promoted consistently across multiple countries. A company can have an international brand without operating in multiple countries, and can operate in multiple countries without a unified international brand.</li><li><strong>D is wrong</strong> — Operations management refers to the internal management of production processes and resources within a business. It does not describe a company operating across multiple countries.</li></ul></div>"}, {"question": "If JLR buys 500,000 tyres and 80% of these are bought from overseas suppliers, calculate the number of tyres JLR buys from overseas. [1 mark]", "marks": 1, "hint": "Multiply the total number of tyres by the percentage bought overseas. You can calculate 80% by doing × 80 ÷ 100, or by multiplying by 0.8.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 1 mark)</h5><ul><li><strong>1 mark</strong> for the correct answer: <strong>400,000</strong></li></ul><p>Working: 500,000 × 80/100 = 400,000</p></div>"}, {"question": "Analyse two impacts of globalisation on JLR. [6 marks]", "marks": 6, "hint": "For each impact: (1) State what the impact of globalisation is, (2) Apply it to JLR using specific details from the case study (e.g. China/Russia/Europe, overseas suppliers, BMW/Mercedes competition), (3) Analyse the effect on JLR as a business. Impacts can be positive or negative.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 6 marks)</h5><ul><li><strong>1 mark</strong> for understanding of an impact of globalisation (up to 2 marks)</li><li><strong>+1 mark</strong> for application of an impact to JLR, using evidence from the case study (up to 2 marks)</li><li><strong>+1 mark</strong> for analysis of the impact on JLR as a business (up to 2 marks)</li><li>Impacts can be positive or negative</li></ul></div><div class=\"marks-section\"><h5>Impacts may include:</h5><ul><li>Larger market size</li><li>Increased competition (e.g. from BMW and Mercedes)</li><li>Increased international trade / movement of goods and services</li><li>Greater movement of people and capital</li><li>More businesses operating in more than one country</li><li>Interdependence of businesses in different countries</li><li>Globalisation of brands</li><li>Greater dependence on external / global factors (e.g. economic conditions in China/Russia)</li></ul></div>"}, {"question": "JLR must consider the impact of globalisation when making business decisions. Recommend which impact of globalisation is most likely to affect JLR? Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Choose ONE impact — the one you think is MOST significant to JLR. Justify your choice using specific details from the case study (e.g. slowdown in China/Russia, increase in Europe, overseas suppliers). A judgement without context will not earn the third mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO3b = 3 marks)</h5><ul><li><strong>1 mark:</strong> A judgement with limited justification showing some appraisal of relevant information or issues</li><li><strong>2 marks:</strong> A judgement with good justification showing appraisal of relevant information and/or issues</li><li><strong>3 marks:</strong> A judgement with strong justification showing detailed appraisal of relevant information and/or issues, using contextual evidence from the case study</li></ul></div>"}]}}'::jsonb),
('business', '7-1-final', '7.1 Interdependent Nature of Business', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must know for this topic. Learn the <strong>exact wording</strong> — examiners reward precise definitions.</p>\n        <ul>\n          <li><strong>Interdependent Nature of Business:</strong> The links between different areas of business (operations, finance, marketing, HR) that affect decision making, the risks and rewards of business activity, and the use of financial information to aid business decision making.</li>\n          <li><strong>Financial Information:</strong> Includes information about revenues, costs, profit, rates of return, break-even and cash flow — used to help the business make decisions.</li>\n          <li><strong>Business Performance:</strong> A measure of how well a business is doing. Key measures are sales, profits and rates of return.</li>\n          <li><strong>Financial Reward:</strong> The profit made by the business as a return for taking a risk.</li>\n          <li><strong>Financial Risk:</strong> The possibility the business will lose money from decisions it makes. Owners may lose money they invested.</li>\n          <li><strong>Non-Financial Rewards:</strong> To owners, this includes the satisfaction of running a successful business, being in charge, being independent and having an impact on what consumers buy.</li>\n          <li><strong>Non-Financial Risk:</strong> To business owners this includes health risks due to stress and strained relationships with family and friends.</li>\n          <li><strong>Synopticity:</strong> In OCR GCSE Business, this means that knowledge from Component 01 topics is brought together with knowledge from Component 02 topics to answer a question — showing how different areas of business are truly connected.</li>\n          <li><strong>Business Areas:</strong> The four main functional areas of a business: Marketing, Human Resources (HR), Business Operations, and Finance.</li>\n          <li><strong>Globalisation:</strong> The process of interaction and integration between people, companies and governments worldwide — opening up international markets and supply chains.</li>\n        </ul>", "check": {"question": "According to the key definitions, what does ''synopticity'' mean in OCR GCSE Business?", "options": ["Bringing together knowledge from Component 01 and Component 02 to answer a question", "The four main functional areas of a business working in isolation", "The possibility that a business will lose money from a decision that it has made", "A measure of how well a business is doing, based on sales and profit"], "answer": 0, "explain": "The card defines synopticity as bringing together knowledge from Component 01 and Component 02 topics to show how different business areas are connected."}}, {"title": "The Four Interdependent Business Areas", "html": "<p>A business has four main functional areas. <strong>Interdependent</strong> means these areas are linked — a decision in one area will always affect at least one other. This is the foundation of the entire topic.</p>\n        <ul>\n          <li><strong>Marketing:</strong> Market research, the marketing mix (price, place, product, promotion), market segmentation, consumer law.</li>\n          <li><strong>Human Resources (HR):</strong> Organisational structure, communication, recruiting and selecting workers, motivating, retaining and training workers, employment law.</li>\n          <li><strong>Business Operations:</strong> Production processes, customer service, location decisions, supply chain management.</li>\n          <li><strong>Finance:</strong> Sources of finance, revenues, costs and profits, break-even analysis, cash flow.</li>\n        </ul>\n        <p>When making decisions, business people must <strong>always</strong> consider the effects of a decision in one area on all other areas. For example:</p>\n        <ul>\n          <li>A <strong>Marketing</strong> decision to launch a new advertising campaign &rarr; <strong>Operations</strong> must increase production to meet higher demand &rarr; <strong>HR</strong> must recruit more workers &rarr; <strong>Finance</strong> must provide the budget and monitor cash flow.</li>\n        </ul>\n        <div class=\"case-study-box\">\n          <h4>Case Study: Wyke Farm</h4>\n          <p>Wyke Farm, a Devon dairy producer, invested in solar panels and biomethane technology. This single decision linked all four areas: <strong>Operations</strong> changed its production process; <strong>Finance</strong> used a £11m bank loan and £2m retained profit; <strong>Marketing</strong> could now promote an environmentally friendly image and sell energy as a new product; <strong>HR</strong> may have needed new skilled workers. The £100,000/month energy saving was a clear financial reward for taking the risk of the investment.</p>\n        </div>", "check": {"question": "According to the Wyke Farm case study, which business areas were linked by the solar panel investment?", "options": ["None of the four business areas were affected by the decision", "All four areas — operations, finance, marketing and HR together", "Only the finance department, with no effect on any other area", "Only the marketing department, with no effect on any other area"], "answer": 1, "explain": "The card explains Wyke Farm''s solar panel investment linked all four areas: operations changed, finance funded it, marketing promoted it, and HR may have needed new skilled workers."}}, {"title": "Risk and Reward in Business", "html": "<p>Every business decision involves <strong>risk</strong> — the chance that something could go wrong. The motivation for taking that risk is the <strong>reward</strong> — typically profit.</p>\n        <ul>\n          <li><strong>Financial Risk:</strong> Losing the money invested if the business fails or a decision backfires. When owners start a business, they invest their own or borrowed money — if the business is unprofitable, they risk losing it.</li>\n          <li><strong>Non-Financial Risk:</strong> Health problems from stress, long irregular hours, difficulty taking holidays, strained relationships with family and friends due to the pressure of running a business.</li>\n          <li><strong>Lack of Security:</strong> Entrepreneurs often give up previous jobs, losing the security of a regular income.</li>\n          <li><strong>Business Failure:</strong> The biggest risk. If the business cannot generate enough money to survive, it will be forced to close.</li>\n        </ul>\n        <p><strong>Rewards for taking the risk:</strong></p>\n        <ul>\n          <li><strong>Financial Reward:</strong> Profit — the primary driving force behind most business start-ups. Money can be reinvested to help the business grow.</li>\n          <li><strong>Independence:</strong> Being your own boss — having full control over decisions without answering to someone else.</li>\n          <li><strong>Business Success:</strong> This can mean different things: seeing an idea become popular, growing the business, winning awards, building a positive reputation.</li>\n          <li><strong>Non-Financial Reward:</strong> Personal satisfaction, the sense of achievement, being part of the community, making an impact on what consumers buy.</li>\n        </ul>\n        <div class=\"two-col\">\n          <div>\n            <div class=\"col-head\">✓ Rewards of Starting a Business</div>\n            <div class=\"pro-item\"><strong>Profit:</strong> The financial return for the entrepreneur''s effort and risk — can be reinvested to grow the business further.</div>\n            <div class=\"pro-item\"><strong>Independence:</strong> Full control over decisions, work hours and business direction without reporting to a manager.</div>\n            <div class=\"pro-item\"><strong>Personal Satisfaction:</strong> The non-financial reward of seeing your idea succeed and building something of your own.</div>\n          </div>\n          <div>\n            <div class=\"col-head\">✗ Risks of Starting a Business</div>\n            <div class=\"con-item\"><strong>Financial Loss:</strong> Invested capital (personal savings or loans) could be lost if the business fails to become profitable.</div>\n            <div class=\"con-item\"><strong>Lack of Security:</strong> No guaranteed income, long hours, difficulty taking holidays — a significant personal sacrifice.</div>\n            <div class=\"con-item\"><strong>Business Failure:</strong> The ultimate risk — if revenues cannot cover costs, the business must close, potentially leaving the owner in debt.</div>\n          </div>\n        </div>", "check": {"question": "According to this card, what is an example of a non-financial risk to a business owner?", "options": ["Full control over decisions without answering to a manager", "Health problems from stress and strained relationships with family", "The profit made by the business as a return for taking that risk", "Losing the money invested if the business fails or a decision backfires"], "answer": 1, "explain": "The card lists health problems from stress and strained family relationships as non-financial risks — distinct from financial risk (losing invested money)."}}, {"title": "Minimising Risk", "html": "<p>Entrepreneurs can take steps to <strong>reduce the risk</strong> of failure before and during the life of a business. These are not guarantees, but they significantly improve the chances of success.</p>\n        <ul>\n          <li><strong>Carry out Market Research:</strong> Gather data on customer needs, competitor prices, and market size before launching. This reduces the risk of producing something nobody wants to buy.</li>\n          <li><strong>Write a Business Plan:</strong> A detailed plan covering objectives, financial forecasts, marketing strategies and operational plans. It forces the entrepreneur to think through every aspect and is required when applying for a bank loan.</li>\n          <li><strong>Ensure Sufficient Finance is Available:</strong> Many businesses fail not because of poor ideas, but because they run out of cash. Planning cash flow carefully and securing enough start-up capital is critical.</li>\n        </ul>\n        <p>All three of these risk-minimisation strategies draw on <strong>financial information</strong> — which demonstrates once again how the different areas of business are interdependent.</p>", "check": {"question": "According to this card, what do all three risk-minimisation strategies draw on?", "options": ["Sheer luck, since risk can never actually be reduced by planning", "Legal advice, which is the only way to reduce the risk of failure", "Financial information, showing how business areas are interdependent", "Government grants, which are required before starting any business"], "answer": 2, "explain": "The card explains market research, a business plan, and ensuring sufficient finance all draw on financial information — showing business areas are interdependent."}}, {"title": "Using Financial Information to Make Decisions", "html": "<p>Businesses use financial information to <strong>measure performance</strong> and <strong>inform decisions</strong>. The most common types include:</p>\n        <ul>\n          <li><strong>Costs and Revenues:</strong> Knowing total costs versus total revenues shows whether the business is profitable.</li>\n          <li><strong>Gross and Net Profit:</strong> Gross profit shows the profit from sales before expenses; net profit shows profit after all costs are deducted.</li>\n          <li><strong>Profit Margins:</strong> Shows what percentage of revenue becomes profit — useful for comparing efficiency over time.</li>\n          <li><strong>Cash Flow:</strong> Shows the timing of money coming in and going out — a business can be profitable but still fail if cash runs out.</li>\n          <li><strong>Break-Even Analysis:</strong> Identifies the sales level at which the business covers all its costs — useful when launching a new product or making investment decisions.</li>\n          <li><strong>Average Rate of Return (ARR):</strong> Used to compare the profitability of different investment options.</li>\n        </ul>\n        <p><strong>For financial information to be useful, it must be:</strong></p>\n        <ul>\n          <li><strong>Accurate:</strong> Incorrect data leads to incorrect decisions and potential financial loss.</li>\n          <li><strong>Sufficient:</strong> There must be enough data to make a meaningful comparison.</li>\n          <li><strong>Up to Date:</strong> Outdated information may be irrelevant, especially if the market has changed significantly.</li>\n        </ul>\n        <div class=\"formula-box\">\n          <strong>Net Profit =</strong> Gross Profit &minus; Expenses (overheads)\n          <br><br>\n            <strong>Gross Profit =</strong> Revenue &minus; Cost of Sales\n            <br><br>\n              <strong>Net Profit Margin (%) =</strong> (Net Profit &divide; Revenue) &times; 100\n            </div>", "check": {"question": "According to this card, what does ''net profit margin'' show?", "options": ["What percentage of revenue becomes profit, useful for comparing efficiency", "The total amount of cash a business has in its bank account today", "The total revenue a business receives before any of its costs are deducted", "The exact number of units a business must sell to break even"], "answer": 0, "explain": "The card explains net profit margin shows what percentage of revenue becomes profit, useful for comparing a business''s efficiency over time."}}, {"title": "Limitations of Financial Information", "html": "<p>While financial information is essential, it has <strong>limitations</strong> that businesses must be aware of when making decisions.</p>\n              <ul>\n                <li><strong>Inflation:</strong> The Average Rate of Return (ARR) does not account for the effects of inflation on the value of money. £1 today is worth more than £1 in five years'' time — but ARR treats them the same.</li>\n                <li><strong>Historical Data:</strong> Financial accounts are published after the period they cover. A lot may have changed in the market by the time the data is analysed.</li>\n                <li><strong>Incomplete Picture:</strong> Financial data only measures what can be quantified in money. It cannot capture reputation, staff morale, brand loyalty or the external competitive environment.</li>\n                <li><strong>Comparability:</strong> Comparing accounts between businesses can be misleading if they use different accounting methods or operate in different markets.</li>\n              </ul>\n              <p>Businesses typically compare their accounts in two ways:</p>\n              <ul>\n                <li><strong>Year-on-Year:</strong> Comparing this year''s performance against previous years to identify trends.</li>\n                <li><strong>Against Competitors:</strong> Comparing with rivals (only possible for Limited Companies which must publish their accounts) to benchmark performance.</li>\n              </ul>", "check": {"question": "According to this card, what limitation does Average Rate of Return (ARR) have?", "options": ["It ignores the cost of the original investment being compared", "It cannot be used to compare two different investment options at all", "It can only ever be calculated by limited companies, not other businesses", "It does not account for the effects of inflation on the value of money"], "answer": 3, "explain": "The card explains ARR does not account for inflation — £1 today is worth more than £1 in five years'' time, but ARR treats them the same."}}, {"title": "Synoptic Questions: How to Link Business Areas", "html": "<p>The final 9-mark question on OCR Paper 2 is <strong>always synoptic</strong> — it requires you to link a topic from Component 01 (e.g. stakeholders, globalisation, environment) with a topic from Component 02 (e.g. cash flow, marketing mix, costs). Here is how to approach these questions:</p>\n              <ul>\n                <li><strong>The Change:</strong> This is the topic that \"makes something happen\" — e.g. a change in marketing, or a decision to go more environmentally friendly. Your Knowledge (K) and Understanding (U) marks come from explaining this topic.</li>\n                <li><strong>The Impact:</strong> This is what is affected — e.g. cash flow, operations, HR. Your Application (APP), Analysis (AN) and Evaluation (EVAL) marks come from explaining the impact on the specific business in the case study.</li>\n              </ul>\n              <div class=\"case-study-box\">\n                <h4>Example: Dog and Gun Inn (Cash Flow)</h4>\n                <p>The question asks: \"Evaluate the impact the <strong>change to marketing</strong> by the Dog and Gun Inn may have had on its <strong>cash flow</strong>.\"</p>\n                <p>&rarr; Knowledge/Understanding marks: define and explain <strong>marketing</strong>.<br>\n                  &rarr; Application/Analysis/Evaluation marks: explain how the specific marketing changes (takeaway menu, website adverts) would have affected the <strong>cash flow</strong> of the Dog and Gun specifically.</p>\n              </div>\n              <p>A common mistake is to write entirely about marketing and forget to link it back to the named impact (cash flow). Always keep asking yourself: <em>\"So what does this mean for the cash flow / costs / revenue of this specific business?\"</em></p>", "check": {"question": "According to this card, where do Application, Analysis and Evaluation marks come from in a synoptic question?", "options": ["Describing the ''change'' topic in as much general detail as possible", "Simply repeating the definition of the ''change'' topic several times over again here", "Explaining the impact on the specific business regarding the named ''affected'' topic", "Listing every possible business area without ever linking any of them together"], "answer": 2, "explain": "The card explains APP, AN and EVAL marks come from explaining the impact on the specific business regarding the named ''affected'' topic, such as cash flow."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Interdependent Nature of Business", "definition": "The links between the four business areas (marketing, HR, operations, finance) that must be considered when making decisions, managing risk and using financial information."}, {"term": "Four Business Areas", "definition": "Marketing, Human Resources (HR), Business Operations, and Finance — all linked and dependent on each other."}, {"term": "Financial Risk", "definition": "The possibility of losing money invested in a business if decisions prove unsuccessful or the business fails."}, {"term": "Non-Financial Risk", "definition": "Personal costs such as stress, health problems, long hours and strained family relationships faced by business owners."}, {"term": "Financial Reward", "definition": "Profit — the monetary return an entrepreneur earns for taking a risk and running a business successfully."}, {"term": "Non-Financial Reward", "definition": "Independence, personal satisfaction, sense of achievement, and the ability to make an impact on consumers."}, {"term": "Synopticity", "definition": "Linking knowledge from OCR Component 01 and Component 02 to show how different business areas are interconnected."}, {"term": "Requirements for Useful Financial Information", "definition": "Must be: (1) Accurate, (2) Sufficient in quantity, and (3) Up to date."}, {"term": "ARR Limitation", "definition": "The Average Rate of Return does not account for the effects of inflation on the value of money — future cash is treated the same as present cash."}, {"term": "How Businesses Measure Performance", "definition": "Year-on-year comparison of their own accounts AND comparison with competitors'' accounts (possible for Limited Companies which must publish theirs)."}, {"term": "Minimising Business Risk (3 Methods)", "definition": "1. Carry out market research. 2. Write a detailed business plan. 3. Ensure sufficient finance is available."}, {"term": "Globalisation", "definition": "The process of interaction and integration between people, companies and governments worldwide — brings both risk (competition, exchange rates) and reward (larger markets, higher revenue) to shareholders."}, {"term": "Net Profit Formula", "definition": "Net Profit = Gross Profit − Expenses (overheads such as salaries, rent, other costs)."}, {"term": "Gross Profit Formula", "definition": "Gross Profit = Revenue − Cost of Sales"}, {"term": "Why Financial Information is Limited", "definition": "It may be outdated, not account for inflation (ARR), not capture non-financial factors like reputation, or be difficult to compare across different businesses."}]}, "mcq": {"enabled": true, "questions": [{"question": "A well-known restaurant chain is reviewing its business performance. Campaign A costs £3m/week and raised sales from £4m to £6m but they dropped back to £4m after. Campaign B costs £0.6m/week and raised sales from £4m to £5m and stayed at £5m after. This data shows that:", "options": ["Both advertising campaigns were cost effective", "Campaign A was cost effective, but campaign B was not", "Campaign B was cost effective, but campaign A was not", "Neither of the advertising campaigns were cost effective"], "answer": 2, "explain": "Correct answer: Campaign B is cost effective because the £1m increase in weekly sales (from £4m to £5m) has been sustained after the campaign, meaning the £0.6m weekly cost generates a net gain. Campaign A boosted sales by £2m during the campaign, but sales returned to £4m afterwards — meaning the £3m weekly cost produced no lasting benefit."}, {"question": "A manufacturer has decided to run a marketing campaign on national television in a month''s time. As a result of this decision, which one of the following actions might also be necessary?", "options": ["Finance should stop monitoring cash flow", "Human resources should employ some temporary production workers", "Operations management should reduce output", "Purchasing should buy smaller quantities of raw materials"], "answer": 1, "explain": "Correct answer: If the marketing campaign is successful, demand for the product will increase. The business will need to increase production to meet this higher demand, which means HR will need to employ additional temporary production workers. Options A, C and D are all the opposite of what would be needed."}, {"question": "The marketing function of a well-known action toy manufacturer is about to launch a major advertising campaign. This advertising campaign will affect the operations function of the business because:", "options": ["Job production will need to be used to speed up production", "Market research into which toy figures are most popular will be required", "More sets of action toy figures will need to be produced", "Vacancies for action toy designers will need to be advertised"], "answer": 2, "explain": "Correct answer: The advertising campaign (a marketing decision) will increase demand for the toys. Operations must respond by increasing production output to meet this new demand. Option A is wrong because job production is slow, not fast. Option B is a marketing activity, not operations. Option D relates to HR."}, {"question": "The interdependent nature of business activity means that:", "options": ["Businesses need to merge to increase market share", "Entrepreneurs should favour high risk options", "Global trade is increasing", "The functional areas in a business are linked"], "answer": 3, "explain": "Correct answer: Interdependence means that the functional areas of a business (finance, marketing, operations and HR) are all linked and connected to one another. A decision in one area will always have an effect on at least one other area."}, {"question": "The impact of risk taken by a business:", "options": ["Affects all business functions", "Affects all business stakeholders equally", "Only affects the finance function", "Only affects the owners of the business"], "answer": 0, "explain": "Correct answer: Risk taken by a business can affect all business functions. For example, a risky decision to launch a new product involves operations (producing it), marketing (promoting it), HR (staffing it) and finance (funding it). Risk does not affect all stakeholders equally, nor is it limited to the finance function or owners alone."}, {"question": "Finance performance data for Pico Ltd:<table class=\"case-table\"><caption>Pico Ltd — Financial Performance</caption><tr><th>Year</th><th>Revenue</th><th>Costs</th></tr><tr><td>2017</td><td>£3.1m</td><td>£2.9m</td></tr><tr><td>2018</td><td>£3.3m</td><td>£2.9m</td></tr><tr><td>2019</td><td>£3.5m</td><td>£2.9m</td></tr></table>According to the table, which of the following MUST be true?", "options": ["Pico Ltd has improved its market share", "Pico Ltd has decreased its prices year on year", "Pico Ltd has made a profit in all three years", "Pico Ltd has not paid its variable costs"], "answer": 2, "explain": "Correct answer: In all three years, revenue exceeds costs (e.g. £3.1m > £2.9m in 2017), meaning Pico Ltd has made a profit in every year. Option A cannot be confirmed without knowing total market size. Option B is not necessarily true — revenue could have increased due to selling more units at the same price. Option D is incorrect as costs are recorded."}, {"question": "Following recent financial success, a business has decided to double the size of its workforce. This decision will significantly increase the workload of the:", "options": ["Finance function because new recruits need to be trained", "Human resources function because applicants need to be interviewed", "Marketing function because person specifications need to be produced", "Purchasing function because contracts of employment need to be issued"], "answer": 1, "explain": "Correct answer: Doubling the workforce means a large-scale recruitment drive. The HR function is responsible for advertising vacancies, shortlisting applications, and interviewing candidates. Training is also an HR function (not finance). Person specifications and contracts of employment are also HR tasks, not marketing or purchasing."}, {"question": "Last year''s financial performance data:<table class=\"case-table\"><caption>Company Performance</caption><tr><th>Company</th><th>Profit / Loss</th></tr><tr><td>Company A</td><td>£22,000</td></tr><tr><td>Company B</td><td>–£6,000</td></tr><tr><td>Company C</td><td>£14,000</td></tr><tr><td>Company D</td><td>–£3,000</td></tr></table>Which company made the greatest loss?", "options": ["Company A", "Company B", "Company C", "Company D"], "answer": 1, "explain": "Correct answer: A negative figure in the profit/loss column means a loss. Company B made a loss of £6,000 and Company D made a loss of £3,000. Since £6,000 is a greater loss than £3,000, Company B made the greatest loss. Companies A and C made profits."}, {"question": "The finance department has forgotten to authorise the purchase of a large order of raw materials. Which of the following is a likely consequence of this?", "options": ["More marketing will be needed", "Production may be delayed", "Sales will increase", "Storage costs will increase"], "answer": 1, "explain": "Correct answer: If raw materials are not purchased because finance failed to authorise the order, the operations function will not have the inputs needed to make products. This demonstrates interdependence — a failure in the finance function directly delays production in the operations function."}, {"question": "A tinned-soup manufacturer is considering extending its product range to include fresh soups. Which one of the following is NOT likely to encourage shareholders to vote for this extension?", "options": ["The opportunity to combine ingredient costs and make higher profits", "The opportunity to gain a reputation for producing healthy meals", "The opportunity to have more customers than other soup manufacturers", "The opportunity to increase the financial risks of the business"], "answer": 3, "explain": "Correct answer: Shareholders invest in a business to receive a financial reward (dividends and share price growth). Increasing financial risk without a clear reward would not attract shareholder support — shareholders generally want risk to be minimised or managed carefully. Options A, B and C all offer potential rewards which would attract shareholders."}, {"question": "Quarterly revenue data for Padre Stores Ltd in 2020:<table class=\"case-table\"><caption>Padre Stores Ltd — Quarterly Revenue (2020)</caption><tr><th>Store</th><th>Q1 (Jan–Mar)</th><th>Q2 (Apr–Jun)</th><th>Q3 (Jul–Sep)</th><th>Q4 (Oct–Dec)</th></tr><tr><td>Store A</td><td>£42,000</td><td>£48,000</td><td>£52,000</td><td>£60,000</td></tr><tr><td>Store B</td><td>£58,000</td><td>£60,000</td><td>£58,000</td><td>£60,000</td></tr><tr><td>Store C</td><td>£65,000</td><td>£50,000</td><td>£40,000</td><td>£60,000</td></tr></table>The data shows that:", "options": ["Average revenue per store in Q2: Apr–Jun was £39,500", "Store A had an average revenue of £50,500 per quarter", "Store C took more revenue in 2020 than either of the other two stores", "Total revenue in Q1: Jan–Mar was better than in any other quarter"], "answer": 1, "explain": "Correct answer: Store A''s total revenue = £42,000 + £48,000 + £52,000 + £60,000 = £202,000. Average = £202,000 ÷ 4 = £50,500. Option A is wrong (Q2 average = (£48k+£60k+£50k)/3 = £52,667). Option C is wrong (Store C total = £215k; Store B total = £236k). Option D is wrong (Q1 total = £165k; Q4 total = £180k)."}, {"question": "Kareem makes hand-made shoes. His performance data is shown below:<table class=\"case-table\"><caption>Kareem''s Shoe Business — Annual Data</caption><tr><th>Year</th><th>Pairs Sold</th><th>Revenue</th><th>Profit / Loss</th></tr><tr><td>Year 1</td><td>104</td><td>£2,080</td><td>–£24,000</td></tr><tr><td>Year 2</td><td>1,040</td><td>£20,800</td><td>£2,000</td></tr><tr><td>Year 3</td><td>820</td><td>£16,400</td><td>–£1,800</td></tr><tr><td>Year 4</td><td>1,860</td><td>£46,500</td><td>£26,000</td></tr></table>According to the data, which of the following is true?", "options": ["Costs have been greater than revenue in all four years", "In Year 2, Kareem reduced the average selling price of the shoes", "In Year 4, Kareem increased the average selling price of the shoes", "Revenue has increased year on year"], "answer": 2, "explain": "Correct answer: Year 3 average price: £16,400 ÷ 820 = £20 per pair. Year 4 average price: £46,500 ÷ 1,860 = £25 per pair. This shows Kareem increased his average price in Year 4. Option A is wrong because revenue exceeded costs in Year 2 and Year 4 (both profitable). Option B is wrong as Year 1 and Year 2 both show a £20 average. Option D is wrong — revenue fell in Year 3."}]}, "fib": {"enabled": true, "questions": [{"text": "The [interdependent] nature of business refers to the links between the four areas of business: marketing, HR, operations and [finance]."}, {"text": "The financial [reward] for taking a risk in business is profit, while a key financial [risk] is the possibility of losing invested money."}, {"text": "Three ways to minimise business risk are: carrying out market [research], writing a business [plan], and ensuring sufficient finance is available."}, {"text": "Financial information must be [accurate], sufficient and [up] to date to be useful for business decision making."}, {"text": "A key limitation of the Average Rate of Return is that it does not account for the effects of [inflation] on the value of money over [time]."}, {"text": "Businesses compare their accounts [year] on year and also against [competitors] to measure their performance."}, {"text": "In OCR GCSE Business, [synopticity] means linking knowledge from Component 01 and Component 02 to show how business areas are [connected]."}, {"text": "Non-financial risks to a business owner include damage to their [health] due to stress and strained [relationships] with family and friends."}, {"text": "If the finance department fails to authorise a purchase of raw materials, it demonstrates interdependence because [production] may be delayed as a result."}, {"text": "A marketing decision to launch an advertising campaign will require [operations] to increase output and [HR] to potentially recruit more workers."}, {"text": "Net profit is calculated by subtracting [expenses] from gross profit, while gross profit equals [revenue] minus cost of sales."}, {"text": "Globalisation can bring [reward] to shareholders through higher profits from larger markets, but also [risk] from increased international competition."}]}, "tf": {"enabled": true, "questions": [{"statement": "The interdependent nature of business means that a decision in one business area will always affect at least one other area.", "answer": true, "explain": "TRUE. This is the core principle of the topic. For example, a marketing decision to increase advertising will affect operations (more production needed), HR (more workers needed) and finance (more money needed). All four areas are linked."}, {"statement": "Financial risk only affects the finance department of a business.", "answer": false, "explain": "FALSE. The impact of risk taken by a business affects ALL business functions. A risky decision — such as opening a new branch — affects operations, HR, marketing and finance simultaneously. It does not fall solely on the finance department."}, {"statement": "Non-financial rewards for entrepreneurs can include independence and personal satisfaction.", "answer": true, "explain": "TRUE. Not all rewards are monetary. Entrepreneurs value the freedom of being their own boss (independence), the sense of achievement from building something successful, and the impact they have on the lives of customers and employees — these are all non-financial rewards."}, {"statement": "The Average Rate of Return (ARR) accounts for the effects of inflation on the value of money.", "answer": false, "explain": "FALSE. This is a key limitation of ARR. It treats money received in the future as having the same value as money today, which ignores inflation. In reality, £10,000 in 10 years is worth less in real terms than £10,000 today."}, {"statement": "A business can be profitable and still run out of cash.", "answer": true, "explain": "TRUE. Cash flow and profit are different things. A business might be owed money by customers (debtors) but not yet received it — it is ''profitable on paper'' but has no cash to pay its immediate bills. This is why cash flow management is a separate and critical business activity."}, {"statement": "For financial information to be useful, it only needs to be accurate.", "answer": false, "explain": "FALSE. For financial information to be useful it must be: (1) Accurate — so correct decisions can be made; (2) Sufficient — enough data for meaningful comparison; AND (3) Up to date — so it reflects the current market situation. All three qualities are required."}, {"statement": "In the OCR GCSE examination, the final 9-mark question on Paper 2 always requires a synoptic response linking two areas of business.", "answer": true, "explain": "TRUE. OCR specifies that the final question on Component 02 will always be a synoptic question, requiring candidates to demonstrate understanding of how different business areas are interconnected. Candidates must link a topic from Component 01 with one from Component 02."}, {"statement": "Entrepreneurs who carry out market research before launching a product completely eliminate the risk of business failure.", "answer": false, "explain": "FALSE. Market research reduces risk by gathering information about customer needs and market conditions, but it cannot eliminate risk entirely. Consumer preferences can change, competition can intensify unexpectedly, and economic conditions can worsen — all despite thorough research."}, {"statement": "Globalisation can bring both risks and rewards to the shareholders of a business.", "answer": true, "explain": "TRUE. Globalisation brings rewards such as access to larger international markets, higher revenues, more customers and potentially higher dividends. However, it also brings risks such as increased international competition, exposure to exchange rate fluctuations, and the need to manage different legal and cultural environments."}, {"statement": "When a business doubles its workforce, the marketing function has the biggest increase in workload.", "answer": false, "explain": "FALSE. When a business doubles its workforce, the Human Resources (HR) function has the biggest increase in workload. HR must advertise vacancies, write job descriptions and person specifications, interview candidates, issue contracts of employment, and organise training for new starters."}, {"statement": "Businesses can only compare their financial performance with their own previous years'' results.", "answer": false, "explain": "FALSE. Businesses can compare their accounts in two ways: year-on-year (against their own previous results) AND against competitors. Comparison with competitors is possible for Limited Companies because they are legally required to publish their accounts, making the data publicly available."}]}, "misc": {"enabled": true, "items": [{"myth": "Students write about ''interdependence'' as simply meaning ''businesses need each other'' or ''companies trade with each other.''", "truth": "Interdependence in this context means the four FUNCTIONAL AREAS within a SINGLE business (marketing, HR, operations, finance) are linked. A decision in one internal area affects the others. It is NOT about businesses trading with each other.", "check": {"question": "What does ''interdependence'' actually mean in this topic?", "options": ["The four functional areas within a single business are linked to each other", "A business depends on customers trading with each other directly", "A business depends entirely on its own direct competitors in order to succeed", "Different businesses need each other and trade with one another"], "answer": 0, "explain": "The card explains interdependence means the four functional areas within a SINGLE business are linked — it is not about businesses trading with each other."}}, {"myth": "For the 3-mark analyse question, students describe what a function does generally (e.g. ''marketing involves promotion'') without linking it to the specific business in the case study.", "truth": "The examiner''s report highlighted this was the most common reason for scoring zero. You MUST name a specific marketing activity (Understanding), THEN link it to the specific company named (Application), THEN explain the impact on the other function mentioned in the question (Analysis).", "check": {"question": "Why does describing a function generally, e.g. ''marketing involves promotion'', score zero on a 3-mark analyse question?", "options": ["It already contains full application and analysis in one short sentence", "It only applies to finance questions, and never to marketing questions", "It fails to link the activity to the specific business named in the case study", "It is factually incorrect, since marketing never involves promotion at all"], "answer": 2, "explain": "The card explains this was the most common reason for scoring zero — you must name a specific activity, link it to the business, then explain the impact."}}, {"myth": "Students confuse ''risk'' with only financial risk — they do not mention non-financial risks like stress, health issues or strained family relationships.", "truth": "The specification explicitly identifies BOTH financial risk (losing money invested) AND non-financial risk (health, stress, damaged family relationships). For a question asking for two risks, one of each type is a strong answer.", "check": {"question": "Does ''risk'' in this topic only refer to financial risk?", "options": ["No — but only because financial risk does not actually exist", "Yes — but only health risks count as a form of financial risk", "No — non-financial risks like stress and strained relationships also count", "Yes — only financial risk is ever recognised in this exam specification"], "answer": 2, "explain": "The card explains the specification identifies BOTH financial risk (losing invested money) AND non-financial risk (health, stress, damaged relationships)."}}, {"myth": "Students write that the limitation of ARR is that ''it is hard to calculate'' or ''businesses do not always have the right data.''", "truth": "The official, examinable limitation of ARR is that it does NOT account for the effects of INFLATION on the value of money. Money received in the future is worth less in real terms than money received today — ARR ignores this.", "check": {"question": "What is the official, examinable limitation of ARR, according to this card?", "options": ["Businesses never have the right data available to calculate it at all", "It can only be used by businesses that have already made a profit", "It does not account for the effects of inflation on the value of money", "It is too difficult for most businesses to actually calculate correctly"], "answer": 2, "explain": "The card explains the official limitation is that ARR ignores inflation — money received in the future is worth less in real terms than money today."}}, {"myth": "For the 9-mark synoptic question, students focus entirely on the ''change'' topic (e.g. marketing) and forget to explain the impact on the ''affected'' topic (e.g. cash flow).", "truth": "Your K and U marks come from explaining the ''change'' topic. But your APP, AN and EVAL marks ALL come from explaining the effect on the specific impact named in the question (e.g. cash flow, costs, revenues). You MUST switch focus to the impact in the second half of your answer.", "check": {"question": "What mistake do students make when they focus entirely on the ''change'' topic in a 9-mark synoptic question?", "options": ["They forget to explain the impact on the ''affected'' topic named in the question", "They accidentally answer a completely different question by mistake", "They correctly earn every single mark available for the whole question", "They spend too little time explaining what the ''change'' topic actually involves"], "answer": 0, "explain": "The card explains APP, AN and EVAL marks all come from explaining the effect on the named ''affected'' topic — you must switch focus in the second half of the answer."}}, {"myth": "Students confuse ''stakeholders'' with ''shareholders'' — they write an entire answer referring to ''stakeholders'' without ever naming a specific one.", "truth": "To gain Application and Analysis marks in the 9-mark question about financial data and stakeholders, you MUST name specific stakeholders (e.g. employees, suppliers, banks, the local community). Vague references to ''stakeholders'' do not earn marks.", "check": {"question": "What must students do to gain Application and Analysis marks about stakeholders?", "options": ["Refer only to shareholders, since stakeholders are never creditable at all here", "Use only the general word ''stakeholders'' throughout the entire answer", "Name specific stakeholders, such as employees, suppliers, banks or the community", "Avoid naming any stakeholder group at all in the final answer given"], "answer": 2, "explain": "The card explains you must name specific stakeholders like employees, suppliers or banks — vague references to ''stakeholders'' do not earn marks."}}, {"myth": "Students think profit and cash flow are the same thing — they use the terms interchangeably.", "truth": "Profit is total revenue minus total costs over a period. Cash flow is the actual movement of money in and out of the business. A business can be profitable but still have a cash flow problem if customers have not yet paid their invoices.", "check": {"question": "Are profit and cash flow the same thing that can be used interchangeably?", "options": ["Yes — profit and cash flow are simply two names for the same figure", "No — but only because cash flow is always higher than profit", "No — a business can be profitable but still have a cash flow problem", "Yes — but only if the business has already paid all of its invoices"], "answer": 2, "explain": "The card explains profit is revenue minus costs over a period, while cash flow is the actual movement of money — a business can be profitable yet still face a cash shortage."}}, {"myth": "When asked how a marketing decision affects operations, students write about marketing activities (e.g. ''they will advertise more'') rather than the impact on the operations/production function.", "truth": "The examiner''s report noted this was very common. Once you have identified the marketing activity (for the Understanding mark), you MUST explain the consequence for the operations function specifically — e.g. ''this means operations will need to INCREASE PRODUCTION to meet higher demand.''", "check": {"question": "When asked how a marketing decision affects operations, what must the answer explain?", "options": ["The consequence for the operations function specifically, such as increased production", "A definition of operations with no link at all to the marketing decision", "The consequence for the finance function instead of the operations function itself", "Only the marketing activities themselves, such as advertising more heavily"], "answer": 0, "explain": "The card explains you must explain the consequence for operations specifically — e.g. ''operations will need to increase production to meet higher demand.''"}}]}, "tips": {"enabled": true, "items": [{"title": "The Locked Gate: Understanding Opens Everything", "html": "\n              <p>Every 3-mark Analyse question in this topic works the same way. There is a <strong>locked gate</strong> — you cannot earn any marks without first showing <strong>Understanding (U)</strong> of the key term in the question.</p>\n              <p><strong>The 3-step formula:</strong></p>\n              <ul>\n                <li><strong>Step 1 — Understanding (U):</strong> Explain what the function or concept DOES. Be specific. Name an activity it carries out.</li>\n                <li><strong>Step 2 — Application (APP):</strong> Link your understanding directly to the business in the case study. Use a specific detail from the text.</li>\n                <li><strong>Step 3 — Analysis (AN):</strong> Explain the impact — what happens as a result? This must be a business-facing consequence (e.g. production increases, costs rise, revenue falls).</li>\n              </ul>\n              <p><strong>❌ Bad Answer (0 marks):</strong><br />\n                <em>\"The finance function is important for BP because it manages the company''s finances efficiently.\"</em><br />\n                This is tautological — saying \"finance manages finances\" earns no understanding mark, and no further marks can follow.</p>\n              <p><strong>✅ Good Answer (3 marks):</strong><br />\n                <em>\"The finance function produces cash-flow forecasts and budgets (U) in order to inform BP''s managers how much money is available for investment into new technologies (APP), such as the wind farms being developed in America, meaning BP can make financially sound decisions to meet its sustainability objectives (AN).\"</em></p>\n              <p><strong>⚠️ Examiner Warning:</strong> On the real exam, two thirds of candidates scored zero on Q2 (Unilever, 3 marks) and the majority scored zero on Q4 (BP, 3 marks). The reason was identical in both cases: they failed to identify a specific activity of the named function. \"Marketing the product\" or \"managing the business efficiently\" are too vague and score nothing.</p>\n              ", "check": {"question": "According to this card, what happens if you don''t show Understanding first in a 3-mark analyse question?", "options": ["You automatically earn 2 out of 3 marks for the remaining two steps", "The examiner awards the mark anyway, provided the answer is detailed", "No further marks can follow, since Understanding is a locked gate", "You can still earn full marks through Application and Analysis alone"], "answer": 2, "explain": "The card describes Understanding as a ''locked gate'' — without it, no Application or Analysis marks can be awarded, no matter how good the rest of the answer is."}}, {"title": "The Synoptic 9: Two Topics, One Answer", "html": "\n              <p>The final 9-mark question always links <strong>two topics</strong>: one from Component 01 and one from Component 02. There are <strong>9 marks split across 5 skills</strong>: K (1) + U (1) + APP (2) + AN (2) + EVAL (3).</p>\n              <p><strong>The 4-paragraph structure:</strong></p>\n              <ul>\n                <li><strong>Paragraph 1 — K &amp; U:</strong> Define the ''change'' topic (K) and explain how it works (U). Keep this brief — it''s only 2 marks total.<br />\n                  <em>Starter: \"Marketing refers to [K]... This involves activities such as [U]...\"</em></li>\n                <li><strong>Paragraph 2 — APP &amp; AN (Point 1):</strong> Use ONE specific detail from the case study (APP) to explain ONE impact on the named affected area (AN).<br />\n                  <em>Starter: \"In the case of [Business Name], [specific detail from text] (APP)... As a result, this would [impact on the named area — cash flow / costs / revenues] (AN)...\"</em></li>\n                <li><strong>Paragraph 3 — APP &amp; AN (Point 2):</strong> Use a SECOND specific detail from the case study (APP) to explain a SECOND impact on the named affected area (AN).<br />\n                  <em>Starter: \"Furthermore, [second detail from text] (APP)... This means [second impact on the named area] (AN)...\"</em></li>\n                <li><strong>Paragraph 4 — EVAL (3 marks):</strong> Make a clear judgement (1 mark), justify it with context (1 mark), and add a conditional ''it depends on'' statement (1 mark).<br />\n                  <em>Starter: \"Overall, I believe [judgement] (EVAL). This is because [reason using case study context] (EVAL). However, this will ultimately depend on [a contextual condition, e.g. the size of the changes / whether customers continue to buy] (EVAL).\"</em></li>\n              </ul>\n              <p><strong>🚫 Critical Warning — Do NOT write evaluation in the wrong place.</strong> The three evaluation marks are ONLY awarded in the final judgement section. Writing \"I think this is good\" halfway through your analysis does not count as evaluation.</p>\n              <p><strong>⚠️ Examiner Warning:</strong> Many candidates wrote entirely about ''stakeholders'' without ever naming a specific one (e.g. employees, suppliers, banks). Vague references to ''stakeholders'' earned zero for application AND analysis. You must name them.</p>\n              ", "check": {"question": "According to this card, where are the three evaluation marks specifically awarded?", "options": ["Only in the very first paragraph, before any analysis is given", "Automatically, regardless of where in the answer they are written", "Only in the final judgement section, not partway through the analysis", "Anywhere in the answer, as long as a personal opinion is expressed"], "answer": 2, "explain": "The card warns evaluation marks are ONLY awarded in the final judgement section — writing ''I think this is good'' halfway through the analysis does not count."}}, {"title": "Q16 Style: Same Business, Three Different Functions", "html": "\n              <p>Some questions ask you to analyse the impact of the SAME thing (e.g. being environmentally friendly) on THREE DIFFERENT functions (marketing, HR, finance) in separate 3-mark questions. Each is marked independently using the same U &rarr; APP &rarr; AN structure.</p>\n              <p><strong>Key tip:</strong> Do NOT repeat the same point in each answer. Each response must show a different aspect of the same theme.</p>\n              <ul>\n                <li><strong>Marketing (3 marks):</strong> Focus on how the marketing mix changes — e.g. promotion changes to highlight eco-credentials, or product packaging changes.</li>\n                <li><strong>HR (3 marks):</strong> Focus on how staff are recruited, trained or managed differently — e.g. online interviews to reduce travel, remote working, new IT training.</li>\n                <li><strong>Finance (3 marks):</strong> Focus on costs, cash flow or sources of finance — e.g. higher costs from eco-friendly suppliers, need to monitor cash flow more carefully, may need an increased overdraft.</li>\n              </ul>\n              <p><strong>✅ Good Answer for Finance (3 marks):</strong><br />\n                <em>\"Being environmentally friendly is likely to increase operating costs (U) as NEXT plc. will need to source products from more expensive ethical/eco-friendly suppliers worldwide (APP). This means the finance department may face cash flow difficulties and need to apply for a larger bank overdraft to cover the shortfall (AN).\"</em></p>\n              ", "check": {"question": "According to this card, what must you avoid when analysing the same theme across three different functions?", "options": ["Writing three separate three-mark answers instead of one combined answer", "Repeating the same point in each answer instead of a different aspect each time", "Discussing marketing, HR and finance as three genuinely separate business functions", "Using the U to APP to AN structure for each of the three separate answers"], "answer": 1, "explain": "The card warns against repeating the same point in each answer — each response must show a different aspect of the same theme, marked independently."}}, {"title": "Make a Choice, Back It Up, Compare", "html": "\n              <p>A 3-mark ''Recommend'' question (like Q16 iv) asks you to make a <strong>clear judgement</strong> about which option is most important or most affected. It is marked on three levels:</p>\n              <ul>\n                <li><strong>1 mark:</strong> A judgement with limited justification — you name a winner but don''t really explain why.</li>\n                <li><strong>2 marks:</strong> A judgement with good justification — you name a winner AND give a clear reason with some reference to relevant information.</li>\n                <li><strong>3 marks:</strong> A judgement with strong, detailed justification — you name a winner AND give a detailed, specific reason that shows clear appraisal of why this function is most affected compared to others.</li>\n              </ul>\n              <p><strong>✅ Good Answer (3 marks):</strong><br />\n                <em>\"The human resources function would be most affected by NEXT plc. being environmentally friendly (JUDGEMENT) because it would impact the way ALL of its workers are employed, trained and managed on a day-to-day basis (JUSTIFICATION). For example, NEXT would need to introduce new IT-based processes, mobile technologies and online training packages to reduce its carbon footprint across its entire workforce (STRONG CONTEXTUAL DETAIL).\"</em></p>\n              ", "check": {"question": "According to this card, what separates a 3-mark recommend answer from a 1-mark answer?", "options": ["Writing a much longer answer overall, regardless of its actual content", "Avoiding any reference at all to the specific business that is named in the question", "Simply naming a winner, without giving any reason for the choice made", "Detailed, specific justification showing clear appraisal, not just a named winner"], "answer": 3, "explain": "The card explains a 3-mark answer needs detailed, specific justification showing clear appraisal, while a 1-mark answer just names a winner with limited justification."}}, {"title": "Precision Over Paragraphs", "html": "\n              <p>For 1-mark ''State'' or ''Identify'' questions, one precise point earns the full mark. Do NOT write paragraphs — it wastes time and the examiner is only looking for a single correct statement.</p>\n              <p><strong>The Formula:</strong></p>\n              <ul>\n                <li>One clear, specific, relevant point = 1 mark ✅</li>\n                <li>A vague, general statement = 0 marks ❌</li>\n              </ul>\n              <p><strong>❌ Bad Answer (0 marks) for \"Identify two variable costs\":</strong><br />\n                <em>\"Production costs and salaries.\"</em><br />\n                \"Salaries\" are a <strong>fixed</strong> cost, not variable. \"Production costs\" is too vague.</p>\n              <p><strong>✅ Good Answer (2 marks):</strong><br />\n                <em>\"1. Raw materials / cost of sales. 2. Packaging.\"</em></p>\n              <p><strong>⚠️ Examiner Warning on Variable Costs:</strong> Do NOT accept ''salaries'' — these are fixed costs. The mark scheme specifically excludes this. Only accept wages (which can vary with hours worked), raw materials, packaging and stock/components.</p>\n              ", "check": {"question": "According to this card, why would ''salaries'' be rejected as an answer to ''identify a variable cost''?", "options": ["Salaries are not a real business cost recognised in this exam specification", "Salaries only ever apply to businesses with more than one employee", "Salaries are a fixed cost, not a variable one, according to the mark scheme", "Salaries are classed as a form of revenue, not a cost, in this topic"], "answer": 2, "explain": "The card''s examiner warning states salaries are a fixed cost — the mark scheme specifically excludes them from being accepted as a variable cost."}}, {"title": "Show Your Workings Every Time", "html": "\n              <p>For calculation questions, you must <strong>always show your workings</strong> — even if you get the final answer wrong, you can still earn marks for correct method.</p>\n              <p><strong>Net Profit Calculation (3 marks) — The Two-Step Method:</strong></p>\n              <ul>\n                <li><strong>Step 1 — Calculate Gross Profit (1 mark):</strong> Revenue &minus; Cost of Sales</li>\n                <li><strong>Step 2 — Calculate Net Profit (2 marks):</strong> Gross Profit &minus; All Other Expenses (Salaries + Rent + Other expenses)</li>\n              </ul>\n              <p><strong>Example (RCP Question):</strong></p>\n              <ul>\n                <li>Gross Profit = £2,000,000 &minus; £500,000 = <strong>£1,500,000</strong> (1 mark)</li>\n                <li>Total Expenses = £1,300,000 + £100,000 + £50,000 = £1,450,000</li>\n                <li>Net Profit = £1,500,000 &minus; £1,450,000 = <strong>£50,000</strong> (2 marks)</li>\n              </ul>\n              <p><strong>Net Profit Margin</strong> = (£50,000 &divide; £2,000,000) &times; 100 = <strong>2.5%</strong></p>\n              <p><strong>⚠️ Warning:</strong> If you only write the final answer with no workings and it is wrong, you score zero. With workings shown, even a mathematical error in the final step earns 2 out of 3 marks.</p>\n              ", "check": {"question": "According to this card, what happens if you write only the final answer with no workings and it is wrong?", "options": ["You score zero, since there is no method shown to award partial credit", "You still score full marks, since only the final answer is ever checked", "You automatically score 2 out of 3 marks regardless of the final answer", "The examiner estimates your workings and awards marks accordingly"], "answer": 0, "explain": "The card warns that with no workings shown, a wrong final answer scores zero — but with workings shown, even a mathematical error can earn 2 out of 3 marks."}}]}, "exam": {"enabled": true, "questions": [{"question": "This data helps the company understand its business performance because it shows that: [1 mark]", "marks": 1, "hint": "Think about what ''cost effective'' means — does the campaign generate more in lasting sales than it costs to run?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Campaign B was cost effective, but campaign A was not [1 mark]</h5><p><strong>Why C is correct:</strong> Campaign B costs £0.6m per week and raised weekly sales from £4m to £5m — a £1m increase that was <strong>sustained</strong> after the campaign ended. The permanent sales gain exceeds the cost. Campaign A raised sales by £2m during the campaign, but sales returned to £4m afterwards — meaning the £3m weekly cost produced no lasting benefit, making it not cost effective.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A</strong> is wrong because Campaign A did NOT produce a lasting increase in sales — therefore it was not cost effective.</li><li><strong>B</strong> is wrong — it is the opposite of the correct answer.</li><li><strong>D</strong> is wrong because Campaign B clearly WAS cost effective given its sustained sales increase.</li></ul></div>"}, {"question": "Analyse one way the marketing function impacts on the operations function of Unilever plc. [3 marks]", "marks": 3, "hint": "You MUST name a SPECIFIC activity the marketing function does (not just ''marketing the product'') — this unlocks ALL three marks. Then link it to Unilever, then explain the impact on operations/production.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> A specific activity the marketing function carries out — e.g. advertising/promotion, price changes, new product development, identifying new markets, using different selling methods. <strong>NB: No mark for general comments like ''marketing the product'' or ''going global.''</strong></li><li><strong>Application (1 mark):</strong> Links understanding to Unilever plc using evidence from the text — e.g. reference to Lynx Body Spray, Dove, Hellmann''s, Persil, 190 countries, flow/batch production, growing revenue, difficult economic climate.</li><li><strong>Analysis (1 mark):</strong> Explains the specific impact on the OPERATIONS function — e.g. changes in output/production quantity, increase in production capacity, need to find new ways to produce a product, need to invest in capital to increase/improve production. <strong>NB: Analysis must be business-facing and focused on operations specifically.</strong></li></ul><p><strong>Examiner''s Comment:</strong> This question was very poorly answered — two thirds of candidates scored zero. The most common mistake was identifying only a general marketing activity without naming a specific function action. Students who said the business ''would market the product'' or ''use marketing activities'' failed to gain the Understanding mark and therefore could not access any further marks. Students also often failed to recognise that ''operations'' refers to production activities.</p></div>"}, {"question": "Evaluate how useful the financial data in Table 2 is to GK''s stakeholders. [9 marks]", "marks": 9, "hint": "This is a SYNOPTIC question — it links financial data (Component 02) with stakeholders (Component 01). You MUST name specific stakeholders (e.g. employees, suppliers, banks) — not just ''stakeholders'' in general — to earn your Application and Analysis marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks (AO1a:1 + AO1b:1 + AO2:2 + AO3a:2 + AO3b:3)</h5><ul><li><strong>Knowledge (1 mark):</strong> Knowledge of financial data beyond what is in Table 2 — e.g. financial statements, cash flow forecasts, break-even predictions, ARR, profit & loss / margins.</li><li><strong>Understanding (1 mark):</strong> What financial data is USED FOR — e.g. cost and revenue data is used for cash flow forecasting; profit and loss data is used to judge success; financial data can assess the stability or long-term future of a business.</li><li><strong>Application (2 marks):</strong> TWO named stakeholders (not just ''stakeholders'') — e.g. owners/shareholders, employees, managers, customers, suppliers, banks/lenders, local community, government. Each named stakeholder = 1 APP mark.</li><li><strong>Analysis (2 marks):</strong> TWO business-facing pieces of analysis — one per named stakeholder — explaining HOW each one finds the financial data useful. E.g. employees want to know if their job is secure; banks want to know how safe it is to lend money; the local community is interested in donations to food banks.</li><li><strong>Evaluation (3 marks):</strong> A justified, contextual judgement about the usefulness of GK''s specific financial data: Judgement (1) + Justification (1) + Contextual detail from Table 2 (1). E.g. noting that the data is from 2022 and may be outdated, or that it doesn''t show trends over time.</li></ul><p><strong>Examiner''s Comment:</strong> Many candidates confused stakeholders with shareholders, and wrote entirely about ''stakeholders'' without naming any specific group — this prevented marks for both application AND analysis. Candidates who named just two stakeholders quickly accessed all 4 marks for APP and AN. About two thirds attempted evaluation, but most could not gain the third evaluation mark as they did not tie their judgement to specific data from Table 2 (e.g. the £425,000 profit, the £1.5m loan, or the £8,500 food bank donations).</p></div>"}, {"question": "Analyse how BP''s finance function may influence its ability to meet BP''s objectives. [3 marks]", "marks": 3, "hint": "What does the finance function ACTUALLY DO? (Not just ''it manages money.'') Name a specific activity like budgeting, cash-flow forecasting, or calculating costs/profits. This is your Understanding mark — without it, you score zero.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b:1 + AO2:1 + AO3a:1)</h5><ul><li><strong>Understanding (1 mark):</strong> A specific activity the finance function carries out — e.g. budgeting, financial forecasting, cash-flow forecasting, calculating revenue/costs/profit, informing spending or investment decisions. <strong>NB: \"The finance function manages the business efficiently\" is tautological — no mark awarded.</strong></li><li><strong>Application (1 mark):</strong> Links understanding to BP using evidence from the text — e.g. revenue grew from $245bn to $283bn; 18,700 petrol stations; aim to cut carbon emissions by 2050; installing electric charge points; developing wind farms in America.</li><li><strong>Analysis (1 mark):</strong> Explains the business-facing impact — e.g. finance monitors revenue/profits to inform directors how much money is available for investment; investigates the financial stability of potential partnerships; provides information on costs of diversification.</li></ul><p><strong>Examiner''s Comment:</strong> The majority of candidates scored zero as they did not identify what the finance function of a business specifically involves. Many gave credit to the finance function for activities it would not undertake, such as deciding how to increase revenue or what to spend money on. In all analyse questions, candidates must use words OTHER than those in the question to show genuine understanding.</p></div>"}, {"question": "The impact of risk taken by a business: [1 mark]", "marks": 1, "hint": "Think about what happens to a business when a risky decision is made — does it affect just one department or all of them?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Affects all business functions [1 mark]</h5><p><strong>Why A is correct:</strong> Risk is inherently cross-functional. A risky business decision — for example, launching a new product or opening a new branch — simultaneously affects operations (must produce more), HR (must recruit more), marketing (must promote the new launch) and finance (must fund it all). Risk does not fall on just one function.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B</strong> is wrong because risk does NOT affect all stakeholders equally — shareholders carry the financial risk of investment loss, while employees carry the risk of job security. The impacts are different in nature and magnitude.</li><li><strong>C</strong> is wrong because risk extends well beyond the finance function — it affects production capacity, staffing levels and marketing strategies.</li><li><strong>D</strong> is wrong because while owners/shareholders bear significant financial risk, employees, suppliers and customers are also affected by the business''s risk decisions.</li></ul></div>"}, {"question": "The marketing function of a well-known action toy manufacturer is about to launch a major advertising campaign. This advertising campaign will affect the operations function of the business because: [1 mark]", "marks": 1, "hint": "The operations function is about PRODUCTION. What will happen to production if the advertising campaign successfully drives up demand?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — More sets of action toy figures will need to be produced [1 mark]</h5><p><strong>Why C is correct:</strong> A successful advertising campaign will increase consumer demand for the toys. The operations function must respond by increasing production output to ensure there is enough stock to meet this higher demand. This is a direct example of a marketing decision creating an interdependency with the operations function.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A</strong> is wrong because job production is slow and individually customised — it would reduce output speed, not increase it. Mass production methods would be needed to meet higher demand.</li><li><strong>B</strong> is wrong because market research is a marketing function activity, not an operations function activity.</li><li><strong>D</strong> is wrong because advertising vacancies for toy designers is an HR function activity, not operations.</li></ul><p><strong>Examiner''s Comment:</strong> Although the question mentions advertising (a marketing activity), the focus is on the impact on OPERATIONS. Some candidates answered B because they saw ''market research'' but this is still a marketing activity, not operations.</p></div>"}, {"question": "Identify two variable costs which a business may incur. [2 marks]", "marks": 2, "hint": "Variable costs CHANGE with the level of production. Think about what a business buys more of when it produces more goods.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><ul><li><strong>1 mark</strong> for each correct variable cost identified, up to a maximum of 2 marks.</li></ul><p><strong>Acceptable answers include:</strong></p><ul><li>Wages (labour costs)</li><li>Raw materials / cost of sales (or one specific example)</li><li>Stock / components</li><li>Packaging</li></ul><p><strong>⚠️ Do NOT accept:</strong> ''Salaries'' (these are fixed costs — paid at a set rate regardless of output) or ''production costs'' (too vague).</p><p><strong>NB:</strong> Answers do not need to apply specifically to RCP — any valid variable cost from any business context is acceptable.</p></div>"}, {"question": "Calculate RCP''s net profit for 2020. Show your workings. [3 marks]", "marks": 3, "hint": "This is a two-step calculation. Step 1: Calculate GROSS profit (Revenue minus Cost of Sales). Step 2: Calculate NET profit (Gross Profit minus ALL other expenses — salaries, rent and other expenses).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2)</h5><ul><li><strong>3 marks:</strong> Correct final answer of £50,000 (with or without workings shown).</li><li><strong>2 marks:</strong> Mathematical error in calculating net profit BUT evidence of correct method shown AND correct use of the data.</li><li><strong>1 mark:</strong> Correct gross profit figure (£1,500,000) shown with evidence of workings, even if net profit is then calculated incorrectly.</li></ul><p><strong>Full working:</strong></p><ul><li>Gross Profit = Revenue − Cost of Sales = £2,000,000 − £500,000 = <strong>£1,500,000</strong></li><li>Total Expenses = £1,300,000 (salaries) + £100,000 (rent) + £50,000 (other) = £1,450,000</li><li>Net Profit = £1,500,000 − £1,450,000 = <strong>£50,000</strong></li></ul><p><strong>Net Profit Margin</strong> = (£50,000 ÷ £2,000,000) × 100 = <strong>2.5%</strong></p></div>"}, {"question": "Analyse one way Alessia and Natalia could use the data shown in Table 1 to improve their net profit margin. [3 marks]", "marks": 3, "hint": "Look at the data in Table 1 — which cost is by far the largest? How could reducing that cost improve the net profit margin? Remember: U → APP → AN.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> One way a business could improve its net profit margin — e.g. recognising that expenses/costs are too high and need decreasing; needing to increase revenue relative to costs; identifying which costs are highest.</li><li><strong>Application (1 mark):</strong> Links to specific data from Table 1 — e.g. net profit margin is 2.5%; revenue has increased by 25% in 2020; cost of sales is 25% of revenue; RCP''s salaries account for 65% of revenue earned; or any other use of data from Table 1.</li><li><strong>Analysis (1 mark):</strong> Explains a specific business-facing consequence — e.g. a pay cut would reduce salaries and increase profits; using lower quality raw materials would widen the gap between revenue and costs; an example of how to achieve any proposed change.</li></ul></div>"}, {"question": "Analyse one way falling unemployment might influence recruitment at Pukka Pies Ltd. [3 marks]", "marks": 3, "hint": "When unemployment FALLS, there are FEWER people looking for work. How does this make it HARDER or MORE EXPENSIVE for Pukka Pies to recruit? Remember U → APP → AN.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Understanding of the issues surrounding falling unemployment — e.g. higher consumer spending; increased difficulty of replacing workers; inability to recruit enough workers; link between increased employment and demand for products.</li><li><strong>Application (1 mark):</strong> Links to Pukka Pies Ltd — e.g. 360 employees; factory in Leicester; family-owned business.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. increased costs of recruitment; higher wages needed to attract applicants; production may decrease or become less efficient if vacancies cannot be filled; business may consider relocating to an area with higher unemployment.</li></ul></div>"}, {"question": "Evaluate how Pukka Pies Ltd''s environmental considerations might influence its marketing mix. [9 marks]", "marks": 9, "hint": "This is a SYNOPTIC 9-marker linking ENVIRONMENT (Component 01) with THE MARKETING MIX (Component 02). Your K and U marks come from explaining environmental considerations. Your APP, AN and EVAL marks come from how each of the 4Ps (Product, Price, Place, Promotion) is affected — link back to Pukka Pies specifically.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks (AO1a:1 + AO1b:1 + AO2:2 + AO3a:2 + AO3b:3)</h5><ul><li><strong>Knowledge (1 mark):</strong> Environmental considerations are about the natural world / trying to keep the impact of business on the environment to a minimum.</li><li><strong>Understanding (1 mark):</strong> An example of an environmental consideration — e.g. sustainability issues, waste disposal, pollution, climate change.</li><li><strong>Application (2 marks):</strong> TWO synoptic applications to elements of the marketing mix — PRODUCT (impact on range of products, types of products or packaging — NOT quantity); PRICE (impact on prices); PLACE (how distribution/transportation is carried out or where products are sold); PROMOTION (efforts to make customers aware of being more environmentally friendly).</li><li><strong>Analysis (2 marks):</strong> TWO business-facing impacts — e.g. changing pie range to include vegan options using eco-friendly suppliers; creating an advertising campaign that stresses environmentally friendly sourcing; prices may rise due to higher supplier costs or electric delivery vans; packaging replaced with recyclable materials.</li><li><strong>Evaluation (3 marks):</strong> Justified contextual judgement — e.g. whether environmental considerations have bigger implications for Pukka Pies than other factors (economic climate, ethical concerns); whether the impact is larger for one element of the mix than another; use of contextual evidence (e.g. Pukka Pies has already changed its packaging / none of its waste goes to landfill).</li></ul>"}, {"question": "Evaluate how globalisation may bring risk and reward to the shareholders of AM plc. [9 marks]", "marks": 9, "hint": "This is a synoptic 9-marker. K and U come from GLOBALISATION. APP, AN and EVAL must all focus on the impact on SHAREHOLDERS specifically — think about dividends, share price and return on investment. Cover BOTH risk AND reward.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks (AO1a:1 + AO1b:1 + AO2:2 + AO3a:2 + AO3b:3)</h5><ul><li><strong>Knowledge (1 mark):</strong> Globalisation is the process of interaction and integration between people, companies, and governments worldwide.</li><li><strong>Understanding (1 mark):</strong> How globalisation works — e.g. movement of workers and/or capital from country to country; greater dependence on external factors like exchange rates; advances in transportation and communication technology; a globalised supply chain.</li><li><strong>Application (2 marks — Synoptic):</strong> Risk examples: increased competition; having to manage legal, political, cultural and regulatory requirements; risk of failure. Reward examples: more revenue/sales; growth of ideas; larger market size; more customers across 50+ countries; expanding brand into new areas (speed boats, submarines).</li><li><strong>Analysis (2 marks — business-facing for shareholders):</strong> Higher profits → higher dividends/share price; higher market share → higher share price; higher sales → lower average cost per car → more profit; risks may decrease profits → lower dividends and share price; maintaining brand identity across cultures costs money → affects profitability.</li><li><strong>Evaluation (3 marks — must be contextual for full marks):</strong> Whether risk exceeds reward or vice versa; factors that determine the balance; use of contextual evidence from AM plc — e.g. 150+ dealerships in 50+ countries; declining UK unemployment (bar chart) potentially increasing UK demand; globalised supply chain bringing dependency on overseas suppliers.</li></ul>"}, {"question": "Analyse one way in which being environmentally friendly could impact on NEXT plc.''s marketing function. [3 marks]", "marks": 3, "hint": "What would NEXT plc.''s marketing team actually CHANGE or DO DIFFERENTLY because of its environmental commitment? Think about advertising, promotion, pricing, product range, or how it communicates with customers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b:1 + AO2:1 + AO3a:1)</h5><ul><li><strong>Understanding (1 mark):</strong> One way being environmentally friendly could impact a business''s marketing function — e.g. change of advertising strategy; promotion of environmentally friendly behaviour; additional market research; change of target market; charge higher prices; extension of product lifecycle; change in how NEXT segments the market.</li><li><strong>Application (1 mark):</strong> Applies to NEXT plc. specifically using evidence from the text.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. increased workload for the marketing department designing new eco-focused promotions; higher promotional costs; potential for attracting a new segment of eco-conscious customers.</li></ul><p>Content from components 01 and 02 is synoptically assessed in this question.</p>"}, {"question": "Analyse one way in which being environmentally friendly could impact on NEXT plc.''s human resources function. [3 marks]", "marks": 3, "hint": "How might the HR function at NEXT operate DIFFERENTLY to reduce its environmental footprint? Think about how people are recruited, interviewed, trained or managed.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b:1 + AO2:1 + AO3a:1)</h5><ul><li><strong>Understanding (1 mark):</strong> One way being environmentally friendly could impact a business''s HR function — e.g. increased use of technology; reduced waste (e.g. paper); use of recycled paper; communication by email; use of online application forms; job interviews conducted online; online training packages; hot desking; home working; issuing mobile communication technologies to staff; encouraging remote working.</li><li><strong>Application (1 mark):</strong> Applies to NEXT plc. specifically.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. reduced travel and therefore less pollution; lower costs from less paper usage; a more flexible and motivated workforce; reduced carbon footprint from daily operations.</li></ul>"}, {"question": "Analyse one way in which being environmentally friendly could impact on NEXT plc.''s finance function. [3 marks]", "marks": 3, "hint": "Think about what happens to COSTS when a business switches to eco-friendly suppliers, packaging or transport. How does this affect the finance function''s responsibilities?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b:1 + AO2:1 + AO3a:1)</h5><ul><li><strong>Understanding (1 mark):</strong> One way being environmentally friendly could impact a business''s finance function — e.g. increased costs; need to monitor cash flow; need to obtain additional sources of finance; effect on break-even point.</li><li><strong>Application (1 mark):</strong> Applies to NEXT plc. specifically.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. may find itself in a more difficult cash flow position; may need to apply for an increase in overdraft; break-even point may rise if costs increase.</li></ul>"}, {"question": "Recommend which function would be most affected by NEXT plc. being environmentally friendly. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Make a clear recommendation (this earns 1 mark). Then give a strong, detailed reason that explains WHY this function is more affected than the others — use specific details about NEXT to score all 3 marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b:3)</h5><ul><li><strong>1 mark:</strong> A judgement with limited justification — names which function is most affected with a brief, general reason.</li><li><strong>2 marks:</strong> A judgement with good justification — names the function AND provides a clear reason with reference to relevant information and/or issues.</li><li><strong>3 marks:</strong> A judgement with strong justification — names the function AND provides a detailed, specific justification that shows clear appraisal of why this function is more affected than the others, with use of relevant contextual detail.</li></ul><p><strong>ARA — Any function is acceptable as long as the justification is detailed and relevant.</strong></p>"}]}}'::jsonb)
